window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["id"]={"ICON-0001":{"nm":"Jejak Kaki","de":"Sebuah bekas berwarna tanah tertinggal di lantai kayu. Ada seseorang yang mondar-mandir lama, lalu akhirnya melangkah satu kali lagi ke depan. Yang dicatat oleh jejak kaki bukanlah waktu yang dihabiskan untuk berdiam, melainkan momen ketika seseorang memutuskan untuk pergi."},"ICON-0002":{"nm":"Lentera","de":"Saat api menyentuh sumbu, kegelapan mundur perlahan sejengkal demi sejengkal. Dengan kehangatan kecil yang menghangatkan ujung jari, orang-orang zaman dahulu menuliskan harapan dan melarungkannya. Lentera dinyalakan bukan untuk menerangi, melainkan untuk menemani."},"ICON-0003":{"nm":"Pita","de":"Dengan satu simpul, hati dibungkus dengan indah. Mudah dilepas bagi tangan yang memberi, namun ingin dilepas perlahan-lahan oleh tangan yang menerima. Yang diikat pita bukanlah kotak, melainkan debar jantung sesaat sebelum diserahkan."},"ICON-0004":{"nm":"Kotak Surat","de":"Ia berdiri di mulut gang dengan mulut merahnya terbuka lebar. Bahkan di zaman ketika surat tulisan tangan menjadi langka, kotak kecil ini tetap menunggu kabar seseorang hingga akhir. Wadah yang penuh kasih ini justru paling bersinar saat menjadi kosong."},"ICON-0005":{"nm":"Peta Mini Pulau Pribadi","de":"Selembar kertas: sekepal saku ketika dilipat, laut dan punggung bukit berjajar ketika dibentangkan. Bagi yang baru tiba pertama kali, setiap sudutnya adalah janji yang belum terbuka. Begitu dibentangkan, pulau kecil pun menjadi dunia yang luas."},"ICON-0006":{"nm":"Mikrofon","de":"Setengah ketukan menahan napas tepat sebelum nada pertama terlontar. Menyadari tatapan penonton menanti satu kata darimu membuat ujung jari gemetar. Mikrofon bukan memperbesar suara, melainkan membawa getaran itu hingga tuntas."},"ICON-0007":{"nm":"Jam","de":"Jarum detik tak pernah beristirahat, namun tak seorang pun mendesakmu. Berapa malam lagi hingga debut, berapa menit lagi hingga panggung—di atas piringan angka, penantian dan debaran berputar dengan kecepatan yang sama. Melihat waktu adalah cara menenangkan hati."},"ICON-0008":{"nm":"Buku Catatan","de":"Benda dengan ruang kosong terbanyak. Alur koreografi, tekad di dini hari, kata-kata yang tak pernah terkirim—semuanya menumpuk di sini. Begitu dibuka, diri hari kemarin diam-diam menyapa diri hari ini."},"ICON-0009":{"nm":"Cap Stempel","de":"Direndam tinta merah lalu ditekan mantap, sebuah janji terukir jelas. Bekas yang lebih berat dari tulisan, lebih tegas dari kata-kata. Di setiap akhir dokumen, orang-orang mempercayakan hatinya pada cap kecil ini, menggantikan nama."},"ICON-0010":{"nm":"Alas Penyangga","de":"Ia merendahkan dirinya sejauh mungkin untuk menopang yang lain. Di posisi paling bawah, menahan beban dalam diam agar yang berada di atasnya tak goyah. Meski tak pernah bersinar, di sinilah kebaikan yang mencegah segalanya runtuh."},"ICON-0011":{"nm":"Prangko","de":"Gambar kecil yang dijilat lalu ditempelkan mantap di satu sudut. Harga paling jujur yang ditetapkan untuk hati yang dikirim jauh. Selembar pemandangan persegi menggandeng tangan surat menyeberangi lautan."},"ICON-0012":{"nm":"Pin Bendera","de":"Menancapkannya di peta berarti berkata, \"aku sudah sampai sejauh ini.\" Bukan penaklukan, melainkan catatan, dan sorak dukungan bagi siapa pun yang datang berikutnya. Penanda yang tanpa kata mendorong punggungmu—melihat bendera ini, melangkahlah satu langkah lagi."},"ICON-0013":{"nm":"Ranting","de":"Ranting yang pernah melengkung sekali lupa cara patah. Di setiap tempat ia menunduk menghadapi angin, buku kayu tertanam kuat dan keras, dan kekuatan sejati datang dari bekas ketahanan—begitulah hutan tua membisikkannya lewat angin."},"ICON-0014":{"nm":"Kancing","de":"Dilepas dan dikancingkan lagi berulang kali, ia merapatkan kerah. Satu lingkaran kecil diam-diam menangkis dinginnya subuh sekaligus rasa malu yang tiba-tiba muncul. Baru ketika terlepas dengan bunyi kecil, orang menyadari betapa besar arti tempatnya itu."},"ICON-0015":{"nm":"Amplop","de":"Saat mulutnya disegel, barulah ia menjadi rahasia. Hanya penerima yang tahu apa yang tersimpan di dalamnya. Selapis kertas yang diletakkan di antara hati dan dunia—pintu paling tipis dan paling lembut dari semuanya."},"ICON-0016":{"nm":"Kotak","de":"Keempat sudutnya rapi, sehingga ia merangkul apa saja dengan lapang dada. Kenangan di musim pindah rumah, hadiah di hari raya, dan barang-barang serba-serbi di hari biasa. Di balik tutup yang tertutup, selalu penuh dengan \"nanti\" milik seseorang."},"ICON-0017":{"nm":"Gagang Pintu","de":"Di antara pintu dan manusia, ia adalah yang pertama mengulurkan tangan. Hanya setelah ditarik sekali, barulah dalam dan luar tersambung. Setiap keputusan untuk masuk atau keluar menggenggam tangan dingin ini sekali sebelum berlalu."},"ICON-0018":{"nm":"Sendok","de":"Dengan mulutnya yang cekung, ia diam-diam mengangkat kuah hangat. Alat yang mengingat kehangatan satu suapan pertama yang ditiup dingin oleh ibu lalu diberikan lebih dulu. Di meja makan, ialah tangan paling lembut—yang paling sering menyentuh bibir."},"ICON-0019":{"nm":"Sandal Rumah","de":"Begitu melewati ambang pintu, kaki lebih dulu menghela napas lega. Suara malam, langkah pelan setelah menanggalkan hari yang penuh derap tergesa. Sepasang yang tersusun rapi di depan pintu berkata, \"sekarang kau sudah di rumah.\""},"ICON-0020":{"nm":"Kunci","de":"Kau belajar cara membuka sebelum belajar cara mengunci. Sekeping logam kecil yang menghangat di telapak tangan, lalu suatu hari berhenti diam-diam di depan pintu baru yang asing. Benda yang menyimpan kehangatan orang yang pergi paling lama."},"ICON-0021":{"nm":"Gelas","de":"Rapi ketika kosong, sehangat mungkin ketika terisi. Dalam denting jernih dua gelas yang diangkat berhadapan dan diadu, tersimpan janji tanpa kata. Wadah yang lahir untuk bersinar bersama dua orang, bukan sendiri."},"ICON-0022":{"nm":"Piring","de":"Di dalam pinggirannya yang bundar, tersaji penuh ketulusan sehari. Dikosongkan, dilap, lalu diisi lagi seumur hidup—perkakas rumah tangga yang paling sering berkilau sekaligus paling sering terlupakan. Panggung meja makan selalu digelar di atasnya."},"ICON-0023":{"nm":"Lampu","de":"Satu saklar dan raut ruangan pun berubah. Terang berarti keseharian, redup berarti penghiburan. Setitik cahaya yang dibiarkan menyala hingga akhir demi seseorang yang pulang larut menjadi sambutan paling hangat di dunia."},"ICON-0024":{"nm":"Sendok Teh","de":"Diaduk perlahan satu putaran di atas air teh, daun dan air pun saling meresap. Gerakan tanpa tergesa, penantian kecil hingga aromanya menyebar. Satu tangan berwarna perak dengan lembut memperlambat laju sore hari."},"ICON-0025":{"nm":"Pembatas Buku","de":"Janji yang diam-diam diselipkan di tempat bacaan terhenti. Tekad \"aku berhenti di sini, pasti akan kembali\" tertidur di antara halaman-halaman. Kisah boleh tertutup, namun hati tertanda jelas pada satu baris itu."},"ICON-0026":{"nm":"Bantal Duduk","de":"Ia menerima tanpa kata punggung dan lutut yang butuh sandaran. Tenggelam dalam-dalam lalu mengembang perlahan, ia menyerap lelahnya sehari. Benda yang paling murah hati mengizinkan sikap paling malas sekalipun."},"ICON-0027":{"nm":"Bingkai","de":"Batas persegi mengikat satu pemandangan menjadi keabadian. Untuk momen yang tertangkap di dalamnya, waktu tak akan memudar betapa pun lamanya berlalu. Pilihan penuh kasih ini bukan soal apa yang disimpan, melainkan apa yang diputuskan untuk dikenang."},"ICON-0028":{"nm":"Peta","de":"Di setiap lipatannya membekas jejak tersesat lalu menemukan jalan kembali. Bentangkan, dan tempat yang belum pernah dikunjungi pun bisa dijelajahi lebih dulu dengan ujung jari. Setiap petualangan bermula dari keberanian kecil membentangkan selembar ini."},"ICON-0029":{"nm":"Kartu Pos","de":"Separuh bagian belakangnya foto, separuh lagi kosong. Seseorang yang pergi jauh mengirimkan \"aku baik-baik saja\" dalam beberapa kata, disertai pemandangan tempat itu. Selembar kertas paling jujur, tempat kabar tak perlu malu tanpa amplop."},"ICON-0030":{"nm":"Kartu Akses","de":"Begitu dikalungkan, barulah kau melangkah ke dalam dunia bagian dalam. Namamu yang tertulis di kartu kecil itu diam-diam mengizinkan, \"di sini, ini tempatmu.\" Bukan syarat untuk lolos, melainkan bukti bahwa kau termasuk di suatu tempat."},"ICON-0031":{"nm":"Huruf B","de":"Huruf yang paling sering dipanggil di tengah sebuah kata. Bibir harus dikatupkan sekali lalu dilepas dengan letupan kecil agar bunyinya keluar. Bukan awal, bukan pula akhir, tetapi posisi kedua yang diandalkan untuk menjaga irama."},"ICON-0032":{"nm":"Kartu Nama","de":"Diserahkan dengan dua tangan, diterima sambil menatap mata. Hari dan kebanggaan seseorang dipadatkan diam-diam dalam selembar kertas. Di celah sempit antara nama dan jabatan, kesan pertama hari itu diam-diam bersemayam."},"ICON-0033":{"nm":"Sampul","de":"Di bagian paling luar sebuah kisah, ia yang lebih dulu menghadapi hujan dan angin. Demi menjaga huruf-huruf di dalamnya, sudutnya sendiri yang lebih dulu aus. Debar sesaat sebelum dibuka selalu bermula dari lembar ini."},"ICON-0034":{"nm":"Buku Pelajaran","de":"Perjuangan seseorang tertulis padat dengan garis bawah dan spidol pewarna. Ketika masih baru terasa membingungkan, setelah selesai dibaca menjadi sahabat paling dapat diandalkan. Jejak memahami hal yang dulu tak diketahui terlipat rapi di setiap halamannya."},"ICON-0035":{"nm":"Kartu Akses Latihan Dansa","de":"Selembar ini membuka lebar pintu ruang latihan. Ruangan penuh cermin, suara hentakan kaki, delapan hitungan pertama yang baru dipelajari. Tak apa jika tarianmu masih canggung—selembar kertas kecil ini diam-diam mendorong punggung yang gemetar."},"ICON-0036":{"nm":"Map Berkas","de":"Lembaran-lembaran kertas yang dulu berserakan kini terjahit rapi pada satu punggung, akhirnya memperoleh urutan. Ketika urutan tercipta, jadilah sebuah kisah, dan semakin tebal ia, semakin lembut pula buktinya bahwa seseorang telah menjalani hidup selangkah demi selangkah."},"ICON-0037":{"nm":"Kertas Ujian","de":"Ujung jari yang gemetar sesaat di atas garis kosong. Yang lebih menakutkan dari jawaban salah adalah menghadapi langsung hal yang belum diketahui. Setelah penilaian selesai, di setiap tempat yang keliru, tersisa diam-diam ruang kosong untuk bertumbuh di lain waktu."},"ICON-0038":{"nm":"Huruf A","de":"Bunyi pertama yang baru muncul saat mulut dibuka lebar-lebar. Ia sering berdiri di paling depan sebuah baris, di awal mula sebuah nama. Karena apa pun yang dimulai selalu dimulai dari huruf ini—maka ia selalu sedikit lebih berani."},"ICON-0039":{"nm":"Huruf D","de":"Dengan punggungnya yang melengkung lembut, ia menopang perlahan sebuah kata. Sisi bundarnya tergantung rapi di ujung nama seseorang. Tak mencolok, namun terasa hilang jika tiada—satu teman yang tenang di antara huruf-huruf."},"ICON-0040":{"nm":"Kertas Latihan","de":"Satu-satunya kertas di dunia yang membolehkan kesalahan. Ia memberi kesempatan menuliskan gerakan yang sama, kalimat yang sama, berpuluh-puluh kali. Sebanyak lembar yang kusut lalu dibuang, sebanyak itu pula seseorang pasti sedang menjadi lebih baik."},"ICON-0041":{"nm":"Kertas Komposisi","de":"Pukul dua dini hari, satu senandung membangunkanmu dari tidur. Pensil ragu-ragu di atas garis paranada karena melodi lebih cepat dari tangan. Di setiap bekas hapusan dan tulisan ulang, sebuah lagu yang belum bernama tumbuh sedikit demi sedikit."},"ICON-0042":{"nm":"Pas Akses","de":"Begitu dikalungkan, koridor biasa berubah menjadi dunia lain. Kabel-kabel melata di kegelapan bagai ular, dan di balik panggung, hitungan mundur yang tak terdengar dimulai. Hak untuk melangkah masuk di sini, selembar ini yang mewakilinya berbicara."},"ICON-0043":{"nm":"Lembar Kontak Foto","de":"Di setiap kotak kecil, ekspresi yang berbeda terhenti membeku. Tertawa, menoleh, memejamkan mata. Menunjuk satu bidikan demi satu bidikan, dan debar hari saat rana ditekan itu kembali ke ujung jari. Bahkan memilih satu lembar saja sudah menjadi sebuah catatan."},"ICON-0044":{"nm":"Lembar Jadwal Syuting","de":"Besok jam berapa, di mana, dan melakukan apa. Selembar kertas menggambar lebih dulu rute sehari. Di antara kotak-kotak yang padat per menit, seseorang mengikuti urutan yang tertulis di sini, melangkah setapak demi setapak menuju mimpi."},"ICON-0045":{"nm":"Label Harga","de":"Di balik label harga tergantung diam-diam waktu sang pembuat. Hanya dengan gerakan singkat menariknya lepas, kertas kecil itu barulah menjadi milikmu. Yang tersisa di tempat guntingannya adalah aroma barang baru dan segenggam debar hati."},"ICON-0046":{"nm":"Portofolio","de":"Buka sampulnya, dan jalan yang telah dilalui terbentang sekaligus. Di samping satu lembar yang dibanggakan, tantangan pertama yang canggung duduk malu-malu berdampingan. Ketika pertama kali menyerahkan diri kepada seseorang, tak ada perkenalan yang lebih jujur dari ini."},"ICON-0047":{"nm":"Agenda","de":"Menuliskan hari ini, menggambar minggu depan, dan sesekali menghitamkan satu kotak. Meski tak pernah berjalan sesuai rencana, tangan yang mengisi kotak-kotak itu tak pernah berhenti. Semacam ritual kecil menjalani masa depan lebih dulu."},"ICON-0048":{"nm":"Daftar Putar","de":"Di antara lagu lambat dan ketukan cepat, kau menyusun musik selaras dengan cuaca hati hari itu. Bayangkan seluruh hari seseorang mengalir persis dalam urutan ini, dan bahkan keheningan di antara lagu-lagu pun menjadi lembut."},"ICON-0049":{"nm":"Kartu Pelajar","de":"Sebuah nama, sebuah foto, dan beberapa angka. Selembar kartu yang membuktikan masa bolak-balik antara ruang kelas dan ruang latihan. Pada kartu yang sudutnya aus karena keluar masuk saku, tersimpan keseharian penuh semangat yang tak akan pernah kembali."},"ICON-0050":{"nm":"Gelang","de":"Masih ingat momen mengikatkan warna hari itu di pergelangan tangan? Yel-yel yang diteriakkan bersama, malam konser yang basah bersama-sama. Meski talinya aus dan warnanya pudar, kau tak melepasnya—karena ingin membiarkan musim panas itu terus hidup di pergelangan tanganmu."},"ICON-0051":{"nm":"Ban Lengan","de":"Begitu dililitkan di lengan, beban bernama tanggung jawab diam-diam ikut bertambah. Tanda bagi orang yang berdiri paling depan dalam barisan dan meninggalkan tempatnya paling akhir. Sepotong kain membuat seseorang tumbuh sejengkal lebih tinggi."},"ICON-0052":{"nm":"Cincin","de":"Satu garis melingkar bulat tanpa putus. Karena awal dan akhirnya bersentuhan, orang-orang melihat di dalamnya bentuk keabadian. Satukan dua tangan perlahan, dan sebelum kata-kata terucap, janji tersisa dalam wujud nyata."},"ICON-0053":{"nm":"Medali","de":"Pada keping logam kecil yang disematkan di dada, terukir hari-hari yang telah dilalui. Yang berkilau bukan logamnya, melainkan malam-malam latihan tak terhitung yang tersembunyi di baliknya. Yang membuncah sebelum kebanggaan adalah, entah kenapa, rasa syukur."},"ICON-0054":{"nm":"Celemek","de":"Ikat talinya di leher, dan kedua tangan pun bebas. Sebuah isyarat bahwa kau siap menceburkan diri sepenuhnya ke dalam sesuatu—entah tepung atau cat. Semakin banyak noda bertambah satu demi satu, semakin dalam pula ketulusan yang dicurahkan hari itu."},"ICON-0055":{"nm":"Penutup Telinga","de":"Selubungi telinga rapat-rapat, dan suara dari luar mundur selangkah. Di jalan berangkat sekolah yang berangin tajam bagai pisau, ia menjadi tempat berlindung kecil untuk bersembunyi diam-diam di dalamnya yang lembut. Kehangatan musim dingin kadang dimulai persis seperti ini, dari ujung telinga."},"ICON-0056":{"nm":"Kostum","de":"Sebelum layar terangkat, sepasang busana tergantung di gantungan sambil menahan napas. Koreografi terlipat di setiap jahitannya. Begitu lengan terselip masuk, seseorang berubah menjadi peran, dan panggung menjadi kulit kedua busana itu."},"ICON-0057":{"nm":"Mahkota","de":"Begitu diletakkan di kepala, punggung yang membungkuk pun tegak dengan sendirinya. Kilau keemasannya membisikkan tanggung jawab sebelum kekuasaan. Beban dingin yang menyentuh dahi berkata segalanya: semakin bersinar sebuah tempat, semakin berat pula ia."},"ICON-0058":{"nm":"Jubah","de":"Selempangkan di bahu, dan angin berkibar di belakang punggung. Perasaan satu lembar kain yang mengejar setiap kali berlari itu. Bukan lambang pahlawan, melainkan lebih dekat pada hati kanak-kanak yang sekadar ingin terlihat keren."},"ICON-0059":{"nm":"Topeng","de":"Menutupi wajah justru membuat seseorang lebih jujur. Seperti pertunjukan halaman kuno di mana orang tertawa dan menangis sepuas hati di balik topeng. Melampaui ekspresi yang disembunyikan, suara sejati yang biasanya ditelan bocor keluar lebih keras."},"ICON-0060":{"nm":"Lipstik","de":"Putar tutupnya, goreskan satu garis, dan tekad kecil pun tegak di bibir. Pemeriksaan terakhir di depan cermin, satu garis merah yang dilapiskan di atas keraguan. Pada momen singkat warna itu terpoles, ketakutan diam-diam menyingkir."},"ICON-0061":{"nm":"Jaket","de":"Ketika garis bahu pas sempurna, seseorang menjadi sedikit lebih tegar. Gulung lengan untuk semangat bekerja, tegakkan kerah untuk semangat melangkah keluar. Satu pakaian diam-diam menentukan sikap hari itu."},"ICON-0062":{"nm":"Sabuk Taekwondo","de":"Setiap kali warna berganti satu tingkat, jumlah keringat yang tertimbun di baliknya pun berubah. Pagi di dojang saat mengencangkan simpul dan membungkuk hormat. Melalui ujung jari yang mengikat sabuk, semangat yang tercerai-berai kembali terkumpul."},"ICON-0063":{"nm":"Kacamata Pelindung","de":"Kenakan di depan mata, dan dunia pun setingkat lebih jernih. Di balik perisai bundar yang menahan angin sekaligus debu, bahkan jalan biasa yang selalu dilalui entah kenapa berkilau bagai garis start."},"ICON-0064":{"nm":"Sarung Tangan","de":"Kenakan di tangan, dan keberanian untuk menggenggam apa pun dengan mantap pun muncul. Jari-jari yang dulu menciut takut menjatuhkan sesuatu kini akhirnya terbuka lebar. Yang dilindungi adalah tangan, namun yang sesungguhnya dijaga adalah tantangan yang akan datang berikutnya."},"ICON-0065":{"nm":"Masker","de":"Menutupi bagian bawah wajah membuat mata berbicara lebih banyak. Di jalanan yang ramai, kebebasan kecil bernama anonimitas dinikmati di balik penutup tipis itu. Maka senyuman yang tersisa saat semuanya dilepas menyebar semakin cerah."},"ICON-0066":{"nm":"Topi","de":"Turunkan sedikit pinggirannya, dan matahari maupun tatapan orang pun menyimpang sejengkal. Di bawah atap kecil yang terpasang di kepala, setidaknya hari ini boleh berjalan dengan wajah yang santai. Perubahan paling ringan selalu dimulai dari sini."},"ICON-0067":{"nm":"Kemeja","de":"Kresek, aroma pagi tercium dari kerah yang baru disetrika. Selagi mengancingkan satu per satu dari atas, hati yang kusut pun ikut merapi selangkah demi selangkah. Selembar putih ini membuka kalimat pertama hari itu."},"ICON-0068":{"nm":"Syal","de":"Lilitkan sekali di leher, dan jalur angin pun terhalang. Selagi ujungnya melambai lembut di bahu, hawa dingin tak lagi bisa menembus ke dalam. Sehelai kain yang berada di suatu tempat antara gaya dan kehangatan."},"ICON-0069":{"nm":"Sarung Tangan","de":"Terbungkus rapat hingga ujung jari, bahkan yang dingin pun tak lagi menakutkan. Kemewahan kecil musim dingin, saat tangan yang dulu dihangatkan dengan embusan napas kini diam-diam menghangat. Sebelah yang dilepas dan diberikan kadang menghangatkan tangan orang lain juga."},"ICON-0070":{"nm":"Kalung Identitas","de":"Dua keping tipis saling berhadapan diam-diam. Tiga suku kata nama dan beberapa angka—itulah yang membuat seseorang terus dikenang hingga akhir. Logam yang dingin, namun entah kenapa menyerupai janji paling hangat."},"ICON-0071":{"nm":"Cincin Pegangan","de":"Selipkan jari, dan kekhawatiran menjatuhkannya pun perlahan lenyap. Kelegaan kecil, cukup untuk dipegang dan digoyangkan bahkan dengan satu tangan. Saat lengan direntangkan jauh untuk mengabadikan satu foto, ia diam-diam menopang telapak tangan."},"ICON-0072":{"nm":"Mahkota Bunga","de":"Letakkan di kepala, dan sepenuh musim semi pun ikut serta. Bunga-bunga yang dipetik dari padang dan dirangkai bundar melingkari dahi dengan lembut. Di atas senyum cerah dalam foto, aroma tipis rerumputan bertahan lama."},"ICON-0073":{"nm":"Penutup Mata","de":"Tutupi mata, dan cahaya maupun kebisingan pun sama-sama menjauh sekaligus. Karena tak bisa melihat, yang terdengar hanya napas sendiri. Matikan dunia sejenak dan melangkahlah ke keheningan di dalam, maka pintu kecil menutup pelan di belakang punggung."},"ICON-0074":{"nm":"Syal Rajut","de":"Satu lilitan, dua lilitan, setiap kali melingkari leher, musim dingin pun sedikit lebih jinak. Di suatu tempat di antara benang wolnya, mungkin tercampur hati seseorang yang merajutnya. Kubur diri hingga ujung hidung, dan dunia terasa jauh lebih hangat."},"ICON-0075":{"nm":"Topeng Setengah Wajah","de":"Hanya menutupi separuh wajah, malam pesta topeng pun dimulai. Bibir yang terbuka tersenyum, mata yang tersembunyi menyimpan rahasia. Celah sempit antara terlihat dan tak terlihat sepenuhnya itu membuat udara tengah malam berdebar."},"ICON-0076":{"nm":"Baret","de":"Letakkan miring, dan hari biasa pun diam-diam memperoleh nuansa. Selembar kain bundar dan pipih dengan lembut mengenakan gaya seniman di bahu. Bahkan saat singkat memilih sudut kemiringan di depan cermin pun menyenangkan."},"ICON-0077":{"nm":"Choker","de":"Lingkarkan pas di leher, dan pandangan pun secara alami terkumpul ke atas. Satu tali tipis mengubah seluruh suasana. Kecil namun tegas, seperti pengait yang mengisi penuh kepercayaan diri hari ini."},"ICON-0078":{"nm":"Parka","de":"Naikkan risletingnya hingga habis, dan bahkan badai salju pun mundur selangkah. Masukkan tangan dalam-dalam ke bagian dalamnya yang tebal, dan segala hiruk pikuk dunia pun mereda. Sebuah rumah kecil yang tetap hangat hingga akhir bahkan di tengah angin yang ganas."},"ICON-0079":{"nm":"Celana Panjang","de":"Masukkan kaki, kencangkan pinggang, dan barulah persiapan untuk melangkah keluar selesai. Setiap langkah yang diayunkan, kainnya bergerak lembut mengikuti seratnya. Di suatu tempat antara kenyamanan dan kerapian, hari pun dimulai."},"ICON-0080":{"nm":"Anting Tindik","de":"Menambahkan satu titik kecil pun butuh sedikit keberanian. Satu kilau logam membubuhkan tanda titik yang jelas di telinga yang biasa. Sangat kecil, namun cahaya yang memantulkan diri hari ini yang pasti telah berubah."},"ICON-0081":{"nm":"Gelombang Suara","de":"Bagi seorang engineer, lagu bukan didengar, melainkan dilihat. Dari punggung bukit yang naik turun di layar, ia membaca di mana napas bergetar hari itu. Suara yang dulu tak terlihat kini terbaring bagai pegunungan, membentangkan lanskap sebuah lagu."},"ICON-0082":{"nm":"Alat Setem","de":"Tepat sebelum pertunjukan, keenam senar disentuh satu per satu, menata nada yang kacau ke tempatnya. Meleset 0,5 derajat saja, penonton akan menyadarinya bagai hantu. Menyetel begitu presisi hingga tak seorang pun tahu—itulah kelembutan bagi panggung."},"ICON-0083":{"nm":"Tali Selempang","de":"Lilitkan sekali di pergelangan tangan, dan kekhawatiran menjatuhkannya pun perlahan terurai. Yang paling ditakuti di atas panggung adalah kehilangan pegangan atas sesuatu, maka hanya dengan tali kecil ini hati pun akhirnya tenang."},"ICON-0084":{"nm":"Simbal","de":"Dalam satu momen benturan tunggal, tanda titik yang jelas dibubuhkan pada kalimat terakhir sebuah lagu. Piringan emas ini tahu cara berdenting paling singkat namun meninggalkan gaung paling panjang. Sebuah akhir harus ditutup secerah ini."},"ICON-0085":{"nm":"Gitar","de":"Ketika jari meluncur di atas enam senar, ruangan sempit pun sepenuhnya berubah menjadi panggung. Melodi pertama seseorang, gumaman diri sendiri di dini hari yang tak bisa tidur—semuanya pertama kali menghirup napas di dalam tabung kayu bundar ini."},"ICON-0086":{"nm":"Awan Suara","de":"Di satu sisi langit, nada-nada bergerombol bagai kapas, mengapung ringan. Konon jika angin menyapu sekali lewat, melodi turun menggantikan tetes hujan—maka anak-anak pulau itu keluar menyambutnya tanpa payung sekalipun."},"ICON-0087":{"nm":"Langkah","de":"Alur panggung adalah hitungan aritmetika yang diselesaikan dengan ujung kaki. Satu langkah di sini, setengah ketukan di sana—tak apa salah, asal pelan-pelan. Kotak-kotak yang diinjak ratusan kali dan terukir dalam tubuh berkumpul menjadi peta lengkap sebuah lagu."},"ICON-0088":{"nm":"Amplifier","de":"Kotak yang mengubah bisikan menjadi sorak-sorai. Namun sebelum menaikkan volume satu tingkat pun, tangan selalu berhenti sejenak. Bahwa suara yang lebih akurat, bukan yang lebih keras, yang mencapai baris paling belakang penonton—kotak ini mengetahuinya."},"ICON-0089":{"nm":"Kapas Not Musik","de":"Kepala-kepala not yang berbentuk kecambah berkumpul menjadi segumpal kapas, empuk bagai bantal. Berbaring dan meletakkan kepala di atasnya, konon terdengar samar-samar nina bobo mengalir keluar—kabar paling lembut di pulau itu."},"ICON-0090":{"nm":"Kaset","de":"Tekan tombol putar ulang, dan—kriet—pita perlahan berputar kembali ke lagu pertama musim panas itu. Di dalam kotak kecil yang menggulung utuh satu masa, waktu yang tak bisa disentuh lagi tertidur lelap."},"ICON-0091":{"nm":"Garpu Tala","de":"Ketuk pelan dua cabang logamnya, dan satu nada acuan pun lahir di udara. Pada getaran kecil ini, setiap alat musik diam-diam menundukkan kepala menyelaraskan diri. Segala sesuatu berawal dari getaran serapuh ini."},"ICON-0092":{"nm":"Cip Gelombang Suara","de":"Sepenggal suara dikurung lembut di dalam cip sekecil kuku. Selipan spontan yang tak sengaja terekam, tawa seseorang yang dikira telah hilang—di dalam sini semuanya masih hidup dan bernapas hangat."},"ICON-0093":{"nm":"Piringan Hitam","de":"Ketika jarum mengambil langkah pertama menyusuri alur, embusan napas samar yang berderak terdengar lebih dulu. Karena mencintai bahkan bising kecil itu, ada yang tak pernah bisa melepaskan piringan hitam ini dari tangannya hingga akhir."},"ICON-0094":{"nm":"Saku","de":"Yang paling disayangi selalu disimpan paling dekat dengan dada. Satu kantong kain sebesar telapak tangan suatu hari menjadi penghangat tangan, di hari lain menjadi jimat, dan di hari lainnya lagi menjadi tempat penyimpanan rahasia."},"ICON-0095":{"nm":"Plester Luka","de":"Di malam-malam ketika latihan berlarut, satu medali kecil menempel di setiap tumit. Selembar yang ditempelkan untuk menelan kata \"sakit\"—janji tenang yang tak diketahui siapa pun, untuk tetap menari besok apa pun yang terjadi."},"ICON-0096":{"nm":"Bantal","de":"Tempat untuk akhirnya meletakkan seluruh panggung sehari adalah, pada akhirnya, selembar kotak empuk ini. Baringkan kepala perlahan, dan tepuk tangan yang masih tersisa di telinga pun perlahan memudar, dan malam pun akhirnya turun juga di pulau itu."},"ICON-0097":{"nm":"Bel","de":"Kring, satu bunyi singkat, dan seseorang mendorong pintu lalu melangkah masuk. Isyarat bahwa tamu telah datang sekaligus sapaan bahwa hari telah dibuka. Sekeping logam kecil sepanjang hari hanya bertugas menyerukan kegembiraan."},"ICON-0098":{"nm":"Wadah","de":"Semakin berharga sesuatu, semakin dibangunkan rumah kokoh tersendiri untuknya. Sentuhan tangan yang membuka dan menutup selalu menjadi lebih hati-hati setiap kali, karena yang tersimpan di dalamnya bukan sekadar benda, melainkan hati yang tak rela hilang."},"ICON-0099":{"nm":"Sikat","de":"Sapukan mengikuti serat hingga ke helai terakhir, dan debu yang menempel di sudut pun diam-diam mundur. Berkat sentuhan yang tak pernah menghindar bahkan dari tempat yang tak terlihat, ruangan menyambut pagi baru setiap hari."},"ICON-0100":{"nm":"Sketsa","de":"Garis-garis sebelum sempurna tak repot menyembunyikan keraguannya. Di setiap bekas yang dihapus lalu digoreskan kembali, tersisa tanpa dusta apa yang ingin ia menjadi. Semakin canggung permulaannya, semakin jujur pula ia."},"ICON-0101":{"nm":"Boneka","de":"Ada makhluk yang menghibur hanya dengan dipeluk erat, tanpa sepatah kata pun. Sahabat berbulu kapas yang ikut gemetar di sisi bantal pada malam saat tanganmu bergetar di balik panggung—setiap orang menyimpan satu sepertinya jauh di dalam hati."},"ICON-0102":{"nm":"Lonceng","de":"Lonceng kuil gunung berdentang sekali dan menyeberangi seluruh lembah. Itulah hati sang logam yang merindukan jangkauan yang lebih jauh, lebih jauh lagi, menangis panjang—hingga suaranya perlahan mengendap di dada siapa pun yang mendengarnya."},"ICON-0103":{"nm":"Payung","de":"Bila dipakai berdua, salah satu bahu pasti akan basah. Di bawah payung yang dimiringkan diam-diam, bahu yang basah itulah bukti kasih sayang yang paling nyata. Perjalanan singkat berbagi satu atap tinggal lama di dalam hati."},"ICON-0104":{"nm":"Matras","de":"Bentangkan selembar di lantai kosong, dan tempat itu seketika menjadi ruang latihan. Tempat yang diam-diam menampungmu setiap kali berguling dan jatuh—tak terhitung gerakan pertama kali membiasakan diri pada tubuh di atasnya."},"ICON-0105":{"nm":"Lonceng Kecil","de":"Goyangkan pelan, dan suara jernih bergulir keluar dari dalam genggaman, gemerincing lembut. Kegembiraan kecil dan bulat yang dulu digantungkan anak-anak di ujung hanbok berwarna-warni sambil berlarian di halaman, kini terbangun kembali di atas telapak tanganmu."},"ICON-0106":{"nm":"Ular Mainan","de":"Bentuknya yang panjang menjuntai nakal-nakal membuat orang terkejut. Takut, lari, lalu akhirnya tertawa terbahak-bahak—lelucon seperti ini pun, pada akhirnya, adalah salah satu cabang dari kasih sayang satu sama lain."},"ICON-0107":{"nm":"Mainan","de":"Setiap orang, walau sudah dewasa, punya satu kotak yang tak sanggup dibuang. Di dalamnya, tawa dari masa paling cemerlang masih tergulung kencang seperti per jam yang belum dilepas."},"ICON-0108":{"nm":"Meja Makan Lipat","de":"Bentangkan kaki-kakinya yang terlipat, dan di mana pun itu segera menjadi tempat berkumpul keluarga. Suara sendok beradu saat semua duduk mengelilinginya—paduan sederhana itulah lagu paling hangat sepanjang hari."},"ICON-0109":{"nm":"Sabun","de":"Mengecil sedikit demi sedikit di tangan, ia diam-diam membersihkan seseorang. Mengorbankan tubuhnya sendiri untuk memandikan orang lain—baru lama setelah semua busa lenyap, hati yang tenang itu akhirnya terlihat."},"ICON-0110":{"nm":"Sisir","de":"Seperti melepaskan rambut kusut helai demi helai, hari yang berantakan pun perlahan menjadi rapi. Satu sentuhan singkat di depan cermin diam-diam merapikan, jauh melampaui rambut, bahkan sikap hati."},"ICON-0111":{"nm":"Sangkar Burung","de":"Ada burung yang tetap bernyanyi tanpa pergi, walau pintunya terbuka lebar. Hati yang tinggal bukan karena terkurung, melainkan karena ingin tetap tinggal—perbedaan halus itu, sangkar ini menyadarinya lebih dulu daripada siapa pun."},"ICON-0112":{"nm":"Penghangat Tangan","de":"Di antrean musim dingin di luar tempat pertunjukan, kehangatan kecil dalam saku perlahan menghangatkan jari-jari yang kaku. Kebaikan seukuran telapak tangan yang sudah dikocok dan dihangatkan lebih dulu oleh seseorang, seraya membayangkanmu menggigil kedinginan."},"ICON-0113":{"nm":"Sapu Tangan","de":"Selembar kain yang menampung air mata maupun keringat tanpa keluhan. Sulaman kecil di sudutnya tinggal di sana dengan anggun, seperti salam perpisahan terakhir dari seseorang yang lebih dulu pergi, berpesan agar jangan lupa."},"ICON-0114":{"nm":"Semprotan","de":"Sekali semprot, tekstur udara berubah dalam sekejap. Kabut yang menyebar di atas panggung, tanaman di jendela pagi—dalam butiran halus ini, sesaat semuanya menjelma dunia lain dan berkilau."},"ICON-0115":{"nm":"Kertas Wangi","de":"Memilih aroma, entah bagaimana, sangat mirip dengan memilih kenangan. Seuntai wangi tipis yang menempel di ujung kertas ramping diam-diam membawa kembali suatu musim yang kau kira telah terlupakan, ke ujung hidungmu."},"ICON-0116":{"nm":"Meja Makan","de":"Di setiap urat kayu yang telah aus, terukir diam-diam jumlah santapan yang pernah dibagi bersama. Makan malam yang ramai, juga malam larut yang dihadapi sendirian—meja persegi ini menampung semuanya tanpa sepatah kata dan menjadi mengilap karenanya."},"ICON-0117":{"nm":"Gulungan Benang","de":"Tarik salah satu ujungnya perlahan, dan ia terurai dengan lancar; satu jahitan, dan ia tersambung lagi. Menyambung yang putus selalu dimulai diam-diam seperti ini, dari seutas benang tipis."},"ICON-0118":{"nm":"Jas Hujan","de":"Bahkan di hari hujan deras, hanya sehelai pakaian inilah yang akhirnya membuatmu berani keluar rumah. Hanya orang yang tahu kesenangan berjalan cipratan di tengah hujan yang tak menjadikan hujan alasan untuk tinggal di rumah."},"ICON-0119":{"nm":"Kantong","de":"Kuncupkan mulutnya menjadi bulat, dan barulah isi di dalamnya aman. Dalam satu kantung kecil yang sudah lusuh oleh tangan, koin, kenangan suatu hari, dan kata-kata yang tak pernah sempat terucap, semuanya berayun bersama."},"ICON-0120":{"nm":"Rak Buku","de":"Susurkan jari perlahan menyusuri punggung buku yang berjajar, dan musim-musim yang telah dilalui terasa di ujung jari. Alasan kita tak sanggup membuang buku yang sudah selesai dibaca adalah karena diri kita yang dulu masih hidup di sana."},"ICON-0121":{"nm":"Tumpukan Buku","de":"Buku yang sudah dibaca direbahkan ke samping, buku yang belum dibaca ditumpuk ke atas. Meski janji untuk membaca semuanya suatu hari nanti bergoyang sedikit dekat langit-langit, goyangan itu pun disukai, maka hari ini pun satu jilid lagi ditambahkan."},"ICON-0122":{"nm":"Roda Berlari","de":"Rasanya diam di tempat walau berlari sekuat tenaga, tetapi kaki-kaki kecil itu sedang lebih dulu mempelajari irama ujung jarinya. Hari-hari kemarin yang tak pernah berhenti berkumpul, dan suatu hari, bersinar terang di jalan yang sesungguhnya."},"ICON-0123":{"nm":"Sarung Pelindung","de":"Agar debu tak menempel, agar tak pudar oleh matahari—bahkan tindakan menutupi ini pun membutuhkan ketelitian ujung jari. Semakin sesuatu disayangi, semakin lembut pula ia dilindungi di tempat yang tak terlihat."},"ICON-0124":{"nm":"Benang Wol","de":"Seutas benang yang dulu terurai bergulir dari pangkuan Nenek. Terlihat kusut, tapi temukan ujungnya dan tarik perlahan, ia pasti mengikut. Begitulah malam-malam musim dingin memanjang, satu jahitan demi satu jahitan."},"ICON-0125":{"nm":"Dompet Kecil","de":"Lip balm, karet rambut, selembar surat yang dilipat rapi—terlihat kecil, tapi di dalamnya tersimpan hati sehari penuh. Bersamaan dengan bunyi ritsleting yang tertutup, segala barang-barang kecil yang berharga menjadi aman sekaligus."},"ICON-0126":{"nm":"Sandaran Tangan","de":"Sore hari tertidur di tengah membaca, malam hari mondar-mandir sambil menelepon. Di tempat yang semakin dalam bekasnya seiring lamanya diduduki, setiap istirahat yang diingat siku mengendap diam-diam sejengkal demi sejengkal."},"ICON-0127":{"nm":"Kemasan","de":"Sebelum dibuka, ia belum menjadi milik siapa pun. Satu bungkus yang tersegel penuh dengan harapan yang belum terbuka, hingga ujung jari yang memegang sudutnya bergetar ringan. Itulah debar hati saat membukanya."},"ICON-0128":{"nm":"Kertas Kado","de":"Hati yang tiba selangkah lebih dulu daripada hadiahnya. Selagi kau melipat sudut-sudutnya rapi dan mengikatnya dengan pita, wajah tersenyum orang yang akan menerimanya sudah lebih dulu terbentang cerah di dalam genggaman tanganmu."},"ICON-0129":{"nm":"Gamepad","de":"Tombol-tombol yang diingat ibu jari lebih dulu daripada kepala. Sudah kalah pun, satu ronde lagi saja—dan satu ronde itu berakhir membuatmu begadang semalaman. Bobot yang pas di tangan diam-diam mengangkat petualangan malam ini."},"ICON-0130":{"nm":"Lampu Lalu Lintas","de":"Merah berarti berhenti sejenak, hijau berarti sekarang boleh jalan. Dengan satu janji sederhana, tak terhitung jalan mengalir tanpa saling kusut. Bahwa menunggu pun ada gilirannya, lampu yang berkedip itu memberitahu dengan lembut."},"ICON-0131":{"nm":"Tanda Panah","de":"Bentuk paling ramah bagi orang yang tersesat. Ketika bingung harus ke mana, satu arah yang sudah lebih dulu digariskan seseorang membuat langkah kaki yang terhenti menjadi mantap kembali."},"ICON-0132":{"nm":"Koordinat","de":"Dengan hanya dua angka, kau bisa menunjuk tepat di mana pun di dunia ini. Tempat yang dijanjikan untuk bertemu, pantai berpasir tempat harta dikubur. Agar sebuah janji tak kehilangan arah, satu titik kecil menahannya erat hingga akhir."},"ICON-0133":{"nm":"Ubin","de":"Sendirian, ia hanyalah sekeping persegi. Begitu berbaring berdampingan, bahu bersentuhan bahu, ia menjadi lantai dan menjadi dinding. Hal-hal kecil berkumpul, menciptakan tempat bagi seseorang untuk melangkah dengan tenang."},"ICON-0134":{"nm":"Jam Pasir","de":"Saat ruang atas kosong, ruang bawah perlahan terisi. Menyaksikan pasir mengalir turun lembut, kita percaya waktu sedang berjalan. Balikkan, dan semuanya kembali ke awal—itulah kebohongan kecil nan lembut dari pasir."},"ICON-0135":{"nm":"Bola","de":"Lempar, dan ia kembali; tendang, dan ia menggelinding pergi. Bulat dan tak pernah tahu ke mana ia akan memantul, itulah pesona terbesarnya. Di tengah lapangan, tawa selalu dimulai dengan bulat dari bola kecil ini."},"ICON-0136":{"nm":"Saklar","de":"Klik, menyala sekali tekan, padam sekali tekan. Bunyi kecil yang muncul saat melangkah masuk ke ruangan gelap itu membagi awal dan akhir hari yang berserakan menjadi satu garis yang jelas."},"ICON-0137":{"nm":"Tanda Tanya","de":"Tidak tahu jawabannya bukanlah hal yang memalukan. Itu justru bukti yang menggembirakan bahwa rasa ingin tahu masih hidup. Saat kait kecil ini mengetuk-ngetuk pikiran, belajar barulah mengambil langkah pertamanya."},"ICON-0138":{"nm":"Korek Api Batang","de":"Sebatang yang menggesek tubuhnya sendiri untuk menyerahkan api. Ia terbakar sebentar dan lenyap diam-diam, tapi dalam sekejap itu lilin menyala dan tungku menghangat. Pemberian kecil menjadi kancing pertama dari kehangatan."},"ICON-0139":{"nm":"Bangku Pijakan","de":"Naik satu langkah saja, dan tangan bisa meraih rak yang tadinya tak terjangkau. Pekerjaan meninggikan tinggi badan seseorang sesaat. Di sinilah tempat lembut yang merunduk rendah untuk diam-diam meninggikan kita."},"ICON-0140":{"nm":"Jam Tangan","de":"Benda pertama yang dikenakan di pergelangan tangan pada hari kau bertekad berolahraga. Pelatih kecil yang menghitung detak jantung dan langkah kaki, mengetuk-ngetuk memberitahu bahwa hari ini kau berjalan sedikit lebih jauh daripada kemarin."},"ICON-0141":{"nm":"Alarm","de":"Sahabat paling setia yang dibenci setiap pagi. Berkat ia yang selalu bertarung menggantikanmu melawan godaan lima menit lagi di balik selimut, janji maupun mimpi tak pernah terlambat. Suara yang berdering menjengkelkan itu, sesungguhnya, adalah semangat."},"ICON-0142":{"nm":"Inti","de":"Bagian paling dalam yang tersisa hingga akhir setelah semua lapisan luar terkelupas. Biji apel, ketulusan hati—apa pun itu, di titik tengahnya selalu tersimpan yang paling kokoh. Satu titik yang tetap bertahan di ujungnya, sekalipun terguncang."},"ICON-0143":{"nm":"Pena","de":"Bekas yang sempat menggores tepi tangan sebelum tintanya kering. Lancar atau tidak menulisnya, goresan pertama di hadapan kertas putih selalu membutuhkan sedikit keberanian. Ia adalah jembatan tempat pikiran menyeberang ke ujung jari."},"ICON-0144":{"nm":"Kuas","de":"Saat menyerap tinta dan melintasi hanji, bahkan satu getaran keraguan pun tertinggal utuh. Terburu-buru menulis karena tamak, dan itu segera terbongkar. Kuas adalah yang pertama tahu kejujuran yang bersemayam di ujung jari."},"ICON-0145":{"nm":"Balon Kata","de":"Tempat yang muncul bulat di atas kepala sebelum kata-kata sempat keluar dari mulut. Satu kalimat yang ingin diucapkan tersimpan di sini. Saat kosong, ia sedang memilih kata apa yang akan mengisinya."},"ICON-0146":{"nm":"Kotak Centang","de":"Goreskan dua garis di kotak kosong, dan hati menjadi jauh lebih ringan. Medali kecil yang diberikan sendiri untuk tugas yang selesai. Di penghujung hari, memandang kotak-kotak yang telah terisi, kita merasa lega telah menjalani hari ini dengan baik."},"ICON-0147":{"nm":"Tablet","de":"Gambar menyebar dan huruf mengalir ke mana pun jari menyentuh. Letakkan dengan tenang di atas pangkuan, dan satu dunia menyala terang. Ringan memang, tapi kemungkinan yang tersimpan di dalamnya sama sekali tidak tipis."},"ICON-0148":{"nm":"Remote","de":"Punya bakat alami untuk bersembunyi di sela-sela sofa. Kekuasaan mengganti saluran selalu milik siapa pun yang memegangnya. Pertengkaran keluarga yang paling kecil dan paling penuh kasih terjadi di atas benda sejengkal ini."},"ICON-0149":{"nm":"Pemberat Penyeimbang","de":"Beban yang menurunkan dirinya sendiri ke titik paling bawah demi menahan sesuatu yang bergoyang. Sekencang apa pun bagian atas terguncang, jika bagian bawah cukup berat, ia tak akan roboh. Keseimbangan selalu bertahan di tempat yang tak terlihat."},"ICON-0150":{"nm":"Puzzle","de":"Malam saat kau meraba-raba hingga ke bawah sofa mencari kepingan terakhir yang hilang. Kenikmatan tanpa suara pada saat ia pas masuk ke tempatnya. Ketika hal-hal yang berserakan menemukan tempatnya, gambar itu akhirnya lengkap."},"ICON-0151":{"nm":"Penggaris","de":"Mengukur panjang juga merupakan cara menepati janji. Agar satu jengkal sama bagi siapa pun, garis-garis skalanya berbaris jujur. Satu garis lurus bahkan bisa meluruskan hati yang bengkok."},"ICON-0152":{"nm":"Kanvas","de":"Permukaan putih yang kosong adalah yang paling menakutkan, sekaligus paling mendebarkan. Sebelum titik pertama diletakkan, ia bisa menjadi apa saja. Kekosongan bukanlah akhir, melainkan nama lain dari permulaan."},"ICON-0153":{"nm":"Kubus Rubik","de":"Tak sedikit orang yang begadang semalaman berusaha menyusun keenam sisinya. Ketekunan ujung jari yang memutar dan memutar lagi. Saat warna-warna yang tercampur menemukan tempatnya, sebuah semesta kecil tertata rapi."},"ICON-0154":{"nm":"Konsol Genggam","de":"Layar kecil yang dulu ditatap bersama sepupu-sepupu, kepala saling merapat, saat liburan sekolah. Dunia petualangan yang pas tergenggam di telapak tangan. Cukup sepenggal melodi saat dinyalakan, dan seluruh musim panas itu kembali serentak."},"ICON-0155":{"nm":"Grip","de":"Sensasi genggaman yang pas melekat di tangan saat digenggam erat diam-diam memberikan kepercayaan diri. Agar tak licin, agar tak terlepas. Pada saat paling genting, ialah titik sambung yang menyatukan tangan dan alat menjadi satu yang kokoh."},"ICON-0156":{"nm":"Pena Bulu","de":"Selama menulis dengan tinta yang diisi ulang, tulisan tangan pun ikut menjadi sedikit lebih rapi. Menenangkan hati mengikuti suara goresan ujung pena, ia diam-diam menyerupai ketelitian saat memulai baris pertama surat tulisan tangan secara perlahan."},"ICON-0157":{"nm":"Palet Warna","de":"Merah di samping biru, hijau di atas kuning. Di atas papan kecil tempat warna-warna berbaring rapi ini, sebuah gambar akhirnya memperoleh ekspresinya. Semua petualangan mencampur dan menumpuk warna dimulai di sini."},"ICON-0158":{"nm":"Set","de":"Satu per satu terlihat biasa, tapi berjajar bersama menjadi satu kisah utuh. Rasa mantap ketika tak ada kepingan yang hilang dan semua lengkap. Mengumpulkan hal-hal yang berserakan ke satu tempat menyimpan kebahagiaan kecil dari kelengkapan."},"ICON-0159":{"nm":"Kok Bulu Tangkis","de":"Desiran angin lembut yang dihasilkan bulu-bulunya saat melesat naik dari raket. Terlihat terlalu ringan untuk terbang jauh, tapi jika dipukul dengan sungguh-sungguh, ia melesat lurus hingga ujung lapangan. Keringanan pun adalah kekuatan yang sesungguhnya."},"ICON-0160":{"nm":"Antena","de":"Berdiri tenang menghadap langit, berusaha menangkap sinyal yang tak terlihat. Kesabaran yang akhirnya menarik bahkan suara dari kejauhan. Pada hari sinyal kurang jelas, cukup ubah sedikit sudutnya, dan ia jernih kembali."},"ICON-0161":{"nm":"Stetoskop","de":"Ujung bulatnya yang dingin menyentuh dada, dan napas yang tertahan sejenak. Kumpulkan telinga pada satu detak kecil, dan irama tertua dari kehidupan tersalur ke ujung jari. Alat yang mengutamakan mendengar lebih dulu."},"ICON-0162":{"nm":"Bidak Catur","de":"Bidak kecil yang berjalan lambat, satu kotak demi satu kotak. Namun begitu mencapai baris terakhir, ia bisa menjadi apa saja. Papan catur tua diam-diam menyaksikan satu langkah kikuk yang membalikkan seluruh permainan itu."},"ICON-0163":{"nm":"Kontroler","de":"Ingat malam-malam menjelajah semesta hanya dengan dua ibu jari? Grip yang sudah lusuh oleh tangan, yang kau lempar karena kalah lalu dipungut kembali dengan malu-malu. Percakapan terpanjang dan terhangat yang pernah kau bagi tanpa kata dengan seseorang di balik layar."},"ICON-0164":{"nm":"Konsol","de":"Nyalakan dayanya, dan bunyi booting kecil berdering seperti sapaan. Kotak persegi yang dinyalakan dan dimatikan di balik selimut sepanjang liburan, petualangan pertama masa kecil selalu dimulai dari cahaya layar ini."},"ICON-0165":{"nm":"Garis Waktu","de":"Ujung kiri adalah awal, ujung kanan adalah hari yang belum tiba. Seret satu titik ke mana pun di antaranya, dan momen yang kau kira telah terlupakan terbentang kembali. Tempat waktu direbahkan menjadi satu garis."},"ICON-0166":{"nm":"Prisma","de":"Siapa sangka cahaya yang terlihat sebening itu ternyata menyimpan tujuh warna sekaligus. Rahasia yang terurai menjadi pelangi begitu melewati sekeping kaca. Semakin sesuatu tampak rapi, semakin banyak warna tersembunyi di dalamnya."},"ICON-0167":{"nm":"Golf Tee","de":"Satu penyangga kecil untuk meletakkan bola dengan tenang. Semakin jauh kau ingin mengirimnya, semakin dulu kau butuh sesuatu yang menopangnya dengan kokoh. Paku kecil di atas rumput ini menopang langkah pertama."},"ICON-0168":{"nm":"Jarum Rajut","de":"Satu jahitan, lalu satu jahitan lagi. Lewatkan satu saja, dan semuanya harus diurai kembali ke awal. Syal yang perlahan memanjang di pangkuan sepanjang satu musim dingin, tempat kesabaran ujung jari dirajut menjadi kehangatan."},"ICON-0169":{"nm":"Larik Lagu","de":"Sepenggal nada yang bocor bergumam dari bibir sebelum lirik ditempelkan di atasnya. Di dalam melodi yang masih kabur dan belum berkata-kata itu, tersimpan wajah pertama sebuah lagu yang paling jujur."},"ICON-0170":{"nm":"Radar","de":"Menembakkan sinyal ke arah kegelapan yang tak terlihat, lalu diam-diam menunggu satu titik yang kembali. Kesabaran cahaya hijau yang bulat, yang percaya ada sesuatu di sana meski tak terlihat apa pun."},"ICON-0171":{"nm":"Rhythm Pad","de":"Tok tok, ketuk ringan, dan cahaya beserta suara melompat keluar sekaligus. Tempat yang membuat tangan menghafal ketukan lebih dulu daripada kepala. Panggung terkecil dan paling ramah, terbentang di atas telapak tangan."},"ICON-0172":{"nm":"Cat","de":"Perajin zaman dulu menggerus batu dan tanah untuk mendapatkan warna. Nila dari rerumputan, merah dari tanah. Dalam setetes yang kini diperas di ujung jari ini pun, mengalir ketelitian lama yang dulu memindahkan alam dengan hati-hati ke dalam sebuah wadah."},"ICON-0173":{"nm":"Garis","de":"Sesuatu yang baru lahir pada saat kau bertekad menghubungkan titik dengan titik. Pendek atau panjang, melengkung atau lurus, itulah jejak paling sederhana yang ditinggalkan oleh keinginan untuk pergi ke suatu tempat. Awal dari setiap gambar."},"ICON-0174":{"nm":"Rana Kamera","de":"Klik, satu kegelapan singkat itu menahan sebuah adegan untuk selamanya. Bahkan satu ekspresi yang nyaris terlewat dalam sekejap mata, ia iris tipis cahayanya dan mengeraskannya menjadi kenangan. Sebilah pisau kecil."},"ICON-0175":{"nm":"Tali Pengaman","de":"Tali yang terikat kokoh selangkah lebih dulu daripada orang yang mendaki ke tempat tinggi. Ia menahan, menggantikan, hati yang cemas akan jatuh, menjaga di sisi tanpa terlihat, seutas tali janji. Selalu berada di punggungmu."},"ICON-0176":{"nm":"Gembok","de":"Gembok besi yang berat, dulu dikunci pada lumbung. Bukan untuk mengurung sesuatu, melainkan keinginan untuk menyimpan yang berharga dengan tenang. Bahkan tangan yang menguncinya menyimpan ketelitian, kekokohan rumah lama."},"ICON-0177":{"nm":"Timbangan","de":"Ketika satu sisi menjadi berat, sisi lain dengan sendirinya menjadi ringan. Pada saat ragu-ragu menentukan apa dan berapa banyak yang diletakkan, seseorang belajar tentang keadilan. Dua lengan yang mengajarkan keseimbangan dengan bergoyang naik turun."},"ICON-0178":{"nm":"Alat Pembelah","de":"Bahkan yang menyatu erat, jika diikuti seratnya, akhirnya akan terbelah. Alat kecil untuk membagi apa saja menjadi dua dan mengintip isinya. Ujung jari yang penasaran, ingin membongkar kembali apa yang telah disatukan."},"ICON-0179":{"nm":"Penghitung","de":"Satu, dua, tiga. Sahabat kecil yang diam-diam menghitung angka menggantikan jari-jari. Sahabat berhitung yang lembut, mengubah hati yang was-was takut terlewat menjadi lega, klik demi klik."},"ICON-0180":{"nm":"Kursor","de":"Panah kecil yang berkedip di suatu tempat di layar, menunggu perintah berikutnya. Bahkan saat kau ragu-ragu, ia tak pernah meninggalkan tempatnya, ujung cahaya yang diam-diam melambai, mengajak untuk mulai sekarang."},"ICON-0181":{"nm":"Pegangan Panjat","de":"Titik terakhir yang digenggam tepat sebelum kekuatan ujung jari sepenuhnya habis. Ada saat-saat kita bertahan hanya dengan satu tekad untuk tidak melepaskan, begitu tonjolan kecil di dinding itu diam-diam memberitahu."},"ICON-0182":{"nm":"Batu Kerikil","de":"Batu yang lama berguling di sungai kecil, merelakan semua sudutnya. Menjadi bulat adalah nama lain dari waktu yang terkikis. Genggam pelan di telapak tangan, dan kesabaran air sungai yang mengalir bisa dirasakan."},"ICON-0183":{"nm":"Lambang Keluarga","de":"Keluarga bangsawan zaman dulu mengukir hewan dan bintang di selembar bendera untuk menandai diri mereka. Gambar yang menyampaikan hati lebih dulu daripada kata-kata. Tanda kuno yang dengan hati-hati memampatkan kebanggaan seseorang ke dalam satu petak kecil."},"ICON-0184":{"nm":"Perisai","de":"Berdiri menghalangi selalu dilakukan demi orang yang berdiri di belakang punggung. Menerima anak panah yang melesat sebagai gantinya, ia menjaga hari biasa seseorang, dinding yang berat sekaligus penuh kasih."},"ICON-0185":{"nm":"Kebangkitan","de":"Ada hati yang padam lalu menyala kembali. Baru setelah pernah roboh sekali, kau akhirnya belajar cara bangkit kembali. Napas kedua yang diam-diam membuncah di tempat yang kau kira adalah akhir."},"ICON-0186":{"nm":"Busur Panah","de":"Tangan yang ingin mengirim jauh lebih dulu menarik talinya hingga ke ujung. Untuk melepaskan, kau harus lebih dulu mendekapnya sedekat itu, begitu batang busur yang melengkung tegang diam-diam memberitahu tanpa sepatah kata."},"ICON-0187":{"nm":"Hati","de":"Kata aku suka terus-menerus menyusut menjadi bentuk kecil. Bentuk ini tergambar diam-diam di ujung lightstick, juga di sela-sela jari yang saling bersentuhan. Singkatan hati yang paling umum dan paling jujur."},"ICON-0188":{"nm":"Awan","de":"Mengalir perlahan ke arah angin bertiup, ia menjadi wajah yang berbeda setiap kali. Kadang kelinci, kadang kapas, tak pernah lama menahan apa pun dan membiarkan semuanya berlalu, hati langit yang paling ringan."},"ICON-0189":{"nm":"Labirin","de":"Tempat belajar cara berbalik dari dinding jalan buntu. Bahkan saat tersesat, langkah kaki perlahan tumbuh sedikit demi sedikit menuju pintu keluar. Sekali kau harus tersesat agar mata jalanmu terbuka."},"ICON-0190":{"nm":"Gigi","de":"Ada kebiasaan melempar gigi yang tanggal ke atas atap. Doa kecil agar gigi baru tumbuh lurus. Janji lembut masa kecil, bahwa kau harus kehilangan sesuatu sekali, seiring bertumbuh, untuk mendapatkan yang lebih kokoh."},"ICON-0191":{"nm":"Planet","de":"Tubuh bulat yang mengelilingi bintang tanpa pernah sekali pun keluar dari jalurnya. Terlihat kesepian, tapi gravitasinya selalu membuat sesuatu ikut berputar di sampingnya. Diam-diam menjaga tempatnya menjadi satu dunia tersendiri."},"ICON-0192":{"nm":"Bintang","de":"Pada malam-malam tersesat, orang-orang menengadah ke titik paling terang. Cahaya yang tak terjangkau jauhnya, namun tetap jelas menunjukkan arah. Janji yang justru semakin kokoh karena berada jauh di sana."},"ICON-0193":{"nm":"Siluet","de":"Berdiri membelakangi cahaya, dan yang tersisa dari seseorang hanyalah garis luarnya. Satu sosok hitam yang nama dan ekspresinya terhapus. Ruang kosong yang justru membuat kita membayangkan lebih banyak karena ia tidak terisi."},"ICON-0194":{"nm":"Telinga","de":"Untuk bernyanyi dengan baik, kau harus lebih dulu mendengar dengan baik. Baik irama maupun hati, pada akhirnya, dimulai dari mendengarkan. Pintu kecil yang terbuka bulat, tempat segala suara di dunia tiba lebih dulu dan singgah."},"ICON-0195":{"nm":"Daun Gugur","de":"Ada daun yang bersinar paling indah justru pada saat ia jatuh. Keringanan membakar habis kehijauan satu musim menjadi merah, lalu meletakkannya dengan lembut. Musim gugur menunjukkan bahwa sebuah akhir pun bisa seindah ini."},"ICON-0196":{"nm":"Bulan","de":"Ada malam-malam saat orang menangkupkan kedua tangan dan berdoa di bawah cahaya bulat malam panen. Wajah yang tak pernah sama, meski terus mengembang dan menyusut berulang kali. Lentera yang berubah, namun selalu menerangi tempat yang sama."},"ICON-0197":{"nm":"Jantung","de":"Bahkan di atas panggung, yang paling jujur pada akhirnya adalah detak ini. Tak berhenti meski gemetar, dan berdegup lebih keras saat hati membuncah. Genderang kecil berwarna merah yang berdebar menggantikan semangat yang tak sempat terucap kata."},"ICON-0198":{"nm":"Bayangan","de":"Teman yang tak pernah terlepas selama masih ada cahaya. Semakin gelap saat terang, semakin pudar saat redup, satu lagi diriku yang paling lama mengikutiku. Satu sosok yang berdiri di sisi bahkan di hari-hari sendirian."},"ICON-0199":{"nm":"Ekor","de":"Bergoyang dengan sendirinya saat gembira, dan melingkar diam-diam saat takut. Ujung yang jujur, yang tak pernah bisa menyembunyikan hati meski mulut terkatup rapat. Isi hati yang lebih dulu bocor lewat tubuh."},"ICON-0200":{"nm":"Tali Pengikat Ekor","de":"Seutas tali kecil yang diikat di ujung untuk menyelesaikan, seperti pita rambut. Hati yang mengikat simpulnya sekali lagi, kencang, agar tidak terlepas. Ikatan lembut yang mengumpulkan dan menenangkan hal-hal yang mudah berserakan menjadi satu."},"ICON-0201":{"nm":"Manik Mata","de":"Kata-kata bisa dipilih, tapi sorot mata tak bisa disembunyikan. Di sanalah, di balik lingkaran hitam itu, perasaan yang ketahuan pertama kali bocor keluar. Meski kata 'aku suka kamu' tertelan kembali, manik mata sudah lebih dulu bergetar ke arahmu."},"ICON-0202":{"nm":"Tapal Kuda","de":"Sepotong besi yang justru makin kokoh seiring ujungnya terkikis oleh jalan panjang yang ditempuh. Digantung terbalik di atas pintu, konon rezeki yang datang dan pergi akan mengendap di dalamnya. Diam-diam ia menopang kepulangan seseorang dengan selamat."},"ICON-0203":{"nm":"Batu Lambang","de":"Meski hujan dan angin mengikis huruf-hurufnya hingga kabur, saat disentuh ujung jari, guratan yang terpahat kembali hidup dengan jelas. Beban suatu hati yang tak ingin dilupakan. Begitulah sebongkah batu menyimpan sebuah nama untuk waktu yang lama."},"ICON-0204":{"nm":"Selaput Kaki","de":"Dengan selaput tipis yang menghubungkan jari-jari kaki, ia belajar cara mendorong air. Dayung kecil yang diam-diam diselipkan alam ke tangan mereka yang kurang pandai berenang. Rancangan penuh kasih yang, meski lambat, akhirnya tetap mengantarmu sampai ke seberang sungai."},"ICON-0205":{"nm":"Glitter","de":"Semua orang mengomel karena kalau menempel di tangan bisa bertahan berhari-hari, tapi di hari perayaan, butiran cahaya inilah yang paling dulu dicari. Taburkan segenggam debu bintang, dan kertas biasa pun berkilau, hari ini pun jadi istimewa."},"ICON-0206":{"nm":"Cakar","de":"Binatang hutan menggaruk tanah dengan cakarnya untuk meninggalkan jejaknya sendiri. Bukan ancaman, melainkan bekas, tanda tangan diam yang berkata 'aku pernah lewat sini'. Ujung yang tajam pun, bagi seseorang, bisa menjadi penunjuk arah yang penuh kasih."},"ICON-0207":{"nm":"Kilat","de":"Pada sekejap langit membentangkan garis tangannya, cahaya tiba lebih dulu daripada guntur. Seolah menyuruhmu menarik satu tarikan napas sebelum suara besar itu sampai. Rasa takut dan kekaguman selalu lahir bersama dari kilatan cahaya yang sama."},"ICON-0208":{"nm":"Jimat","de":"Satu baris harapan yang ditekan kuat dengan tinta di atas kertas merah. Diselipkan di bawah bantal, konon mimpi buruk akan menyingkir. Hati yang mendoakan keselamatan seseorang bisa sehangat ini, hanya lewat selembar kertas tipis."},"ICON-0209":{"nm":"Sayap Kuas","de":"Ada saat-saat ketika ujung kuas berubah menjadi sayap. Ringannya meluncur di atas kertas ketika satu goresan digambar. Bahwa menulis pada dasarnya adalah sejenis terbang, mungkin sudah samar-samar diketahui oleh tangan lampau yang menggosok tinta."},"ICON-0210":{"nm":"Tulang","de":"Sesuatu yang tersisa hanya setelah semua daging luruh. Rangka putih yang bertahan hingga akhir karena ia yang paling keras. Sekeping bukti yang tenang, yang mengingat bentuknya saja, walau waktu membawa pergi segalanya."},"ICON-0211":{"nm":"Hidung","de":"Aroma adalah jalan pintas tercepat menuju kenangan. Bau minyak di dapur saat hari raya, udara dingin pagi setelah salju pertama turun, ujung hidung yang lebih dulu menyadarinya, dan hati menyusul selangkah di belakang."},"ICON-0212":{"nm":"Roti Panggang","de":"Santapan tercepat yang bisa diraih di pagi yang sibuk. Gigit permukaannya yang keemasan, dan keberanian sehari pun hancur renyah. Hal-hal yang tak perlu mewah, asalkan mengenyangkan, mampu membangkitkan seseorang kembali berdiri."},"ICON-0213":{"nm":"Kukis","de":"Orang yang menunggu paling lama di depan oven mendapat gigitan pertama. Kehangatan pinggirannya yang baru dipanggang, manis yang sekejap. Anehnya, yang dipanggang sambil memikirkan seseorang selalu terasa lebih manis."},"ICON-0214":{"nm":"Camilan","de":"Di sore hari ketika latihan berlangsung lama, sebungkus kecil dikeluarkan dari dasar tas. Dibagi dua, rasa kenyangnya anehnya justru berlipat ganda. Segenggam kelembutan hati yang mengisi hati lebih dulu daripada mengisi perut lapar."},"ICON-0215":{"nm":"Kapsul","de":"Tak seorang pun tahu isinya sampai memutar dan membukanya. Yang ada di dalam cangkang bulat itu selalu debaran hati yang sama. Kegembiraan paling jujur di dunia, tempat kebetulan kecil diperjualbelikan."},"ICON-0216":{"nm":"Gagang Pintu","de":"Tempat yang paling dulu disentuh oleh tak terhitung tangan yang membuka dan menutup pintu. Sapaan pertama rumah, yang dingin di awal lalu menghangat di telapak tangan. Semakin banyak bekas sentuhan menumpuk, ruangan itu perlahan menjadi rumah bagi seseorang."},"ICON-0217":{"nm":"Jalan-Jalan","de":"Berjalan tanpa tujuan pun punya alasannya sendiri. Waktu untuk menguraikan pikiran yang kusut, seuntai demi seuntai, ke dalam langkah kaki. Setelah berputar satu putaran dan kembali, jawabannya memang tetap sama, tapi hati saja terasa jauh lebih ringan."},"ICON-0218":{"nm":"Skuter","de":"Dua roda yang melaju membelah gang sempit. Tak perlu cepat, asal angin menerpa seluruh tubuh. Ada hari-hari ketika kau hanya ingin melaju dengan segar hari ini, biarpun tak bisa pergi jauh."},"ICON-0219":{"nm":"Palang Pengaman","de":"Sebelum naik, sebatang palang turun kukuh di depan dada. Janji yang menenangkan, yang menemanimu bertahan hingga akhir bagian yang menakutkan. Tanpa sepatah kata pun, dengan dinginnya sendiri ia mengatakan, tak apa untuk berpegangan erat."},"ICON-0220":{"nm":"Tangga","de":"Menaiki satu anak tangga demi satu, dan tanpa terasa pemandangan pun berubah. Telapak kaki lebih dulu belajar bahwa tak ada ketinggian yang bisa dicapai dalam satu lompatan. Naik-turun itu sendiri, bagi seseorang, adalah langkah sehari penuh."},"ICON-0221":{"nm":"Terarium","de":"Ini bukan mengurung hutan di dalam kaca, melainkan merawat sebuah dunia dengan sepenuh hati. Semesta seukuran telapak tangan, tempat lumut menyebar dan tetesan air terbentuk. Semakin lama menatapnya, hati pun perlahan terwarnai hijau."},"ICON-0222":{"nm":"Podium","de":"Naik ke tempat yang lebih tinggi sejengkal saja, dan pemandangan yang terlihat pun berubah. Tempat di mana rasa takut dan rasa bangga bertemu pada ketinggian yang sama. Tergantung siapa yang berdiri di sana, satu anak tangga itu setiap kali menjadi panggung yang berbeda."},"ICON-0223":{"nm":"Pesawat Terbang","de":"Pada saat awan terhampar di bawah kaki, tempat yang ditinggalkan baru terasa dirindukan. Ini bukan menjauh, melainkan dunia yang semakin meluas. Mimpi yang tumbuh di pulau kecil pun menyeberangi langit seperti ini."},"ICON-0224":{"nm":"Papan Seluncur","de":"Sesuatu yang baru bisa dikendarai setelah lebih dulu belajar cara terjatuh. Setiap kali lutut tergores, keseimbangan sedikit demi sedikit terukir di dalam tubuh. Empat roda yang jujur, yang menggelinding semakin jauh untuk setiap kejatuhan yang baik."},"ICON-0225":{"nm":"Paspor","de":"Buka sampulnya, dan penuhlah halaman-halaman kosong. Setiap cap yang akan mengisinya kelak menjadi bukti sebuah kehidupan yang dijalani. Buku kecil yang menyimpan bukan seberapa jauh kau pernah pergi, melainkan kemungkinan untuk pergi ke mana saja."},"ICON-0226":{"nm":"Peta Sketsa","de":"Tak ada jarak atau skala yang tepat, tapi karena jalan ini digambar dengan tangan, tak ada rasa takut tersesat. Kertas tempat gang-gang dan nama toko bertautan dengan akrab. Petunjuk yang disertai hati selalu lebih hangat daripada jalan itu sendiri."},"ICON-0227":{"nm":"Denah Pergerakan","de":"Kertas tempat setiap langkah kaki di atas panggung digambar sebagai garis. Di mana harus berhenti, di mana harus berputar, panah-panah itu sudah menjanjikannya lebih dulu. Bahkan tarian yang tampak bebas sesungguhnya bermula dari selembar kertas ini."},"ICON-0228":{"nm":"Denah Tempat Duduk","de":"Di ruang yang asing, hal pertama yang diraba-raba untuk dicari adalah tempat duduk sendiri. Mengikuti baris dan nomor hingga akhirnya sampai di satu petak itu. Selembar kertas mendudukkan ribuan debaran hati, rapi, masing-masing di tempatnya."},"ICON-0229":{"nm":"Kartu Panduan Gang","de":"Petunjuk yang ditulis tangan seseorang untuk mereka yang mungkin tersesat di gang-gang seperti labirin. Tulisan yang ramah, memberi tahu belok di tikungan keberapa. Keramahan sebuah kampung tertuang rapi dalam selembar kartu kecil."},"ICON-0230":{"nm":"Kartu Keamanan","de":"Hanya dengan menggantungkan kartu ini di leher, pintu ke dunia bagian dalam akhirnya terbuka. Izin kecil yang mengabulkan akses masuk, sekaligus tanda diam bahwa kau termasuk di sini. Hanya mereka yang tahu berapa lama waktu untuk mendapatkannya yang mengerti bobotnya."},"ICON-0231":{"nm":"Gelang Akses Harian","de":"Kenakan sekali di pergelangan tangan, dan kau menjadi bagian dari hari itu hingga dilepas. Selembar pita kertas memisahkan dalam dan luar, sekaligus menjadi tanda bahwa kalian melewati hari yang sama bersama. Bahkan setelah diputuskan, bekasnya bertahan cukup lama."},"ICON-0232":{"nm":"Label Tamu","de":"Dengan selembar tanda pengenal kecil yang ditempel di dada, tempat yang asing pun menjadi tempatmu. Ketika kata selamat datang dititipkan pada selembar kertas dan disodorkan, bahkan orang yang baru pertama kali datang akhirnya menjadi tamu."},"ICON-0233":{"nm":"Tabung Poster","de":"Silinder kukuh yang menjaga poster yang digulung tetap tanpa satu lipatan pun. Sebab semakin berharga sebuah gambar, semakin harus dikirim dalam keadaan lurus. Walau isinya tak terlihat, ia berangkat membawa ketulusan seseorang."},"ICON-0234":{"nm":"Sampul Berkas","de":"Halaman pertama yang membungkus tumpukan berkas yang tebal. Wajah yang tersentuh tangan lebih dulu daripada isinya. Ketika sampulnya rapi, bahkan sikap hati di dalamnya pun tampak rapi, awal yang lembut dari sebuah formalitas kecil."},"ICON-0235":{"nm":"Kartu Pos Kenangan","de":"Sepotong kabar ditulis di atas serpihan pemandangan dari tempat yang jauh, lalu dikirimkan. Saat tiba nanti, hati yang dikirim pun ikut sedikit menua, dan justru semakin akrab karenanya. Kehangatan lambat sepucuk surat tulisan tangan, yang tak pernah bisa dikejar oleh pesan di layar."},"ICON-0236":{"nm":"Label Hadiah","de":"Selembar kertas kecil yang diikatkan pada hadiah. Hanya dengan tiga kata 'untukmu', pembungkusnya sudah lengkap sepenuhnya. Surat terpendek di dunia, yang menuliskan bukan apa yang diberikan, melainkan siapa yang teringat."},"ICON-0237":{"nm":"Gulungan Stiker Pembungkus","de":"Setiap kali disobek selembar untuk dipakai, hasil akhirnya menjadi semakin rapi. Simpul kecil yang dengan tertib menahan ujung yang hendak lepas. Sentuhan terakhir dari bungkusan yang dikemas sepenuh hati selalu datang dari pita gulungan ini."},"ICON-0238":{"nm":"Sampul Surat Bening","de":"Selapis bening yang membungkus surat tulisan tangan agar tak pudar dimakan waktu. Hurufnya tetap terlihat jelas, tapi bekas sentuhan tangan tak sampai menyentuhnya. Selaput tak kasatmata ini diam-diam menjaga hati seseorang yang menyayangi."},"ICON-0239":{"nm":"Segel Lilin Warna","de":"Titik terakhir yang menutup sebuah amplop, semakin cerah warnanya, semakin hati tak bocor keluar. Sebuah janji bahwa tak ada tangan yang menyentuhnya sebelum disobek. Bahkan rahasia butuh simpul yang secantik ini."},"ICON-0240":{"nm":"Buku Label Pesan","de":"Buku kecil yang menjilid catatan-catatan pendek menjadi satu. Setiap lembarnya adalah sepatah kata untuk disampaikan pada seseorang. Kumpulkan rapi kata-kata yang belum sempat terucap, dan suatu hari keberanian untuk pasti menyampaikannya akan tumbuh."},"ICON-0241":{"nm":"Papan Petunjuk Lipat","de":"Dibuka berkata 'lewat sini', dilipat berkata 'cukup sampai di sini untuk hari ini'. Kaki terentang berdiri di mulut gang, berdiri sepanjang hari demi seseorang yang mungkin tersesat. Senja saat ia terlipat adalah istirahat paling lembut bagiku."},"ICON-0242":{"nm":"Pita Pengikat Surat","de":"Peluk setumpuk kartu pos dengan melilitkannya di pinggang, dan kabar-kabar yang hampir berserakan akhirnya menjadi satu ikatan hati. Sepotong pita ringan mengikat rapi kata-kata yang akan pergi ke tempat jauh, dan diam-diam melepas kepergian punggung yang berangkat."},"ICON-0243":{"nm":"Bundel Catatan Terima Kasih","de":"Karena kata terima kasih selalu tergelincir dari lidah, ditulislah ia di atas kertas seukuran telapak tangan dan diikat diam-diam. Semakin tebal ikatannya, semakin tebal pula, sejalan, hati yang berutang pada seseorang."},"ICON-0244":{"nm":"Lembar Contoh Yel-Yel","de":"Selembar contoh bertuliskan 'teriakkan begini'. Sorakan yang belum diberi suara hanya menyimpan debaran diam, seperti partitur kosong yang menunggu ketukan pertama."},"ICON-0245":{"nm":"Memo Permintaan Pra-Rekaman","de":"Memo yang menuliskan permintaan untuk mendapat jadwal rekaman sebelum siaran selalu tertulis di kolom jam lima pagi. Hati yang memangkas tidur demi mengamankan tempat, seolah dipahami sepenuhnya, dicatat diam-diam oleh selembar kertas kecil ini."},"ICON-0246":{"nm":"Tiket Urutan Fansign","de":"Selembar tiket yang menentukan urutan keberapa kau akan menyapa. Mengantre bukanlah menunggu giliran, melainkan sejenak meminjam urutan karena tak bisa memberi angka pada seberapa besar rasa suka."},"ICON-0247":{"nm":"Gelang Nomor Antrean","de":"Satu angka menentukan urutan antrean hari ini. Entah di depan atau di belakang, orang-orang yang mengenakan pita kecil dan ringan ini di pergelangan tangan, pada akhirnya adalah kawan seperjuangan dengan satu hati yang berkumpul untuk menyaksikan panggung yang sama."},"ICON-0248":{"nm":"Tabel Sortir Photocard","de":"Wajah yang sama tapi katanya semua berbeda, dicatat terpisah petak demi petak. Semakin penuh tabelnya, semakin rapi hatinya, dan satu petak kosong yang tersisa membuat dada berdebar dengan keinginan untuk mengisinya hari ini."},"ICON-0249":{"nm":"Daftar Periksa Album","de":"Versi, photocard, bahkan segel, daftar kasih sayang yang tercatat dalam angka. Membayangkan lebih dulu kebanggaan hari semuanya terisi penuh, hari ini pun sebuah lingkaran kecil digambar rapi di satu baris."},"ICON-0250":{"nm":"Catatan Panduan Yel-Yel","de":"Bentuk tangan, ketukan saat berteriak, bahkan titik untuk menarik napas. Agar bahkan orang yang baru pertama datang cepat berbaur dalam satu suara, catatan kecil ini menjadi penunjuk jalan yang ramah, berpindah dari tangan ke tangan."},"ICON-0251":{"nm":"Buku Catatan Pribadi","de":"Hanya kalimat yang tak akan ditunjukkan pada siapa pun yang dipilih untuk ditulis di sini. Bahwa halaman yang belum pernah dibuka adalah yang paling jujur, buku catatan ini menjaganya diam-diam dengan sampul yang selalu tertutup."},"ICON-0252":{"nm":"Lembar Stempel Hari Peringatan","de":"Ditekan, dan satu hari lagi menjadi istimewa. Dengan satu stempel kecil yang ditekan di atas tanggal biasa, hari ini diam-diam mendaftarkan namanya ke dalam daftar hari-hari yang ingin dikenang."},"ICON-0253":{"nm":"Sampul Papan Jepit","de":"Meski angin bertiup, meski hujan menampar, ia menjaga kertas yang terjepit hingga akhir. Aku, yang menjadikan diriku sebagai baju zirah papan ini, adalah pengawal setia bagi huruf-huruf yang tertulis."},"ICON-0254":{"nm":"Indeks Berkas","de":"Agar tak tersesat di antara berkas yang tebal, ia menjulurkan lidah kecilnya dan memberi tahu di sini. Selembar tab berwarna-warni menguasai seratus halaman hanya dalam sekali pandang."},"ICON-0255":{"nm":"Label Tab Kategori","de":"Ini di petak ini, itu di petak itu. Tugasku adalah merapikan kekacauan dunia satu baris demi satu baris. Saat label ditempelkan, hal-hal yang tadinya berantakan akhirnya menemukan tempatnya."},"ICON-0256":{"nm":"Papan Persetujuan Mini","de":"Saat stempel ditekan sekali, entah kenapa terasa seperti benar-benar menjadi orang dewasa. Ukurannya kecil tapi wibawanya sigap, satu stempel disetujui saja dan pekerjaan yang menumpuk pun tuntas dengan cepat."},"ICON-0257":{"nm":"Kantong Berkas Bening","de":"Bagian dalamnya terlihat jelas, tak ada yang disembunyikan. Sambil membawa kertas penting, ia membungkusnya dengan tubuh beningnya sendiri agar tak basah hujan atau kusut, dan mengantarnya sampai ke tempat janji temu."},"ICON-0258":{"nm":"Pita Absensi","de":"Datang, dan satu petak lagi terisi. Ketika jejak setiap hari menumpuk berbaris sepanjang pita, ketekunan yang tak terlihat akhirnya menjadi pola yang tampak jelas sekali pandang."},"ICON-0259":{"nm":"Buku Catatan Kesalahan","de":"Menuliskan yang salah bukanlah mengumpulkan rasa malu. Agar tak tersandung dua kali di tempat yang sama, kesalahan kemarin ditulis ulang menjadi penunjuk jalan untuk hari ini."},"ICON-0260":{"nm":"Papan Stempel Jadwal","de":"Tekan satu stempel di jadwal yang kosong, dan lahirlah sebuah janji. Sihir sebuah hari yang ditentukan hanya dengan satu kibasan pergelangan tangan, sihir itu sebenarnya adalah nama lain dari ketekunan mempersiapkan diri jauh-jauh hari."},"ICON-0261":{"nm":"Label Punggung Buku","de":"Tanda pengenal buku-buku yang berdiri membelakangi rak. Huruf-huruf pendek yang tertulis di punggung yang sempit itu, dengan sekali lambaian, memanggil keluar buku yang tengah dicari di antara ratusan lainnya."},"ICON-0262":{"nm":"Pelindung Foto","de":"Tangan kosong dilarang. Sambil berkata jangan sampai meninggalkan satu sidik jari pun, ia lembut menutupi tubuhnya di atas satu bidikan yang berharga. Hati yang menyayangi bertahan lama begitu, lewat sentuhan yang begitu berhati-hati."},"ICON-0263":{"nm":"Lembar Indeks Film","de":"Beri nomor pada setiap potongan film, dan momen-momen yang berserakan pun menemukan kembali urutan ceritanya. Penunjuk kecil yang merawat kenangan yang tertulis dengan cahaya agar tak tertukar."},"ICON-0264":{"nm":"Kantong Sampul Foto","de":"Rumah bening tempat kebahagiaan berbentuk persegi disimpan satu per satu dengan hormat. Tanpa khawatir sudutnya tertekuk, wajah yang paling disayang bersinar rapi di dalamnya sepanjang empat musim."},"ICON-0265":{"nm":"Amplop Foto Mini","de":"Sebelum kehangatan foto yang baru dicetak sempat mendingin, sebuah amplop kecil membentangkan kedua lengannya untuk menyambut. Satu bidikan yang masuk lewat mulut seukuran telapak tangan itu, tanpa terasa, menjadi harta karun di dalam tas seseorang."},"ICON-0266":{"nm":"Sampul Lentikular","de":"Menjaga tanpa satu goresan pun sebuah foto rewel yang ekspresinya berubah saat dimiringkan, itulah misiku. Berusaha melindungi setiap wajah berbeda di setiap sudut, akulah yang tak boleh kalah rajin."},"ICON-0267":{"nm":"Label Sortir Cut","de":"Dari empat cut, mana yang terbaik, labelnya yang menunjukkan. Tugas kecil memisahkan yang hasilnya bagus dan yang lucu, berdampingan, adalah rahasia untuk menikmati sebuah kenangan dua kali."},"ICON-0268":{"nm":"Pita Penyimpan Foto Strip","de":"Ia melilit rapi kenangan empat petak yang sempit dan panjang. Memeluk erat tawa hari itu yang hampir berserakan menjadi satu ikatan, dan membawanya dengan selamat sampai ke dasar tas."},"ICON-0269":{"nm":"Stiker Sudut Foto","de":"Saat menempelkan foto di album, tangan kecil yang lembut memegang keempat sudutnya. Agar tak lepas tanpa perlu melumuri lem, kelembutan begitulah dimulai dari sudut."},"ICON-0270":{"nm":"Tabel Koreksi Cetak","de":"Sedikit lebih hangat, sedikit kurang terang. Selembar tabel tempat angka-angka diutak-atik sampai warna yang disukai muncul, diam-diam mengubah satu bidikan biasa menjadi sebuah karya."},"ICON-0271":{"nm":"Klip Struk","de":"Ia menggigit rapi struk-struk yang kusut dan tak melepaskannya. Dengan mulut kecilnya ia menjaga pengeluaran sehari dengan cermat, sehingga penghitungan akhir bulan pun jadi jauh lebih ringan."},"ICON-0272":{"nm":"Bukti Konfirmasi Reservasi","de":"Pada satu baris reservasi telah dikonfirmasi, hati pun perlahan lega. Selembar kertas menjadi bukti sebuah janji, menyimpan debaran hati rapi hingga tiba hari yang dinanti."},"ICON-0273":{"nm":"Bukti Pengembalian","de":"Bukti kecil namun tegas bahwa yang dipinjam telah dikembalikan ke tempatnya. Saat kertas ini berada di tangan, satu utang yang membebani sudut hati pun terhapus dengan ringan."},"ICON-0274":{"nm":"Tempat Bukti Titipan","de":"Agar tiket untuk mengambil barang yang dititipkan tak hilang, biar aku yang memegangnya erat-erat untukmu. Sebab keberadaan selembar kertas kecil pun bisa menentukan akhir hari seseorang."},"ICON-0275":{"nm":"Ekor Label Peminjaman","de":"Sepotong label kecil yang bergoyang di setiap barang yang dipinjam. Ikuti ekor ini, dan langsung terungkap siapa membawa apa, sehingga misteri barang hilang pun cepat terpecahkan."},"ICON-0276":{"nm":"Lembar Centang Pemeriksaan","de":"Satu per satu diraba dengan mata untuk memastikan tak ada yang terlewat. Saat tanda centang terisi berbaris, ketelitian yang tak terlihat akhirnya mendapat nama: kepercayaan."},"ICON-0277":{"nm":"Amplop Catatan Perhitungan","de":"Tuliskan uang yang masuk dan keluar di atas amplop, dan angka-angka yang berserakan pun tenang berbaris. Akhir dari sebuah perhitungan selalu diberi titik penutup oleh memo kecil ini dengan tenang."},"ICON-0278":{"nm":"Label Pengiriman","de":"Sambil menuliskan ke mana ia akan pergi dan kepada siapa ia akan sampai di tubuhnya sendiri, ia berangkat. Begitu label ini ditempelkan, kotak itu menjadi seorang pelancong dengan tujuan dan berangkat dengan penuh debaran."},"ICON-0279":{"nm":"Pita Konfirmasi Penerimaan","de":"Ia mengikat sepatah kata sudah diterima dengan baik ke dalam satu pita dan mengirimkannya kembali. Kelegaan orang yang menerima dan rasa tenang orang yang mengirim diam-diam berjabat tangan di atas tali kecil ini."},"ICON-0280":{"nm":"Cincin Kartu Kata","de":"Kata-kata yang akan hilang jika berserakan sebagai lembaran lepas, dirangkai dan digenggam erat oleh sebuah cincin kecil. Membolak-balik lagi dan lagi, kata-kata yang dulu asing pun tanpa terasa menjadi sahabat yang akrab di lidah."},"ICON-0281":{"nm":"Pita Catatan Pelafalan","de":"Sebuah tanda kecil digantungkan di tempat ujung lidah terus tergelincir. Bahkan bunyi asing yang tersesat di dalam mulut menemukan pelafalannya sendiri, tanpa terasa, dengan mengikuti catatan ini. Halaman pertama menjinakkan bunyi yang canggung, sedikit demi sedikit."},"ICON-0282":{"nm":"Kotak Catatan Terjemahan","de":"Jembatan-jembatan kecil yang menyeberangi antara kata dan kata terlipat rapi di setiap kotaknya. Tuliskan sepatah kata yang dipilih dengan susah payah dan sodorkan diam-diam, dan bahkan hati yang tak tersampaikan pun menjadi lebih dekat lewat selembar catatan di antaranya."},"ICON-0283":{"nm":"Kliping Kutipan","de":"Kalimat yang tepat mengenai hati hanya akan bertahan lama jika disalin dengan tangan. Tempelkan satu baris yang digunting dari sudut buku di depan meja, dan huruf-huruf itu diam-diam menopang hari yang sedang tenggelam."},"ICON-0284":{"nm":"Indeks Catatan","de":"Bendera-bendera kecil berwarna-warni yang diselipkan agar tak tersesat di dalam buku yang tebal. Hanya dengan tahu tempat untuk kembali, kau bisa mengembara lebih jauh, begitulah tab-tab yang menyembul diam-diam memberi tahu dari sela-sela halaman."},"ICON-0285":{"nm":"Chip Centang Hafalan","de":"Satu tanda yang ditekan di samping apa yang sudah dihafal. Menjadi jangkar kecil yang menahan hal-hal yang sekilas singgah di kepala lalu hendak menghilang, setiap petak yang terisi hitam diam-diam menyimpan usaha yang tercurah semalam."},"ICON-0286":{"nm":"Paket Amplop Kuis","de":"Sampai amplop itu disobek, tak seorang pun tahu apa yang akan keluar. Beberapa detik saat jari-jari mengutak-atik bagian yang tersegel, bungkusan debaran yang menyegel bersamaan sebuah pertanyaan yang terlipat rapi di dalamnya beserta gemuruh hatinya."},"ICON-0287":{"nm":"Buku Catatan Tab Tata Bahasa","de":"Aturan bukan dihafal dengan kepala, melainkan dibiasakan oleh tangan. Dari tab berwarna di halaman yang paling sering dibuka hingga buku catatan yang perlahan melunak dan lusuh, sudut yang aus itu menjadi lingkaran tahun dari waktu yang telah kau lewati."},"ICON-0288":{"nm":"Tabel Latihan Berbicara","de":"Selembar tabel untuk orang yang merasa membuka mulut adalah hal tersulit di dunia. Telusuri petak demi petak dengan jari, dan kata pertama yang gemetar di tenggorokan pun menemukan suaranya sendiri, tanpa terasa. Sebab keberanian pun ada gilirannya."},"ICON-0289":{"nm":"Lembar Sketsa Warna","de":"Warna-warna sebelum selesai berbaring kasar, mengatur napas. Bukan jawaban yang benar, melainkan sebuah kemungkinan yang masih ada, di atas selembar kertas yang belum dirapikan ini, lebih banyak hari esok daripada apa pun bergoyang-goyang di dalamnya."},"ICON-0290":{"nm":"Potongan Mood Board","de":"Kumpulkan dan tempelkan kesan-kesan yang berserakan satu per satu di satu tempat, dan suasana yang sulit tergenggam pun samar-samar menampakkan garis besarnya. Sebuah rasa yang masih tanpa nama, potongan-potongan itu saling bersandar dan diam-diam menunjuk ke arahnya."},"ICON-0291":{"nm":"Buku Contoh Pola","de":"Kisi-kisi kain pembungkus dan anyaman jeruji jendela tersusun rapi dalam satu buku. Di tempat pola yang sama diulang sampai akhir, yang bersemayam bukan kemalasan, melainkan janji, hati yang teguh menjaga satu corak."},"ICON-0292":{"nm":"Lembar Swatch Kostum","de":"Meski cahayanya sama, tekstur dan bayangan menempel berbeda pada setiap potongan kain. Sebelum memilih kostum panggung, malam yang dihabiskan ragu-ragu sambil mengelusnya puluhan kali dengan ujung jari itu terekam utuh dalam sebuah contoh kain kecil."},"ICON-0293":{"nm":"Lembar Panduan Larangan Logo","de":"Kertas yang lebih dulu menuliskan dengan jelas hal-hal yang tak boleh dilakukan. Di dalam garis yang dicoret tanda silang merah, justru kebebasan menjadi semakin jelas, sehingga di tempat yang dikira jalan buntu, malah terbuka jalan baru."},"ICON-0294":{"nm":"Chip Referensi Warna","de":"Warna yang sama sekali tak bisa dijelaskan dengan kata-kata, dibuatlah sepotong contoh tersendiri. Ia mengurung di atas telapak tangan kecilnya sebuah saat ketika langit senja paling merah, agar bisa disampaikan tepat pada orang berikutnya: inilah warnanya, persis."},"ICON-0295":{"nm":"Kartu Sketsa Tata Letak","de":"Gambar pertama yang digoreskan ringan tentang apa diletakkan di mana. Menentukan tempat pada dasarnya adalah menentukan hati, sehingga di antara garis-garis yang tercecer canggung, keseimbangan keseluruhan perlahan membuka matanya."},"ICON-0296":{"nm":"Papan Catatan Bahan","de":"Kayu, tanah, batu, nama benda-benda yang bisa disentuh tertulis rapat. Rahasia yang hanya diketahui oleh mereka yang mulai dengan membaca seratnya lebih dulu dengan tangan, dengan apa dibangun sudah menentukan setengah dari apa yang akan menjadi."},"ICON-0297":{"nm":"Kertas Kalkir Pola","de":"Letakkan kertas tipis di atas sketsa dan diam-diam telusuri garisnya. Selagi sejenak meminjam jalan orang lain, tanganmu belajar jalan itu, dan di antara garis-garis yang ditiru, tanpa terasa tumbuh diam-diam garis milikmu sendiri."},"ICON-0298":{"nm":"Pita Alur Masuk","de":"Orang-orang berbaris masuk mengikuti pita yang menempel panjang di lantai. Satu garis yang diam-diam menuntun agar langkah yang riang tak kusut, tangan lembut tak kasatmata yang menopang debaran hati agar tak runtuh."},"ICON-0299":{"nm":"Papan Petunjuk Acara","de":"Papan yang berdiri menggantikan sepatah kata lewat sini. Kebaikan kecil yang didirikan di setiap persimpangan agar tak ada yang tersesat, menuntun hari yang asing bagi seseorang yang baru pertama datang, seolah menggandeng tangannya dengan tenang."},"ICON-0300":{"nm":"Label Nomor Stan","de":"Satu nomor yang diberikan pada setiap stan dengan jelas menentukan pemilik petak itu. Angka kecil, namun sebuah janji bahwa di sinilah tempatmu, sehingga di acara yang asing pun tercipta tempat untuk kembali."},"ICON-0301":{"nm":"Formulir Persetujuan Staf","de":"Satu goresan tanda tangan yang ditinggalkan di tempat hati-hati bersepakat untuk bekerja sama. Hanya selembar kertas tipis, namun di dalamnya tersimpan bobot keputusan untuk saling percaya, dan setiap uluran tangan dalam acara ini bermula persis dari sini."},"ICON-0302":{"nm":"Ikatan Tiket Percobaan","de":"Segepok tiket percobaan yang diikat tebal agar pas digenggam sebelah tangan. Semakin banyak dibagikan, ia tak makin menyusut, melainkan makin banyak menghadirkan \"pertama kali\" bagi orang lain—ikatan kebaikan hati yang semakin hangat setiap kali disentuh."},"ICON-0303":{"nm":"Lembar Penanda Antrean","de":"Mulai dari sini, silakan menunggu, bisik lantai itu perlahan. Ketika hati-hati yang menjaga giliran berkumpul, antrean panjang pun menjadi sebuah pemandangan tersendiri, dan satu penanda kecil mengubah ketergesaan menjadi ketenangan."},"ICON-0304":{"nm":"Label Pengambilan di Tempat","de":"Label kecil yang tersemat di tempat mengambil langsung pesanan yang sudah dipesan sebelumnya. Begitu berada di tangan, kelegaan lembut itu langsung mengalir turun dari bahu—sebuah simpul tempat hati yang lama menunggu akhirnya menemukan wujudnya."},"ICON-0305":{"nm":"Tiket Kotak Misteri","de":"Kesenangan memilih satu tanpa tahu isinya. Guncang sedikit, dan bunyi gemerincing di dalamnya membuat jantung berdebar lebih dulu, lalu sesaat sebelum dibuka menjadi waktu paling menggelembung penuh harap sepanjang hari."},"ICON-0306":{"nm":"Stiker Tukar Selesai","de":"Stempel kecil bulat yang mengabarkan bahwa pertukaran telah berjalan lancar. Ia adalah titik penutup yang halus di antara tangan yang memberi dan menerima, dan begitu ditempelkan, transaksi itu barulah bulat dan hangat sepenuhnya."},"ICON-0307":{"nm":"Pita Segel Arsip","de":"Sebuah kotak berharga dililit sekali oleh pita dan disegel dengan tenang. Sebuah permintaan agar tidak dibuka sembarangan, sekaligus kesopanan paling diam yang menghargai isi di dalamnya sedemikian rupa, semuanya tersimpan dalam satu untai pita."},"ICON-0308":{"nm":"Kapsul Memo Rahasia","de":"Sepatah kata yang ingin diucapkan disimpan rapi terkunci dalam tabung kecil. Menutupnya erat-erat bagaikan mengubur perasaan yang tak sempat terkirim, dan sebuah brankas mungil di telapak tangan menjaga waktu sampai hari ketika kau membukanya kembali."},"ICON-0309":{"nm":"Kartu Kliping Kecil","de":"Sepotong guntingan yang ditempel menyimpan samar suasana hari itu. Lebih ringan dari buku harian dan lebih terasa buatan tangan daripada foto—selembar kertas seukuran telapak tangan menahan erat sehari yang mudah lolos dari sela jari."},"ICON-0310":{"nm":"Lembar Catatan Kunjungan Pertama","de":"Getar hari pertama menginjakkan kaki di pulau ini tertinggal dalam satu baris singkat. Tepat sebelum keasingan berubah menjadi kehangatan, kertas ini menyimpan perasaan pertama yang paling jernih itu menggantikan dirimu, dan menjaganya lama."},"ICON-0311":{"nm":"Bagan Klasifikasi Kenangan","de":"Sebuah bagan tempat kenangan dipilah rapi menurut jenis dan cabangnya, dituliskan satu demi satu. Jika semua ingatan ditumpuk sembarangan dalam satu laci, bahkan hari yang paling disayangi pun bisa terkubur, maka semakin berharga sesuatu, semakin lembut pula tempatnya ditentukan."},"ICON-0312":{"nm":"Chip Memo Balon Kata","de":"Kata-kata yang ingin diucapkan menggembung bulat seperti balon dan melayang di atas kertas. Bahkan sepatah kata yang tak sanggup terucap lewat mulut diam-diam menemukan keberanian di dalam bingkai bundar itu—jalan kecil nan hangat tempat hati menyelinap keluar."},"ICON-0313":{"nm":"Penyangga Tanggal","de":"Penyangga kecil yang menegakkan tanggal hari ini agar berhadapan langsung denganmu. Memilih satu hari saja dari deretan hari yang terus mengalir dan mendudukkannya di depan, membuat tanggal yang biasa saja pun memancarkan kehangatan yang layak dirayakan."},"ICON-0314":{"nm":"Label Nomor Koleksi","de":"Nomor unik yang disematkan pada setiap benda yang disayangi. Mengoleksi berarti berikrar untuk menyebut benda itu sebagai satu-satunya di dunia, sehingga angka di label kecil itu terukir jelas dengan bobot hati."},"ICON-0315":{"nm":"Selip Arsip","de":"Sampul dalam tipis tempat menyelipkan satu per satu benda yang ingin disimpan lama. Menjauhkannya selapis tipis dari cahaya dan waktu—menyayangi sesuatu, pada akhirnya, adalah pekerjaan menyimpannya dengan baik."},"ICON-0316":{"nm":"Tali Toploader Photocard","de":"Tali tipis yang memungkinkan toploader digantung di leher. Ini adalah cara ber-fandom, membawa bias di dekat dada sepanjang hari, dan pada seutas tali tipis ini terikat seluruh kebersamaan lembut sepanjang hari."},"ICON-0317":{"nm":"Pin Penyangga Photocard","de":"Dengan satu pin kecil, photocard berdiri tegak di atas meja. Terbaring, ia hanyalah selembar kertas, namun berdiri ia menjadi wajah yang saling bertatapan, diam-diam menciptakan tempat bagi pandangan untuk berlama-lama."},"ICON-0318":{"nm":"Film Holografik Photocard","de":"Selapis film tipis tempat pelangi mengalir mengikuti setiap sudut pandang. Lapisan yang menangkap sedikit cahaya ini membalut kartu biasa dengan kilau bintang, sebuah sihir kecil di mana ekspresi berbeda terbangun berkilau setiap kali pergelangan tangan menyentaknya."},"ICON-0319":{"nm":"Pelindung Sudut Photocard","de":"Sekali saja sudutnya tertekan, rasanya hati yang disayangi ikut terlipat juga. Sebuah zirah bening yang mendekap erat selembar kartu berharga, dan kehati-hatian semacam ini selalu menyertai sesuatu yang sungguh-sungguh disayangi."},"ICON-0320":{"nm":"Baki Penyusun Photocard","de":"Baki dangkal yang membaringkan puluhan photocard rapi berjajar sesuai urutannya. Berserakan, ia hanya tumpukan biasa, namun tersusun berbaris ia menjadi sebuah koleksi, dan urutan kasih sayang terukir rapi lapis demi lapis dari setiap tangan yang merapikannya."},"ICON-0321":{"nm":"Amplop Tukar Photocard","de":"Saat menyelipkan selembar photocard ke dalam amplop untuk diserahkan, ujung jari sejenak ragu. Ini bukan melepas kepergian, melainkan permintaan agar ia menjadi bias seseorang. Begitu lipatan amplop ditutup, sebuah ikatan kecil diam-diam berpindah tangan."},"ICON-0322":{"nm":"Pena Hias Photocard","de":"Yang mengisi ruang kosong bukanlah tulisan, melainkan perasaan. Di setiap tempat mata pena melintas, hati dan bintang kecil bermunculan, dan selembar kertas biasa terbangun menjadi dukungan yang satu-satunya di dunia. Menghias hanyalah nama lain dari pengakuan hati."},"ICON-0323":{"nm":"Ring Jepit Photocard","de":"Klik, bunyi jepitan yang mengatup. Dengan satu kunci kecil itu, kartu-kartu yang nyaris berserakan berkumpul menjadi satu deret. Meski terguncang sepanjang hari di dalam tas, tak satu sudut pun terluka. Kekuatan bisa sesenyap ini."},"ICON-0324":{"nm":"Pouch Bawa Photocard","de":"Sebuah kebiasaan telah meresap pada tangan yang membuka-tutup risletingnya. Diterjang hujan mendadak, terhimpit desakan kerumunan, hanya bagian dalam yang tetap kering. Menyimpan yang paling disayangi di tempat paling dalam, itulah kerja lembut yang disebut membawa."},"ICON-0325":{"nm":"Tali Gelang Fan Meeting","de":"Betapa hangat tangan staf yang mengikatkan tali di pergelangan tangannya, dikenang lama oleh seorang penggemar. Sebuah simpul tunggal menandai keberadaan di tempat ini hari ini. Tali yang dililit dua kali agar tak lepas itu menahan seluruh debar hari itu tetap di tempatnya."},"ICON-0326":{"nm":"Gelang Masuk","de":"Tepat pada saat melewati pintu masuk, barulah dalam dan luar terbagi dengan jelas. Dipakai sepanjang hari, ia lambat laun akrab dengan kulit, dan menjelang dilepas tertinggal bekas tipis, seperti bukti tempat yang pernah disinggahi."},"ICON-0327":{"nm":"Chip Sesi Obrolan","de":"Ketika sesi obrolan dibuka, sebuah chip menggelinding pelan. Siapa yang bicara lebih dulu, pertanyaan mana yang terpilih—kebetulan kecil itu mengubah seluruh suasana. Keisengan satu chip lebih memikat daripada naskah yang sudah tersusun rapi."},"ICON-0328":{"nm":"Tiket Antre Fan Sign","de":"Menggenggam secarik kertas bernomor, kau berdiri dalam antrean. Nomor 142. Sambil menghitung 141 orang di depan, jantung lebih dulu menghitung gilirannya sendiri. Penantian memang panjang, tapi berkat selembar tiket ini, waktu itu pun menjadi bagian dari debaran."},"ICON-0329":{"nm":"Sarung Tangan Hi-Touch","de":"Pada detik telapak tangan bersentuhan, sarung tangan ini menerima kehangatan singkat itu menggantikan dirimu. Tangan yang dihangatkan seharian penuh demi sentuhan 0,5 detik. Bahkan berbalut kain pun tak mampu menahan getaran itu—semua orang baru menyadarinya saat itu."},"ICON-0330":{"nm":"Pin Foto Kenangan","de":"Cekrek, satu bunyi dan hari ini terawetkan begitu saja. Di dalam bingkai yang dikunci pin, bahkan senyum canggung pun kelak menjadi adegan yang paling dirindukan. Rekaman adalah keserakahan paling lembut untuk menggenggam sebuah momen."},"ICON-0331":{"nm":"Pita Penanda Kursi","de":"Pita kecil yang tergantung di sandaran kursi bergoyang meski tak ada angin. Sebuah penanda yang diikatkan seseorang, jejak bahwa seseorang pernah ada di sini. Bahkan di kursi kosong setelah pertunjukan usai, hanya pita itu yang seolah masih mengingat iramanya."},"ICON-0332":{"nm":"Label Pemeriksaan Hadiah","de":"Label ditempel pada setiap hadiah, satu per satu. Sudah dikirim atau belum, sudah diperiksa atau belum, ada yang terlewat atau tidak. Menerima hati seseorang pun butuh pengurusan, maka stiker kecil ini menyambungkan ketulusan demi ketulusan tanpa satu celah pun."},"ICON-0333":{"nm":"Selip Memorial","de":"Selembar kertas yang dituliskan untuk disimpan dan dilihat kembali lama-lama. Cuaca hari itu, nomor kursi, bahkan judul lagu terakhir. Ingatan bisa memudar, tapi hanya selip ini yang tak akan pudar. Menyimpan kenangan pun ternyata butuh bentuk kecilnya sendiri."},"ICON-0334":{"nm":"Gelang Handuk Semangat","de":"Selipkan gelang di ujung handuk, dan ia tak akan melorot dari bahu. Di sela-sela gerakan mengelap keringat, memutar di atas kepala, lalu menyampirkannya lagi ke leher, satu sambungan kecil menjaga gerakan menyemangati tetap tak terputus."},"ICON-0335":{"nm":"Jepitan Slogan","de":"Jepitan mencengkeram kokoh kedua ujung slogan. Agar meski kedua lengan terangkat tinggi, huruf-hurufnya tak terlipat atau berkibar liar. Di tempat yang tak terlihat, ada peran pendukung paling setia yang meluruskan pesan itu."},"ICON-0336":{"nm":"Pouch Peredam Suara","de":"Risleting meluncur perlahan, tanpa suara. Sebuah kesunyian yang dirancang agar tak satu pun bunyi bocor di tempat yang telah dijanjikan hening. Perhatian terkadang berarti membuat diri tak terdengar, bisik pouch ini pelan-pelan."},"ICON-0337":{"nm":"Chip Ritme Tepuk Tangan","de":"Setiap kali telapak tangan bertemu, chip ini menghitung iramanya. Prok, prok, prok—tepukan yang berserakan pada suatu saat berkumpul menjadi satu ritme. Sihir ribuan tepuk tangan yang menyatu menjadi satu napas, diam-diam dibantu oleh sebuah chip kecil."},"ICON-0338":{"nm":"Folder Panduan Fanchant","de":"Dibuka, panduan fanchant tertulis bertahap di dalamnya. Warna apa yang diangkat pada bait mana, kapan sorakan disisipkan. Bahkan orang yang baru pertama datang langsung menjadi bagian keluarga berkat satu folder ini. Sebuah panduan kecil untuk berbagi janji."},"ICON-0339":{"nm":"Tali Kipas Kursi","de":"Ikatkan tali pada pegangan kipas, dan ia tak akan jatuh meski terlepas dari genggaman. Pada hari yang panas, saat kedua tangan bebas untuk bersorak setelah mengipas, ia bergelantungan di pergelangan tangan. Satu tali mendinginkan panas dan gairah sekaligus."},"ICON-0340":{"nm":"Serpihan Film Berkilau","de":"Terkena cahaya, setiap serpihan memecahkannya ke sudut yang berbeda-beda. Diletakkan di telapak tangan, pelangi kecil berkelap-kelip, dan warnanya hidup bergerak setiap kali diguncang. Mungkin berkilau berarti berbagi cahaya yang dibelah menjadi kepingan kecil."},"ICON-0341":{"nm":"Tongkat Spanduk Mini","de":"Rentangkan tongkat kecilnya, dan kain menegang menampung angin. Angkat tinggi dengan kedua tangan, huruf-hurufnya menjangkau hingga jauh melewati kursi penonton, lipat kembali, dan ia muat di sudut tas. Besarnya hati tak diukur dari panjang tongkatnya."},"ICON-0342":{"nm":"Paket Stiker Semangat","de":"Setiap lembar stiker terpahat kalimat penyemangat. Di buku agenda, di ponsel, di sudut laptop—di mana pun ditempel, keseharian ikut terwarnai semangat. Begitulah hati yang menyukai meninggalkan jejaknya di mana-mana."},"ICON-0343":{"nm":"Sampul Pelindung Album","de":"Tangan yang membungkus album dengan sampul bergerak hati-hati. Agar sudutnya tak aus, agar tak pudar terkena matahari. Musik didengar oleh telinga, tapi selembar sampul ini diingat oleh tangan. Sebuah zirah hati yang ingin menjaga yang disayangi tetap dekat lama-lama."},"ICON-0344":{"nm":"Ring Sleeve Cakram","de":"Masukkan cakram ke dalam sleeve dan ikat dengan ring, jadilah sebuah album berjilid. Bunyi gemerisik setiap kali membalik satu lembar terasa menyenangkan. Mengumpulkan musik yang berserakan menjadi rapi dalam genggaman, itulah kebahagiaan diam-diam seorang kolektor."},"ICON-0345":{"nm":"Sekat Penyimpanan Goods","de":"Dengan satu sekat, goods yang nyaris tercampur aduk menemukan tempatnya masing-masing. Di sini photocard, di sana keyring, di sebelahnya lightstick. Merapikan adalah membangun rumah bagi benda-benda. Begitu sekat itu terbagi, kekacauan pun berubah menjadi keteraturan."},"ICON-0346":{"nm":"Tali Segel Paket Acak","de":"Ikatkan tali pada mulut paket acak, dan nasib siapa pun belum ditentukan. Sampai dibuka, semua orang adalah tokoh utama dari harapannya sendiri. Getar ujung jari saat melepas segel itulah kesenangan yang selama ini dijaga oleh tali ini."},"ICON-0347":{"nm":"Kotak Penyusun Bonus Perk","de":"Berbagai perk berbaris menurut jenisnya di dalam kotak. Kartu pos bersama kartu pos, pembatas buku bersama pembatas buku. Lihatlah sekat-sekat yang makin padat seiring bertambahnya koleksi, dan seluruh waktu yang telah dikumpulkan pun terlihat sekilas. Merapikan adalah menyusun daftar kenangan."},"ICON-0348":{"nm":"Label Pembeda Versi","de":"Ada benda-benda yang tampak sama namun sebenarnya berbeda. Satu label membedakan Versi A dari Versi B, cetakan pertama dari cetakan ulang. Berkat penanda kecil itu, kebingungan lenyap, dan sebuah label nama yang jelas melekat pada dunia mengoleksi."},"ICON-0349":{"nm":"Memo Cek Penjualan Minggu Pertama","de":"Minggu rilis, dan satu angka membuat hati bergoyang. Tanda centang tertulis rapi di kertas memo. Kumpulkan catatan beberapa hari, dan jadilah rapor kecil dukungan. Sebuah kebiasaan penuh ketelitian menerjemahkan hati yang menyukai ke dalam angka."},"ICON-0350":{"nm":"Tutup Pengunci Poster","de":"Selipkan tutup pada ujung poster yang tergulung, dan ia tetap terurai dengan tenang. Agar tak kusut sementara masih bimbang antara menggantungnya di dinding atau membingkainya. Sebuah penutup kecil yang menjaga adegan favorit tetap lurus sempurna."},"ICON-0351":{"nm":"Penyangga Foto Berdiri","de":"Foto berdiri miring di atas penyangganya. Di sudut meja, pada sudut yang pas dengan tinggi mata. Sebuah penemuan yang membuat mata bertemu setiap kali melintas. Cara paling sederhana untuk menghadirkan wajah tercinta ke dalam pemandangan sehari-hari."},"ICON-0352":{"nm":"Gulungan Selotip Rehearsal","de":"Selotip ditempel di lantai untuk menandai tempat berdiri. Satu kotak, dua kotak, tepat di sini. Menginjak bekas yang sama puluhan kali, jalur gerak pun terpahat dalam tubuh. Di bawah panggung yang gemerlap terhampar jejak selotip yang jujur ini."},"ICON-0353":{"nm":"Pin Penanda Blocking Panggung","de":"Satu pin yang tertancap di lantai panggung memberi tahu langkah berikutnya. Bahkan dalam gelap, ujung kaki lebih dulu menemukan tempat itu. Jalan yang tepat meski tak terlihat, sebuah peta tersembunyi yang digambar oleh latihan yang tak terhitung jumlahnya."},"ICON-0354":{"nm":"Ear Cap Staf","de":"Pasang ear cap-nya, dan sorak sorai penonton meredup selapis, sementara hanya suara yang menyampaikan aba-aba tetap jernih. Telinga staf di balik panggung selalu mendengar dua dunia sekaligus. Sebuah alat kecil untuk memilah sinyal di tengah keramaian."},"ICON-0355":{"nm":"Label Gantungan Ruang Tunggu","de":"Sebuah label nama tergantung di setiap gantungan. Kostum 1, kostum 2, kostum encore. Melihat daftar urutan ganti kostum yang tertulis berderet itu, panggung hari itu sudah tergambar lebih dulu lewat urutan pakaian. Sebuah keteraturan yang diam-diam menjinakkan kesibukan."},"ICON-0356":{"nm":"Tag Pemeriksaan Properti","de":"Sebelum naik panggung, tag dipasang pada setiap properti, satu per satu. Ada yang hilang atau tidak, semuanya utuh atau tidak. Penonton tak tahu, tapi pemeriksaan kecil ini mencegah kecelakaan. Di balik panggung yang terlihat sempurna selalu ada tangan yang teliti."},"ICON-0357":{"nm":"Chip Isyarat Cue","de":"Chip isyarat cue berpindah dari tangan ke tangan. Sekarang, masuk. Momen ketika waktu yang tepat tersampaikan tanpa sepatah kata pun. Dalam kegelapan di samping panggung, sinyal kecil ini menjaga agar semua orang tak kehilangan iramanya."},"ICON-0358":{"nm":"Patch Backstage","de":"Ada pintu yang hanya bisa dilewati oleh pemakai patch ini. Di belakang panggung, tempat sorak sorai terdengar dari balik dinding. Sepotong kain kecil memisahkan bagian depan yang gemerlap dan bagian belakang yang sibuk. Sebuah tanda bagi orang-orang yang menopang panggung."},"ICON-0359":{"nm":"Papan Penutup Prompter","de":"Papan penutup ini menahan cahaya prompter agar tak bocor ke bangku penonton. Hanya orang di atas panggung yang melihatnya, penonton tak pernah tahu. Penjaga rahasia panggung yang sopan, diam-diam menyembunyikan bantuan yang tak boleh ketahuan."},"ICON-0360":{"nm":"Sarung Cermin Ruang Tunggu","de":"Di ruang tunggu setelah pertunjukan usai, cermin ditutupi kain. Kaca yang seharian memantulkan begitu banyak ekspresi kini menutup mata sejenak. Yang terakhir dihadapi wajah polos tanpa rias bukanlah cermin, melainkan kegelapan yang sunyi."},"ICON-0361":{"nm":"Gelang Masuk Rekaman Awal","de":"Sebuah gelang kecil yang, sekali terpasang, tak akan lepas sebelum digunting. Demi satu-satunya syarat untuk memasuki bangku penonton rekaman awal, seseorang menaiki kereta pertama di subuh yang masih gelap gulita. Beban di pergelangan tangan itu menjelma debar sepanjang hari."},"ICON-0362":{"nm":"Label Siaga Rekaman","de":"Tepat sebelum lampu merah menyala, mengikat napas semua orang menjadi satu baris adalah tugasku. Dalam kesunyian menanti isyarat cue, aku bertahan diam sampai detik terakhir. Begitu aku dilepas, barulah tirai siaran langsung terangkat."},"ICON-0363":{"nm":"Chip Posisi Kamera","de":"Satu tanda kecil yang tercetak di lantai menetapkan jalur enam kamera dengan cermat. Di mana harus tertangkap agar tampak paling bercahaya, sang sutradara sudah tahu jauh sebelum gladi bersih. Sebuah sentuhan yang menggambar isi layar dari luar layar, jauh sebelum saatnya."},"ICON-0364":{"nm":"Tag Cek Suara","de":"Kau mengetuk-ngetuk mikrofon pelan ke arah bangku penonton yang kosong. Jika gemanya terlalu panjang, satu lapis lagi peredam suara ditambahkan di langit-langit. Ketelitian menata serat suara tanpa sepengetahuan penonton diam-diam dimulai dari tag kecil ini."},"ICON-0365":{"nm":"Buku Stempel Lokasi","de":"Setiap kali melewati sebuah lokasi, satu stempel lagi terkumpul di dalam kotaknya. Di setiap bekas tinta yang membaur, cuaca dan debar hari itu ikut tercetak bersamanya. Halaman yang telah terisi penuh menjadi peta jejak langkah yang tak bisa ditiru siapa pun, hanya milikku sendiri."},"ICON-0366":{"nm":"Tali Kartu Tamu Stasiun TV","de":"Tanpa tali ini, gerbang lobi tak akan terbuka. Dikalungkan di leher, melangkah menyusuri koridor selangkah demi selangkah, dunia yang hingga kemarin hanya terlihat lewat layar perlahan mendekat cukup dekat untuk disentuh."},"ICON-0367":{"nm":"Paket Penutup Sepatu Studio","de":"Lantai studio selalu dingin dan licin. Lepas sepatu, kenakan penutup kaki yang tipis, dan langkah kaki lenyap perlahan. Kamera merekam tarian, bukan derap langkah, jadi menghapus suara pun adalah bentuk kesopanan sendiri terhadap panggung."},"ICON-0368":{"nm":"Label Camilan Ruang Tunggu","de":"Di antara gladi bersih dan siaran langsung, rasa lapar datang paling jujur. Sebuah label nama kecil pada setiap camilan di ruang tunggu, menandai milik siapa. Kelembutan hati menyiapkannya itulah yang membuat hari yang panjang bertahan sampai akhir."},"ICON-0369":{"nm":"Pita Memo Monitoring","de":"Kau menonton ulang rekaman sambil mencatat. Di sini soal tatapan, di sana soal setengah ketukan. Tulisan yang penuh sesak itu adalah surat rahasia untuk diri di hari esok. Pita yang ditempel di ujungnya adalah janji tenang untuk menjadi sejengkal lebih baik dari kemarin."},"ICON-0370":{"nm":"Selip Undangan Showcase","de":"Selembar kertas bisa menjadi penantian setahun penuh bagi seseorang. Satu kalimat singkat mengundang ke showcase, lahir sebagai undangan terkecil di dunia, menyimpan bahkan getar ujung jari yang membuka amplopnya."},"ICON-0371":{"nm":"Tali Lanyard Pers","de":"Tergantung di leher para wartawan, ia menerobos jantung riuh bunyi rana kamera. Langkah kaki yang berlari sibuk mencari sudut terbaik, dan kecepatan itulah yang menjadi jalan membawa panasnya panggung keluar ke dunia luar."},"ICON-0372":{"nm":"Bagan Urutan Salam Panggung","de":"Agar tak ada yang kacau bahkan saat tepuk tangan bergemuruh turun, siapa lebih dulu dan siapa berikutnya dituliskan dalam satu baris. Susunan salam terakhir disusun dengan ketelitian yang sama seperti kemunculan pertama."},"ICON-0373":{"nm":"Penanda Lantai Photo Wall","de":"Di depan photo wall, tempat meletakkan ujung kaki sudah ditandai sebelumnya. Bergeser satu langkah saja, logo latar belakang akan terpotong. Rahasia posisi yang tertangkap paling bercahaya itu diam-diam ditandai di bawah kaki."},"ICON-0374":{"nm":"Gelang Pemutaran Perdana","de":"Sebuah gelang kecil dipasang di pergelangan tangan tepat sebelum lampu bioskop padam. Ketika layar terangkat, semua orang bertemu adegan yang sama untuk pertama kalinya dalam kegelapan yang sama. Sebuah tanda kecil kehadiran bersama pada momen pertama itu."},"ICON-0375":{"nm":"Serpihan Tirai Kenangan","de":"Pada hari pertunjukan terakhir, tirai turun perlahan setelah salam penutup. Sepotong kain dari lembaran itu dipotong dan dibingkai. Panas lampu sorot dan getar tepuk tangan masih meresap hangat di kain itu, belum juga dingin."},"ICON-0376":{"nm":"Stempel Pengungkapan Perdana","de":"Pada hari pertama kali menampakkan diri ke dunia, sebuah stempel terpahat untuk satu momen itu. Tak ada pengungkapan pertama yang kedua, jadi bahkan sesaat singkat ketika tintanya mengering pun adalah waktu yang tak akan pernah kembali."},"ICON-0377":{"nm":"Kartu Momen Panggung","de":"Satu bingkai paling bersinar dari sebuah panggung digunting dan ditempel pada kartu. Musik dan lampu sudah berhenti, tapi begitu berada di tangan, sorak sorai hari itu kembali menggelembung di telinga. Sebuah sihir kecil ketika adegan yang terhenti kembali hidup."},"ICON-0378":{"nm":"Memo Pose Penutup","de":"Sebuah memo yang menggambarkan sudut ujung jari dan tatapan yang harus membeku tepat saat nada terakhir berhenti. Hanya orang yang tahu satu bingkai penutup bisa memengaruhi berhari-hari yang menyimpan gambar kecil ini dengan hati-hati dilipat rapi."},"ICON-0379":{"nm":"Pin Kota Tur","de":"Di atas peta, sebuah pin tertancap pada setiap kota yang pernah disinggahi. Angin laut Busan dan siang hari Gwangju sama-sama tertanam di ujung paku kecil ini. Hubungkan titik-titiknya perlahan, dan tampaklah garis panjang perjalanan yang melintasi satu musim penuh."},"ICON-0380":{"nm":"Klip Zona Kursi","de":"Membagi puluhan ribu kursi menjadi zona-zona dan menunjukkan jalan. Agar tak tersesat, agar tak bertabrakan. Ikuti aku, dan siapa pun akan sampai ke tempatnya. Keteraturan, pada akhirnya, adalah kebaikan kecil untuk semua orang."},"ICON-0381":{"nm":"Tag Gerbang Masuk","de":"Di depan gerbang, satu per satu orang melewati pemeriksaan sesuai giliran. Gerbang terakhir yang mengizinkan tangan yang menggenggam tiket dan hati yang berdebar masuk ke dalam. Begitu melewatiku, penantian yang panjang berakhir dan panggung hari ini pun dimulai."},"ICON-0382":{"nm":"Kapsul Simpan Gelang","de":"Meski warnanya memudar, sorak sorai hari itu tetap tersegel utuh. Tak tega membuang pita dari pergelangan tangan, kau menggulungnya rapi ke dalam kapsul kecil. Karena bahkan kenangan berharga pun ingin diberi satu ruang kecil untuk berbaring."},"ICON-0383":{"nm":"Tongkat Tukar di Lokasi","de":"Antara penggemar dan panggung, sesuatu berpindah dari tangan ke tangan. Bisa surat, bisa hadiah kecil. Aku membuka jalan agar hati itu sampai dengan selamat, jembatan paling sibuk di lokasi ini."},"ICON-0384":{"nm":"Segel Tanggal Pertunjukan","de":"Tanggal hari itu tercetak di dalam segel bulat dan berhenti untuk selamanya. Kalender terus berganti, tapi hanya lingkaran kecil ini yang tetap tinggal di hari itu. Ketika ada hari yang tak ingin dilupakan, orang selalu menyegel sesuatu."},"ICON-0385":{"nm":"Patch Tas Tur","de":"Tas yang ikut berkeliling tur bertambah satu patch untuk setiap kota. Nama-nama tempat yang dijahit di kainnya, tanpa sadar, menjadi sebuah riwayat hidup. Bahkan sudut yang aus dan lusuh pun tersisa sebagai bukti telah pergi bersama ke mana pun."},"ICON-0386":{"nm":"Tali Papan Tiket","de":"Papan yang bergoyang di ujung antrean masuk, ujungnya diikat kuat oleh satu tali. Di tengah pemandangan tangan-tangan yang mengangkat tiket tinggi-tinggi berderet panjang, aku diam-diam menandai kepala barisan tempat debar hati mengantre."},"ICON-0387":{"nm":"Serpihan Pita Encore","de":"Pada malam ketika teriakan meminta encore paling keras, sepotong pita yang menghiasi panggung terjatuh. Seperti lagu yang dinyanyikan lebih panjang karena sayang untuk berakhir, serpihan ini pun menyimpan simpul keengganan untuk pergi."},"ICON-0388":{"nm":"Botol Kapsul Pesan","de":"Sepatah kata dilipat rapi di dalam botol kaca. Seperti perahu kecil yang dilepas mengapung berharap suatu hari sampai, aku mendekap sebuah hati dan hanyut perlahan menyusuri waktu. Sampai hari ia dibuka, janji itu tertidur tenang di dalam."},"ICON-0389":{"nm":"Tag Pengakuan Kecil","de":"Kata-kata yang tak sanggup terucap lewat mulut dituliskan pada tag kecil dan diselipkan diam-diam. Tulisannya gemetar, tapi ketulusannya saja yang jelas. Ada kalanya kertas terkecil menyimpan keberanian terbesar."},"ICON-0390":{"nm":"Kotak Pesan Semangat Anonim","de":"Meski tak mencantumkan nama, hati tetap tersampaikan. Setiap kali sepucuk pesan masuk ke kotak, semangat seseorang bertumpuk selembar demi selembar, secara anonim. Sebuah kumpulan kelembutan tanpa wajah, di mana hanya kehangatannya yang jelas meski tak tahu siapa penulisnya."},"ICON-0391":{"nm":"Kertas Lipat Harapan","de":"Selembar kertas persegi berubah menjadi burung bangau, menjadi bintang, mengikuti ujung jari. Setiap kali dilipat, harapan pun ikut terlipat selapis demi selapis. Dalam bentuk yang dilipat dengan penuh perhatian, bersemayam ketulusan yang bertahan lebih lama dari kata-kata."},"ICON-0392":{"nm":"Lilin Segel Pita","de":"Teteskan lilin dan tekan stempelnya, dan surat itu barulah tersegel. Persis cara lama untuk mengukuhkan sebuah hati. Di atas lilin merah yang mulai mendingin, sebuah rahasia diam-diam terkunci."},"ICON-0393":{"nm":"Kertas Bantalan Hadiah","de":"Takut hadiahnya terluka, kertas ini membungkus lembut sekelilingnya. Di setiap lipatan yang kusut tersirat pesan agar jangan sampai pecah. Sebuah lapis hati yang berhati-hati di tempat tak terlihat, yang bahkan mungkin akan terlewatkan begitu saja oleh si penerima."},"ICON-0394":{"nm":"Tali Surat Berwarna","de":"Bahkan tali yang mengikat surat pun punya warna. Kuning untuk semangat, biru untuk kerinduan. Perasaan yang tak sanggup terucap sepenuhnya lewat kata dipilih lewat warna dan diikat simpul. Bahkan sebelum dibuka, suhu hati sudah lebih dulu tersampaikan ke ujung jari."},"ICON-0395":{"nm":"Pita Penutup Tulisan Tangan","de":"Sebuah pita yang menyembunyikan tulisan sampai detik terakhir sebelum diserahkan. Ia menjaga pengakuan yang cemas ketahuan sampai saat-saat terakhir. Ketulusan yang tersingkap saat sedikit diangkat, beban getar itu kupahami paling dekat dari siapa pun."},"ICON-0396":{"nm":"Chip Kalimat Semangat","de":"Pada malam ketika lightstick bergelombang, satu kalimat yang akan diteriakkan serentak terukir di dalam chip. Kata-kata janji yang mengumpulkan hati-hati yang berserakan menjadi satu baris. Ketika dinyanyikan bersama-sama, kalimat itu bersinar paling terang."},"ICON-0397":{"nm":"Keyring Ruang Latihan yang Lusuh","de":"Sebuah keyring yang telah membuka dan menutup pintu ruang latihan ratusan kali. Catnya mengelupas dan gelangnya mengendur, tapi di dalamnya keringat masa-masa paling canggung tertinggal sebagai patina yang halus di tangan. Lusuh berarti telah bertahan selama itu."},"ICON-0398":{"nm":"Serpihan Rias Panggung","de":"Riasan panggung baru sempurna di bawah sorot lampu. Sepotong dari warna pekat itu. Pada bekas yang dioleskan kuat agar tak luntur oleh keringat, tersimpan penuh ketelitian untuk menyampaikan ekspresi hingga ke bangku penonton terjauh."},"ICON-0399":{"nm":"Wadah Eartip","de":"Eartip kecil yang membuat suaranya sendiri terdengar di atas panggung. Setelah pertunjukan usai, dibaringkan rapi ke dalam wadahnya. Semakin dekat sesuatu menghantarkan musik kepadamu, semakin ingin pula kau menyimpannya dengan penuh perhatian."},"ICON-0400":{"nm":"Label Loker Pribadi","de":"Di ujung koridor asrama, sebuah label nama tertempel pada setiap loker. Tulisan kecil yang memberi tahu ini milik siapa mengubah ruang yang asing menjadi rumah. Memiliki kotak sendiri adalah izin lembut untuk boleh tinggal di sini."},"ICON-0401":{"nm":"Botol Perawatan Tenggorokan","de":"Di sela latihan, kau menelan seteguk air hangat perlahan. Tenggorokan adalah alat musik yang dipinjam seorang penyanyi, jadi botol kecil yang diisi sebelum airnya dingin ini menjaga nada pertama esok hari sejak sekarang. Rasa sayang selalu setenang ini."},"ICON-0402":{"nm":"Pin Pengingat Jadwal","de":"Di atas hari yang padat menit demi menit, sebuah pin menunjuk ke kotak berikutnya. Di antara barisan yang rapat itu, yang paling dinanti adalah satu kotak kosong. Waktu untuk sekadar menoleh ke luar jendela bersembunyi kecil di sana."},"ICON-0403":{"nm":"Klip Selimut Ruang Tunggu","de":"Suatu sore, dengan rias yang sudah rampung, kau tertidur sejenak bersandar di kursi, dan seseorang diam-diam menyelimuti bahumu. Klip ini, yang menggigit agar selimut tak melorot, dengan tenang menggenggam kehangatan sentuhan itu hingga tiba waktumu naik panggung."},"ICON-0404":{"nm":"Sampel Parfum Mini","de":"Ketuk perlahan di pergelangan tangan bagian dalam, dan aromanya hanya mekar dalam jarak sejengkal. Tak apa jika tak menyebar jauh. Jejak yang hanya disadari oleh mereka yang mendekat itu lebih rahasia, dan karena itu lebih terasa seperti diriku."},"ICON-0405":{"nm":"Label Cucian Baju Latihan","de":"Berapa kali pun dicuci, bau keringat yang meresap dalam ke kainnya tak pernah benar-benar hilang. Sambil melipat kembali baju latihan yang telah kering lembut dijemur di bawah matahari, kau berpikir—noda yang tak mau hilang itu sebenarnya adalah jejak paling jujur."},"ICON-0406":{"nm":"Film Gel Lampu Panggung","de":"Selipkan selembar film berwarna tipis, dan cahaya putih pun merembes menjadi warna senja; tumpuk selembar lagi, fajar pun turun perlahan. Musim apa yang akan mewarnai panggung, sebuah tangan yang mendandani bahkan cahaya dengan pakaian kini menahan napas di balik tirai."},"ICON-0407":{"nm":"Tutup Lensa Sorot","de":"Bahkan saat kamera mati, seseorang membuka tutup kecil ini untuk membersihkan lensa. Demi adegan berikutnya yang belum terekam. Di atas waktu yang tak tertangkap layar, tangan yang paling sibuklah yang lebih dulu mengatur fokus."},"ICON-0408":{"nm":"Papan Reflektor Panggung","de":"Ada sebuah papan yang, meski tak bercahaya sendiri, mengembalikan cahaya yang diterimanya ke wajah yang tersaput bayangan. Bagian tengah panggung begitu terang karena di tepi ada lengan seseorang yang diam-diam mengatur sudut dan memantulkannya kembali."},"ICON-0409":{"nm":"Sarung Filter Warna","de":"Selipkan cahaya biru ke dalam sarung bening ini, dan seluruh bangku penonton pun berubah menjadi lautan; ganti dengan merah, dan senja jatuh di tempat yang sama. Keajaiban panggung yang sama berubah musim hanya dengan satu warna, dimulai dari selembar tipis ini."},"ICON-0410":{"nm":"Pin Nomor Lampu","de":"Setiap lampu dari sekian banyak memiliki nomor kecilnya sendiri. Nomor berapa yang menyala dan nomor berapa yang terlelap, alur pertunjukan malam ini sudah tersusun lebih dulu lewat urutan angka-angka ini. Di balik tirai yang mempesona selalu terbentang daftar yang teliti."},"ICON-0411":{"nm":"Penanda Pita Bercahaya","de":"Di lantai panggung yang gelap gulita, pita fosfor diam-diam menerangi titik tempat kaki harus berhenti. Tak terlihat dari bangku penonton, namun ujung kaki sang penampil meraba cahaya samar ini untuk menemukan posisinya. Bahkan dalam gelap ada penunjuk jalan yang lembut."},"ICON-0412":{"nm":"Papan Penghalang Bayangan","de":"Papan yang menahan cahaya yang menyusup agar bayangan jatuh dengan tegas. Mengurus kegelapan pun pada akhirnya adalah mengurus cahaya, sebab apa yang akan ditampilkan lebih dulu ditentukan oleh apa yang diam-diam disembunyikan."},"ICON-0413":{"nm":"Chip Pengukur Cahaya","de":"Sebuah chip kecil pengukur terang-gelap ruangan membaca angka di telapak tangan. Sebab terlalu terang maupun terlalu gelap sama-sama membuat mata tak nyaman. Batas nyaman yang tak kasat mata, tempat seseorang paling betah berlama-lama, dijaga diam-diam oleh chip ini."},"ICON-0414":{"nm":"Penutup Lampu Sorot Titik","de":"Penutup yang dipasang agar lampu sorot titik tak bocor ke tempat yang salah. Memusatkan cahaya hanya pada satu orang adalah bentuk perhatian yang lembut. Begitu kau melangkah ke dalam lingkaran cahaya itu, dunia untuk sesaat hanya memandang satu orang."},"ICON-0415":{"nm":"Set Eartip","de":"Sepasang eartip yang pas terpasang di telinga. Meleset sedikit saja ukurannya, suara pun bocor, dan saat bocor, ketukan pun hilang. Nyanyian di atas panggung yang tak bergetar sedikit pun, kadang bermula dari sepasang karet kecil ini."},"ICON-0416":{"nm":"Velcro Pengikat Kabel","de":"Tali velcro yang mengikat rapi kabel-kabel yang kusut menjadi satu untai. Semakin tak terlihat oleh siapa pun di balik panggung, kerapian itu justru semakin bersinar. Kerapian seikat kabel diam-diam menopang suara yang mengalir tanpa goyah di depan panggung."},"ICON-0417":{"nm":"Label Pengecekan Jalur","de":"Label bertuliskan tangan yang ditempel pada puluhan kabel, menandai instrumen mana yang mana. Hanya ketika setiap coretan yang tak rapi itu menjaga tempatnya, suara-suara yang tadinya bermain sendiri-sendiri akhirnya mengalir menyatu menjadi satu lagu."},"ICON-0418":{"nm":"Alas Peredam Suara","de":"Selembar alas peredam yang diam-diam menelan suara langkah kaki maupun getaran. Dihamparkan di tempat yang benar-benar membutuhkan kesunyian. Suara yang paling jernih terkadang baru lahir di atas lantai sunyi ini, tempat tak ada bising sedikit pun yang bocor keluar."},"ICON-0419":{"nm":"Token Cek Suara","de":"Sebuah token yang menghangat di tangan selama pengecekan suara sebelum pertunjukan. Setiap kali satu mikrofon, satu pengeras suara selesai diperiksa, token ini berpindah genggaman. Kesempurnaan panggung utama dibentuk selangkah demi selangkah dalam gladi bersih yang sunyi ini."},"ICON-0420":{"nm":"Tutup Pelindung Mikrofon","de":"Karena inilah tempat sekian banyak suara pernah menyentuh, tutup yang membungkus ujung mikrofon ini dibersihkan dengan lebih telaten. Ia adalah wadah yang menampung nyanyian, jadi bagi penyanyi ia bagaikan tangan lain. Sambil membersihkannya, kau membayangkan bait pertama esok hari lebih dulu."},"ICON-0421":{"nm":"Klip Filter Pop","de":"Selapis jaring tipis yang terbentang antara bibir dan mikrofon. Berkat klip kecil yang menahan tirai itu, embusan napas yang tadinya bocor kasar kini terhalus menjadi suara yang bulat dan lembut saat mengalir keluar."},"ICON-0422":{"nm":"Label Rak Audio","de":"Di balik panggung yang gelap gulita, di antara rak-rak peralatan yang bertumpuk berlapis, tergantung label kecil ini agar tak tersesat. Sumber suara memukau yang memenuhi bangku penonton selalu tertata rapi di tempat seremang ini."},"ICON-0423":{"nm":"Pin Kisi Speaker","de":"Pin yang mengencangkan jaring speaker. Jendela tempat suara keluar adalah bagian pertama yang terkena debu, jadi selapis jaring tipis menjaga nadanya. Segala sesuatu yang sampai ke telinga selalu terbungkus selapis pelindung yang tak terlihat."},"ICON-0424":{"nm":"Stiker Penanda Langkah","de":"Stiker penanda gerak yang ditempel titik demi titik di lantai. Rahasia gerak tari kelompok yang menyatu bagai pisau sebenarnya tersembunyi di bawah kaki. Di atas jejak-jejak janji yang tak terhitung, tempat puluhan orang menginjak titik yang sama, berpencar, lalu berkumpul kembali."},"ICON-0425":{"nm":"Cakram Latihan Putaran","de":"Cakram latihan yang berputar-putar di tempat. Untuk mengalahkan pusing, kau lebih dulu belajar menancapkan pandangan pada satu titik. Sekencang apa pun berputar, keseimbangan yang perlahan terpahat dalam tubuh ini membuatmu tak pernah melepaskan titik itu."},"ICON-0426":{"nm":"Gulungan Plester Lutut","de":"Segulung plester yang membalut lutut dengan erat. Sendi yang telah melompat dan mendarat ribuan kali akhirnya tetap diam tanpa suara, namun selapis ini dengan tenang menopang kesunyiannya. Di balik tubuh yang bertahan hingga akhir selalu ada perhatian seseorang."},"ICON-0427":{"nm":"Papan Penyelaras Ujung Kaki","de":"Papan yang merapikan sudut ujung kaki. Konon tari disempurnakan bukan di ujung jari, melainkan di ujung kaki. Puluhan ujung kaki yang terentang ke arah yang sama berkumpul, menciptakan keajaiban banyak orang yang tampak seperti satu."},"ICON-0428":{"nm":"Alas Antiselip Ruang Latihan","de":"Alas antiselip yang dihamparkan di lantai ruang latihan. Untuk melompat sepuas hati, kau harus aman lebih dulu. Hanya di atas lantai tempat kau bisa berguling tanpa rasa takut jatuh, gerakan paling berani dan tanpa gentar akhirnya bisa mekar."},"ICON-0429":{"nm":"Kartu Pecahan Gerakan","de":"Kartu yang menggambarkan koreografi terurai kecil-kecil, satu ketukan demi satu ketukan. Segarang apa pun gerakannya, jika dibagi kotak demi kotak, kau pun tanpa sadar bisa mengikutinya. Alur yang mengalir semulus air di atas panggung tercipta dari kumpulan gambar-gambar yang dihafal terputus-putus ini."},"ICON-0430":{"nm":"Pin Tirai Penutup Cermin","de":"Pin yang menahan tirai yang untuk sementara menutupi cermin ruang latihan. Ada kalanya dibutuhkan waktu menari hanya dengan indra tubuh, tanpa bayangan diri. Saat cermin tertutup, musik pun akhirnya meresap hingga ke kulit, begitulah yang kau tahu."},"ICON-0431":{"nm":"Manik Penghitung Ketukan","de":"Tik, satu manik didorong dengan ujung jari untuk setiap ketukan, sambil menghitung. Bisa diraba, seperti cara berhitung zaman dulu. Ketukan, tulang punggung musik, baru benar-benar melekat kuat pada tubuh ketika dipelajari lewat sesuatu yang bisa disentuh seperti ini."},"ICON-0432":{"nm":"Tali Cek Pemanasan","de":"Tali penanda apakah tubuh sudah cukup diregangkan. Sebelum latihan sungguhan selalu datang lebih dulu persiapan yang tenang. Daripada menyesal setelah cedera, mengikat satu tali dan membangunkan tubuh perlahan justru membuatmu bisa menari lebih lama pada akhirnya."},"ICON-0433":{"nm":"Klip Nomor Kostum","de":"Klip yang menjepitkan nomor agar berbagai kostum tak tertukar. Di sela pergantian baju yang terburu napas, tertukar satu saja sudah jadi masalah besar, jadi setiap baju punya urutannya sendiri yang tertulis jelas. Kesibukan pun jadi anggun kalau ditopang keteraturan."},"ICON-0434":{"nm":"Bantalan Jarum Ruang Jahit","de":"Bantalan jarum yang terletak di sudut ruang jahit. Tangan yang tanpa kata menambal jahitan yang robek dan kancing yang lepas berdiam di sini. Di balik penampilan yang rapi tanpa cela di panggung, tersembunyi ketelatenan jahitan yang tak pernah sekalipun melihat panggung."},"ICON-0435":{"nm":"Cincin Potongan Kain","de":"Cincin yang merangkai potongan-potongan kain cadangan menjadi satu. Kain yang sama disisihkan lebih dulu untuk berjaga-jaga jika kostum utama rusak. Persiapan kecil yang disimpan sambil berharap tak terjadi apa-apa ini, justru menyelamatkan kostum panggung tepat saat hal besar menimpa."},"ICON-0436":{"nm":"Paket Kancing Darurat","de":"Sepaket kancing yang bisa langsung dipasang saat mendesak. Tepat sebelum pertunjukan, saat satu kancing lepas begitu saja, seluruh ruang rias langsung riuh sesaat. Kotak P3K kecil namun sangat diandalkan ini meredam kepanikan singkat yang mendebarkan itu dalam sekejap."},"ICON-0437":{"nm":"Penahan Sabuk Panggung","de":"Penahan yang mengencangkan sabuk kostum panggung dengan kokoh. Agar baju tak berantakan sekeras apa pun melompat dan berputar. Kebebasan yang dinikmati sepuas hati di atas panggung, pada akhirnya datang dari bagian tak terlihat yang dirapikan dengan yakin."},"ICON-0438":{"nm":"Kemoceng Bulu","de":"Karena di bawah lampu bahkan sehelai bulu halus pun mencolok, kau menyapu lembut kostum dengan kemoceng bulu. Tepat sebelum melangkah ke panggung, sentuhan lembut merapikan baju untuk terakhir kalinya itu selalu jadi tugas bulu lembut ini."},"ICON-0439":{"nm":"Label Sandal Ruang Tunggu","de":"Label nama yang tertempel di setiap sandal ruang tunggu. Dalam satu label kecil bertuliskan milik siapa, tersimpan diam-diam kelegaan bahwa kita satu tim. Ruangan tempat kau melepas sepatu dan meluruskan kaki itu menjadi rumah paling nyaman di balik panggung."},"ICON-0440":{"nm":"Papan Jepit Penataan Rambut","de":"Papan jepit yang menahan bagian rambut sementara ditata. Di sela merapikan helai demi helai, jari untuk sesaat mempercayakan rambut yang ingin berantakan pada jepitan ini. Kerapian, pada akhirnya, terbentuk dari kumpulan jeda-jeda kecil seperti ini."},"ICON-0441":{"nm":"Kapsul Peniti","de":"Di dini hari saat jahitan robek, buka tutup kapsul ini, dan warna perak kecil yang dingin terbaring rapi di dalamnya. Tangan yang menahan kostum paling kuat dari sisi dalam yang tak terlihat—peniti selalu bekerja diam-diam di balik panggung."},"ICON-0442":{"nm":"Kain Pembersih Lensa","de":"Embuskan napas sekali, lalu usap membentuk lingkaran, dan dunia yang buram pun menjadi jernih. Karena menyukai sekejap singkat itu, kau terus-menerus membersihkan lensa. Selembar cahaya musim semi kecil yang menjernihkan pandangan orang lain sebagai gantinya."},"ICON-0443":{"nm":"Kaki Karet Tripod","de":"Selipkan karet di ketiga ujung kaki, dan lantai kayu tak lagi menjerit. Sementara titik-titik kecil ini menelan getaran, pemandangan di layar pun menjadi tenang bagai kebohongan. Kestabilan selalu bermula diam-diam dari bawah kaki."},"ICON-0444":{"nm":"Sampul Hujan Kamera","de":"Meski tetes hujan mengalir turun, lensa tetap kering merekam dunia. Di sore mendung saat syuting luar ruangan, jas hujan bening dikenakan lembut ke tubuh kamera. Sebab yang berharga harus dilindungi lebih dulu sebelum basah."},"ICON-0445":{"nm":"Pita Penanda Syuting","de":"Berdiri di sini, berputar ke sana—jejak pendek warna-warni menunjukkan arah dengan jelas tanpa sepatah kata pun. Meski dilepas tanpa penyesalan setelah pertunjukan usai, ujung kaki yang sudah terbiasa akan lama mengingat tempat itu."},"ICON-0446":{"nm":"Klip Pemisah Adegan","de":"Klip kecil yang menggigit kertas-kertas yang hendak berserakan dalam satu gigitan. Klik, satu bunyi yang renyah mengikat rapi hari kemarin dan hari ini. Merapikan adalah kebiasaan tangan yang lembut, diam-diam memegang erat sesuatu yang nyaris hilang."},"ICON-0447":{"nm":"Papan White Balance","de":"Sorotkan papan putih ke layar, dan warna-warna pun diam-diam menemukan tempatnya. Senja yang kekuningan, fajar yang kebiruan, semua tanpa dusta. Satu papan yang mengenal warna putih sejati membuat warna-warna lain berbicara jujur."},"ICON-0448":{"nm":"Kaleng Penyimpan Memori","de":"Di dalam kaleng seng kecil, chip-chip kenangan tertidur lelap. Buka tutupnya, klik, dan adegan-adegan musim lalu pun tumpah ke telapak tangan. Kenangan tersimpan tenang, terjaga dalam satu kaleng yang kokoh seperti ini."},"ICON-0449":{"nm":"Tudung Monitor","de":"Lilitkan tudung hitam mengelilingi monitor, dan pantulan cahaya pun langsung berhenti. Bahkan di dekat jendela yang dibanjiri sinar matahari, layar tak kehilangan warnanya. Untuk melihat dengan baik, cahaya liar harus dihalau lebih dulu, begitu tudung ini diam-diam mengingatkan."},"ICON-0450":{"nm":"Pin Kedap Suara Lokasi Syuting","de":"Satu pin kecil yang terselip di celah pintu diam-diam memotong kebisingan dari luar. Suara langkah di lorong, tawa dari ruangan sebelah, semua tak sampai sejauh ini. Sebab untuk merekam suara yang jernih, kesunyian harus dibangun lebih dulu."},"ICON-0451":{"nm":"Paket Spons Rias","de":"Satu ikat spons lembut yang tersusun rapi berlapis-lapis. Tepuk-tepuk bedak dengan ujung jari, dan wajah pun mencerah satu tingkat. Di balik senyum cerah di atas panggung selalu tersembunyi sentuhan-sentuhan lembut ini."},"ICON-0452":{"nm":"Kotak Jepit Rambut","de":"Rumah yang rapi bagi jepit-jepit kecil yang mudah hilang. Buka tutupnya, dan warna perak berbaris rapi menyambutmu. Berserakan, mereka tak terlihat; terkumpul, mereka menenangkan hati—bahkan benda sekecil ini pun butuh rumahnya sendiri."},"ICON-0453":{"nm":"Kotak Sterilisasi Kuas","de":"Kuas-kuas yang menyerap warna sepanjang hari mandi sinar ultraviolet di dalam kotak. Sementara cahaya tak kasat mata itu membasuh yang lama, ujung kuas esok hari pun kembali lembut seperti semula. Kebersihan juga salah satu lipatan dari ketelatenan."},"ICON-0454":{"nm":"Jaring Puff Bedak","de":"Puff-puff yang bulat menarik napas dengan tenang di dalam kantong jaring. Saat angin keluar masuk lewat jaringnya, kelembutannya bertahan lebih lama. Satu puff yang kering sempurna menyimpan lebih dulu kecerahan pagi esok hari."},"ICON-0455":{"nm":"Tutup Semprotan Penata Rambut","de":"Cess—sekali semprot, dan tak sehelai pun bergoyang meski tertiup angin. Tutup kecil yang menahan gaya rambut yang ditata susah payah sepanjang malam. Di atas rambut yang tertata kokoh, cahaya lampu yang terang tercurah seperti pecah berkeping-keping."},"ICON-0456":{"nm":"Penutup Kuas Bibir","de":"Tutup kecil yang lembut membungkus ujung bulu kuas yang ramping. Diguncang ke sana kemari di dalam tas, kuas tetap terjaga lurus dan bersih. Rasa sayang pada satu kuas kecil ini menyempurnakan satu goresan warna di atas bibir."},"ICON-0457":{"nm":"Cermin Nomor Antrean","de":"Sebuah cermin kecil menempel diam-diam di samping angka yang memanggil giliranmu. Tepat sebelum naik panggung, di sinilah tempat merapikan poni yang berantakan untuk terakhir kalinya. Bahkan kegugupan pun sedikit mereda begitu tercermin sekali."},"ICON-0458":{"nm":"Handuk Ban Pergelangan","de":"Sehelai kain lembut yang mengusap keringat di dahi hanya dengan satu gerakan pergelangan tangan. Semakin garang koreografinya, semakin sering tangan meraihnya. Setiap napas yang tersengal, ia setia menemani—satu untai penghibur kecil di pergelangan tangan."},"ICON-0459":{"nm":"Label Tas Properti","de":"Meski sepuluh tas yang sama persis berbaris di ruang rias, tak ada yang tertukar. Sebab label nama di setiap tas dengan jelas menunjukkan siapa pemiliknya. Menuliskan 'milikku' adalah tanda yang kecil namun penuh sayang."},"ICON-0460":{"nm":"Pin Reservasi Ruang Latihan","de":"Siapa yang akan memakai ruang latihan ini hari ini? Sebuah pin kecil yang tertancap di papan dekat pintu diam-diam membagi waktu. Hati-hati yang menunggu giliran berikutnya diam-diam mengantre pada satu pin ini."},"ICON-0461":{"nm":"Cincin Penutup Jam Dinding","de":"Sebuah penutup bening turun lembut di atas jam dinding untuk mencegah debu. Jarum yang berdetak tak pernah kabur, dan waktu mengalir jernih. Sesuatu yang berharga selalu membutuhkan selapis pelindung yang tak kasat mata."},"ICON-0462":{"nm":"Alas Pelindung Lantai","de":"Alas tipis yang tertempel di kaki kursi mencegah lebih dulu goresan pada lantai kayu. Diseret pun tak lecet, dipindah pun tak berbekas. Perhatian yang menjaga lantai secara diam-diam, itulah rahasia agar bisa dipakai lama."},"ICON-0463":{"nm":"Chip Penanda Larangan Minuman","de":"Mari letakkan minuman kita sebentar di sini, pinta chip kecil ini dengan lembut. Sebab partitur maupun peralatan akan repot kalau basah. Bahkan kata 'terlarang' pun berubah menjadi perhatian yang hangat kalau disampaikan seperti ini."},"ICON-0464":{"nm":"Label Tombol Ventilasi","de":"Saat ingin mengganti udara yang pengap, tekan di sini, begitu label kecil di samping tombol menunjukkan jalan. Menghirup napas lega ternyata diam-diam bermula dari satu tanda sepele seperti ini."},"ICON-0465":{"nm":"Kaki Karet Speaker","de":"Alas karet di bawah speaker diam-diam menelan getaran yang berat. Karena bas tak lagi menjalar lewat lantai, suara pun terdengar jauh lebih jernih. Gema yang indah baru terasa bersih di atas pijakan yang kokoh."},"ICON-0466":{"nm":"Magnet Nomor Loker","de":"Sebuah magnet angka kecil yang menempel erat di pintu loker. Di kotak nomor berapa barangku akan tertidur hari ini? Meski tempatnya berganti setiap hari, satu magnet saja langsung menjadikan loker itu milikku. Rasa memiliki datang dari tanda seringan ini."},"ICON-0467":{"nm":"Wiper Pembersih Cermin","de":"Sekali usap melintasi cermin, dan embun pun tersapu bersih. Saat wajahku yang tadinya buram muncul jelas kembali. Untuk benar-benar melihat diriku, aku harus lebih dulu diam-diam menghapus apa yang mengaburkannya."},"ICON-0468":{"nm":"Bantalan Peredam Pintu","de":"Bantalan empuk yang terselip di celah pintu yang menutup keras. Baik suara 'brak' maupun jari yang terjepit ditahan dengan lembut. Sebuah keamanan kecil yang menyelipkan selapis kelembutan di antara benturan yang kasar."},"ICON-0469":{"nm":"Blok Penutup Kabel","de":"Penutup yang kokoh membentangkan jembatan dengan yakin di atas kabel-kabel yang melintasi lantai. Tak ada kaki yang tersandung, tak ada kabel yang terinjak. Ketenangan satu blok yang menjaga jalan tanpa menghalanginya."},"ICON-0470":{"nm":"Kerucut Peringatan Lantai Licin","de":"Kerucut kuning berdiri sendirian di atas lantai basah, diam-diam memberi peringatan. Melangkahlah hati-hati, pelan-pelan. Di balik panggung yang terang benderang, berdiri penjaga kecil seperti ini yang diam-diam mengawal setiap langkah."},"ICON-0471":{"nm":"Tongkat Lampu Darurat","de":"Seberkas cahaya menyala di lorong yang gelap gulita akibat listrik padam. Agar kau tak tersesat bahkan dalam gelap, cahaya darurat itu digenggamkan ke tanganmu. Ada hal-hal di dunia ini yang justru paling terang di saat paling gelap."},"ICON-0472":{"nm":"Tutup Pelindung Pegangan Tangga","de":"Tutup bulat yang dipasang di ujung pegangan tangga membungkus lembut sudut yang tajam. Meski tangan tak sengaja tersentuh, tak akan terluka. Menyelimuti sesuatu yang tajam secara diam-diam, itu pun bentuk perhatian bagi seseorang."},"ICON-0473":{"nm":"Bantalan Tepi Panggung","de":"Sebuah bantalan empuk melingkupi tepi ujung panggung. Agar ujung kaki yang menyentuh saat koreografi garang tak sampai memar. Di balik setiap gerakan yang bersinar, perlindungan yang tak terlihat turut menari bersamanya."},"ICON-0474":{"nm":"Cakram Penanda Lantai","de":"Sebuah cakram bulat yang diletakkan di lantai diam-diam berkata, 'Berdirilah di sini.' Baik yang mengantre maupun yang mencari tempat, semua berhenti di satu titik ini. Keteraturan tumbuh dari tanda yang kecil."},"ICON-0475":{"nm":"Tali Senter","de":"Lilitkan tali yang tergantung di ujung senter sekali putaran ke pergelangan tangan, dan kau tak akan kehilangan cahaya bahkan dalam gelap. Kedua tangan bebas tanpa khawatir terjatuh, seuntai kecil namun bisa diandalkan."},"ICON-0476":{"nm":"Tali Pembatas","de":"Tolong jangan masuk lebih jauh dari sini, satu utas tali menggaris batas dengan lembut. Batas yang ramah, diam-diam memisahkan tempat berbahaya dari yang aman. Menghalangi pun adalah salah satu cara menjaga seseorang."},"ICON-0477":{"nm":"Pin Cek Keamanan","de":"Di setiap titik yang selesai diperiksa, sebuah pin kecil meninggalkan tanda 'sudah dicek'. Satu titik bagai cap dari pikiran yang memeriksa tanpa melewatkan satu tempat pun. Keamanan bukanlah sesuatu yang megah, melainkan jumlah dari jejak-jejak yang ditelusuri satu per satu seperti ini."},"ICON-0478":{"nm":"Papan Klap Mini","de":"Pada bunyi renyah yang memotong ketukan pertama—tak—napas semua orang di lokasi syuting langsung menyatu dalam sekejap. Sekecil apa pun ukurannya, garis start setiap adegan selalu ketukan ini. Permulaan syuting yang mendebarkan terbuka dari sini."},"ICON-0479":{"nm":"Penutup Mikrofon Meja","de":"Sebuah penutup lembut terpasang perlahan pada mikrofon di atas meja. Meski embusan napas meletup kasar, suaranya tersampaikan halus tanpa bising. Yang membungkus suara paling hangat adalah selapis kecil dan lembut ini."},"ICON-0480":{"nm":"Kepingan Panel Peredam Suara","de":"Sekeping panel peredam suara yang tertanam di dinding diam-diam mengumpulkan gema. Karena suara tak lagi berbenturan dan berserakan, nyanyian pun mengendap jauh lebih jernih. Gema yang indah bermula dari upaya menghaluskan kesunyian dengan telaten."},"ICON-0481":{"nm":"Kait Gantungan Headphone","de":"Menggantungkan headphone di sini adalah janji kecil. Uraikan kabelnya dan letakkan rapi, agar orang berikutnya bisa langsung mengambil dan memakainya. Satu kait membawa ketertiban yang tenang ke dalam bilik yang sibuk."},"ICON-0482":{"nm":"Lampu Tanda Sedang Merekam","de":"Tepat saat lampu merah menyala, setiap napas di dalam bilik terhenti sejenak. Sebuah sinyal yang bahkan menghentikan langkah kaki di luar pintu. Merekam suara bermula dari menjaga kesunyian yang dalam ini."},"ICON-0483":{"nm":"Kotak Penyimpan Pick","de":"Pick-pick yang tertata rapi di setiap sekat menurut warnanya. Ketebalan dan bobotnya membentuk kebiasaan ujung jari. Tepat sebelum naik panggung, ketepatan mengambil pick yang tepat tanpa melihat itu tumbuh dari sini."},"ICON-0484":{"nm":"Alat Pelabel Kabel","de":"Agar tak tersesat bahkan di lantai yang dipenuhi puluhan untai kabel kusut, kedua ujungnya harus diberi nama. Hanya orang yang menuliskan dari mana datang dan ke mana perginya yang tangannya tak akan meraba-raba dalam gelap."},"ICON-0485":{"nm":"Kenop Mixer Mini","de":"Putar seukuran satu ruas jari, dan tekstur suara pun berubah. Naikkan jadi kasar, turunkan jadi tenggelam, meraba satu titik pas di antara keduanya. Sentuhan yang paling halus membentuk perubahan yang paling besar."},"ICON-0486":{"nm":"Ring Pengunci Standing","de":"Yang menopang panggung bukanlah lampu yang gemerlap, melainkan cincin kecil ini. Sambil menahan erat setiap goyangan, ia bertahan diam-diam di tempatnya, tak terlihat oleh mata siapa pun."},"ICON-0487":{"nm":"Label Pembongkaran Set","de":"Bahkan merebahkan kembali dengan hati-hati semua yang telah didirikan pun punya urutan yang jelas. Selembar catatan tentang di mana melepas dan ke mana memindahkan. Tangan yang membereskan sama tangkasnya dengan tangan yang membangun."},"ICON-0488":{"nm":"Chip Amplop Barang Hilang","de":"Setiap barang yang tertinggal menyimpan kisahnya sendiri. Memasukkannya ke dalam amplop kecil untuk menunggu nama pemiliknya adalah kelembutan yang untuk sesaat turut menampung hati orang yang kehilangan."},"ICON-0489":{"nm":"Penanda Rute Pembersihan","de":"Ikuti tanda panah yang digariskan di lantai, dan semuanya akan tersapu tanpa celah. Bahkan sapu pun butuh jalur agar tak berputar sia-sia. Tempat yang paling berkilau ada di ujung jejak langkah yang paling baik tergambar."},"ICON-0490":{"nm":"Tongkat Pengarah Keluar","de":"Ketika tepuk tangan terakhir mereda, tongkat ini membuka jalan. Sebuah tangan yang perlahan mengalirkan keluar hati-hati yang masih berdebar, agar tak terluka. Bahkan mengantar sebuah akhir menyimpan perhatian yang hangat."},"ICON-0491":{"nm":"Bola Sisa Selotip","de":"Gulung bulat sisa-sisa yang tersisa, dan ia pun berguna sekali lagi. Seperti ujung yang nyaris terbuang berkumpul menjadi bola yang padat, rasa hemat tumbuh dari ujung jari yang kecil."},"ICON-0492":{"nm":"Tutup Nomor Kursi","de":"Setiap kursi di bangku penonton harus berangka agar tak ada yang tersesat. Satu topi kecil yang menetapkan tempat duduk ini mengubah debar hati orang yang baru pertama datang menjadi kelegaan yang nyaman."},"ICON-0493":{"nm":"Pin Pemilah Sampah","de":"Pin kecil yang memilah dan menancapkan kertas terpisah dari plastik. Tercampur, ia hanya sampah; terpilah, ia menjadi sumber daya yang bisa dipakai lagi. Memilah adalah pekerjaan yang lembut, mengembalikan kehidupan kedua bagi sebuah benda."},"ICON-0494":{"nm":"Label Pengembalian Peralatan","de":"Sesuatu yang dipinjam harus selalu kembali ke tempatnya. Setiap ujung jari yang mengembalikannya dengan label terpasang menumpuk kepercayaan selapis demi selapis. Orang yang mengembalikan dengan baik akan meminjam dengan hati tenang di lain waktu."},"ICON-0495":{"nm":"Kunci Check-out Ruang Tunggu","de":"Setelah melepas seluruh rias dan kostum hari ini, terakhir kau mengembalikan kunci ini. Mengembalikan saat keluar apa yang diterima saat masuk. Awal dan akhir sebuah hari tergenggam dalam tangan yang sama."},"ICON-0496":{"nm":"Kotak Puff Cushion","de":"Puff yang lembut kehilangan teksturnya kalau tertekan. Di situlah alasan ia dibaringkan dengan tenang dalam satu rumah bundar. Untuk menjaga kelembutan tetap lama, kau harus lebih dulu memperlakukannya dengan lembut."},"ICON-0497":{"nm":"Chip Eyeshadow","de":"Satu titik warna yang dioleskan di kelopak mata mengubah seluruh ekspresi. Warna yang tertidur dalam chip kecil ini baru terbangun di bawah lampu, menambah kedalaman pada tatapan yang mengarah ke panggung."},"ICON-0498":{"nm":"Tutup Kuas Blush","de":"Kalau ujung bulunya rusak, hasil warnanya pun ikut hancur. Memasangkan topi kecil untuk menjaga teksturnya adalah kebiasaan diam-diam dari orang yang ingin menyimpan alat yang baik di sisinya lebih lama."},"ICON-0499":{"nm":"Palet Bibir Tipis","de":"Palet yang tebal memakan seluruh ruang di dalam tas. Tangan yang tahu bahwa satu lapis tipis saja sudah cukup. Momen ketika mengurangi justru menjadi cara untuk membawa lebih baik."},"ICON-0500":{"nm":"Pelindung Maskara","de":"Agar bulu mata yang ditegakkan helai demi helai tak luntur, pelindung kecil ini lembut menjaga lengkungannya. Apa yang diangkat dengan telaten harus dijaga dengan telaten pula, begitu waktu di depan cermin mengingatkan."},"ICON-0501":{"nm":"Wadah Cotton Bud","de":"Rumah kecil yang menjaga cotton bud putih agar tak berserakan ke mana-mana. Sentuhan yang selalu didekatkan untuk satu sentuhan akhir terakhir. Persiapan-persiapan kecil itulah yang menutup celah panggung besar."},"ICON-0502":{"nm":"Paket Karet Penjepit Bulu Mata","de":"Saat karetnya mengeras, menjepit bulu mata jadi terasa perih dan menyengat. Menyiapkan cadangan untuk diganti lebih dulu lahir dari kelembutan hati yang memperhitungkan bahkan rasa sakit sekecil apa pun."},"ICON-0503":{"nm":"Kuas Concealer","de":"Ujung bulu kuas yang halus perlahan menghapus bayangan. Menghadirkan cahaya ke tempat yang tak pernah tersentuh sinar. Tangan yang menambahkan cahaya, bukan sekadar menutupi kekurangan, menyempurnakan segalanya dengan jauh lebih anggun."},"ICON-0504":{"nm":"Ayakan Bedak","de":"Saring bedak halus sekali saja, dan ia akan menempel mulus tanpa menggumpal. Kerepotan menyaringnya sekali lagi lewat ayakan itu. Pada akhirnya, ketulusan tampak dari ujung jari yang mau menempuh satu langkah tambahan."},"ICON-0505":{"nm":"Jepit Roll Poni","de":"Jepitan yang menggulung poni bulat dan menahannya sejenak. Selagi menunggu, bentuknya perlahan tertata dengan tenang. Kerapian mekar di tempat yang tahu cara menunggu tanpa tergesa."},"ICON-0506":{"nm":"Sendok Wax Rambut","de":"Wax diciduk dengan sendok kecil ini sebelum sempat menempel di tangan. Kendali diri untuk mengambil hanya sebanyak yang benar-benar diperlukan. Tangan yang tahu menggunakan tanpa berlebihan menciptakan tekstur paling alami."},"ICON-0507":{"nm":"Alas Catokan Rambut","de":"Catokan yang membara panas tak bisa sembarangan diletakkan. Selembar alas penyangga melindungi meja sekaligus tangan. Tempat yang menangani panas selalu butuh persinggahan yang aman."},"ICON-0508":{"nm":"Sampel Minyak Rambut","de":"Satu tetes saja sudah cukup berkilau, jadi ia dikemas rapi dalam botol sampel mungil dan diselipkan ke sudut tas. Botol kecil, dibanding yang besar, justru lebih sering berada di genggaman tangan."},"ICON-0509":{"nm":"Sisir Pembersih Kuas","de":"Rambut yang kusut di bulu sikat disisir perlahan turun dengan garuk kecil ini. Merawat alat adalah ritual sunyi setelah pekerjaan usai. Sikat yang terawat baik akan membentuk tekstur esok hari dengan indah."},"ICON-0510":{"nm":"Gulungan Ikat Rambut","de":"Cukup dililitkan pada gulungan, dan semuanya langsung terlihat sekali pandang. Bundelan kecil yang tertata melingkar rapi ini adalah kelonggaran penuh kasih yang dihadiahkan untuk pagi-pagi sibuk saat ikat rambut biasa berguling ke segala arah."},"ICON-0511":{"nm":"Paket Sarung Tangan Pewarna","de":"Sarung tangan tipis yang dipakai agar tangan yang mewarnai tidak ikut terwarnai. Keinginan untuk menyambut hal berikutnya dengan tangan bersih meski pekerjaan sudah selesai. Perlindungan hanyalah nama lain dari kesiapan semacam itu."},"ICON-0512":{"nm":"Pouch Jaring Rambut","de":"Kantong kecil untuk melipat rapi dan menyimpan jaring yang menjaga bentuk rambut. Semakin tak bervolume suatu benda, semakin mudah ia hilang, karenanya sentuhan penuh perhatian yang memberinya rumah sendiri begitu berharga."},"ICON-0513":{"nm":"Pena Perapi Rambut Halus","de":"Pena yang menepuk lembut rambut-rambut halus yang mencuat agar kembali rapi. Sentuhan terakhir setelah semua penataan besar selesai. Penyelesaian selalu berupa pekerjaan mengelus bagian terkecil."},"ICON-0514":{"nm":"Tutup Uji Parfum","de":"Saat memilih aroma, jangan langsung mendekatkannya ke hidung. Oleskan pada tutup kecil ini dan biarkan menyebar di udara agar corak sejatinya terungkap. Wewangian pun baru jujur ketika dicium dari jarak selangkah."},"ICON-0515":{"nm":"Botol Parfum Roll-On","de":"Bola bundar menggelinding pelan, menggoreskan wangi di pergelangan tangan. Berbeda dari botol parfum lama yang dioleskan dengan tepukan, kini satu garis meluncur dan menyebar. Wangi meninggalkan kisah berbeda setiap kali ia menyentuh."},"ICON-0516":{"nm":"Tutup Body Mist","de":"Tutup kecil yang mengurung wangi yang menyebar bagai kabut. Menutup dan menjaga sesuatu yang hanya berhamburan saat dibuka. Hati yang sedikit berhemat membuat wangi itu bertahan lebih lama di sisi kita."},"ICON-0517":{"nm":"Gantungan Kunci Hand Cream","de":"Pasangkan gantungan pada krim kecil untuk tangan, dan ia akan menemani ke mana pun pergi. Teman yang bergoyang-goyang tergantung di luar tas menjadi kabar penuh kasih bagi ujung jari yang kering."},"ICON-0518":{"nm":"Gantungan Spons Mandi","de":"Setelah membuat busa yang menggelembung, ia harus dikeringkan dengan baik. Bola jaring yang tergantung di kait sudut kamar mandi mengibaskan air, menanti pagi esok yang segar."},"ICON-0519":{"nm":"Pouch Bola Pijat","de":"Kantong kecil untuk menyimpan bola keras yang melemaskan bahu yang kaku. Istirahat singkat di balik panggung, saat menenangkan tubuh yang tegang dengan diam-diam. Perhatian selalu dimulai dari diri sendiri."},"ICON-0520":{"nm":"Kaleng Koyo Pendingin","de":"Kaleng yang mengumpulkan koyo yang mendinginkan begitu ditempelkan. Pada malam setelah panggung yang membara usai, sebuah penghiburan kecil tertidur di dalamnya, perlahan meredakan tubuh dan hati yang memanas."},"ICON-0521":{"nm":"Pena Minyak Kuku","de":"Tekan, gosok, berkilau. Satu tetes saja cukup untuk ujung jari yang kering. Tak perlu perawatan mewah, kilau lembut yang menyebar dari ujung pena kecil ini melingkupi kuku dengan anggun. Perhatian dimulai dari satu tetes kecil seperti ini."},"ICON-0522":{"nm":"Klip Kantong Wangi","de":"Simpul kecil yang mengikatkan wangi pada kertas. Setiap kali laci dibuka, segenggam aroma lembut menyapa lebih dulu daripada tangan. Kelembutan yang tetap dekat meski tak terlihat—satu klip diam-diam menyimpan kehangatan sehari penuh."},"ICON-0523":{"nm":"Baki Ujung Kuku Palsu","de":"Panggung kecil untuk membentangkan warna sepuluh jari lebih dulu. Rona mana yang cocok dengan hari ini? Audisi sunyi pun terbuka di atas baki. Sekejap memilih itu entah kenapa mendebarkan, dan hari sang ujung jari dimulai dari sini."},"ICON-0524":{"nm":"Tutup Pendorong Kutikula","de":"Ada juga kelembutan dalam tindakan mendorong. Satu kulit ari yang terkelupas, perlahan dengan ujung bulat, tanpa terburu. Tangan yang tergesa selalu melewatkan sesuatu, maka merapikan lebih dekat dengan hati yang menatap perlahan."},"ICON-0525":{"nm":"Mini File Buffer Kuku","de":"Sisi kasar dan sisi halus, dua wajah digenggam dalam satu tangan. Mengikir bagian yang bersudut hingga licin adalah hal remeh, namun kesempurnaan selalu datang dari sentuhan-sentuhan kecil semacam ini. Kata akhir, pada akhirnya, milik kelembutan."},"ICON-0526":{"nm":"Lembar Stiker Kuku","de":"Bintang, bunga, hati—cukup pilih satu lembar yang pas dengan suasana hati hari ini lalu tempelkan. Di atas lembaran berjajar gambar sekecil kuku, satu stiker berkilau bagai tanda tangan penuh kasih yang tertinggal di ujung jari."},"ICON-0527":{"nm":"Pelat Penutup Lampu Gel","de":"Selaput tipis yang mengurung cahaya sejenak. Selama proses pengerasan, mata beristirahat dan hanya ujung jari yang diam-diam mengeras. Bahkan menunggu pun butuh sehelai naungan—dalam waktu yang tak tergesa, ujung jari hari ini pun selesai."},"ICON-0528":{"nm":"Kaleng Aksesori Nail Art","de":"Kepingan-kepingan berkilau tertidur di tiap sekat. Batu kristal, mutiara, serbuk bintang—tutupnya dibuka dengan debar bagai membuka kotak perhiasan tanpa nama. Cahaya mana yang akan diletakkan di kuku? Momen memilih itulah yang paling berkilau."},"ICON-0529":{"nm":"Paket Sarung Tangan Perawatan","de":"Liburan singkat yang dinikmati tangan selagi tidur. Di dalam sarung tangan, kulit kering perlahan melembap sepanjang malam. Perawatan, pada akhirnya, adalah sesuatu yang terjadi di tempat tak terlihat—begitu pagi tiba, ujung jarilah yang pertama mengenal kelembutan itu."},"ICON-0530":{"nm":"Botol Pompa Remover","de":"Sekali tekan, tepat secukupnya. Aroma sejuk yang meresap ke kapas menghapus bersih jejak kemarin di atas kuku. Bahkan mengosongkan pun punya iramanya sendiri, satu kali pompaan diam-diam menyediakan ruang untuk warna baru."},"ICON-0531":{"nm":"Penjepit Batu Kristal","de":"Untuk mengambil permata yang lebih tipis dari ujung jari, dibutuhkan tangan yang lebih halus lagi. Ujung penjepit yang memindahkan satu titik tanpa gemetar—kelembutan adalah bagian dari alat, sama seperti bagian dari hati. Satu cahaya kecil menemukan tempatnya."},"ICON-0532":{"nm":"Pelat Penyimpan Anting","de":"Agar anting yang kehilangan pasangannya tak lagi tersesat di dalam laci. Selipkan sepasang demi sepasang ke tempatnya, dan waktu memilih di pagi yang sibuk pun terasa jauh lebih ringan. Merapikan adalah kebaikan kecil yang dihadiahkan untuk diri sendiri di masa depan."},"ICON-0533":{"nm":"Cincin Ukur Jari","de":"Sebundel lingkaran kecil yang mengubah lingkar jari menjadi angka. Mencoba satu per satu ukuran yang pas mirip dengan perlahan mengenali sesuatu yang benar-benar cocok untuk diri sendiri. Seperti kelegaan itu, saat semuanya pas sempurna."},"ICON-0534":{"nm":"Pin Tali Jam Tangan","de":"Ketika tali jam mengendur, satu pin kecil ini kembali mengikat waktu pada pergelangan tangan. Bagian yang tersembunyi paling dalam bertahan paling lama—sesuatu yang diketahui dalam diam oleh jam yang telah lama dikenakan."},"ICON-0535":{"nm":"Pelat Anti-Kusut Kalung","de":"Sekat-sekat dibuat agar rantai tipis tak saling kusut. Pagi tanpa kusut dimulai dari sekat-sekat kecil yang dipisahkan sejak malam sebelumnya. Kelonggaran, pada akhirnya, adalah hati yang tertata rapi sebelum tangan sempat menyentuhnya."},"ICON-0536":{"nm":"Pengunci Belakang Bros","de":"Semakin megah bagian depan, semakin diam bagian belakang. Pengunci kecil yang menopang kokoh bros yang disematkan di kain—di balik cahaya yang terlihat, selalu ada tangan tanpa nama yang bertahan. Tempat yang justru semakin kokoh karena tak terlihat."},"ICON-0537":{"nm":"Pouch Kacamata Hitam","de":"Kain lembut membungkus tenang lensa yang telah menahan cahaya musim panas. Kantong kecil yang menjaga sepasang penglihatan dari benturan di dalam tas. Hati yang menyayangi sesuatu selalu datang sebagai selapis kelembutan seperti ini."},"ICON-0538":{"nm":"Pelubang Sabuk","de":"Untuk pinggang yang menyusut satu lubang, atau musim yang melebar satu lubang. Cukup lubangi satu lagi, dan sabuk kembali pas di badan. Yang selalu berubah adalah diriku, dan menyesuaikan dalam diam adalah tugas alat kecil ini."},"ICON-0539":{"nm":"Klip Cincin Syal","de":"Klip yang mengumpulkan syal yang melorot ke satu titik dan menahannya. Gaya yang terus terurai tertiup angin akhirnya menemukan tempatnya. Bahkan keanggunan kadang bersandar pada jepitan kecil ini, merapikan hari yang nyaris berantakan."},"ICON-0540":{"nm":"Set Gantungan Charm","de":"Sekumpulan gantungan kecil untuk digantung di sisi tas datang sebagai satu set. Hati yang membawa serta hal-hal yang disukai—menggantungkan suasana hari ini pada satu charm terasa seperti ritual kecil yang hanya diketahui diri sendiri, dan entah kenapa itu menyenangkan."},"ICON-0541":{"nm":"Alat Penghilang Bulu Kain","de":"Ketika sweater tampak menua semalam karena bulu-bulu kecil bermunculan, gulirkan alat ini perlahan dan ia kembali mengenakan wajah yang baru. Dengung ringan yang mengangkat kelusuhan itu entah kenapa terasa menenangkan. Pakaian tersayang pun hidup kembali sekali lagi."},"ICON-0542":{"nm":"Kartu Pengharum Kain","de":"Diselipkan dalam-dalam di lemari, ia diam-diam memenuhi hari-hari dengan wangi. Surat yang ditulis dengan aroma, bukan kata—selembar yang terbaca tanpa perlu dibuka. Setiap pagi saat pakaian dikeluarkan, kelembutan yang dituliskan kemarin menyebar lebih dulu."},"ICON-0543":{"nm":"Pin Anti Statis","de":"Pada pagi musim dingin ketika ujung rok menempel di kaki, satu pin diam-diam melepaskan lekatan itu. Kedamaian kecil yang menenangkan bahkan gesekan yang tak terlihat—begitu satu kekesalan sepele lenyap, hari terasa jauh lebih mulus."},"ICON-0544":{"nm":"Sikat Pakaian Portabel","de":"Tepat sebelum melangkah keluar pintu, seurat debu hinggap lembut di bahu. Buka sikat yang terlipat, satu sapuan, dan kesan pertama kembali rapi. Penyelesaian selalu terjadi di depan pintu, dan kerapian dituntaskan oleh satu sentuhan itu."},"ICON-0545":{"nm":"Label Kantong Cucian","de":"Kurung hal-hal yang tak boleh tercampur dalam kantong jaring, dan label diam-diam menuliskan namanya. Bahkan cucian punya tempatnya sendiri, dan tempat itu disertai penanda kecil. Ketertiban hari yang mudah kusut tumbuh dari label kecil ini."},"ICON-0546":{"nm":"Pena Penghilang Noda","de":"Bahkan bekas setetes kopi di kemeja pun perlahan menghilang saat ditepuk-tepuk. Pena yang bukan menutupi kesalahan, melainkan diam-diam menghapusnya. Setiap orang butuh satu kesempatan untuk memulai hari kembali dengan bersih."},"ICON-0547":{"nm":"Kain Pengilap Sepatu","de":"Sekali usap dengan kain ini, kulit kembali memancarkan kilaunya. Semakin lama sepatu dipakai, semakin dalam kilaunya meresap. Kilau adalah balasan atas waktu yang dijalani bersama—sepatu diam-diam mengukir tahun-tahun itu di atas punggung kaki."},"ICON-0548":{"nm":"Tutup Ujung Tali Sepatu","de":"Topi kecil yang dipasangkan pada ujung tali yang terurai. Agar tak melirik ke mana-mana sebelum garis akhir, ujungnya disegel erat. Satu tali yang terikat baik mengantarkan satu langkah lebih jauh—kewaspadaan sekecil apa pun menjadi keberanian untuk berlari sampai akhir."},"ICON-0549":{"nm":"Chip Nama Gantungan Baju","de":"Di antara gantungan-gantungan yang serupa, satu chip kecil ini diam-diam menunjukkan \"tempatku\". Penunjuk arah yang sunyi, meredakan kekacauan pagi yang sibuk—semakin sedikit repot mencari, semakin ringan pula awal hari."},"ICON-0550":{"nm":"Kaleng Pinset Lensa","de":"Ada kalanya dibutuhkan ujung yang lebih presisi dari ujung jari. Pinset yang mengangkat lensa kecil tanpa gemetar menunggu giliran di dalam kaleng. Presisi selalu tertidur siap dalam diam, terjaga seketika begitu dipanggil."},"ICON-0551":{"nm":"Paket Mini Kapas Wajah","de":"Sebundel kecil yang berisi tepat secukupnya untuk sekali pakai. Volume di dalam tas berkurang, namun kelembutannya tetap sama. Membawa sedikit pun adalah bentuk kasih sayang—hari yang ringan mengisi tempat yang dikosongkan itu."},"ICON-0552":{"nm":"Wadah Kertas Minyak Wajah","de":"Tekan lembut kilau yang menyebar di hidung siang hari dengan selembar kertas tipis. Kertas-kertas yang tertidur rapi berbaris di dalam wadah—untuk momen menarik satu lembar saja, siapa pun berhenti sejenak menatap diri sendiri dengan lembut di depan cermin."},"ICON-0553":{"nm":"Cermin Sisir Lipat","de":"Terlipat, ia sebesar telapak tangan; terbuka, ia menjadi cermin dan sisir. Alat serbaguna kecil yang menangani penataan darurat dari sudut tas. Kerapian bukanlah hal besar, melainkan lebih dekat pada hati yang bisa dibuka di mana saja untuk satu sentuhan cepat."},"ICON-0554":{"nm":"Tutup Pisau Cukur Travel","de":"Ia menidurkan dengan aman mata pisau yang tajam di dalam tas perjalanan. Berkat tutup yang tumpul namun kokoh ini, ujung jari yang meraba-raba di pagi sibuk pun tak terluka. Menjaga selalu berarti menutupi bahaya satu langkah lebih dulu."},"ICON-0555":{"nm":"Gantungan Lip Balm","de":"Perisai kecil yang bergoyang di tali tas. Tanpa perlu khawatir menggelinding di saku dan pecah, bibir kering selalu berada dalam jangkauan tangan. Menjaga sesuatu tetap dekat, pada akhirnya, adalah hati yang meletakkan yang dibutuhkan pada jarak paling dekat."},"ICON-0556":{"nm":"Holder Hand Sanitizer","de":"Tekan dengan satu tangan, dan segenggam kebersihan menetes keluar. Gantungkan di pintu, di meja, di mana saja, dan kebiasaan mencuci tangan pun terasa semakin dekat. Kebiasaan baik bukanlah hal besar, ia dimulai dari jangkauan tangan."},"ICON-0557":{"nm":"Pouch Tisu Slim","de":"Rangka ramping ini menyimpan segenggam tisu. Tanpa membuat saku menggembung, ia selalu siap dalam diam menghadapi hidung meler atau air mata yang tiba-tiba. Selembar untuk diselipkan kepada seseorang—kesiapan yang semakin ramping justru semakin indah."},"ICON-0558":{"nm":"Botol Mini Obat Kumur","de":"Pada hari harus bertemu seseorang setelah makan ramyeon pedas, botol kecil ini diam-diam menangani penyegaran mulut. Satu tegukan kesegaran kadang menjadi kepercayaan diri yang besar, membuat sapaan yang ragu-ragu jadi jauh lebih ringan."},"ICON-0559":{"nm":"Chip Bedak Kilau","de":"Sentuhkan sedikit ke ujung jari lalu usapkan ke pipi, dan ia menyebar bagai serbuk bintang berhamburan di bawah lampu sorot. Pipi biasa berkilau seketika berkat sihir satu chip kecil ini. Cahaya selalu datang seperti ini, lewat serbuk yang menempel di ujung jari."},"ICON-0560":{"nm":"Stiker Peredam Glitter","de":"Di tempat yang terlalu berkilau hingga terasa berlebihan, stiker ini pelan-pelan meredam cahayanya. Mengurangi selapis kemewahan juga bagian dari berhias—kelembutan yang tersisa di ruang yang dikurangi itu, terkadang menjadi rasa yang berbeda lagi."},"ICON-0561":{"nm":"Pena Pengambil Batu","de":"Sebuah batu kecil tersangkut di ujung kaki saat berjalan di jalan. Pena yang sengaja membungkuk untuk memungutnya. Hati yang diam-diam memungut dengan ujung jari sesuatu yang bisa saja terlewatkan begitu saja—kelembutan selalu dimulai dari berhenti sejenak."},"ICON-0562":{"nm":"Pelat Penyimpan Bulu Mata Palsu","de":"Pelat kecil untuk merebahkan satu per satu bulu mata dengan rapi. Bahkan setelah dilepas, lengkungan indahnya tak pernah kacau. Penghiburan sunyi dan rapi dari penyimpanan yang berkata bahwa hal-hal yang sejenak diletakkan pun mengingat tempatnya."},"ICON-0563":{"nm":"Tutup Pemotong Selotip Kelopak Mata","de":"Dua mata pisau bertemu dan memutus simpul dalam sekali gerak. Semakin bersih potongannya, semakin rapi simpul berikutnya. Dari ujung jari yang pandai mengikat dan pandai memutus, awal yang baru pun terurai jauh lebih ringan."},"ICON-0564":{"nm":"Selotip Garis Wajah","de":"Satu garis mengikuti garis rahang, ditempelkan hati-hati sambil menahan napas. Kontur bukanlah menggambar garis yang tak pernah ada, melainkan menunjuk tempat yang sudah indah sejak semula. Sentuhan yang lembut mengikuti alur yang memang selalu ada di sana."},"ICON-0565":{"nm":"Bedak Pemantul Cahaya","de":"Bedak yang menyerap cahaya sepenuhnya lalu mengembalikannya dengan anggun. Meski tak bersinar sendiri, ia menerangi dengan menghamburkan cahaya yang diterimanya menjadi butiran halus. Bagai meneruskan kelembutan yang diterima kepada orang lain, kilau semakin besar semakin dibagikan."},"ICON-0566":{"nm":"Kipas Pengunci Riasan","de":"Embusan kipas yang menahan riasan yang telah dikerjakan susah payah hingga akhir hari. Agar tak luruh, agar tak meleleh, ia diam-diam mendinginkan dan mengeraskannya. Agar wajah yang dirawat dengan tulus tetap jelas sampai tirai panggung turun."},"ICON-0567":{"nm":"Chip Palet Koreksi Warna","de":"Kepingan-kepingan kecil yang meredakan dan meluruskan rona yang timpang, satu sekat demi satu sekat. Bahkan warna yang tampak canggung sendirian akhirnya menjadi cerah begitu ada warna serasi di sampingnya. Hanya ketika warna bergandengan tangan dengan warna, terciptalah satu lukisan yang jernih."},"ICON-0568":{"nm":"Paket Syal Leher","de":"Lilitkan di leher, dan udara dingin ruang latihan fajar pun mereda jauh. Hangat seperti sentuhan tangan nenek yang melilitkan syal di leher cucunya. Dingin selalu datang lebih dulu ke tempat yang paling tipis, karenanya ia merengkuh tengkuk terlebih dahulu."},"ICON-0569":{"nm":"Kantong Penutup Mata Hangat","de":"Amplop kecil untuk menyimpan penutup mata yang dihangatkan. Begitu bagiannya dibuka, kehangatan yang mengantuk perlahan menyebar di kelopak mata. Ritual penuh kasih sebelum tidur, menyegel sejenak hari yang melelahkan lalu melepaskannya."},"ICON-0570":{"nm":"Filter Humidifier Portabel","de":"Selaput saring kecil yang mengembalikan kelembapan pada ruangan yang kering kerontang. Dari dalam yang tak terlihat, ia diam-diam menyaring yang keruh. Kelembapan yang memenuhi ruangan adalah kejernihan yang dijaga oleh jerih payah seseorang yang tak terlihat."},"ICON-0571":{"nm":"Kotak Pengatur Vitamin","de":"Kotak yang membagi pil sehari ke dalam sekat-sekat. Rajin meminumnya adalah janji untuk berdiri di panggung esok hari juga. Di setiap sekat kecil, tertata rapi hati yang menyayangi diri sendiri."},"ICON-0572":{"nm":"Wadah Penyumbat Telinga Tidur","de":"Rumah bagi penyumbat telinga yang sejenak menutup suara dunia. Bahkan keheningan pun butuh perawatan, karenanya ia berbaring rapi di dalam wadah. Bahwa malam yang tertidur lelap membuat suara esok hari bangun jernih kembali, istirahat mengetahuinya dengan baik."},"ICON-0573":{"nm":"Klip Handuk Dingin","de":"Klip yang menggigit kuat di bahu agar handuk yang didinginkan tak melorot. Pada hari yang terik, seurat kesejukan yang menyentuh tengkuk membantu bertahan sepanjang sore yang panjang. Bahkan kesejukan kecil, bila ditahan di tempatnya, bertahan jauh lebih lama."},"ICON-0574":{"nm":"Kantong Bola Peregangan","de":"Kantong untuk menyimpan kembali bola yang telah melemaskan tubuh. Merentang lebar lalu mengumpulkannya kembali kecil mirip embusan napas masuk dan keluar. Di antara membentang dan mengumpulkan itulah, tubuh dan hati perlahan mengeras dengan kokoh."},"ICON-0575":{"nm":"Gulungan Perban Kompresi","de":"Pita yang melilit pergelangan kaki yang terkilir putaran demi putaran. Ia bukan mencekik, melainkan diam-diam menopang. Semakin terbebani suatu tempat, semakin ia butuh tangan yang bertahan diam di sisinya—begitu bisik gulungan itu saat melilit."},"ICON-0576":{"nm":"Tag Cek Kondisi","de":"Tag yang ditulisi kondisi hari ini dalam satu baris lalu digantungkan. Menggantungkan baik dan buruk dengan jujur adalah keberanian kecil. Alih-alih berpura-pura baik-baik saja, tuliskan diri hari ini, dan seseorang akan membaca satu baris itu dan diam-diam menjaga."},"ICON-0577":{"nm":"Kapsul Pengharum Sepatu","de":"Kapsul wangi yang diselipkan ke dalam sepatu. Penghiburan kecil dan lembut yang dihadiahkan untuk kaki yang menjelajahi panggung seharian. Wangi terbaik untuk tempat yang bekerja paling keras—kelembutan menjangkau hingga ujung kaki, tanpa terlewat sedikit pun."},"ICON-0578":{"nm":"Tabel Ukuran Insole","de":"Tabel yang mencatat jelas ukuran kaki bahkan di atas selembar insole. Satu pasang yang pas sempurna membuat langkah di panggung terasa ringan. Memperhitungkan langkah kaki yang berbeda-beda setiap orang—kecocokan, pada akhirnya, adalah hati yang menatap dalam-dalam ke diri orang lain."},"ICON-0579":{"nm":"Gantungan Kunci Sendok Sepatu","de":"Gantungan kunci dengan sendok sepatu yang diperkecil sebesar telapak tangan. Perhatian kecil yang memuluskan sekejap saat mengenakan sepatu. Kaki yang melangkah ke jalan selalu membawa serta, tergantung lembut di sisinya, bantuan penuh kasih dari seseorang."},"ICON-0580":{"nm":"Sarung Debu Tas","de":"Kain yang lembut menyelimuti tas kesayangan dari debu. Bahkan saat tak dipakai, ia menidurkan tas dengan rapi dan menjaga teksturnya. Hal-hal yang jarang tersentuh tangan namun tetap tinggal di hati, membawa perawatan setenang ini."},"ICON-0581":{"nm":"Pin Pengatur Tali","de":"Pin yang menyesuaikan tali yang mengendur agar pas ke tubuh. Terlalu longgar, bahu melorot; terlalu ketat, napas jadi sesak. Dalam penyesuaian sekecil satu sekat untuk menemukan yang pas, kostum panggung dan hati pun akhirnya merasa lega."},"ICON-0582":{"nm":"Pena Pelumas Ritsleting","de":"Goreskan sekali pada ritsleting yang seret, dan ia kembali meluncur mulus. Betapa melegakannya suara sesuatu yang tersendat tiba-tiba terlepas. Yang membuat tempat yang macet mengalir kembali adalah satu goresan kelancaran."},"ICON-0583":{"nm":"Ujung Pembersih Sepatu Kets","de":"Ujung sikat yang membersihkan sepatu kets berlumur debu, titik demi titik. Di luar panggung, ia dengan tekun menghapus jejak latihan yang tak terlihat. Melihat ujung sepatu memutih kembali, rasanya esok bisa berlari lagi dengan hati yang baru."},"ICON-0584":{"nm":"Tutup Semprotan Anti Air","de":"Tutup anti air yang menggulung tetesan hujan menjadi bulatan lalu menjatuhkannya. Melapisi satu lapis lebih dulu agar tak basah adalah kelembutan yang memandang jauh ke depan. Karena tahu hari hujan akan datang, satu lapis pelindung dibentangkan di hari cerah ini."},"ICON-0585":{"nm":"Kain Pelindung Kulit","de":"Kain yang diletakkan lembut di atas kulit untuk mencegah kerutan. Ia menjaga teksturnya seperti tangan lama yang membungkus layar lipat dengan kertas hanji. Semakin lama akan disimpan dekat, semakin perlahan—menjinakkan hanyalah nama lain dari waktu yang dihabiskan untuk merawat."},"ICON-0586":{"nm":"Sabuk Nama Koper","de":"Sabuk nama yang membuat tas sendiri langsung dikenali di antara ribuan tas lain. Di antara barang-barang yang berputar-putar di ban berjalan, ia mengangkat tangan dengan satu huruf. Sejauh apa pun perjalanan, satu nama adalah rasa lega akan bertemu kembali."},"ICON-0587":{"nm":"Klip Kantong Kompresi","de":"Klip yang menekan rata dan mengunci barang bawaan yang menggembung. Ia bukan sekadar dikosongkan, melainkan dilipat rapi berlapis-lapis. Dari ujung jari yang merapikan barang hingga sederhana, keserakahan pun ikut mengecil, begitu diam-diam disampaikan oleh barang bawaan yang tertekan erat."},"ICON-0588":{"nm":"Lembar Deterjen Travel","de":"Lembar deterjen yang mengubah wastafel menjadi tempat mencuci hanya dengan satu lembar. Ia menyerupai kebijaksanaan perantau yang mencuci pakaian sendiri di jalan yang jauh dari rumah. Bepergian ringan namun tetap membawa kerapian, sikap lama seorang musafir di jalan."},"ICON-0589":{"nm":"Sarung Bantal Leher","de":"Sarung bersih yang baru dipasangkan pada bantal yang menopang leher. Tempat untuk bersandar harus selalu bersih agar hati tenang. Membiarkan tempat itu lembut dan bersih agar seseorang bisa bersandar dengan nyaman—keramahan dimulai dari situ."},"ICON-0590":{"nm":"Tali Timbangan Bagasi","de":"Tali yang mengangkat tas tinggi-tinggi untuk menaksir beratnya. Sebelum berangkat, berat barang bawaan itu digenggam lebih dulu dengan tangan. Di antara yang akan dibawa dan yang akan ditinggalkan, momen menimbang diam-diam bahkan beban hati sekalipun."},"ICON-0591":{"nm":"Sepasang Pouch Sepatu","de":"Sepasang pouch yang menyimpan dua sepatu, kiri dan kanan, berdampingan. Yang mudah hilang bila terpisah menjadi kokoh bila dipasangkan. Hal-hal yang selalu bepergian bersama memiliki kekuatan untuk diam-diam saling menjaga."},"ICON-0592":{"nm":"Gantungan Tas Tambahan","de":"Pada hari satu tangan tak lagi cukup, satu gantungan kecil untuk menggantungkan tas sejenak. Satu ruang cadangan untuk hari-hari dengan barang bawaan yang tak mungkin semuanya dijinjing. Hanya dengan adanya tempat untuk digantungkan sebentar, bahu terasa jauh lebih ringan."},"ICON-0593":{"nm":"Chip Itinerari Perjalanan","de":"Rute perjalanan hari itu dituliskan jelas pada satu chip. Di mana bertemu dan ke mana mengalir selanjutnya, garis panduan yang digariskan lebih dulu untuk langkah kaki yang kurang tahu arah. Jalan yang ditempuh bersama, bila dicatat sekat demi sekat, jarang tersesat."},"ICON-0594":{"nm":"Tutup Adaptor Serbaguna","de":"Tutup yang pas terpasang bahkan pada stopkontak negeri asing. Meski bentuknya berbeda, pada akhirnya semua tersambung menjadi satu. Menghubungkan hal-hal yang datang dari tempat berbeda—keserasian diam-diam dimulai dari satu perubahan kecil."},"ICON-0595":{"nm":"Sarung Kartu Transportasi","de":"Selembar bening yang melindungi kartu setiap kali menyentuh gerbang tiket. Perjalanan pulang-pergi tiap hari, bahkan bekas gesekan yang mulai usang, dibungkus dengan lembut. Bahwa jalan biasa pun bisa menjadi kenangan bila dijaga, selapis tipis ini membuktikannya."},"ICON-0596":{"nm":"Klip Tiket","de":"Klip yang menggigit rapi selembar tiket yang cepat kusut. Kehilangan tiket di jalan bisa membuat hati ikut goyah. Semakin kecil kertasnya, semakin erat harus dipegang—rasa aman perjalanan datang justru dari satu sekat itu."},"ICON-0597":{"nm":"Chip Memo Transit","de":"Chip kecil yang mencatat di mana harus berpindah kendaraan dalam satu baris. Di setiap persimpangan yang membingungkan, satu kata yang dicatat lebih dulu membuka jalan dengan terang. Memo adalah bisikan penuh kasih yang diam-diam dititipkan untuk diri sendiri di masa depan yang mungkin tersesat."},"ICON-0598":{"nm":"Tag Lolos Gerbang","de":"Tag yang diam-diam dikenali saat melewati gerbang. Bahkan jalan yang tampak tertutup akan terbuka begitu memiliki kelayakannya sendiri. Melangkah dengan tegas berarti maju ke ruang berikutnya dengan ringan tanpa ragu sedikit pun."},"ICON-0599":{"nm":"Holder Struk Taksi","de":"Setiap secarik kertas kecil mencatat jelas jejak jalan yang ditempuh hari itu. Kumpulkan struk yang berserakan ke segala arah dan selipkan rapi bersama, dan hari yang tampak biasa pun menumpuk, lembar demi lembar, menjadi perjalanan yang berarti."},"ICON-0600":{"nm":"Pita Reflektor Sepeda","de":"Pita yang menangkap cahaya lewat di jalan yang temaram dan diam-diam berkilau. Meski tak bersinar sendiri, ia menerangi dengan cahaya orang lain. Membuat diri terlihat adalah pesan penuh kasih dari jalan malam, agar pulang dengan selamat."},"ICON-0601":{"nm":"Pelindung Roda Koper","de":"Alasan sudut koper tetap mulus meski sudah berputar ribuan kali di atas ban berjalan bandara adalah pelindung kecil yang membungkus roda ini. Bagian yang paling dulu menyentuh jalan paling kasar—menjaga seseorang diam-diam selalu tersembunyi di tempat yang jarang diperhatikan."},"ICON-0602":{"nm":"Sarung Sandaran Kepala","de":"Dalam perjalanan bus yang panjang, kau memasangnya di sandaran kepala lalu bersandar ke jendela. Aroma penumpang sebelumnya, kelelahan hari kemarin—semuanya tak akan sampai sejauh ini. Tempat bersandar yang bersih adalah kenyamanan besar yang tak terduga di jalan yang asing."},"ICON-0603":{"nm":"Pin Penanda Parkir","de":"\"Lantai berapa, petak mana, ya.\" Siapa pun yang pernah tersesat lama di lahan parkir yang sepi tahu betapa menenangkannya pin ini. Satu penanda yang tertancap menggantikan ingatan yang memudar, menyiapkan jalan pulang lebih dulu."},"ICON-0604":{"nm":"Tali Gantungan Kunci Kamar","de":"Betapa mudahnya kunci kamar menghilang begitu saja. Untai pada tali dan lingkarkan di pergelangan tangan, maka satu kamar yang menunggu malam ini tak akan terlupakan. Bahkan di kota yang asing, rasa lega kecil karena punya tempat sendiri tergantung di pergelangan tangan."},"ICON-0605":{"nm":"Chip Tanda Gantung Pintu","de":"Saat gladi resik dimulai, sebuah chip digantungkan di pintu. Jangan ganggu—ini waktu untuk fokus sepenuhnya. Keheningan dalam di balik panggung dijaga diam-diam oleh sinyal-sinyal kecil seperti ini."},"ICON-0606":{"nm":"Pouch Perlengkapan Mandi","de":"Sikat gigi, sabun cuci muka, handuk sebesar telapak tangan. Ke mana pun pergi, cukup bawa pouch ini dan akhir maupun awal hari selalu tertata oleh sentuhan yang sama akrabnya. Segenggam kecil urusan rumah tangga yang membuat tempat tidur asing terasa seperti rumah sendiri."},"ICON-0607":{"nm":"Jepitan Handuk Cadangan","de":"Di samping wastafel, handuk cadangan itu selalu basah karena tak punya tempat. Jepit dengan klip dan gantungkan, maka ia akhirnya menemukan tempatnya. Memberi ruang untuk mengering—kebaikan biasanya berukuran sebesar ini."},"ICON-0608":{"nm":"Pouch Terminal Listrik","de":"Setiap kali membuka tas, charger-charger selalu kusut jadi satu gumpalan. Gulung seluruh terminal listrik dan masukkan, isi tas pun jadi lebih rapi. Kabel yang terurai berarti sedikit sudut hati juga ikut mengendur sebelum bepergian."},"ICON-0609":{"nm":"Label Nomor Ranjang","de":"Label angka tertempel di setiap ranjang susun asrama. Dengan satu label yang menunjukkan mana tempatmu, kamar baru yang asing pun berubah jadi rumah begitu malam tiba. Permulaan selalu sekecil ini."},"ICON-0610":{"nm":"Tali Jemuran Mini","de":"Kaitkan kedua ujungnya di antara bingkai jendela, dan jadilah tali jemuran. Di hari yang cerah, beberapa kaus kaki cucian tangan bergoyang kering dan lembut ditiup angin. Bahkan jauh dari rumah, keseharian tetap kering di atas seutas tali seperti ini."},"ICON-0611":{"nm":"Tag Pembeda Sandal","de":"Saat sandal menumpuk di depan pintu, sulit tahu punya siapa yang mana. Pasang satu tag kecil, dan sepatu pun mengenali pemiliknya. Hidup berdesakan bersama orang lain butuh penanda hangat seperti ini."},"ICON-0612":{"nm":"Holder Kupon Sarapan","de":"Holder untuk menyelipkan tiket sarapan. Di pagi buta yang lapar, selembar ini menjanjikan semangkuk sup yang masih mengepul. Satu hari di perjalanan selalu terbuka perlahan lewat satu santapan hangat."},"ICON-0613":{"nm":"Pita Reflektor Pergelangan Kaki","de":"Lilitkan di pergelangan kaki dan ia memantulkan cahaya dalam gelap. Di jalan malam, pita kecil ini melambai tanpa suara pada mobil yang mendekat dari kejauhan—\"ada orang di sini.\" Keselamatan berkilau sesederhana ini."},"ICON-0614":{"nm":"Tutup Tisu Basah","de":"Tutup yang pas terpasang di mulut kemasan tisu basah. Selembar demi selembar tertarik dengan lembut, dan sisanya tak mengering. Terlihat sepele, tapi benda yang selalu terjamah setiap hari selalu punya alasannya."},"ICON-0615":{"nm":"Tali Tikar Piknik","de":"Gulung tikar menjadi bundar dan ikat dengan tali. Di tepi sungai, di bawah naungan bunga sakura, di mana pun digelar, saat itu juga tempat itu jadi milik kita. Tali yang membawa kemanapun sebidang wilayah rumput seukuran telapak tangan."},"ICON-0616":{"nm":"Kotak Patch Anti Nyamuk","de":"Perlengkapan wajib malam musim panas, kotak penyimpan patch anti nyamuk. Kepedulian menyiapkan sesuatu sebelum gatal datang, tersimpan dalam satu ruang kecil ini. Barisan belakang panggung luar ruangan selalu terasa aman berkat persiapan-persiapan kecil seperti ini."},"ICON-0617":{"nm":"Kait Botol Minum Jalan Kaki","de":"Kait untuk menggantungkan botol minum di tas saat berjalan-jalan. Air yang bisa dijangkau tepat saat haus datang berarti bisa melangkah lebih jauh lagi. Sambungan kecil yang membuat seorang pejalan kaki tak pernah berhenti."},"ICON-0618":{"nm":"Keranjang Belanja Lipat","de":"Dibuka jadi keranjang belanja, dilipat muat di telapak tangan. Pas sekali untuk membawa seikat sayur yang jadi akrab setelah berkeliling gang pasar. Kearifan rumah tangga selalu tumbuh ke arah yang lebih ringkas, lebih ringan dibawa."},"ICON-0619":{"nm":"Jepitan Penahan Angin","de":"Di hari berangin, ia menjepit ujung tenda yang berkibar dan menahannya erat. Satu jepitan menekan diam yang tadinya terus bergoyang. Yang paling diandalkan di luar ruangan, ternyata, benda sekecil jari."},"ICON-0620":{"nm":"Pin Peneduh Sinar Matahari","de":"Pin yang ditancapkan di jendela untuk memiringkan dan menghalau sinar matahari. Saat cahaya siang terlalu terik, ia diam-diam melimpahkan segenggam naungan. Meringankan silau pun, bagi seseorang, bisa menjadi sentuhan paling lembut."},"ICON-0621":{"nm":"Tutup Peluit Darurat","de":"Tutup yang menutupi mulut peluit darurat. Agar debu tak masuk, agar saat benar-benar dibutuhkan ia berbunyi seketika. Ada benda yang membawa ketenangan hanya dengan keberadaannya, meski berharap tak pernah harus dipakai."},"ICON-0622":{"nm":"Tutup Ujung Payung","de":"Tutup kecil yang disematkan di ujung payung. Saat ujung yang runcing jadi tumpul, orang di sebelah maupun tas sendiri tak terluka. Sopan santun hari hujan diam-diam dimulai dari membungkus ujung tajam menjadi bulat dan lembut."},"ICON-0623":{"nm":"Kantong Penyimpan Jas Hujan","de":"Kantong untuk menggulung dan menyimpan jas hujan yang sudah dilipat. Ia menunggu diam-diam di sudut tas sampai hujan deras berikutnya turun. Persiapan, pada akhirnya, adalah secuil hati yang menyiapkan lebih dulu sesuatu yang mungkin tak pernah terpakai."},"ICON-0624":{"nm":"Pelindung Sepatu Anti Air","de":"Pasang di atas sepatu, dan air hujan tak lagi bisa meresap. Bahkan di jalan ke sekolah saat hujan monsun mengguyur, kaus kaki tetap kering. Hari tanpa basah sampai ujung kaki mengubah suasana hati jauh lebih besar dari yang dikira."},"ICON-0625":{"nm":"Bantalan Anti Licin Salju","de":"Tempelkan di bawah sepatu, dan jalan berlapis es pun terasa jauh lebih tidak menakutkan. Musim dingin itu, saat tergopoh-gopoh melintasi gang yang tertutup salju, bantalan ini diam-diam menjaga langkah agar tak tergelincir. Keandalan yang tersembunyi di balik langkah yang hati-hati."},"ICON-0626":{"nm":"Kalung Pendingin Leher","de":"Lilitkan di leher, dan hawa sejuk mengalir tenang. Kearifan musim panas untuk mengalungkan seuntai kesejukan di tengkuk bahkan di tengah teriknya hari-hari terpanas. Cara bertahan dari panas pun tiap tahun semakin cermat dan bersahaja."},"ICON-0627":{"nm":"Penyangga Kipas Genggam","de":"Penyangga untuk mendirikan kipas genggam. Saat kedua tangan bebas, halaman buku bisa dibalik, tulisan pun bisa ditulis alih-alih mengipas. Seuntai angin kecil membuat musim panas panjang di meja belajar terasa cukup tertahankan."},"ICON-0628":{"nm":"Pouch Penghangat Tangan","de":"Pouch untuk membawa penghangat tangan. Saat memasukkan jari yang membeku ke dalam saku untuk mencairkannya, hangat kecil itu sudah lebih dulu menunggu di sana. Bepergian di musim dingin bertahan berkat segenggam kehangatan ini."},"ICON-0629":{"nm":"Kotak Penutup Telinga","de":"Kotak untuk menyimpan penutup telinga. Tempat menyimpannya dengan rapi sampai dingin berikutnya datang. Benda yang tak tega dibuang meski musim berganti menyimpan kepercayaan diam-diam pada musim dingin yang akan kembali dijumpai."},"ICON-0630":{"nm":"Chip Pengukur Sinar UV","de":"Sentuhkan sebentar ke cahaya, dan chip ini memberi tahu kekuatan sinar UV hari ini lewat warna. Ia akhirnya membuat kekuatan sinar matahari yang tak terlihat menjadi terlihat. Seperti mengenakan sepasang mata kecil pembaca langit, diam-diam terpasang di pergelangan tangan."},"ICON-0631":{"nm":"Papan Stempel Gang","de":"Papan yang diisi dengan mengumpulkan stempel dari setiap toko di mulut gang. Setiap kotak yang terstempel, peta lingkungan tergambar semakin jelas di dalam hati. Kenangan yang dikumpulkan dengan berjalan kaki tersisa sebagai jejak tinta seperti ini."},"ICON-0632":{"nm":"Papan Pin Tempat Kunjungan","de":"Papan kecil tempat menancapkan satu pin untuk setiap tempat yang pernah dikunjungi. Semakin banyak titik bertambah, semakin luas pula lingkar duniaku. Setiap pin adalah jejak yang diam-diam berkata, \"aku pernah di sini.\""},"ICON-0633":{"nm":"Tali Kompas Kecil","de":"Sejauh apa pun tersesat, arah utara saja selalu tetap di tempatnya. Kompas kecil yang tergantung di dada, saat sama sekali tak tahu harus ke mana, lebih dulu menenangkan hati yang goyah dengan lembut."},"ICON-0634":{"nm":"Cincin Memo Petunjuk Arah","de":"Kertas-kertas catatan yang ditulis sambil mencari jalan, diuntai pada satu cincin. \"Belok kiri di kotak pos merah.\" Tulisan tangan seseorang yang canggung diam-diam menuntun gang yang asing. Jalan yang tertinggal di atas kertas jarang sekali memudar."},"ICON-0635":{"nm":"Buku Stiker Landmark","de":"Buku yang diisi satu stiker yang dibeli di setiap tempat tujuan. Menara, jembatan, tembok benteng tua bertumpuk halaman demi halaman. Mengumpulkan tempat-tempat yang pernah disinggahi mirip dengan menyentuh kembali waktu yang telah dilalui dengan ujung jari."},"ICON-0636":{"nm":"Chip Transfer Kereta Bawah Tanah","de":"Chip yang digenggam erat di stasiun transit tempat jalur-jalur bercabang. Sesaat singkat memilih ke mana harus pindah, kadang mengubah seluruh arah satu hari. Dengan satu pilihan kecil, kota menampakkan wajah yang berbeda."},"ICON-0637":{"nm":"Kartu Petualangan Lingkungan","de":"\"Hari ini, sampai toko roti di lingkungan ini.\" Tarik satu kartu, dan tujuan petualangan hari ini pun ditentukan. Gang yang biasa dilewati setiap hari pun berubah jadi jalan baru begitu ada misi. Selembar kartu yang mengingatkan bahwa petualangan tak pernah jauh."},"ICON-0638":{"nm":"Holder Kartu Nama Toko","de":"Holder untuk menyelipkan kartu nama yang diterima dari toko-toko langganan. Tempat makan yang enak, pemilik yang ramah menyapa, terkumpul satu demi satu, rapi berjajar. Menjadi akrab dengan sebuah kota dimulai dari lembaran-lembaran kecil kertas seperti ini."},"ICON-0639":{"nm":"Papan Lencana Penyelesaian Rute","de":"Papan yang terisi satu lencana setiap kali rute jalan kaki diselesaikan sampai akhir. Kepuasan menuntaskan perjalanan tersisa di tangan sebagai satu keping logam bundar. Kebanggaan yang hanya diketahui mereka yang berjalan sampai akhir, terpatri jelas di sini."},"ICON-0640":{"nm":"Gembok Ritsleting Tas Bergantungan Kunci","de":"Gembok kecil sekaligus gantungan kunci yang dipasang di ritsleting tas. Menjaga barang berharga dengan ketat sambil berdenting-denting di ujung tas. Teman perjalanan yang cukup cerdik, di mana keamanan dan hiasan menyatu dalam satu tubuh."},"ICON-0641":{"nm":"Tag Anti Hilang","de":"Ia meringkuk di kegelapan paling dalam tas, dan tepat di saat semua orang menyerah, ia berkedip pelan. \"Di sini.\" Suara sesuatu yang dikira hilang kembali ke ujung jari. Sekecil apa pun, ia menjaga sisi pemiliknya sampai akhir."},"ICON-0642":{"nm":"Gantungan Kunci Ritsleting","de":"Klik, sekali terpasang, tak sembarang tangan bisa membukanya. Ketangguhan yang menahan kuku yang tergesa dan jari yang diam-diam mendekat sama saja. Keamanan kadang boleh sedikit kaku, begitu ia mengingatkan lewat bobotnya yang mantap."},"ICON-0643":{"nm":"Tali Bel Anti Pencurian","de":"Penjaga gerbang tak kasat mata yang menjaga barang di atas rak agar tak keluar sembarangan sebelum dibayar. Saat tangan yang jujur menyentuhnya, ia tetap diam sampai akhir. Lonceng yang tak berbunyi adalah lonceng paling damai."},"ICON-0644":{"nm":"Label Penutup Kontak","de":"Ia diam-diam menutupkan satu lapis di atas nama dan nomor yang tertulis di kotak paket. Siapa yang tinggal di sana, ke mana ia dikirim—cukup diketahui penerimanya saja. Menutupi dengan baik pun sejenis kebaikan, katanya, sambil diam-diam menjaga tempatnya."},"ICON-0645":{"nm":"Pita Sampul Paspor","de":"Bandara yang asing, puluhan sampul yang sama berputar di ban berjalan saat fajar. Di antaranya, dengan warna yang hanya kau kenali, ia melambai \"lewat sini.\" Mantel kecil yang dikenakan pada dokumen yang berangkat jauh. Meski sampul aus, perjalanan tetap cerah."},"ICON-0646":{"nm":"Pouch Pemisah Uang Tunai","de":"Uang kertas di kiri, koin di kanan, uang darurat di kompartemen yang tak diketahui siapa pun. Ini tempat pertama yang diraba tangan yang baru pulang dari pasar. Bahkan hari yang kusut menemukan tempatnya di dalam sini, tersusun rapi dan berdenting."},"ICON-0647":{"nm":"Stiker Segel Keamanan","de":"Sekali dikelupas, bekasnya tertinggal. Hati nurani kecil yang jujur, yang tak pernah bisa menyembunyikan \"seseorang telah membukanya.\" Di balik setiap kotak yang tiba tersegel dan utuh, tersimpan kebisuan teman ini yang tak pernah berubah."},"ICON-0648":{"nm":"Chip Kontak Darurat","de":"Saku anak yang tersesat, bagian dalam tas laptop, ujung tali kekang anjing. Bahkan saat momen itu tak bisa bicara, ia meneriakkan nomor dengan jelas menggantikannya. Satu chip kecil menyimpan seutuhnya \"tolong antar aku pulang.\""},"ICON-0649":{"nm":"Tutup Remote Tongkat Swafoto","de":"Foto bersama yang selalu kehilangan satu orang karena lengan tak cukup panjang. Kini cukup satu ketukan tombol di ujung, seluruh keluarga masuk dalam satu bingkai. Di detik semua orang tersenyum bersama, aku diam-diam menekan rana dan meloncat masuk ke dalamnya."},"ICON-0650":{"nm":"Tali Pouch Lensa","de":"Tali yang mendekap erat lensa cadangan agar tak saling berbenturan di dalam tas. Karena sekeping kaca adalah satu pemandangan, bobot itu tak sembarang digoyang. Kehati-hatian seorang fotografer terikat di setiap simpulnya."},"ICON-0651":{"nm":"Cincin Kotak Filter","de":"Selembar tipis mengubah langit yang sama menjadi cahaya yang berbeda. Tempat menyimpan sihir-sihir kecil itu rapi dalam satu sarang bundar. Setiap kali kotak dibuka, ujung jari sejenak berdebar—senja seperti apa yang akan kutangkap hari ini?"},"ICON-0652":{"nm":"Pouch Tripod","de":"Dilipat sejengkal, dibentangkan jadi tiga kaki yang tak bergoyang. Digulung rapi teman yang akan menahan pemandangan menggantikan tangan yang gemetar. Semakin berat perlengkapannya, semakin lembut kain yang layak menjadi alasnya."},"ICON-0653":{"nm":"Bantalan Tali Kamera","de":"Berjalan seharian, tibalah saatnya kamera menekan bahu. Saat itulah satu bantalan diam-diam ikut menanggung sebagian bobotnya. Kenyamanan kecil dan empuk yang diletakkan di bahu yang berjalan jauh demi satu bidikan yang bagus."},"ICON-0654":{"nm":"Kartu Pemilah Memori","de":"Di malam ketika bingung ratusan kenangan tersimpan di kartu yang mana, penanda warna-warni menunjukkan jalannya. Perjalanan musim semi biru, panggung pertama kuning. Pustakawan kecil nan ramah yang memberi kenangan pun rak masing-masing."},"ICON-0655":{"nm":"Gulungan Kabel Charger","de":"Sebelum kabel-kabel menggelar pertunjukan kusut di dalam tas, gulung bundar dan tidurkan dengan rapi. Merapikan seutas kabel entah mengapa turut mengendurkan seutas hati. Bentuk yang tergulung rapi itu damai dipandang."},"ICON-0656":{"nm":"Label Cadangan Foto","de":"\"Foto-foto ini, sudah dicadangkan belum ya?\" Sebuah memo kecil yang menjawab lebih dulu kegelisahan yang tiba-tiba muncul larut malam. Semakin berharga momennya, semakin harus tersimpan di lebih dari satu tempat, begitu label ini menuliskannya dengan jelas."},"ICON-0657":{"nm":"Papan Bingkai Komposisi","de":"Memandang dunia lewat jendela persegi, langsung terlihat apa yang perlu dimasukkan dan apa yang perlu disisihkan. Foto yang bagus bukan soal menambahkan lebih banyak, melainkan mengurangi dengan baik—bingkai yang kosong itulah yang mengajarkannya lebih dulu."},"ICON-0658":{"nm":"Charm Dompet Koin","de":"Bergelantungan di ujung tas, menyimpan beberapa keping koin. Gudang harta kecil yang paling dulu terbuka di depan mesin penjual otomatis, di depan gerobak ikan panggang yang mengepul. Bunyi denting itu adalah efek suara kebahagiaan kecil."},"ICON-0659":{"nm":"Tusukan Kumpulan Struk","de":"Kertas-kertas yang nyaris dibuang tertusuk satu demi satu. Apa yang dimakan dan dibeli hari ini, struk adalah buku harian yang lebih jujur daripada buku kas mana pun. Kumpulkan sebulan penuh, dan jadilah catatan hidup yang cukup tebal."},"ICON-0660":{"nm":"Tag Keranjang Pasar","de":"Tergantung di pergelangan tangan yang berangkat belanja, ikut menjelajahi lorong pasar. Sepotong tahu, seikat daun bawang, bahkan kebaikan yang diberikan sebagai bonus. Semua bobot itu diterima tanpa keluhan. Teman yang lebih senang saat diisi daripada saat dikosongkan."},"ICON-0661":{"nm":"Papan Magnet Suvenir","de":"Pilih satu di setiap tempat tujuan dan tempelkan di pintu kulkas, dapur pun berubah jadi peta dunia mungil. Kota-kota yang pernah dikunjungi bergantungan berjajar, berbisik \"ayo ke sana lagi.\" Bahkan lembaran logam biasa punya kekuatan untuk menggenggam kenangan."},"ICON-0662":{"nm":"Buku Stempel Daerah","de":"Satu stempel per halaman, gang-gang yang pernah dilewati hidup kembali dalam tinta. Jejak merah yang terkumpul mengelilingi seluruh negeri adalah peta jejak langkah. Semakin sedikit kotak kosong, semakin lembut perjalanan berikutnya melambai."},"ICON-0663":{"nm":"Gulungan Tali Kado","de":"Kesabaran panjang tak berujung yang terus terurai hanya untuk mengikat satu kotak hadiah. Ia hanya mengizinkan simpul yang rapi bagi tangan yang tahu kapan harus memotong. Tergulung bundar, ia diam menunggu giliran berikutnya tiba."},"ICON-0664":{"nm":"Bantalan Pelindung Kado","de":"Ia mendekap hati yang rapuh dalam pelukan yang empuk. Bahkan di dalam bak truk pengiriman yang berguncang, ia bertahan lembut dan kokoh—\"tenang saja, aku menopangmu.\" Ia bahkan menjaga lebih dulu senyum cerah orang yang akan membuka kotak itu."},"ICON-0665":{"nm":"Stiker Penutup Label Harga","de":"Sehelai kebohongan kecil nan hangat yang diam-diam menutupi harga barang yang akan dihadiahkan. \"Tak perlu tahu berapa harganya, terima saja hatinya,\" katanya, sambil hinggap lembut di atas label harga. Bukan menyembunyikan, melainkan membuat hati itu bersinar lebih terang."},"ICON-0666":{"nm":"Chip Troli Belanja Mini","de":"Meski tak bisa mendorong troli sungguhan, teman kecil yang bergelantungan di ujung jari ini menyimpan seutuhnya debar jalan-jalan ke supermarket. Sekecil apa pun, debar \"mau beli apa hari ini?\" itu tak kalah berat dari yang aslinya."},"ICON-0667":{"nm":"Jepitan Sepatu Bercahaya","de":"Berkilau di ujung sepatu kets yang berjalan malam, mengirim sinyal pada mobil yang lewat, \"ada orang di sini.\" Cahaya kecil yang paling dulu menyambut di gang yang gelap. Keselamatan selalu dimulai diam-diam dari ujung jari kaki."},"ICON-0668":{"nm":"Tutup Senter Mini","de":"Pasang di kepala senter, dan cahaya menyebar lebih jauh, lebih lembut. Pesulap kecil yang melukis gugusan bintang di langit-langit tenda yang gelap gulita. Di malam-malam ketika kegelapan sedikit menakutkan, tak ada teman sebaik ini."},"ICON-0669":{"nm":"Tombol Notifikasi Pulang","de":"Tekan sekali, dan sebaris kalimat \"sudah sampai dengan selamat\" terbang ke keluarga yang jauh di sana. Alih-alih bunyi pintu depan larut malam, satu tombol kecil menyampaikan kabar baik. Seseorang tertidur sambil menunggu sinyal ini."},"ICON-0670":{"nm":"Gulungan Stiker Reflektor","de":"Potong satu kotak, tempelkan di tas, di sepeda, di payung, dan jalan malam pun jadi jauh lebih tidak berbahaya. Si pemalas yang terbangun cerah begitu bertemu lampu sorot. Tergulung rapi, ia menunggu kegelapan berikutnya tiba."},"ICON-0671":{"nm":"Kartu Taksi Darurat","de":"Selipkan di satu kompartemen dompet, dan halte yang kosong larut malam pun terasa jauh lebih tidak menakutkan. Satu nomor, sebaris alamat tertulis seperti janji—\"akan kuantar kau pulang.\" Siapa sangka kata darurat bisa terasa sehangat ini."},"ICON-0672":{"nm":"Pita Peta Jalan Malam","de":"Melilit di pergelangan tangan, kau berjalan menyusuri jalan yang lampunya jarang-jarang. Gang mana yang terang, mana yang gelap gulita, ia diam-diam membisikkan jalan pintas yang hanya diketahui malam. Pita yang mengikatkan diri di sisimu agar tak kehilangan arah bahkan dalam gelap."},"ICON-0673":{"nm":"Pouch Alarm Keamanan","de":"Ditarik saat darurat, ia berteriak begitu keras sampai seluruh gang terkejut. Selebihnya, ia bersembunyi tenang di dalam pouch, menyimpan suaranya untuk satu momen itu saja. Teriakan terbesar, tersimpan di dalam tas terkecil."},"ICON-0674":{"nm":"Gantungan Kunci Lampu Depan Pintu","de":"Selamat tinggal malam-malam meraba-raba mencari lubang kunci di ujung lorong yang gelap. Bergantung di depan pintu, ia menyambut tangan yang pulang dengan cahaya bundar. \"Kerja bagus, kau sudah sampai,\" gantungan kunci itu menyapa lebih dulu."},"ICON-0675":{"nm":"Memo Kembali ke Penginapan","de":"\"Bawa payungmu, matikan lampu sebelum keluar.\" Pesan singkat yang tertempel di kulkas menjaga kamar yang kosong. Sepucuk catatan kecil untuk orang yang akan kembali. Kehangatan yang tersimpan dalam selembar kertas diam-diam ikut mengantar sampai ke pintu depan."},"ICON-0676":{"nm":"Sisir Perapi Kabel","de":"Ia menyisir kabel-kabel yang kusut hingga rapi dan lurus, seperti menyisir rambut. Hutan kabel di belakang meja yang mirip belantara jadi tertata hanya dengan beberapa kali sisiran. Bukan hanya rambut yang bisa kusut, begitu sisir ini mengingatkan dengan lembut."},"ICON-0677":{"nm":"Sekat Tempat Pensil","de":"Pensil di sini, stabilo di sana, gunting di petak ujung. Ia membagi desa kecil di dalam satu wadah dan memberi setiap pena tempatnya sendiri. Begitu ada sekat, tangan pun tak lagi meraba-raba. Awal dari keteraturan kecil di atas meja."},"ICON-0678":{"nm":"Jepitan Memo Monitor","de":"Bergantung di sisi monitor, mengangkat \"hal yang harus dilakukan hari ini\" tepat setinggi mata. Papan pengingat kecil yang terlihat langsung dari depan, tanpa sempat terlupakan. Satu jepitan diam-diam menahan hati yang terus ingin menunda."},"ICON-0679":{"nm":"Baki Pemilah Laci","de":"Klip dan karet gelang, paku payung dan penghapus. Ia memberi ruang masing-masing bagi suku-suku kecil di dalam laci. Ketika tangan menjangkau petak-petak yang terbagi, waktu untuk mencari berkurang dan satu sudut hati terasa lebih ringan."},"ICON-0680":{"nm":"Tabung Kuas Debu","de":"Sebutir debu saja yang hinggap di atas lensa bisa jadi noda raksasa dalam foto. Karena itu kuas selalu menunggu rapi dan siap sedia di dalam tabungnya. Ujung jari yang rajin, menjaga kebersihan yang tak pernah diperhatikan siapa pun."},"ICON-0681":{"nm":"Alas Meja Sudut","de":"Sejengkal kelembutan yang terhampar di satu sudut meja. Pena tak lagi menggelinding jatuh, dan alih-alih kaca yang dingin, urat kain yang hangat menopang pergelangan tangan. Permukaan yang penuh perhatian, yang paling dulu menyediakan tempatnya, agar tulisan di malam yang panjang tetap tak goyah."},"ICON-0682":{"nm":"Holder Kabel Mouse","de":"Saat kabel kusut, entah bagaimana hati pun ikut kusut di suatu tempat. Sentuhan yang menangkap lebih dulu seutas kabel yang hendak berantakan dan membaringkannya rapi. Nyaris tak terlihat, diam-diam merapikan urat meja—sebuah keteraturan kecil yang rajin."},"ICON-0683":{"nm":"Dudukan Charging Dock","de":"Mendirikan perangkat yang tadinya terbaring miring, hingga layar akhirnya bertatap mata denganmu. Bahkan waktu menunggu selagi mengisi daya jadi terasa lebih rapi. Menopang berarti memberi bahkan sesuatu yang sedang beristirahat sebuah sikap yang pantas."},"ICON-0684":{"nm":"Label Tempat Sampah Kecil","de":"Bahkan tempat sampah terkecil pun mendapat namanya sendiri. Sebaris kalimat \"buang di sini\" memanggil keteraturan yang tenang ke atas meja yang berantakan. Label, pada akhirnya, adalah sapaan kecil yang memberi tahu sebuah benda: gunanya ada di sini."},"ICON-0685":{"nm":"Pin Papan Sekat","de":"Menekan selembar kertas kuat-kuat ke atas papan. Menitipkan sejenak perasaan yang tak ingin dilupakan pada dinding. Tekad hari ini yang tergantung di ujung pin bergoyang pelan tertiup angin, menahanmu setiap kali lewat."},"ICON-0686":{"nm":"Chip Bingkai Label","de":"Satu bingkai persegi mengubah tulisan biasa menjadi satu kalimat yang jelas dan tegas. Chip yang membungkus kesan rapi pada memo yang mudah tercecer. Bukan mengurung, melainkan mendekap kata-kata penting agar tak hilang."},"ICON-0687":{"nm":"Gagang Laci Transparan","de":"Pasang gagang pada laci yang tembus pandang, dan kau bisa melihat isinya tanpa sembarangan membukanya. Sejengkal jarak—terlihat, namun tak didekati. Bahkan transparansi butuh sopan santun, begitu bisik laci ini."},"ICON-0688":{"nm":"Jepitan Pengunci Tutup","de":"Dibiarkan terbuka, aroma dan warnanya diam-diam menguap pergi. Dengan satu jepitan kecil yang menggigit tutup dengan erat, warna hari kemarin tersisa utuh sampai esok. Mengunci, sesungguhnya, adalah pekerjaan menjaga sesuatu yang kau sayangi."},"ICON-0689":{"nm":"Holder Penyerap Lembap","de":"Penjaga kecil yang membenci kelembapan dan diam-diam setia berjaga di posnya. Menjaga udara tetap kering adalah syarat pertama penyimpanan yang lama, begitu holder yang rapi ini diam-diam mengingatkan. Begitulah kekeringan terjaga."},"ICON-0690":{"nm":"Tag Keranjang Penyimpanan","de":"Satu label nama kecil di tiap keranjang. Tentukan petak mana menyimpan apa, dan waktu yang biasa habis untuk mencari langsung berubah jadi waktu untuk beristirahat. Merapikan adalah sepucuk catatan hangat yang dititipkan lebih dulu untuk diri di masa depan."},"ICON-0691":{"nm":"Papan Sekat Mini","de":"Sekat kecil yang dengan cepat mendirikan satu ruang mungil yang nyaman di atas meja. Dengan satu papan ini, muncul sudut sunyi yang sedikit membelakangi dunia. Satu tempat hangat yang sepenuhnya milikmu sendiri, tempat fokus bisa singgah."},"ICON-0692":{"nm":"Dudukan Kantong Penyimpanan","de":"Dudukan yang lembut menopang punggung kantong-kantong yang tadinya terus jatuh roboh. Hanya dengan berdiri berjajar rapi, memilih yang ingin dipakai jadi jauh lebih mudah. Mendirikan sesuatu tegak lurus berarti memperhatikan lebih dulu sentuhan tangan berikutnya."},"ICON-0693":{"nm":"Chip Penanda Kosong","de":"Chip yang sengaja menandai kekosongan. Menyisakan tempat yang harus diisi pun adalah rencana yang sah adanya. Kekosongan bukanlah kemalasan, melainkan sejengkal ruang yang dengan sopan dibiarkan kosong untuk sesuatu yang akan segera datang."},"ICON-0694":{"nm":"Tutup Sikat Gigi","de":"Untuk sikat yang menyentuh mulut, kau jadi lebih rewel menjaganya. Satu topi kecil yang menahan bahkan sebutir debu sekalipun. Menjaga kebersihan yang tak terlihat adalah kepedulian kecil yang membuka setiap pagi dengan segar."},"ICON-0695":{"nm":"Jaring Alas Sabun","de":"Jaring yang lembut mengangkat sabun agar tak melunak terendam air. Prinsip bahwa mengalirkan sisa air membuatnya bertahan lebih lama—ia diam-diam membuktikannya setiap hari dari tempat paling rendah dan kecil di kamar mandi."},"ICON-0696":{"nm":"Jepitan Pompa Sampo","de":"Ia dengan lembut menahan kepala pompa, hingga satu tekanan hanya mengeluarkan jumlah yang pas. Kebiasaan tangan yang berhemat adalah dasar rumah tangga yang bertahan lama. Satu jepitan kecil dengan hangat menjaga pemborosan tetap terkendali."},"ICON-0697":{"nm":"Tutup Gantungan Pisau Cukur","de":"Benda yang tajam mendapat rumah kecilnya sendiri. Selipkan pisau cukur ke tutupnya dan gantungkan, maka air dan bahaya sama-sama mengalir turun. Cara berhati-hati menangani ketajaman, pada akhirnya, adalah cara menyayangi diri sendiri juga."},"ICON-0698":{"nm":"Cincin Handuk Mandi","de":"Handuk panjang membentuk lingkaran dan menjangkau punggung yang tak terjamah tangan. Mengikuti seutas urat tempat busa meluncur, kehangatan ramah yang menggosok punggung sendiri menyebar hangat memenuhi seluruh kamar mandi."},"ICON-0699":{"nm":"Saringan Lubang Pembuangan","de":"Satu jaring kecil yang mengalirkan air dan menahan sisa kotoran. Di tempat yang tak terlihat, ia diam-diam mencegah tersumbatnya saluran. Yang bekerja di posisi paling rendah menjaga aliran rumah tetap lancar, begitu saluran pembuangan mengingatkan tanpa sepatah kata pun."},"ICON-0700":{"nm":"Papan Kait Isap","de":"Ia menciptakan tempat baru di dinding tanpa memaku sebatang pun paku. Tekan kuat-kuat lalu lepaskan, dan bahkan bekasnya pun tak tersisa. Seni untuk singgah sebentar tanpa meninggalkan jejak—kait isap ini memahami betul kesopanan ringan itu."},"ICON-0701":{"nm":"Label Sandal Kamar Mandi","de":"Sepasang sandal tertata rapi di depan ambang pintu. Kepedulian rumah tempat orang melepas alas kaki terus terjaga hingga ke depan pintu kamar mandi. Sambutan kecil yang menghangatkan ujung kaki yang dingin ini, ditandai dengan tenang oleh sebuah label nama."},"ICON-0702":{"nm":"Gelas Kumur Mini","de":"Gelas kecil dan bundar yang menampung seteguk air untuk menyikat gigi. Dalam sesaat singkat berkumur, ia diam-diam menerima awal dan akhir sebuah hari. Tidak mewah, namun selalu ada di sisi setiap hari—kesederhanaan adalah rumah tangga yang paling bertahan lama."},"ICON-0703":{"nm":"Sarung Kemoceng","de":"Sarung yang diselipkan pada bulu kemoceng yang mengumpulkan debu seolah mengelusnya lembut. Seperti burung yang melipat sayapnya dengan anggun saat tak terbang, alat yang tahu tempatnya beristirahat akan bertahan lama di sisi kita."},"ICON-0704":{"nm":"Isi Ulang Rol Perekat Debu","de":"Lepas satu lapis, dan di baliknya muncul permukaan baru yang bersih dan lembut. Lembaran-lembaran lengket di dalamnya mengumpulkan bulu dan rambut halus. Dalam gulungan isi ulang yang terisi kembali setiap kali habis, tersimpan kebajikan pengulangan yang rajin."},"ICON-0705":{"nm":"Jepitan Kain Pel","de":"Jepitan yang menggigit kain pel dengan mantap, menggantikan tangan. Ia menjaga jarak sejengkal antara lantai yang dingin dan jari-jari. Satu gagang yang menerima pekerjaan kotor itu membuat bersih-bersih yang melelahkan terasa jauh lebih ringan."},"ICON-0706":{"nm":"Tutup Sikat Celah","de":"Sikat tipis yang mengincar celah sempit untuk disisir, dengan topi kecil yang menjaga ujungnya yang lembut. Sebuah hati yang memperhatikan bahkan sudut yang tak terjangkau tangan. Orang yang membersihkan tempat tak terlihat itulah yang memperluas pelukan rumah selebar sejengkal."},"ICON-0707":{"nm":"Cincin Label Botol Semprot","de":"Label kecil yang menempel lembut di bahu botol semprot. Entah isinya air bening atau deterjen, ia memberi tahu dengan jelas hanya dalam satu baris. Label yang menghapus kebingungan sejak awal ini adalah kebiasaan lama seorang pengurus rumah yang cekatan."},"ICON-0708":{"nm":"Pita Isi Ulang Tisu Gulung","de":"Pita yang menyelipkan gulungan baru ke tempat yang habis dan mengikatnya erat. Sentuhan paling sederhana yang menyambung kembali yang terputus. Hati seseorang yang mengisi ulang sebelum habis, melingkar bundar pada kaitan kecil ini."},"ICON-0709":{"nm":"Gantungan Sarung Tangan Bersih-Bersih","de":"Gantungan tempat menjemur sarung tangan basah yang baru saja selesai bekerja dengan air. Ia memberi tangan yang telah bersusah payah tempat beristirahat sejenak. Selama kelembapannya perlahan mengering, ada waktu istirahat singkat untuk menarik napas sebelum pekerjaan berikutnya."},"ICON-0710":{"nm":"Pin Gantungan Sapu","de":"Gantung sapu terbalik dan bulunya akan tetap lurus, tak melengkung. Sebuah sikap tegak yang menanti halaman berikutnya. Tempat kecil namun kokoh ini membantu sapu menjaga bentuknya bahkan setelah tugasnya usai."},"ICON-0711":{"nm":"Klip Kantong Sampah","de":"Menggigit mulut kantong dengan mantap, menyegelnya rapat tanpa satu pun yang bocor. Satu sentuhan menutup ujungnya dengan pas membuat beres-beres jauh lebih rapi. Penyelesaian, pada akhirnya, dimulai dari menutup dengan baik."},"ICON-0712":{"nm":"Wadah Jepitan Jemuran","de":"Wadah tempat jepitan jemuran, yang mudah hilang bila berserakan, hidup bersama. Ia memberi benda-benda kecil itu rumah bersama untuk tinggal. Kumpulkan para prajurit kecil di ujung jari itu dalam satu tempat, dan kau bisa menemukannya sekilas saat dibutuhkan."},"ICON-0713":{"nm":"Cincin Pemisah Kaus Kaki","de":"Kaus kaki yang kehilangan pasangannya selalu menghilang entah ke mana. Ikat sepasang dengan cincin sebelum dicuci, dan bahkan setelah kering lembut, keduanya tak akan berpisah. Memilah adalah janji kecil yang dibuat lebih dulu untuk mencegah kehilangan."},"ICON-0714":{"nm":"Kantong Bola Cuci","de":"Berguling-guling di dalam mesin cuci, ia menepuk-nepuk membangunkan kotoran yang meresap di pakaian. Sebuah irama yang mengelus cucian dengan tubuh bundarnya. Di tengah derasnya air, insting lama cucian—menepuk—tergulung dan dibawa berputar di dalam kantong."},"ICON-0715":{"nm":"Tutup Takar Sabun Wol","de":"Untuk pakaian yang halus, secukupnya yang halus pula. Tutup takar yang mengukur deterjen wol tepat satu tutup penuh. Dalam satu goresan takaran kecil tersimpan sentuhan hati-hati dalam merawat kain wol. Mengurangi yang berlebihan pun adalah bentuk ketulusan."},"ICON-0716":{"nm":"Tambalan Pelindung Kain","de":"Tambalan kecil yang lembut ditempelkan pada bagian yang usang. Hati di ujung jari yang merawat bagian yang lusuh, bukan membuangnya begitu saja. Setiap bekas tambalan menyimpan dengan indah pola tahun-tahun yang dilalui bersama pakaian itu."},"ICON-0717":{"nm":"Pin Penjepit Rak Jemuran","de":"Pin yang diam-diam menahan rak jemuran agar cucian tak terbang tertiup angin. Bahkan di hari cucian bergoyang di bawah sinar matahari, ia membantu menjaga tempatnya di tengah goyangan. Peran sebuah pemberat kecil namun bisa diandalkan."},"ICON-0718":{"nm":"Label Kantong Cuci Pakaian Dalam","de":"Pakaian dalam yang halus dicuci terpisah di dalam jaring. Jaring yang membungkus benda-benda lembut itu erat dari derasnya air. Satu kantong kecil berlabel ini mengingatkan bahwa menjaga hati-hati yang rapuh juga bagian dari mengurus rumah."},"ICON-0719":{"nm":"Gantungan Sendok Deterjen","de":"Menggantung sendok deterjen bubuk rapi di dinding. Tanpa repot menjatuhkannya ke dalam wadah dan membasahi tangan. Kebiasaan rapi menyimpan alat yang sama di tempat yang sama, tersimpan mantap dalam gantungan kecil ini."},"ICON-0720":{"nm":"Penahan Tali Jemuran","de":"Menggigit erat ujung tali jemuran, sehingga meski dimuati cucian yang berat, ia tak akan mengendur perlahan. Simpul terakhir yang bertahan sampai akhir, menjaga tali yang tegang agar tak melorot. Penyelesaian yang mantap bergantung padanya."},"ICON-0721":{"nm":"Label Sarung Bantal","de":"Tempat pipi paling dulu menyentuh setiap malam, dengan label sebesar kuku yang dijahit di bagian dalamnya. Siapa yang sungguh membaca tulisan kecil tentang suhu cucian itu? Namun tetap saja, ia panduan terdekat yang menjaga di sisi wajah yang tertidur."},"ICON-0722":{"nm":"Jepitan Selimut","de":"Pada malam dengan jendela terbuka, selimut tak akan lari meski angin masuk. Sebab jepitan yang menutup mulutnya rapat sedang menggigit ujungnya. Tangan tanpa kata yang memegangi tepi selimut, menggantikan orang yang tertidur."},"ICON-0723":{"nm":"Sekat Peredup Lampu Tidur","de":"\"Kalau cahaya mengenai mata, kantuk pun menjauh.\" Dengan selembar sekat yang diam-diam didirikan seseorang, cahaya mundur ke belakang dan hanya membasahi samar ujung kaki ranjang. Sekat kecil yang meminjamkan sejengkal kegelapan."},"ICON-0724":{"nm":"Kantong Celah Ranjang","de":"Bayangkan celah antara kasur dan dinding, yang dulu tak terjangkau tangan. Remote yang terguling jatuh, kacamata juga, kini berkumpul di sini. Kantong yang diam-diam dibentangkan ranjang untuk menangkap benda-benda yang nyaris hilang."},"ICON-0725":{"nm":"Baki Penyimpan Kacamata","de":"Lepaskan lensanya, dan dunia pun mengabur lembut, sementara piring dangkal menampung ketidakberdayaan sesaat itu. Di pagi hari, meski jari tak meraba-raba, kacamata selalu menunggu di tempat yang sama."},"ICON-0726":{"nm":"Alas Jam Alarm","de":"Pukul enam pagi, di atas pijakan kokoh tempat suara paling dibenci berbunyi. Tanpa goyah, ia menopang jam dan pada akhirnya membuka hari seseorang. Ia menanggung, tanpa sepatah kata, janji tegas untuk terbangun."},"ICON-0727":{"nm":"Penyangga Kabel Samping Ranjang","de":"Kabel pengisi daya yang dulu meluncur turun ke bawah kepala tidur, kini tak lagi jatuh ke lantai. Sebab penyangga kecil ini diam-diam menggenggam ujung kabel. Dalam jangkauan tangan—sentuhan yang merapikan alur malam."},"ICON-0728":{"nm":"Pita Penyimpan Piyama","de":"Pita yang melingkari piyama yang telah dilipat rapi dan mengikatnya sekali putaran. Bahkan kelembutan yang mudah kusut butuh kerapian. Untuk diriku esok malam, diriku hari ini menggulungnya rapi—sebuah persiapan kecil."},"ICON-0729":{"nm":"Penyangga Kartu Wangi","de":"Dirikan selembar kartu beraroma dengan sedikit condong, dan seperti membalik halaman, kau membalik musim lewat ujung hidung. Dari lavender ke citrus—ia menjadi buku harian hari itu yang tertulis lewat aroma."},"ICON-0730":{"nm":"Alas Piring Kunci","de":"Sudut di dekat pintu masuk, tempat kunci-kunci biasa jatuh berdenting. Piring berlapis alas lembut ini menelan suara tajam itu. Sebuah alas kecil diam-diam menerima gerakan pertama orang yang baru pulang."},"ICON-0731":{"nm":"Tutup Penampung Tetesan Payung","de":"Air hujan menetes perlahan dari ujung payung yang baru dibawa masuk. Satu tutup menangkap tetesan itu dengan rapi, sehingga genangan kecil yang biasa merembes diam-diam di lantai kayu, telah lebih dulu diantisipasi dan dicegah seseorang."},"ICON-0732":{"nm":"Chip Gantungan Masker","de":"Chip sebesar kuku yang menempel di dinding samping pintu masuk. Seperti ritual terakhir sebelum keluar rumah, masker digantung di sini. Sebuah alat pengingat kecil yang menjaga ketinggian mata di depan pintu, agar tak lupa apa yang harus dibawa."},"ICON-0733":{"nm":"Sarung Pisau Pemotong Paket","de":"Penutup pelindung yang diselipkan pada mata pisau pemotong kotak paket. Ia diam-diam menutup bahaya tersayat yang tersembunyi di balik kegembiraan membuka paket. Perhatian yang tak terlihat, yang membuka akhir sebuah penantian dengan aman."},"ICON-0734":{"nm":"Alas Sikat Sepatu","de":"Tempat sikat sepatu diletakkan dalam keadaan basah setelah selesai menyikat. Meski menyerap kelembapan, alasnya tetap kering dengan lembut. Bahkan alat pencipta kebersihan butuh tempat beristirahat, begitulah alas kecil ini mengingatkan."},"ICON-0735":{"nm":"Papan Pesan Tamu","de":"\"Mampir sebentar lalu pergi.\" Sebaris tulisan singkat yang tertinggal di papan pesan pintu masuk. Sebuah alun-alun kecil tempat orang-orang yang berselisih waktu saling berbagi lintas masa. Di satu petak kertas, kabar, permintaan, dan sebuah hati bertumpuk saling tindih."},"ICON-0736":{"nm":"Gulungan Penahan Angin Celah Pintu","de":"Angin dari luar yang dulu menyusup lewat celah sebesar jari di bawah pintu. Penahan yang tergulung diam-diam menutup jalan itu. Ia menahan satu lapis lagi kehangatan dalam ruangan yang dulu bocor tanpa terlihat."},"ICON-0737":{"nm":"Aksesori Ganjal Pintu","de":"Aksesori kecil yang mengganjal alas pintu yang terbuka lebar agar tak menutup kembali. Ia bertahan dengan bobotnya untuk angin dan langkah kaki yang lalu-lalang. Sebuah kekeraskepalaan yang ramah, yang menjaga pintu tetap terbuka."},"ICON-0738":{"nm":"Penutup Saklar Lampu Pintu Masuk","de":"Saklar pintu masuk yang dulu diraba-raba di larut malam. Penutup yang berpendar dalam gelap dengan lembut menandai tempatnya. Agar tangan tak tersesat, sebuah penunjuk kecil yang bersinar lebih dulu, sebelum lampu menyala."},"ICON-0739":{"nm":"Alas Penahan Gelas","de":"Saat gelas yang diletakkan di meja mulai meluncur perlahan, selembar alas dengan tenang menahan kakinya. Sebuah tatakan yang menjaga tempatnya dengan tenang, tak menyisakan satu pun bekas meski butiran air mengembun."},"ICON-0740":{"nm":"Klip Pewangi Mobil","de":"Klip pewangi kecil yang tergantung di dalam mobil. Menunggangi angin dari ventilasi, aroma lembutnya perlahan memenuhi ruang sempit itu. Sebuah hiburan hangat di kursi pengemudi, yang menghangatkan bahkan kebosanan menunggu lampu merah dengan aroma."},"ICON-0741":{"nm":"Sarung Sabuk Pengaman","de":"Sarung lembut yang diselipkan pada sabuk yang melintasi bahu. Rasa kasar yang menyentuh tengkuk pun perlahan menghilang. Bahkan tali untuk keselamatan bisa ditambahkan kelembutan, begitulah kain sejengkal ini berkata."},"ICON-0742":{"nm":"Papan Penutup Nomor Parkir","de":"Papan yang diam-diam menutup plat nomor penanda petak parkir di basement, sebelum kau mengambil foto. Setiap orang punya informasi yang tak ingin ditinggalkan jejaknya. Satu lapis yang dihapus dengan hati-hati dari satu adegan kehidupan sehari-hari."},"ICON-0743":{"nm":"Tutup Bel Sepeda","de":"Kring-kring. Sapaan cerah yang diberikan sepeda di tikungan gang. Tutup yang menyelimuti bel menjaga suara itu tetap terdengar bahkan di tengah hujan. Pada satu dentingan kecil, orang-orang tersenyum dan melangkah menepi."},"ICON-0744":{"nm":"Cincin Genggaman Setang","de":"Cincin yang membungkus lembut sentuhan setang di telapak tangan. Meski digenggam lama saat mengayuh, tangan tak kesemutan. Semakin jauh perjalanannya, semakin kenyamanan tempat menggenggam itu mempersingkat jaraknya."},"ICON-0745":{"nm":"Stiker Label Helm","de":"Stiker nama yang ditempel di bagian dalam helm. Di antara helm-helm pengaman yang tampak sama, ia berteriak pelan, \"ini punyaku.\" Tanda paling pribadi, terukir di atas kekokohan yang melindungi kepala."},"ICON-0746":{"nm":"Tutup Reflektor Roda","de":"Tutup yang baru memulai tugasnya setelah matahari terbenam. Ia menangkap cahaya yang lewat dan memantulkan roda dengan jelas. Dalam gelap, ia mengirim sinyal kecil lewat cahaya, \"ada orang di sini.\""},"ICON-0747":{"nm":"Kantong Pelindung Kunci Mobil","de":"Kunci mobil yang dulu tergores berbenturan dengan kunci lain di dalam saku. Kantong lembut ini membungkus permukaannya dengan pas. Harapan agar benda yang digenggam setiap hari tetap bebas goresan dan bertahan lama, tersimpan di dalamnya."},"ICON-0748":{"nm":"Pin Rak Isap Tempel","de":"Pin rak isap tempel yang menempel di dinding tanpa satu paku pun tertancap. Bahkan dinding yang tak ingin ditandai pun mendapat satu petak penyimpanan. Keahlian menggantung isi rumah di ruang yang hanya dipinjam sementara, tanpa meninggalkan jejak."},"ICON-0749":{"nm":"Papan Kait Tanpa Bor","de":"Bisa menggantung sesuatu tanpa melubangi dinding, siapa sangka. Papan kait tanpa bor diam-diam mengambil alih beban ringan. Keinginan untuk tak merusak ruang yang dipinjam, tersimpan indah dalam satu kait kecil."},"ICON-0750":{"nm":"Batang Organizer Magnet","de":"Suara logam yang berbunyi tok, menempel pas di tempatnya. Sapukan magnet untuk mengumpulkan alat-alat kecil yang berserakan ke mana-mana, dan meja kerja yang berantakan pun tertata rapi dalam satu barisan, disusul kepuasan kecil yang menyertainya."},"ICON-0751":{"nm":"Batang Penyimpan Celah","de":"Bayangkan celah sempit yang terbengkalai antara kulkas dan dinding. Batang tipis ini mengisi celah itu dengan kegunaan. Sebuah gagasan hemat yang menarik keluar penyimpanan dari ruang yang dulu dianggap sia-sia."},"ICON-0752":{"nm":"Lembar Bantalan Perekat","de":"Lembar bantalan perekat yang, sekali ditempel, mampu menopang benda berat dengan mudah. Lepaskan, dan anehnya, tak ada bekas sama sekali. Sebuah kekuatan yang tenang dan gigih, menahan beban dari tempat yang tak terlihat."},"ICON-0753":{"nm":"Tutup Kait Gantung Pintu","de":"Tutup kait yang cukup disangkutkan ringan di atas daun pintu. Tas dan handuk tergantung setinggi jangkauan tangan. Gantungan yang lahir tanpa satu paku pun ini menambah satu petak kelegaan pada ruangan yang sempit."},"ICON-0754":{"nm":"Klip Kabel Dinding","de":"Klip yang mengumpulkan kabel yang menjuntai di dinding menjadi satu garis rapi. Kekusutan benang di belakang meja pun terurai menjadi alur yang bersih. Kerapian yang tak terlihat ini membuat udara ruangan terasa jauh lebih ringan."},"ICON-0755":{"nm":"Alas Kaki Lampu Meja","de":"Alas yang lembut diletakkan di bawah kaki lampu berdiri. Ia tak meninggalkan goresan di meja, dan meredam getaran sekecil apa pun. Bahkan dalam mendirikan cahaya, lantai yang tak bergoyang harus lebih dulu ada."},"ICON-0756":{"nm":"Plat Perekat Anti-Selip","de":"Keset yang dulu diam-diam bergeser dari bawah kaki, akhirnya berhenti tepat di tempatnya, karena plat perekat menggigit erat lantai. Sebuah jaring pengaman tak terlihat yang diam-diam menyingkirkan momen nyaris terpeleset sebelum terjadi."},"ICON-0757":{"nm":"Tutup Obeng Presisi","de":"\"Sekrup kecil ini saja tak mau kendur.\" Tutup yang dipasang di ujung obeng presisi menjaga mata obengnya. Alat paling halus di ujung jari, yang membuka dunia sebesar telapak tangan di dalam sebuah mesin."},"ICON-0758":{"nm":"Cincin Kunci L Set","de":"Cincin yang merangkai beberapa kunci L menjadi satu gantungan. Logam yang berbaris menurut ukuran terbentang seperti kipas dengan satu gerakan. Irama rapi sebuah tangan yang memilih satu batang yang dibutuhkan dalam sekali gerak."},"ICON-0759":{"nm":"Gantungan Meteran Mini","de":"Gantungan yang terpasang pada meteran mini yang muat pas di telapak tangan. Tergantung di gantungan kunci, ia ikut ke mana saja. Sahabat kecil yang mengukur dan menjawab panjang apa pun yang tiba-tiba membuat penasaran, tepat di tempatnya."},"ICON-0760":{"nm":"Kotak Pemilah Sekrup","de":"Kotak pemilah tempat sekrup-sekrup yang berbeda-beda menemukan petaknya masing-masing. Bahkan komponen kecil yang dulu berguling campur aduk pun mendapat keteraturan. Tangan yang belajar merapikan lebih dulu, sebelum memperbaiki apa pun."},"ICON-0761":{"nm":"Tutup Nozel Lem","de":"Ditutup, aku tak akan mengeras; dibiarkan terbuka, aku mengering—aku hidup di antara keduanya. Setiap kali setetes jatuh, di suatu tempat sesuatu yang patah sedang tersambung kembali. Satu tutup kecil dengan tenang menjaga batas antara diam dan mengalir."},"ICON-0762":{"nm":"Gantungan Kunci Waterpas","de":"Kejujuran sebesar telapak tangan yang bergoyang di ujung segenggam kunci. Selalu gelembung kecil inilah yang pertama menyadari rak yang miring. Aku membawa dalam saku seorang sahabat yang diam-diam memberitahu bahwa dunia sedikit condong."},"ICON-0763":{"nm":"Tutup Pelindung Pinset","de":"Semakin runcing sesuatu, semakin ia butuh pakaian untuk menenangkannya. Bungkus ujungnya dengan lembut, dan baik tangan maupun komponen tak akan terluka. Sopan santun pertama dalam menangani yang tajam adalah menutup ujungnya dengan tenang—tutup kecil ini mengemban kelembutan itu."},"ICON-0764":{"nm":"Alas Potong Kecil","de":"Papan yang bekas lukanya sembuh sendiri meski mata pisau melintas ribuan kali. Pekerjaan berikutnya ditumpuk lagi di atas sayatan, dan sembuh lagi. Sebuah dasar yang diam-diam merelakan tubuhnya sendiri agar benda lain dapat dipotong rapi."},"ICON-0765":{"nm":"Kantong Suku Cadang Perbaikan","de":"Kantong yang mengatupkan mulutnya agar satu sekrup, satu pegas tak hilang selamanya. Benda-benda kecil yang tersisa setelah perbaikan diam-diam menanti giliran berikutnya di sini. Yang selalu mencegah kehilangan adalah petak-petak kecil sederhana seperti ini."},"ICON-0766":{"nm":"Klip Kantong Camilan","de":"Menjaga kerenyahan kantong yang terbuka, pada akhirnya bergantung pada satu jepitan yang tegas. Sebuah janji kecil untuk tak memberi celah agar melempem. Kebiasaan tangan menggigit ujungnya dengan mantap menyelamatkan camilan esok hari."},"ICON-0767":{"nm":"Cangkir Bagi Jeli","de":"Untuk membagi satu kantong bersama banyak orang, harus dibagi dulu dengan adil. Hati yang menyendokkan bagian yang sama persis ke setiap cangkir kecil. Berbagi, aku percaya, dimulai dari jumlah yang benar-benar sama, agar tak ada yang merasa kecewa."},"ICON-0768":{"nm":"Sisa Foil Cokelat","de":"Perak yang membungkus manis itu mudah kusut di ujung jari. Diratakan, ia berkilau sesaat; dilipat, ia menjadi kenangan. Sepotong cahaya yang justru paling cantik setelah semua habis dimakan—dilihat sekali lagi sebelum dibuang."},"ICON-0769":{"nm":"Pita Label Camilan","de":"Apa isinya, sampai kapan masih baik—aku bicara mewakili kantong yang bisu itu. Begitu satu pita menempel, camilan pun mendapat nama dan janji. Memilah, sesungguhnya, adalah cara mengingat yang paling lembut."},"ICON-0770":{"nm":"Kotak Pemilah Permen","de":"Yang asam dan yang manis tak diletakkan di petak yang sama. Pekerjaan memisahkan lebih dulu agar tangan tak ragu-ragu. Ketika kotak-kotak kecil berbaris rapi, kesenangan memilih pun diam-diam berlipat ganda."},"ICON-0771":{"nm":"Kertas Peredam Kukis","de":"Kertas tipis yang diselipkan di sela-sela kukis agar tak memar sepanjang perjalanan. Semakin rapuh sesuatu, semakin ia butuh teman yang lebih lembut. Kelembutan terkadang menjaga lebih baik daripada kekokohan."},"ICON-0772":{"nm":"Tali Kotak Donat","de":"Satu simpul silang bertanggung jawab atas keselamatan kue di dalam kotak. Ia menjadi pegangan, menjadi segel, menjadi tanda penantian yang berdebar. Saat tali ini terlepas, itulah momen ulang tahun seseorang."},"ICON-0773":{"nm":"Jepitan Kantong Roti","de":"Puntir sekali, lipat, dan selipkan aku, maka kelembutan roti tersegel hingga esok pagi. Sebuah kekeraskepalaan kecil yang menghalau udara. Menjaga sesuatu yang lembut agar bertahan lama selalu menjadi tugas sesuatu yang kokoh."},"ICON-0774":{"nm":"Label Tukar Camilan","de":"Bagianmu untukku, bagianku untukmu. Ingat getaran hari itu, menuliskan nama di label kecil dan bertukar camilan? Kertas yang menempel pada hati yang saling berbagi selalu bertuliskan rapi nama seorang sahabat."},"ICON-0775":{"nm":"Tutup Sedotan","de":"Saat berhenti sejenak di antara seruputan, kau menutupku. Agar tak tumpah, agar tak dingin, agar ia menunggu diam di sana. Tugas sebuah tutup kecil yang menjaga lubangnya untuk saat bibir kembali menyentuhnya."},"ICON-0776":{"nm":"Cincin Nama Tumbler","de":"Cincin kecil yang berkata 'ini punyaku' di antara deretan tumbler yang berjejer. Satu warna saja, dan kebingungan pun perlahan mencair. Tanda kepemilikan cukup dijelaskan dengan satu cincin ini."},"ICON-0777":{"nm":"Sarung Pemegang Gelas","de":"Selapis karton bergelombang yang menyelinap di antara gelas panas dan telapak tangan. Sebuah perhatian yang diselipkan agar tak terbakar, tak tergelincir. Menjaga jarak di antara keduanya itulah yang menyempurnakan segelas minuman tanpa masalah."},"ICON-0778":{"nm":"Label Cetakan Es","de":"Ada orang yang menuliskan tanggal pembuatan pada setiap es batu. Dengan keyakinan bahwa bahkan dingin pun punya urutan. Selembar label kecil membuat waktu di dalam freezer mengalir jujur, giliran demi giliran."},"ICON-0779":{"nm":"Jepitan Kantong Teh","de":"Mengawasi waktu seduhan, lalu mengangkatnya tepat pada saat yang pas. Kepekaan tangan yang tahu berhenti sebelum terlalu pekat. Kedalaman rasa teh ditentukan bukan oleh lama merendam, melainkan oleh ketepatan waktu mengangkatnya."},"ICON-0780":{"nm":"Penyangga Filter Seduh","de":"Ia menopang filter dan berdiri diam agar air panas mengalir turun perlahan. Ia tahu betul bahwa terburu-buru membuat aromanya menipis. Bahkan menopang sebuah penantian butuh sikap yang tak goyah."},"ICON-0781":{"nm":"Tali Gantung Botol","de":"Tali yang menggantungkan botol air di pergelangan tangan, di bahu, untuk berjalan bersama. Sebuah cara menemani yang membuatnya selalu ada di sisi, tanpa harus sengaja membawanya. Kadang, mengikatnya sedikit adalah cara paling lembut agar tak lupa."},"ICON-0782":{"nm":"Penutup Kaleng Minuman","de":"Menutup mulut kaleng yang belum habis diminum agar debu tak masuk dan gasnya tak hilang. Sebuah topi kecil yang bertanggung jawab menjaga kesegaran hingga tegukan berikutnya. Bahkan tindakan menutup dengan tenang sesuatu yang sempat terbuka pun menyimpan ketulusan."},"ICON-0783":{"nm":"Penyangga Kartu Kupon Minuman","de":"Gelas kesepuluh yang gratis—ia memeluk kartu stempel itu agar janji tersebut tak hilang. Agar hari-hari yang terisi satu petak demi satu petak tak sampai kusut. Di dalam penyangga ini tersimpan langkah-langkah rajin seorang pelanggan setia."},"ICON-0784":{"nm":"Tali Pengikat Kotak Bekal","de":"Tali yang memeluk kotak bekal satu putaran erat agar tutupnya tak terbuka. Sebuah kelegaan kecil bahwa kuahnya tak akan bocor di dalam tas. Yang bertanggung jawab atas keselamatan bekal hingga jam makan siang adalah satu putaran yang mantap ini."},"ICON-0785":{"nm":"Set Cangkir Lauk","de":"Beri setiap lauk tempatnya sendiri, dan rasa pun tak akan bercampur. Kimchi tetap kimchi, sayuran tetap sayuran, masing-masing jelas. Pembagian petak yang dibuat cangkir-cangkir kecil ini adalah tatanan kotak bekal, sekaligus kelembutan di atas cita rasa masakan."},"ICON-0786":{"nm":"Kotak Sumpit","de":"Rumah kecil yang membawa bersih sumpit yang menemani tiga kali makan sehari. Teman diam yang menjaga kerapian bahkan di dalam tas sekolah. Kepedulian membawanya serta itulah, pada akhirnya, yang menciptakan hidangan yang rapi."},"ICON-0787":{"nm":"Label Botol Saus","de":"Kecap atau cuka? Ia memberi kejelasan pada botol yang dulu membingungkan. Begitu satu garis menempel, keraguan di ujung jari pun lenyap. Kecepatan dapur yang sibuk diciptakan dengan tenang oleh penanda-penanda kecil seperti ini."},"ICON-0788":{"nm":"Lembar Penggulung Gimbap","de":"Selembar rumput laut tipis yang menggulung nasi dan isian menjadi satu tubuh. Harus dibungkus erat agar tak berantakan saat dipotong. Getaran pagi hari piknik keluar tergulung bundar dari lapisan tunggal ini."},"ICON-0789":{"nm":"Wadah Tusuk Sate Mini","de":"Berdirikan tusuk sate dan tusuk gigi di satu tempat, dan tangan tak akan bingung saat dibutuhkan. Memberi rumah tetap bahkan pada benda-benda yang runcing. Merapikan, pada akhirnya, adalah kebaikan kecil untuk sentuhan tangan berikutnya."},"ICON-0790":{"nm":"Sarung Kantong Pendingin","de":"Membungkus satu lapis lagi kantong pendingin agar dingin bertahan sedikit lebih lama. Sekaligus mencegah tas basah karena embun. Yang menjaga kesejukan hingga akhir selalu lapisan tebal ini."},"ICON-0791":{"nm":"Sekat Kotak Bekal","de":"Dinding kecil yang didirikan agar nasi dan lauk tak melanggar batas satu sama lain. Kedamaian satu petak tempat kuah tak akan meluber. Kotak bekal yang terbagi petak demi petak menyimpan utuh hati yang teliti dari pembuatnya."},"ICON-0792":{"nm":"Kartu Urutan Makan","de":"Sup dulu atau nasi dulu? Kartu yang lembut memberi tahu urutan santapan hari ini. Sebuah panduan ramah yang mengatakan makan berurutan terasa lebih lezat. Ia diam-diam memberitahu bahwa bahkan sebuah santapan punya alur, seperti sebuah cerita."},"ICON-0793":{"nm":"Stiker Gelas Takar","de":"Stiker kecil di samping garis ukur menunjuk tepat, \"sampai sini.\" Sebuah penanda yang membuat takaran yang selalu membingungkan itu pas dalam sekali coba. Ketepatan berasal dari satu garis panduan kecil seperti ini."},"ICON-0794":{"nm":"Pegangan Silikon Tutup Panci","de":"Pegangan kecil yang membuat tutup panas dapat diangkat tanpa membakar jari. Ia diam-diam meminjamkan keberanian untuk membuka panci yang mengepul. Keamanan selalu datang dari menyiapkan tempat berpegang lebih dulu."},"ICON-0795":{"nm":"Gantungan Klip Mini","de":"Klip kecil yang memberi tempat pada lap atau kantong yang dulu tak punya tempat menggantung. Ia mengubah satu petak dinding yang berantakan menjadi pemandangan yang rapi. Satu kebiasaan menggantung membuat dapur terasa jauh lebih ringan."},"ICON-0796":{"nm":"Tutup Kuas Minyak","de":"Menutup ujung kuas pengoles minyak membuat debu dan pengerasan pun terhindar. Sebuah topi yang menjaga kelembutannya hingga masakan berikutnya. Perhatian kecil untuk merawat alat, pada akhirnya, menjaga rasa bertahan lama."},"ICON-0797":{"nm":"Wadah Sendok Garam","de":"Sendok kecil yang tinggal tertanam di dalam wadah garam. Ia menyendok ketepatan satu jumput dengan tulus setiap kali. Cita rasa memberi bumbu adalah sebesar hati yang diingat oleh sendok kecil ini."},"ICON-0798":{"nm":"Papan Magnet Pengatur Waktu","de":"Menempel di pintu kulkas, ia menghitung 3 menit untuk mi instan, mengukur 30 detik untuk olahraga. Dengan satu lembar magnet, waktu yang akan berlalu tertahan di depan mata. Sebuah lingkaran rajin yang sejenak menahan yang berlalu di dinding."},"ICON-0799":{"nm":"Sarung Pegangan Panci","de":"Selapis yang membungkus agar pegangan yang panas tak dipegang dengan tangan telanjang. Sebuah perisai kecil yang menghalangi antara panas dan telapak tangan. Memindahkan panci dengan selamat selalu dimulai dari bungkusan lembut ini."},"ICON-0800":{"nm":"Karet Alas Talenan","de":"Ketika aku dibentangkan di bawahnya, talenan tak lagi tergelincir. Sepotong karet yang menahan dari bawah setiap kali sayatan pisau bergoyang. Kestabilan adalah pekerjaan menggigit kokoh di tempat yang tak terlihat."},"ICON-0801":{"nm":"Klip Sarung Tangan Dapur","de":"Tempat sejenak berhenti bagi tangan yang tak henti bergerak di depan api. Jepitkan satu sarung tangan yang berkibar ke dinding, dan dimulailah jeda singkat hingga santap berikutnya. Merapikan, pada akhirnya, adalah nama lain dari kelembutan hati."},"ICON-0802":{"nm":"Wadah Batang Pengaduk Kopi","de":"Di samping meja kasir, sebuah tempat di mana batang-batang tipis bersandar bahu-membahu, tersusun rapi. Bersiap menggambar lingkaran kecil di cangkir pagi seseorang, berbaris rapi bagai paduan suara yang siap membuka suara bersama."},"ICON-0803":{"nm":"Ikat Set Tatakan Gelas","de":"Sehelai pita yang lembut menangkap bunyi denting kecil saat gelas menyentuh meja. Ikat tatakan-tatakan bundar itu menjadi satu, dan sambutan bagi tamu pun telah siap. Keramahan selalu bermula, seperti ini, dari tempat sekecil apa pun."},"ICON-0804":{"nm":"Label Kecil Sirup","de":"Selarik nama yang tertempel di botol. Manis, kental—satu kata singkat itu saja mampu merapikan pagi yang sibuk menjadi sedikit lebih tenang. Label adalah kertas tempat menuliskan janji kecil lebih dahulu."},"ICON-0805":{"nm":"Wadah Tusuk Dessert","de":"Wadah tempat tinggal bersama batang-batang runcing yang siap menusuk sepotong buah. Sebelum ditancapkan bagai bendera di atas piring dessert, di sinilah mereka menunggu giliran dengan tenang. Bahkan rasa manis pun punya urutannya sendiri."},"ICON-0806":{"nm":"Sarung Pengaduk Minuman","de":"Baju kertas yang membungkus segenggam batang pengaduk dengan erat. Ia menyerap embun yang menetes dari minuman dingin, menjaga ujung jari yang menggenggam gelas tetap kering. Perhatian yang tak terlihat selalu datang dari tepian."},"ICON-0807":{"nm":"Tag Pemegang Gelas Bawa Pulang","de":"Saat kedua tangan tak lagi cukup, sebuah pegangan kecil membawakan gelas untukmu. Ia menahan kehangatan yang terbungkus itu agar tak setetes pun tumpah, mengantarkan kehangatan itu hingga ke ujung gang seseorang."},"ICON-0808":{"nm":"Sarung Bel Getar Kafe","de":"Sehelai baju yang diam-diam membungkus masa penantian hingga getarannya berbunyi. Menjaga nomor antrean yang berpendar di sudut kafe, ia turut menyimpan gemuruh debar bahwa nomormu akan segera dipanggil."},"ICON-0809":{"nm":"Cincin Kupon Stempel","de":"Selembar kertas yang, bila sepuluh kotaknya terisi penuh, mengganjar satu cangkir gratis. Setiap kali satu stempel bertambah, nama \"pelanggan setia\" pun ikut tumbuh sedikit demi sedikit. Kebahagiaan sesederhana ini terangkai di sebuah cincin kecil."},"ICON-0810":{"nm":"Kantong Sampel Biji Kopi","de":"Kantong yang menyimpan segenggam biji kopi dan menyapa lebih dulu dengan aromanya. Keasaman dan manis yang melintas di ujung hidung, kesan pertama itulah yang menentukan nasib secangkir kopi. Aroma selalu tiba lebih cepat dari penjelasan apa pun."},"ICON-0811":{"nm":"Magnet Label Kulkas","de":"Label magnet kecil yang menempel ringan di pintu kulkas. Catat apa yang masuk dan kapan, maka lauk yang nyaris terlupakan pun mendapatkan kembali gilirannya. Mengurus rumah tangga adalah pekerjaan menahan ingatan yang terus mengalir."},"ICON-0812":{"nm":"Chip Tanggal Simpan","de":"Sekeping penanda yang mengukir jelas hari sesuatu dikemas. Saksi kecil yang diam-diam berbisik, meski sudah beberapa hari, ini masih aman. Kesegaran terjaga oleh ujung jari yang mengingat tanggal."},"ICON-0813":{"nm":"Ikat Wadah Porsi","de":"Sebuah ikat yang melingkari pinggang wadah berisi bagian-bagian yang telah dipilah. Ia merangkul tutup yang bergoyang hingga rapat, menjaga tatanan kecil di dalam kulkas. Mengikat sesuatu ternyata mirip dengan merapikan hati."},"ICON-0814":{"nm":"Klip Penutup Warna-Warni","de":"Klip warna-warni yang menggigit rapat mulut kantong. Merah untuk pedas, kuning untuk manis—hanya dari warnanya saja tangan sudah tahu lebih dulu. Lampu lalu lintas dapur ini menuntun jalan tanpa sepatah kata pun."},"ICON-0815":{"nm":"Label Nama Kemasan Beku","de":"Label nama yang diletakkan lembut di atas sesuatu yang telah membeku. Ia menenangkan kantong berbalut embun beku agar tak lupa apa dirinya dulu. Sapaan kecil yang disampaikan kepada bahan makanan yang tengah tidur musim dingin."},"ICON-0816":{"nm":"Jaring Simpan Sayur","de":"Jaring longgar yang dengan murah hati merangkul sayuran berlumur tanah. Dapur nenek telah lama tahu bahwa memberi ruang untuk bernapas membuat mereka bertahan lebih lama. Sirkulasi udara adalah ruang lapang penuh kasih yang diberikan pada sayuran."},"ICON-0817":{"nm":"Tutup Pemilah Tutup Botol","de":"Tutup pemilah yang memasangkan tutup-tutup sesuai ukurannya, satu demi satu. Menemukan kembali pasangan yang hilang ternyata lebih menyentuh dari yang dikira. Padukan sepasang yang cocok, dan dapur pun ikut menjadi lebih rapi."},"ICON-0818":{"nm":"Label Baki Telur","de":"Tanda yang tertera rapi pada masing-masing dari sepuluh sarang kecil. Kebijaksanaan rumah tangga yang mengingatkan untuk memakai telur yang lebih dulu ada. Bahkan sebutir telur ceplok di pagi hari menyimpan hati yang menjaga urutan."},"ICON-0819":{"nm":"Stiker Makanan Sisa","de":"Tulis \"ini punyaku!\" lalu tempelkan, dan kulkas pun sejenak merasakan damai. Deklarasi perang kecil yang menggemaskan, menentukan pemilik camilan malam lebih dulu. Keluarga tetap berputar hari ini juga, berkat perjanjian sekecil ini."},"ICON-0820":{"nm":"Sandaran Sendok Garpu","de":"Sekeping penyangga yang lembut menopang sendok dan sumpit agar tak langsung menyentuh meja. Kerapian kecil ini diam-diam mengangkat martabat sebuah santapan. Sopan santun di meja makan tumbuh dengan tenang dari tempat sekecil ini."},"ICON-0821":{"nm":"Cincin Penahan Serbet","de":"Cincin yang diam-diam menjepit dan menahan serbet yang bisa saja tertiup angin. Ia mengumpulkan kertas putih yang menanti gilirannya untuk terbuka, mengukir tatanan kecil dengan rapi di atas meja."},"ICON-0822":{"nm":"Penjepit Sudut Alas Meja","de":"Sekeping penjepit yang lembut menekan dan menenangkan sudut alas meja yang terangkat. Meja mengajarkan setiap hari bahwa hanya ketika satu ujung tertahan, seluruhnya baru terhampar rata. Bahkan sudut pun punya bagian tanggung jawabnya sendiri."},"ICON-0823":{"nm":"Baki Bumbu Kecil","de":"Baki kecil yang menampung semangkuk kecap dan sejumput garam berdampingan. Pelukan luas meja makan yang memberi tempat bahkan bagi pelengkap sekecil apa pun. Masakan Korea semakin dalam maknanya dari hati yang memperhatikan hal-hal kecil di sampingnya."},"ICON-0824":{"nm":"Chip Nomor Meja","de":"Angka yang dipanggil \"meja nomor sekian!\" di restoran yang ramai. Ia memberi urutan pada penantian dan menjaga keadilan bagi semua orang. Yang tersimpan dalam sekeping chip ini adalah janji kecil, dan semangkuk hangat yang akan segera tiba."},"ICON-0825":{"nm":"Ikat Penanda Gelas Air","de":"Sehelai ikat yang melingkar di gelas air, diam-diam memberitahu itu milik siapa. Bendera kecil yang menandai tempatmu di antara gelas-gelas yang serupa. Di meja yang dikelilingi bersama, perhatian sekecil ini mencegah kesalahpahaman yang tak perlu."},"ICON-0826":{"nm":"Pin Pemilah Piring Kecil","de":"Pin yang memisahkan piring kecil untuk mengambil makanan berdasarkan warnanya. Ia menggariskan batas milikmu dan milikku dengan penuh kasih, membuat kesenangan berbagi jadi lebih bersih. Kehangatan boleh dibagi, tapi kebersihan tetap dijaga dengan cermat."},"ICON-0827":{"nm":"Papan Penutup Menu","de":"Waktu untuk berpikir yang tersembunyi diam-diam di balik buku menu yang terbuka. Bahkan keraguan singkat memilih apa yang akan disantap itu, sesungguhnya, bagian dari makan itu sendiri. Hari ini mau makan apa ya—ia dengan lembut menyembunyikan debar kecil itu."},"ICON-0828":{"nm":"Penyangga Kartu Nama Tempat","de":"Sebuah sandaran kecil yang menegakkan kartu nama. Entah di acara resmi atau di meja perjamuan, ia dengan jelas mengumumkan bahwa di sinilah tempatmu. Keramahan baru sungguh sempurna pada saat sebuah nama dipanggil."},"ICON-0829":{"nm":"Sarung Cup Muffin","de":"Baju kertas yang membungkus rapat pinggang gempal muffin yang baru dipanggang. Ia menopang tubuh hangatnya agar tak lolos dari tangan, menjaga kehangatan itu tetap tersimpan hingga gigitan pertama. Bahkan dessert pun butuh sehelai baju."},"ICON-0830":{"nm":"Tutup Kantong Semprot Krim","de":"Penyumbat yang menjaga ujung kantong penyemprot krim tetap terkatup rapat. Ia menutup mulutnya dengan erat agar tak setetes pun bocor selagi beristirahat. Sekuntum bunga kecil di atas kue mekar dari kesabaran ini."},"ICON-0831":{"nm":"Cincin Cetakan Kukis","de":"Sebentuk cetakan bundar yang memotong adonan menjadi bintang, menjadi beruang. Tepung yang sama terbangun menjadi puluhan ekspresi lewat ujung jari. Apa pun yang dipanggang, yang menyentuh adonan lebih dulu selalu ketulusan hati."},"ICON-0832":{"nm":"Liontin Pengikis Adonan","de":"Sebuah tangan pipih yang cermat mengumpulkan adonan dan membelahnya dengan rapi. Ketekunan memperhatikan bahkan segenggam sisa yang menempel di mangkuk itulah yang menentukan besar sebuah roti. Membuat kue adalah pekerjaan tangan yang hemat."},"ICON-0833":{"nm":"Papan Sendok Takar","de":"Satu sendok teh, setengah sendok makan—papan yang membaringkan sendok-sendok takar dengan rapi, tanpa goyah. Satu takaran yang tepat meluruskan keseimbangan rasa. Di balik ungkapan \"cita rasa tangan\" sesungguhnya tersembunyi ketelitian menakar."},"ICON-0834":{"nm":"Gantungan Sarung Tangan Oven","de":"Sebuah gantungan untuk menggantung sarung tangan yang berjaga di depan oven panas. Tangan tebal yang menahan luka bakar itu tetap berada dalam jangkauan bahkan saat beristirahat. Keselamatan selalu bermula dari sesuatu yang tetap berada di tempatnya."},"ICON-0835":{"nm":"Klip Rak Pendingin","de":"Sebuah jepitan yang menggigit rapi jaring tempat kue yang baru dipanggang mendingin. Ia menahan agar tak bergeser selagi uapnya menguar, menunggu bersama hingga kerenyahan itu sempurna. Bahkan proses mendinginkan pun butuh segenggam kesabaran."},"ICON-0836":{"nm":"Tusuk Hiasan Kue Ulang Tahun","de":"Sebuah tusuk yang menegakkan lima huruf \"Selamat Ulang Tahun\" di atas kue. Sesaat sebelum lilin padam, bendera kecil ini menerangi hari seseorang dengan paling cerah. Ucapan selamat terlihat paling indah bila ditegakkan tinggi."},"ICON-0837":{"nm":"Tabung Gula Halus","de":"Sebuah tabung yang menyimpan satu taburan ringan terakhir. Ia turun bagai salju putih di atas dessert yang baru dipanggang, mengubah sepotong biasa menjadi hadiah kecil. Sentuhan akhir datang dari tangan yang paling ringan."},"ICON-0838":{"nm":"Label Gimbap Segitiga","de":"Kupas plastiknya dengan urutan 1, 2, 3, dan rumput lautnya kembali renyah pada segitiga itu. Selarik tulisan yang membuatmu mengenali sekilas teman andalan minimarket di dini hari. Malam-malam lapar sehabis belajar tersimpan di sini."},"ICON-0839":{"nm":"Penahan Tutup Cup Mi Instan","de":"Sebuah penyangga yang diam-diam menekan agar tutupnya tak terangkat selama tiga menit menunggu. Ia menggantikan tempat sumpit yang dulu diletakkan di atas agar uapnya tak lolos. Waktu singkat mi itu matang adalah momen paling berdebar dari camilan malam."},"ICON-0840":{"nm":"Tutup Tusuk Hot Bar","de":"Sebuah tutup kecil yang menggenggam erat ujung tusuk sate. Ia menjaga agar mudah digigit, tanpa setetes bumbu pun mengotori tangan. Kesenangan jajan di depan kedai bunsik selalu disempurnakan oleh hal-hal kecil seperti ini."},"ICON-0841":{"nm":"Pegangan Kantong Plastik","de":"Kaitkan di jari, dan plastik itu berderit pelan. Berat belanjaan condong ke satu sisi, dan jalan pulang meninggalkan bekas merah di telapak tangan. Dalam bunyi yang ringan itu, seluruh urusan rumah tangga hari ini tergantung berat dan bergoyang."},"ICON-0842":{"nm":"Klip Lipat Struk","de":"Lipat struk yang terurai panjang jadi dua lalu jepit rapat, dan uang yang dibelanjakan hari ini menjadi satu berkas yang rapi. Selagi kertas beraroma tinta itu menumpuk satu per satu, kenangan sekecil apa pun tentang mengurus rumah tangga pun ikut tersusun rapi."},"ICON-0843":{"nm":"Tag Microwave","de":"Sebelum bunyi \"ting\" terdengar, tag ini diam-diam menghitung waktu untuk memanaskan. Papan penanda kecil yang mencatat berapa menit berapa detik, serta nama apa yang akan dihangatkan. Bahkan hati yang menunggu giliran untuk menghangat memiliki skalanya sendiri seperti ini."},"ICON-0844":{"nm":"Gulungan Stiker Diskon","de":"Setiap kali satu kotak dilepas, bunyi lengket yang kecil menggelitik ujung jari. Ketika angka merah terurai berbaris, keranjang belanja seseorang menjadi sedikit lebih ringan. Segulung kebaikan kecil, tergulung bundar sambil menunggu."},"ICON-0845":{"nm":"Cincin Kantong Saus","de":"Sesuatu yang asam meletup di sudut bibir, dan hari yang biasa saja pun terasa sedikit lebih manis. Ketika kantong yang tergantung di cincin bundar bergoyang setiap langkah, satu manis kecil mengikutiku sepanjang hari di dalam saku."},"ICON-0846":{"nm":"Chip Keranjang Minimarket","de":"Genggam saja, dan plastiknya melengkung ringan. Toko yang terang benderang di malam larut, cukup dalam untuk memuat beberapa gimbap segitiga dan sekaleng minuman. Wadah hangat sebesar satu kali makan, di mana sendirian pun tak terasa sepi."},"ICON-0847":{"nm":"Ikat Kotak Macaron","de":"Sehelai ikat dengan lembut merangkul kotak agar macaron warna-warni di dalamnya tak berantakan. Siapa pun yang pernah menerima hadiah tahu lewat ujung jarinya, debar sesaat sebelum melepas pita itulah yang sesungguhnya paling manis."},"ICON-0848":{"nm":"Klip Jaring Buah","de":"Kumpulkan mulut jaringnya lalu jepit, dan aroma apel diam-diam menyusup keluar lewat sela jaring. Sebuah tangan kecil yang menahan agar tak berguling jatuh. Ajakan lembut tanpa suara untuk segera memakannya sebelum terlalu lembek."},"ICON-0849":{"nm":"Kain Tutup Toples Selai","de":"Teringat dapur musim panas nenek dari pihak ibu, menutup tutup toples dengan kain bundar lalu mengikatnya dengan karet gelang. Selembar kain kotak-kotak menyegel bersama waktu manis dan ketulusan hati selagi selai matang. Cita rasa tangan disimpan dengan cara ditutupi seperti ini."},"ICON-0850":{"nm":"Pita Ikat Kukis","de":"Masukkan kukis yang baru dipanggang ke dalam plastik selofan lalu puntir ikatannya, dan aroma mentega meresap hingga ke ujung pita. Tangan yang menyerahkan sesuatu buatan sendiri kepada seseorang selalu sedikit gemetar. Sebuah simpul yang turut mengikat hati bersamanya."},"ICON-0851":{"nm":"Papan Sekat Cokelat","de":"Kotak demi kotak, ia menentukan tempat agar cokelat-cokelat itu tak saling bersentuhan. Agar tak meleleh, agar tak hancur. Yang dijaga oleh sekat kecil ini hingga akhir adalah, pada akhirnya, satu keping utuh hati yang akan diserahkan kepada seseorang."},"ICON-0852":{"nm":"Label Hadiah Teh","de":"Di atas label yang melilit kantong teh, sebuah nama tertulis rapi dengan tangan. Selembar kertas kecil itu berbisik lebih dulu bahwa bila diseduh, aroma rerumputan akan naik bersama uapnya. Secangkir yang menghangatkan tangan bahkan sebelum diminum."},"ICON-0853":{"nm":"Kalung Botol Permen","de":"Sebuah kalung yang dibuat dengan melilitkan tali di leher botol berisi permen warna-warni. Setiap kali melangkah, terdengar bunyi bagai manik-manik kecil bergulir di dalamnya. Harta karun kebanggaan masa kecil, mengalungkan kemanisan di leher."},"ICON-0854":{"nm":"Liontin Sendok Hadiah","de":"Dengan satu liontin kecil yang tergantung di ujung gagangnya, sendok biasa pun tanpa disadari berubah menjadi hadiah. Bunyi gemerincing ringan dan jernih setiap kali menyendok. Sebuah hiasan kecil yang menambahkan sentuhan istimewa pada hati yang diberikan."},"ICON-0855":{"nm":"Tag Balasan Terima Kasih Camilan","de":"Keinginan untuk membalas walau sedikit dari apa yang telah diterima. Selembar tag ucapan terima kasih yang tergantung lembut di kantong camilan. Menggantikan \"terima kasih\" yang belum sempat terucap lengkap, sapaan kecil itu berpindah diam-diam dari tangan ke tangan."},"ICON-0856":{"nm":"Cincin Sampel Masking Tape","de":"Motif-motif yang dipotong dan ditempel sejengkal demi sejengkal berbaris menjadi pita kecil. Selagi ujung jari perlahan memilih warna yang disukai, sekadar membayangkan menghias saja sudah mewarnai hari jadi berwarna-warni. Selarik sampel di mana bahkan menimbang-nimbang pun terasa menyenangkan."},"ICON-0857":{"nm":"Tutup Pinset Stiker","de":"Pasangkan tutup pada ujung pinset yang runcing, dan stiker sekecil kuku pun tak akan rusak. Tangan yang teliti dengan lembut mengangkat sudut yang tak terjangkau oleh jari. Menangani sesuatu yang disukai selalu disertai kehati-hatian."},"ICON-0858":{"nm":"Segel Sudut Diary","de":"Tempelkan segel di keempat sudut diary, dan halaman yang berkibar pun tiba-tiba tenang bagai sulap. Sensasi kertas yang tertekan lembut, sebuah ritual kecil yang menyegel rapi hari ini. Catatan mulai kokoh sejak dari sudut-sudutnya."},"ICON-0859":{"nm":"Papan Panduan Lubang","de":"Sebuah papan yang memberi tahu lebih dulu di mana harus melubangi. Sejajarkan dengan tenang sepanjang garis putus-putus, dan tak akan meleset. Hati yang menakar sekali lagi tanpa terburu-buru, ketepatan selalu datang diam-diam dari kelonggaran sesaat itu."},"ICON-0860":{"nm":"Baki Serpihan Kertas","de":"Serpihan kertas sisa guntingan mengumpul lembut ke dalam baki. Tempat singgah sesaat bagi keping-keping kecil itu, agar meja tak berantakan. Sisa dari kegiatan membuat kerajinan dirapikan, seperti ini, tanpa suara."},"ICON-0861":{"nm":"Bantalan Tinta Warna","de":"Tekan bantalannya ringan lalu angkat, dan warna menyebar lembap di ujung jari. Merah kuning biru, sebuah pelangi kecil yang tercetak dari satu kali stempel. Sepetak tempat lembut untuk menanamkan warna, tap demi tap, di atas kertas putih."},"ICON-0862":{"nm":"Gulungan Pita Hias","de":"Motifnya terurai bergulung tanpa henti. Lepaskan satu jengkal lalu tempelkan, dan bunga pun mekar di tempat yang tadinya polos. Segulung sihir kecil yang tergulung bundar sambil menunggu, semakin cantik seiring tangan bergerak."},"ICON-0863":{"nm":"Tutup Stempel Tema","de":"Sebuah topi kecil yang membungkus rapat kepala stempel agar tintanya tak mengering. Ia diam-diam menjaga agar motif berikutnya tetap tercetak jelas. Warna yang tersimpan baik akan mekar sama cerahnya di lembar kertas berikutnya."},"ICON-0864":{"nm":"Serpihan Punch Hias","de":"Serpihan kecil yang dijatuhkan oleh alat pelubang. Serpihan kertas warna-warni yang dipotong menjadi bintang, hati, dan kelopak bunga mengumpul lembut di telapak tangan. Permata-permata kecil yang terlalu cantik untuk dibuang, hingga akhirnya tertempel lagi di suatu tempat."},"ICON-0865":{"nm":"Cincin Label Kumparan Benang","de":"Selembar label kecil dengan nama tiap benang warna tertulis pada setiap kumparan. Sebuah penanda penuh perhatian yang menunjukkan tempatnya sebelum sempat kusut. Benang yang kusut, dan juga hati, jauh lebih mudah diurai hanya dengan satu label nama."},"ICON-0866":{"nm":"Sampul Buku Jarum","de":"Sampul lembut yang menutupi buku berlembar felt tempat jarum-jarum tertancap rapat. Buka, dan alat-alat jahit terbaring rapi menyambutku. Sebuah buku kecil yang dengan lembut menidurkan benda-benda runcing, agar ujung jari tak terluka."},"ICON-0867":{"nm":"Cincin Sampel Kain","de":"Kasar atau lembut, waktu yang perlahan meraba tekstur kain satu demi satu dengan ujung jari untuk memilih. Di antara potongan kain yang terkumpul rapi menurut warnanya, sebelum menjadi sehelai pakaian, kain diam-diam menunggu untuk disentuh lebih dulu."},"ICON-0868":{"nm":"Ring Pemidangan Sulam","de":"Pasang kain pada pemidangan bundar lalu kencangkan, dan ia meregang kencang bagai kulit gendang. Sebuah tanda kecil bahwa persiapan menyulam seuntai demi seuntai telah selesai. Yang ditahan kuat oleh pemidangan bukanlah kain, melainkan hati yang tengah berkonsentrasi."},"ICON-0869":{"nm":"Kapsul Pemilah Kancing","de":"Kancing-kancing yang dulu berguling ke sana kemari kini duduk tenang menurut warnanya di tiap ruang kapsul. Kebijaksanaan rumah tangga membaginya ke dalam wadah kecil agar tak ada yang hilang. Bahkan mengumpulkan yang berserakan membutuhkan ketulusan sebesar ini."},"ICON-0870":{"nm":"Pemegang Kapur Jahit","de":"Sebuah pemegang yang menggenggam nyaman kapur untuk menggaris kain di tangan. Ia menopang kuat sesuatu yang mudah patah. Niat tenang sebelum mengangkat gunting, bahwa garis pertama yang lurus akan membuat pakaian pun lurus."},"ICON-0871":{"nm":"Toples Jarum Pentul","de":"Di dalam toples bening, jarum-jarum pentul saling berbenturan dan berdenting pelan. Diterawang ke cahaya, seberkas kilau kecil menempel di ujung tiap jarum. Sebuah wadah yang cermat, mengumpulkan di satu tempat dan menidurkan dengan lembut, benda-benda yang berbahaya bila berserakan."},"ICON-0872":{"nm":"Gulungan Pita Tambal","de":"Sebuah pita ajaib yang diam-diam merekat begitu disetrika di atas bagian yang robek. Tanpa satu jahitan pun, pakaian yang usang pun sembuh dengan tenang. Hati yang menambal dan terus memakainya alih-alih membuang, tergulung rapi lapis demi lapis di dalam gulungan bundar itu."},"ICON-0873":{"nm":"Kertas Pola Tempel","de":"Selembar kertas pola dengan bentuk tempelan yang telah digambar lebih dulu. Garis putus-putus dengan lembut menuntun jalan yang akan dilalui gunting. Menggambar dahulu garis besar dari apa yang ingin dibuat, debar itu selalu bermula dari sketsa samar ini."},"ICON-0874":{"nm":"Tutup Toples Air Cat Air","de":"Pasang di mulut toples, dan air berwarna tak akan bocor setetes pun meski terguncang sekeras apa pun. Ia bahkan menutupi kekhawatiran akan air bilasan kuas yang keruh menyebar ke meja. Sebuah penyumbat tenang yang diam-diam menjaga tempat kau melukis."},"ICON-0875":{"nm":"Pita Pelindung Pastel","de":"Lingkarkan sehelai pita pada pastel yang meninggalkan bubuk keputihan, dan jari-jari jadi tak sekotor itu. Kertas yang lembut membungkus warna yang rapuh agar tak hancur. Semakin lembut warnanya, semakin lembut pula harus digenggam, agar tergores lembut pula di atas kertas."},"ICON-0876":{"nm":"Tutup Penyambung Pensil Warna","de":"Pasang tutup di ujung pensil warna yang sudah pendek, dan sebatang itu memanjang kembali. Hati yang tak mudah membuang hanya karena sudah memendek. Dari ujung jari yang memakainya hingga habis, warna gambar pun sempurna lebih pekat hingga kotak terakhir."},"ICON-0877":{"nm":"Gantungan Cangkir Cuci Kuas","de":"Gantungkan cangkir pencuci di kaitnya, dan tetes air yang jatuh dari kuas mengalir turun perlahan. Sebelum mewarnai warna berikutnya, keheningan singkat dan jernih saat membilas kuas. Bahkan dalam bunyi yang semakin bersih itu, mengalir sebuah irama yang tenang."},"ICON-0878":{"nm":"Tutup Pisau Palet","de":"Sebuah tutup kecil yang membungkus rapat mata pisau yang membentangkan dan mengikis cat. Ia diam-diam menjaga agar ujung yang tajam tak menumpul. Tekstur warna yang dioleskan tebal lahir dari ujung yang terawat baik ini."},"ICON-0879":{"nm":"Klip Kanvas","de":"Sebuah jepitan kokoh yang menarik kencang kain kanvas ke rangkanya dan menahannya erat. Gigit kuat, dan permukaan untuk melukis pun terentang kencang bagai kulit gendang. Hanya dengan dasar yang tak bergoyang, sapuan kuas yang berlari di atasnya bisa bebas sepuasnya."},"ICON-0880":{"nm":"Tali Papan Gambar","de":"Selempangkan tali di bahu, dan papan itu mengikuti di belakang punggung. Duduk di mana pun, dan di situlah studio pribadimu. Sebuah studio kecil yang dipanggul di punggung, berangkat ringan mencari pemandangan yang ingin digambar."},"ICON-0881":{"nm":"Tube Cat Akrilik","de":"Tambah setetes air dan jadilah fajar; kurangi sedikit dan jadilah tengah malam. Biru yang sama membuka langit yang berbeda setiap kali di ujung jari. Saat satu tube diperas, warna hati hari ini menyebar ke atas kertas."},"ICON-0882":{"nm":"Lembar Sampel Gradasi","de":"Kertas ini lebih dulu tahu bahwa senja tak memerah dalam sekejap. Anak tangga-anak tangga kecil yang menyeberang dari yang pucat menuju yang pekat. Mata berjalan perlahan di antaranya, dengan tenang mengikuti waktu warna itu matang."},"ICON-0883":{"nm":"Tutup Jarum Hakpen","de":"Sebuah pelindung sekecil bidal yang dipasang sebelum benang menggores jari. Tangan yang sudah lama merajut tahu benar. Hanya dengan tetap tak terluka, ia bisa membawa seuntai benang dengan lembut hingga tusukan terakhir."},"ICON-0884":{"nm":"Penanda Cincin Rajut","de":"Satu penanda saja, dan sejauh mana sudah dicapai kembali jelas terlihat. Kelegaan tak perlu menghitung tusukan yang sama dua kali. Hati pun begitu, hanya ketika dengan lembut menandai tempat yang telah dilalui, ia tak akan tersesat."},"ICON-0885":{"nm":"Liontin Penghitung Baris","de":"Bukti tenang bahwa satu baris telah selesai menumpuk kotak demi kotak. Bahkan pekerjaan yang tampak tanpa akhir, bila dihitung satu per satu, tanpa disadari telah melewati separuh jalan. Hitungan kecil ini membawa hati hari ini bertahan hingga akhir."},"ICON-0886":{"nm":"Pin Perapi Ujung Benang","de":"Biarkan ujung benang yang terurai begitu saja, dan tak ada yang tahu di mana simpul berikutnya akan kusut. Sentuhan yang merapikan lebih dulu tempat yang tak akan terlihat. Kelembutan hati biasanya, seperti ini, lebih dulu bergerak di tempat yang tak tampak mata."},"ICON-0887":{"nm":"Tali Latihan Simpul","de":"Simpul mati, simpul pita, simpul cincin. Ikat dan lepaskan tali yang sama berulang kali hingga tangan menghafal bentuknya. Ketika ujung jari yang dulu canggung tiba-tiba menjadi luwes di suatu malam, seutas tali itulah yang pertama kali tahu."},"ICON-0888":{"nm":"Pita Label Benang Wol","de":"Sehelai pita kecil yang mencatat ketebalan dan warna apa pada tiap gulungan benang. Kebiasaan ini lahir dari malam-malam yang tersesat mencari benang yang sama setelah kehabisan. Catatan adalah pesan penuh kasih untuk diriku di masa depan."},"ICON-0889":{"nm":"Penggaris Pengukur Gauge","de":"Berapa banyak tusukan yang muat dalam 10 sentimeter—angka kecil itu yang menentukan ukuran sehelai pakaian. Bahwa sekeping seukuran telapak tangan memegang ukuran keseluruhan, kalau dipikir-pikir, itu urusan yang cukup berat."},"ICON-0890":{"nm":"Penanda Lubang Kancing","de":"Sebelum menjahitkan kancing, satu titik ditandai lebih dulu di mana harus dilubangi. Berkat tanda yang akan segera lenyap itu, kancing baju tak akan miring. Ketulusan biasanya diam-diam tersisa di tempat yang pada akhirnya tak terlihat."},"ICON-0891":{"nm":"Ring Rumbai Kecil","de":"Bagai rumbai di ujung norigae, satu cincin kecil menciptakan ayunan. Sesuatu yang tergantung dan bergoyang tenang selalu menahan pandangan mata. Sebuah tekstur yang diam-diam hidup bergerak setiap kali angin berlalu."},"ICON-0892":{"nm":"Botol Cat Mini","de":"Bukan menghemat, melainkan menggunakan dengan tepat—itulah cara memperlakukan cat dengan benar. Sebuah warna yang cukup dengan setetes saja, ditakar oleh tangan yang berada di samping botol kecil. Ketertiban lahir dari melepaskan keserakahan, sekali saja."},"ICON-0893":{"nm":"Stik Amplas Kecil","de":"Mulai dari permukaan kasar lalu berpindah perlahan ke yang halus. Tak ada permukaan mana pun yang menjadi mulus dalam satu kali usapan. Dari ujung jari yang menurunkan tekstur setahap demi setahap, tempat yang tadinya kasar perlahan menjadi lembut."},"ICON-0894":{"nm":"Penyangga Klip Model Kit","de":"Genggam komponen yang telah dilem di tangan, dan sidik jari pun tertinggal. Jepit lembut pada klip, dan tangan menjadi bebas, sementara pengeringan selesai dengan sendirinya tanpa suara. Bahkan penantian menjadi ringan saat ada yang menopangnya untukmu."},"ICON-0895":{"nm":"Alas Kerja Lem","de":"Setetes lem yang jatuh ke meja meninggalkan bekas yang bertahan lama. Kebiasaan menggelar selembar alas lebih dulu. Separuh dari sebuah pekerjaan, barangkali, bermula dari niat sekecil itu untuk tidak mengotori tempat."},"ICON-0896":{"nm":"Kotak Pemilah Komponen","de":"Campurkan puluhan komponen berbentuk sama, dan perakitan segera menjadi labirin. Sentuhan yang membagi-baginya ke tiap kotak, sudah lebih dulu mengurangi waktu yang akan terbuang tersesat. Merapikan adalah kebaikan yang diberikan kepada diriku di masa depan."},"ICON-0897":{"nm":"Chip Urutan Rakitan","de":"Sekeping chip kecil yang mencatat komponen nomor berapa yang harus dipasang lebih dulu. Ikuti urutannya, dan semuanya tak akan mudah runtuh. Sebuah model kit, dan hari apa pun yang dibangun perlahan setahap demi setahap, menjadi kokoh di atas janji yang tenang itu."},"ICON-0898":{"nm":"Gantungan Kuas Mini","de":"Baringkan kuas yang telah dipakai, dan bulunya tertekan hingga bengkok. Sebuah tempat untuk menggantungnya terbalik agar embunnya menetes habis. Orang yang lama menjaga alatnya di sisinya justru lebih sibuk dan lebih penuh perhatian setelah pekerjaan usai."},"ICON-0899":{"nm":"Wadah Sisa Runner Plamo","de":"Sebuah wadah tempat potongan sisa yang dilepas dari rangka cetakan diam-diam berkumpul. Meski tampak terbuang, suatu hari ia kembali menjadi detail kecil. Bahwa bahkan sisa pun punya gilirannya sendiri, wadah ini tahu sambil menunggu dengan tenang."},"ICON-0900":{"nm":"Tutup Semprotan Cat Akhir","de":"Lapisan terakhir, bila disemprot terlalu dekat, akan langsung meleleh ke bawah. Dari jarak sejengkal, ringan, ringan saja. Memberi lapisan kilap barangkali juga latihan untuk melepaskan keserakahan hati, sekali saja."},"ICON-0901":{"nm":"Kotak Isi Ulang Pensil Mekanik","de":"Isi pensil mekanik yang tipis begitu mudah patah di dalam saku. Diletakkan rapi berbaring dalam tabung kecil, tak satu batang pun terbuang sia-sia. Merapikan, pada akhirnya, adalah cara diam-diam menyayangi diri di hari esok."},"ICON-0902":{"nm":"Sarung Penghapus","de":"Baju kertas kecil yang dikenakan pada penghapus. Semakin menghitam oleh bekas tangan, semakin banyak jejak koreksi yang terkumpul. Menghapus juga merupakan izin lembut untuk memulai lagi dari awal."},"ICON-0903":{"nm":"Tabung Penyimpan Mata Pena","de":"Mata pena retak bila mengering dan bengkok bila terbentur. Satu tabung kecil untuk membaringkannya secara terpisah menjaga guratan tulisan tetap terjaga lama. Alat yang diperlakukan dengan lembut akan meluncur lembut pula sebagai balasannya."},"ICON-0904":{"nm":"Sampel Tinta Pena","de":"Tinta-tinta yang dicoba setetes demi setetes. Warna yang dikira toska berubah menjadi laut yang pekat di atas kertas. Warna selalu harus ditemui secara langsung untuk dikenali—sebab warna yang dibayangkan dalam hati sering meleset."},"ICON-0905":{"nm":"Kaleng Penanda Buku","de":"Bendera kecil yang diselipkan pelan di halaman tempat berhenti membaca. Saat buku dibuka lagi lain waktu, diri kemarin melambai menunggu. Bahkan tempat berhenti pun menjadi sebuah janji, itulah tugas lembut penanda kecil itu."},"ICON-0906":{"nm":"Paket Label Bendera","de":"Sobek satu lembar dan tempelkan, maka cerita mulai lagi tepat dari situ. Ketika bendera-bendera kecil berbaris di tepi buku, pikiran yang berserakan terkumpul rapi menjadi satu peta."},"ICON-0907":{"nm":"Magnet Pengumpul Klip","de":"Magnet kecil yang menyapu klip-klip yang berserakan sekaligus. Semakin kecil sesuatu, semakin mudah hilang, maka satu kekuatan pengumpul diam-diam menyelamatkan meja yang berantakan. Ada kelembutan bahkan dalam tarikan."},"ICON-0908":{"nm":"Set Tutup Pensil","de":"Topi-topi kecil yang membungkus ujung pensil dan menjaga isi tas. Sesuatu yang runcing pasti akan menusuk sesuatu, sehingga dibutuhkan tangan yang menutupinya dengan lembut. Agar tetap tajam, namun tak melukai."},"ICON-0909":{"nm":"Stiker Papan Nama Meja","de":"Begitu nama dituliskan dan ditempel di depan meja, tempat itu akhirnya menjadi milik seseorang. Ketika ruang seluas sejengkal pun memiliki pemilik, cara hati bertumpu di sana pun ikut berubah."},"ICON-0910":{"nm":"Tutup Pegangan Tali Lompat","de":"Tutup yang dipasang sebelum ujung pegangan aus dan retak. Irama tali yang telah diputar beribu kali lebih dulu diingat telapak tangan daripada kepala. Ketukan yang terukir di tubuh tak mudah dilupakan."},"ICON-0911":{"nm":"Tali Cincin Yoga","de":"Pegang cincinnya dan buka tubuh perlahan. Semakin kencang tali ditarik, semakin bahu yang kaku terurai selapis demi selapis. Meregangkan bukan soal menarik paksa, melainkan lebih dekat pada menunggu dengan tenang hingga tubuh terbuka."},"ICON-0912":{"nm":"Kotak Bola Pingpong","de":"Bola putih yang begitu ringan hingga menggelinding jauh, dan langsung penyok begitu terinjak. Satu kotak kecil melindungi bola paling rapuh itu hingga pertandingan berikutnya. Kekuatan sering kali datang dari dibungkus dengan lembut."},"ICON-0913":{"nm":"Lakban Grip Bulu Tangkis","de":"Melilit satu lapis rapi pada pegangan yang licin oleh keringat. Di atas grip yang terlilit baik, raket menjadi bagian dari tangan. Rahasia memukul dengan rasa, bukan tenaga, tersembunyi dalam satu lapis tipis ini."},"ICON-0914":{"nm":"Chip Skor Kecil","de":"Satu poin, lalu satu poin lagi. Memindahkan chip kecil, skor tersusun perlahan sedikit demi sedikit. Ketika hitungan terlihat jelas, pertandingan menjadi lebih gamblang, dan keberanian mengejar selisih satu poin pun diam-diam muncul."},"ICON-0915":{"nm":"Klip Pengatur Arah Sepatu","de":"Ujung sepatu yang tersusun rapi selalu menghadap arah yang sama. Sentuhan tangan yang memutarnya sedikit saat dilepas. Satu kerapian kecil membuat langkah esok pagi terasa jauh lebih ringan."},"ICON-0916":{"nm":"Tali Kalung Peluit","de":"Mengalungkan peluit di leher memberi hak untuk berkata berhenti. Pemandangan seluruh lapangan berhenti serentak pada satu bunyi pendek. Hati-hati yang mempercayai bunyi kecil itu berkumpul menjadi sebuah janji."},"ICON-0917":{"nm":"Tabung Jarum Pompa Bola","de":"Bola yang kempis pun kembali kencang dengan satu jarum tipis. Jarum yang disimpan rapi dalam tabung kecil itu, begitu hilang, membuat seluruh pompa jadi tak berguna. Saat yang paling kecil menjadi yang paling penting."},"ICON-0918":{"nm":"Kerucut Penanda Mini","de":"Dari sini sampai sana, kerucut kecil menggambar batas yang tak terlihat. Tanpa garis sekalipun, orang-orang secara alami berbaris mengikuti penanda itu. Ketertiban tumbuh diam-diam dari sinyal kecil semacam ini."},"ICON-0919":{"nm":"Kantong Token","de":"Kantong yang mengumpulkan token yang berdenting menjadi satu. Kencangkan mulutnya dan tak ada yang akan tercecer. Bahwa hal-hal kecil dan sepele pun butuh tempat untuk ditampung agar bisa menunaikan perannya, kantong ini menunjukkannya tanpa sepatah kata."},"ICON-0920":{"nm":"Alas Kocok Kartu","de":"Di atas meja yang licin, kartu tak mudah digenggam tangan. Satu alas saja membuat mengocok maupun mengambil kartu jauh lebih lancar. Dalam bermain dengan baik pun, ada persiapan lembut memilih permukaan lebih dulu."},"ICON-0921":{"nm":"Pelindung Sudut Papan Permainan","de":"Ketika malam board game berakhir, seseorang diam-diam lebih dulu merapikan keempat sudut papan. Sebab ia tahu lipatan yang semakin dalam akan membuat ronde berikutnya melenceng. Pada ujung jari yang meratakan sudut itu, tersimpan keinginan untuk bermain bersama lagi esok."},"ICON-0922":{"nm":"Tutup Gelas Dadu","de":"Sesaat singkat ketika semua orang mengocok, melempar, dan menahan napas bersama. Ini langit-langit kecil yang mencegah dadu melompat keluar. Di dalam tutup itu, keberuntungan hari ini menarik napas sejenak sebelum bergulir keluar dengan bunyi berderak."},"ICON-0923":{"nm":"Papan Perata Ubin","de":"Semakin seseorang bersemangat karena permainan, semakin miring pula barisannya. Perlahan mendorong ubin yang condong agar kembali rapi sejajar. Perataan adalah tangan yang menerima dengan lembut ketergesaan gembira seseorang."},"ICON-0924":{"nm":"Kaleng Chip Skor","de":"Semakin penuh sebuah kaleng dengan chip, semakin panas pula permainannya. Ketika bulatan-bulatan skor beradu berderak di telapak tangan, bunyi itu lebih dulu menjadi kegembiraan sebelum menang atau kalah."},"ICON-0925":{"nm":"Cincin Penanda Giliran","de":"Cincin kecil yang memberi tahu bahwa kini giliranmu. Hanya pada momen memindahkannya satu petak itu, mata semua orang tenang terkumpul padaku. Sebuah lingkaran yang berputar perlahan di antara penantian dan debar hati."},"ICON-0926":{"nm":"Alas Bidak Permainan","de":"Semakin mudah sebuah bidak roboh, semakin kokoh pula pijakannya harus dibuat. Satu alas menjaga posisinya bahkan di atas papan yang sedikit bergoyang. Yang kecil harus bertahan agar yang besar di atasnya bisa berdiri tegak."},"ICON-0927":{"nm":"Klip Buku Panduan","de":"Buku panduan selalu diam-diam membalik halamannya sendiri saat dibiarkan terbuka. Sebelum angin membuat lembarannya kabur, jepitan ini menggigit lembut satu halaman. Aturan harus ditahan di tempatnya agar permainan berlanjut sampai akhir."},"ICON-0928":{"nm":"Tali Kotak Pick Gitar","de":"Pick gitar selalu lolos dari jari justru di bagian paling seru. Satu tali yang tergantung dari kotaknya mencegah pelarian kecil itu. Hanya orang yang pernah melewati malam saat musik berhenti yang berterima kasih pada tali ini."},"ICON-0929":{"nm":"Tabung Penyimpan Reed","de":"Reed kehilangan suaranya begitu mengering. Di dalam tabung yang lembap, sepotong buluh tipis menunggu pertunjukan berikutnya. Sebuah tempat untuk menidurkan napas lebih dulu, sebelum meniupkannya kembali."},"ICON-0930":{"nm":"Pemutar Senar","de":"Ketika senar mengendur, nada pun diam-diam melemah. Memutar perlahan gagangnya untuk mengembalikan kekencangan—ketelitian selalu datang dari ujung pergelangan tangan. Suara yang rapi dimulai dari perawatan sekecil ini."},"ICON-0931":{"nm":"Kain Pembersih Alat Musik","de":"Usai bermain, keringat tipis pun tertinggal pada alat musik. Satu usapan kain lembut mengembalikan kilaunya sekaligus menenangkan nada-nada hari ini. Hati yang menyayangi selalu tampak pada penutupnya."},"ICON-0932":{"nm":"Penutup Pin Tuning","de":"Dibiarkan telanjang, pin tuning tanpa disadari akan berkarat. Satu penutup kecil menunda musim logam itu selangkah. Orang yang lebih dulu merawat sudut yang tak terlihat adalah orang yang bermain musik paling lama."},"ICON-0933":{"nm":"Lampu Jepit Stand Partitur","de":"Di belakang panggung yang gelap, ada saat hanya partitur yang harus terang. Ini lampu kecil yang dijepitkan pada stand, pelan-pelan menurunkan cahayanya. Segenggam sinar yang menerangi langkah agar not-not tak kehilangan jalan."},"ICON-0934":{"nm":"Tutup Peredam Latihan","de":"Latihan dini hari selalu diam-diam berselisih dengan tidur tetangga. Pasang satu tutup dan suara yang menggelegar menyusut menjadi bisikan. Ada musik yang tumbuh sambil menjaga lelap tidur seseorang."},"ICON-0935":{"nm":"Stiker Pad Drum","de":"Tanda-tanda kecil yang tertempel di atas pad drum. Di mana harus dipukul untuk bunyi yang mana, mata lebih dulu mengenal jalannya sebelum tangan menghafal. Irama terukir perlahan pada tubuh dengan cara ini."},"ICON-0936":{"nm":"Chip Memo Melodi","de":"Melodi yang digumamkan cepat menghilang bila tak segera ditangkap. Beberapa bar yang buru-buru dituliskan pada chip terkadang tumbuh menjadi satu lagu utuh di kemudian hari. Inspirasi selalu kembali pada tangan yang rajin mencatat."},"ICON-0937":{"nm":"Karet Pengikat Buku","de":"Merepotkan bila buku yang belum selesai dibaca terbuka sendiri di dalam tas. Satu ikatan saja mengikat halaman-halaman agar tetap patuh. Sebuah janji untuk melipat rapi demi halaman berikutnya."},"ICON-0938":{"nm":"Cincin Penahan Halaman","de":"Hari ketika ingin membuka buku dengan satu tangan sambil menyeruput kopi hangat. Cincin yang diselipkan di jari menahan halaman menggantikan tangan. Kelonggaran kecil dimulai dari penemuan sepele semacam ini."},"ICON-0939":{"nm":"Chip Pengatur Waktu Membaca","de":"Duduk untuk satu bab saja, tanpa sadar malam sudah semakin larut. Menekan chip untuk menetapkan waktu, maka membaca pun memiliki tanda koma. Semakin dicintai suatu hal, semakin dibutuhkan keberanian lembut untuk tahu kapan berhenti."},"ICON-0940":{"nm":"Tutup Pelindung Sudut Buku","de":"Semakin disayangi sebuah buku, semakin cepat pula sudutnya diam-diam aus. Pasang satu tutup dan telinga sampul terjaga bulat dan aman. Sebuah zirah kecil yang diselipkan untuk mendekap keinginan menyimpannya di sisi selama-lamanya."},"ICON-0941":{"nm":"Pita Catatan Kesan","de":"Ada momen ketika satu baris kalimat membuat dada seketika runtuh. Kesan yang dituliskan pada pita itu tinggal di halaman itu seperti pembatas buku. Suhu hangat dari garis bawah, yang hanya diketahui oleh orang yang membacanya."},"ICON-0942":{"nm":"Label Pengembalian Perpustakaan","de":"Tanggal pengembalian selalu datang sehari lebih awal. Ketika tanggal yang tertulis pada label diam-diam mendorong punggung, buku pinjaman pun mendapat sopan santun sebuah akhir. Demi tangan orang berikutnya, perpustakaan menunggu seperti itu."},"ICON-0943":{"nm":"Lampu Jepit Buku","de":"Malam ketika hanya sendiri yang terjaga membaca di samping keluarga yang tertidur. Satu cahaya kecil yang dijepitkan di ujung buku sudah cukup. Tak perlu menyingkirkan seluruh kegelapan, cukup satu halaman untuk waktu yang tenang."},"ICON-0944":{"nm":"Kartu Aroma Buku","de":"Buku lama mengeluarkan aroma sinar matahari yang bercampur dengan kertas. Kartu yang disebut menyimpan aroma itu dalam satu lembar, saat dibuka menghidupkan kembali gang toko buku bekas sejenak di ujung hidung. Ingatan pun menyelipkan pembatas lewat aroma."},"ICON-0945":{"nm":"Pin Penanda Halaman Terakhir","de":"Sampai mana tadi aku membaca, pin kecil ini menghapus pertanyaan yang membingungkan itu. Tancapkan di kalimat terakhir dan diri esok tak lagi tersesat. Penanda lembut yang mengingat tempat berhenti sebagai gantiku."},"ICON-0946":{"nm":"Gantungan Tali Ponsel","de":"Satu gantungan yang tersemat pada tali ponsel membuat seseorang tampak sedikit berbeda. Warna favorit, bentuk favorit. Selera kecil yang digenggam di tangan pelan-pelan menggoyang suasana hati hari itu."},"ICON-0947":{"nm":"Tutup Pelindung Lensa Kamera","de":"Nasib foto perjalanan bergantung pada satu keping lensa. Momen melepas tutup pelindung adalah kesiapan hati untuk menekan rana. Sebuah ritual kecil, yang pertama membuka mata sebelum menangkap sebuah pemandangan."},"ICON-0948":{"nm":"Sumbat Port Pengisi Daya","de":"Debu di dalam tas selalu mengincar lubang pengisi daya lebih dulu. Sumbat satu lubang kecil itu dan port tetap bersih untuk waktu lama. Di sinilah kerajinan yang merawat bahkan celah yang tak terlihat."},"ICON-0949":{"nm":"Cincin Pop Penyangga Ponsel","de":"Menyandarkan ponsel miring hanya demi menonton satu video dengan nyaman. Membuka cincin pop di baliknya membuat tangan dan layar sama-sama lebih leluasa. Satu sandaran kecil yang tumbuh membuat satu waktu malam terasa lebih santai."},"ICON-0950":{"nm":"Patch Pembersih Layar","de":"Layar penuh sidik jari entah bagaimana membuat hati pun ikut buram. Sekali usap dengan patch dan dunia kembali jernih. Kebersihan kadang hanyalah pekerjaan singkat satu jari."},"ICON-0951":{"nm":"Kotak Pin SIM","de":"Pin pengeluar kartu SIM adalah peri yang menghilang justru pada saat paling dibutuhkan. Simpan dalam satu ruang kotak dan tak perlu lagi mengobrak-abrik seisi rumah mencari jepit rambut. Kerapian kecil diam-diam menyelamatkan momen yang mendesak."},"ICON-0952":{"nm":"Stiker Alas Pengisi Daya Nirkabel","de":"Malam ketika daya terisi dengan sendirinya saat diletakkan tenang di atas alasnya. Stiker yang tertempel menandai pelan tempat ponsel harus berbaring. Arus yang tak terlihat diam-diam mengisi penuh tenaga untuk sehari."},"ICON-0953":{"nm":"Stiker Penutup Notifikasi","de":"Notifikasi yang tak ingin dilihat lebih baik ditutup saja demi ketenangan hati. Satu lembar stiker meredupkan cahaya kecil di dini hari. Kadang tidak melihat pun menjadi cara lembut menjaga diri sendiri."},"ICON-0954":{"nm":"Cincin Pelindung Lensa","de":"Saat lensa kamera menyentuh lantai sekejap, jantung serasa jatuh. Satu cincin yang melingkarinya diam-diam menahan jatuhnya. Sebuah bingkai yang melindungi, pertama-tama, mata yang menyimpan kenangan."},"ICON-0955":{"nm":"Label Nama Kabel","de":"Memilah milikku sendiri dari tumpukan kabel yang kusut dan bersimpul. Satu label saja akhirnya memberi kabel pengisi daya namanya sendiri. Bendera kecil yang menunjukkan jalan di antara tali-tali yang berantakan."},"ICON-0956":{"nm":"Pouch Charger","de":"Charger-charger dalam tas perjalanan selalu saling kusut berselisih. Kumpulkan rapi dalam satu ruang pouch dan mereka akhirnya berdamai. Seni berkemas terletak pada memanggil dengan lembut hal-hal yang berserakan ke satu tempat."},"ICON-0957":{"nm":"Label Terminal Listrik","de":"Lubang-lubang stop kontak semuanya terlihat sama, selalu membingungkan setiap kali. Menempelkan label untuk menentukan tempat siapa milik siapa membuat pagi yang sibuk jauh lebih lancar. Label nama kecil mengurangi pertengkaran remeh sehari-hari."},"ICON-0958":{"nm":"Gulungan Kabel","de":"Dibuka untuk dipakai, digulung kembali, sehari yang rapi bagi sebuah kabel. Gulung dalam satu reel lapis demi lapis dan kekusutan lenyap bersih. Tangan yang mengembalikan sesuatu ke tempatnya setelah dipakai membuat esok terasa ringan."},"ICON-0959":{"nm":"Tutup Konektor Magnetik","de":"Konektor magnet tanpa disadari mengumpulkan serbuk logam halus. Tutup dengan sebuah caps dan debu lengket tak akan menempel. Perangkat yang tersentuh satu perhatian ekstra hidup lebih lama di sisi kita."},"ICON-0960":{"nm":"Ikat Power Bank","de":"Power bank dan kabelnya bila dipisah, salah satunya pasti hilang. Ikat dengan sebuah band dan keduanya akhirnya menjadi satu pasang. Simpul kecil yang diikatkan lembut tepat sebelum berangkat, berpesan agar mereka pergi bersama."},"ICON-0961":{"nm":"Tutup Debu Colokan","de":"Lubang stop kontak yang kosong hanya dalam beberapa hari sudah pelan-pelan didiami debu. Ketika tutup kecil ini menjaga tempat itu sebagai gantinya, charger yang akan tersambung berikutnya bisa menghirup napas pertama yang bersih. Seorang penjaga gerbang yang menjaga waktu kekosongan tetap rapi."},"ICON-0962":{"nm":"Cincin Warna Kabel","de":"Pada malam meraba-raba mencari milikku di antara kabel yang kusut, siapa yang mengusulkan agar diberi warna. Biru untukmu, kuning untukku. Dengan satu lingkaran kecil, kita tak lagi saling tertukar. Sebuah jejak janji manis yang tersisa di sudut ruang latihan."},"ICON-0963":{"nm":"Chip Pemilah Adaptor","de":"Kaki bulat dan kaki pipih, 110 dan 220. Sebuah chip yang diam-diam menghafal wajah stop kontak yang berbeda tiap negara. Di sudut koper untuk perjalanan pertama menyeberangi lautan menuju panggung, kartu pemilah kecil ini selalu terselip di sana."},"ICON-0964":{"nm":"Nampan Pemilah Ear Tip","de":"Konon lubang telinga berbeda kedalaman dan lebarnya untuk setiap orang. Membaringkan besar, sedang, dan kecil berjajar, lalu memilih satu pasang yang pas untuk telinga sendiri. Sebuah prosedur lembut menyesuaikan tubuh lebih dulu, sebelum mendengarkan suara."},"ICON-0965":{"nm":"Cincin Silikon Casing","de":"Kostum panggung diperhatikan hingga ke setiap jahitan, tetapi justru sudut casing selalu terbentur telanjang. Ketika bingkai silikon tipis ini melingkupi tepinya dengan lembut, bahkan pada dini hari saat terlepas dari tangan, layar tetap menyambut pagi tanpa cela."},"ICON-0966":{"nm":"Stiker Peredam Bising","de":"Ada hari-hari ketika ingin mematikan sejenak suara dunia. Stiker kecil yang ditempel di telinga headphone ini adalah penanda yang menyalakan kesunyian. Sorak-sorai penonton dan bising kereta bawah tanah, jimat ini membawanya menjauh hanya sampai satu lagu berakhir."},"ICON-0967":{"nm":"Set Kait Telinga","de":"Saat menari, earphone selalu ada satu sisi yang lebih dulu kabur. Kaitkan lingkaran yang mendekap lembut daun telinga ini, dan musik saja yang tetap tinggal di telinga sampai akhir bahkan di tengah koreografi yang keras. Penemuan kecil yang saling ditukar orang-orang di ruang latihan."},"ICON-0968":{"nm":"Tutup Sikat Pembersih","de":"Topi kecil yang dipasang agar debu di ujung bulu sikat tak beterbangan lagi. Bahwa alat pembersih pun butuh dibersihkan, sudah lama diketahui oleh tangan yang terbiasa mendirikan sapu terbalik setelah menyapu."},"ICON-0969":{"nm":"Alas Dasar Charging Dock","de":"Charging dock selalu tergelincir di atas meja karena tak memiliki kaki. Begitu satu lembar alas tipis ini berperan sebagai kaki, perangkat itu diam tenang di tempatnya dan mengisi tenaga dengan tenang sepanjang malam."},"ICON-0970":{"nm":"Penanda Kiri-Kanan","de":"Kiri L, kanan R. Satu titik tambahan ditandai agar bisa dikenali bahkan dengan meraba dalam gelap. Keinginan untuk tak pernah sekalipun keliru antara kaki kiri dan kanan di panggung, terpatri utuh pada penanda kecil ini."},"ICON-0971":{"nm":"Tutup Jack Pembagi Audio","de":"Jack tempat satu aliran suara dibagi didengarkan banyak orang, ujungnya harus ditutup saat beristirahat. Agar debu tak meresap ke sirkuit. Sebuah tangan yang kecil dan berhati-hati, berharap lagu yang pernah didengarkan bersama bisa mengalir jernih lagi lain waktu."},"ICON-0972":{"nm":"Gulungan Kabel Earphone","de":"Seperti gerakan tangan lama menggulung segulung benang, kabel earphone pun menjadi rapi bila digulung bulat di sini. Momen ketika musik yang berguling kusut di dalam tas tertata rapi. Esok yang akan mengurainya terasa jauh lebih ringan."},"ICON-0973":{"nm":"Tali Penahan Tutup Lensa","de":"Setiap kali lensa dibuka, tutupnya selalu kehilangan arah. Ikatkan pada tali yang tersemat di samping kamera, dan tak perlu lagi meraba-raba saku dengan sia-sia. Agar tak hilang, cukup ikat di dekatnya—tangan lebih dulu memahaminya."},"ICON-0974":{"nm":"Charm Penutup Hot Shoe","de":"Ke dalam tempat hot shoe yang kosong di atas kamera, diselipkan diam-diam sebuah ornamen kecil. Satu charm tanpa fungsi apa pun itu entah bagaimana membuat perlengkapan yang berat dan kaku itu tampak akrab seperti barang milik sendiri. Sebuah upaya menumbuhkan kasih sayang pada sebuah alat."},"ICON-0975":{"nm":"Gesper Pengatur Tali","de":"Setiap kali tali tas menusuk bahu, gesper ini dikendurkan dan dikencangkan sedikit demi sedikit. Satu gerakan jari untuk memilih panjang yang pas dengan tubuh sendiri. Bahwa membawa beban pun pada akhirnya adalah merawat diri sendiri, gesper ini diam-diam memberitahunya."},"ICON-0976":{"nm":"Kotak Tumpukan Filter","de":"Sebuah rumah kecil tempat kepingan kaca yang membelah cahaya dibaringkan berlapis-lapis. Kabut dan cerah, senja dan malam. Seperti sebuah laci tempat cuaca dipilih dan disimpan lebih dulu, fotografer selalu membuka kotak ini lebih dulu sebelum berangkat."},"ICON-0977":{"nm":"Tutup Debu Blower","de":"Bola karet yang menyemburkan angin untuk mengusir debu, mulutnya sendiri sama lemahnya terhadap debu. Selagi beristirahat, tutupi dengan caps ini. Ada sesuatu yang lembut pada alat pembersih orang lain yang justru menutup mulutnya sendiri lebih dulu dengan tenang."},"ICON-0978":{"nm":"Penutup Tombol Rana","de":"Rana yang tertekan sendiri di dalam tas hingga memotret seratus lembar langit kosong, hampir semua orang pernah mengalaminya sekali. Penutup kecil di atas tombol ini mencegah kesia-siaan itu. Sebuah kunci sederhana, agar hanya momen yang benar-benar ingin disimpan yang tersimpan."},"ICON-0979":{"nm":"Stiker Pemilah Baterai","de":"Selalu jadi masalah ketika yang habis dan yang penuh tercampur dalam satu kantong. Stiker warna yang ditempel pada tiap baterai diam-diam merapikan kekacauan itu. Merah berarti kosong, hijau berarti dapat diandalkan. Lampu lalu lintas tanpa kata yang dinyalakan di lokasi pemotretan."},"ICON-0980":{"nm":"Sekat Tas Kamera","de":"Membagi ruang dalam tas agar lensa, bodi kamera, dan baterai cadangan tak saling berbenturan. Sebuah upaya membangun beberapa ruang kecil di dalam satu bawaan. Setiap tempat sudah punya pemiliknya, sehingga tak ada yang kehilangan posisinya bahkan saat terguncang."},"ICON-0981":{"nm":"Sarung Tangan Foto Berbantalan","de":"Pemotretan luar ruangan di musim dingin, hanya ujung jari yang menekan rana yang tak boleh kedinginan. Bantalan tebal di telapak, sarung tangan yang menyisakan rasa di ujung jari. Sebuah kompromi lembut di lapangan, menggenggam kehangatan dan ketepatan sekaligus dalam satu tangan."},"ICON-0982":{"nm":"Tabung Mata Pena Tablet","de":"Bahwa mata pena pun aus seperti isi pensil, hanya diketahui orang yang sudah lama memegang tablet. Tabung kecil tempat mata pena cadangan digulung bersama ini seperti dana darurat di ujung jari, mengisi lebih dulu garis yang tak boleh terputus."},"ICON-0983":{"nm":"Nampan Keycap Keyboard","de":"Pada hari mencabut satu per satu keycap untuk dicuci lalu dipasang kembali, nampan ini menjadi hamparan lumpur pantai kecil. Pemandangan konsonan dan vokal berbaring petak demi petak mengeringkan air. Ada ketelitian yang baru terlihat setelah membongkarnya sekali."},"ICON-0984":{"nm":"Paket Kaki Mouse","de":"Rahasia mouse yang meluncur mulus di atas meja terletak pada kaki-kaki kecil yang menempel di bawahnya. Satu paket untuk diganti saat aus. Jerih payah dari hal-hal yang diam-diam menopang kelicinan dari tempat yang tak terlihat."},"ICON-0985":{"nm":"Alas Karet Penyangga Laptop","de":"Mirip buku catatan, tetapi sebenarnya alas karet yang menopang laptop. Mengangkat layar sedikit ke tinggi mata untuk meluruskan leher yang membungkuk. Sebuah perhatian yang meluruskan postur, bagi orang yang lama menulis dan menatap layar."},"ICON-0986":{"nm":"Slider Penutup Webcam","de":"Mendorong lensa dengan jari untuk menutupinya, lalu mendorong lagi untuk membukanya. Keinginan untuk terlihat hanya ketika ingin dilihat. Dalam satu slider kecil ini bersemayam ketenangan besar bernama privasi. Bunyi tertutupnya entah kenapa terasa meyakinkan."},"ICON-0987":{"nm":"Label Pemilah USB","de":"Lima batang hitam yang mirip, sama sekali tak bisa dibedakan mana berisi apa. Menempelkan label kecil untuk memberinya nama, barulah ia menjadi bagian keluarga sendiri. Sebuah benda perlu nama untuk dipanggil agar mudah ditemukan pula."},"ICON-0988":{"nm":"Penjepit Sudut Alas Meja","de":"Ketika sudut alas meja terus menggulung ke atas, tulisan tangan pun ikut miring. Komponen kecil yang menekan lembut keempat sudut ini menjaga kedamaian datar di atas meja. Permukaan harus tenang agar ujung jari pun ikut tenang."},"ICON-0989":{"nm":"Klip Penyangga Hub","de":"Jepitan yang mendirikan hub, tempat berkumpulnya banyak kabel, miring di ujung meja. Pemandangan kabel-kabel yang berantakan berkumpul rapi menjadi satu titik. Sentuhan tangan yang mengikat sesuatu yang kusut menjadi satu untai hidup di sini juga."},"ICON-0990":{"nm":"Tutup Semprotan Pembersih Layar","de":"Sebuah tutup kecil untuk mulut semprotan yang menghapus bekas jari dari layar. Selalu ditutup rapat agar cairan tak bocor atau mengering. Untuk melihat dengan jernih, harus lebih dulu menjaga alat pembersihnya—urutan sederhana dari mengurus rumah."},"ICON-0991":{"nm":"Dompet Kartu Memori","de":"Rekaman panggung selama beberapa hari tertidur tenang dalam satu kartu sebesar kuku. Bila hilang, satu hari itu lenyap seutuhnya, maka dikumpulkan dengan sayang dalam dompet kecil. Sebuah rumah yang menyimpan kenangan yang paling kecil sekaligus paling besar."},"ICON-0992":{"nm":"Cincin Label Hard Drive Eksternal","de":"Lima hard drive eksternal hitam tertidur dalam laci dengan wajah yang sama persis. Menempelkan label dan menamainya 'musim panas itu', 'klip yang belum dirilis'. Sebuah kerja menyematkan indeks yang jelas pada ingatan yang samar."},"ICON-0993":{"nm":"Chip Penanda Cadangan","de":"Sudah selesai atau belum backup-nya, hati mengerut karena selisih setipis itu. Chip kecil yang diselipkan pelan di tempat yang sudah selesai ini memberi tahu 'sampai sini sudah aman'. Ketenangan datang dari meninggalkan sebuah tanda."},"ICON-0994":{"nm":"Token Memo Awan","de":"Sebuah token yang mengapungkan satu baris memo ke gudang penyimpanan entah di mana di langit. Sebuah sihir kecil, di mana pun dinyalakan, tulisan itu keluar menyambut. Langit malam tempat menerbangkan layang-layang sambil menulis harapan kini seolah turun pelan ke atas telapak tangan."},"ICON-0995":{"nm":"Set Tutup Pelindung USB","de":"Dibiarkan berguling di dalam tas dengan konektor terbuka, kontaknya pasti akan aus. Tutup tiap ujungnya dengan topi kecil dan simpan sebagai satu set. Sebuah tindakan menidurkan waktu yang tak terpakai dengan lembut. Persiapan paling tenang untuk sambungan berikutnya."},"ICON-0996":{"nm":"Ikat Kotak Data","de":"Sebuah ikat yang membungkus dan mengencangkan perangkat berisi data berharga. Lilit sekali dan ikat erat agar tak berbenturan dalam tas yang terguncang. Sentuhan tangan yang dulu menyimpul bungkusan dengan penuh perhatian, kini tetap hidup pula dalam dunia digital."},"ICON-0997":{"nm":"Tag Pengelompok Berkas","de":"Ketika ratusan berkas menumpuk tanpa nama, mencari pun menjadi tersesat. Momen menempelkan tag berwarna-warni untuk membuka cabang, sebuah jalan terbentuk di antara tumpukan yang berantakan. Merapikan, pada akhirnya, adalah pekerjaan membuka jalan."},"ICON-0998":{"nm":"Kartu Petunjuk Kata Sandi","de":"Menuliskan kata sandi secara utuh itu berbahaya, sama sekali tak menuliskannya membuat lupa. Maka disisakan hanya petunjuk yang hanya diri sendiri mengerti. Seperti 'kota panggung pertama itu'. Sebuah cara mengingat yang cerdas dan lembut, menuliskan jalannya, bukan jawabannya."},"ICON-0999":{"nm":"Stiker Tanggal Penyimpanan","de":"Tanpa mencatat hari disimpan, penyimpanan pun segera menjadi lupa. Stiker tanggal yang ditempel pada tiap kotak mengukir jelas 'sejak kapan'. Hati gudang lama yang mencatat hari pasta kedelai dibuat, kini berlanjut di atas selembar kertas kecil ini."},"ICON-1000":{"nm":"Tutup Lampu Ring Mini","de":"Sebuah tutup yang menutupi lubang cahaya dari lampu kecil yang memancarkan sinar bulat. Menidurkan cahaya sejenak agar lensa tak tergores di dalam tas. Menjaga kegelapan dengan baik sebelum dinyalakan pun adalah salah satu cara menyayangi terang."},"ICON-1001":{"nm":"Sekrup Pengencang Dudukan","de":"Satu putaran lagi saja. Celah yang longgar lenyap, dan rasa lega yang berat mengendap di bawah telapak tangan. Di balik panggung yang tak bergoyang, selalu ada satu putaran pergelangan tangan seseorang yang cekatan; yang ditopang sekrup kecil ini adalah kekokohan yang tak terlihat."},"ICON-1002":{"nm":"Chip Penanda Siaran","de":"Begitu lampu merah menyala, langkah kaki di lorong diam-diam berjinjit. Di hadapan kata \"Sedang Siaran\", semua orang menahan napas. Bahwa bahkan keheningan di balik pintu adalah hati yang tertuju pada seseorang, itulah yang diam-diam diberitahukan chip kecil ini."},"ICON-1003":{"nm":"Buku Memo Obrolan","de":"Menangkap dengan ujung jari dukungan yang akan sekilas lewat di layar. Waktu ketika setiap kata yang akan mengalir pergi justru tinggal, rapi dan jelas, di atas kertas. Mencatat adalah tempat singgahnya kelembutan hati yang ingin sampai, sekalipun terlambat."},"ICON-1004":{"nm":"Penutup Keyboard Senyap","de":"Pukul dua dini hari, suara tuts yang ditekan lenyap seperti kebohongan. Selembar lapisan tipis, agar napas teman sekamar yang tidur nyenyak tak terusik. Perhatian yang paling tenang selalu dimulai di tempat yang tanpa suara."},"ICON-1005":{"nm":"Klip Lengan Mikrofon","de":"Antara bibir dan mikrofon, jarak yang pas agar lagu tak bergetar. Klip kecil ini menjaga janji itu tetap terikat. Di balik panggung, selalu ada tangan seperti ini yang lebih dulu hadir untuk menopang segalanya tetap stabil."},"ICON-1006":{"nm":"Jepitan Kain Latar","de":"Sekencang apa pun angin bertiup, kain latar tak bergeming. Sebab satu rahang kecil yang menggigit erat di sudutnya menahan seluruh adegan tetap di tempatnya. Di balik pemandangan yang tak goyah, selalu ada seseorang di tempat tersembunyi yang mengatupkan gigi kuat-kuat."},"ICON-1007":{"nm":"Label Stream Deck","de":"Di atas puluhan tombol, label nama kecil membuat tangan tak tersesat arah. Satu baris label menghapus lebih dulu satu kesalahan siaran langsung sebelum terjadi. Ketenangan berasal dari huruf yang dituliskan sebelum getaran gugup dimulai."},"ICON-1008":{"nm":"Tombol Stempel Waktu","de":"Tekan dalam-dalam, dan sebuah bendera kecil tertancap di atas waktu yang mengalir. Tindakan membubuhkan cap pada saat ini yang tak akan pernah kembali. Ketika ditengok jauh kemudian, tanda itu telah menjadi pintu menuju kenangan."},"ICON-1009":{"nm":"Gantungan Kunci Pembaca Tag","de":"Dekatkan saja, lalu bip, informasi pun terbangun. Teman kecil yang bergantung di gantungan kunci, bergemerincing di dalam saku. Hari yang biasa berlangsung dengan aman lewat bunyi sinyal sekecil ini."},"ICON-1010":{"nm":"Label Colokan Pintar","de":"Berikan nama pada setiap stopkontak, dan kau tak lagi bingung kabel mana untuk apa. Hati yang bahkan memberi nama pada listrik yang tak terlihat. Kerapian adalah wajah lain yang sesekali dipinjam kelembutan hati untuk dikenakan."},"ICON-1011":{"nm":"Dudukan Sensor Suhu-Kelembapan","de":"Penjaga sebesar telapak tangan yang tanpa kata mengawasi suhu dan kelembapan ruangan. Kenyamanan tak pernah membuka mulut, tapi dudukan ini diam-diam menjaga kondisimu setiap saat. Kesejahteraan dijaga sesenyap ini."},"ICON-1012":{"nm":"Tutup Sensor Pintu","de":"Mata kecil yang tak melewatkan sekejap ketika pintu perlahan terbuka. Ia menyampaikan tanpa suara tanda bahwa seseorang telah pulang. Yang menjaga rumah kosong selalu, seperti ini, benda-benda yang tak berkata-kata."},"ICON-1013":{"nm":"Tempat Remote","de":"Remote-remote yang berguling ke sana kemari akhirnya menemukan tempatnya masing-masing. Satu tempat kecil yang lembut menahan sesuatu yang hampir hilang, tangan yang mengukir lebih dulu janji untuk bertemu lagi."},"ICON-1014":{"nm":"Token Aplikasi Tidur","de":"Setiap malam kau tidur nyenyak, satu keping bulat pahala menggelinding dan menumpuk. Tidur pun, kata aplikasi ini dengan lembut, terkumpul sedikit demi sedikit layaknya latihan. Hadiah terkecil di dunia, diberikan pada dirimu yang telah beristirahat baik."},"ICON-1015":{"nm":"Alas Kubus Pengatur Waktu","de":"Selagi tiga menit mengalir dengan tertib, kubus menghitung waktunya tanpa goyah. Satu tempat sebesar telapak tangan yang lembut menopangnya dari bawah. Bahkan menunggu pun butuh lantai untuk dipijak dengan tenang."},"ICON-1016":{"nm":"Penutup Lampu Notifikasi","de":"Agar tak terlalu terang, ia lembut membungkus cahaya dengan satu lapis. Biarlah notifikasi mendesak, tapi mata tetap nyaman. Perhatian adalah hati yang diam-diam memperhitungkan bahkan kekuatan cahaya."},"ICON-1017":{"nm":"Kartu Ganti Baterai","de":"Ketika kartu ini muncul, artinya sudah waktunya mengganti jantung kecil di dalam perangkat. Bisikan lembut untuk mengurusnya sebelum ia berhenti. Rahasia kebersamaan yang panjang selalu terletak pada kewaspadaan yang selangkah lebih dulu."},"ICON-1018":{"nm":"Set Tutup Joystick","de":"Topi-topi kecil yang dipasangkan agar ibu jari tak tergelincir. Kepekaan ujung jari pun menjadi jauh lebih jelas. Satu tutup kecil ini bahkan bisa menentukan menang kalahnya satu ronde yang dimainkan dengan tangan berkeringat."},"ICON-1019":{"nm":"Penutup Docking Switch","de":"Ia lembut menutupi tempat istirahat konsol dari debu. Sebab bahkan perangkat yang sejenak tertidur butuh selimut satu lembar. Kasih sayang justru tampak lebih jelas ketika sesuatu sedang tidak dipakai."},"ICON-1020":{"nm":"Pouch Konsol Genggam","de":"Saat bepergian, wajib masuk ke dalam ini. Kantong yang membungkus konsol genggam dengan pelukan yang empuk. Agar tetap aman sekalipun terbentur ke sana kemari di dalam tas, yang berharga memang sebaiknya dibungkus sekali lagi."},"ICON-1021":{"nm":"Set Stiker Tombol","de":"Cukup letakkan satu gambar kecil di atas tombol yang polos, dan seketika itu menjadi sepenuhnya milikmu. Tindakan meninggalkan tanda sendiri di atas perangkat yang sama seperti milik orang lain. Keunikan selalu mekar diam-diam dari tempat sepele seperti ini."},"ICON-1022":{"nm":"Kotak Kaset Game","de":"Satu sesi permainan yang membuatmu larut semalaman tidur nyenyak di dalam kotak kecil ini. Buka kembali tutupnya, dan malam itu terbangun utuh kembali. Kenangan, ternyata, seringkali tersimpan dalam kotak yang tak lebih besar dari telapak tangan."},"ICON-1023":{"nm":"Alas Kipas Pendingin","de":"Selagi angin mendinginkan panas, ada tempat yang menopang perangkat dengan sedikit kemiringan. Ia memberi ruang bagi tubuh yang memanas untuk menghela napas sejenak. Untuk berlari jauh, kau juga harus tahu cara berhenti sebentar untuk mendinginkan diri."},"ICON-1024":{"nm":"Pin Tali Pergelangan","de":"Lilitkan di pergelangan tangan dan kancingkan pinnya, maka segigih apa pun gerakan, kontroler tak akan meninggalkan sisimu. Tali yang tampak merepotkan ini sebenarnya adalah jaminan rasa aman yang membiarkanmu bermain sepuas hati."},"ICON-1025":{"nm":"Tutup Grip Analog","de":"Mengenakan baju baru pada grip yang sudah licin mengilap karena lama digenggam. Rasa yang sudah akrab di tangan dibiarkan tetap, hanya permukaannya saja yang seperti baru. Sebuah momen ketika keakraban dan sedikit debaran baru berdampingan dalam satu genggaman."},"ICON-1026":{"nm":"Label Slot Simpan","de":"Di setiap slot simpan, dituliskan dengan rapi petualangan siapa itu. Satu baris label diam-diam menjaga perjalanan beberapa hari terakhir. Kenangan berharga sebaiknya diberi nama agar tak tertimpa yang baru."},"ICON-1027":{"nm":"Pouch Alat Rekam","de":"Mesin yang menyimpan suara menjadi lebih berharga karena apa yang ada di dalamnya. Kau membawanya dengan rapi terbungkus dalam kantong empuk yang melindunginya dari benturan. Boleh jadi suara seseorang sedang tertidur di dalamnya, maka dijaga lebih hati-hati lagi."},"ICON-1028":{"nm":"Tudung Peredam Angin","de":"Menyapu bersih suara angin, menyisakan hanya suara. Tudung berbulu lembut yang dipasangkan pelan-pelan pada mikrofon untuk rekaman luar ruangan. Saringan kecil yang memilah hanya ketulusan dari tengah kebisingan yang semrawut."},"ICON-1029":{"nm":"Label Memo Suara","de":"Yang ini lirik yang baru terlintas, yang ini melodi yang digumamkan. Kau menempelkan label nama berwarna-warni pada setiap memo suara. Serpihan-serpihan inspirasi yang berserakan ke mana-mana akhirnya menemukan tempatnya dan berbaris rapi."},"ICON-1030":{"nm":"Chip Tombol Sampling","de":"Tekan dalam-dalam, dan sepotong suara yang tersimpan sebelumnya meloncat keluar. Tetesan hujan, tepuk tangan, tawa seseorang, serpihan-serpihan dunia terbangun di ujung jari. Musik adalah paduan suara lembut dari chip-chip kecil seperti ini."},"ICON-1031":{"nm":"Amplop Kumpulan Suara","de":"Suara-suara yang kau pungut tanpa sengaja saat berjalan, lembut kau simpan dalam amplop ini. Tekstur angin, bahkan kesunyian gang di fajar hari. Bahan-bahan yang suatu hari akan menjadi lagu selalu berkumpul sesederhana ini."},"ICON-1032":{"nm":"Kaki Tripod Mini","de":"Tiga kaki membentangkan panggung kecil di atas meja. Alih-alih tangan yang bergetar, mereka berdiri kokoh menahan adegan tetap di tempat. Satu bidikan yang tajam lahir, pada akhirnya, dari tiga kaki yang diam berdiri tanpa goyah."},"ICON-1033":{"nm":"Tag Berkas Rekaman","de":"Pada ratusan berkas rekaman, kau menempelkan label singkat satu per satu. Agar sekali lihat kau tahu bait pertama yang mengalir keluar pada hari yang mana. Satu penanda kecil yang membantumu menemukan kembali suara-suara yang tercecer."},"ICON-1034":{"nm":"Pita Stiker Gelombang Suara","de":"Pita bermotif gelombang yang mencetak persis bentuk suara. Lilitkan pada buku catatan atau kotak, dan seolah musik tampak nyata di depan mata. Sebuah tipuan lembut yang mengubah yang terdengar menjadi terlihat."},"ICON-1035":{"nm":"Pin Gantungan Headset","de":"Ketika latihan usai, ia lembut menyiapkan tempat istirahat bagi headset yang lelah. Satu kait kecil yang tertancap di sudut meja. Meja yang rapi adalah tempat untuk menggantungkan semangat esok hari lebih dulu."},"ICON-1036":{"nm":"Pita Kotak Hadiah Mini","de":"Lilitan terakhir yang melingkari pinggang kotak hadiah. Dengan satu pita ini, hati akhirnya menjadi lengkap. Ketulusan sering tersampaikan lebih dulu dari tangan yang merapikan luarnya, ketimbang dari isinya."},"ICON-1037":{"nm":"Tutup Ujung Pita","de":"Membungkus lembut ujung pita agar tak terurai, menyempurnakannya. Satu detail yang nyaris tak kentara diam-diam mengubah kesan pertama sebuah hadiah. Bila akhirannya indah, hati pun sampai dengan indah."},"ICON-1038":{"nm":"Lilin Segel","de":"Meneteskan satu tetes panas untuk menyegel amplop. Seperti surat lama, satu janji yang berat untuk tak dibuka sembarangan. Formalitas kadang, seperti ini, menyimpan bobot yang hangat."},"ICON-1039":{"nm":"Penyangga Kartu Terima Kasih","de":"Ia menopang tegak kartu berisi ucapan terima kasih agar tak kusut. Agar hati berdiri lurus saat disampaikan. Rasa syukur bertahan lebih lama di hati ketika bahkan bentuknya pun rapi."},"ICON-1040":{"nm":"Kertas Pengisi Bentuk Bintang","de":"Kertas yang dipotong bentuk bintang mengisi empuk celah-celah dalam kotak. Kapas dari hati yang berharap tak ada yang terluka sekalipun terguncang. Dalam gelapnya bungkusan pun, seolah ada satu bintang kecil yang mengambang."},"ICON-1041":{"nm":"Tag Daftar Hadiah","de":"Di depan kolom nama penerima, pena berhenti cukup lama. Wajah yang terlintas selagi menuliskan tiga huruf nama itu, musim-musim yang pernah dilalui bersama. Begitu diikatkan, kertas kecil ini menjadi rahasia yang tak bisa dibaca siapa pun sampai diurai."},"ICON-1042":{"nm":"Stempel Cincin Ucapan Selamat","de":"Tekan dalam-dalam, dan sebuah ucapan selamat bulat tercetak jelas. Selagi menunggu sesaat tinta mengering, hati yang membayangkan kepada siapa akan diberikan adalah yang paling hangat. Kalau ada cacatnya, itu adalah keinginan untuk menekannya sekali lagi."},"ICON-1043":{"nm":"Gulungan Tali Hadiah","de":"Digulung dengan penuh perhatian, lalu terurai riang di ujung jari seseorang yang berdebar. Dalam sekejap penggulungan dan penguraian itu, satu hati yang terikat pada benang akhirnya menjadi hadiah."},"ICON-1044":{"nm":"Liontin Simpul (Bukan Bunga)","de":"Bukan tiruan bunga, melainkan bentuk ketika satu untai benang memeluk tubuhnya sendiri berkali-kali lalu mekar dengan sendirinya. Kesabaran ujung jari yang memilih-milih simpul semalaman tersisa sebagai satu kuncup kecil seperti ini."},"ICON-1045":{"nm":"Kantong Koin Keberuntungan","de":"Hati yang diam-diam menyelipkan beberapa keping koin ke saku seseorang yang berangkat menempuh perjalanan jauh. Bukan bobot yang diisi, melainkan kelembutan hati. Bunyi gemerincing di setiap langkah menggantikan ucapan agar perjalanan berjalan lancar."},"ICON-1046":{"nm":"Liontin Kapsul Permohonan","de":"Di dalam cangkang bulat, satu permohonan yang terlipat tertidur lelap. Kata bahwa membukanya akan membuat itu terkabul adalah bohong, tapi bahwa menyimpannya tanpa dibuka membuat harapan itu hidup selamanya, itulah yang benar."},"ICON-1047":{"nm":"Tali Simpul Pelindung","de":"Tali yang dianyam kokoh dari benang lima warna, memutar balik energi buruk ke belakangmu. Seperti sentuhan tangan nenek yang mengikat simpul di pergelangan tangan saat kecil dulu, di setiap tempat yang terikat tersemat rapi doa seseorang."},"ICON-1048":{"nm":"Kotak Bangau Kertas Kecil","de":"Rumah kecil yang menjaga satu-satunya bangau kertas agar tak terluka, dari seribu yang harus dilipat untuk menjadi permohonan. Sebab jika satu sayap saja kusut, ketulusan yang dicurahkan malam itu pun perlahan terurai."},"ICON-1049":{"nm":"Pouch Batu Gemerlap","de":"Serpihan-serpihan cahaya kecil yang jatuh dari kostum panggung, sebuah tempat untuk menyapu apa yang tak sanggup kau buang. Bahkan kerlip yang dulu menempel dan mengikutimu selama seminggu, di sini tertidur setenang di atas telapak tanganmu."},"ICON-1050":{"nm":"Chip Stempel Pertanda Baik","de":"Kepingan kecil yang diam-diam kau tambahkan saat memilih hari baik. Bukan di ambang pintu peramal, melainkan di atas mejamu sendiri, sepotong takhayul manis yang lembut kau stempelkan, berharap hanya hal baik terjadi hari ini."},"ICON-1051":{"nm":"Kartu Gelang Doa","de":"Selembar kertas yang dicetak berbentuk gelang, menyimpan doa diam seseorang. Sekalipun tak bisa dikaitkan di pergelangan tangan, selipkan dalam-dalam ke dompet, dan hati itu tetap terikat di sisimu, berjalan bersamamu selalu."},"ICON-1052":{"nm":"Toples Garam Depan Pintu","de":"Garam kasar dituang ke toples kecil, diletakkan tenang di depan pintu. Perhitungan lama yang mengusir energi buruk dan hanya menyambut tamu yang baik. Setiap butir garam adalah penjaga kecil yang mengawasi rumah kita."},"ICON-1053":{"nm":"Tag Penutup Nomor Keberuntungan","de":"Tepat sebelum digosok, semua orang sejenak menjadi pemenang. Tag ini, yang lembut menutupi angka keberuntungan, menjaga detik terakhir ketika harapan mengembang paling tinggi. Sekalipun ujung jari yang menggosok gemetar, ia pura-pura tak tahu dan memejamkan mata."},"ICON-1054":{"nm":"Tutup Penyimpan Lilin Ulang Tahun","de":"Hati yang rapi menjaga bahkan lilin yang pernah dinyalakan sekali agar tetap terawat sampai ulang tahun berikutnya. Jika permohonan tahun lalu belum juga terkabul, tahun ini kau tinggal melanjutkan dari situ dan berharap lagi, sebuah perhitungan yang lembut."},"ICON-1055":{"nm":"Cincin Hitung Mundur Hari Spesial","de":"Benda nakal yang menyelipkan D-day ke jarimu. Setiap kali angka hari yang tersisa berputar mundur satu langkah, hatimu pun tertarik maju sejauh itu. Ia bersikeras sendiri, bahwa ia akan bersinar saat mencapai angka nol."},"ICON-1056":{"nm":"Tali Topi Pesta","de":"Tali tipis yang menahan topi kerucut tetap pas di kepala. Sang bintang acara sendiri segera mengeluh sesak dan segera melepasnya, tapi dalam foto, satu bidikan itu membuatnya tetap terpasang selamanya. Tugas itu sudah cukup."},"ICON-1057":{"nm":"Tusuk Kue Kecil","de":"Penanda kecil yang tertancap di kue sebesar dua ruas jari. Bahkan di atas rasa manis yang lenyap dalam satu suapan, ucapan selamat berdiri tegak. Sekecil apa pun, ulang tahun tetaplah ulang tahun, dan bintang hari ini adalah kau."},"ICON-1058":{"nm":"Label Petasan Kertas","de":"Petasan kertas yang tak berbunyi dentum tapi tampak paling meriah. Begitu ditempel di amplop, kiriman pos yang biasa berubah menjadi surat dari rumah yang sedang berpesta. Banyak orang membiarkannya saja, sayang untuk dilepas."},"ICON-1059":{"nm":"Jepitan Gantungan Foto","de":"Takut kehilangan kenangan yang tergantung di tali, aku selalu menutup mulut rapat-rapat. Selama satu lembar foto tergigit erat, angin sekalipun yang masuk dari celah jendela tak akan menjatuhkan hari-hari itu."},"ICON-1060":{"nm":"Patch Balon Tanggal","de":"Patch berbentuk balon dengan angka tertulis di atasnya. Tempelkan pada baju, dan seluruh lingkungan tahu hari spesial keberapa ini. Lepas, dan bekasnya tertinggal, tapi bahkan bekas yang samar itu menjadi satu kenang-kenangan lagi."},"ICON-1061":{"nm":"Penanda Tukar Hadiah","de":"Penanda jahil yang lembut mengaburkan tangan mana yang menerima dan mana yang memberi. Aturan kecil nan hangat di meja tukar-menukar hadiah, meminta kau mengingat bukan siapa yang memberi, melainkan apa yang saling dipertukarkan."},"ICON-1062":{"nm":"Nomor Meja Peringatan","de":"Satu angka kecil yang berdiri di setiap meja perjamuan. Menentukan lebih dulu siapa duduk di mana agar tak ada yang canggung, ini menyimpan kebijaksanaan hangat dari orang-orang yang sudah berkali-kali menyelenggarakan pesta."},"ICON-1063":{"nm":"Kantong Hadiah Gantungan Pintu","de":"Cara menyampaikan hati tanpa membunyikan bel pintu. Gantungkan diam-diam di gagang pintu lalu menghilang seperti melarikan diri, dan wajah terkejut orang yang menemukannya menjadi hadiah terbesar yang kembali kepada si pemberi."},"ICON-1064":{"nm":"Label Kiriman Rahasia","de":"Tak ada yang tertulis di permukaannya. Menyembunyikan siapa pengirimnya sampai akhir adalah kebanggaan kecil label ini. Semakin lama penerima menengok bingung sambil tersenyum, semakin sempurna misi rahasia itu terlaksana."},"ICON-1065":{"nm":"Chip Memo Bel Pintu","de":"Secarik kertas kecil yang ditinggalkan sebagai pengganti ketika tak ada keberanian untuk mengetuk pintu. Satu baris singkat seperti \"aku mampir sebentar\" bertahan lebih lama daripada bunyi bel pintu. Sebab tulisan tangan yang berantakan punya ekspresinya sendiri."},"ICON-1066":{"nm":"Tutup Pengaman Cutter","de":"Ketika mata pisau cutter tanpa sengaja mengincar jari, seorang pahlawan kecil diam-diam melangkah maju. Ia menjaga ujung jari yang terburu-buru karena debaran menyambut barang baru, sampai potongan terakhir dengan selamat."},"ICON-1067":{"nm":"Potongan Bubble Wrap","de":"Aku lahir untuk ditekan. Dengan bunyi \"pop\" itu, entah bagaimana ketegangan hari perlahan mengendur. Kadang ada hari ketika aku dicintai lebih lama daripada barang yang dulu kubungkus."},"ICON-1068":{"nm":"Pin Waktu Kedatangan","de":"Pin yang menandai tepat pukul berapa kiriman tiba. Bahkan penantian yang samar menjadi lebih mudah ditanggung begitu punya satu titik koordinat. Berapa kali kau akan mengintip pintu depan sampai jam itu, sepenuhnya urusanmu sendiri."},"ICON-1069":{"nm":"Gantungan Kunci Loker Paket","de":"Teman kecil bagi orang yang terus lupa kode loker paket. Ia bergantung bergoyang di gantungan kunci, dan bakat diam-diamnya adalah memancing ucapan \"ah, benar\" pada saat yang genting."},"ICON-1070":{"nm":"Tag Keranjang Teras","de":"Label nama yang tertempel di keranjang di sudut teras. Di sana tertulis janji tanpa kata, \"tinggalkan di sini.\" Sekalipun kosong, tempat yang menanti hati seseorang tak pernah kesepian."},"ICON-1071":{"nm":"Stiker Penutup Alamat","de":"Di atas kotak yang akan dibuang, nama dibiarkan, hanya alamat yang dihapus pelan. Yang boleh diketahui semua orang cukup sampai nama, tempat tinggal tetap jadi rahasiamu sendiri. Begitu satu lapis ini dikelupas dan ditempel, muncul rasa lega kecil."},"ICON-1072":{"nm":"Label Toples Camilan","de":"Label yang memberi tahu sekali lihat apa isi di dalam toples. Tapi jebakannya, menuliskan \"camilan\" entah bagaimana membuatmu merasa tenang bahkan tanpa membuka tutupnya. Label memang tak bertanggung jawab atas nafsu makanmu."},"ICON-1073":{"nm":"Liontin Kalung Kecil","de":"Satu bulir kecil yang diam-diam berbagi kehangatan tubuh di balik baju. Selalu menempel di tempat yang tak terlihat mata siapa pun, justru karena itu ia lebih menyentuh. Sahabat terdekat yang berjalan bersama di dada."},"ICON-1074":{"nm":"Matras Stempel Jejak Kaki","de":"Tekan pada telapak kaki, dan sederet jejak kecil tertinggal berbaris. Buku harian jalan-jalan sehari-hari yang mencatat rapi di atas kertas, siapa berjalan ke mana. Langkah pertama yang berlumur tinta selalu yang paling jelas."},"ICON-1075":{"nm":"Tutup Sikat Bulu","de":"Tutup kecil yang menangani bersih bulu yang tersangkut di sikat. Di musim pergantian bulu, ketika satu sapuan mengumpulkan segenggam, tanpa tutup ini seisi rumah akan berubah menjadi hamparan salju berbulu. Petugas kebersihan rajin yang bekerja tanpa jejak."},"ICON-1076":{"nm":"Kotak Kantong Jalan-Jalan","de":"Rumah kecil yang rapi membawa kantong-kantong yang perlu dibawa saat jalan-jalan. Kotak ini setiap hari diam-diam membuktikan bahwa hanya yang mempersiapkan lebih dulu bisa berjalan santai. Satu lembar yang akan merepotkan jika lupa dibawa."},"ICON-1077":{"nm":"Tag Penutup Nama","de":"Tag yang diam-diam menyembunyikan nama asli dan hanya menyisakan nama panggilan. Di dunia ini ada juga kelembutan hati yang tak ingin ditunjukkan pada sembarang orang. Panggilan sayang yang hanya diketahui yang tahu, tersembunyi lembut di sini."},"ICON-1078":{"nm":"Alas Mangkuk Air","de":"Terhampar di bawah mangkuk air, aku selalu basah. Menampung tetesan air yang memercik ke segala arah, aku menjaga lantai kayu tetap kering. Tak ada yang memujiku, tapi aku pun tak pernah mengeluh."},"ICON-1079":{"nm":"Benang Jahit Mainan","de":"Boneka yang jahitannya lepas bukan untuk dibuang, melainkan dijahit kembali. Di setiap tempat yang ditambal jarum demi jarum, waktu yang dihabiskan bersama si kecil itu menguat kembali. Menjahit, pada akhirnya, adalah menunda perpisahan dengan lembut."},"ICON-1080":{"nm":"Kalung Foto Kenangan","de":"Hati yang mengalungkan di leher satu bidikan senyum paling cerah. Hari itu dalam foto, alih-alih diawetkan diam, bergoyang bersama setiap langkah dan berlanjut sampai hari ini. Momen indah itu tak pernah berhenti."},"ICON-1081":{"nm":"Chip Warna Suasana Hati","de":"Kalau hati juga punya warna, warna apa dirimu hari ini? Begitu memilih satu chip dan meletakkannya di meja, perasaan yang tak sempat terucap kata-kata diam-diam menyebar. Warna senja atau cahaya fajar, keduanya baik saja, sebuah cermin kecil yang lembut memantulkan dirimu hari itu."},"ICON-1082":{"nm":"Kelereng Catatan Hari Ini","de":"Ketika hari beranjak senja, hari ini mengumpul bulat di dalam kelereng. Hal-hal yang kau lakukan baik dan yang kau lakukan dengan canggung semuanya digulung dan digelindingkan bersama. Letakkan di telapak tangan, dan dirimu di masa lalu terasa sedikit hangat, menepuk punggungmu, mengatakan kau telah menjalani hari ini dengan baik."},"ICON-1083":{"nm":"Toples Kertas Pujian","de":"Kata-kata baik terlalu mudah tercerai-berai, jadi kau melipatnya satu per satu ke dalam toples ini. Ketika pujian mengendap seperti wangi-wangian, kau membuka tutupnya di malam-malam ketika hati terasa hampa. Ambil kembali sepotong kelembutan yang diberikan seseorang dan baca lagi, kehangatan hari itu pun hidup kembali."},"ICON-1084":{"nm":"Tali Pita Rekonsiliasi","de":"Hati yang kusut mirip simpul; mengurainya pun butuh ketulusan. Ketika dua orang memegang kedua ujung tali dan menariknya perlahan, tanpa sadar terbentuk satu pita yang indah. Berdamai bukanlah memutuskan, melainkan mengikat kembali, begitu tali ini lembut memberi tahu."},"ICON-1085":{"nm":"Token Rasa Syukur","de":"Pada hari ketika kata terima kasih sulit keluar dari mulut, kau diam-diam menyerahkan satu token sebagai gantinya. Tangan yang menerimanya membaca seluruh hatimu dari bobot kecil itu. Ketulusan yang tiba lebih dulu daripada kata-kata, kasih sayang terbawa dalam satu butir bulat."},"ICON-1086":{"nm":"Penanda Waktu Istirahat","de":"Bahkan ruang latihan yang telah berlari sepanjang hari butuh satu ketukan untuk menghela napas. Gantungkan penanda ini di pintu, dan waktu sejenak melambat. Bahwa lagu butuh tanda istirahat agar bisa bernapas, siapa pun yang pernah menjalani hari yang terengah-engah tahu itu."},"ICON-1087":{"nm":"Laci Perasaan Rahasia","de":"Ada hari-hari ketika kau tak bisa membuka semua isi hatimu. Pada hari seperti itu, kau diam-diam memasukkan kesedihan dan debaran ke dalam satu laci kecil di hati dan menutupnya. Tak apa dibiarkan begitu untuk sekarang, suatu hari nanti akan tiba waktunya untuk membukanya perlahan dan merapikan semuanya."},"ICON-1088":{"nm":"Gulungan Stiker Senyum","de":"Kelupas satu kotak, dan satu tanda senyum menempel di ujung jari. Keceriaan kecil yang lembut ditempel di sudut buku catatan, di loker teman. Ketika matahari kecil terbit di atas kertas, hari orang yang menemukannya menjadi sedikit lebih cerah."},"ICON-1089":{"nm":"Liontin Lonceng Kabar","de":"Hasrat untuk sampai kepadamu yang jauh berkumpul menjadi satu lonceng kecil. Goyangkan, dan bunyi yang jernih menyampaikan kabar sebagai penggantimu. Pada hari ketika tak sanggup bertanya \"apa kabar\", dering kecil ini menunggangi angin dan sampai lebih dulu."},"ICON-1090":{"nm":"Pin Penutup Hujan Musim Semi","de":"Di hari hujan musim semi turun, yang paling kau sayangi justru yang paling mudah basah. Kancingkan sampulnya dengan pin ini, dan tetesan hujan mengalir menyamping menjauh. Hati yang memeluk satu buku berharga dekat di dada, satu pin kecil ini menggantikan kelembutan itu."},"ICON-1091":{"nm":"Stiker Pendingin Musim Panas","de":"Satu tempelan cepat di punggung tangan yang lelah oleh panas tengah musim panas. Sensasi sejuk menyebar seperti mentol dan keringat pun sedikit mereda. Kesejukan berbaring di beranda kayu sambil mengipas-ngipas diri itu, ditiru dengan setia oleh selembar kertas sebesar telapak tangan."},"ICON-1092":{"nm":"Potongan Kain Kotak-Kotak Musim Gugur","de":"Sepotong kain bermotif kotak-kotak yang menyerupai ladang musim gugur. Ia adalah jejak seseorang yang dengan penuh perhatian menambal tempat yang usang. Hati yang menjahit alih-alih membuang, kain-kain kecil berkumpul menghidupkan kembali yang lusuh dengan kehangatan."},"ICON-1093":{"nm":"Klip Sarung Tangan Musim Dingin","de":"Sarung tangan musim dingin entah mengapa terus kabur satu per satu. Sambungkan keduanya dengan klip ini, dan tangan yang kedinginan tak akan tersesat. Hasrat untuk tak kehilangan bersemayam dalam sepotong logam kecil, menjaga sepasang itu tetap berdampingan."},"ICON-1094":{"nm":"Tag Anti-Air Musim Hujan","de":"Di musim hujan, bahkan label nama pun luntur oleh air hujan. Tag berlapis anti-air ini menjaga tulisannya bahkan di tengah hujan deras. Satu baris yang tetap jelas terbaca setelah hujan reda, agar milik siapa ini tak pernah terlupakan sampai akhir."},"ICON-1095":{"nm":"Toples Penyimpan Salju Pertama","de":"Salju pertama lenyap begitu tersentuh tangan, jadi setidaknya debaran itu kau simpan dalam toples. Yang terkurung di dalam kaca bukanlah salju, melainkan hati yang berdebar hari itu. Goyangkan, dan satu musim dingin utuh kembali berhamburan, membawamu kembali ke pagi itu."},"ICON-1096":{"nm":"Pita Amplop Hari Raya","de":"Satu pita merah yang melingkari amplop hari raya. Semua orang tahu, kasih sayang di tangan yang memberi jauh lebih besar daripada apa yang ada di dalamnya. Hati yang membungkus ucapan sehat selalu bersama berkah, terikat rapi di dalam pita tipis ini."},"ICON-1097":{"nm":"Karet Perekat Peralatan Piknik","de":"Bentangkan tikar dan buka kotak bekal, angin terus mengangkat tutupnya. Kencangkan peralatan makan dengan pita ini, dan piknik pun tak jadi berantakan. Hati yang ingin menjaga satu bekal yang dibawa sampai akhir, tersimpan dalam satu pita kecil."},"ICON-1098":{"nm":"Kartu Sampel Aroma Musiman","de":"Agar bisa mengenali musim tanpa perlu membukanya, aroma musim itu disimpan dalam selembar kartu. Bunga di musim semi, aroma daun kering di musim gugur. Begitu tercium di ujung hidung, seluruh musim itu kembali terlintas utuh, \"inilah udara bulan April.\""},"ICON-1099":{"nm":"Papan Jepit Label Harga","de":"Masalah lapak yang label harganya terus terbang tertiup angin, diselesaikan oleh satu papan jepit ini. Ia menggigit erat angka-angka dan menyodorkannya lurus di hadapan pembeli. Sapaan pertama dalam berdagang dimulai dari satu baris jujur yang tak pernah berantakan."},"ICON-1100":{"nm":"Papan Balik Buka Toko","de":"Balikkan papan ini dan gantungkan di depan pintu, maka toko akhirnya terbangun. Dari \"sedang bersiap\" menjadi \"selamat datang.\" Sinyal kecil yang mengumumkan dimulainya hari, tempat yang paling dulu disentuh tangan pemilik toko setiap pagi."},"ICON-1101":{"nm":"Kartu Stempel Loyalitas","de":"Jika sepuluh kotak terisi penuh, entah kenapa sesuatu yang baik akan datang. Setiap cap adalah langkah kaki pelanggan setia, kasih sayang yang terkumpul seiring waktu. Di setiap jejak yang ditekan hingga tintanya kering, hidup dan bernapas sebuah janji kecil untuk kembali lagi."},"ICON-1102":{"nm":"Tutup Pegangan Tas Kertas","de":"Pegangan tas kertas selalu rapuh menghadapi beban. Pasang tutup ini, dan tali yang nyaris putus pun menjadi kokoh. Keinginan untuk membawa pulang isi tas dengan selamat, sebuah komponen kecil yang menopang perjalanan itu hingga akhir."},"ICON-1103":{"nm":"Nampan Koin Kasir","de":"Nampan ini diam-diam meredakan keraguan saat menyerahkan uang kembalian dari tangan ke tangan. Suara koin berdenting mencari tempatnya. Memberi dan menerima jadi lebih hangat, berkat kebaikan kecil yang bundar ini."},"ICON-1104":{"nm":"Chip Poin Loyalitas","de":"Langkah kaki hari ini menumpuk rapi menjadi satu keping. Hitungan ajaib di mana semakin banyak terkumpul, semakin ringan hati terasa. Kegembiraan mengisi sedikit demi sedikit ini mirip dengan kebahagiaan menyaksikan guci kosong perlahan penuh tanpa disadari."},"ICON-1105":{"nm":"Pin Nomor Rak","de":"Di setiap rak, sebuah nomor kecil tersemat dengan penuh perhatian. Penunjuk arah yang diam-diam memberi tahu di mana segala sesuatu berada. Niat menandai tempat lebih dulu agar tidak tersesat, bahkan dalam keteraturan pun tersimpan kehangatan seperti ini."},"ICON-1106":{"nm":"Cangkir Tusuk Cicip","de":"Cangkir kecil yang menyodorkan sesuap untuk dicicipi. Bahkan pelanggan yang ragu perlahan membuka hatinya pada sepotong kecil ini. Kemurahan hati yang mengajak, coba satu ya, bergantung di ujung tusuknya, menahan langkah orang yang baru pertama datang."},"ICON-1107":{"nm":"Penyangga Daftar Reservasi","de":"Nama-nama tamu yang akan datang hari ini berdiri rapi di penyangga ini. Janji lembut bahwa menunggu pun ada gilirannya. Menegakkan selembar kertas menjadi persiapan pertama yang penuh perhatian untuk menyambut hari seseorang."},"ICON-1108":{"nm":"Jepitan Tali Foto Dinding","de":"Pasang seutas tali di dinding dan jepit foto-foto satu per satu. Momen-momen tersenyum tergantung berjajar dan mengering seperti jemuran. Jemur kenangan di tempat yang disinari matahari, dan setiap kali melintas, tawa hari itu berkibar lagi."},"ICON-1109":{"nm":"Sudut Karpet Mini","de":"Sehelai karpet kecil digelar di tepi ruangan. Tempat yang lebih dulu menebarkan kehangatan ke lantai yang dingin. Sejengkal yang pertama disentuh kaki telanjang, ujung kaki yang baru pulang ke rumah akhirnya merasa tenang dan mengantuk di sini."},"ICON-1110":{"nm":"Kain Penutup Papan Nama","de":"Selembar kain yang lembut menutupi papan nama. Menyembunyikan nama sejenak juga sebuah keanggunan rumah tangga tersendiri. Sehelai tirai yang indah membentang di batas antara dalam dan luar, tergantung lembut, membawa keinginan untuk beristirahat tenang hari ini."},"ICON-1111":{"nm":"Klip Kabel Lampu","de":"Klip ini merapikan kabel lampu yang menjuntai. Tangan yang meluruskan jalan agar cahaya tak berantakan. Rapikan satu utas kabel yang kusut saat senja tiba, dan cahaya di dalam ruangan pun hati menjadi lebih tenang."},"ICON-1112":{"nm":"Tutup Magnet Poster","de":"Tutup magnet kecil untuk menempelkan poster di dinding. Kertas itu tetap di tempatnya tanpa membuat satu pun lubang paku payung. Tangan yang merawat sesuatu yang disayangi selalu lembut, niat untuk menjaganya agar tak rusak tersimpan di sini."},"ICON-1113":{"nm":"Tali Rumbai Tirai","de":"Tali berumbai yang mengikat ujung tirai ke satu sisi. Membuka jalan yang indah bagi sinar matahari pagi untuk masuk. Tarik sekali saja tali berumbai itu, dan hari yang cerah pun menerobos masuk ke dalam ruangan dan menetap."},"ICON-1114":{"nm":"Label Alas Lilin Aroma","de":"Selembar label kecil ditempel di alas lilin aroma. Mencatat rapi aroma apa yang sedang menyala dan kapan pertama kali dinyalakan. Memberi nama pada wangi yang disukai, kerapian itu membuat udara di ruangan terasa lebih hangat."},"ICON-1115":{"nm":"Kaki Karet Rak Pajangan","de":"Empat kaki karet yang menopang rak agar tidak goyah. Dari tempat yang tak terlihat, mereka diam-diam menahan beban. Kecil dan rendah hingga luput dari perhatian, namun yang bertahan paling bawah itulah yang bertahan paling lama pada akhirnya."},"ICON-1116":{"nm":"Gantungan Panah Penunjuk Arah","de":"Untuk mereka yang ragu ke mana harus pergi, sebuah panah diam-diam menunjukkan arah. Isyarat lembut agar tidak tersesat. Berkat hati seseorang yang lebih dulu memasangnya di setiap persimpangan, hari ini pun kita melangkah maju tanpa tersesat."},"ICON-1117":{"nm":"Tali Kunci Undangan Pulau","de":"Tali kunci yang digenggamkan ke tangan orang yang mengundangmu ke pulau ini. Terimalah, dan kini kau pun bagian dari keluarga di sini. Keramahan menyambut tamu asing ke dalam kehangatan tersimpan kokoh dalam janji kecil yang tergantung di ujung tali."},"ICON-1118":{"nm":"Chip Suhu Kedekatan","de":"Sebuah chip diam-diam memberi tahu suhu di antara dua orang. Entah masih biru yang canggung, atau sudah berubah menjadi merah jingga yang hangat. Kecepatan kasih sayang bertumbuh sulit diukur, tapi telapak tangan lebih dulu merasakan kehangatan itu."},"ICON-1119":{"nm":"Kotak Sampel Selera","de":"Saat belum tahu apa yang disukai seseorang, kau kumpulkan contoh-contoh kecil ke dalam sebuah kotak dan menyerahkannya. Dalam kesenangan memilih, selera pun perlahan tumbuh. Yang mana akan menjadi milikmu, kotak ini penuh kemungkinan yang mendebarkan."},"ICON-1120":{"nm":"Pin Reservasi Titip Jaga","de":"Janji untuk menjaga seseorang tersemat jelas pada pin ini. Tuliskan nama dan waktunya, dan hati pun tak akan tersesat. Kebiasaan saling bergantian menjaga anak satu sama lain itu, hidup dan bernapas di sini."},"ICON-1121":{"nm":"Kapsul Catatan Pertumbuhan","de":"Seperti tanda tinggi badan yang menumpuk satu garis demi satu garis di kusen pintu, kapsul ini diam-diam menyegel dirimu yang kemarin. Buka tutupnya kelak di masa depan, dan kau akan tahu, sejauh mana langkah-langkah kecil itu telah berjalan."},"ICON-1122":{"nm":"Pita Kenangan Pertemuan Pertama","de":"Debaran saat pertama kali menggenggam tangan itu, diikat lembut pada sehelai pita. Simpul ini bukan untuk dilepas, melainkan agar kehangatan hari itu terus hidup di pergelangan tangan."},"ICON-1123":{"nm":"Label Dekorasi My Room","de":"\"Ini tempatku.\" Saat selembar label kecil menempel di sudut meja, ruangan yang asing pun akhirnya bernapas dan menjadi My Room. Label nama adalah tempat pertama hati menemukan tempat berlabuh."},"ICON-1124":{"nm":"Toples Kelereng Keakraban","de":"Kocok, dan bunyi gelinding pun terdengar, suara dua hati yang semakin dekat satu langkah. Saat toples ini hampir penuh, cukup memanggil namamu saja, dan tawa akan lebih dulu menyambut."},"ICON-1125":{"nm":"Segel Persiapan Debut","de":"Lembar terakhir yang menutup amplop. Sampai di sini adalah persiapan; balik halaman berikutnya, dan itulah panggung. Menekannya erat dengan ujung jari, sang trainee menenangkan napasnya. Akhirnya, dimulai juga."},"ICON-1126":{"nm":"Air","de":"Yang paling umum, karenanya paling berharga. Di ruang latihan menjelang subuh dengan lampu padam, seteguk saja mampu membangkitkan orang yang tersungkur. Kelembutan tanpa wujud tetapnya sendiri, yang meresap ke dalam wadah apa pun."},"ICON-1127":{"nm":"Air Jernih","de":"Kejernihan yang memantulkan terang bahkan kerikil di dasarnya. Mata air pegunungan tak pernah sekali pun membanggakan kejernihannya sendiri. Hati yang tak punya yang disembunyikan selalu seperti ini, terlihat hingga ke dasar."},"ICON-1128":{"nm":"Air Laut","de":"Begitu menyentuh ujung lidah, ombak jauh pun menggulung datang. Dalam seteguk rasa asin itu, cakrawala dan camar serta pelabuhan yang ditinggalkan larut menjadi satu. Laut selalu tertinggal dalam ingatan dengan rasa asin."},"ICON-1129":{"nm":"Es","de":"Perlahan mengecil di telapak tangan, lenyap sebanyak genggaman menekannya. Sekeras apa pun terlihat, ia tahu pada akhirnya akan kembali menjadi air. Es adalah sungai yang untuk sesaat menahan napasnya."},"ICON-1130":{"nm":"Bola Salju","de":"Satu gumpalan yang dipadatkan erat melesat putih membelah gang. Tawa riang dan pipi yang memerah kedinginan. Mainan paling putih yang diam-diam diselipkan musim dingin ke tangan anak-anak."},"ICON-1131":{"nm":"Tanah","de":"Ia mendekap benih, meminum air hujan, dan diam-diam menerima jejak kaki yang melintas. Kulit hitam yang merangkul segalanya. Di tempat pertama segala sesuatu tumbuh, ada segenggam tanah ini."},"ICON-1132":{"nm":"Tanah Subur","de":"Sodorkan jari ke dalamnya, dan kelembutan hitam berminyak pun melingkupi dengan lembut. Rahasia mengapa kebun sayur nenek selalu hijau setiap tahun, ternyata ada di sini. Tanah yang matang berbisik tentang panen melimpah lewat aroma pupuknya."},"ICON-1133":{"nm":"Tanah Liat","de":"Begitu menyerap air, ia patuh menerima bentuk apa pun. Daging lembut yang mengikuti sentuhan, menjadi burung, menjadi mangkuk. Selama roda pemutar berputar, segenggam tanah pun akhirnya mulai bermimpi."},"ICON-1134":{"nm":"Pasir","de":"Butiran-butiran halus yang meluncur lolos di antara jari-jari. Semakin erat digenggam, semakin cepat ia mengalir turun, terus-menerus menyerupai waktu. Dalam segenggam pantai, tak terhitung banyaknya kemarin tertidur lelap."},"ICON-1135":{"nm":"Kerikil","de":"Batu-batu yang terkikis bulat di tepi sungai. Itulah jejak air yang lama sekali membelai hingga sudut-sudut tajamnya lenyap. Semakin jauh ia pernah bergulir, semakin lembut ia mendekap di dalam tangan."},"ICON-1136":{"nm":"Batu","de":"Segumpal batu yang tergeletak begitu saja di pinggir jalan. Seseorang menendangnya lalu berlalu, seseorang lain memungutnya diam-diam untuk menyusun menara. Batu yang sama bisa menjadi beban atau harapan, tergantung pada hati yang memandangnya."},"ICON-1137":{"nm":"Batu Ubin","de":"Batu lebar dan datar yang membentang di halaman istana tua. Ratusan tahun alas kaki melintas di atasnya hingga cekungan terbentuk di tengahnya. Setiap orang yang menapak satu langkah di sana, menambahkan satu lapis waktu."},"ICON-1138":{"nm":"Batu Kapur","de":"Kerang-kerang dari masanya sebagai lautan mengeras berlapis-lapis menjadi batu putih. Masukkan ke dalam tungku, dan ia terurai menjadi kapur, mengecat dinding seputih salju. Sekalipun tampak tenang, ini adalah batu yang mendekap satu zaman utuh di dalamnya."},"ICON-1139":{"nm":"Batu Bara","de":"Hutan tua yang tertidur menjadi hitam kelam. Pakis-pakis dari ratusan juta tahun silam, mengeras kokoh jauh di dalam tanah. Nyalakan api, dan sinar matahari yang lama terpendam pun berkobar bangun kembali."},"ICON-1140":{"nm":"Arang","de":"Ia menyimpan api namun diam-diam menelan asap. Kayu yang dipadatkan hitam di dalam tungku, mekar merah tanpa sepatah kata di atas tungku bara. Semakin diam sesuatu, semakin lama pula ia tetap hangat."},"ICON-1141":{"nm":"Ranting","de":"Ranting yang diam-diam melengkung agar tak patah, mengerti cara untuk menyerah pada lekukan. Di setiap tempat yang bertahan dari angin kencang, tumbuhlah simpul kayu, dan kekokohan sejati pada akhirnya adalah jejak dari kelenturan yang baik."},"ICON-1142":{"nm":"Kayu Gelondongan","de":"Di dalam lingkaran tahun yang terpotong, seratus musim semi dan musim dingin tersusun melingkar bertumpuk. Tahun-tahun yang dijalani sebatang pohon terbaring utuh, kini diam-diam menunggu giliran menjadi tiang sebuah rumah."},"ICON-1143":{"nm":"Kayu Olahan","de":"Setiap kali ketam melintas, serat harum tersingkap selapis demi selapis. Sementara kayu yang kasar berubah halus, serbuk gergaji menumpuk di lantai seperti salju kuning. Tangan yang merapikan membangunkan kegunaannya."},"ICON-1144":{"nm":"Papan Kayu","de":"Ia melapisi lantai, menyusun bangku, mengelilingi pagar. Ketika lembar demi lembar yang dipotong rapi berkumpul, barulah tempat manusia hidup berdiri. Hal-hal biasa yang menumpuk menjadi sebuah rumah."},"ICON-1145":{"nm":"Bambu","de":"Kosong di dalam, namun tegak menghadapi angin. Para sarjana zaman dahulu ingin menyerupai tekadnya itu, putus di setiap ruas lalu bertunas lagi. Di sini berdiri sesuatu yang justru semakin tegak karena kekosongannya."},"ICON-1146":{"nm":"Gabus","de":"Tekan lalu lepaskan, dan ia mengembang kembali ke ketebalan semula. Melihat seratnya yang ringan namun ulet ini, kau akan tahu bahwa lembut sama sekali bukan berarti lemah. Dari sumbat botol hingga papan pengumuman, ia diam-diam menopang segalanya."},"ICON-1147":{"nm":"Rumput","de":"Terinjak pun, ia berdiri lagi begitu hujan berikutnya turun. Keuletan hijau tanpa satu nama pun yang menutupi seluruh ladang. Jangan meremehkan yang kecil, yang paling dulu mengabarkan musim semi selalu tempat yang rendah ini."},"ICON-1148":{"nm":"Jerami","de":"Yang tersisa menguning di ladang setelah panen musim gugur usai. Dianyam, ia menjadi atap; digelar, ia menjadi alas tidur yang hangat. Sebuah hati yang, meski telah memberikan semua bulirnya, masih menyelimuti manusia hingga yang terakhir."},"ICON-1149":{"nm":"Buluh","de":"Saat angin menyapu, gemerisik, gemerisik, seluruh tepi sungai pun bernyanyi serentak. Batang yang kosong di dalam justru menangis lebih jauh. Buluh sama sekali tidak malu bahwa goyangannya sendiri adalah nyanyiannya."},"ICON-1150":{"nm":"Kapas","de":"Ketika polong yang matang meletup terbuka, sekuntum awan kecil pun mekar. Kapas yang ringan dan lembut ini menjadi benang, menjadi kain, dan diam-diam menghangatkan bahu seseorang di malam musim dingin yang dingin membeku."},"ICON-1151":{"nm":"Wol Domba","de":"Sentuh dengan tangan, dan minyak alami serta kehangatan pun diam-diam tertinggal. Mantel yang dikenakan domba di tubuhnya sendiri untuk bertahan dari gunung yang dingin. Kehangatan yang telah dicukur itu kini berpindah ke musim dingin manusia."},"ICON-1152":{"nm":"Benang","de":"Setipis apa pun, nyaris tak terlihat, benang inilah yang selalu menyambungkan kembali dua ujung yang terputus. Selemah apa pun satu helai, jika dianyam ia menjadi sehelai kain utuh. Dalam pekerjaan menyambung, ketebalan tidaklah penting."},"ICON-1153":{"nm":"Kain","de":"Benang pakan dan lungsin saling menyilang tanpa henti membentuk satu lembar kain. Ini adalah hasil dari benang-benang yang akan terurai sendirian, namun saling menggenggam erat satu sama lain. Bahwa semakin rapat tenunannya semakin hangat, hal itu juga berlaku sama di antara manusia."},"ICON-1154":{"nm":"Kulit","de":"Semakin sering dipakai, semakin meresap jejak tangan, perlahan menyerupai pemiliknya. Selagi kekakuan awalnya melunak, warnanya makin dalam dan seratnya makin lembut. Kilau yang diukir oleh waktu itu, tak bisa ditiru oleh apa pun."},"ICON-1155":{"nm":"Bulu","de":"Ringan hingga tak terasa beratnya sekalipun diletakkan di telapak tangan. Sehelai yang menyimpan utuh ingatan terbang melintasi langit. Yang paling ringan yang terbang paling tinggi, jangan sampai lupa itu."},"ICON-1156":{"nm":"Cangkang Kerang","de":"Tiba-tiba teringat kata-kata nenek yang menyuruh menempelkannya ke telinga. Di kilau pelangi bagian dalamnya, laut yang telah ditinggalkan terukir utuh, sehingga bahkan dari cangkang kosong pun terdengar gelombang satu masa yang telah berlalu."},"ICON-1157":{"nm":"Karang","de":"Mengeras seperti batu, namun dulu jelas merupakan koloni yang bernapas. Di laut yang tenang, ia menghabiskan ratusan tahun untuk merentangkan cabang-cabangnya. Cabang yang paling kokoh tumbuh hanya setelah penantian yang paling panjang."},"ICON-1158":{"nm":"Mutiara","de":"Tak tahan menanggung iritasi sebutir pasir, tiram itu diam-diam membungkusnya dengan cahaya. Dekap rasa sakit hingga membulat, dan begitulah ia menjadi berkilau, penghiburan kecil yang ditawarkan laut."},"ICON-1159":{"nm":"Rumput Laut","de":"Pita hijau yang terjuntai licin di batu karang pantai saat air surut. Genggam dengan tangan, dan aroma amis laut pun langsung menyeruak. Tanpa akar, menyerahkan tubuhnya pada arus, laut diam-diam merawat kebunnya sendiri."},"ICON-1160":{"nm":"Nori","de":"Panggang sebentar selembar nori hitam di atas api, dan ia pun menghijau sambil menyebarkan aroma gurih. Pagi itu, saat digulung mengelilingi nasi yang baru matang. Setipis apa pun, ia sanggup mendekap utuh kebahagiaan satu kali makan."},"ICON-1161":{"nm":"Garam","de":"Aku kristal putih yang ditinggalkan laut di bawah terik matahari. Sejumput saja membuat sup yang hambar menjadi dalam rasanya, namun jika tangan tergelincir, aku menutupi semua rasa. Hanya ujung jari yang tahu takaran yang pas yang bisa memakaiku dengan benar."},"ICON-1162":{"nm":"Pecahan Kaca","de":"Justru di tempat ia pecah, cahaya baru dibiaskan menjadi pelangi. Bakat yang tak diketahui saat masih utuh. Bahwa yang pecah pun masih menyimpan bagian untuk membagikan sinar matahari, itulah yang diam-diam disampaikan oleh pecahan kaca yang tergeletak di tepi jendela."},"ICON-1163":{"nm":"Kaca","de":"Bening tidak selalu berarti tak ada yang disembunyikan. Ia menghapus wujudnya sendiri demi membiarkan cahaya melintas utuh. Bahkan dalam bertahan tak terlihat seperti itu, ada kerapian yang sejuk saat tangan menyentuhnya."},"ICON-1164":{"nm":"Botol Kaca","de":"Ia harus kosong di dalam agar bisa memuat sesuatu. Selai, segenggam bunga liar, atau surat yang dilipat, namanya berubah sesuai apa yang masuk ke dalamnya. Wadah yang tak takut pada kekosongan adalah yang paling lapang hati."},"ICON-1165":{"nm":"Botol Kosong","de":"Aku menyukai keheningan yang datang setelah tetes terakhir diminum. Seseorang membuangku, seseorang lain membilasku dan meletakkanku di ambang jendela untuk diisi sinar matahari. Menemukan kegunaan lagi di tempat yang telah berakhir, itulah kehidupan kedua bagi yang telah dikosongkan."},"ICON-1166":{"nm":"Kertas","de":"Aku terbentang putih, siap mencatat apa pun. Selalu akulah yang paling lama menatap ke dalam hati seseorang yang ragu menuliskan baris pertama. Kesabaran selembar kertas kosong lebih dalam sejengkal daripada tinta."},"ICON-1167":{"nm":"Kertas Lusuh","de":"Menguning bukanlah menua, melainkan bertahan. Di setiap lipatan, kehangatan tangan yang membuka dan membacanya telah meresap. Kertas tua, agar tak terlupakan, menuliskan waktu yang telah berlalu lewat warnanya sendiri."},"ICON-1168":{"nm":"Tinta","de":"Dimulai dari setetes, menjadi kalimat, dan begitu kering, tertinggal seperti sebuah janji. Meluber, ia tetap menjadi jejak hari itu apa adanya. Karena tugasku membuat sesuatu tak bisa dihapus, orang-orang menekanku sekali lagi dengan penuh kehati-hatian."},"ICON-1169":{"nm":"Bijih Besi","de":"Batu yang tidur dalam lelap kemerahan di dalam tanah. Hanya setelah melewati api, ia akhirnya melepaskan besi di dalamnya. Kekerasan bukanlah keras sejak awal, melainkan nama yang diperoleh setelah melewati panas yang membara."},"ICON-1170":{"nm":"Batangan Besi","de":"Baru setelah bijih menahan api, ia mendingin menjadi satu gumpalan. Bentuk yang dingin dan berat ini bisa menjadi jembatan, menjadi pedang, menjadi cangkul. Karena kegunaanku belum ditentukan, aku bisa menjadi apa saja."},"ICON-1171":{"nm":"Bijih Tembaga","de":"Aku keluar dari tanah dengan balutan karat sewarna apel muda. Leburkan aku, dan lonceng berdentang, patung berdiri, kawat listrik mengalir. Bahkan saat tertidur di tanah yang gelap gulita, aku selalu menunggu giliran untuk dipanggil menjadi sesuatu."},"ICON-1172":{"nm":"Batangan Tembaga","de":"Biarkan lama di dekatmu, dan ia menjahit sendiri pakaian biru untuk dirinya. Ada yang menyebut warna itu cacat, ada pula yang membelainya sebagai corak yang diukir waktu. Logam yang tak malu pada warnanya yang berubah itulah yang paling lama dicintai."},"ICON-1173":{"nm":"Bijih Emas","de":"Sebutir yang ditemukan setelah menyaring pasir sungai berulang kali. Berharga bukan karena langka, melainkan karena tak pernah berubah. Orang-orang zaman dahulu menggenggamkannya ke tangan sebagai tanda mata, berharap hati seseorang menyerupainya, hati yang tak pernah berkarat."},"ICON-1174":{"nm":"Batangan Emas","de":"Ia terbaring sebagai satu gumpalan, tak pudar maupun berkarat. Ia telah mendengar keserakahan manusia paling banyak, namun aku sendiri tak mengingini apa pun. Hanya keheningan yang berat, setia semata pada tugas untuk bersinar."},"ICON-1175":{"nm":"Besi Tua","de":"Bukan kehabisan guna, melainkan sedang menunggu guna berikutnya. Paku yang patah dan kaleng yang penyok berkumpul bersama untuk kembali bertemu api yang membara. Bagiku, kata dibuang berarti sedang beristirahat sejenak."},"ICON-1176":{"nm":"Sekrup","de":"Sendirian, aku tak bisa berbuat apa-apa. Hanya saat diputar masuk mengunci erat dua papan, barulah aku memainkan peranku. Bakat tubuh kecil menahan sesuatu yang besar, bahkan dalam kekuatan mengencangkan itu tersimpan kesungguhan hati."},"ICON-1177":{"nm":"Paku","de":"Sekali tertancap, aku jarang mundur. Setiap pukulan palu yang memperdalamku bukanlah luka, melainkan janji. Jika itu urusan menyambung sesuatu dengan kokoh, aku dengan rela menyerahkan kepalaku."},"ICON-1178":{"nm":"Roda Gigi","de":"Aku mendorong gigi tetanggaku dan berputar bersama. Aku tak berusaha melaju sendirian, melainkan tahu cara menyesuaikan kecepatan dengan yang di sampingku. Seperti jam yang waktunya mengalir hanya ketika gigi-giginya saling mengunci, aku percaya keselarasan itulah gerak itu sendiri."},"ICON-1179":{"nm":"Pegas","de":"Semakin ditekan, semakin ia mengumpulkan kekuatan di dalam untuk kembali. Melengkung bukanlah menyerah, melainkan persiapan untuk merentang lagi. Sebuah lilitan kecil yang memantul sebanyak guncangan yang diterimanya, di mana kelenturan itu sendiri adalah kekokohan."},"ICON-1180":{"nm":"Kawat Listrik","de":"Luarnya selubung yang tenang, dalamnya jalan yang mengalir tanpa henti. Dari tempat yang tak terlihat, ia mengangkut cahaya dan suara. Seperti tangan yang diam-diam menyambungkan segala hal di balik panggung, ia adalah jalur yang justru semakin dipercaya karena tak tampak."},"ICON-1181":{"nm":"Baterai","de":"Ia menyimpan cahaya terang setengah hari, sedikit demi sedikit, di dalam tubuhnya yang kecil. Katanya, jika habis, isi ulang saja, ia tak pernah menganggap kekosongan sebagai akhir. Ia mendekap senja kecil untuk menerangi malam panjang seseorang."},"ICON-1182":{"nm":"Bola Lampu","de":"Sehelai filamen tipis membara kemerahan dan mendorong mundur kegelapan. Ia membakar tubuhnya sendiri bukan untuk menghangatkan ruangan, melainkan untuk menerangi. Paling panas saat menyala, dan karena itu paling terang, matahari kecil dari satu sekejap mata."},"ICON-1183":{"nm":"Lensa","de":"Ia mengumpulkan cahaya yang berserakan dan menegakkannya jelas di satu titik. Bintang jauh di sana, maupun tulisan kecil di telapak tangan, sama-sama dipanggilnya dengan tenang. Membantu perbuatan melihat, namun justru menyembunyikan wujudnya sendiri, mak comblang yang bening dan bundar."},"ICON-1184":{"nm":"Karet","de":"Ditekan atau direntangkan, ia akhirnya kembali ke tempatnya semula. Mereka yang dulu mencemoohnya lembek pun memilihku untuk dipakai di hari hujan. Pekerjaan menahan guncangan keras dengan lembut, keuletan hidup bahkan di dalam kelembekan ini."},"ICON-1185":{"nm":"Pecahan Plastik","de":"Aku serpihan kecil yang lepas dari bagian utamanya. Hampir saja dibuang, namun jika terkumpul banyak, aku bisa menjadi baru lagi. Bukan ringan karena kecil, melainkan bisa pergi jauh karena ringan, bagian dari sesuatu."},"ICON-1186":{"nm":"Tali Tambang","de":"Hanya dengan memilin banyak helai, ia baru menjadi satu tali utuh. Sendirian ia mudah terurai, namun jika dianyam ia bisa menarik kapal dan mengikat muatan. Simpul kerja sama yang lama, kasar di telapak tangan, semakin kuat karena terpilin bersama."},"ICON-1187":{"nm":"Kain Layar","de":"Ia tak membenci angin, melainkan mendekapnya penuh ke dada. Hanya saat mengembang kencang ia bisa mengirim kapal jauh, sehingga bahkan angin sakal pun menjadi kekuatan bagiku. Cara maju dengan merangkul, bukan melawan yang keras, kupelajari dari laut."},"ICON-1188":{"nm":"Pecahan Jangkar","de":"Ia hanyalah satu sudut dari sebuah jangkar, namun ia mengingat penuh beratnya. Masa-masa mencengkeram dasar yang dalam dan menghentikan sebuah kapal. Bahkan setelah terlepas kini, ia tetap serpihan berat yang mengerti beratnya untuk bertahan di tempat."},"ICON-1189":{"nm":"Paku Kapal","de":"Paku yang menahan geladak yang berayun diterjang ombak, titik demi titik. Meski berkarat merah oleh garam, ia tak pernah melepaskan tempatnya hingga akhir. Menahan kokoh sesuatu yang terapung pun butuh ketabahan."},"ICON-1190":{"nm":"Terpal Anti Air","de":"Ia tak mengeluh soal pekerjaan menahan hujan. Ia diam-diam menampung yang tercurah dari atas, dan menjaga yang di bawah tetap kering. Meski tak mewah, sehelai lapisan yang kokoh menutupi muatan seseorang agar tak basah."},"ICON-1191":{"nm":"Zat Pewarna Kain","de":"Diam-diam meresap ke kain putih polos, barulah ia menjadi warna. Nila atau mengkudu, para ibu zaman dahulu mewarnai ujung jari mereka sambil mendandani kain dengan warna. Bahkan dalam pekerjaan mengendap dan meresap, ada kedalaman yang tak mudah luntur."},"ICON-1192":{"nm":"Minyak Wewangian","de":"Setetes saja, dan ladang luas pun terbentang seketika memenuhi ruangan. Tamu yang datang paling dulu meski tak terlihat mata. Pemandangan yang menyentuh hidung lebih dulu, diam-diam menarik ujung jubah kenangan yang sedang tidur."},"ICON-1193":{"nm":"Wax","de":"Terkena panas ia meleleh, mendingin ia mengeras, menjaga bentuknya sendiri. Berpindah di antara lembut dan keras, ia diam-diam mencetak apa saja. Bahan yang lembut, yang menutup, menyegel, dan mengilapkan, mengubah wajahnya sesuai suhu."},"ICON-1194":{"nm":"Lilin","de":"Ia melelehkan tubuhnya sendiri perlahan untuk menerangi satu petak kegelapan. Setelah habis terbakar, hanya tersisa tinggi yang memendek, namun waktu yang telah menghangatkan malam seseorang itu tak pernah lenyap. Sumbu yang tegak, yang tahu cara bersinar sambil mengecil."},"ICON-1195":{"nm":"Kompos","de":"Hal-hal yang membusuk berkumpul menjadi satu, menjadi tanah paling subur. Kulit yang terbuang dan daun kering yang gugur menjadi santapan tunas baru di musim semi. Di tempat yang dianggap telah berakhir itu, kehidupan berikutnya diam-diam menyiapkan napas pertamanya."},"ICON-1196":{"nm":"Beras","de":"Delapan puluh delapan kali sentuhan tangan diperlukan hingga sebutir beras bisa digenggam. Dari menanam hingga menumbuk, satu tahun seorang petani tersimpan utuh dalam butiran kecil ini. Semangkuk nasi yang mengepul adalah empat musim seseorang."},"ICON-1197":{"nm":"Beras Cokelat","de":"Hanya kulit terluarnya yang dikupas tipis, mempertahankan warna aslinya apa adanya. Semakin dikunyah semakin gurih rasanya, itulah rasa kejujuran yang tak tergesa-gesa. Kekeraskepalaan kokoh sebutir beras, yang menolak digiling halus dan mempertahankan seratnya yang kasar."},"ICON-1198":{"nm":"Gandum","de":"Ia mengingat ladang keemasan yang serempak menundukkan kepala ditiup angin. Menjadi roti, menjadi mi, menjadi adonan sup, ia menghangatkan meja makan di seluruh penjuru dunia. Justru karena begitu umum, ia meresap lebih dalam ke dalam kehidupan manusia."},"ICON-1199":{"nm":"Tepung Terigu","de":"Hanya setelah menjadi bubuk putih yang halus, ia akhirnya bersiap menjadi apa saja. Bertemu air, ia mengembang; bertemu api, ia matang. Karena tak memiliki wujud tetap, ia adalah bahan dasar yang lembut, mengambil bentuk sesuai apa yang diadon oleh tangan."},"ICON-1200":{"nm":"Adonan","de":"Tepung dan air berpadu menjadi satu gumpalan di bawah telapak tangan. Semakin diuleni semakin kenyal, semakin lama menunggu semakin mengembang bulat. Buru-buru dan ia mengeras liat, sehingga waktu fermentasi saja tak bisa dipercepat, kata toko roti tua itu."},"ICON-1201":{"nm":"Remah Roti","de":"Saat kau mengibaskan bubuk putih halus dari ujung jari, tanpa sadar lengan bajumu pun ikut memutih. Sebagai lapisan pelapis ia jadi renyah; saat menumpuk lembut, ia tampak seperti salju pertama. Inilah jejak paling ringan yang ditinggalkan sepotong roti dari proses memanggangnya, namun sekecil apa pun ia, kegunaannya tumbuh juga."},"ICON-1202":{"nm":"Mi Pasta","de":"Begitu segenggam mi dikibaskan seperti kipas ke dalam air mendidih, sinar matahari yang jauh seolah menyeberang masuk ke dapur. Untaian panjang adalah kerja pergelangan tangan, dan al dente adalah kesabaran menunggu saat ia belum matang benar. Lihatlah kilau yang melilit lembut di sekeliling garpu itu."},"ICON-1203":{"nm":"Mi Instan","de":"Sebungkus mi yang diam-diam dimasak di atas kompor saat fajar, ketika semua rias panggung telah terhapus. Tiga menit mi itu melunak adalah waktu paling pribadi dalam sehari. Ketegangan mereda bersama embusan napas saat kau meniupnya, dan di balik kacamata yang berembun, hari ini pun diam-diam berakhir."},"ICON-1204":{"nm":"Tteok (Kue Beras)","de":"Hanya setelah beras bertahan dari tumbukan lesung, ia baru menjadi tteok. Polos, sebagai injeolmi, sebagai songpyeon—biji-bijian yang sama mendapat seratus nama dari tangan yang membentuknya. Disajikan di meja perayaan, ia memanggil kasih sayang sebelum lidah; rasanya paling nikmat jika dimakan bersama."},"ICON-1205":{"nm":"Tteok Sup (Tteokguk)","de":"Iris gara-tteok secara menyerong dan potongannya bulat seperti koin-koin kecil. Apakah itu kue beras yang mengambang di kuah putih, atau harapan bulat kecil? Menghabiskan semangkuk di pagi pertama Tahun Baru menambah satu tahun usia—cara yang penuh kasih, cara negeri ini menghitung umur."},"ICON-1206":{"nm":"Kentang","de":"Kibaskan tanah yang menempel dan wajah bulatnya pun tersingkap. Umbi yang membesar diam-diam diterpa angin lereng Gangwon—empuk mengembang saat dikukus, gurih saat digoreng. Bahkan di hari-hari kantong tipis, ia dengan jujur mengenyangkan perut seisi keluarga."},"ICON-1207":{"nm":"Ubi Jalar","de":"Ketika drum ubi bakar berdiri di mulut gang, itulah tanda musim dingin dimulai. Kupas aluminium foilnya dan uap kuning menghangatkan jari lebih dulu; rasa manis itu adalah balasan sang umbi atas dinginnya yang ditahankan. Pas sekali untuk ditiup-tiup, dibelah dua, dan dibagi hangatnya bersama."},"ICON-1208":{"nm":"Wortel","de":"Sebatang tombak oranye menembus lurus ke dalam tanah. Kukira hanya kelinci yang menyukainya, tapi saat ditumis rasa manis tersembunyi terbangun, dan saat masuk sup ia menambah warna. Kata orang tua dulu bahwa wortel baik untuk mata, ternyata sebagian besar benar."},"ICON-1209":{"nm":"Lobak","de":"Cukup satu umbi putih yang berat ini, meja makan musim dingin pun kokoh. Menggigit dingin sebagai dongchimi, menyegarkan sebagai sup lobak, renyah sebagai kkakdugi. Tak ada yang terbuang—bahkan daun hijaunya dikeringkan di bawah atap dan disimpan sebagai siraegi—sayuran yang hemat."},"ICON-1210":{"nm":"Bawang Bombai","de":"Kupas kulitnya dan setetes air mata menggelinding turun. Daging pedas dan menyengatnya berubah manis bak kebohongan begitu bertemu minyak panas. Namanya tertulis di baris pertama hampir semua masakan Korea—pemeran diam yang tanpa suara meletakkan dasar cita rasa."},"ICON-1211":{"nm":"Daun Bawang","de":"Taburkan bagian pangkal putih yang diiris tipis dan daun hijaunya di atas kuah, dan barulah semangkuk sup terasa benar-benar lengkap. Tancapkan sisa pangkalnya ke gelas berisi air dan ia akan tumbuh menjulang lagi—kebun jendela kecil bagi mereka yang telaten mengurus rumah."},"ICON-1212":{"nm":"Bawang Putih","de":"Enam siung berkumpul melingkar membentuk satu bonggol. Akar pedas yang, konon, mengubah beruang menjadi manusia. Cincang dengan sisi datar pisau dan aromanya langsung menyala; tanpa segenggam ini, kimchi maupun jjigae sama sekali tak masuk akal."},"ICON-1213":{"nm":"Jahe","de":"Akar kecil bergelombang seperti simpul yang kusut. Cukup satu iris untuk meredam bau amis dan menghangatkan tubuh yang menggigil dari dalam. Pada malam-malam mengerang karena flu, secangkir hangat yang diseduh bersama madu itu berawal dari kepedasan kecil ini."},"ICON-1214":{"nm":"Sawi Putih (Napa)","de":"Garami daun yang rapat berlapis-lapis, dan barulah bab pertama kimchi terbuka. Di akhir musim gugur ia menumpuk seperti gunung di setiap halaman rumah. Seisi keluarga duduk melingkar untuk membuat satu tong adalah janji untuk melewati musim dingin panjang bersama-sama."},"ICON-1215":{"nm":"Kubis","de":"Kupas lembar demi lembar daunnya yang menggulung berlapis-lapis dan rasanya tak berujung, hingga tanpa sadar hati pun jadi lebih tenang. Direbus sekilas, ia lembut; ditumis, ia manis. Di balik penampilannya yang sederhana, sayuran ini menyimpan kelembutan yang tak terduga."},"ICON-1216":{"nm":"Selada","de":"Letakkan sepotong daging di atas daun yang cekung, tambahkan sedikit ssamjang, lalu jejalkan sepenuh mulut. Di lingkaran orang-orang yang membungkus dan makan bersama, siapa pun diam-diam melepaskan formalitasnya—inilah tak lain keramahan sang hijau."},"ICON-1217":{"nm":"Daun Selada","de":"Daun pertama yang muncul di sudut kebun. Dipetik pun tumbuh lagi, memenuhi meja makan sepanjang musim panas. Aroma segar hijaunya—dibilas air dingin dan dibungkus dengan tangan—bagi sebagian orang adalah rasa kampung halaman itu sendiri."},"ICON-1218":{"nm":"Bayam","de":"Hijau dalam kartun itu, yang memberi kekuatan berlipat saat kalengnya dikosongkan. Direbus sekilas, ia menyusut jadi segenggam, tapi aroma dan tenaganya tetap utuh. Enak diolah dengan tangan atau dicampur ke dalam sup kedelai—sayuran yang sama sekali tak boleh dipandang remeh hanya karena mudah dijumpai."},"ICON-1219":{"nm":"Pakis (Gosari)","de":"Petik pucuk lembut yang diberikan gunung musim semi, lalu rebus dan keringkan. Hanya setelah kerja keras yang panjang itu, ia baru boleh naik ke meja sesaji maupun mangkuk bibimbap. Sarat dengan perhatian sebanyak tenaga yang dibutuhkan, inilah sayuran liar berharga yang dibesarkan gunung selama satu musim."},"ICON-1220":{"nm":"Sayuran Liar Gunung","de":"Seolah tak bernama, namun masing-masing menyimpan aroma tersendiri—hadiah musim semi. Tangan nenek tahu sekilas pandang daun mana di jalan gunung yang boleh dimakan. Dalam satu keranjang sayuran, satu musim penuh ikut terbawa, lengkap dengan aromanya."},"ICON-1221":{"nm":"Mugwort (Ssuk)","de":"Rumput pahit namun harum yang paling dulu menembus tanah yang membeku. Dibentuk jadi kue beras, cahaya musim semi pun langsung masuk ke mulut. Pada bulan pertama tahun, orang percaya merebusnya menjadi sup menangkal sial setahun, jadi musim semi selalu datang lewat aroma ini."},"ICON-1222":{"nm":"Daun Perilla (Kkaennip)","de":"Aroma yang cukup dengan satu lembar saja untuk mewarnai seluruh mulut secara pekat. Padukan dengan samgyeopsal yang keemasan, atau acarkan berlapis-lapis dalam kecap—semangkuk nasi pun ludes dalam sekejap. Aroma khas ini terasa pas hanya di meja makan negeri ini."},"ICON-1223":{"nm":"Paprika Hijau","de":"Buah hijau berongga yang pecah renyah. Rasa pahit tipisnya membangunkan lidah yang tumpul, dan saat ditumis dalam minyak warnanya kian cerah. Cukup dicincang halus dan ditaburkan saja, masakan apa pun langsung terasa lebih segar."},"ICON-1224":{"nm":"Paprika","de":"Merah, kuning, oranye—warna-warni bak lampu lalu lintas memenuhi satu keranjang penuh. Gigit mentah-mentah dan sari manisnya menetes; warnanya saja sudah mencerahkan meja makan. Ungkapan bahwa sayuran yang cantik membangkitkan selera, pas benar untuk yang satu ini."},"ICON-1225":{"nm":"Tomat","de":"Merah bulat yang selalu diperdebatkan—buah atau sayur? Direbus lama, rasanya kian dalam; dimakan mentah, ia luar biasa segar. Inilah buah yang paling jujur mengumpulkan matahari pertengahan musim panas, hingga sekali gigit, seluruh siang hari pun pecah berhamburan."},"ICON-1226":{"nm":"Mentimun","de":"Hijau yang paling menyegarkan mendinginkan panas musim panas. Apungkan dalam sup dingin dan mulut pun jadi sejuk renyah; acarkan sebagai sobagi dan kerenyahannya hidup kembali. Di hari yang menyengat, irislah tipis dan letakkan di atas mata—sayuran yang sejuk luar dalam."},"ICON-1227":{"nm":"Labu","de":"Bergantung bulat di ujung sulur, perlahan mengisi diri dengan rasa manis hingga akhir musim gugur. Direbus lunak ia menjadi bubur kuning yang menenangkan perut; digoreng ia menjadi jeon yang keemasan. Digantung di bawah atap, ia berperan sebagai lumbung yang andal sepanjang musim dingin."},"ICON-1228":{"nm":"Labu Muda (Aehobak)","de":"Hijau muda yang membesar dari hari ke hari di kebun musim panas. Dipotong-potong ke dalam jjigae doenjang, digoreng jadi jeon keemasan—begitu lembut hingga ramah bahkan di mulut anak kecil. Justru karena mudah didapat, ia semakin patut disyukuri: pelanggan tetap meja makan pertengahan musim panas."},"ICON-1229":{"nm":"Terong","de":"Buah lonjong yang berkilau lembut keunguan. Menyerap minyak, ia jadi lembut tanpa batas; dikukus matang, seratnya sehalus sutra. Meski tampak biasa saja, ia cocok dipadukan dengan apa pun—pemeran pendukung yang lembut hati di meja makan."},"ICON-1230":{"nm":"Jagung","de":"Butiran kuning yang berbaris rapi, satu demi satu. Camilan musim panas yang dikukus dalam panci, ditiup-tiup lalu digigit; juga tanda gembira bahwa ladang telah matang. Dalam seikat rambut jagungnya yang berbulu halus, rasa manis tersimpan penuh."},"ICON-1231":{"nm":"Kedelai","de":"Butiran kecil yang keras meminum air semalaman dan menggembung. Digiling halus jadi susu kedelai, difermentasi lunak jadi jang—sebagian besar protein meja makan negeri ini bermula persis dari sini. Tanam satu biji di tanah, dan ia kembali sebagai satu pohon utuh."},"ICON-1232":{"nm":"Tahu","de":"Ketika kedelai meminum air, digiling, dan dipadatkan, ia menjadi balok putih bersudut rapi. Lembut dan bersahaja, ia tak pernah bersikeras mempertahankan warnanya sendiri di dalam sup apa pun. Runtuh perlahan bahkan hanya disentuh sendok—makanan yang keutamaannya justru terletak pada kesederhanaan."},"ICON-1233":{"nm":"Kacang Merah (Pat)","de":"Rebus butiran merah kecil hingga matang dan manis merah kehitaman meresap pekat. Pada malam terpanjang, semangkuk bubur kacang merah hangat dulu mengusir dingin sekaligus roh jahat—hati itu masih hidup di dalamnya. Berlapis-lapis dalam kue kukus, warna merah itu tak lain adalah ketulusan."},"ICON-1234":{"nm":"Pasta Kacang Merah (Patangkeum)","de":"Kacang merah rebus dihaluskan lembut, direduksi dan direduksi lagi hingga jadi isian yang lembut. Satu sendok di antara roti, di dalam tteok, di atas es serut—seuntai rasa manis menghangatkan bahkan ingatan lama. Waktu panjang menyaring dan mereduksi itu, dengan sendirinya, menjadi rasa manis."},"ICON-1235":{"nm":"Jamur","de":"Setelah hujan reda, ia mengangkat kepala tanpa suara di keteduhan hutan yang remang. Keahlian tanah, menumbuhkan aromanya sendiri tanpa segenggam pun sinar matahari. Cukup segenggam ke dalam sup dan rasa gurih yang dalam meresap tanpa daging—rahasia yang disembunyikan hutan."},"ICON-1236":{"nm":"Jamur Shiitake","de":"Payung cokelat yang tudungnya terbentang lebar. Dikeringkan garing di bawah matahari, aromanya kian pekat berlipat-lipat, hingga satu jamur kering saja sanggup menanggung sepanci penuh kuah. Tiang andal meja makan vegetarian, dan langganan lama bagi mereka yang paham rasa yang dalam."},"ICON-1237":{"nm":"Jamur Songi (Jamur Pinus)","de":"Jauh di dalam hutan pinus musim gugur, ia mengangkat kepala hanya di dekat pohon pinus. Tak bisa dibudidayakan dan harus ditemukan dengan berjalan kaki, itulah yang membuat aromanya kian berharga. Dipanggang sebentar dan cukup dicelup sedikit garam, sepotong hutan pun masuk ke mulut."},"ICON-1238":{"nm":"Jamur Tiram Raja (Saesongi)","de":"Robek batangnya yang tebal mengikuti seratnya dan kekenyalan itu langsung terasa di tangan. Tumbuh kokoh sepanjang musim, ia tak pernah jauh dari meja makan. Dipanggang atau ditumis—dalam dagingnya yang berlimpah, rasa kenyang yang ringan terisi penuh."},"ICON-1239":{"nm":"Stroberi","de":"Di ujung rumah kaca yang bertahan dari musim dingin, ia paling dulu matang memerah. Sekali gigit, rasa manis asamnya terasa, persis seperti sapaan pertama awal musim semi. Letakkan satu bulat di atas kue, dan hari biasa pun berubah jadi hari perayaan."},"ICON-1240":{"nm":"Blueberi","de":"Pecah dengan bunyi 'tok' dan rasa asam yang cerah menyebar memenuhi mulut. Ambil butiran ungu kecil satu demi satu dan tanpa sadar wadahnya sudah kosong; taburkan di atas susu putih, dan sebuah langit malam kecil pun terbentang."},"ICON-1241":{"nm":"Apel","de":"Gigit satu buah dan dengan bunyi renyah, musim gugur pun pecah berkeping. Merah yang diusap nenek pekebun dengan lap dan diulurkan itu adalah warna yang hanya lahir dari lamanya menyimpan sinar matahari. Semakin keras buahnya, semakin ia tahu cara mempertahankan manis hingga akhir."},"ICON-1242":{"nm":"Pir Korea (Bae)","de":"Kupas kulitnya dan ujung jari pun lebih dulu terasa sejuk. Baris terdepan meja sesaji Chuseok—saat sari manisnya yang dingin memenuhi mulut, sepetak angin malam musim gugur diam-diam datang duduk di sampingmu."},"ICON-1243":{"nm":"Persik","de":"Di setiap tempat bunga persik gugur, musim panas berbulu halus terbentuk. Tekan sedikit dan aromanya menyebar lebih dulu; begitu sekali gigit, seluruh musim ikut masuk ke dalam mulut."},"ICON-1244":{"nm":"Anggur","de":"Butiran ungu bergantung sebagai satu tandan, saling bersandar bahu. Pecahkan satu dan rasa asam datang lebih dulu, manisnya menyusul setengah ketukan kemudian—seperti paduan suara rapi yang dipanggil oleh hari-hari terakhir musim panas."},"ICON-1245":{"nm":"Anggur Hijau","de":"Hijau muda membiarkan sinar matahari lewat begitu saja, menyalakan lentera di tiap butirnya. Tanpa biji dan bersih menyegarkan, rasa manisnya tanpa kelebihan sedikit pun, seperti frasa pertama yang baru saja diucapkan."},"ICON-1246":{"nm":"Lemon","de":"Gores kulit kuningnya dengan kuku dan aromanya menyentak, membangunkan ujung hidung. Setetes saja membuat bibir mengerut sendiri, namun di ujung rasa asam itu ada sudut aneh yang justru mencerahkan seluruh hari."},"ICON-1247":{"nm":"Jeruk Nipis","de":"Lebih kecil dan lebih hijau pekat dari lemon, buah kecil ini menyapa lebih dulu dengan aroma tajamnya yang menyengat. Satu iris saja membangunkan air suam-suam kuku dalam sekejap—segenggam kesegaran yang kecil namun tangguh."},"ICON-1248":{"nm":"Jeruk Oranye","de":"Begitu kulitnya dikupas, aroma sinar matahari menempel di jari. Masukkan tiap juringnya ke mulut dan pop, pop—balon-balon kecil sari manis pun pecah, dan yang bulat itu ikut menggulirkan suasana hati jadi bulat pula."},"ICON-1249":{"nm":"Jeruk Mandarin (Gyul)","de":"Ingat rasa itu—mengupasnya dengan kaki terselip di bawah selimut hangat lantai musim dingin? Aroma yang menyebar dari sela kuku mewarnai seluruh ruangan jadi kuning. Satu kantong saja jadi alasan seisi keluarga berkumpul melingkar."},"ICON-1250":{"nm":"Pisang","de":"Ada hari-hari ketika aku mengganjal perut hanya dengan satu buah kuning yang menggelinding keluar dari tas di sudut ruang latihan pada fajar yang lapar. Lembut, manis, dan mengenyangkan—jalan pintas paling penuh kasih."},"ICON-1251":{"nm":"Nanas","de":"Harus melewati selapis kulit berduri dulu sebelum daging kuningnya terlihat. Gigit sepotong dan rasa manis asamnya menyengat lidah, sementara di bibir samar-samar tercium aroma laut selatan."},"ICON-1252":{"nm":"Mangga","de":"Belah daging matangnya dengan tangan dan aroma manis lengket membasahi jari. Ketika kuning pekatnya meleleh dan lenyap di dalam mulut, mimpi manis seperti tidur siang singkat musim panas pun berlalu."},"ICON-1253":{"nm":"Kelapa","de":"Guncang tempurungnya yang keras dan terdengar suara air bergemercik di dalam. Pecahkan—daging putih dan air yang segar—stoples kecil yang menampung seluruh lautan jauh, bergoyang di dalamnya."},"ICON-1254":{"nm":"Buah Naga","de":"Penampilan bersisik merah muda itu membuat kita ragu sejenak, tapi belah dan di dalamnya yang putih bertabur biji-biji hitam kecil. Rasanya sederhana namun penampilannya mewah—si licik yang luar dalamnya justru berlawanan."},"ICON-1255":{"nm":"Kiwi","de":"Belah dua yang cokelat berbulu halus itu dan sebutir permata hijau pun tersingkap. Sendokkan penampang tempat biji-biji hitam tertanam bak bintang, dan satu suapan asamnya mengguncang bangunkan kantuk."},"ICON-1256":{"nm":"Daging Ayam","de":"Letakkan di wajan berminyak dan bunyi cess keemasan lebih dulu matang. Bersahaja dan lembut, ia mudah duduk di meja siapa saja—langganan tetap untuk semangkuk makan yang bersahabat."},"ICON-1257":{"nm":"Daging Babi","de":"Di atas panggangan, ia mendesis, minyaknya meletup-letup sambil matang keemasan. Pada malam-malam makan bersama rekan kerja, menjejalkan sepenuh mulut yang dibungkus selada dengan sedikit ssamjang, kegurihannya menghangatkan seluruh meja."},"ICON-1258":{"nm":"Daging Sapi","de":"Di setiap serat merahnya, lemak tertanam rapi dan berkilau. Letakkan di atas lempengan batu panas dan aromanya lebih dulu memenuhi ruangan; begitu sepotong masuk mulut, kelelahan sehari diam-diam mengendur."},"ICON-1259":{"nm":"Bacon","de":"Di atas wajan pagi, ia menggarang renyah, minyaknya menari-nari. Cukup dengan aroma asinnya saja, bahkan keluarga yang masih tidur pun bangun mengucek mata dan berkumpul ke dapur—makanan yang aromanya lebih dulu memanggil."},"ICON-1260":{"nm":"Sosis","de":"Sayatan yang dibuat terbuka lebar, sari dagingnya meletup keluar. Bentuk gurita merah yang menjaga satu petak kotak bekal itu adalah kemewahan kecil yang dinikmati waktu makan siang masa kanak-kanak."},"ICON-1261":{"nm":"Peperoni","de":"Sepotong bulat pedas melengkung dari tepinya di atas keju panas. Ketika minyak sedikit menggenang, itulah puncak seloyang pizza—kecil, namun kehadirannya bulat dan pekat."},"ICON-1262":{"nm":"Patty (Daging Burger)","de":"Bentuk tebal dan letakkan di atas panggangan, dan ia mulai matang kecokelatan dari tepi ke tengah. Selipkan sayuran di antara satu lembar yang ditekan dan dipanggang, dan rasa kenyang yang pas dalam satu genggaman pun rampung."},"ICON-1263":{"nm":"Telur","de":"Pecahkan dan kuning telurnya meluncur seperti matahari kecil yang bulat. Enak dicampur ke nasi baru matang, enak juga jadi garis kuning di dalam gimbap—protein paling umum namun karenanya paling penuh kasih."},"ICON-1264":{"nm":"Susu","de":"Sebotol dingin yang diletakkan di depan pintu saat fajar—hari sering kali dimulai dari kesejukan itu yang menyentuh telapak tangan. Berasap saat dihangatkan, gurih saat didinginkan—putih yang selalu setia menemani kapan saja."},"ICON-1265":{"nm":"Keju","de":"Selembar kuning perlahan meleleh di atas roti hangat. Hati yang menunggu satu momen ia melar memanjang—semakin meleleh, semakin dalam dan pekat kegurihannya."},"ICON-1266":{"nm":"Keju Cheddar","de":"Oranye pekatnya sekilas saja sudah menandakan rasa asin gurih. Iris tipis, selipkan ke roti panggang, dan rasa gurihnya menyebar memenuhi mulut—sejelas warnanya, sejelas itu pula cita rasanya."},"ICON-1267":{"nm":"Mentega","de":"Jatuhkan sepotong ke wajan panas dan ia meleleh perlahan, uap gurih pun mengepul. Dioles ke roti, dicampur ke nasi—sihir kuning yang membuat apa pun yang disentuhnya menjadi lebih lembut."},"ICON-1268":{"nm":"Krim Kocok","de":"Semakin diputar pengocoknya, putih yang encer perlahan mengembang menjadi awan yang kokoh. Begitu satu sendok diletakkan di atas kue, sore yang biasa saja pun cerah bagai hari ulang tahun kecil."},"ICON-1269":{"nm":"Yoghurt","de":"Masukkan sendok dan putih asamnya terangkat mulus. Campurkan sepotong buah dan pagi jadi lebih ringan; satu gelas saja, dan perut pun tertata tenang—rasa dari sebuah awal yang lembut."},"ICON-1270":{"nm":"Ikan Kembung","de":"Letakkan di atas panggangan besi dan minyaknya meletup-letup, asap yang amis sekaligus gurih memenuhi dapur. Tangan yang memisahkan durinya dan meletakkannya di atas nasi—ketulusan paling dalam yang bersemayam dalam meja makan sehari-hari."},"ICON-1271":{"nm":"Salmon","de":"Serat merah muda terbaring bertumpuk rapi. Disantap dingin, ia terurai lembut di mulut; dipanggang, minyaknya meresap gurih—rasa kokoh yang berenang melawan arus laut yang jauh untuk pulang."},"ICON-1272":{"nm":"Tuna","de":"Buka tutup kalengnya dan aroma asin gurih pun menyeruak. Ada masa-masa di malam hari di kamar kos sempit ketika satu kaleng dicampur ke nasi atau dibungkus rumput laut menjadi semangkuk makan yang mengenyangkan."},"ICON-1273":{"nm":"Ikan Kod","de":"Dagingnya yang bening begitu ringan hingga direbus saja kuahnya sudah menyegarkan sejak awal. Ikan putih yang bertahan dari angin tajam pelabuhan musim dingin—semangkuk sup panas saja membuat tangan yang membeku pun perlahan mencair."},"ICON-1274":{"nm":"Udang","de":"Melengkungkan punggungnya bulat dan seiring matang, abunya memerah muda. Kenyalnya yang meletup dan aroma gurihnya—kupas dan makan satu per satu, dan tanpa sadar piring sudah kosong."},"ICON-1275":{"nm":"Kepiting","de":"Mengeluarkan daging putih dari cangkang yang keras adalah masa kesabaran kecil. Sepotong yang akhirnya masuk mulut setelah kerja keras itu manis, seolah lautan musim gugur masuk utuh ke dalam mulut."},"ICON-1276":{"nm":"Cumi-Cumi","de":"Di atas panggangan ia menggulung bulat, mengepulkan aroma gurih. Sepotong yang kenyal digigit, dicelup saus cabai lalu masuk mulut, dan laut yang asin gurih pun ikut menyertai."},"ICON-1277":{"nm":"Kerang","de":"Dalam kuah bening, ia membuka cangkangnya dan diam-diam melepaskan aromanya. Saat mendidih bergolak, aroma laut menyebar, dan sekali seruput saja perut yang menggigil pun menghangat lega."},"ICON-1278":{"nm":"Odeng (Kue Ikan)","de":"Celupkan tusukannya utuh ke dalam kuah hangat dan uapnya mengepul mengumpul. Di depan gerobak kaki lima pada hari dingin, tangan yang menampung kuah dalam gelas kertas sambil ditiup-tiup itu—penghiburan kecil yang diberikan gang."},"ICON-1279":{"nm":"Kimchi","de":"Di dalam toples ia matang perlahan, menumbuhkan aroma asam yang dalam. Robek dengan tangan dan letakkan di atas nasi yang baru matang, cukuplah itu—rasa yang berbeda di tiap rumah adalah riwayat rumah itu sendiri."},"ICON-1280":{"nm":"Acar Lobak Kuning (Danmuji)","de":"Sepotong kuning renyah, pecah ringan di dalam mulut. Sahabat setia di samping segulung gimbap atau seporsi jajanan—manis asamnya membilas mulut yang berminyak jadi segar."},"ICON-1281":{"nm":"Acar (Pikel)","de":"Mentimun menahan napas sejenak dalam garam, lalu membuka mata dalam cuka. Agar tak melewatkan saat kerenyahan itu kembali, stoples kacanya tak pernah beranjak dari jendela yang berjemur matahari. Waktu yang perlahan mengasinkan itulah yang membawakan rasanya."},"ICON-1282":{"nm":"Gochujang (Pasta Cabai Merah)","de":"Merah yang bertahan setahun penuh di dalam toples. Di ujung rasa pedasnya, manis kedelai bersembunyi lembut, sehingga satu sendok saja membuat jjigae akhirnya menjadi wajah keluarga kita sendiri. Kedalaman yang dibesarkan toples jang di halaman dengan sinar matahari."},"ICON-1283":{"nm":"Doenjang (Pasta Kedelai)","de":"Meju memeluk jamurnya dan melewati satu musim dingin. Kegurihannya adalah tarian tali yang menegangkan antara matang dan terlalu matang—nenek mengenali batas itu hanya dari aroma di ujung jarinya. Rasa yang kian dalam seiring lamanya menunggu."},"ICON-1284":{"nm":"Kecap Asin (Ganjang)","de":"Semakin hitam kedelainya, semakin dalam isinya. Setetes saja menghidupkan sayuran dan memberi kilau pada jorim, sehingga semua warna di dapur pada akhirnya berawal dari cokelat hangat ini. Rasa gurih di balik asinnya."},"ICON-1285":{"nm":"Chunjang (Pasta Kedelai Hitam)","de":"Sama-sama hitam, tapi seratnya berbeda. Rasa akhir manis-asin dari digoreng sekali lagi dengan karamel—campurkan ke mi dan kilau hitam itu mengguncang membangunkan selera. Kancing pertama yang memulai cita rasa wajan Tionghoa."},"ICON-1286":{"nm":"Bubuk Kari","de":"Bubuk kuning tempat berbagai rempah berbaur akur dalam satu sendok. Larutkan dalam air dan ia mendidih menggelegak, menghangatkan seisi rumah—menjadi cuplikan pembuka semangkuk paling mengenyangkan pada senja yang hujan."},"ICON-1287":{"nm":"Lada","de":"Digiling utuh, aromanya hidup; digiling lebih dulu, aromanya diam-diam menguap pergi. Putaran terakhir selalu tepat sebelum api dimatikan—titik kecil yang dihemat-hemat oleh tangan yang memasak."},"ICON-1288":{"nm":"Bubuk Cabai","de":"Cabai matahari yang dikeringkan di bawah sinar musim gugur akhirnya menyempurnakan warna merahnya. Digiling halus atau kasar menentukan karakter kimchi, sehingga sentuhan tangan seorang juru masak pada akhirnya datang dari memilih butiran bubuk ini."},"ICON-1289":{"nm":"Garam","de":"Menyeimbangkan rasa berarti melangkah sejumput demi sejumput ke arah yang kurang. Rasa asin yang sudah masuk tak bisa ditarik kembali, sehingga tangan yang berpengalaman selalu menambahkan sedikit lebih sedikit di akhir lalu mencicip. Yang disisihkan itulah kelonggarannya."},"ICON-1290":{"nm":"Gula","de":"Ia meredakan rasa pahit dan membulatkan sudut-sudut rasa asam. Namun rasa manis tak boleh ketahuan kehadirannya, sehingga semakin baik bumbunya, semakin diam-diam gula menghilang jejak di akhir. Rasa manis yang tahu cara bersembunyi."},"ICON-1291":{"nm":"Madu","de":"Sebotol yang dikumpulkan lebah dengan bolak-balik ribuan kali ke ladang bunga. Saat mengeras, hidupkan kembali dengan merendamnya dalam air hangat; larutkan ke teh dan ia membungkus tenggorokan dengan lembut. Satu sendok emas dari satu musim penuh yang direduksi utuh."},"ICON-1292":{"nm":"Minyak Goreng","de":"Lingkarkan sekali ke wajan panas dan bahan-bahan pun lupa untuk lengket. Tuang terlalu dini dan gosong, terlalu lambat dan melekat, sehingga satu ketukan saat asap baru mulai naik itulah aturan baku menggoreng. Waktunya diukur lewat bunyi."},"ICON-1293":{"nm":"Minyak Zaitun","de":"Dalam hijau perasan pertama, aroma rumput dan sedikit rasa pedas hidup bersama. Dituangkan di akhir alih-alih dipanaskan di atas api, aromanya bertahan hingga akhir, sehingga tidak dimasak adalah penggunaannya yang paling jujur."},"ICON-1294":{"nm":"Minyak Wijen","de":"Teteskan satu tetes di akhir dan sayuran yang dibumbui pun akhirnya menyatakan diri selesai. Kegurihannya mudah kabur di atas api, sehingga ia selalu menjadi titik penutup yang diam-diam ditambahkan setelah semua proses masak selesai."},"ICON-1295":{"nm":"Vanili (Polong Vanili)","de":"Belah satu polong dan kerok bijinya yang hitam, maka hidangan penutup pun berganti busana aroma. Tidak membuang kulitnya yang sudah terpakai, melainkan mengubur di dalam gula—kehematan lama yang diwariskan kepada juru pastry."},"ICON-1296":{"nm":"Kakao","de":"Daging putih dan biji pahit di dalam buahnya. Hanya setelah melalui fermentasi dan penjemuran matahari, ia baru diterjemahkan menjadi rasa manis yang kita kenal. Sebelum menjadi cokelat, ia memiliki wajah pertama yang paling dekat dengan liar."},"ICON-1297":{"nm":"Cokelat","de":"Sifatnya yang rewel meleleh hanya dengan kehangatan telapak tangan. Harus dipadatkan pada suhu sekitar 28 derajat agar kilau dan bunyi patahnya hidup, sehingga di balik manisnya tersembunyi aturan suhu yang ternyata cerewet."},"ICON-1298":{"nm":"Biji Kopi","de":"Sebelum digiling, satu biji hampir menyerupai keheningan yang keras. Namun begitu bertemu air panas, ia mengembang dan memuntahkan aromanya—sinyal pertama yang membangunkan pagi selalu berawal dari biji kecil ini."},"ICON-1299":{"nm":"Daun Teh","de":"Terlalu lama berendam di air panas, ia jadi sepat; terlalu singkat, jadi hambar. Menghitung dengan tenang waktu daun itu perlahan mekar—menyeduh teh adalah mengukur penantian dengan ujung jari."},"ICON-1300":{"nm":"Daun Mint","de":"Diremas, rasa pahitnya keluar, sehingga selalu harus diperlakukan dengan lembut, daun yang rapuh ini. Ketuk ringan untuk membangunkan aroma yang tertidur, dan apungkan dalam gelas kaca di hari yang menyengat, maka pertengahan musim panas pun mereda satu tingkat lebih sejuk."},"ICON-1301":{"nm":"Herba","de":"Masukkan bersama batangnya, aromanya jadi dalam; pakai daunnya saja, rasanya jadi bersih. Dikeringkan, aromanya kian pekat; dipakai segar, rasanya kian ringan—seluas rentang aroma yang dikandung seikat herba, seluas itu pula wajah dapur ikut melapang."},"ICON-1302":{"nm":"Kastanye","de":"Di balik kulit berduri tersembunyi daging yang berkilau. Sayat sedikit lalu panggang, kulitnya merekah dengan bunyi letup dan aroma manis pun menyeruak—kehangatan sekantong kastanye panggang di gang berangin dingin terasa begitu dekat, seolah bisa digenggam tangan."},"ICON-1303":{"nm":"Kacang Tanah","de":"Kelezatannya rampung di atas api sangrai. Butir demi butir dikupas hingga waktu terasa berlalu tanpa disadari—dibagi sambil duduk melingkar di lantai kayu, cerita pun ikut terkupas pelan-pelan bersamanya."},"ICON-1304":{"nm":"Almond","de":"Direbus sebentar lalu dikupas kulitnya, bagian dalamnya jadi lebih putih dan lembut. Dihaluskan jadi seperti susu, dipanggang utuh jadi renyah—rentang perubahan yang dikandung satu butir ini melapangkan imajinasi seorang pembuat kue."},"ICON-1305":{"nm":"Wijen","de":"Goyang perlahan di atas api kecil, dan pada suatu saat ia mulai meletup-letup. Saat tepat sebelum bunyi itu berhenti adalah saat paling harum—menyangrai wijen ternyata adalah pekerjaan yang dilakukan dengan telinga."},"ICON-1306":{"nm":"Tebu","de":"Kunyah satu ruas dan air manisnya meresap keluar bersama aroma rumput. Batang yang harus direbus dan dipekatkan berulang kali hingga menjadi manis yang kita kenal—ternyata awal mula gula sehijau dan setinggi ini."},"ICON-1307":{"nm":"Gula Mentah","de":"Manis kasar yang mempertahankan warna aslinya karena melewati sedikit penyulingan. Kedalaman seperti aroma tanah masih tersisa samar-samar, sehingga tangan-tangan yang menyukai kejujuran sesuatu sebelum dihaluskan sengaja mencarinya."},"ICON-1308":{"nm":"Biji Kakao","de":"Biji yang baru dikeluarkan dari polongnya terasa pahit dan sepat. Harus diam-diam bertahan beberapa hari fermentasi agar aromanya mekar, maka rasa manis adalah hadiah kecil yang diterima biji ini setelah lama bersabar."},"ICON-1309":{"nm":"Kepingan Kakao","de":"Tak ada sebutir pun gula dalam kepingan biji sangrai yang dihancurkan ini. Masukkan ke mulut, kepahitan datang lebih dulu, kelezatan menyusul belakangan—di sinilah kita bertemu kakao sebelum manis, dengan cara paling jujur."},"ICON-1310":{"nm":"Biji Kopi Hijau","de":"Butiran hijau yang masih membawa aroma mentah. Sebagaimana adanya, aromanya masih tertidur lelap, maka sebelum menerima baptisan api, ia diam-diam tetap menjadi kemungkinan yang belum tahu akan menjadi apa."},"ICON-1311":{"nm":"Biji Kopi Sangrai","de":"Di permukaan cokelat yang sedikit berminyak, aroma tergenang penuh. Harus digiling sebelum dingin agar aroma itu tetap utuh, maka nasib secangkir kopi diam-diam ditentukan dalam beberapa hari setelah disangrai."},"ICON-1312":{"nm":"Polong Vanili","de":"Satu batang aroma mewarnai sepanci susu secara menyeluruh. Bahkan kulitnya yang sudah terpakai, jika ditancapkan ke dalam toples gula, beberapa hari kemudian seluruh gula pun jadi harum—kemewahan yang tak menyisakan satu bagian pun untuk dibuang."},"ICON-1313":{"nm":"Merica","de":"Aroma sebutir merica utuh memudar sejak saat digiling. Karena itu ia disimpan utuh di atas meja dan dihancurkan sesuai kebutuhan—kesegaran mekar dari hati yang tak suka menunda."},"ICON-1314":{"nm":"Merica Putih","de":"Butiran yang menjadi lebih halus setelah kulitnya dikupas terasa lembut, bukan tajam. Lahir dari perhatian untuk tidak meninggalkan satu bintik hitam pun di saus putih—kehalusan dari tempat yang tak terlihat."},"ICON-1315":{"nm":"Kayu Manis","de":"Rendam satu potong dan pedas hangat perlahan menyebar dalam teh. Aroma bertahan lebih lama jika dimasukkan utuh ketimbang bubuk, maka kedalaman minuman musim dingin datang dari keteguhan kulit kayu kering ini."},"ICON-1316":{"nm":"Cengkih","de":"Dalam satu kuncup bunga berbentuk paku kecil, aroma terpadatkan sepenuhnya. Terlalu banyak dimasukkan, ia menelan seluruh masakan bulat-bulat, maka kesederhanaan satu kuncup saja diam-diam menjaga keseimbangan rasa."},"ICON-1317":{"nm":"Pala","de":"Simpan bijinya utuh dan parut sedikit sesuai kebutuhan. Ia bersifat cepat kehilangan aroma jika digiling lebih dulu, maka sentuhan terakhir berupa satu kerokan cepat itulah yang membuat aroma susu jadi jauh lebih dalam."},"ICON-1318":{"nm":"Kapulaga","de":"Pecahkan kulit hijaunya dan aroma segar menyegat tumpah dari dalam. Cukup dengan menghancurkan satu-dua biji ke dalam teh, secangkir yang biasa saja tiba-tiba mendapat keharuman negeri yang jauh."},"ICON-1319":{"nm":"Saffron","de":"Benang merah yang hanya dipanen tiga helai dari satu kuntum bunga. Larutkan dalam air hangat dan cahaya kuning perlahan menyebar, maka kelangkaan juga adalah bobot waktu yang dihabiskan memilih satu per satu dengan tangan."},"ICON-1320":{"nm":"Kunyit","de":"Giling akarnya dari dalam tanah dan ia mewarnai kuning bahkan hingga ujung jari. Ia bersifat aromanya baru terbangun saat ditumis sebentar dalam minyak, maka warna emas kari adalah warna yang ditumbuhkan akar kecil ini di atas api."},"ICON-1321":{"nm":"Daun Laurel","de":"Daun yang konon pernah bertengger di dahi sang pemenang. Apungkan selembar ke air mendidih dan di sela uapnya, sorak-sorai arena kuno sejenak membubung. Bahkan di hari kau tak menang, menghirup aromanya menjadi penghiburan hijau yang diam-diam merangkul dirimu hari ini."},"ICON-1322":{"nm":"Santan","de":"Sari putih yang baru mengalir keluar setelah tempurung kerasnya dipecahkan. Di sudut pasar negeri panas, tancapkan sedotan dan seteguk saja, dahaga siang bolong pun mereda seketika. Aroma manis sejuk yang menyebar penuh di dalam mulut membawa serta keteduhan tropis."},"ICON-1323":{"nm":"Minyak Kelapa","de":"Ketika membeku, ia putih seperti salju pertama; dihangatkan di telapak tangan, aromanya menyebar perlahan. Kebijaksanaan rumah tangga yang penuh kasih dari seorang nenek di pulau—yang menyerahkannya sambil berkata satu toples saja cukup dari ujung rambut sampai ujung kaki—tersimpan utuh di dalam toples bundar ini."},"ICON-1324":{"nm":"Pisang Kering","de":"Dijemur di bawah matahari selama beberapa hari, daging kuningnya jadi kenyal. Gigit sepotong demi sepotong dengan hemat, dan aroma manis lengket musim panen yang hujan itu diam-diam hidup kembali di dalam mulut. Manis yang matang perlahan menyimpan sebuah musim seperti itu."},"ICON-1325":{"nm":"Mangga Kering","de":"Daging buah yang lembek, dipekatkan di bawah matahari, terlahir kembali sebagai jeli warna madu. Rasa asam, manis, dan kenyal, ketiganya ada dalam satu potong, maka gulirkan perlahan di dalam mulut dan satu bungkus pun memanjangkan sore hari."},"ICON-1326":{"nm":"Nanas Kering","de":"Berbeda dari penampilan luarnya yang berduri, daging di dalamnya begitu kuning dan cerah. Dikeringkan di bawah matahari, keasamannya makin pekat, maka satu gigitan saja membuat sudut bibir terangkat sendiri. Kesan segar yang tersisa di ujung sepotong bertahan lama."},"ICON-1327":{"nm":"Keranjang Buah Tropis","de":"Warna-warna yang baru dipetik berpadu dalam satu keranjang. Oranye mangga, kuning pisang, keemasan nanas—sebelum tangan sempat terulur untuk memilih, musim panas sudah lebih dulu menyerbu lewat ujung hidung. Seranjang penuh yang mencerahkan hati hanya dengan memandangnya."},"ICON-1328":{"nm":"Ikatan Rumput Laut","de":"Rambut laut yang dikumpulkan dari batu karang saat air surut. Suara ombak terjalin dalam aroma asin lautnya, maka rendam perlahan dalam air dingin dan bau laut yang samar amis perlahan menyusup hingga ke dapur. Segenggam membentangkan lumpur pantai kecil di atas meja."},"ICON-1329":{"nm":"Hasil Laut Kering","de":"Segenggam laut yang dikeringkan hingga kenyal. Sobek mengikuti seratnya dengan tangan, dan bersama rasa asinnya, angin asin pelabuhan lama pun kembali terlepas. Sahabat lama di samping meja makan yang penuh kasih, yang dengan sendirinya membuat teringat semangkuk makgeolli."},"ICON-1330":{"nm":"Cumi Kering","de":"Sepuluh kakinya direntangkan rapi dan dijemur di bawah matahari. Panggang sebentar di atas api hingga aroma gurih naik, lalu sobek mengikuti seratnya. Dengan kekenyalan yang terasa itu, martabat sepiring camilan larut malam pun naik setingkat."},"ICON-1331":{"nm":"Ikan Asin","de":"Ditimbun dalam garam kasar, ikan belajar cara bertahan menghadapi waktu. Sepotong daging asin yang dalam saja bisa mengosongkan semangkuk nasi dalam sekejap—rahasia penuh kasih yang diwariskan nenek di tepi pantai lewat ujung jarinya."},"ICON-1332":{"nm":"Udang Asin","de":"Udang-udang kecil matang perlahan dalam garam, terlahir kembali sebagai rasa gurih yang dalam. Saat satu sendok dimasukkan ke dalam sawi putih di musim membuat kimchi, aroma asin itu menyebar ke seluruh halaman. Satu sendok itu yang menentukan rasa kimchi sepanjang tahun."},"ICON-1333":{"nm":"Ikan Teri","de":"Tubuh sebesar jari bertanggung jawab atas kedalaman satu panci kaldu. Dapur masa kecil tempat bercerita sambil melepas kepala dan isi perutnya—ikan yang kecil namun berdiri kokoh di jantung rumah tangga, penuh rasa syukur."},"ICON-1334":{"nm":"Kombu","de":"Pita hitam panjang yang tumbuh di dasar laut. Dimasukkan ke air dingin dan diangkat lembut tepat sebelum mendidih—itulah janji yang dijaga turun-temurun oleh tangan-tangan pembuat kaldu. Rasa gurih yang dalam tak pernah, sama sekali, terburu-buru."},"ICON-1335":{"nm":"Hijiki","de":"Tekstur yang berbintil-bintil meletup-letup di dalam mulut. Rumput laut yang mewarnai batu karang pantai jadi hijau saat musim semi—diaduk perlahan dengan bumbu, ia membentangkan laut kecil yang segar di sudut meja makan. Rasa mengunyah musim semi."},"ICON-1336":{"nm":"Tiram Mutiara","de":"Cahaya bundar yang dibentuk dari dekapan panjang di antara dua cangkang keras. Untuk mengubah ketidaknyamanan sebutir pasir menjadi permata, laut tak pernah sekali pun terburu-buru. Letakkan di telapak tangan dan bobot kesabaran panjang itu ikut terasa."},"ICON-1337":{"nm":"Hiasan Karang","de":"Dahan pohon laut yang dipahat ombak selama ratusan tahun. Tersentuh cahaya, ia menyebar jadi merah muda dan oranye, sehingga hanya dengan diletakkan diam di atas rak, satu ruangan pun terwarnai jadi pulau yang hangat. Bahkan tekstur kasar yang tersentuh ujung jari terasa akrab."},"ICON-1338":{"nm":"Kancing Kerang","de":"Di tempat daging kerang pernah tinggal, bagian dalamnya yang berkilau dipotong bundar. Dipasang di kerah baju, sebuah pelangi kecil berkilau di ujung jari setiap kali dikancingkan. Hadiah terakhir penuh kasih yang ditinggalkan laut saat pergi, setelah memberikan segalanya."},"ICON-1339":{"nm":"Kelereng Kaca","de":"Gulirkan di telapak tangan dan cahaya yang terperangkap di dalamnya ikut menggelinding bersamanya. Di masa saat berjongkok di gang bermain kelereng tanpa sadar matahari terbenam, saku anak yang berhasil merebut satu butir lagi terasa istimewa berat dan bangga."},"ICON-1340":{"nm":"Ukiran Kayu Juniper","de":"Pada setiap serat yang terpahat, aroma lembut meresap keluar. Orang-orang zaman dahulu membakar kayu ini untuk menenangkan hati yang kacau. Genggam satu potong dengan diam, dan ketenangan perlahan memenuhi dari ujung jari."},"ICON-1341":{"nm":"Dupa","de":"Satu batang tipis terbakar perlahan, membuka jalan ke atas. Ikuti dengan mata lengkungan yang digambar asapnya, dan hati yang terburu-buru sepanjang hari pun tanpa sadar memperlambat langkah dan berdiam tenang di tempatnya."},"ICON-1342":{"nm":"Bunga Pewarna","de":"Larutkan warna yang tersembunyi di dalam kelopak ke dalam panci mendidih, dan kain putih bersih perlahan terwarnai warna itu. Meminjam sejenak warna yang telah dilukis alam sebelumnya—mewarnai kain pada dasarnya adalah salam penuh kasih yang disampaikan kepada bunga."},"ICON-1343":{"nm":"Pewarna Nila","de":"Biru yang dalam dan lembut, diperoleh dari memfermentasi tanaman nila berulang kali. Setiap kali dicelup dan diangkat, kain perlahan berpindah warna dari biru langit ke biru laut. Warna penantian, yang baru mekar setelah ketergesaan diletakkan."},"ICON-1344":{"nm":"Pewarna Merah","de":"Rendam akar pewarna merah ini, dan semburat senja yang tertidur di dalam tanah pun terbangun di dalam panci. Warna paling meriah dan paling cerah di desa, yang dahulu mewarnai indah ujung rok pengantin baru pada hari pernikahan."},"ICON-1345":{"nm":"Benang Emas","de":"Emas yang ditarik lebih halus dari sehelai rambut dipintal seutas demi seutas dengan penuh ketelatenan. Di setiap tempat yang disulam, ia menyimpan cahaya, sehingga bahkan di kamar gelap dengan lampu padam, pola itu saja bangkit lembut bercahaya dengan sendirinya."},"ICON-1346":{"nm":"Sutra","de":"Benang yang dimuntahkan ulat sutra harus ditenun dan ditenun lagi hingga baru menjadi selembar kain. Sentuhan yang meluncur seperti air musim semi di punggung tangan—kain berserat halus yang dipeluk orang-orang zaman dahulu selama satu musim penuh dan ditumbuhkan perlahan."},"ICON-1347":{"nm":"Kancing Mutiara","de":"Hanya cahaya bagian dalam mutiara yang dipilih dan dibentuk bundar. Setiap kali dikancingkan satu di kerah jeogori, ujung jari sejenak menjadi anggun. Kecil namun bulir yang rapi ini diam-diam mengangkat martabat sebuah busana."},"ICON-1348":{"nm":"Pecahan Peta Pelayaran","de":"Di balik tepian yang robek, garis pantai yang tak diketahui terputus tiba-tiba. Konon hanya yang mengumpulkan pecahan sisanya yang bisa mencapai harta karun—namun bisa jadi perjalanan mengembara mencarinya mengikuti arah angin itu sendiri sudah menjadi harta karun."},"ICON-1349":{"nm":"Peta Laut Tua","de":"Jalur pelayaran yang luntur oleh air laut dan gambar kompas yang telah pudar. Telusuri dengan ujung jari garis yang digambar seorang pelaut hanya dengan bintang di malam yang gelap gulita, dan sebuah pulau yang lama menghilang perlahan muncul kembali di atas kertas tua itu."},"ICON-1350":{"nm":"Surat dalam Botol","de":"Selembar kertas yang tergulung di dalam botol kaca yang terdampar ombak. Kabar yang tak diketahui siapa dan kapan mengirimnya, akhirnya sampai ke tangan seseorang. Asalkan ada niat, laut pun bisa menjadi tukang pos yang selambat ini."},"ICON-1351":{"nm":"Peti Terdampar","de":"Petualangan berlangsung hingga saat tutup yang mengeras kaku terendam air asin itu berhasil dibuka. Entah yang menunggu di dalamnya harta karun atau sekadar pasir kosong, peti yang terdampar dari jauh selalu ikut membawa terdampar kisah seseorang yang wajahnya tak dikenal."},"ICON-1352":{"nm":"Kunci Kecil","de":"Sepotong logam usang yang pas menggenggam di telapak tangan. Meski pintu mana yang dibukanya telah lama terlupakan, bobot lembut yang membuat orang teringat cara membuka lebih dulu ketimbang cara mengunci masih tersisa berat di ujung jari."},"ICON-1353":{"nm":"Koin Perak","de":"Perak bundar yang polanya memudar karena tersentuh tangan berulang kali. Sekeping koin yang pernah menjadi ongkos perjalanan seseorang atau tempat menginap semalam yang melelahkan—usap permukaannya yang telah dingin, dan kehangatan sebuah transaksi lama samar-samar bangkit kembali di ujung jari."},"ICON-1354":{"nm":"Koin Emas","de":"Letakkan di telapak tangan dan bobotnya yang berat lebih dulu menggetarkan hati. Sekeping koin yang berkilau kuning tersinari matahari, seolah menjanjikan kekayaan bila dimiliki—namun yang sesungguhnya bersinar paling terang adalah debar jantung sesaat sebelum ia jatuh ke tangan."},"ICON-1355":{"nm":"Segel Kapten","de":"Janji sang kapten, yang ditekan kuat ke atas lilin merah. Satu pola saja bisa menegakkan perintah dan menentukan jalur pelayaran yang berat. Otoritas, pada akhirnya, hanyalah satu cap kecil yang kokoh, yang disepakati bersama untuk dipercaya oleh semua yang menumpang kapal yang sama."},"ICON-1356":{"nm":"Mikrofon Genggam","de":"Begitu digenggam, bobot yang aneh menenteramkan memenuhi telapak tangan. Baik saat menyampaikan sapaan pertama yang gemetar, maupun saat akhirnya melengking tinggi—satu batang kecil ini diam-diam memasang sayap pada suaramu."},"ICON-1357":{"nm":"Mikrofon Nirkabel","de":"Begitu kabelnya lenyap, seluruh panggung ikut melapang. Berlari sampai ke ujung kursi penonton pun suara tak pernah sekali pun terputus, seolah ada seseorang yang diam-diam mendorong punggungmu, menyuruhmu berlari dan bernyanyi sepuasnya."},"ICON-1358":{"nm":"Mikrofon Berdiri","de":"Berdiri kokoh di bawah kaki, ia diam-diam menunggu sang penyanyi. Ketika kedua tangan bebas, lagu menyebar ke seluruh tubuh, bukan hanya ujung jari. Ada keindahan yang jelas juga dalam menjaga satu tempat hingga akhir, begitu batang ini berkata diam-diam."},"ICON-1359":{"nm":"Pop Filter","de":"Selapis kain bundar yang menghalangi depan mikrofon. Ia menyaring lembut napas yang keras dan hanya meloloskan suara yang jernih. Membuat sesuatu terdengar jelas berarti diam-diam menahan dari tempat yang tetap tak terlihat hingga akhir."},"ICON-1360":{"nm":"In-Ear Monitor","de":"Selipkan pas ke dalam telinga, dan nyanyian sendiri kembali jernih terdengar di balik sorak-sorai puluhan ribu orang. Teman paling kecil dan paling diam-diam ini menjaga agar ketukan tak pernah terlewat di atas panggung yang dibanjiri cahaya dan suara."},"ICON-1361":{"nm":"Headphone","de":"Begitu menutup telinga, dunia menyusut sejengkal dan hanya lagu yang tersisa besar. Satu ruang bundar yang tak bisa disela siapa pun. Di dalam headphone yang dipakai sendirian, anehnya, terasa tidak sendirian."},"ICON-1362":{"nm":"Partitur","de":"Ketika titik-titik hitam hinggap diam di atas garis, kertas yang tadinya bisu mulai menyimpan suara. Tulisan yang bukan dibaca, melainkan didengar. Begitu dibuka, lagu yang tadinya berhenti bernapas kembali."},"ICON-1363":{"nm":"Partitur Vokal","de":"Sebuah lingkaran kecil digambar di setiap tempat untuk bernapas. Tarik napas di sini, lepaskan perlahan di sana. Selembar peta penuh kasih yang membuka jalan agar suara tak terluka."},"ICON-1364":{"nm":"Partitur Piano","de":"Halaman tempat sepuluh jari sekaligus bertanya arah. Tangan kiri memegang akar, tangan kanan menggambar lagu. Dua tangan yang bercerita hal berbeda, pada birama terakhir akhirnya bertumpuk menjadi satu."},"ICON-1365":{"nm":"Diagram Kunci Gitar","de":"Bahasa asing pertama yang dipelajari jari-jari, kata pertamanya tertulis di sini. Ketika enam titik berkumpul menjadi lingkaran, barulah satu nada menangis. Di setiap malam menekan dan menekan lagi, kapalan pun tumbuh di ujung jari."},"ICON-1366":{"nm":"Metronom","de":"Tik, tik—satu langkah yang tak tergoyahkan berdetak di samping. Ketika hati berlari lebih dulu, ia menahan perlahan, perlahan dari belakang. Sebab ketukan, pada akhirnya, adalah janji untuk berjalan bersama."},"ICON-1367":{"nm":"Tuner","de":"Ketika jarum meluncur ke tengah, barulah nada menemukan tempatnya. Titik tunggal itu, tak tinggi tak pula rendah. Ternyata sesuai itu artinya seperti ini—tak lagi bergetar, hanya diam-diam berhenti dengan tenang."},"ICON-1368":{"nm":"Kartu Tuts Piano","de":"Balik selembar demi selembar, dan tuts-tuts berjalan masuk ke telapak tangan. Dari do sampai si, semesta kecil tujuh kotak. Bahkan di malam tanpa piano sungguhan, lagu tumbuh diam-diam di sini."},"ICON-1369":{"nm":"Pick Gitar","de":"Kepingan kecil yang kokoh, terselip di antara ibu jari dan telunjuk. Jatuhkan dan ia lenyap selamanya di bawah kursi, namun begitu digenggam, keenam senar berdenting sekaligus."},"ICON-1370":{"nm":"Stik Drum","de":"Ketika kedua batang bertemu di udara, sebuah aba-aba jatuh di tempat itu. Satu, dua, tiga, empat. Semua jantung yang tadinya berserakan mulai berdetak pada kecepatan yang sama, mengikuti keempat ketukan itu."},"ICON-1371":{"nm":"Tamborin","de":"Sekali dikocok, suara jernih berhamburan ke segala arah seperti sinar matahari yang pecah berkeping-keping. Terlihat ringan, namun ia adalah ketukan pertama yang diraih tangan saat semangat mulai memudar. Sekecil apa pun, tak ada yang bisa meremehkannya."},"ICON-1372":{"nm":"Sneakers Dansa","de":"Bagi kaki yang berputar meluncur di atas lantai, gesekan menjadi senjata. Di setiap sol yang aus, terukir putaran demi putaran yang telah dilalui. Gerakan paling keren selalu dimulai dari sepasang sepatu yang kokoh."},"ICON-1373":{"nm":"Pelindung Lutut","de":"Hanya orang yang telah berlutut tak terhitung kali dan bangkit kembali yang tahu betapa berartinya selapis kain tipis ini. Sesuatu yang membuat lantai tak lagi menakutkan—keberanian kadang terbalut di lutut seperti ini."},"ICON-1374":{"nm":"Pelindung Pergelangan Tangan","de":"Bungkus lebih dulu tempat yang mudah terkilir, dan gerakan yang dipaksakan pun jadi lebih dimaafkan. Pergelangan tangan tak banyak bicara, bertahan sendirian hingga terasa sakit. Kesunyian panjang itu, selapis kain ini yang menahannya sebagai ganti."},"ICON-1375":{"nm":"Pelindung Pergelangan Kaki","de":"Di ujung lompatan yang tinggi ada pendaratan, dan di ujung pendaratan itu ada pergelangan kaki. Tempat paling rendah yang menampung bobot seluruh tubuh. Ikatan kecil ini diam-diam menjaga latihan hari esok."},"ICON-1376":{"nm":"Karet Peregangan","de":"Tarik dan ia melawan sebesar tarikan itu, berusaha kembali ke tempat semula. Selama menahan perlawanan itu, tubuh perlahan memanjang tanpa disadari. Kelenturan, pada akhirnya, adalah jejak yang ditinggalkan waktu yang dihabiskan untuk bertahan."},"ICON-1377":{"nm":"Matras Yoga","de":"Begitu dibentangkan, sebidang tanah untuk satu orang muncul di atas lantai. Wilayah kecil untuk tengkurap, berbaring, dan menata napas. Awal dan akhir hari diam-diam dirapikan di atas selembar ini."},"ICON-1378":{"nm":"Foam Roller","de":"Tekan perlahan tempat yang mengencang, dan mula-mula terasa sakit, lalu segera terasa lega. Selalu ada sedikit rasa sakit dalam melepaskan sesuatu yang telah kaku. Sebab tubuh maupun hati, keduanya harus ditekan sekali dulu agar bisa terurai."},"ICON-1379":{"nm":"Dumbel","de":"Angkat beban yang sama, lalu angkat lagi. Tepat satu kali lebih banyak dari kemarin, hanya itu saja. Dalam pengulangan yang tak ada gemerlapnya sama sekali, lengan menebal tanpa sepatah kata. Sebongkah besi yang hanya jujur belaka."},"ICON-1380":{"nm":"Kettlebell","de":"Dengan satu pegangan, seluruh tubuh terayun sekaligus. Ketika bobot yang bundar berputar menggambar lingkaran, keseimbangan sang penahan diuji. Agar tak goyah, ia harus lebih dulu mengenali pusat dirinya sendiri."},"ICON-1381":{"nm":"Tali Lompat","de":"Lompati satu tali yang melintas cepat di bawah kaki, dan lompati lagi. Seperti permainan menghitung bersama teman di halaman dulu, semakin tinggi angka bertumpuk, semakin tersengal napas dan semakin bertambah tawa."},"ICON-1382":{"nm":"Sepatu Lari","de":"Sepasang sepatu yang baru diketahui nilai sejatinya setelah berdiri di atas jalan. Membelah udara subuh dan berlari lagi di jalan yang sama, tikungan yang terasa jauh kemarin kini sudah ada di depan mata. Jarak diingat oleh kaki."},"ICON-1383":{"nm":"Handuk Olahraga","de":"Setelah keringat di dahi diseka, di sana meresap satu baris usaha hari ini. Meski bekasnya hilang saat dicuci, sebanyak yang telah dicucurkan tetap tertumpuk rapi di suatu tempat. Dukungan paling jujur selalu mengering di sisimu."},"ICON-1384":{"nm":"Botol Minum","de":"Kosong lalu diisi, kering lalu diteguk seteguk. Perjalanan bolak-balik sederhana itu diam-diam menopang satu hari. Seperti timba yang naik turun di sumur, hari pun kembali dimulai dari tindakan mengisi."},"ICON-1385":{"nm":"Protein Shake","de":"Kocok baik-baik lalu telan seteguk, dan otot yang hancur hari ini terisi kembali esok hari. Rasanya memang tak istimewa, tapi tubuh tahu ini adalah bahasa pemulihan. Pertumbuhan selalu diminum diam-diam."},"ICON-1386":{"nm":"Energy Bar","de":"Satu batang yang terjepit pipih di dalam saku. Bekal darurat yang mengisi waktu kosong di antara jam makan. Tak ada yang megah, tapi satu gigitan kecil ini membuatmu bertahan satu gerakan lagi di sore hari."},"ICON-1387":{"nm":"Permen Pelega Tenggorokan","de":"Gulirkan di dalam mulut, dan mentol yang menyegat lembut mengusap tenggorokan yang kasar. Di hari banyak bicara, di malam banyak bernyanyi—satu butir permen kecil menenangkan jalan yang menggelitik. Manis pun jelas ada gunanya."},"ICON-1388":{"nm":"Teh Vokal","de":"Uap hangat menghangatkan tenggorokan, dan seteguk saja ketegangan di bahu perlahan mengendur. Resep lama seperti teh jahe yang dulu direbuskan nenek. Sapaan penuh kasih yang disampaikan kepada suara sebelum bernyanyi."},"ICON-1389":{"nm":"Air Madu","de":"Larutkan perlahan sesendok madu ke dalam air hangat suam-suam. Cangkir yang biasa disuguhkan orang dewasa setiap kali tenggorokan terasa gatal serak. Bukan obat, bukan pula minuman, hanya rasa manis yang diam-diam membelai tubuh dari dalam."},"ICON-1390":{"nm":"Tangki Humidifier","de":"Wadah yang melepaskan kabut kecil ke dalam ruangan. Di malam musim dingin ketika udara kering mencakar tenggorokan, ia membagikan kelembapan tanpa terlihat. Merawat seseorang biasanya mengalir diam-diam seperti ini."},"ICON-1391":{"nm":"Kupon Istirahat","de":"Selembar kertas yang bertuliskan boleh beristirahat. Begitu diterima di tangan, beban di hati terasa satu ukuran lebih ringan. Bahwa berhenti pun adalah sebuah latihan—selembar tiket kecil ini yang memberi izin sebagai gantinya."},"ICON-1392":{"nm":"Jadwal Latihan","de":"Di atas waktu yang tertulis di setiap kotak, hari perlahan mengendap rapi. Pagi vokal, siang koreografi, malam istirahat. Bahkan esok yang tadinya terasa buntu, begitu digaris dan dibagi, tiba-tiba jadi terasa bisa dijalani."},"ICON-1393":{"nm":"Stempel Kehadiran","de":"Tekan kuat satu tanda bahwa hari ini pun telah hadir. Semakin banyak lingkaran yang tintanya sedikit belepotan bertambah di setiap kotak, ketekunan yang tadinya tak berarti apa pun tanpa sadar telah menjadi sebuah jalan. Bukti kecil setiap hari."},"ICON-1394":{"nm":"Stiker Pujian","de":"Alih-alih mengatakan kau hebat, sebuah bintang ditempelkan diam-diam. Kilauan sebesar kuku jari, namun begitu bertengger di sudut buku catatan, hari pun jadi cerah. Pujian memang kecil, tapi anehnya bersinar lama."},"ICON-1395":{"nm":"Catatan Mental","de":"Halaman tempat hati yang gemetar di balik panggung dilepaskan menjadi kata-kata. Bahkan hari yang tak berjalan lancar, jika dituliskan dengan jujur, entah bagaimana terasa jauh lebih ringan. Hati menjadi kokoh sebanyak ia ditatap dalam-dalam."},"ICON-1396":{"nm":"Kartu Latihan Visualisasi","de":"Pejamkan mata dan genggam, dan panggung diam-diam terbentang di dalam kepala. Berjalan satu putaran lebih dulu di tempat yang belum pernah dipijak. Jalur yang digambar dalam imajinasi tiba satu langkah lebih dulu daripada ujung jari kaki yang sesungguhnya."},"ICON-1397":{"nm":"Cermin Latihan Ekspresi","de":"Di depan cermin, tersenyum lalu menegang, wajah yang sama dibuat lebih dari seratus kali. Di sinilah dipelajari bahwa kebahagiaan maupun kesedihan sama-sama butuh latihan. Sebab ekspresi adalah pekerjaan menyalin hati ke luar."},"ICON-1398":{"nm":"Catatan Koreografi","de":"Halaman tempat jalur yang akan dilalui kaki dan lengan disalin menjadi gambar. Di setiap delapan ketukan, panah diam-diam menunjukkan ke mana tubuh harus bergerak. Bahkan gerakan yang susah payah dihafal pun perlahan menjadi jinak di atas halaman ini."},"ICON-1399":{"nm":"Chip Video Koreografi","de":"Ratusan gerakan tersimpan utuh di dalam satu chip kecil. Putar sekali lagi sebelum tidur, dan ujung jari bergerak dengan sendirinya mengikuti jalur itu. Pengulangan adalah satu lagi catatan, yang disalin lewat tubuh."},"ICON-1400":{"nm":"Peta Pergerakan Panggung","de":"Selembar peta panggung yang dilihat dari atas. Siapa bertemu di mana dan berpencar ke mana, sudah dijanjikan lebih dulu lewat garis dan titik. Untuk menggambar satu gambar bersama-sama, jalur harus dibagi lebih dulu."},"ICON-1401":{"nm":"Pas Gladi Resik","de":"Kursi penonton masih kosong dan lampu panggung masih tertidur. Selembar pas ini membawamu masuk ke dalam keheningan itu. Panggung saat tak ada yang menyaksikan, di situlah waktu untuk bertemu dirimu yang paling jujur dimulai."},"ICON-1402":{"nm":"Buku Gaya","de":"Dengan suasana hati apa aku akan berpakaian hari ini? Bahkan selembar kemeja punya perasaan yang cocok untuknya, buku ini diam-diam membisikkannya. Semakin banyak halaman dibalik, semakin banyak kepekaan kecil terkumpul di ujung jari yang dulu ragu di depan cermin."},"ICON-1403":{"nm":"Hairspray","de":"Cess, sekali semprot, bahkan angin pun tak bisa sembarangan mengacaukannya. Ambisi kecil untuk menahan beberapa menit di atas panggung agar tetap sempurna tanpa cela. Momen yang sempurna selalu tuntas di atas keras kepala sepele seperti ini."},"ICON-1404":{"nm":"Palet Rias","de":"Dua belas kotak warna adalah dua belas suasana hati. Ekspresi mana yang akan dipakai untuk bernyanyi hari ini, ujung jari memilih lebih dulu dan hati mengikutinya. Di setiap kotak yang mengosong, hari-hari yang ditinggalkan di panggung diam-diam membekas."},"ICON-1405":{"nm":"Peniti Kostum","de":"Di momen paling gemerlap, justru di tempat yang tak terlihat ada peniti kecil yang menahan kain. Agar tak melorot, agar tak berantakan. Kilau di atas panggung selalu berdiri di atas keteguhan seseorang."},"ICON-1406":{"nm":"Papan Nama","de":"Saat papan yang tadinya kosong terisi sebuah nama, satu janji yang samar menjadi jelas. Siapa yang akan berdiri di tempat ini, satu baris tulisan yang menentukannya. Nama adalah tekad tersingkat sekaligus paling teguh."},"ICON-1407":{"nm":"Kartu Fan Service","de":"Penerimanya hanya satu orang, dan bagi orang itu, itu adalah seluruh dunia. Perbuatan menekan rasa terima kasih beberapa malam ke dalam satu baris sapaan singkat. Hati bisa meluap seperti ini bahkan di atas kertas seukuran telapak tangan."},"ICON-1408":{"nm":"Kertas Latihan Tanda Tangan","de":"Pada awalnya, bahkan namamu sendiri terasa asing saat dituliskan. Melalui subuh demi subuh menggoreskannya seratus kali dan menghalusinya seribu kali, sampai tangan menghafal alurnya lebih dulu daripada hati. Begitulah sebuah nama akhirnya menjadi tanda tangan."},"ICON-1409":{"nm":"Lembar Pertanyaan Wawancara","de":"\"Harus jawab apa untuk pertanyaan ini.\" Ujung jari yang memegang kertas itu sedikit gemetar. Bukan menghafal jawaban, melainkan waktu untuk menata ketulusan satu per satu, sebab wawancara, seperti pengakuan hati, pada akhirnya adalah soal urutan hati."},"ICON-1410":{"nm":"Buku Kosakata Bahasa Asing","de":"Sudut yang paling lusuh menunjukkan kata yang paling lama ditatap. Sepanjang waktu yang dibutuhkan satu pelafalan asing untuk melekat di lidah, jarak ke dunia yang belum pernah dikunjungi pun mengecil sejengkal demi sejengkal."},"ICON-1411":{"nm":"Kartu Koreksi Pelafalan","de":"'R' yang bergulir, 'S' yang bocor keluar. Ada subuh-subuh yang dihabiskan membalik kartu satu demi satu, menjinakkan lidah. Sebanyak ucapan menjadi jelas, sebanyak itu pula wajah seseorang yang ingin dicapai dengan kata-kata itu menjadi jelas."},"ICON-1412":{"nm":"Daftar Periksa Siaran Langsung","de":"Mikrofon menyala, in-ear terperiksa, jalur pergerakan tercek. Setiap kotak yang terisi satu per satu, sebanyak itu pula kecemasan di dada mengosong satu kotak. Sebelum naik panggung, ketelitian adalah keberanian yang paling diam."},"ICON-1413":{"nm":"Plester Kondisi","de":"Ada titik yang menghangat begitu ditempelkan. Bahu yang tegang, betis yang kaku, penghiburan seukuran telapak tangan yang diam-diam menjawab sinyal-sinyal kecil dari tubuh. Beristirahat dengan baik juga bagian dari latihan."},"ICON-1414":{"nm":"Kompres Es","de":"Diletakkan pelan-pelan di pergelangan kaki yang bengkak. Baru saat rasa dingin perlahan meresap, kau akhirnya sadar seberapa jauh kau berlari hari ini. Pemulihan di balik panggung selalu datang tanpa suara seperti ini."},"ICON-1415":{"nm":"Pouch P3K","de":"Plester, obat pereda nyeri, cermin kecil. Ada momen ketika kantong kecil berisi hal-hal yang tampak biasa ini menjadi yang paling menenangkan. Kebaikan yang disiapkan lebih dulu bersinar paling terang di hadapan krisis yang tak terduga."},"ICON-1416":{"nm":"Kartu Isyarat","de":"Seseorang mengangkatnya diam-diam dari balik kamera. Satu kalimat yang nyaris terlupa tertulis rapi di sana. Di balik acara yang mengalir tanpa hambatan, selalu ada tangan seperti ini yang tak pernah tertangkap layar."},"ICON-1417":{"nm":"Amplop Misi","de":"Saat-saat sebelum merobek amplop adalah yang paling berdebar. Apa pun isinya, celah singkat yang berdebar karena belum tahu itu. Daya tarik acara varietas hidup utuh di dalam satu momen tersegel itu."},"ICON-1418":{"nm":"Name Tag","de":"Nama kecil yang tersemat di dada menggantikan sapaan pertama. Di antara orang-orang yang belum saling kenal, satu name tag memecah kecanggungan seperti es yang retak. Sejak nama itu dipanggil, sebuah hubungan pun dimulai."},"ICON-1419":{"nm":"Stiker Hukuman","de":"Selembar stiker yang ditempel di dahi orang yang kalah meledakkan tawa serempak. Terlalu akrab untuk disebut hukuman, hingga kekalahan pun menjadi kenangan yang dikenang lama. Tanda kecil nan hangat yang dibuat agar bisa tertawa bersama."},"ICON-1420":{"nm":"Kartu Hukuman Acak","de":"Sebelum diambil, tak ada yang tahu. Sepuluh putaran belalai gajah, atau satu kali aegyo. Di momen mempercayakan seluruh nasib pada selembar kertas, justru tawa itulah yang lebih dulu lepas terurai."},"ICON-1421":{"nm":"Kartu Petunjuk","de":"Sesuatu seperti uluran tangan yang diam-diam disodorkan ke tempat yang buntu. Ia tak memberi seluruh jawaban, tetapi menunjukkan arah. Petunjuk yang baik bukanlah jawaban, melainkan tindakan diam-diam menyerahkan keberanian untuk berpikir sekali lagi."},"ICON-1422":{"nm":"Kartu Kesempatan","de":"Satu kesempatan untuk membalikkan papan yang timpang dalam sekejap. Kapan kartu ini dikeluarkan yang menentukan kemenangan. Keberuntungan yang disimpan dan disimpan baru membuktikan nilainya di momen paling menentukan."},"ICON-1423":{"nm":"Kartu Time-Out","de":"Tak apa berhenti sejenak, kartu ini yang mengatakannya untukmu. Mengangkat tangan dengan percaya diri saat butuh napas, berhenti pun strategi yang sah, dan beristirahat dengan baik juga bagian dari kemampuan."},"ICON-1424":{"nm":"Tombol Tawa","de":"Klik, dan begitu ditekan, gelak tawa riang tumpah ruah seketika. Adegan yang benar-benar lucu memang butuh sedikit bantuan efek suara seperti ini. Kehangatan sebuah tempat menghangat justru dari lelucon kecil semacam ini."},"ICON-1425":{"nm":"Remote Efek Suara","de":"Satu tombol untuk tepuk tangan, satu lagi untuk sorakan cemooh. Seorang penyihir yang membentuk suasana hanya dengan ujung jari duduk diam-diam di ruang kendali. Penyutradaraan yang tak pernah tertangkap layar itulah yang membuat adegan itu bernapas hidup."},"ICON-1426":{"nm":"Papan Klap","de":"Tak, bersama suara yang renyah, satu adegan dimulai. Di antara puluhan kali NG dan satu kali OK, papan hitam ini menghitung setiap momen dengan jelas. Ia adalah ketukan pertama yang dilangkahi oleh rekaman."},"ICON-1427":{"nm":"Selotip Penanda","de":"Begitu ujung kaki menyentuh garis itu dengan tenang, lampu turun dengan lembut seolah sudah menunggu. Satu titik yang dihafal sampai usang, panggung akhirnya sempurna hanya dengan sehelai garis warna kecil yang digambar di lantai."},"ICON-1428":{"nm":"Filter Lampu","de":"Wajah yang sama pun berubah seutuhnya oleh warna cahaya. Fajar bersemayam dalam filter biru, senja dalam filter merah. Suasana tak pernah jauh, ia terlipat diam-diam di dalam selembar kertas warna yang tipis."},"ICON-1429":{"nm":"Baterai Kamera","de":"Begitu lampu merah mulai berkedip, hati pun mulai gelisah lebih dulu. Sebab adegan terbaik selalu datang tepat di sisa 1 persen. Satu cadangan di saku segera menjadi kelegaan untuk menarik napas."},"ICON-1430":{"nm":"Kartu Memori","de":"Tawa dan keringat sehari penuh terisi padat dalam sebuah chip seukuran kuku. Terlalu kecil hingga mudah hilang, dan karena itu pula terasa lebih berharga. Bobot kenangan yang dikandungnya tak pernah bisa diukur dengan ukuran."},"ICON-1431":{"nm":"Film Polaroid","de":"Cekrek, lalu penantian yang tenang. Beberapa detik saat wajah perlahan muncul di atas permukaan yang tadinya putih itu entah mengapa terasa berdebar. Bahkan foto instan di tangan pun butuh tepat satu sendok kesabaran."},"ICON-1432":{"nm":"Film Photocard","de":"Ekspresi apa yang akan tercetak di selembar ini masih rahasia sampai detik sebelum dicetak. Wajah yang akan menjadi bias seseorang lahir tepat di sini. Selembar kertas kecil menyimpan hati yang begitu besar."},"ICON-1433":{"nm":"Sleeve Photocard","de":"Photocard tak pernah disentuh dengan tangan kosong. Sekali tertekan sudutnya, bahkan senyum hari itu pun terasa nyeri. Membungkus bias dengan penuh hati-hati dalam selembar plastik bening, bahkan menyayangi pun butuh kesungguhan sebesar ini."},"ICON-1434":{"nm":"Toploader","de":"Diselipkan di antara dua lembar keras, bahkan waktu pun tak bisa sembarangan meremukkannya. Jangan melengkung, jangan terlipat. Menjaga sesuatu yang berharga selalu meminjam selapis kekokohan."},"ICON-1435":{"nm":"Paket Stiker","de":"Dilepas satu per satu, ditempel di sudut diary, di belakang laptop. Dengan satu gambar kecil, hari yang tadinya tanpa warna menjadi berwarna-warni. Tak ada batas usia untuk keinginan menghias sekeliling."},"ICON-1436":{"nm":"Spidol Tanda Tangan","de":"Seiring suara tinta yang berbisik melintasi kertas, antrean semakin memanjang. Di atas album yang disodorkan dengan tangan gemetar, pertemuan hanya beberapa detik itu membekas lama sekali. Hati menyeberang melalui ujung pena."},"ICON-1437":{"nm":"Album Bertanda Tangan","de":"Buka sampulnya dan tanda tangan berlekuk yang familiar menyapa lebih dulu. Ikatan yang terjalin lewat musik menjadi sejengkal lebih dekat di atas kertas. Menyimpannya berarti diam-diam menghentikan momen itu di tempatnya."},"ICON-1438":{"nm":"Baterai Lightstick","de":"\"Nyala, kumohon.\" Tangan sibuk mengganti baterai tepat sebelum masuk. Agar di antara puluhan ribu cahaya, satu milikku tak padam, baterai kecil ini menerangi malam yang begitu besar itu."},"ICON-1439":{"nm":"Pouch Lightstick","de":"Rapi tanpa satu goresan pun, terjaga baik-baik sampai sorakan malam berikutnya. Meski tempat yang tadinya panas sudah sepenuhnya dingin, ia dibawa pulang dengan hati-hati. Alat untuk bersorak pun punya tempatnya sendiri, dan ada hati yang merawat tempat itu."},"ICON-1440":{"nm":"Spanduk Slogan","de":"Kalimat yang tertulis di atas kain panjang terbentang melintasi bangku penonton. Di momen dukungan yang terlalu berat untuk diucapkan itu terbuka lebar, ketulusan satu orang menjadi teriakan semua orang. Kain itu sendiri menjadi suara."},"ICON-1441":{"nm":"Banner Mini","de":"Dukungan kecil yang pas di telapak tangan. Spanduk besar yang tergantung jauh adalah milik semua orang, tetapi yang ini berkibar hanya di ujung mejamu. Bergoyang pelan, ia membuktikan bahwa kecil ukurannya tak berarti hatinya ikut kecil."},"ICON-1442":{"nm":"Surat untuk Idola","de":"Kutulis ulang nama penerima tiga kali dan kuhapus kalimat pertama tujuh kali. Ujung jariku gemetar tepat sebelum menutup amplop, karena hatiku terlalu jujur. Ketulusan yang lebih berat dari selembar perangko terlipat di dalamnya."},"ICON-1443":{"nm":"Kertas Kado","de":"Kertas kado tahu lebih baik dari siapa pun bahwa satu detik sebelum dibuka adalah momen yang paling berdebar. Meski tahu nasibnya akan segera disobek, ia tetap membalut dirinya dengan tekstur paling indah, menyerupai hati orang yang memberikannya."},"ICON-1444":{"nm":"Pita","de":"Diikat terlalu kencang terasa sesak, terlalu longgar mudah lepas, jadi menemukan titik tepat di antaranya itulah kesungguhan. Bentuk hati tersimpan dalam satu simpul yang dipilih ujung jari. Baris terakhir sebuah hadiah selalu ditulis oleh pita, menggantikan kata-kata."},"ICON-1445":{"nm":"Kartu Ucapan Terima Kasih","de":"Ucapan terima kasih yang diucapkan lisan menghilang tertiup angin, tetapi yang ditulis tangan bertahan lama. Perbuatan mengembalikan kebaikan yang diterima, dengan sedikit tambahan di atasnya. Selama menuliskan setiap huruf dengan tekanan, hati pun semakin dalam dua kali lipat."},"ICON-1446":{"nm":"Kupon Bekal Makan Siang","de":"Dengan selembar kertas ini, kekhawatiran soal makan siang pun mencair perlahan. Nasi yang baru matang dengan uap mengepul, semangkuk lauk yang mengisi setiap sekat sudah dijanjikan. Jimat kecil yang menjaga sore hari yang lapar dengan kokoh."},"ICON-1447":{"nm":"Kupon Camilan","de":"Diciptakan untuk dikeluarkan pukul tiga sore, saat rasa lapar ringan mulai memberi isyarat samar. Kupon yang tahu satu camilan manis kecil bisa mengangkat suasana hati setengah jengkal. Bukan hadiah besar, tetapi tiba pelan-pelan tepat di saat dibutuhkan."},"ICON-1448":{"nm":"Kupon Kafe","de":"Secangkir hangat dan satu kursi di dekat jendela, itulah semua yang dijanjikan kupon ini. Terkesan sepele, tapi bagi seseorang ini menjadi hadiah kecil karena bertahan seharian. Undangan hangat yang aromanya tiba selangkah lebih dulu."},"ICON-1449":{"nm":"Voucher Bersih-Bersih Asrama","de":"Jendela dibuka lebar, selimut dikebas-kebas, hari saat bahkan sebutir debu pun kabur. Siapa sangka tak perlu melakukannya sendiri bisa terasa semewah ini. Saat kamar berkilau, hati pun diam-diam ikut tertata."},"ICON-1450":{"nm":"Kit Perbaikan","de":"Obeng, selotip, beberapa komponen yang tak jelas asalnya. Kalau terkumpul semua, sepertinya tak ada yang tak bisa diperbaiki, tetapi begitu dibuka selalu ada satu yang kurang. Meski begitu, kotak kepercayaan diri yang entah mengapa terasa menenangkan begitu digenggam."},"ICON-1451":{"nm":"Tiket Keberuntungan","de":"Selembar tiket kosong tanpa kursi dan tanpa nomor. Intinya justru karena tak tertulis hal baik apa yang akan datang hari ini. Mengisi kekosongan itu adalah tugas orang yang membawanya di saku."},"ICON-1452":{"nm":"Dadu","de":"Sahabat yang paling paham arti kata adil. Ia tak memihak siapa pun dan mencintai keenam sisinya sama rata. Untuk momen ia meninggalkan telapak tangan dan berguling menggelinding itu, bahkan kemampuan dan koneksi pun sejenak menyerahkan tempatnya pada keberuntungan."},"ICON-1453":{"nm":"Tiket Perjalanan","de":"Janji bahwa dari sini ke sana, satu langkah saja cukup. Selembar kertas ajaib yang melipat jalan jauh menjadi kecil dan menyimpannya di saku. Di hari kau ragu untuk berangkat, tak ada penghalang alasan sebaik ini."},"ICON-1454":{"nm":"Tiket Coba Lagi","de":"Alih-alih mengulurkan tangan pada yang jatuh, ini adalah tiket yang diam-diam mendorong punggung, menyuruh mencoba lagi. Ia memberitahu paling lembut bahwa kegagalan bukan akhir, melainkan koma sesaat. Keberanian untuk sekali lagi terisi penuh di sini."},"ICON-1455":{"nm":"Tiket Penyelesaian Cepat","de":"Cheat key yang lembut, melompati sedikit masa tunggu. Siapa yang bisa menyalahkan hati yang tak sanggup menunggu bahkan 3 menit? Di sini ada kesenangan yang sedikit curang, seperti mendorong pasir jam pasir dengan jari."},"ICON-1456":{"nm":"Booster Produksi","de":"Tangan yang sama, waktu yang sama, tetapi hasilnya dua kali lipat. Berputar riang di atas meja kerja seolah berkata jangan tanya rahasianya. Alat kecil yang diam-diam memberi sayap pada dua tangan yang rajin bergerak."},"ICON-1457":{"nm":"Permen Keakraban","de":"Bahkan kecanggungan yang sulit diurai dengan kata-kata meleleh perlahan di depan sesuatu yang manis. Ikatan yang menjadi sejengkal lebih dekat dari kemarin lewat sebutir permen yang dibuka bersama. Penemuan kecil yang menggemaskan, bahwa manis adalah kecepatan menjadi akrab."},"ICON-1458":{"nm":"Jeli Pemulih Suasana Hati","de":"Di hari yang menyedihkan, sesuatu yang dingin dan kenyal langsung manjur. Satu gigitan saja dan raut wajah yang mendung diam-diam mengendur. Memperbaiki hati memang sesuatu yang berharga, jadi grade R bukan tanpa alasan disematkan."},"ICON-1459":{"nm":"Bubuk Kilau","de":"Ditaburkan sedikit di atas sesuatu yang biasa, tiba-tiba jadi istimewa. Wujud aslinya hanya bubuk berkilau, tetapi begitu ditaburkan dunia terlihat sedikit lebih semarak, sungguh ajaib. Seperti bumbu kebahagiaan yang dipercikkan pada keseharian."},"ICON-1460":{"nm":"Selotip Panggung","de":"Berdiri di atas panggung, tak terhitung lampu sekaligus mencarimu. Sebuah X kecil di lantai diam-diam menandai tempat itu. Yang paling presisi dari tempat yang tak terlihat itulah yang akhirnya menopang panggung terbesar."},"ICON-1461":{"nm":"Cable Tie","de":"Pahlawan kecil yang merapikan kabel-kabel kusut sekaligus dalam satu gerakan. Bahwa sekali dikencangkan tak bisa dikembalikan lagi adalah sekaligus kelemahan dan daya tariknya. Barang wajib yang diam-diam disiapkan oleh mereka yang serius soal kerapian."},"ICON-1462":{"nm":"Kabel Cadangan","de":"Barang yang tak terasa keberadaannya saat ada, baru dirindukan sungguh-sungguh saat tak ada. Tertidur dalam-dalam di dasar tas belakang panggung, ia terbangun mendadak di momen yang menentukan. Ia membuktikan kata kesiapsiagaan dengan seluruh dirinya."},"ICON-1463":{"nm":"Lembar Cek Gladi Resik","de":"Kertas yang padat kotak demi kotak, mulai dari jalur pergerakan, cue, hingga pergantian kostum. Jika satu saja centang di sini terlewat, hati seseorang pun tersentak. Panggung yang sempurna baru mengangkat tirainya setelah lembar ini terisi penuh."},"ICON-1464":{"nm":"Papan Petunjuk Set Syuting","de":"Di sini kafe, di sana gang, ikuti anak panah dan masuklah ke dunia yang sama sekali berbeda. Kebohongan yang dilukis di atas kayu lapis, tetapi di depan kamera ia menjadi nyata. Pemandu jujur yang mengabdikan seluruh hidupnya untuk menunjukkan arah."},"ICON-1465":{"nm":"Piala Mini","de":"Sekeping emas yang entah mengapa membuatmu terasa sejengkal lebih tinggi begitu diterima. Ia berkilau di atas meja, seolah berkata tak apa tak jadi juara satu, ia tahu semua kerja kerasmu hari ini. Penghiburan besar yang diberikan oleh hadiah kecil."},"ICON-1466":{"nm":"Ransel","de":"Begitu diselempangkan di punggung, rasanya bisa berangkat ke mana saja. Isinya mungkin tak seberapa, tetapi kemungkinannya penuh sampai ke tepi. Petualangan selalu dimulai dari perbuatan mengencangkan tali bahu ini erat-erat."},"ICON-1467":{"nm":"Kompas","de":"Tersesat pun tak panik, karena ujung jarumnya selalu menunjuk utara. Cara ia bergoyang cukup lama sebelum akhirnya menemukan tempatnya sendiri sungguh mirip hati manusia. Tak apa tersesat, ia mengatakannya lewat ujungnya yang gemetar."},"ICON-1468":{"nm":"Buku Catatan","de":"Halaman pertama selalu kosong. Apa yang akan ditulis hanya diketahui oleh orang yang memegang pena. Aku hanya menunggu, agar pikiran hari ini menjelma tulisan dan turun tenang di atasku. Grade R adalah bobot kemungkinan yang segera terisi."},"ICON-1469":{"nm":"Pensil","de":"Bahwa tak apa salah adalah sisi paling lembut dari alat ini. Selama penghapus sahabatnya ada di sisi, kau bisa memulai lagi berapa kali pun. Semakin diraut semakin pendek, tetapi kependekan itu bukti betapa lama ia dicintai."},"ICON-1470":{"nm":"Film","de":"Saat cahaya menembus, warna hari itu terpatri utuh. Bahwa sekali satu bingkai berlalu tak bisa dikembalikan lagi adalah sekaligus ketegangan dan daya tariknya. Pilihan mereka yang sengaja mengingat satu ketukan lebih lambat di zaman yang serba cepat."},"ICON-1471":{"nm":"Kamera Instan","de":"Cekrek, lalu sebentar penantian. Digenggam sambil dikibas pelan, momen yang buram perlahan menjadi jelas. Mesin yang sedikit ajaib, menangkap tempat ini apa adanya ke atas selembar kertas."},"ICON-1472":{"nm":"Foto Lama","de":"Sebanyak warnanya memudar, sebanyak itu pula waktu telah berlalu. Di setiap sudut yang usang, sentuhan seseorang pernah singgah. Bahwa foto tertua menyimpan kenangan paling jelas, mungkin karena sentuhan-sentuhan itu."},"ICON-1473":{"nm":"Buku Kliping","de":"Serpihan-serpihan yang sayang dibuang berkumpul dan berkumpul menjadi satu jilid. Tiket bioskop yang memudar, kelopak bunga kering, satu memo pendek. Di mata orang lain mungkin hanya barang bekas, tetapi bagi yang membukanya, satu musim utuh terhidupkan kembali."},"ICON-1474":{"nm":"Buku Catatan Pelayaran","de":"Angin dan ombak hari ini, dan satu baris tentang hati. Menuliskannya dengan setia bahkan di hari-hari tanpa kejadian apa pun adalah aturan pelayaran. Bukti bahwa kau tiba dengan selamat selalu tertulis di suatu tempat dalam catatan tebal ini."},"ICON-1475":{"nm":"Pecahan Peta","de":"Hanya satu sudut dari keseluruhan, tetapi tanpanya kau tak akan pernah menemukan jalan. Betapa nikmatnya saat sisi yang robek pas berpadu dengan pecahan lainnya. Grade R memiliki kehadiran seperti kepingan terakhir sebuah puzzle."},"ICON-1476":{"nm":"Surat dalam Botol","de":"Tanpa tahu siapa yang akan membacanya, ia mempercayakan dirinya dengan tenang pada ombak. Ia tak mengharap balasan, hanya berharap hati ini sampai ke suatu tempat. Cara mengirim surat yang paling lambat namun paling romantis."},"ICON-1477":{"nm":"Dadu","de":"Enam sisi yang tersenyum bulat seolah berkata, kamu lagi? Bentuk yang sama, tetapi memberi jawaban berbeda setiap kali digulirkan adalah keisengan sahabat ini yang tak pernah berubah. Di momen ia meninggalkan tanganmu, kau sejenak mempercayakan pilihan pada takdir."},"ICON-1478":{"nm":"Kincir Angin","de":"Ia baru hidup ketika angin bertiup. Dibiarkan diam, ia hanyalah sayap kertas, tetapi begitu seseorang meniupnya, ia mulai berputar riang. Tak malu menerima bantuan adalah kebijaksanaan bunga kecil ini."},"ICON-1479":{"nm":"Keranjang Piknik","de":"Buka tutupnya dan aroma gimbap menyapa lebih dulu. Rumput hijau, tikar yang digelar, dan tangan-tangan yang berbagi makanan dengan tangan lain. Hari-hari keranjang ini penuh, anehnya, langitnya selalu cerah."},"ICON-1480":{"nm":"Vas Bunga","de":"Menaruh satu tangkai saja pun mengubah udara ruangan. Saat kosong, menunggu dengan diam adalah tugasnya yang sebenarnya. Perangkat panggung paling rendah hati di dalam ruangan, merendahkan keberadaannya sendiri agar bunga lebih bersinar."},"ICON-1481":{"nm":"Kelopak Bunga","de":"Ketika angin membawa satu lembar pergi, musim semi menjadi seringan itu. Pohon tua di halaman menyampaikan sapaan yang sama setiap tahun, bahwa gugur pun adalah satu bagian dari pekerjaan mekar. Berhamburan bukanlah akhir, melainkan surat yang dikirim lebih dulu untuk musim semi berikutnya."},"ICON-1482":{"nm":"Mawar","de":"Menegakkan duri lebih dulu adalah janji untuk tidak disentuh sembarangan. Di baliknya tersembunyi hati yang paling merah. Seseorang meletakkan setangkai dengan tenang di kaki dan pergi, menuliskan hatinya hanya lewat warna, bukan nama."},"ICON-1483":{"nm":"Bunga Lili","de":"Di samping porselen putih yang bersih, bunga putih ini selalu diletakkan. Semoga aromanya menjangkau jauh namun sikapnya tak pernah goyah. Di tempat itu, tempat ia memilih kesucian alih-alih kemewahan, lili diam-diam menjaga satu takaran keanggunan."},"ICON-1484":{"nm":"Tulip","de":"Berdiri berbaris dengan kepala sedikit tertunduk, entah mengapa terlihat begitu rapi. Bunga yang mengambil alih barisan depan taman musim semi. Kejujurannya mekar serentak dan gugur serentak mewarnai musim yang singkat itu paling pekat."},"ICON-1485":{"nm":"Hiasintus","de":"Pada satu tangkai, ia menggantungkan lonceng-lonceng kecil dengan rapat. Dikibaskan pun tak bersuara, tetapi aromanya yang menggantikan gema di dalam ruangan. Di ambang musim semi, kemewahan lembut yang mengganti seluruh udara ruangan hanya dengan satu vas."},"ICON-1486":{"nm":"Spesimen Katak","de":"Tubuh kecil yang waktunya berhenti di dalam kotak kaca. Labelnya tertulis, 'Sawah dan waduk, paling bersemangat sehari setelah hujan.' Baru setelah berhenti, bahkan suhu tepi air tempat satu makhluk hidup pernah tinggal pun tersisa sebagai catatan."},"ICON-1487":{"nm":"Spesimen Kadal","de":"Bahkan sebagai spesimen, kecerdikannya memutus ekor dan kabur tak bisa terhapus. Tamu kecil yang menyukai tembok batu yang hangat oleh matahari. Catatan di sampingnya menuliskan dengan rapi arah tempat cerah yang senang ia panjat."},"ICON-1488":{"nm":"Catatan Tikus Tanah","de":"Buku harian sang penjelajah bawah tanah ditulis dalam serat tanah. Ke mana ia menggali dan di mana ia berhenti, sebuah peta jalan yang tak terlihat. Waktu yang dijalani dengan membelakangi cahaya pun menjadi catatan yang begitu tekun bagi seseorang."},"ICON-1489":{"nm":"Spesimen Kerang","de":"Pola kokoh yang dipoles ombak beribu-ribu kali. Orang-orang pesisir bisa tahu dari laut mana asalnya hanya dengan melihat serat cangkangnya. Bentuk laut yang dulu pernah hidup dan bernapas tersimpan utuh dalam spesimen seukuran telapak tangan."},"ICON-1490":{"nm":"Spesimen Karang","de":"Di kedalaman laut, ia hanya tumbuh sejengkal dalam ratusan tahun. Terlihat seperti ranting, tetapi sebenarnya adalah rumah yang dibangun bersama oleh begitu banyak kehidupan kecil. Bahwa yang lebih lambat bertahan lebih lama, karang membuktikannya dalam diam."},"ICON-1491":{"nm":"Petunjuk Aidong","de":"Satu penggalan cerita yang tersebar di suatu tempat di pulau. Selembar kertas kecil diam-diam menunjukkan langkah berikutnya. Setiap petualangan, pada akhirnya, dimulai dari memungut jejak sepele seperti ini, kata sang pemandu tua."},"ICON-1492":{"nm":"Kepingan Tanda Tangan","de":"Ketika pola yang berserakan menemukan tempatnya, satu tanda pun akhirnya sempurna. Kepingan yang terukir dengan corak unik seseorang. Sebelum tersusun, ia menyembunyikan maknanya, dan tepat saat tersusun, ia baru menjadi sebuah nama."},"ICON-1493":{"nm":"Kepingan Kenangan Panggung","de":"Meski satu lagu berakhir, panas sisa masih tertinggal di bangku penonton. Kupas kehangatan itu dan bekukan, jadilah kepingan kecil seperti ini. Serpihan-serpihan tepuk tangan dan sorakan yang berserakan, jika dikumpulkan dengan tenang, malam itu terhidupkan kembali secara utuh."},"ICON-1494":{"nm":"Stempel Debut","de":"Hari saat namamu pertama kali dipanggil, bekas tinta yang tercap di punggung tangan. Bahkan kehati-hatian mengeringkannya agar tak luntur pun adalah bagian dari garis start itu. Satu stempel kecil membuat suatu hari tak pernah terhapus selamanya."},"ICON-1495":{"nm":"Medali Idola Puncak","de":"Bobot yang hanya diizinkan bagi mereka yang mencapai tempat tertinggi. Namun medali ini berat bukan karena logamnya. Melainkan karena bobot begitu banyak tangan yang bersama-sama mengisi panggung itu berkumpul utuh di satu titik."},"ICON-1496":{"nm":"Kunci Kecil","de":"Kunci pertama asrama selalu untuk kamar paling dalam. Tempat di mana kau belajar cara membuka lebih dulu daripada cara mengunci. Di hari kepergian, kehangatan yang ditinggalkan telapak tangan bertahan lama di atas logam yang dingin."},"ICON-1497":{"nm":"Peti Harta Karun","de":"Sebelum dibuka, tak seorang pun tahu apa isinya. Ketidaktahuan itulah harta karun sesungguhnya dari peti ini. Di momen singkat mengangkat tutupnya, siapa pun kembali sejenak ke debaran masa kanak-kanak."},"ICON-1498":{"nm":"Cetak Biru","de":"Di atas garis yang digambar kotak demi kotak, hidup sebuah bangunan yang belum berdiri. Membentangkan gambar rancangan adalah berjalan melewati hari esok lebih dulu sekali. Satu garis yang digambar dengan baik menopang hari esok yang tak akan runtuh."},"ICON-1499":{"nm":"Kartu Resep","de":"Pada selembar kartu yang lusuh oleh sentuhan tangan, cita rasa nenek tertulis dalam takaran. Kata yang samar seperti 'sejumput garam' adalah rahasia yang paling tepat. Semakin pudar tulisannya, semakin jelas terbayang dapur tempat masakan itu dulu direbus."},"ICON-1500":{"nm":"Izin Fasilitas","de":"Selembar kertas mengubah lahan kosong menjadi 'tempat yang bisa digunakan.' Bangunan baru biasanya butuh stempel desa lebih dulu. Izin, pada akhirnya, adalah cap hangat yang mengatakan tak apa memulai sesuatu di sini."},"ICON-1501":{"nm":"Izin Pelabuhan","de":"Sebelum kapal bisa melabuhkan sauh, selembar surat ini harus ada lebih dulu. Stempel pudar pelabuhan adalah sapaan pertama bagi mereka yang datang dari jauh. Di antara kepergian dan kedatangan, pelabuhan selalu membuka hatinya dengan selembar kertas."},"ICON-1502":{"nm":"Tanda Warga Pulau","de":"Sertifikat kecil yang menandakan kau kini menjadi bagian dari pulau ini. Dahulu, ketika tetangga baru datang, desa lama akan menambahkan namanya ke dalam daftar dan membagikan kue beras hangat. Hanya selembar kertas, namun di sana tertulis sambutan cerah: 'Sekarang kau juga salah satu dari kami.'"},"ICON-1503":{"nm":"Papan Nama Kamar","de":"Dengan sebuah nama tergantung di samping pintu, kamar kosong akhirnya menjadi rumah seseorang. Bahkan di paviliun tamu zaman dahulu, papan berukir nama sang tuan rumah adalah yang pertama dipasang. Papan nama memang kecil, namun di dalamnya penuh kehangatan bahwa 'di sini ada seseorang yang tinggal.'"},"ICON-1504":{"nm":"Perangko Fandom","de":"Bahkan ketelitian menjilat dan menekannya erat-erat adalah bagian utuh dari sepucuk surat. Menempelkan perasaan sayang pada secarik kertas kecil lalu mengirimkannya jauh. Di era digital sekalipun, ada saja yang tetap mengirim hatinya dengan tangan sendiri."},"ICON-1505":{"nm":"Lencana Pulau Berkilau","de":"Disematkan di kerah, cahaya kecil itu mengikuti ke mana pun langkah pergi. Bertemu orang dengan lencana yang sama di jalan, hati langsung terhubung tanpa sepatah kata. Kilauan ini bukan kebanggaan, melainkan sinyal diam-diam: 'kita mencintai pulau yang sama.'"},"ICON-1506":{"nm":"Meja Kerja","de":"Permukaan penuh goresan ini menjadi saksi tangan yang paling banyak berkarya. Tempat sesuatu diperbaiki, disambung, dan dihaluskan. Dibanding meja yang bersih, meja kerja yang berantakan justru menyimpan jauh lebih banyak cerita."},"ICON-1507":{"nm":"Kotak Penyimpanan","de":"Semakin berharga sesuatu, semakin dahulu tempatnya ditentukan. Orang-orang zaman dahulu pun menyimpan dokumen berharga secara terpisah dalam peti kayu paulownia. Menyimpan dengan baik pada akhirnya adalah melipat hari ini rapi-rapi, untuk seseorang di masa depan."},"ICON-1508":{"nm":"Peti Perbekalan","de":"Saat berlebih, dikumpulkan; saat kurang, dikeluarkan. Di sinilah tersimpan kebijaksanaan zaman ketika lumbung yang penuh berarti hati yang tenang. Menyimpan persediaan adalah menyerahkan sepiring makanan penuh kasih kepada diri sendiri di masa depan."},"ICON-1509":{"nm":"Kotak Pendingin","de":"Peti yang diisi es ini menjaga kesejukan bahkan di puncak musim panas. Seolah kearifan lama gudang es diwariskan dalam ukuran segenggam tangan. Menjaga dingin berarti membuat momen paling segar bertahan sedikit lebih lama."},"ICON-1510":{"nm":"Pompa Air","de":"Gerakkan pegangannya naik turun, dan air dari dalam tanah pun menyembur ke atas. Mesin jujur yang baru mengalir deras setelah dituangi seciduk air pancingan. Bahwa harus memberi dahulu untuk menerima, itulah yang sejak lama dipahami di tepi sumur."},"ICON-1511":{"nm":"Penjernih Air","de":"Keajaiban kecil ketika air keruh menjadi jernih, lapis demi lapis. Orang zaman dahulu menyaring air dengan menumpuk pasir dan arang berlapis-lapis dalam guci tanah. Kejernihan bukanlah sesuatu yang didapat cuma-cuma, melainkan ketelatenan menyaring perlahan."},"ICON-1512":{"nm":"Rak Penyiram Bunga","de":"Begitu penyiram bunga menemukan tempatnya beristirahat, hari di petak bunga pun menjadi rapi. Menentukan tempat menggantung alat adalah kebiasaan orang yang mencintai pekerjaannya. Ketika satu tempat sudah pasti, seluruh halaman menjadi jauh lebih tertata."},"ICON-1513":{"nm":"Rak Joran Pancing","de":"Sampai sensasi tarikan ikan itu datang, orang boleh pergi, tapi joran tetap menjaga tempatnya. Sikap sabar memancing waktu di tepi sungai tertanam persis di sini. Rak, pada akhirnya, adalah sandaran untuk sejenak meletakkan ketergesaan."},"ICON-1514":{"nm":"Keranjang Pemungut","de":"Bawaan tangan seorang ibu, membawa segenggam sayur liar dan sekuntum bunga ladang. Dari celah anyaman bambu, aroma tanah samar-samar menyeruak keluar. Tergantung apa yang diisikan, keranjang kosong bisa menjadi musim semi atau musim gugur."},"ICON-1515":{"nm":"Lesung dan Alu","de":"Duk, duk, menumbuk biji-bijian dengan ketukan tetap membangunkan hari desa. Alat yang suara tumbukannya dahulu memenuhi lorong-lorong saat hari raya. Membuat yang keras menjadi lembut membutuhkan irama tangan yang tekun."},"ICON-1516":{"nm":"Talenan","de":"Setiap bekas sayatan pisau mengukir sejarah satu kali makan. Papan kayu penuh goresan adalah lencana kehormatan bagi tangan tersibuk di dapur. Memotong sesuatu bermula dari niat untuk menyajikannya dengan sepenuh hati."},"ICON-1517":{"nm":"Panci","de":"Suara mendidih yang berdesir lebih lembut daripada musik apa pun. Di fajar yang lapar, tiga menit menunggu mi matang adalah penghiburan paling pribadi. Di seluruh dasarnya yang bundar, kehangatan niat memberi makan seseorang ikut memanas."},"ICON-1518":{"nm":"Wajan Penggorengan","de":"Kepiawaian memasak sesuatu dalam sekejap di atas api bergantung pada satu wajan ini. Semakin matang permukaannya, semakin tidak lengket dan semakin mengilap. Wajan besi yang sudah lama dipakai adalah bukti nyata tahun-tahun yang telah dilalui dapur itu sendiri."},"ICON-1519":{"nm":"Oven","de":"Selagi pintu tertutup dan menunggu, di dalamnya keajaiban terjadi diam-diam. Waktu ketika adonan mengembang dan warnanya kian matang. Meski tak terlihat, jika menunggu dengan percaya, hasil yang hangat akan membuka pintu dan melangkah keluar."},"ICON-1520":{"nm":"Blender","de":"Sesuatu yang keras pun, begitu dimasukkan ke sini, dalam sekejap menjadi seteguk yang lembut. Pusaran kecil tempat bahan-bahan berbeda bercampur dan cita rasa baru lahir. Keselarasan, pada akhirnya, adalah masing-masing merelakan sedikit sudut tajamnya."},"ICON-1521":{"nm":"Pengocok Telur","de":"Sekali kibasan pergelangan tangan menjebak udara, dan secepat kocokan itu, yang encer pun berdiri kokoh. Selagi buih naik bagaikan puncak-puncak kecil, bukan hanya adonan yang mengembang. Niat untuk memberi makan seseorang hari ini pun turut mengembang bersamanya."},"ICON-1522":{"nm":"Penggiling Kopi","de":"Putar pegangannya pada segenggam biji kopi, dan aroma pecah lebih dulu di antara gigi-gigi roda. Ketika lengan mulai pegal, bubuk kopi baru menjadi halus, dan seteguk pertama pun sedalam usaha yang tercurah. Ketulusan selalu bermula dari pergelangan tangan."},"ICON-1523":{"nm":"Penggiling Tepung","de":"Butir gandum masuk di antara batu giling dan keluar sebagai tepung putih. Tak mengapa jika belum halus sekali giling, tinggal digiling dua kali lagi. Bahwa membuat yang kasar jadi halus pun ada tahapannya, itulah yang diam-diam diajarkan penggiling tepung."},"ICON-1524":{"nm":"Bangku Penggergajian","de":"Ketika batang kayu diletakkan, gergaji lebih dulu membaca seratnya. Menghindari mata kayu dan memotong hanya sepanjang jalur lurus, agar papan tidak melengkung. Memotong kayu, pada akhirnya, adalah membentangkan rapi waktu yang telah dijalani sebatang pohon."},"ICON-1525":{"nm":"Mesin Jahit","de":"Klik-klek—suara jarum menggigit kain dan berlari mengisi malam yang larut. Satu jahitan menyatukan dua lembar kain menjadi satu tubuh, dan di setiap tusukan tersembunyi di balik kostum panggung, tertanam kokoh jam-jam tak tidur seseorang."},"ICON-1526":{"nm":"Meja Pencelupan","de":"Kain putih dicelup lalu diangkat: mula-mula hijau muda, kemudian bertemu udara barulah berubah biru. Warna itu konon baru muncul setelah nila direndam tiga kali. Bahwa penantian itu sendiri menjadi warna—aku pertama kali mempelajarinya di depan meja pencelupan ini."},"ICON-1527":{"nm":"Tripod Kamera","de":"Begitu ketiga kakinya terbentang dan menapak tanah, dunia yang bergoyang pun terhenti. Satu bidikan yang akan gemetar bila dipegang tangan menjadi jernih di atas janji tiga titik ini. Untuk menatap sesuatu lama-lama, seseorang harus lebih dulu tahu cara berdiri diam."},"ICON-1528":{"nm":"Dudukan Lampu Sorot","de":"Pasang cahaya di atas satu tiang, dan sudut mana pun di ruangan menjadi panggung kecil. Miringkan sudutnya sedikit saja, bayangan memanjang dan ekspresi pun hidup. Ia tak menghapus gelap, melainkan menempatkan kegelapan itu dengan lembut pada tempatnya."},"ICON-1529":{"nm":"Dudukan Mikrofon","de":"Begitu tingginya disesuaikan, jarak antara mulut dan lagu pun ditetapkan. Lepaskan tangan, suara tetap bertahan di tempatnya. Hanya di atas panggung dengan kedua tangan bebas, lagu yang dinyanyikan sepenuh tubuh benar-benar dimulai."},"ICON-1530":{"nm":"Dudukan Partitur","de":"Ketika lembaran terbuka bersandar miring, not-not berbaris setinggi mata pemain. Meski birama berikutnya datang dalam sekejap gerakan tangan, penyangga ini tak goyah. Di balik permainan seseorang, selalu ada tempat yang diam tak bersuara."},"ICON-1531":{"nm":"Kebun Sayur","de":"Membajak tanah dan membuat alur, garis-garis janji kecil pun muncul di atas bumi. Beberapa hari setelah benih ditanam tampak seperti tak ada yang terjadi, tetapi suatu pagi tunas muda mendorong tanah dan tumbuh ke atas. Pemandangan yang hanya terlihat oleh mereka yang menunggu."},"ICON-1532":{"nm":"Kebun Subur","de":"Benih yang sama, namun di tanah ini daunnya tumbuh dua kali lebih besar. Tusukkan jari, dan tanah gelap yang lembut ikut menempel sampai ke bawah kuku. Tumbuh subur, pada akhirnya, adalah hasil kerja diam-diam yang dilakukan tanah tak terlihat di bawah kaki."},"ICON-1533":{"nm":"Rumah Kaca","de":"Di bawah atap kaca, musim mengalir satu ketukan lebih lambat. Meski embun beku turun di luar, di dalam tetap lembap oleh kelembapan pertengahan musim panas. Untuk hal-hal yang lemah menghadapi dingin, seseorang diam-diam menjebak sinar matahari di dalam atap."},"ICON-1534":{"nm":"Petak Herba","de":"Sentuh daunnya dengan ujung jari, dan aroma menyapa lebih dahulu. Basil, rosemary, mint—setiap nama dipanggil, aroma yang berbeda menempel di jari. Satu petak kecil saja mampu mengubah seluruh dapur menjadi lebih hangat."},"ICON-1535":{"nm":"Kebun Buah","de":"Di musim semi dahan melengkung oleh naungan bunga, di musim gugur oleh beratnya buah. Naik tangga, petik sebutir, gigit, dan manisnya sinar matahari setahun penuh pun pecah di dalam mulut. Seperti balasan yang diberikan pohon kepada manusia."},"ICON-1536":{"nm":"Kayu Gelondongan Jamur","de":"Lubangi kayu gelondongan yang telah ditebang dan tanami bibit jamur, maka pohon yang mati pun menumbuhkan sesuatu sekali lagi. Beberapa hari kemudian, di pagi ketika tudung jamur bermunculan bergerombol, kehidupan baru diam-diam dimulai di tempat yang dikira sudah berakhir."},"ICON-1537":{"nm":"Sarang Lebah","de":"Dekatkan telinga, dan terdengar dengungan rendah yang tekun dari dalam. Ribuan kepakan sayap berkumpul hanya untuk menghasilkan semanis segenggam sendok. Kerja keras sehari terbang di antara ladang bunga tersimpan di sini, lengket dan keemasan."},"ICON-1538":{"nm":"Kandang Ayam","de":"Sebelum fajar menyingsing, yang bertengger di ranggon lebih dulu berisik. Selipkan tangan ke jerami hangat, dan tergenggam sebutir telur yang masih menyimpan kehangatannya. Tempat yang paling dulu mengumumkan pagi adalah yang paling dulu menyiapkan meja sarapan."},"ICON-1539":{"nm":"Padang Gembala","de":"Padang luas tempat aroma rumput bercampur aroma matahari. Di atas punggung-punggung yang lamban mengunyah kembali di dalam pagar, bayangan awan berlalu. Di tempat tanpa keperluan untuk buru-buru ini, bahkan waktu mengalir perlahan, seolah sedang merumput."},"ICON-1540":{"nm":"Bengkel Keju","de":"Susu yang baru diperah perlahan mengeras melalui penggumpalan dan pematangan. Tunggu beberapa bulan di rak sejuk bagai gua, dan cita rasa yang dalam meresap ke dalam gumpalan putih itu. Keju adalah nama yang hanya diberikan pada susu yang tidak tergesa-gesa."},"ICON-1541":{"nm":"Bengkel Tahu","de":"Rendam kedelai, giling, rebus, dan susu kedelai yang tadinya amis pun menjadi gurih. Setetes air garam mengumpulkan yang berserakan menjadi tahu lembut, dan bila ditekan pelan, ia mengambil bentuk bersudut. Di sini ada tangan yang menenangkan hati yang berserakan hingga terbentuk."},"ICON-1542":{"nm":"Teras Guci Saus","de":"Di sudut halaman yang cerah, guci-guci pendek berkumpul rapat berjemur sinar matahari. Buka tutupnya, dan aroma waktu yang telah lama mengendap pun menyeruak. Rasa saus yang difermentasi nenek, sesungguhnya adalah menyantap tahun demi tahun satu sendok demi satu sendok."},"ICON-1543":{"nm":"Kilang Padi","de":"Ketika batu giling berputar berderak-derak, biji-bijian pun terurai menjadi tepung. Debu putih melayang di dalam sinar matahari, dan orang-orang yang ingin membuat sebakul kue beras menunggu giliran. Hari pesta desa selalu tampak bermula dari ambang pintu ini."},"ICON-1544":{"nm":"Toko Roti","de":"Dari celah pintu oven, aroma mentega dan gula menyeruak keluar. Ketika adonan yang mengembang mulai kecokelatan, langkah kaki yang lewat di depan toko tanpa sadar melambat. Sepotong roti yang baru dipanggang menyimpan kelembutan yang tak tertahankan siapa pun."},"ICON-1545":{"nm":"Gerobak Jajanan","de":"Terpal vinil berkibar tertiup angin, dan kuah tteokbokki mendidih menyusut perlahan. Malam menyeruput kuah dari cangkir kertas dengan sepotong sate ikan, tempat yang meleburkan dingin dan lapar sekaligus. Sebuah penghiburan kecil yang terletak di ujung gang."},"ICON-1546":{"nm":"Dapur Barat","de":"Wajan memanas dan minyak zaitun mendesis. Dengan sekali putaran api, saus bisa mengental atau justru gosong. Di tempat yang bahkan mempertimbangkan keseimbangan warna di atas piring, satu kali makan menjadi sebuah pertunjukan yang digarap dengan sepenuh hati."},"ICON-1547":{"nm":"Dapur Tionghoa","de":"Di atas api yang berkobar, wajan cekung berputar cekatan bagaikan menari. Dalam sekejap kobaran api menyembur, aroma bahan-bahan pun terkurung utuh. Cepat dan panas, rahasia masakan Tionghoa tersembunyi dalam satu tarikan napas yang akan lewat begitu saja bila ragu."},"ICON-1548":{"nm":"Kafe","de":"Dorong pintu, dan aroma kopi serta musik lembut menyambut lebih dulu. Kursi dekat jendela, secangkir latte yang mendingin, dan buku catatan yang terbuka. Agar seseorang bisa menghela napas sejenak di tengah hari yang sibuk, kota menyembunyikan ruang-ruang kecil seperti ini di mana-mana."},"ICON-1549":{"nm":"Toko Kue","de":"Di dalam etalase kaca, kue-kue warna-warni berjajar menunggu pembeli. Begitu ujung garpu membelah krim, sudut bibir pun terangkat lebih dulu. Resep kecil dan manis yang membuat hari sedih pun terasa tertahankan hanya dengan sepotong."},"ICON-1550":{"nm":"Toko Daging","de":"Di bawah lampu merah, daging tersusun rapi mengikuti seratnya. Dengan sepatah kata, \"Hari ini yang ini bagus,\" pisau meluncur pada ketebalan yang tepat. Kehangatan meja makan malam diam-diam bermula dari sentuhan tangan yang menjaga tempat yang sama setiap hari."},"ICON-1551":{"nm":"Meja Olah Hasil Laut","de":"Meja kerja tempat amis dini hari bercampur dengan dinginnya es. Sisik beterbangan dan tangan membeku, namun mata yang memilih yang paling segar tak pernah berhenti. Di sinilah hasil laut yang baru terangkat menemukan jalannya menuju meja makan."},"ICON-1552":{"nm":"Ladang Garam","de":"Perangkap air laut, dan sinar matahari serta angin mengerjakan sisanya. Tunggu beberapa hari hingga air mengering, dan kristal putih bermunculan di dasar bagaikan bintang. Segenggam rasa asin sesungguhnya adalah hadiah yang perlahan dihasilkan bersama oleh laut dan langit."},"ICON-1553":{"nm":"Rak Jemur Rumput Laut","de":"Di tali panjang, rumput laut miyeok dan dasima tergantung berjajar, bergoyang tertiup angin. Yang basah oleh air laut menghitam menjadi hijau pekat seiring mengering. Rasa laut yang paling sederhana, hasil karya bersama sinar matahari dan angin pantai, tergantung di sini."},"ICON-1554":{"nm":"Dermaga Kecil","de":"Papan kayu yang separuh terendam air bergoyang ringan di bawah kaki. Tempat yang pas untuk menambatkan sebuah perahu kecil. Baik berlayar jauh maupun pulang dengan selamat, keduanya bermula dan berakhir di satu petak ini."},"ICON-1555":{"nm":"Gudang Pelabuhan","de":"Buka pintu kayu yang telah diasap angin laut, dan jaring, tong, serta tali menumpuk hingga ke langit-langit. Muatan yang akan berlayar jauh dan muatan yang baru tiba beristirahat sejenak di bawah satu atap. Tempat bagaikan stasiun transit tempat kepergian dan kepulangan sekejap berpapasan."},"ICON-1556":{"nm":"Mercusuar","de":"Baru saat laut malam menjadi paling gelap, ia benar-benar memulai tugasnya. Cahaya yang berputar menembus kabut dan berkata, \"Di sini ada jalan.\" Penjaga tinggi yang, demi kepulangan seseorang dengan selamat, sampai akhir menolak untuk tertidur."},"ICON-1557":{"nm":"Galangan Kapal","de":"Pasang lunas dan sambung gading-gading, dan kerangka sebuah kapal pun terbentuk. Di halaman tempat suara palu berdentang sepanjang hari, kapal yang belum mengenal rasa air bermimpi tentang pelayaran pertamanya. Tempat yang mengokohkan diri dahulu, demi bisa berangkat."},"ICON-1558":{"nm":"Bilik Rekaman","de":"Begitu pintu tertutup, seluruh suara dari luar lenyap dalam sekejap. Yang terdengar lewat headphone hanyalah napas dan ketukan sendiri. Dalam keheningan ruang kecil ini, suara yang boleh bergetar sepuasnya akhirnya terlahir."},"ICON-1559":{"nm":"Ruang Musik","de":"Harmoni yang bocor lewat celah pintu memenuhi lorong. Seseorang menekan tangga nada, seseorang menghitung ketukan. Tempat di mana suara yang canggung dan suara yang sudah matang boleh bercampur, kelas hangat tempat setiap lagu pertama kali melangkah."},"ICON-1560":{"nm":"Ruang Piano","de":"Buka tutup papan tuts, dan debu tipis menempel di tuts putih. Begitu jari menyentuhnya, gema jernih menyebar memenuhi ruangan. Jika ada malam yang tak terasa kesepian meski sendirian, mungkin itu karena satu piano ini."},"ICON-1561":{"nm":"Ruang Dansa","de":"Tekan ujung kaki, dan lantai mendorongnya balik ke atas. Selagi cermin di empat sisi menyalin gerakan yang sama empat kali, tubuh menghafal koreografi setengah ketukan lebih dulu dari irama. Ruang tempat keringat dan napas paling lama bertahan, tempat gerakan yang tumbuh di sini melangkah keluar menuju panggung."},"ICON-1562":{"nm":"Ruang Gym","de":"Beban tidak pernah berbohong. Karena mencintai kejujuran itu—persis sebanyak yang diangkat, tercatat di bahu—orang-orang mencariku setiap dini hari. Yang perlahan terpahat di cermin bukanlah otot, melainkan waktu-waktu yang bertahan tanpa menyerah."},"ICON-1563":{"nm":"Ruang Yoga","de":"Tarik napas dalam-dalam, dan terasa seolah lantai kayu ikut mengembang bersama. Ruang tempat hari yang berlari cepat dilipat perlahan-lahan; di atas selembar matras, siapa pun kembali ke kecepatan napasnya sendiri. Hati yang tergesa-gesa pun sejenak diletakkan di sini."},"ICON-1564":{"nm":"Ruang Rias","de":"Tepat sebelum melangkah ke panggung, orang-orang sejenak menjadi orang lain di sini. Ketika bola lampu di sekeliling cermin menghangatkan wajah secara merata, getaran menempel di ujung puff bedak dan diam-diam bersembunyi di balik kerah. Tempat transformasi dimulai sekaligus berakhir."},"ICON-1565":{"nm":"Ruang Kostum","de":"Hingga satu setelan di atas panggung selesai, pakaian yang tergantung di sini dikenakan dan dilepas berpuluh kali. Manekin berputar dengan peniti jelujur tertancap, garis kampuh digambar dengan kapur. Di balik kilauan, selalu tertinggal bekas jahitan tangan seseorang."},"ICON-1566":{"nm":"Set Studio Siar","de":"Hanya satu sisi yang tersorot kamera perlu tampak nyata, begitu aku belajar sejak dini. Berputar ke balik papan triplek, hanya ada rangka kosong. Menopang kemegahan bagian depan selalu menjadi tugas balok-balok kayu yang tak terlihat."},"ICON-1567":{"nm":"Studio Foto","de":"Rahasia pertama adalah melempar cahaya dari tiga arah untuk menghapus bayangan. Cahaya utama menghidupkan wajah, cahaya pengisi menghidupkan bayangan, cahaya belakang menghidupkan ujung rambut. Pada saat rana jatuh, satu lembar latar putih mengurung senyum terbaik hari ini."},"ICON-1568":{"nm":"Gedung Konser","de":"Dalam kegelapan berlangit-langit tinggi, aku selalu menyimpan janji yang sama: bahwa saat tirai terangkat, bahkan kursi-kursi kosong akan menahan napas sebagai satu. Demi sesaat ketukan pertama itu jatuh, aku berdiri kosong dalam diam sepanjang tahun."},"ICON-1569":{"nm":"Bilik Fan Meeting","de":"Jarak antara tangan dan tangan tepat selebar satu meja. Sapaan singkat, tanda tangan yang gemetar, dan sepatah kata yang tak sempat terucap berlalu berbaris. Di dalam bilik kecil ini, perasaan sayang yang lama dipupuk akhirnya bertatap muka untuk pertama kalinya."},"ICON-1570":{"nm":"Ranjang","de":"Yang pertama menerima ujung hari selalu aku. Setelah kaki yang berat oleh latihan dan getaran yang tersisa di balik panggung sepenuhnya mereda, pagi kembali dimulai dengan ujung jari kaki yang ringan. Mengucap selamat tidur, aku memelukmu tanpa sepatah kata."},"ICON-1571":{"nm":"Ranjang Susun","de":"Di antara tingkat atas dan bawah, lima anak tangga menyambungkan dua orang. Suara pelan yang dibagi setelah lampu dimatikan, bintang-bintang bercahaya yang ditempel di langit-langit. Penginapan sempit menjadi paling luas berkat cerita yang naik turun tangga setiap malam."},"ICON-1572":{"nm":"Rak","de":"Apa yang diletakkan di atasnya menunjukkan siapa orangnya. Surat yang diterima, trofi pertama, tiket masuk yang telah pudar berjajar berdampingan. Aku bukan perabot untuk pamer, melainkan tempat yang diam-diam memajang kenangan yang tak tega dibuang."},"ICON-1573":{"nm":"Meja Tulis","de":"Dengan buku catatan lirik terbuka, garis baru kembali digoreskan di atas bekas coretan yang terhapus. Cangkir kertas yang menumpuk semalaman dan satu baris melodi yang nyaris tak terselamatkan. Kerja lambat memindahkan hati ke dalam kata-kata selalu berlangsung diam-diam di atas permukaan datar ini."},"ICON-1574":{"nm":"Kursi","de":"Ucapan \"duduklah sebentar\" ternyata adalah kata yang lembut. Sepanjang apa pun rapat memanjang atau latihan mengulur waktu, sandaran punggung diam-diam menampung berat tubuh seseorang. Semakin lama seseorang berdiri, semakin ia menyambutku—aku tahu itu."},"ICON-1575":{"nm":"Sofa","de":"Untuk mengubah penginapan larut malam menjadi ruang keluarga, cukup aku seorang diri. Berdesakan menonton acara hiburan bersama, dan tak lama satu orang sudah tertidur bersandar di sandaran tangan. Kursi tengah yang cekung membuktikan kehangatan rumah itu."},"ICON-1576":{"nm":"Meja","de":"Duduk melingkar, dan tak ada yang menjadi tempat terhormat. Sup yang baru mendidih, denting sendok beradu, kejadian hari ini berkumpul ke tengah. Begitu satu permukaan bundar terbentang, hari yang tadinya berserakan pun duduk melingkar bersama lagi."},"ICON-1577":{"nm":"Lemari Pakaian","de":"Setiap kali musim berganti, cerita lama tumpah dari dalam. Kostum panggung dan pakaian sehari-hari berdampingan bahu, di balik pintu tertutup pakaian-pakaian menunggu giliran berikutnya. Hanya dengan membuka pintu, hari yang akan dikenakan hari ini akhirnya ditentukan."},"ICON-1578":{"nm":"Cermin","de":"Pujian maupun cela, kukembalikan dengan kejujuran yang sama. Tempat pemeriksaan terakhir sebelum melangkah ke panggung, orang-orang menata ekspresi dan meluruskan sikap di depanku. Sahabat paling jujur selalu tak pernah mengucapkan sepatah kata pun."},"ICON-1579":{"nm":"Meja Rias","de":"Di setiap laci kecil, wajah yang berbeda tertidur. Satu untuk panggung, satu untuk sehari-hari, satu edisi terbatas yang disimpan baik-baik. Duduk di depan cermin, perlahan mulai menentukan akan menjadi siapa saat melangkah keluar hari ini."},"ICON-1580":{"nm":"Karpet","de":"Sentuhan pertama kaki telanjang menentukan suhu ruangan itu. Bekas duduk melingkar sambil ngemil dan berguling-guling tertinggal sebagai bulu halus. Perabot yang bekerja dari tempat paling rendah, menghangatkan lantai dingin sejengkal lebih hangat."},"ICON-1581":{"nm":"Tirai","de":"Seberapa banyak pagi dibiarkan masuk, akulah yang menentukan. Sedikit dibuka, sinar matahari masuk memanjang; ditutup rapat, bahkan bangun kesiangan pun jadi termaafkan. Berdiri di antara jendela dan ruangan, mengatur diam-diam jumlah cahaya selalu menjadi tugas yang dipercayakan padaku."},"ICON-1582":{"nm":"Lampu","de":"Ruangan yang sama bisa menjadi waktu yang sama sekali berbeda tergantung warna cahayanya. Cahaya kuning memanjangkan senja, cahaya putih membangunkan fajar dengan tegas. Penyihir sebesar telapak tangan yang, dengan satu saklar, diam-diam mengubah suasana hari."},"ICON-1583":{"nm":"Jam Dinding","de":"Suara detik hanya terdengar di ruangan yang sunyi. Semakin dalam latihan berlangsung, aku pun terlupakan, hingga tiba-tiba mendongak dan mendapati di luar jendela sudah fajar. Tanpa pernah menyalahkan waktu yang berlalu, aku hanya menunjuk diam-diam ke ketukan berikutnya."},"ICON-1584":{"nm":"Vas Bunga","de":"Meski bunga layu, aku tak membiarkan tempatku kosong. Wadah yang menampung sejenak perasaan yang diterima; selama ada tangan yang mengganti airnya, meja makan tetap cerah. Bahkan saat kosong, aku berdiri dalam bentuk menunggu seseorang."},"ICON-1585":{"nm":"Bingkai Poster","de":"Menggantung wajah yang disayangi di dinding pun butuh ketelitian. Tempat yang tak tersentuh sinar matahari langsung, satu paku dengan kerataan yang pas. Selembar kertas yang dibaringkan lembut di dalam kaca adalah yang pertama menyapaku setiap pagi begitu memasuki ruangan."},"ICON-1586":{"nm":"Papan Photocard","de":"Menyusunnya berdasarkan abjad atau urutan rilis—kebimbangan bahagia itulah awal mula kegilaan fandom. Satu petak kosong adalah tempat untuk bias yang belum ditemui. Seiring terisi satu kartu demi satu kartu, papan ini menjadi kronik kecilku sendiri."},"ICON-1587":{"nm":"Dudukan Lightstick","de":"Baterai dilepas, pegangan menghadap ke atas. Bahkan sudut kemiringan saat menyandarkannya punya triknya sendiri. Sambil menunggu sorakan berikutnya tiba, lightstick memadamkan cahayanya di sini dan membaringkan tubuhnya rapi. Beristirahat baik-baik agar menyala lebih terang."},"ICON-1588":{"nm":"Rak Trofi","de":"Di barisan paling depan diletakkan yang paling lama. Dari patung kecil kompetisi kecil hingga piala panggung besar, tersusun bukan berdasarkan tinggi, melainkan urutan hati. Setiap kali dilap, getaran panggung hari itu kembali menempel di ujung jari."},"ICON-1589":{"nm":"Keranjang Piknik","de":"Buka tutupnya, dan aroma sinar matahari musim semi menyeruak lebih dulu. Gimbap, termos, dan selembar tikar tersusun rapi, bersiap menuju ladang. Langkah orang yang membawaku entah mengapa selalu terasa sejengkal lebih ringan dari biasanya."},"ICON-1590":{"nm":"Pot Bunga Kecil","de":"Sejengkal ambang jendela sudah cukup bagiku. Hijau kecil yang dengan murah hati bertahan meski sering lupa disiram. Di sudut meja orang yang sibuk, aku membentangkan satu lagi daun setiap hari, diam-diam menyampaikan kabar hari ini."},"ICON-1591":{"nm":"Pot Bunga Besar","de":"Selagi tinggiku tumbuh, orang itu pun ikut tumbuh bersamaku. Ketika daun lebar yang menempati sudut ruang keluarga menangkap sinar matahari dan menjatuhkan bayangan, musim pun diam-diam memasuki ruangan itu. Kebanggaan yang hanya diketahui oleh mereka yang tak lupa menyiram."},"ICON-1592":{"nm":"Set Lilin Aromaterapi","de":"Begitu sumbu dinyalakan, udara ruangan turun satu tingkat menjadi tenang. Aroma menyebar perlahan, menghangatkan dan mengeluarkan kelelahan yang tersisa dari kemarin. Dengan satu nyala api kecil, mengakhiri penghujung hari yang sibuk bagaikan ritual yang tenang."},"ICON-1593":{"nm":"Kulkas Mini","de":"Buka pintuku larut malam, dan sekaleng minuman dingin menyambutku. Suara dengungan kecil membuat penginapan yang kosong terasa sedikit kurang sepi. Aku memang tak bisa mengurus rumah tangga besar, tapi untuk mengatasi fajar yang lapar, tak ada yang menandingiku."},"ICON-1594":{"nm":"Topi Jaring Capung","de":"Begitu dipasang di kepala, padang musim panas ikut mengalir ke atas bahu. Jaring bundar menyaring sinar matahari dengan lembut, dan setiap langkah aroma rumput bergoyang lembut. Topi yang membalut satu musim penuh, tetap menyenangkan meski tak berhasil menangkap seekor capung pun."},"ICON-1595":{"nm":"Kantong Jaring Pemungut","de":"Tergantung di pinggang, ia menjadi teman dalam mengumpulkan. Mengencangkan mulut kantong sedikit agar yang tertangkap tak kabur lagi—trik pertama yang dipelajari di ladang. Satu kantong kain ringan mendekap hasil tangkapan sehari dengan rapi."},"ICON-1596":{"nm":"Toples Pengamatan Serangga","de":"Bagi tamu yang hanya singgah sejenak, lubang udara adalah yang paling penting—ini kutahu. Jalan napas kecil yang dilubangi di tutup, selembar daun rumput yang dialas di dasar. Mengembalikannya ke semak setelah pengamatan selesai adalah bagian yang tak terpisahkan."},"ICON-1597":{"nm":"Kotak Peniti Spesimen","de":"Bahkan pada satu sudut menancapkan peniti miring, ada keterampilan yang hidup. Terlalu dalam bisa patah, terlalu dangkal bisa goyah, maka kekuatan ujung jari harus dibagi dengan presisi. Kotak yang diam-diam menyimpan ketelitian orang yang ingin menatap lama-lama satu kehidupan kecil."},"ICON-1598":{"nm":"Tutup Terarium","de":"Menjaga batas antara dalam dan luar adalah tugasku. Ditutup terlalu rapat, sesak napas; dibiarkan terlalu longgar, tersesat jalan, maka aku selalu menyisakan celah seperti garis silang. Melindungi jelas berbeda dengan mengurung."},"ICON-1599":{"nm":"Piring Pakan Kupu-kupu","de":"Letakkan kapas yang dibasahi air gula di tengah, dan sayap-sayap pun berkumpul. Rahasianya adalah menampungnya dangkal dan lebar, sedalam yang tak menenggelamkan kaki-kaki kecil. Satu piring diam-diam mengumpulkan tamu yang singgah sebentar di taman yang cerah oleh matahari."},"ICON-1600":{"nm":"Lampu Pemikat Serangga","de":"Nyalakan samar dalam gelap, dan sayap-sayap kecil berkumpul mengikuti cahaya. Kecerahan yang lembut, tempat yang jauh dari orang. Pemikat yang amat ramah, yang menenangkan malam musim panas yang berdengung menjadi jauh lebih sunyi."},"ICON-1601":{"nm":"Label Stiker Serangga","de":"Enam kaki dan sepasang antena—dalam secarik kertas seukuran kuku, sebuah kehidupan kecil tertidur. Tempelkan perlahan di sudut buku catatan, dan sejengkal padang rumput pun diam-diam terbentang di antara halaman-halaman."},"ICON-1602":{"nm":"Label Izin Menangkap Serangga","de":"Sebelum mengangkat jaring serangga, orang dewasa bertanya lebih dulu: berapa ekor, sampai mana batasnya. Selembar label kecil ini menggoreskan garis lembut antara rasa ingin tahu yang menggebu dan janji yang harus dijaga."},"ICON-1603":{"nm":"Kaleng Umpan","de":"Buka tutupnya dan aroma amis nan sejuk fajar pun menyeruak. Yang memanggil ikan mungkin bukan umpannya, melainkan hati yang tahu cara menunggu dengan tenang hingga pelampung bergetar."},"ICON-1604":{"nm":"Kotak Penyimpan Pelampung","de":"Lemari kecil tempat pelampung warna-warni berbaring tertidur, petak demi petak. Ada yang mewakili pagi danau yang tenang, ada pula siang hari arus yang deras. Untuk setiap ekspresi air, pasangan yang pas dilipat rapi di dalamnya."},"ICON-1605":{"nm":"Gulungan Senar Pancing","de":"Jangan melilitkan senar yang terurai pada jari. Gulung kembali rapi-rapi pada alat bundar ini, dan bahkan kekusutan pun diam-diam terurai. Ia mirip sentuhan tangan yang merapikan hari yang telah kendur."},"ICON-1606":{"nm":"Pencabut Kail","de":"Hanya mereka yang pernah tertusuk saat mencabut kail dengan tangan kosong yang mengenali alat ini. Jalan yang lebih tak menyakitkan, baik bagi makhluk kecil maupun ujung jari sendiri. Perhatian selalu berawal dari hal-hal remeh semacam ini."},"ICON-1607":{"nm":"Sarung Sekop Kerang","de":"Selapis pelindung yang membungkus mata sekop yang baru saja digunakan menggali di lumpur pantai. Agar lumpur dan air asin tak menggerogoti matanya, ia menyelipkan istirahat tipis dan lembut di antara laut dan alat itu."},"ICON-1608":{"nm":"Kartu Tabel Pasang Surut","de":"Kapan air pasang dan kapan surut, selembar kartu seukuran telapak tangan diam-diam memberitahu. Sebuah kalender kecil, salinan janji lama yang dibuat bulan dan laut bersama-sama."},"ICON-1609":{"nm":"Sikat Pembersih Akuarium","de":"Sapu perlahan lumut hijau yang menempel di dinding kaca, dan cahaya pun kembali meresap ke dunia kecil di dalam air. Pekerjaan yang mencerahkan hari seseorang biasanya mengalir setenang ini."},"ICON-1610":{"nm":"Chip Suhu Akuarium","de":"Satu angka berkedip, dan ketika berhenti pada derajat yang tepat, ikan-ikan pun akhirnya merasa tenang. Sepetak kehangatan yang tak terlalu dingin maupun panas. Perhatian menjangkau bahkan hingga ke tempat yang tak terlihat."},"ICON-1611":{"nm":"Tabung Pengamatan Biota Laut","de":"Seorang tamu kecil singgah sejenak di dalam tabung bening. Hitung perlahan sirip punggungnya, lalu kembalikan ke laut. Mengamati bukanlah memiliki, melainkan meminjam sebentar."},"ICON-1612":{"nm":"Sikat Fosil","de":"Yang membangunkan urat batu yang tertidur puluhan juta tahun bukanlah palu, melainkan ujung sikat yang lembut. Di hadapan waktu yang akan hancur jika terburu-buru, kehati-hatian menjadi kesopanan yang paling dalam."},"ICON-1613":{"nm":"Tutup Kuas Penggalian","de":"Ketika ujung kuas terlalu kering, tanah pun tak lagi runtuh dengan rapi. Sebuah tutup kecil menjaga napas kuas tetap lembap. Tangan yang merawat alatnya melangkahkan langkah pertama penggalian."},"ICON-1614":{"nm":"Piring Sampel Lapisan Tanah","de":"Dalam sejengkal tanah, ratusan tahun terlipat berlapis-lapis. Ambil perlahan ke atas piring ini, dan pola waktu yang selama ini tak terlihat pun menggaris dan perlahan muncul ke permukaan."},"ICON-1615":{"nm":"Baki Pecahan Tulang","de":"Baringkan serpihan-serpihan yang tercecer petak demi petak, dan satu kehidupan yang dulu tersebar oleh angin perlahan meraba jalan kembali ke tempatnya. Restorasi adalah pekerjaan menanyakan kembali urutan yang hilang dengan penuh kasih."},"ICON-1616":{"nm":"Pita Restorasi","de":"Seutas pita tipis yang menyambung bagian yang retak. Ia tak berusaha menyembunyikan bekas luka, melainkan merangkulnya dengan lembut dan menahannya erat. Ia diam-diam membuktikan bahwa yang pernah hancur pun bisa utuh kembali."},"ICON-1617":{"nm":"Penutup Papan Nama Pameran","de":"Selembar penutup yang lembut melapisi label di balik kaca agar tak memudar. Di dalamnya tersimpan harapan agar kalimat singkat tentang siapa yang pernah hidup, dan di mana, tetap terbaca jelas hingga jauh di masa depan."},"ICON-1618":{"nm":"Label Ruang Penyimpanan","de":"Sebuah ruang dalam tempat harta yang tak pernah melangkah ke cahaya tertidur. Segala sesuatu di dalamnya mengenakan label nama kecil—agar meski tak berdiri di tempat yang terang, mereka tak pernah terlupakan."},"ICON-1619":{"nm":"Amplop Donasi Museum","de":"Seseorang menyerahkan apa yang dikumpulkannya seumur hidup, tanpa sepatah kata. Yang tersimpan dalam amplop ini bukanlah benda, melainkan hati yang lama dipeluknya. Berbagi menjadi pameran yang paling lama bertahan, menyinari seseorang."},"ICON-1620":{"nm":"Chip Nomor Spesimen","de":"Tepat di tempat ditemukannya, sebuah angka kecil diam-diam disematkan. Kapan, dan di mana, pertama kali bertemu dengannya. Penemuan yang tak dicatat akan segera menghilang seperti kabut pagi."},"ICON-1621":{"nm":"Botol Pecahan Meteor","de":"Sebuah serpihan yang jatuh membelah langit malam terperangkap di dalam botol kaca. Seberkas cahaya yang pudar sebelum sempat kau mengucap harapan, kini berkilau kembali dengan lembut di genggaman tanganmu."},"ICON-1622":{"nm":"Tali Lonceng Angin Kerang","de":"Untai kerang yang dipungut satu demi satu di tepi pantai pada seutas benang, lalu gantungkan di bawah atap. Setiap kali angin berlalu, gemerincing lembut, laut musim panas itu diam-diam mengikuti langkah masuk ke dalam rumah."},"ICON-1623":{"nm":"Tetes Embun Pelangi","de":"Setetes air yang menggantung bulat di ujung daun sehabis hujan reda. Dalam bentuk bundarnya itu, seluruh langit dan tujuh warna tersimpan melingkar. Ada kalanya yang paling kecil menampung pemandangan yang paling luas."},"ICON-1624":{"nm":"Botol Pengumpul Kabut","de":"Kubawa pulang sebotol penuh kabut fajar dari lereng gunung. Genggam, dan ia terasa sejuk, mengabur keputihan. Sebuah keserakahan kecil nan lembut untuk menyimpan sejenak di sisi, sesuatu yang tak bisa digenggam."},"ICON-1625":{"nm":"Cangkir Penampung Embun","de":"Cangkir kecil yang menampung embun yang dikumpulkan helai rumput setetes demi setetes sepanjang malam. Belum sampai seteguk pun, namun bagian yang paling jernih dan bersih dari pagi hari mengendap tenang di sana."},"ICON-1626":{"nm":"Peniti Pita Angin Sepoi","de":"Sebuah pita yang diikat meniru persis alur yang ditinggalkan angin saat berlalu. Sematkan di rambut, dan setiap langkah angin sepoi mengikuti dengan lembut bergoyang. Kelembutan hari musim semi diam-diam terikat pada sebuah peniti."},"ICON-1627":{"nm":"Kapsul Suara Ombak","de":"Dekatkan perlahan ke telinga, dan ombak dari laut jauh pun bergulung datang. Seolah seseorang telah menyegel dengan hati-hati ke dalam sebutir kapsul kecil, suara yang dulu tersimpan dalam cangkang kerang di masa kanak-kanak."},"ICON-1628":{"nm":"Pecahan Bintang Pasir","de":"Genggam segenggam pasir di pantai malam, dan remah-remah bintang bercampur di dalamnya, berkilauan. Apakah jatuh dari langit atau digiling halus oleh ombak, tak seorang pun repot-repot bertanya."},"ICON-1629":{"nm":"Chip Catatan Cuaca Pulau","de":"Langit pulau berubah pikiran beberapa kali dalam sehari. Catat cerah, kabut, dan hujan rintik rapi-rapi ke dalam sebuah chip kecil, dan kau bisa membentangkan kembali langit kemarin hari ini."},"ICON-1630":{"nm":"Kit Tangga Tebing","de":"Satu anak tangga, lalu satu lagi, untuk naik turun lereng yang curam. Pasang komponen yang tercecer, dan bahkan tebing pun menjadi jalan santai untuk berjalan-jalan. Membuka jalan berarti meletakkan lebih dulu langkah berikutnya bagi seseorang."},"ICON-1631":{"nm":"Gulungan Pola Jalan Tanah","de":"Sebuah gulungan yang mengambil persis alur jalan tanah yang lembut. Bentangkan dengan sekali gerak, dan sebuah jalan setapak desa yang membuatmu ingin berjalan tanpa alas kaki pun tergelar tenang di bawah telapak kaki."},"ICON-1632":{"nm":"Chip Pola Jalan Batu","de":"Motif batu paving yang dulu menghampar gang-gang tua tersimpan utuh dalam sebuah chip kecil. Setiap kali dipijak, tok tok, langkah kaki desa lama hidup kembali di ujung jari kaki."},"ICON-1633":{"nm":"Potongan Pagar Pantai","de":"Sepotong pagar rendah yang didirikan di hamparan pasir agar ombak tak melewatinya. Seorang penjaga batas yang kecil dan diam, berdiri menggoreskan garis lembut antara laut dan pasir."},"ICON-1634":{"nm":"Tambalan Pemulihan Rumput","de":"Sepotong hijau yang lembut menutupi tempat yang gundul terinjak. Dalam beberapa hari, rumput-rumput saling bergandengan tangan mengisi tempat kosong itu. Alam selalu tahu cara menyembuhkan dirinya sendiri."},"ICON-1635":{"nm":"Patok Penanda Jalur Air","de":"Sebuah patok yang lebih dulu memberitahu jalan yang akan dilalui air. Agar air hujan tak tersesat bingung ke mana harus pergi, sebuah rambu kecil yang tertancap di tanah berdiri diam bahkan di hari hujan."},"ICON-1636":{"nm":"Komponen Jembatan Kecil","de":"Sekeping bagian dari jembatan mungil yang menghubungkan dua tepi sungai. Antara sisi ini dan sisi itu, janji bahwa kau bisa menyeberang kapan saja diam-diam bermula dari komponen kecil ini."},"ICON-1637":{"nm":"Tutup Pagar Menara Pandang","de":"Di tempat tertinggi pulau, sebuah bagian penutup yang membungkus ujung pagar itu. Ia diam-diam menopang dan melindungi tempat yang paling sering disentuh oleh tangan-tangan orang yang berkumpul untuk memandang jauh."},"ICON-1638":{"nm":"Alas Api Unggun","de":"Sebelum kayu bakar diletakkan, sebuah tempat yang menopang agar bara tak berserakan. Di atasnya, malam-malam mengobrol sambil menengadah ke bintang menyala hangat untuk waktu yang lama."},"ICON-1639":{"nm":"Gulungan Sampel Wallpaper","de":"Suasana sebuah ruangan bermula dari satu sisi dinding. Membentangkan gulungan kecil untuk memilih warna adalah diam-diam menggambar lebih dulu, hari-hari seperti apa yang ingin kau jalani ke depannya."},"ICON-1640":{"nm":"Chip Sampel Lantai","de":"Rasakan lebih dulu dengan ujung jari, tekstur lantai yang akan disentuh kaki telanjang. Hangat atau sejuk—pada selembar chip kecil ini tergantung kenyamanan hari-hari yang akan kau jalani ke depan."},"ICON-1641":{"nm":"Set Kaitan Langit-Langit","de":"Begitu sebuah kaitan digantung di balok, langit-langit yang kosong menjadi tempat yang menanti seseorang. Menggantung lonceng angin, atau pot bunga? Kaitan besi kecil ini menahan bebannya, tapi apa yang akan digantung, hati penghuni yang menentukan."},"ICON-1642":{"nm":"Film Tirai Jendela","de":"Cahaya siang terlalu jujur, hingga kau melapisi jendela dengan selembar film tipis. Sinar matahari tetap masuk, tapi tepinya melunak, dan segala sesuatu di dalam ruangan berubah lembut warna aprikot. Bukan menghalangi, melainkan menyebarkan cahaya dengan lembut."},"ICON-1643":{"nm":"Penutup Bel Pintu","de":"Sambil berkata bahkan bel yang ditekan tamu pun butuh pakaian, seseorang memasangkan penutup bundar. Ia menahan hujan, menahan debu, dan yang terpenting, adalah mulut bundar kecil pertama yang menyampaikan sapaan \"ada orang tinggal di sini.\""},"ICON-1644":{"nm":"Standar Buku Tamu","de":"Sebuah dudukan yang didirikan agar setiap orang yang datang menuliskan namanya sebelum pergi. Sebelum tinta mengering, sebaris salam mengalir dari ujung pena. Ketika langkah-langkah yang pernah singgah menumpuk baris demi baris, buku catatan kosong itu perlahan menjadi album paling tebal di rumah ini."},"ICON-1645":{"nm":"Pin Penanda Posisi Furnitur","de":"Posisi meja yang tadinya kau ragu-ragu untuk dipindahkan, diputuskan begitu saja saat sebuah pin ditancapkan ke lantai. Sebuah paku kecil yang lembut menahan kaki furnitur itu. Sebuah tempat, sekali ditetapkan, akan tumbuh rasa sayang di dalamnya, lantai kayu mengangguk diam-diam."},"ICON-1646":{"nm":"Bingkai Label Penyimpanan","de":"Apa yang tersimpan di mana, laci tak pernah bisa mengatakannya. Karena itu, sebuah label nama disisipkan ke bingkai persegi untuk berbicara mewakilinya. Begitu selembar label menempati tempatnya, petak-petak yang berantakan itu merebut kembali namanya dan menjadi tenang."},"ICON-1647":{"nm":"Stik Diffuser Aroma Ruangan","de":"Aroma yang membasahi ujung stik perlahan menyebar ke atas. Sesaat lavender, sesaat lagi padang rumput sehabis hujan. Ketika seutas benang aroma yang tak terlihat menggantikan udara ruangan, kelelahan sehari itu perlahan luruh dari bahu orang yang baru pulang."},"ICON-1648":{"nm":"Klip Bungkus Benih","de":"Benih yang dibeli di musim semi namun tak sempat ditanam, dijepit rapat lengkap dengan bungkusnya oleh sebuah klip. Jika sebutir saja tercecer keluar, musim depan berkurang satu baris. Di dalam kunci kecil ini, kebun tahun depan tertidur utuh."},"ICON-1649":{"nm":"Baki Bibit Tanaman","de":"Isi setiap petak dengan tanah untuk membuat kamar pertama bagi kecambah muda. Satu kehidupan per lubang, murid-murid baru yang tumbuh berbaris rapi berdampingan. Intiplah, dan pagi hari saat hijau memanggil absen bergerombol pun dimulai lagi setiap hari di atas baki ini."},"ICON-1650":{"nm":"Pin Penanda Penyiraman","de":"\"Aku haus.\" Karena pot bunga tak bisa bicara, sebuah papan kecil yang ditancapkan di tanah mengirim sinyal sebagai gantinya. Ketika warnanya berubah, itu waktunya menyiram. Penerjemah terkecil antara tumbuhan dan manusia, semuanya termuat dalam batang sepanjang sejengkal ini."},"ICON-1651":{"nm":"Tali Penopang Tanaman","de":"Khawatir batang yang tumbuh tinggi akan goyah oleh beratnya sendiri, kau mengikatnya perlahan ke tiang penopang dengan tali yang lembut. Terlalu kencang membuatnya sesak, terlalu longgar membuatnya roboh, maka tangan yang mengikat membutuhkan kelembutan yang pas. Bahkan tumbuh besar pun butuh seseorang di sisi."},"ICON-1652":{"nm":"Jaring Anti Hama","de":"Jaring yang dirajut halus diam-diam menghalangi mulut-mulut kecil yang mengincar daun muda. Ia membiarkan angin dan sinar matahari lewat namun hanya menyingkirkan yang membahayakan, seorang penjaga gerbang tak kasatmata. Kebun tetap damai berkat perhatian yang teranyam dalam lubang-lubang jaring yang rapat ini."},"ICON-1653":{"nm":"Kartu Pengukur Sinar Matahari","de":"Berapa banyak sinar matahari yang sampai di sini? Kau menancapkan selembar kartu di petak bunga dan bertanya perlahan. Semakin pekat warnanya, semakin banyak cahaya yang diterima hari ini. Secarik kertas kecil ini memilah tempat bagi anak yang menyukai matahari dan yang lebih nyaman di keteduhan."},"ICON-1654":{"nm":"Kertas Uji pH Tanah","de":"Tempelkan kertas uji ke tanah, dan dari merah muda hingga biru, tanah mengungkapkan isi hatinya lewat warna. Di tempat yang tak terlalu asam maupun terlalu pahit, akar bernapas paling lega. Perasaan tanah yang tak terlihat terbaca petak demi petak."},"ICON-1655":{"nm":"Label Keranjang Panen","de":"Apakah yang dipetik hari ini selada atau tomat ceri, setiap keranjang diberi label nama. Pada pagi panen yang bercampur aroma tanah dan bau segar dedaunan, begitu selembar label terpasang, keranjang itu menjadi rambu pertama di jalan menuju meja makan."},"ICON-1656":{"nm":"Toples Penyimpan Benih","de":"Kau menyimpan benih yang dipanen tahun ini dalam toples kaca dan mengirimkannya kepada musim semi berikutnya. Tutup toplesnya dan waktu berhenti sejenak, sementara butiran-butiran kecil menunggu giliran mereka dalam gelap. Ini toples bagaikan surat yang dikirim melintasi satu musim penuh."},"ICON-1657":{"nm":"Selotip Sambung Tanaman","de":"Pertemukan ranting yang terpotong dengan ranting baru, lilitkan selotip, dan perlahan keduanya menyatu menjadi satu tubuh. Getah mengalir kembali di titik terputus itu, luka yang perlahan sembuh. Menyambung, pada akhirnya, adalah tindakan menerima urat kayu satu sama lain."},"ICON-1658":{"nm":"Tutup Gunting Pangkas","de":"Kau menyelipkan topi kecil pada ujung gunting yang tajam. Selagi tangan yang menipiskan ranting beristirahat, mata pisau tetap tajam dan tangan tetap tak terluka. Sambil berkata bahkan alat yang selesai bekerja pun butuh piyama, kebun merawat alatnya dengan telaten sebelum tidur."},"ICON-1659":{"nm":"Kotak Pemilah Benih Bunga","de":"Pacar air, portulaka, kembang pukul empat—benih-benih yang berbeda nama dan warna masing-masing mendapat kamarnya sendiri di petak terpisah. Kalau tercampur, saat musim semi tiba tak akan ketahuan siapa siapa. Sekat-sekat kecil dalam kotak ini menggambar lebih dulu cetak biru taman yang belum mekar."},"ICON-1660":{"nm":"Roda Alas Pot","de":"Pasang empat roda, dan bahkan pot yang berat pun berangkat mengikuti sinar matahari. Jendela timur di pagi hari, keteduhan di siang bolong. Hijau yang dulu terpaku pada bobotnya menggelinding, mengejar cahaya sepanjang hari mencari tempat terbaik."},"ICON-1661":{"nm":"Tali Pengarah Sulur","de":"Sulur yang meraba udara kosong, tak tahu ke mana harus pergi, dituntun perlahan oleh tali ke jalan yang benar. Ke atas, dan lebih tinggi lagi. Berikan tempat untuk berpegangan, dan anehnya tanaman itu meraih tangan itu. Bahkan bertumbuh pun butuh seorang penunjuk jalan."},"ICON-1662":{"nm":"Penjepit Kartu Bahasa Bunga","de":"Kartu yang terselip di samping bunga bertuliskan kata yang disampaikan bunga itu. Hydrangea berkata tulus, daisy berkata murni. Agar berjalan di petak bunga menjadi jalan-jalan membaca surat, sebuah penjepit kecil diam-diam meminjamkan suara pada mulut bunga yang bisu."},"ICON-1663":{"nm":"Tutup Papan Nama Taman","de":"Khawatir tulisan akan luntur diterpa hujan dan angin, kau memasangkan topi bening di atas papan nama taman. \"Tomat di sini,\" \"kemangi di sini.\" Nama-nama yang nyaris pudar tetap tajam, hingga sekalipun setahun berlalu, kebun tak melupakan satu pun anggota keluarganya."},"ICON-1664":{"nm":"Sendok Pupuk","de":"Saat menambahkan nutrisi ke tanah, keserakahan justru membuat akar terbakar. Karena itu, satu sendok, pas segitu saja. Sendok kecil ini menciduk jumlah yang tepat dan mengingatkan—hati yang merawat dengan baik selalu datang dari ujung jari yang tahu batas kecukupan."},"ICON-1665":{"nm":"Nosel Semprot Kabut","de":"Putar nosel, dan aliran air pun tercerai berai turun seperti kabut. Daun muda yang dulu tergerus derasnya aliran kini mengangkat kepalanya perlahan di bawah tetes-tetes seperti embun. Air yang sama bisa menjadi sapaan yang sama sekali berbeda, tergantung cara memberikannya."},"ICON-1666":{"nm":"Gelas Ukur Pakan","de":"Satu gelas, dua gelas. Kau mengukur satu porsi makan sahabatmu bukan dengan kira-kira, melainkan dengan ketelitian penuh perhatian. Terlalu banyak akan tersisa, terlalu sedikit akan membuatnya sedih, maka kau menakar jumlah yang pas. Cinta terkadang datang dalam wujud pengukuran yang teliti seperti ini."},"ICON-1667":{"nm":"Penutup Sikat Bulu Rontok","de":"Pada musim rontok bulu, penutup ini membungkus rapi bulu halus yang tersangkut di sikat. Tutupkan topi pada sikat yang selesai menyisir, dan esok hari pun dimulai kembali lembut dan segar. Kilau seorang teman serumah tumbuh diam-diam dari perapian sekecil ini."},"ICON-1668":{"nm":"Tutup Pemotong Kuku","de":"Kau memasangkan tutup kecil di ujung tajam pemotong kuku, agar alat yang selesai bekerja tak menggores benda lain di dalam laci. Setelah waktu perawatan berakhir, menidurkan alat dengan menepuk lembut adalah putaran penuh dari sebuah perhatian."},"ICON-1669":{"nm":"Liontin Kalung Hewan","de":"Gantungkan sebuah liontin berkilau pada kalungnya, dan jalan-jalan yang biasa itu pun menjadi sedikit lebih istimewa. Sebuah hiasan kecil yang berkilau ditimpa matahari. Tak perlu mencolok, cukuplah sebagai tanda bahwa si kecil ini adalah anggota keluarga yang sangat dicintai seseorang."},"ICON-1670":{"nm":"Kartu Kesehatan Hewan","de":"Apakah hari ini makan dengan baik, adakah yang sakit? Kau menuliskan sebaris demi sebaris hari-hari sahabat serumahmu di kartu ini. Ketika kondisi anggota keluarga yang tak bisa bicara tercatat dalam tulisan, hati yang merawat pun ikut menjadi lebih teliti dan kokoh."},"ICON-1671":{"nm":"Sarung Bantal Tidur Hewan","de":"Kau mengenakan pakaian baru yang lembut pada bantal tidurnya. Lepaskan kain yang aus karena berguling-guling dan bergesekan, dan aroma bulu halus yang dijemur di bawah matahari pun menyeruak. Merawat paling bersih tempat ia paling sering berbaring adalah ketulusan setiap hari bagi teman serumahmu."},"ICON-1672":{"nm":"Pin Pagar Kecil","de":"Tancapkan pin-pin kecil di sepanjang tepi petak bunga untuk mendirikan pagar rendah. Bukan ancaman keras \"jangan melewati,\" melainkan batas lembut yang berkata sampai sinilah tempat bunga itu. Dengan adanya garis yang dijaga, mereka bisa tumbuh dengan tenang di dalamnya."},"ICON-1673":{"nm":"Kaleng Camilan Pendekatan","de":"Bahkan anak yang pemalu pun menegakkan telinganya mendengar bunyi kaleng ini dikocok. Di dalamnya ada segenggam camilan yang membuka hati. Karena janji kecil lebih cepat mendekatkan daripada kata-kata, bunyi gemerincing itu melangkah maju lebih dulu."},"ICON-1674":{"nm":"Tag Catatan Jalan-Jalan","de":"Jalan mana yang ditempuh hari ini, dan seberapa jauh? Kau mengikat catatan pada tag ini seperti simpul jahitan. Jejak kaki yang terkumpul menjadi peta, dan peta yang terkumpul menjadi kenangan. Setiap hari yang dilalui bersama menumpuk rapi pada tag kecil ini."},"ICON-1675":{"nm":"Piring Pakan Burung","de":"Letakkan piring di ambang jendela, taburkan beberapa butir milet, dan tamu-tamu tak dikenal pun berdatangan terbang satu demi satu. Bunyi mematuk yang riuh, kepakan sayap yang gemerisik. Ini meja kecil tempat segenggam pemberian mendatangkan konser mungil setiap pagi."},"ICON-1676":{"nm":"Wadah Pengamatan Tupai","de":"Di dalam wadah bening, kau bertemu pandang dengan mata bulat seekor tupai. Pipinya penuh terisi biji ek, memiringkan kepala—sungguh pemandangan. Di atas janji untuk mengintip sebentar dan segera melepaskannya, kau bertukar sapa singkat dengan sepotong kecil alam liar."},"ICON-1677":{"nm":"Cetakan Gips Jejak Kaki","de":"Kau menuangkan gips lembut untuk mencetak jejak kaki kecil. Selagi menunggu mengeras, waktu di halaman pun berhenti sejenak. Cap kaki sejengkal yang pasti akan lenyap seiring pertumbuhannya, cetakan putih ini mengangkatnya bagaikan keabadian dan menyerahkannya perlahan ke kedua tanganmu."},"ICON-1678":{"nm":"Tutup Lensa Teropong Malam","de":"Kau menutupkan tutup kecil pada ujung lensa yang menatap ke dalam malam. Agar kaca yang telah menyaksikan bintang dan sarang menanti malam berikutnya tanpa sebutir debu pun. Bahkan mata yang melihat kegelapan dengan jernih membutuhkan sebuah koma istirahat sepanjang siang."},"ICON-1679":{"nm":"Penanda Perlindungan Sarang","de":"Menemukan sarang di antara ranting, kau mendirikan penanda alih-alih mendekat. \"Ada keluarga burung di sini, mohon tenang.\" Mengawasi tanpa mengganggu—satu langkah lembut ke belakang itulah yang membuat sarang paling aman."},"ICON-1680":{"nm":"Chip Perekam Suara Hewan","de":"Nyanyian semak rumput, kicauan di bawah atap, suara serangga malam—kau tak mengurungnya dalam chip, melainkan meminjamnya sejenak. Sebuah kotak suara kecil yang, saat diputar ulang, menghidupkan kembali bahkan udara saat itu. Agar segala yang pernah terdengar tak pernah benar-benar lenyap."},"ICON-1681":{"nm":"Penutup Teropong Pengamatan","de":"Tepat sebelum seekor burung terbang, hutan menahan napas sejenak. Pada saat sunyi itu, selembar kain yang menutupi lensa menjaga kejernihan tempat yang jauh, tak tersentuh noda jari sedikit pun."},"ICON-1682":{"nm":"Tali Kamera Jalan Hutan","de":"Setiap kali mendaki jalan hutan yang curam, kamera menyentuh dada dengan lembut berulang kali. Detak jantung yang berdebar dan suara rana bergoyang dalam irama yang sama, dan seutas tali ini menahan momen-momen itu dengan kokoh di depan dada."},"ICON-1683":{"nm":"Kartu Panduan Alam","de":"Bahkan sehelai rumput pun punya nama, kartu ini diam-diam memberitahu. Ketika sesuatu yang dulu terlewat tanpa diketahui mendapat sebutan, jalan gunung tiba-tiba dipenuhi wajah-wajah akrab yang hangat."},"ICON-1684":{"nm":"Tambalan Perbaikan Layar","de":"Bahkan kain yang menerima angin dengan seluruh tubuhnya menyisakan luka. Dengan sepotong kain kecil yang ditambalkan perlahan di tempat yang robek, layar itu mendapatkan kembali haknya untuk memeluk laut lepas."},"ICON-1685":{"nm":"Papan Latihan Simpul Tali","de":"Ke atas, ke bawah, lilit sekali lagi—urutan yang telah dihafal tangan itu menjadi sebuah simpul. Pada malam ketika badai menghantam geladak, satu prosedur itulah yang mengikat manusia dan kapal menjadi satu."},"ICON-1686":{"nm":"Tutup Rantai Jangkar","de":"Jangan pandang remeh topi kecil yang dipasang di ujung rantai besi ini. Karat tumbuh diam-diam di dalamnya, maka sebuah tutup yang berdiri melawan angin laut diam-diam memperpanjang umur jangkar itu."},"ICON-1687":{"nm":"Bendera Penanda Jalur","de":"Pada hari ketika kabut begitu pekat hingga jarak pandang terhapus, sehelai bendera berbicara menggantikan jalan itu. Setitik warna yang berkibar tertiup angin akhirnya melonggarkan bahu nakhoda yang kaku karena tersesat."},"ICON-1688":{"nm":"Gantungan Kunci Kabin","de":"Di atas laut yang bergoyang, sebuah cincin kecil tergantung di pintu kabin yang sempit. Selama kunci itu menjaga tempatnya, sebuah kamar untuk kembali tak pernah terkunci bagimu."},"ICON-1689":{"nm":"Wadah Peta Anti Air","de":"Dalam hujan, peta kertas lebih dulu menghapus jalan. Selagi selembar peta bertahan kering di dalam wadah bening, bahkan perjalanan yang basah kuyup pun tak pernah kehilangan arah."},"ICON-1690":{"nm":"Sumbu Lampu Kapal","de":"Minyak yang perlahan diserap sumbu akhirnya mekar menjadi nyala api. Setitik cahaya di atas geladak, dan pada satu getar kecil itu, jarak laut malam yang seolah tak terjangkau pun diam-diam mendekat."},"ICON-1691":{"nm":"Kain Sinyal Darurat","de":"Pada jarak yang tak terjangkau suara, tangan yang mengibarkan kain merah tinggi-tinggi menjangkau lebih jauh daripada kata-kata. Selembar kain ini menembus angin, berteriak menggantikanmu bahwa ada seseorang yang hidup di sini."},"ICON-1692":{"nm":"Pin Penunjuk Arah Angin Laut","de":"Orang yang tahu dari mana angin bertiup, dialah yang menentukan haluan. Pada satu arah yang ditunjuk diam-diam oleh pin kecil ini, nasib pelayaran sehari penuh diam-diam bersandar."},"ICON-1693":{"nm":"Sarung Sekop Lipat","de":"Lipat mata sekopnya dan tutup, dan bahkan sekop yang rajin pun menghela napas sejenak. Hal terakhir yang dilakukan tangan yang telah menggali seluruh tanah adalah merawat mata sekop esok hari agar tak tumpul."},"ICON-1694":{"nm":"Wadah Kompas Saku","de":"Jarum selalu menunjuk utara tanpa gemetar, namun yang melindungi jarum itu adalah wadah yang kokoh. Semakin sering seseorang pernah tersesat, semakin dalam ia mendekap arah dengan penuh sayang."},"ICON-1695":{"nm":"Jaring Peralatan Makan Kemah","de":"Kau menggantung piring yang telah dicuci di jaring untuk dikeringkan di bawah sinar matahari pagi. Sehari di perkemahan dimulai dengan bunyi air yang mengering, dan hal sekecil itu mengisi tenda dengan rasa lega."},"ICON-1696":{"nm":"Kartu Izin Berkemah","de":"Izin untuk bermalam di gunung ini. Begitu selembar kertas berada di tanganmu, bahkan hutan yang asing pun sejenak menjadi sekutumu dan menerima tenda kecilmu dengan lembut."},"ICON-1697":{"nm":"Tali Bendera Jalur Jelajah","de":"Ikat bendera di setiap percabangan jalan, dan jalan pulang tak akan tercerai berai dalam gelap. Satu penanda kecil yang ditinggalkan orang yang berjalan lebih dulu diam-diam mendorong punggung langkah yang mengikuti di belakang."},"ICON-1698":{"nm":"Kaleng Korek Api Anti Air","de":"Korek api tenggelam oleh setetes air pun akan bungkam selamanya. Tersegel dalam kaleng yang tak bisa dimasuki setetes air pun, bara api menunggu diam dan kering, hanya untuk malam yang paling dingin."},"ICON-1699":{"nm":"Filter Air Portabel","de":"Bahkan air keruh yang membuat ragu pun menjadi jernih setelah melewati filter ini. Sebuah alat kecil yang meletakkan keraguan lebih dulu daripada rasa haus—keyakinan bahwa air ini bisa diminum itulah seteguk kedamaian."},"ICON-1700":{"nm":"Paket Selimut Darurat","de":"Dilipat, ia hanya sebesar telapak tangan; dibentangkan, ia menjadi kehangatan seorang manusia. Agar kata \"darurat\" terasa sedikit lebih ringan, selimut ini selalu bersiap untuk menghangat di sudut tas."},"ICON-1701":{"nm":"Gelang Penanda Malam","de":"Di jalan gunung yang telah gelap gulita, sebuah pergelangan tangan memancarkan cahaya lembut. Pita kecil yang menandai keberadaan satu sama lain itu menyatukan mereka yang berjalan bersama dengan benang tak terlihat yang penuh kasih."},"ICON-1702":{"nm":"Stiker Helm Penambang","de":"Stiker yang ditempel di helm adalah nama panggilan lain bagi penambang. Di lorong tambang yang dalam, tempat cahaya sekalipun begitu berharga, seorang rekan dikenali dengan hangat lewat gambar kecil itu yang berpendar di bawah lampu."},"ICON-1703":{"nm":"Pin Penanda Urat Bijih","de":"Di tempat urat bijih ditemukan, sebuah pin ditancapkan dengan tenang. Satu titik yang bersinar sendirian dalam kegelapan itu dengan lembut memberi tahu siapa pun yang datang berikutnya untuk mulai menggali dari sini."},"ICON-1704":{"nm":"Penggaris Pengukur Retakan","de":"Mengukur retakan yang membelah dinding adalah kesabaran yang lambat dan tekun. Apakah celahnya melebar selebar telapak tangan sejak kemarin? Angka kecil yang ditunjukkan penggaris itu menangkap keruntuhan sebelum ia benar-benar terjadi."},"ICON-1705":{"nm":"Kertas Gesekan Relief Kuno","de":"Kertas diletakkan di atas ukiran pada batu, lalu tinta ditepuk perlahan-lahan. Saat sentuhan dari seribu tahun lalu muncul dalam guratan hitam, gesekan itu untuk sesaat mendudukkan waktu yang telah berlalu tepat di hadapanmu."},"ICON-1706":{"nm":"Kotak Koin Kuno","de":"Kepingan logam kecil ini, yang tertidur tenang dan terjaga dari karat, menyimpan suara terakhir dari sebuah bangsa yang telah lenyap. Satu masa utuh bersemayam dalam sekeping koin, menua perlahan di dalam kotak beningnya."},"ICON-1707":{"nm":"Dudukan Pecahan Kristal","de":"Bahkan kristal yang mengurung cahaya di dalamnya butuh sesuatu untuk bersandar. Begitu ia diletakkan dengan lembut di atas dudukan kecil itu, sesuatu yang begitu rapuh akhirnya membentangkan kilaunya secara utuh."},"ICON-1708":{"nm":"Potongan Peta Gua","de":"Peta yang robek hanya memperlihatkan separuh rahasianya secara sekilas. Hingga hari ketika kepingan lain ditemukan, selembar ini akan terus menyembunyikan separuh jalan di suatu tempat di dalam gua."},"ICON-1709":{"nm":"Karabiner Turun Tali","de":"Untuk menyerahkan tubuh menuruni tebing, kau harus lebih dulu mempercayai penuh karabiner ini. Menggantungkan berat badan pada sekeping logam dingin—begitulah sejatinya kepercayaan, sesuatu yang seberat itu."},"ICON-1710":{"nm":"Surat Izin Penggalian","de":"Selembar kertas dengan cap yang jelas mengizinkan tanah untuk digali. Untuk membangunkan yang terkubur, mintalah izin lebih dulu—penggalian dengan tenang mengajarkan cara memulai dengan kesantunan."},"ICON-1711":{"nm":"Kemasan Penahan Angin","de":"Bentangkan dengan punggung menghadap angin, dan sepetak ketenangan pun tercipta di tengah padang yang bergemuruh. Di balik selembar penahan ini, api kecil terlindungi dan orang yang lelah bisa beristirahat sejenak."},"ICON-1712":{"nm":"Penutup Kacamata Badai Pasir","de":"Sekeras apa pun pasir menerjang, pandangan setidaknya harus tetap terjaga sampai akhir. Selembar penutup tipis pada kacamata itu menjadi keberanian untuk tetap membuka mata dan terus melangkah, bahkan di tengah badai."},"ICON-1713":{"nm":"Nampan Penyambut Tamu Hujan","de":"Air hujan menetes dari ujung sepatu tamu yang datang berkunjung. Sebuah nampan yang diletakkan tenang di depan pintu diam-diam dan hangat menyambut kaki yang basah dan mendingin."},"ICON-1714":{"nm":"Tag Pendingin Gelombang Panas","de":"Tag kecil yang perlahan mendinginkan terik siang hari. Tergantung di tas, ia menyimpan kesejukannya, lalu diam-diam menyelipkan segenggam keteduhan tepat saat keringat mulai menetes."},"ICON-1715":{"nm":"Sabuk Penghangat Tangan Musim Dingin","de":"Sebuah sabuk hangat yang dililitkan sekali di pinggang. Ketika kehangatan si penghangat tangan menjalar ke punggung bawah, bahkan padang di puncak musim dingin yang menggigit pun menjadi sedikit lebih tertahankan."},"ICON-1716":{"nm":"Kantong Penyerap Kelembapan","de":"Kelembapan menggerogoti benda tanpa suara. Sementara kantong kecil di dalam kotak diam-diam menyerap uap air, barang-barang yang disayangi tetap terjaga bentuknya, kering dan utuh."},"ICON-1717":{"nm":"Penutup Sepatu Anti-Lumpur","de":"Ada kalanya sepatu saja harus tetap bersih meski berjalan menembus lumpur. Pelindung tipis yang menahan lumpur ini membuat langkah yang melewati ambang pintu rumah terasa jauh lebih ringan."},"ICON-1718":{"nm":"Penutup Lampu Kabut Laut","de":"Ketika kabut laut hendak menelan bulat-bulat cahaya lampu, penutup ini diam-diam mengumpulkan serat cahaya yang tercerai-berai. Bahkan di fajar yang buram, satu cahaya pelabuhan tetap enggan padam hingga akhir."},"ICON-1719":{"nm":"Pin Peringatan Petir","de":"Ketika awan gelap merendah, sebuah pin lebih dulu menyampaikan peringatan. Kata untuk merunduk sebelum petir menyambar—kerendahan hati di hadapan alam memang selalu lebih baik dipelajari sejak awal."},"ICON-1720":{"nm":"Penanda Buku Resep","de":"Pembatas buku kecil yang diselipkan di antara halaman buku masak yang terbuka. Saat kau meraba-raba mencari kembali baris yang hilang di depan kompor, cita rasa masakan ibu pun turut terjaga di halaman itu."},"ICON-1721":{"nm":"Tongkat Takaran Bumbu","de":"Ibu selalu hanya bilang \"satu jumput.\" Perkiraan mata tak mungkin selalu tepat, namun cita rasa tangannya tak pernah goyah. Sambil menakar garam dengan tongkat ini, kau menyadari bahwa yang matang lebih lama dari sekadar takaran bukanlah perkiraan, melainkan cinta."},"ICON-1722":{"nm":"Pita Penutup Fermentasi","de":"Tahukah kau bahwa guci pun bernapas? Ketika pita ini memeluk erat tutupnya, bagian dalam dan luar perlahan mulai saling bertukar kata. Baru setelah hari-hari yang tak tergesa itu berlalu, penantian akhirnya mendapatkan namanya sebagai rasa."},"ICON-1723":{"nm":"Cip Label Pematangan","de":"Sekeping cip kecil dengan tanggal pembuatan yang tertulis rapi. Tulisannya kian pudar, sementara isinya justru semakin dalam. Mencatatnya seolah hendak dilupakan, lalu suatu hari tiba-tiba mengeluarkannya kembali—begitulah pematangan menjadi janji yang ditepati."},"ICON-1724":{"nm":"Saringan Kaldu","de":"Kaldu yang bening hanya datang setelah disaring, dan disaring lagi. Menyaksikan jaring yang menahan ampas dan membiarkan hanya sarinya mengalir, ucapan dapur lama itu—bahwa kedalaman mengendap di tempat sesuatu telah disisihkan—sampai ke ujung jarimu."},"ICON-1725":{"nm":"Kain Pengembang Adonan","de":"Selembar kain diletakkan lembut menutupi adonan. Sementara ragi dengan tekun mengembang di bawah keremangan itu, kau untuk pertama kalinya belajar kelembutan hal-hal yang tumbuh diam-diam di tempat yang tak terlihat."},"ICON-1726":{"nm":"Pin Persiapan Bahan Masakan","de":"Pin kecil yang membelah serat daun bawang dan menahan bawang putih dengan kokoh. Persiapan bahan bagai salam pertama yang disampaikan kepada bahan masakan, sehingga semakin cermat kau merapikannya, semakin cerah pula cahaya meja makan di malam hari."},"ICON-1727":{"nm":"Penjepit Penataan Hidangan","de":"Di mana potongan terakhir di atas piring akan diletakkan, pada akhirnya penjepit inilah yang menentukan. Pada sesaat singkat ketika tangan yang terampil ragu setengah ketukan di udara, satu sajian pun diam-diam berubah menjadi sebuah lukisan."},"ICON-1728":{"nm":"Penutup Kotak Bekal Penghangat","de":"Bekal yang diterima di depan gerbang sekolah harus tetap hangat sampai bel makan siang berbunyi. Kehangatan yang tersimpan di dalam penutup ini tak mendingin, sedalam hati seseorang yang berdiri di depan kompor sejak fajar."},"ICON-1729":{"nm":"Kupon Undangan Makan","de":"\"Ayo makan di rumah kami suatu kali.\" Adakah kata yang lebih hangat dari itu? Tanpa janji muluk, sekadar duduk di meja yang sama—undangan tertua yang bisa disampaikan dalam bahasa Korea tersimpan dalam selembar ini."},"ICON-1730":{"nm":"Cip Reservasi Meja","de":"Kau menuliskan nama dan menahan tempat duduk. Selagi sekeping cip kecil mengikat meja kosong menjadi milik seseorang untuk sementara, waktu yang telah dijanjikan pun mendekat perlahan, seperti derap langkah kaki."},"ICON-1731":{"nm":"Kartu Penilaian Cicip Rasa","de":"Wajah-wajah yang menggigit sesuap dan dengan serius memberi bintang penilaian. Satu baris jujur yang tertulis rapi di kartu ini adalah omelan paling hangat yang ada, demi membuat hidangan berikutnya lebih lezat lagi."},"ICON-1732":{"nm":"Pita Ucapan Terima Kasih Bekal","de":"Kau melilitkan sehelai pita pada kotak bekal yang telah dikosongkan bersih dan mengembalikannya. Bahkan orang yang tak pernah sempat mengucap terima kasih pun mengikat, setidaknya dalam simpul ini, perasaan yang tak sanggup ia ucapkan."},"ICON-1733":{"nm":"Tag Penanda Alergi","de":"Satu tag kecil ini diam-diam menjaga meja makan seseorang. Menuliskan dengan jelas apa yang terkandung di dalamnya adalah nama lain dari keramahan—kepedulian yang menjangkau bahkan hal yang tak terlihat."},"ICON-1734":{"nm":"Sendok Kenangan Rasa","de":"Rasa yang lama bertahan di ujung lidah itu, sesungguhnya adalah pemandangan hari itu. Melihat bagaimana satu sendok bisa membawamu seketika kembali ke dapur masa kecil, tampaknya kenangan adalah sesuatu yang disendok dan disimpan oleh hati, bukan oleh perut."},"ICON-1735":{"nm":"Token Menu Hari Ini","de":"Mau makan apa hari ini. Di hadapan pertanyaan tersulit di dunia, kita selalu kalah. Setelah membalik token ini dan menyerahkan menu pada takdir, hati pun—di luar dugaan—menjadi ringan dan riang."},"ICON-1736":{"nm":"Bel Meja Makan Bersama","de":"Sekali lonceng berbunyi, keluarga yang tersebar di kamar masing-masing berkumpul di satu tempat. Bunyi bel di atas meja bundar itu adalah terjemahan paling akrab dari kata-kata \"sudah siap, ayo cepat.\""},"ICON-1737":{"nm":"Kartu Urutan Hidangan Penutup","de":"Yang manis selalu datang paling akhir. Janji yang tak diketahui siapa yang membuatnya itu dijaga oleh kartu ini. Pembawa acara meja makan yang kecil dan lembut, menyisihkan puncak selera hingga satu suap hidangan penutup."},"ICON-1738":{"nm":"Token Tawar-Menawar","de":"Di tengah pasar, \"kurangi sedikit dong\" dan \"ini sudah rugi lho\" bertabrakan dengan akrab. Token ini adalah bukti pelanggan lama, di mana tawar-menawar itu pada akhirnya selalu berakhir dengan tawa."},"ICON-1739":{"nm":"Pin Pemeriksaan Stok","de":"Kau menyisir rak gudang dengan tenang, menemukan tempat yang kosong, dan menancapkan pin. Mengetahui apa yang tersisa dan apa yang habis—pekerjaan besar bernama rumah tangga selalu dimulai dari pemeriksaan kecil ini."},"ICON-1740":{"nm":"Sikat Pembersih Lapak","de":"Di sore hari setelah pasar bubar, suara sikat yang menyapu lapak kosong menggema pelan di toko. Di ujung jari yang membersihkan tempat untuk diisi kembali esok hari, tersimpan ketekunan yang mengikat hari itu dengan rapi."},"ICON-1741":{"nm":"Kartu Rekomendasi Hari Ini","de":"\"Yang ini enak hari ini.\" Selembar kartu yang disodorkan diam-diam oleh sang pemilik toko. Dalam rekomendasi yang lembut mendorong bahu pelanggan yang ragu memilih itu, tersimpan rapi kebanggaan sehari penuh."},"ICON-1742":{"nm":"Kartu Stempel Pelanggan Setia","de":"Isi sepuluh kali, yang kesebelas gratis. Kartu ini, dengan kotak-kotak stempelnya yang terisi sedikit demi sedikit, adalah wajah lain dari kata \"pelanggan setia,\" sebab sering mampir pada akhirnya berarti menyukainya."},"ICON-1743":{"nm":"Klip Buku Catatan Tukar-Menukar","de":"Klip yang mengumpulkan dan menahan catatan barang-barang yang ditukar dan dikembalikan. Semakin banyak yang berpindah tangan, semakin tebal buku catatan itu, dan seiring ketebalannya itu, kepercayaan yang terjalin dengan tetangga pun turut menebal."},"ICON-1744":{"nm":"Label Terjual Habis","de":"Saat label ini tertempel pada yang terakhir, hati pun terasa penuh dengan aneh. Ini adalah perpisahan singkat, seperti kata \"sampai jumpa,\" bagi barang yang akan pergi menuju meja makan seseorang, ke suatu sudut kamar."},"ICON-1745":{"nm":"Keranjang Barang Reservasi","de":"Sebuah keranjang bertuliskan namamu menjaga satu petak di rak. Tempat yang sudah dititipkan lebih dulu itu diam-diam berkata kepadamu yang baru masuk, \"aku sudah menunggumu sedari tadi.\""},"ICON-1746":{"nm":"Alas Meja Pembungkus","de":"Alas yang terhampar di meja pembungkus adalah panggung bagi tangan-tangan yang sibuk. Dalam waktu singkat ketika kertas dilipat dan tali diikat dengan rapi, sebuah benda biasa diam-diam berubah menjadi hadiah untuk seseorang."},"ICON-1747":{"nm":"Nota Janji Kunjungan","de":"\"Aku akan mampir besok.\" Secarik nota yang ditulis satu baris dan diselipkan pelan di celah pintu. Bahkan ketika wajah tak sempat bertemu, janji itu menumpang selembar kertas, tiba lebih dulu daripada orangnya, menunggu dengan tenang."},"ICON-1748":{"nm":"Keranjang Hadiah Tetangga","de":"Keranjang yang disodorkan lewat pagar selalu disertai alasan \"aku bikin kebanyakan, sih.\" Kehangatan khas Korea menyeberang ke sisi ini begitu saja, berpura-pura acuh di balik kedok kelimpahan."},"ICON-1749":{"nm":"Kotak Kabar Desa","de":"Kabar besar dan kecil dari desa menumpuk rapi di dalam kotak ini. Siapa yang baru pindah, keluarga siapa yang sedang mengadakan pesta—beberapa lembar kertas berkumpul menyampaikan denyut tenang dari lingkungan sekitar."},"ICON-1750":{"nm":"Stempel Terima Kasih Kunjungan","de":"Rasa terima kasih atas kedatangan seseorang ditekan kuat dengan satu stempel. Satu bekas tinta yang membekas di kertas itu bertahan lebih lama di tempatnya daripada kata-kata \"aku takkan lupa.\""},"ICON-1751":{"nm":"Kartu Pujian Kebaikan","de":"Kartu tempat kau menuliskan dengan tenang kebaikan yang diberikan seseorang hari ini lalu mengembalikannya. Di desa yang bersusah payah menuliskan kelembutan-kelembutan kecil, hal-hal baik terus berputar dan kembali lagi."},"ICON-1752":{"nm":"Segel Surat Permintaan Maaf","de":"Seperti apel yang matang merona merah, kata maaf pun hanya bisa disampaikan setelah cukup matang. Segel yang ditekan kuat di amplop ini adalah bekas keberanian yang memeluk permintaan maaf yang sulit diucapkan hingga akhir."},"ICON-1753":{"nm":"Papan Tugas Bersama","de":"Selembar papan yang ditulis dalam kolom-kolom, siapa mengerjakan apa. Pekerjaan yang berat sendirian menjadi jauh lebih ringan begitu nama-nama dibagi di dalamnya—siapa pun yang pernah bahu-membahu bekerja pasti tahu itu."},"ICON-1754":{"nm":"Pita Selera Tetangga","de":"Kau diam-diam menandai apa yang disukai tetangga dengan pita berwarna-warni. Mengingat selera seseorang adalah pengakuan paling diam-diam bahwa kau menyayanginya, tanpa pernah perlu mengatakannya."},"ICON-1755":{"nm":"Cincin Papan Nama Undangan","de":"Sebuah cincin yang tergantung di papan nama mengumumkan \"hari ini menerima tamu.\" Ia hanyalah penanda seukuran telapak tangan, namun di dalamnya tergantung hati yang terbuka lebar, telah selesai bersiap menyambut seseorang."},"ICON-1756":{"nm":"Gelang Masuk Festival","de":"Sehelai pita yang telah pudar warnanya, dikenakan selama berhari-hari karena terlalu sayang untuk dilepas. Baru ketika ia terpasang di pergelangan tangan, festival itu sungguh-sungguh dimulai. Di dalamnya tertidur utuh sebuah hari yang tak pernah benar-benar berakhir meski telah usai."},"ICON-1757":{"nm":"Dompet Tiket Kembang Api","de":"Tepat sebelum langit malam meletus, tiket di dalam dompet ini menggenggam erat debar jantung. Ia adalah janji yang digenggam hingga telapak tangan berkeringat, semata untuk sesaat itu ketika kembang api pertama mekar dengan letusan."},"ICON-1758":{"nm":"Piring Penyambut Bulan","de":"Ada malam-malam yang terasa seperti menyendok bulan purnama utuh ke dalam piring. Susun buah segar dan songpyeon dengan rapi di atas piring ini dan bersujudlah kepada bulan, maka satu hati yang bundar akan sampai ke ujung langit."},"ICON-1759":{"nm":"Pin Sarung Tangan Festival Musim Dingin","de":"Meski tangan membeku di atas salju, sarung tangan terus saja melorot dari pergelangan. Baru setelah pin ini terpasang erat di ujung lengan, kau bisa berlarian sepuas hati di festival musim dingin."},"ICON-1760":{"nm":"Kartu Benih Penyambut Musim Semi","de":"Beberapa butir benih yang tertidur di dalam kartu masing-masing menantikan musim seminya. Menguburnya di tanah, dan ia bertunas tanpa gagal bagai sebuah janji—tampaknya setiap awal bermula dari satu titik kecil yang kokoh."},"ICON-1761":{"nm":"Stempel Pantai Musim Panas","de":"Ombak menekankan cap kuat di pasir lalu surut perlahan. Meski tahu akan segera terhapus, ia tetap meninggalkan tanda kecil bahwa seseorang pernah datang ke sini. Musim panas selalu tertera jelas sekali seperti ini, lalu hanyut bersama aroma asin laut."},"ICON-1762":{"nm":"Pita Panen Musim Gugur","de":"Tangan yang mengikat bulir-bulir padi akhirnya mengikat pita dengan rapi. Satu simpul yang merangkum keringat setahun dengan penuh perhatian. Meski ladang mengosong, musim gugur menyampaikan satu salam lagi dalam warna terindahnya, laksana senja."},"ICON-1763":{"nm":"Gelembung Kata Foto Kenangan","de":"\"Terima kasih sudah datang sejauh ini.\" Sapaan yang tak pernah sanggup diucapkan itu mengembang bundar di atas kertas. Sekeping hati yang bundar, dengan lembut meminjamkan suara pada kebisuan yang terhenti dalam foto."},"ICON-1764":{"nm":"Pin Peta Lokasi Festival","de":"Penanda yang ditancapkan seseorang agar kau tak tersesat di halaman yang luas. Meski kaki lebih dulu berlari mengejar suara musik rakyat, satu pin ini dengan tenang menuntun kamu yang tersesat itu ke tempat yang telah dijanjikan."},"ICON-1765":{"nm":"Kunci Master Album","de":"Yang terkunci bukanlah album, melainkan waktu yang tersegel di dalamnya. Getaran rekaman pertama, fajar dari mix terakhir. Putar kuncinya perlahan, dan pintu ruangan yang hanya diketahui oleh mereka yang membuatnya itu pun berderit terbuka."},"ICON-1766":{"nm":"Kartu Daftar Lagu","de":"Urutan lagu yang tertulis di selembar kertas ini sesungguhnya adalah urutan hati. Di mana tenggorokan akan tercekat, di mana napas harus ditahan—kertas ini sudah tahu semuanya lebih dulu. Debar yang menggelora bahkan sebelum nada pertama terdengar."},"ICON-1767":{"nm":"Tag Pemeriksaan Rekaman","de":"Hanya orang yang telah memutar ulang bagian yang sama seratus kali yang menempelkan tag ini. Sekali lagi, hanya sekali lagi saja. Di samping cap lolos itu tersembunyi malam seseorang yang meragukan telinganya sendiri hingga fajar."},"ICON-1768":{"nm":"Label Pre-Order","de":"Janji untuk menunggu sesuatu yang bahkan belum hadir di dunia. Begitu label ini tertempel, satu tempat kosong diam-diam dipesan atas nama seseorang. Bahkan penantian yang berdebar pun punya nomor antreannya sendiri."},"ICON-1769":{"nm":"Stiker Segel Cetakan Pertama","de":"Ia menyerupai sentuhan lama menutup guci dengan kertas hanji dan menyegelnya dengan lem. Selembar yang berikrar menjaga segalanya tetap seperti semula. Karena tahu akan lenyap begitu dikupas, kau terus menatap wujudnya lebih lama lagi."},"ICON-1770":{"nm":"Cip Kalender Comeback","de":"Tambahkan satu lingkaran di kalender, dan malam yang tersisa hingga hari itu memendek satu petak. Tanggal kembalinya jelas tertulis di cip kecil dalam genggamanmu. Bagi yang menunggu, waktu dihitung dengan tangan, begitu adanya."},"ICON-1771":{"nm":"Sampul Foto Konsep","de":"Sebelum konsep berikutnya menggeser warna konsep ini, selembar plastik bening menyimpan rapi seratnya. Agar tak terlupakan saat musim berganti, ia dengan lembut menjaga corak hari-hari yang telah lewat, hingga ke sudut-sudutnya."},"ICON-1772":{"nm":"Token Pengungkap Teaser","de":"Tepat sebelum tirai tersingkap, sekeping koin kecil digenggam di telapak tangan. Begitu ia disodorkan, adegan pertama yang terkunci itu terbuka sejengkal ke arah dunia. Pengungkapan, pada akhirnya, adalah soal siapa yang lebih dulu mengulurkan tangan."},"ICON-1773":{"nm":"Dudukan Pajangan Album","de":"Begitu sebuah dudukan rendah mengangkat album sedikit, selembar cakram biasa pun menjadi bintang utama pajangan. Pemeran pendukung yang lembut, menopang dari belakang dalam diam, sudut di mana cahaya jatuh paling indah."},"ICON-1774":{"nm":"Pas Showcase Debut","de":"Selembar pas bertuliskan kata-kata \"kami perkenalkan untuk pertama kalinya.\" Dari koridor panjang di balik panggung hingga tepuk tangan pertama dari kursi penonton, pas ini membawamu melewati ambang pintu debut yang berdebar."},"ICON-1775":{"nm":"Cip Penanda Posisi Panggung Pertama","de":"Kau meraba dengan ujung kaki cip yang tertempel di lantai. Satu petak yang lebih dulu diketahui tubuh, bahkan tanpa melihat. Begitu kau tepat mendarat di tempat yang telah dihafal, getaran di ujung jari akhirnya berubah menjadi gerakan yang jelas."},"ICON-1776":{"nm":"Kartu Kata Sambutan","de":"Bahkan kalimat lazim \"semua ini berkat kalian\" tak lagi terasa lazim ketika ditulis dengan tulisan tangan yang gemetar. Beberapa baris yang dicatat lebih dulu karena takut terlupa saat haru menyergap. Ketulusan kadang bersandar pada selembar kartu."},"ICON-1777":{"nm":"Jadwal Pemotretan Profil","de":"Selembar jadwal dengan tanggal untuk berdiri di depan lensa tertulis rapi. Sebuah jadwal untuk perlahan menyiapkan wajah terbaik. Setiap kolom kosong yang terisi membuat malam yang dihabiskan di depan cermin semakin panjang."},"ICON-1778":{"nm":"Formulir Pendaftaran Fan Club","de":"Selembar formulir pendaftaran tempat nama dan hati dituliskan malu-malu dalam satu baris. Mengatakan suka selalu sulit, namun formulir ini menuliskan kata-kata itu dengan rapi untukmu. Tanda tangan pertama untuk memilih bersama."},"ICON-1779":{"nm":"Lembar Periksa Hadiah Debut","de":"Sentuhan yang memeriksa satu per satu, membayangkan orang yang akan menerimanya. Apakah sudutnya tak lecet, apakah hatinya tak tertinggal? Hadiah telah dicintai satu kali bahkan sebelum diserahkan, dan berangkat begitu saja."},"ICON-1780":{"nm":"Penanda Akhir Panggung","de":"Tepat sebelum layar turun, sebuah penanda diletakkan di tempat pose terakhir bertahan. Bukan pertanda akhir, melainkan sebuah titik kecil yang mengikat akhir itu dengan rapi. Hanya panggung yang ditutup dengan baik yang membuka panggung berikutnya."},"ICON-1781":{"nm":"Pin Tunggu Wawancara","de":"Pin yang diam-diam menjaga keheningan sebelum pertanyaan dimulai. Selama keheningan singkat memilih jawaban di kepala, penanda kecil ini dengan lembut berkata untukmu, \"belum, sebentar lagi.\""},"ICON-1782":{"nm":"Amplop Kenangan Debut","de":"Seperti hati zaman dulu yang menyerahkan surat berharga beserta amplopnya ke tangan orang yang hendak berangkat, selembar sampul ini menyimpan catatan panggung pertama dengan penuh perhatian. Pada hari kau membukanya kelak di masa depan, getaran hari itu pun ikut tumpah bersamanya."},"ICON-1783":{"nm":"Sedotan Latihan Napas Vokal","de":"Latihan mengembuskan napas panjang dalam satu aliran lewat ujung pipa tipis. Bernyanyi, pada akhirnya, adalah napas yang terkendali baik—sedotan kecil ini diam-diam mengajarkannya setiap pagi. Angin dulu sebelum suara."},"ICON-1784":{"nm":"Cip Klik Latihan Tempo","de":"Tik, tik, tik—teman paling jujur di dunia. Ia menahanmu saat terburu-buru dan mendorong punggungmu saat melambat. Menanamkan ketukan ke dalam tubuh terasa seperti percakapan panjang dengan cip yang kokoh ini."},"ICON-1785":{"nm":"Pita Pemeriksa Garis Tari","de":"Di mana ujung jari berhenti dan bahu terbuka, kau menelusuri garis gerakan dengan sehelai pita. Garis tari yang tergambar baik tetap lurus dan rapi bahkan di bagian yang tak terlihat dari bangku penonton."},"ICON-1786":{"nm":"Kartu Umpan Balik Ekspresi","de":"Kata-kata itu, bahwa tersenyum pun perlu dipelajari. Selembar kartu yang mencatat rapi sudut mata dan tinggi ujung bibir. Ekspresi yang gagal diberitahu cermin, kartu ini dengan lembut menyampaikannya untukmu."},"ICON-1787":{"nm":"Catatan Alur Rap","de":"\"Berhenti sejenak di sini, curahkan semua di sana\"—sebuah catatan yang menggambarkan lebih dulu alur kata-kata. Semakin cepat bagiannya, semakin jelas harus jalur napasnya. Di dalam anak panah yang digoreskan cepat itu, ritme sebuah bait hidup dan bernapas."},"ICON-1788":{"nm":"Stiker Suhu Vokal","de":"Suara pun punya hari hangat dan hari dingin. Sebuah penanda kecil yang kau pilih warnanya dan tempelkan untuk corak hari ini. Menghangat dan mendingin bergantian, suara terbangun setiap hari pada suhu yang sedikit berbeda."},"ICON-1789":{"nm":"Token Rutinitas Istirahat","de":"Sekeping koin yang diselipkan ke tanganmu dengan kata-kata bahwa beristirahat dengan baik pun adalah sebuah kemampuan. Sodorkan ini, dan kau bisa berhenti sejenak tanpa rasa bersalah. Bagi orang yang terus berlari, berhenti adalah pilihan paling berani."},"ICON-1790":{"nm":"Pin Target Pertumbuhan","de":"Sebuah pin kecil yang ditancapkan dengan kata \"coba kita capai sampai sini.\" Meski tampak jauh nyaris tak terjangkau, kau tumbuh selangkah ke arah sana setiap hari. Sebuah target ibarat janji lembut yang melambai dari kejauhan."},"ICON-1791":{"nm":"Amplop Evaluasi Mingguan","de":"Kau mengumpulkan keringat dan air mata seminggu dengan rapi ke dalam satu amplop dan menyerahkannya. Yang baik dan yang masih kurang duduk berdampingan di dalamnya. Membukanya adalah tugas kecil yang diserahkan kepada dirimu di minggu depan."},"ICON-1792":{"nm":"Kaleng Komponen Dekorasi Panggung","de":"Di balik panggung yang gemerlap, hiduplah komponen-komponen tanpa nama. Satu sekrup, satu cincin berkumpul untuk mengapungkan bintang di langit-langit. Buka kalengnya, dan penuhlah dengan kesungguhan kecil yang diam-diam menopang segala kemegahan itu."},"ICON-1793":{"nm":"Papan Konsep Kostum","de":"Menempelkan potongan kain dan warna satu per satu, kau mencoba lebih dulu busana yang belum ada di dunia. Kostum panggung yang lebih dulu selesai di atas papan. Imajinasi selalu berjalan satu langkah lebih dulu daripada jarum jahit."},"ICON-1794":{"nm":"Cip Pencocokan Warna","de":"Baju yang sama pun mengenakan wajah yang sama sekali berbeda tergantung cahayanya. Warna mana yang tersenyum paling cerah bersama orang itu, kau temukan dengan mendekatkan cip satu per satu. Kecocokan adalah temuan di ujung perbandingan yang panjang."},"ICON-1795":{"nm":"Papan Sampel Tali Sepatu","de":"Yang menopang satu langkah kokoh di atas panggung, di luar dugaan, adalah sehelai tali kecil. Agar tak terlepas, namun juga tak terlalu ketat. Pertimbangan paling lembut, dibuat di tempat paling rendah, memilih dari berbagai serat tali yang terbentang."},"ICON-1796":{"nm":"Amplop Pemeriksaan Aksesori","de":"Semakin berkilau sesuatu, semakin mencolok satu goresan cacat terlihat. Sentuhan yang menyorotkan perhiasan dari dalam amplop ke cahaya, memeriksanya dengan cermat. Hati yang menelisik hal-hal kecil hingga tuntas itulah yang menjaga panggung."},"ICON-1797":{"nm":"Patch Warna Rambut","de":"Sebuah contoh kecil untuk mencoba lebih dulu musim baru pada rambut. Warna yang menyemat samar pada satu helai itu diam-diam membisikkan kesan pertama dari konsep berikutnya. Perubahan selalu bermula dari tempat seukuran telapak tangan."},"ICON-1798":{"nm":"Kartu Konsep Kuku","de":"Selembar kartu yang menentukan lebih dulu gambar-gambar kecil untuk dilukis di sepuluh ujung jari. Agar konsep itu samar terasa bahkan dalam satu gestur, setiap detail sekecil apa pun didandani dengan cerita secara penuh perhatian."},"ICON-1799":{"nm":"Tiket Ubah Gaya","de":"\"Mungkinkah aku menjadi sedikit berbeda dari kemarin hari ini?\"—selembar tiket yang mewujudkan satu kalimat itu. Rambut, pakaian, atau suasana, tiket ini membuka pintu yang berdebar menuju wujud yang baru."},"ICON-1800":{"nm":"Tag Penyesuaian Ukuran","de":"Sebuah tag yang mencatat dengan teliti tempat yang perlu dikecilkan atau dilonggarkan sampai pas di badan. Seperti sentuhan zaman dulu yang membenahi baju anak jahitan demi jahitan, penyesuaian kecil ini membuat panggung terasa sejengkal lebih nyaman."},"ICON-1801":{"nm":"Kartu Sketsa Thumbnail","de":"Selembar kertas yang belum tersentuh warna. Di atas goresan pensil yang masih kasar, ia diam-diam menerka ke mana adegan berikutnya akan mengalir. Yang lebih mendebarkan dari hasil akhir selalu saja baris pertama yang belum rampung ini, begitu ruang penyuntingan yang sunyi mengingatkan kita."},"ICON-1802":{"nm":"Stiker Persetujuan Syuting","de":"\"Bolehkah saya terekam di sini?\" Alih-alih berkata-kata, sebuah tanda bundar ditempelkan di dada. Selembar stiker kecil membangun janji lembut antara kamera dan hati."},"ICON-1803":{"nm":"Pin Penanda Photo Wall","de":"Sebuah pin kecil tertancap di sudut dinding. Ia menandai lebih dulu siapa akan berdiri di mana. Di setiap tempat pin itu tertancap, sebuah senyum berhenti sejenak dan menjelma selembar foto."},"ICON-1804":{"nm":"Keping Pemilih Cut","de":"Sebuah jari yang menunjuk satu dari ratusan bidikan. Begitu keping ini diletakkan, semua ekspresi yang tersimpan pun seolah telah hidup demi selembar itu saja. Memilih selalu menyerupai perpisahan yang sunyi."},"ICON-1805":{"nm":"Amplop Balik Layar","de":"Segala yang terjadi di balik kamera tersimpan di sini. Begitu bibirnya dilipat, tawa, adegan gagal, dan kuap yang mengantuk tertidur bersama. Yang lebih disayangi daripada tayangan utama seringkali justru isi di dalamnya ini."},"ICON-1806":{"nm":"Memo Permintaan Edit","de":"\"Di sini tambah satu detik lagi, musiknya sedikit dikecilkan.\" Secarik catatan yang penuh sesak tulisan merah. Kerewelan seseorang menyentuh napas video hingga bergeser satu ketukan. Kesempurnaan tumbuh di atas sentuhan-sentuhan kecil semacam ini."},"ICON-1807":{"nm":"Tag Jadwal Unggah","de":"Sebuah tanda kecil yang ditempelkan pada video yang akan melangkah keluar ke dunia sendirian, pukul tujuh besok pagi. Sementara semua orang tertidur, hanya janji itu yang tetap terjaga. Waktu yang telah ditetapkan lebih dulu tak pernah tahu caranya terlambat."},"ICON-1808":{"nm":"Sampul Bingkai Thumbnail","de":"Sebuah sampul yang membungkus adegan pertama yang paling bagus. Sudut-sudutnya dirapikan agar noda tangan maupun debu tak dapat menyentuhnya. Sebelum diperlihatkan, kesan pertama dijaga serapi ini."},"ICON-1809":{"nm":"Keping Durasi Rekaman","de":"Sebuah keping kecil yang mengukur berapa menit rekaman hari ini. Panjang belum tentu baik, pendek pun belum tentu ringan. Hati yang mengetahui panjang yang pas adalah kancing pertama dalam penyuntingan."},"ICON-1810":{"nm":"Lembar Koreksi Yel-Yel","de":"Selembar kertas yang diperiksa sekali lagi sebelum diteriakkan sekuat-kuatnya. Sebab jika satu huruf saja meleset, ribuan suara bisa berantakan. Di balik sorak-sorai, tangan koreksi yang tak terlihat selalu singgah lebih dulu."},"ICON-1811":{"nm":"Sleeve Penyimpan Fan Art","de":"Selembar gambar yang digoreskan seseorang semalam suntuk. Sebuah rumah bening diberikan agar tak kusut. Seolah berkata bahwa yang digambar dengan hati harus dipeluk dengan hati agar bertahan lama, sleeve ini merangkulnya tanpa sepatah kata."},"ICON-1812":{"nm":"Tali Pengurut Surat Fan","de":"Seutas tali yang mengikat rapi tumpukan surat menurut pengirimnya. Dalam setiap simpul, kerinduan sehari tertata rapi. Walau tak bisa membalas, di sinilah tangan yang berusaha tak membiarkan satu pun surat terlewat."},"ICON-1813":{"nm":"Lembar Daftar Tukar Merchandise","de":"\"Ada yang mau tukar dengan punya saya?\" Selembar kertas tempat hati yang berdebar dituliskan dan diulurkan. Hanya karena menyukai hal yang sama, dua orang asing pun sejenak menjadi teman."},"ICON-1814":{"nm":"Keping Kursi Fanchant Bersama","de":"Sebuah keping yang menetapkan tempat duduk berjajar bagi orang-orang berbaju warna senada. Ketika hati-hati yang tercerai berkumpul di satu blok, tribun penonton mulai bernyanyi seperti satu sosok raksasa."},"ICON-1815":{"nm":"Struk Iklan Ulang Tahun","de":"Selembar struk yang diterima setelah menerbangkan cinta ke papan iklan raksasa. Yang tak tertulis di samping nominalnya adalah ketulusan yang terkumpul semalam suntuk. Kertas ini tersisa sebagai satu-satunya bukti perayaan yang ditujukan untuk seorang saja."},"ICON-1816":{"nm":"Sampul Buku Pesan","de":"Sebuah sampul yang membungkus buku kumpulan tulisan tangan banyak orang. Saat dibuka, guratan tangan yang berbeda-beda bertumpuk menjadi satu hati. Luarnya rapi, tapi dalamnya penuh keriuhan yang hangat."},"ICON-1817":{"nm":"Pin Anggota Fan Club","de":"Sebuah pin kecil yang hanya diberikan pada mereka yang menyerukan nama yang sama. Begitu disematkan di dada, rasa suka yang dulunya kesepian berubah menjadi janji bersama. Rasa memiliki ternyata berbentuk bundar seperti ini."},"ICON-1818":{"nm":"Token Semangat Daring","de":"Setitik cahaya yang dilambaikan tangan-tangan dari jauh, melintasi layar. Jarak boleh membentang tak terhingga, tapi iramanya tetap sama. Ini bukti bahwa dukungan pasti sampai, bahkan dari kursi yang tak terlihat."},"ICON-1819":{"nm":"Pecahan Kunci Tua","de":"Sepotong logam yang giginya sudah rompal. Tak ada lagi yang mengingat pintu mana yang dulu dibukanya. Yang bertahan lebih lama daripada tempat yang terkunci selalu saja separuh kunci yang telah kehilangan kegunaannya seperti ini."},"ICON-1820":{"nm":"Peta Lorong Rahasia","de":"Selembar kertas usang yang menggambarkan jalan tersembunyi di balik tanaman rambat. Jalan pintas hanya diketahui mereka yang tahu. Begitu dibentangkan, pulau yang biasa-biasa saja diam-diam berganti wajah menjadi panggung petualangan."},"ICON-1821":{"nm":"Kartu Pemecah Sandi","de":"Sebuah kartu yang mengembalikan huruf-huruf yang berserakan acak ke tempat asalnya. Ketika satu baris berhasil dipecahkan, rahasia berikutnya melambai memanggil. Bahkan simpul yang tampak mustahil terurai pun pada akhirnya bermula dari huruf pertama."},"ICON-1822":{"nm":"Tali Kotak Segel","de":"Seutas tali yang terikat kencang seolah melarang siapa pun membukanya. Hanya yang mengikatnya yang tahu apa yang tertidur di dalam simpul itu. Keinginan untuk melepaskan dan keinginan untuk menjaga terikat berdampingan dalam seutas tali ini."},"ICON-1823":{"nm":"Keping Puzzle Reruntuhan","de":"Sekeping kecil yang terlepas dari dinding batu kuno. Bila dipasang kembali ke tempatnya, keahlian seseorang dari seribu tahun lalu hidup kembali di ujung jari. Mengumpulkan yang tercerai berarti menyambung kembali waktu."},"ICON-1824":{"nm":"Guntingan Legenda Pulau","de":"Selembar kertas berisi salinan tangan dari kisah lama yang beredar di pulau. Benar atau tidaknya tidak terlalu penting. Kisah yang berpindah dari mulut ke mulut, dengan sendirinya, menjadi lingkar tahun pulau ini."},"ICON-1825":{"nm":"Batu Penanda Tersembunyi","de":"Sebongkah batu yang seolah tergeletak begitu saja di pinggir jalan. Hanya kepada mata yang tahu, ia diam-diam menunjukkan arah. Semakin dalam sebuah rahasia ingin dikubur, semakin biasa wajah yang dikenakannya untuk berdiri di sana."},"ICON-1826":{"nm":"Amplop Teka-Teki","de":"Tak ada kata tertulis di sampul luarnya. Sesaat sebelum segel dirobek, itulah momen paling berdebar. Sebelum jawaban digenggam di tangan, segala kemungkinan masih hidup di dalam amplop."},"ICON-1827":{"nm":"Tutup Kaca Pembesar Detektif","de":"Sebuah tutup kecil yang dipasang perlahan di ujung kaca pembesar. Saat tak digunakan mengintip, ia membiarkan lensa beristirahat dengan tenang. Bahwa untuk melihat dengan baik, harus dijaga dengan baik lebih dulu—itulah yang dipelajari sang detektif sejak awal."},"ICON-1828":{"nm":"Tiket Bus Keliling Pulau","de":"Selembar tiket untuk menaiki bus yang mengelilingi pulau. Halte terakhir adalah titik keberangkatan itu sendiri. Di jalan yang berputar-putar dan kembali ke tempat semula, pemandangan selalu tampak sedikit baru setiap kali."},"ICON-1829":{"nm":"Tag Sewa Sepeda","de":"Sebuah tanda yang tergantung di setang sepeda pinjaman. Kebebasan sesaat diizinkan hingga saat dikembalikan. Ketika waktu membelah angin itu berakhir, tag ini diam-diam menarik kembali janji tersebut."},"ICON-1830":{"nm":"Tiket Naik Perahu Kecil","de":"Tiket naik untuk menumpang sebuah perahu kecil. Di atas geladak yang bergoyang, jarak antar pulau kian mendekat. Menyeberangi jalur air selalu membawa serta sedikit debar dan sedikit mabuk laut."},"ICON-1831":{"nm":"Pin Roda Gerobak","de":"Sebuah pin yang mencengkeram kuat roda gerobak barang. Sepotong logam kecil ini membuat muatan berat bisa berguling maju. Bagian yang paling tak terlihat sering kali diam-diam menanggung beban yang paling besar."},"ICON-1832":{"nm":"Token Kereta Gantung","de":"Sebuah token bundar yang dimasukkan ke kereta gantung yang membelah udara. Begitu kaki meninggalkan tanah, seluruh pulau terangkul dalam satu pandangan. Semakin tinggi naik, semakin luas pula pemandangan yang terbentang."},"ICON-1833":{"nm":"Gelang Naik Balon Udara","de":"Sebuah gelang yang dililitkan di pergelangan tangan sebelum naik ke keranjang. Ketika api membumbung dan tanah menjauh, hati pun ikut menjadi ringan. Melayang berarti meletakkan beban untuk sesaat."},"ICON-1834":{"nm":"Keping Panggil Taksi Air","de":"Sebuah keping kecil untuk memanggil taksi yang melaju di atas air. Angkat tangan, dan perahu pun mendekat membelah arus. Yang membuka jalan bahkan di tempat tanpa jalan, pada akhirnya, adalah keberanian orang yang memanggil lebih dulu."},"ICON-1835":{"nm":"Pas Masuk Jalur Pendakian","de":"Sebuah izin masuk yang diberikan di gerbang pertama menuju gunung. Mulai dari sini, ujung kaki sendirilah yang menentukan jalan. Puncak boleh jauh, tapi hanya yang melewati gerbang ini yang dijanjikan pemandangan itu."},"ICON-1836":{"nm":"Kunci Loker Pelabuhan","de":"Sebuah kunci kecil untuk membuka loker di tepi dermaga. Menitipkan bawaan, lalu memandang laut dengan tangan yang telah ringan. Memiliki tempat untuk sejenak meletakkan sesuatu berarti meminjamkan keberanian untuk pergi jauh."},"ICON-1837":{"nm":"Tutup Toples Acar","de":"Sebuah tutup toples yang mengurung hal-hal asam di dalamnya. Bila dikencangkan rapat, mentimun musim panas menjaga kerenyahannya hingga musim dingin. Rahasia mengalahkan waktu, ternyata, berawal dari kemampuan menutup dengan baik."},"ICON-1838":{"nm":"Label Rak Jemuran","de":"Sebuah label nama yang ditempelkan pada barang-barang yang dijemur di rak. Bila dicatat apa dan kapan dijemurnya, penantian pun tak menjadi kacau. Bahkan pada waktu matahari dan angin, urutan tetap dibutuhkan."},"ICON-1839":{"nm":"Amplop Serpihan Asap","de":"Sebuah amplop berisi serpihan kayu wangi. Begitu dibuka, aroma seperti api unggun menyapa hidung lebih dulu. Cita rasa yang mendalam berkat asap hanya terbuka perlahan bagi mereka yang tahu cara menunggu."},"ICON-1840":{"nm":"Stiker Makanan Awetan","de":"Sebuah stiker yang ditempelkan di guci agar bertahan baik sepanjang tahun. Tanggal pembuatan dan ketulusan tertulis di atasnya. Makanan yang disimpan lama untuk dimakan selalu disertai catatan kecil yang berusaha mengenang cita rasa tangan hari itu."},"ICON-1841":{"nm":"Tag Jam Fermentasi","de":"Fermentasi tak percaya pada jam. Sebab ia mengukur waktu dengan aroma, bukan jarum menit. Begitu bau asam menyentuh hidung, tag ini diam-diam mengangguk, \"sudah cukup sekarang.\" Bahkan penantian punya skala ukurannya sendiri."},"ICON-1842":{"nm":"Pin Pengurut Rak Kulkas","de":"Di sinilah polisi lalu lintas kecil dari kulkas. Sayuran di atas, lauk di bawah, sisa kemarin di baris depan. Cukup pasang satu pin, dan tangan yang selalu kebingungan tiap kali membuka pintu pun akhirnya tahu jalannya."},"ICON-1843":{"nm":"Sabuk Penghangat Kotak Bekal","de":"Ibu melilitkan sabuk pada kotak bekal, agar kehangatannya tak kabur sampai makan siang. Ketika sabuk itu dilepas, di bawah tutup yang berembun, ketulusan pagi itu masih terbaring hangat menungguku."},"ICON-1844":{"nm":"Botol Pematang Saus","de":"Bumbu yang baik tak pernah tergesa. Ia diam-diam memberi waktu bagi kecap asin dan bawang putih untuk saling meresap. Di dalam kegelapan botol, rasa mendalam perlahan-lahan, dan kearifan lambat dari halaman guci berpindah duduk ke dalam botol kecil ini."},"ICON-1845":{"nm":"Label Selai Musiman","de":"Stroberi di musim semi, aprikot di musim panas, ara di musim gugur. Selembar label menuliskan musim dengan rapi di atas botol. Buka tutupnya di tengah musim dingin, dan sinar matahari tahun lalu meleleh keluar perlahan, satu sendok demi satu sendok."},"ICON-1846":{"nm":"Papan Lencana Koleksi","de":"Tak perlu repot menghitung berapa banyak yang telah terkumpul, sebab papan lencana ini yang membanggakannya untukmu. Setiap kali satu kotak kosong terisi, bahu pun sedikit terangkat—ini bukan sekadar angka, melainkan jejak langkah yang dicap dengan ujung kaki."},"ICON-1847":{"nm":"Kartu Slot Belum Ditemukan","de":"Satu tempat yang belum dijumpai. Siluet di dalam kartu menawarkan janji hanya dengan garis luar yang samar. Kosong berarti akan segera terisi, maka debar hati selalu menunggumu dalam wujud tanda tanya."},"ICON-1848":{"nm":"Cap Katalog Lengkap","de":"Suara cap yang berdebum jatuh di kotak terakhir. Tutup ensiklopedia itu, buka telapak tangan, dan setitik tinta merah menempel bagaikan lencana kesempurnaan. Kelegaan mendalam yang hanya dipahami mereka yang mengumpulkan hingga tuntas."},"ICON-1849":{"nm":"Keping Warna Kelangkaan","de":"Bahkan bentuk yang sama bisa bercerita berbeda jika warnanya berlainan. Sekeping benda ini diam-diam menggariskan batas antara yang biasa dan yang langka. Mata seorang kolektor selalu berhenti lama di hadapan perbedaan warna yang halus itu."},"ICON-1850":{"nm":"Voucher Tukar Duplikat Koleksi","de":"Keluar lagi, lagi. Pada hari memungut untuk ketiga kalinya sesuatu yang sudah dimiliki, voucher ini diam-diam mengulurkan tangan. Seperti hiburan lembut yang berkata: bila duplikat pun dipeluk, bukan dibuang, suatu hari ia akan kembali sebagai sesuatu yang berharga."},"ICON-1851":{"nm":"Plat Nomor Kotak Koleksi","de":"Bila setiap kotak diberi nomor, gudang pun berubah menjadi perpustakaan kecil. Kotak nomor 17 berisi yang dikumpulkan di musim semi, nomor 23 yang dipungut di tepi laut. Aku adalah indeks yang sunyi, merapikan kenangan yang tercerai satu baris demi satu baris."},"ICON-1852":{"nm":"Panduan Tata Letak Pajangan","de":"Separuh dari sebuah pameran dibangun oleh penempatan. Yang tinggi ke belakang, yang berkilau ke tengah. Ikuti panduan sambil menggeser tangan, dan rak pajangan yang tadinya berantakan pun perlahan menarik napas bagaikan galeri kecil."},"ICON-1853":{"nm":"Kemoceng Koleksi","de":"Semakin disayangi sesuatu, semakin mudah debu menempel padanya. Dengan ujung bulu sikat yang lembut, perlahan-lahan, bahkan rasa bersalah karena lama tak menengok pun ikut tersapu. Selama membersihkannya, kenangan yang tertidur pun sejenak berkilau kembali."},"ICON-1854":{"nm":"Voucher Perluasan Kapasitas Simpan","de":"Bila terus mengumpulkan, kekurangan tempat pun menjadi kegelisahan yang membahagiakan. Hati yang diam-diam lega melihat satu rak lagi bertambah—ini bukan keserakahan, melainkan bukti betapa banyak yang disukai."},"ICON-1855":{"nm":"Kartu Kode Undangan Teman","de":"Menyerahkan kode ini adalah undangan paling hangat yang berkata, \"ayo main bareng.\" Hati yang tersimpan dalam beberapa digit angka—baru ketika teman yang menerimanya menapakkan kaki pertama di pulau, kisah berdua pun dimulai."},"ICON-1856":{"nm":"Kunci Gudang Bersama","de":"Pintu gudang tak pernah terbuka sendirian. Sebuah gembok yang baru berputar ketika tanganmu dan tanganku bersatu. Di ruang yang digunakan bersama, janji yang dijaga bersama selalu tergantung dalam wujud kunci."},"ICON-1857":{"nm":"Tag Lapor Barang Hilang","de":"Barang yang hilang pun berharga bagi seseorang. Menuliskan satu baris, \"ada di sini,\" dan menggantungkannya—tag ini adalah tali kecil yang diam-diam menyambungkan kembali hati yang sempat tersesat dengan pemiliknya."},"ICON-1858":{"nm":"Bendera Minta Bantuan","de":"Kata minta tolong bukanlah kelemahan, melainkan keberanian. Begitu bendera dikibarkan, seseorang dari suatu tempat berlari datang. Yang paling cepat menyebar di pulau ini bukanlah gosip, melainkan uluran tangan yang terentang untuk satu sama lain."},"ICON-1859":{"nm":"Gelang Kontak Darurat","de":"Sebuah rasa aman kecil yang dililitkan di pergelangan tangan. Apa pun yang terjadi, nomor yang tertulis di sini akan datang berlari lebih dulu daripada siapa pun. Teman diam yang biasanya terlupakan, namun menjadi paling dapat diandalkan tepat di saat dibutuhkan."},"ICON-1860":{"nm":"Keping Pembagi Tugas","de":"Siapa berbelanja dan siapa memasak—jika kepingnya dibagi, tak ada yang perlu diperdebatkan. Langkah pertama membuat sesuatu bersama dimulai dari menentukan bagian masing-masing dengan penuh kelembutan."},"ICON-1861":{"nm":"Lembar Kerja Bersama","de":"Hal yang tak berani dibayangkan sendirian, menjadi mungkin bagai sulap begitu banyak orang berkumpul. Semakin banyak nama terisi di lembar ini, semakin sedikit kotak kosong dan semakin banyak tawa. Kerja sama tumbuh diam-diam di antara kotak-kotak itu."},"ICON-1862":{"nm":"Kartu Sopan Santun Berkunjung","de":"Ketika melangkah ke rumah orang lain, ujung kaki pun jadi berhati-hati. Yang tertulis di kartu ini bukanlah aturan besar, melainkan sekadar janji-janji kecil dan hangat seperti \"rapikan sepatu, ucapkan salam lebih dulu.\""},"ICON-1863":{"nm":"Lonceng Bubar Pesta","de":"Kesenangan pun perlu memiliki akhir agar yang berikutnya dinanti. Begitu lonceng berdenting \"kring,\" semua orang mengemasi barang dengan wajah enggan. Pesta yang tahu cara berpisah dengan baik yang paling lama tersimpan di hati."},"ICON-1864":{"nm":"Sabuk Sudut Kasur","de":"Sehalus apa pun selimut direntangkan, sudut-sudutnya selalu saja terangkat. Berkat sabuk yang mencengkeram keempat sudut dengan kokoh, tempat tidur terbangun rapi seperti kamar hotel setiap pagi."},"ICON-1865":{"nm":"Tali Kancing Kerah Selimut","de":"Aku adalah tali kancing yang menahan kerah selimut. Sekeras apa pun berguling sepanjang malam, aku menggenggam erat agar kerahnya tak lari. Selimut yang tak bergeser sedikit pun saat bangun tidur, itulah imbalan dari jaga malamku."},"ICON-1866":{"nm":"Klip Pengunci Topper","de":"Topper selalu mencoba menyelinap tergelincir setiap ada kesempatan. Setiap kali itu terjadi, klip menggigit erat sudutnya dan mempertahankan posisi. Seorang keras kepala yang diam, menjaga tempat tidur dari sudut yang tak terlihat."},"ICON-1867":{"nm":"Alat Pelicin Kerutan Seprai","de":"Kerutan-kerutan halus yang muncul di seprai semalaman entah mengapa menyerupai lipatan di hati. Seperti kain yang menjadi mulus dengan satu sapuan alat pelicin ini, semoga hari yang kusut pun tersetrika rapi seperti itu."},"ICON-1868":{"nm":"Alas Ventilasi Kasur","de":"Bahkan kasur pun butuh celah untuk bernapas. Ketika alas ini membuka jalur angin di bawahnya, kelembapan pun keluar dan kesejukan kering meresap masuk. Tidur yang nyenyak diam-diam bermula dari udara yang menopang punggung itu."},"ICON-1869":{"nm":"Penutup Resleting Sarung Selimut","de":"Kekacauan tengah malam ketika bulu selimut terus mencuat keluar saat mengganti sarung. Tutup resletingnya sekali dengan flap ini, dan tak akan lagi terbangun karena kaki tersangkut. Kedamaian besar yang dibawa oleh selembar penutup kecil."},"ICON-1870":{"nm":"Pad Anti-Gumpal","de":"Bulu bantal diam-diam menggumpal ke satu sisi hingga membentuk bukit kecil. Bila pad ini bertahan diam di celah itu, kerataan pun bertahan sampai akhir. Berkatnya, kelembutan yang seperti baru selalu kembali setiap malam."},"ICON-1871":{"nm":"Pengait Elastis Seprai","de":"Seprai selalu mencoba perlahan-lahan melorot ke satu sisi. Kaitkan pengait di sudutnya dan tarik hingga kencang, dan ia tak akan bergeser sekeras apa pun berguling sepanjang malam. Kekencangan itu diam-diam menjadi dasar tidur yang lelap."},"ICON-1872":{"nm":"Tag Ganti Sarung Bantal","de":"Ketika tiba-tiba bingung apakah sarung bantal sudah dicuci hari ini, selembar tag menjawab dengan jelas. Jadwal yang terus terlupakan karena tidur dan tidur lagi, tanda kecil ini yang mengingatnya dengan telaten sebagai gantinya."},"ICON-1873":{"nm":"Pembatas Buku Jurnal Mimpi","de":"Mimpi yang buyar melalui celah jari begitu terbangun, ditahan pembatas buku pada halaman yang disisipkannya. Buka halaman itu dan laut serta langit tadi malam masih di sana—sebuah jembatan kecil yang diletakkan lembut antara tidur dan tulisan."},"ICON-1874":{"nm":"Kerikil White Noise","de":"Malam yang terlalu sunyi justru sering membuat terjaga. Ketika kerikil ini melepaskan suara gemerisik seperti hujan, hati pun perlahan tenggelam mengikuti alunannya. Sebongkah batu kecil yang diam-diam menenangkan kesunyian."},"ICON-1875":{"nm":"Keping Sensor Suhu Tidur","de":"Apakah dahi terasa panas atau ujung kaki terasa dingin saat tertidur, keping ini diam-diam mengamati di sampingmu. Berkat penjaga malam yang diam-diam mencari suhu yang pas untuk tubuh, tidur mengalir tanpa terbangun hingga fajar."},"ICON-1876":{"nm":"Penjepit Tirai Anti-Cahaya","de":"Betapa rajinnya sinar mentari pagi, terus menyelinap masuk lewat celah tirai. Gigit kedua ujungnya erat-erat dengan penjepit, dan kamar kembali gelap seperti tengah malam. Sekutu tepercaya untuk satu kali bangun kesiangan."},"ICON-1877":{"nm":"Lampu Duduk Proyeksi Bulan","de":"Matikan lampu, dan bulan pun terbit di langit-langit. Cahaya lembut yang dipancarkan lampu duduk ini mengubah kamar menjadi langit malam kecil. Perasaan tertidur sambil menengadah pada bulan itu, disimpan apa adanya di sisi bantal."},"ICON-1878":{"nm":"Gantungan Kantong Aroma Tidur","de":"Sebuah kantong berisi aroma lavender dan rerumputan bergoyang lembut di sisi bantal. Mengikuti wangi yang meresap ke hidung, bahu pun perlahan mengendur, dan sebuah kantong wangi mengundang tidur bahkan sebelum bantal melakukannya."},"ICON-1879":{"nm":"Pin Kotak Musik Nina Bobo","de":"Putar per dengan lembut, dan melodi kecil pun terurai keluar. Nina bobo yang berputar dari ujung pin ini persis menyerupai irama tepukan lembut di punggung dari nenek. Setiap nada perlahan memberatkan kelopak mata."},"ICON-1880":{"nm":"Gelas Tanaman Pelembap","de":"Aku adalah gelas yang menumbuhkan tanaman dengan air jernih, bukan tanah. Menatap akar-akar halus mengambang di dalam air, bahkan udara ruangan pun terasa lebih lembap. Sebuah sumur hijau kecil yang tergenang di atas meja."},"ICON-1881":{"nm":"Botol Pengumpul Serpihan Mimpi","de":"Mimpi yang tumpah dalam tidur tak berbentuk, begitu terbangun ia bocor lewat celah jari. Menyumbat satu serpihan yang hampir lenyap dengan tutup botol, menahannya hingga pagi—keinginan untuk mengingat bermula dari hal sekecil ini."},"ICON-1882":{"nm":"Baki Kacamata Samping Tempat Tidur","de":"Begitu kacamata dilepas dan diletakkan, anehnya, kelelahan sehari pun ikut turun bersamanya. Tempat kecil di sisi bantal ini ada di sana untuk menampung gerakan itu. Sebuah baki yang diam-diam mengaburkan dunia sebelum tidur."},"ICON-1883":{"nm":"Cincin Alas Gelas Nakas","de":"Sebuah bekas bundar yang ditinggalkan gelas air, terlihat sepele, namun menjadi cacat pada serat kayu nakas. Sebuah cincin kecil dipasang untuk mencegahnya. Rasa sayang selalu bekerja diam-diam di tempat yang tak terlihat seperti ini."},"ICON-1884":{"nm":"Alat Pembentuk Sudut Lipatan Selimut","de":"Bahkan melipat selimut menjadi persegi rapi pun ada tekniknya. Sejajarkan sudutnya mengikuti alat pembentuk sudut ini, dan hati yang kusut pun ikut terentang sekali. Ruang yang tertata adalah salam paling rapi untuk membuka hari."},"ICON-1885":{"nm":"Pengait Kabel Charger Samping Tempat Tidur","de":"Sebuah pengait yang digantung di sisi bantal karena tak suka kabel pengisi daya melorot pelan ke lantai sepanjang malam. Kabel yang diam-diam terisi tenaga selagi tertidur, di pagi hari menunggu ujung jari dalam keadaan penuh."},"ICON-1886":{"nm":"Keranjang Camilan Samping Tempat Tidur","de":"Sebuah keranjang berisi camilan kesukaan, dikumpulkan dalam jangkauan tangan. Persiapan penuh perhatian yang mengantisipasi rasa lapar di larut malam. Suara gemerisik saat mengambil dan menggigit sebutir di dalam gelap terasa hangat entah mengapa."},"ICON-1887":{"nm":"Sayap Penopang Buku Sebelum Tidur","de":"Sebuah sayap yang diam-diam menopang halaman terbuka, agar baris yang tengah dibaca tak hilang meski kantuk menyerbu. Satu halaman yang ditutup tepat sebelum mata terpejam menunggumu di tempat yang sama esok malam."},"ICON-1888":{"nm":"Alas Batu Alarm Samping Tempat Tidur","de":"Bahkan jam alarm yang membangunkan pagi butuh tempatnya sendiri yang tak goyah. Alas batu bundar ini menopang beratnya dengan kokoh, menjaga posisinya seperti janji yang tak tergelincir bahkan saat fajar tiba."},"ICON-1889":{"nm":"Paku Gantungan Penutup Mata Tidur","de":"Sebuah paku untuk menggantung penutup mata yang telah menghalau cahaya semalaman, agar bisa bernapas sepanjang hari. Memberikan tempat yang kering bagi kain yang telah menuntaskan tugasnya—perhatian kecil meresap sebersih ini."},"ICON-1890":{"nm":"Penjepit Senter Samping Tempat Tidur","de":"Sebuah penjepit yang menahan cahaya kecil yang dibutuhkan di tengah malam ke arah yang diinginkan. Jepitkan senter di tepi tempat tidur, dan tangan yang meraba-raba dalam gelap pun jauh lebih tenang. Sentuhan yang menentukan arah cahaya."},"ICON-1891":{"nm":"Tali Pengikat Tirai Sekat","de":"Seutas tali pengikat yang menahan tirai pemisah ruang bersama. Hanya selembar kain tipis, namun di baliknya adalah malam pribadi seseorang. Garis batas yang lembut, menjaga tidur satu sama lain di kamar yang dihuni bersama."},"ICON-1892":{"nm":"Papan Pembagi Stopkontak Bersama","de":"Sebuah papan kayu yang dibuat agar satu-satunya stopkontak bisa dipakai bersama oleh banyak orang. Ia mengalirkan listrik secara merata sehingga malam siapa pun tak menjadi gelap. Hidup bersama, pada akhirnya, dimulai dari berbagi hal sekecil ini."},"ICON-1893":{"nm":"Batu Peredam Cahaya","de":"Ketika cahaya lampu terlalu terang, sebuah batu diam-diam diulurkan alih-alih berkata-kata. \"Bisakah dikecilkan sedikit?\" Benda kecil ini yang menyampaikan kalimat itu untukmu. Permintaan paling lembut di kamar yang dihuni bersama."},"ICON-1894":{"nm":"Token Giliran Bangun Pagi","de":"Sebuah keping kecil yang diserahkan ke telapak tangan orang yang akan bangun lebih dulu. Siapa yang tidur lebih lama di dini hari dan siapa yang bangun lebih awal, token ini yang menentukan tanpa perselisihan. Hati yang menentukan urutan mengalah lewat ujung jari."},"ICON-1895":{"nm":"Cincin Nomor Gantungan Bersama","de":"Sebuah cincin bernomor yang disematkan pada gantungan baju yang dipakai bersama. Agar tak bingung siapa punya siapa, satu angka kecil diam-diam menciptakan keteraturan. Garis lembut yang digariskan pada keseharian yang mudah tercampur."},"ICON-1896":{"nm":"Tutup Anak Tangga Ranjang Susun","de":"Sebuah tutup yang dipasang pada anak tangga menuju lantai atas. Agar kaki telanjang yang menyentuhnya tak merasa dingin maupun licin, ia menjaga keamanan satu anak tangga. Perhatian kecil di ujung tangga ini kokoh menopang mimpi di lantai atas."},"ICON-1897":{"nm":"Gantungan Lengan Tisu Bersama","de":"Sebuah gantungan berbentuk lengan untuk menggantung tisu toilet bersama. Ia diposisikan agar siapa pun bisa mudah menarik selembar dengan satu tangan. Terlihat sepele, namun ini sentuhan yang menyambungkan pagi banyak orang dengan lancar."},"ICON-1898":{"nm":"Keping Giliran Pengharum Ruangan","de":"Sebuah keping yang mencatat giliran siapa yang akan mengisi ulang pengharum ruangan. Ini adalah janji untuk bergiliran bertanggung jawab, bahkan atas seuntai aroma lembut. Bau yang harum tak datang cuma-cuma, melainkan mekar dari giliran seseorang."},"ICON-1899":{"nm":"Gagang Lampu Tidur Bersama","de":"Sebuah gagang lampu tidur yang dinyalakan dan dimatikan bersama-sama. Tangan yang paling lama terjaga adalah yang terakhir mengumpulkan cahaya itu. Janji sunyi dari mereka yang berbagi kamar, membagi cahaya lembut bersama."},"ICON-1900":{"nm":"Ceruk Gelas Sandaran Tangan Sofa","de":"Sebuah lubang bundar yang diukir pada sandaran tangan sofa. Meletakkan gelas dari tangan sejenak pun tak perlu khawatir tumpah. Tempat untuk beristirahat butuh tempat menaruh satu gelas, barulah hati bisa benar-benar merebahkan diri dengan tenang."},"ICON-1901":{"nm":"Penarik Ritsleting Sarung Bantal","de":"Gagang kecil yang terpasang pada ritsleting pembuka sarung dalam bantal. Satu cincin kecil ini meringankan repotnya mengganti cucian. Jemari yang peduli hingga ke bagian dalam yang tak terlihat—kelembutan rumah tangga selalu bersembunyi di sana."},"ICON-1902":{"nm":"Bantal Sisip Sandaran Sofa","de":"Bantal yang mengisi celah sandaran dan menopang punggung bawah. Ia mengisi ruang kosong itu agar punggung tidak pegal meski duduk lama. Kenyamanan yang lebih dulu disadari tubuh, mendesah 'ah, ini dia,' begitu bersandar."},"ICON-1903":{"nm":"Tali Pengikat Sudut Bantal Duduk","de":"Tali yang mencengkeram bantal di setiap sudut, bantal yang dulu selalu bergeser tiap kali diduduki. Ia mengikatnya di satu tempat agar tak lagi tergelincir. Kerapian dimulai dari pengikatan kecil yang gigih seperti ini."},"ICON-1904":{"nm":"Pelindung Jahitan Bantal","de":"Bagian bantal yang pertama kali aus selalu jahitan di sudutnya. Pelindung ini melilit tempat itu lebih dulu, menjaganya agar tak sampai robek. Hati yang ingin menyimpannya lama sekokoh jahitan itu sendiri."},"ICON-1905":{"nm":"Kantong Remote Celah Sofa","de":"Remote yang selalu menghilang di antara bantal akhirnya punya rumah sendiri. Kantong kecil yang terselip di celah sofa. Mengetahui bahwa yang dikira hilang selalu ada di situ, ternyata jauh lebih melegakan dari dugaan."},"ICON-1906":{"nm":"Tali Gulung Selimut Pangkuan","de":"Tali untuk menggulung dan mengikat selimut pangkuan. Kehangatan yang berserakan saat dibentangkan, dirapikan kembali untuk malam berikutnya. Kehangatan pun, bila disimpan begini, bisa dikeluarkan dan diselimutkan lagi esok hari."},"ICON-1907":{"nm":"Kancing Sarung Pijakan Kaki","de":"Kancing yang mengencangkan sarung pijakan kaki, bagian yang paling cepat aus karena sentuhan kaki, agar mudah diganti. Satu klik kancing itu memperpanjang umur kainnya. Hati yang ingin memakai sesuatu lama-lama teliti pada hal sekecil ini."},"ICON-1908":{"nm":"Tutup Geser Kaki Sofa","de":"Sofa seberat apa pun tak boleh menggores lantai. Tutup lembut yang menyarungi ujung keempat kakinya, mengendap-endap menjaga lantai kayu. Perabot yang berhati-hati sampai ke ujung kakinya entah kenapa terasa lebih disayang."},"ICON-1909":{"nm":"Rak Kumpulan Remote","de":"Rak yang menjajarkan rapi remote-remote yang dulu berguling dan berserakan ke mana-mana. Ketika batang-batang panjang dan pendek itu berdiri tegak berbaris, hanya dengan itu saja suasana ruangan turun satu nada lebih tenang."},"ICON-1910":{"nm":"Gantungan Isi Daya Gamepad","de":"Kaitan untuk menggantung dan mengisi daya gamepad setelah sesi bermain yang seru. Selagi ia tergantung dan diam-diam mengisi ulang tenaganya, tangan pun ikut beristirahat sejenak. Jeda singkat ini menyiapkan babak berikutnya dengan mantap."},"ICON-1911":{"nm":"Kantong Bidak Board Game","de":"Kantong kecil berisi bidak beraneka warna. Bidak-bidak yang menunggu babak berikutnya di dalam satu kantong berdenting setiap kali dikocok. Dari suara itu, debar 'main satu ronde lagi?' terlebih dulu terbangun."},"ICON-1912":{"nm":"Nampan Lempar Dadu","de":"Nampan khusus untuk melempar dadu. Keberuntungan yang dulu memantul keluar meja dan hilang, kini ditahan pinggirannya di dalam. Pada saat singkat dadu berputar lalu berhenti, napas semua orang sejenak tertahan bersama."},"ICON-1913":{"nm":"Tali Pengikat Kartu","de":"Tali yang mengikat satu set kartu agar tak berserakan. Sebelum dikocok, urutan itu sendiri adalah sebuah janji. Dalam gerakan melepas ikatan dan membentangkan kartu, cerita satu babak permainan baru dimulai."},"ICON-1914":{"nm":"Klip Rapi Kabel Konsol","de":"Klip yang mencengkeram dan menyisir rapi kabel-kabel kusut di balik konsol. Ia diam-diam merapikan kekacauan di tempat yang nyaris tak terlihat. Kerapian selalu diselesaikan dengan tenang seperti ini, dari balik punggung."},"ICON-1915":{"nm":"Dial Pemutar Skor","de":"Dial kecil yang diputar untuk menunjukkan skor. Klik, setiap kali angka naik satu takik, sorak-sorai pun menyusul. Tanpa perlu menghitung dalam kepala, ujung jari lebih dulu mengingat pertandingan hari itu."},"ICON-1916":{"nm":"Penyangga Papan Berdiri","de":"Penyangga yang menegakkan papan permainan miring, mengatur sudutnya agar semua yang duduk melingkar bisa melihat papan sekali pandang. Agar tak ada yang perlu menjulurkan leher, ia diam-diam membentangkan pandangan yang adil untuk semua."},"ICON-1917":{"nm":"Tabung Undi Giliran","de":"Tabung tempat tangan disusupkan untuk mengundi giliran bermain. Satu batang yang diraba dan digenggam menentukan siapa jalan pertama. Pada saat singkat sedikit bersandar pada keberuntungan itu, semua orang berdebar bersama di dalam tabung bundar itu."},"ICON-1918":{"nm":"Piring Sekat Camilan Bersama","de":"Piring bersekat untuk menyajikan camilan menurut jenisnya. Dengan ruang yang terpisah, tangan tak perlu bertabrakan saat memilih yang disukai. Ketulusan yang memikirkan orang-orang yang akan berbagi tersimpan di setiap sekatnya."},"ICON-1919":{"nm":"Sarung Penghangat Teko Teh","de":"Sarung yang membalut bahu teko teh untuk menjaga kehangatannya. Ia menyelimuti agar teh tak mendingin selagi perlahan meresap. Keinginan ujung jari untuk menyajikan secangkir hangat tetap hangat sampai tetes terakhir."},"ICON-1920":{"nm":"Alas Sandar Kantong Teh","de":"Alas tempat kantong teh yang telah diseduh diangkat dan dibiarkan beristirahat sejenak. Ia menampung bahkan tetes air terakhir agar tak ada yang menetes sia-sia. Sebuah tempat yang memberi akhir yang rapi bahkan bagi daun yang telah menuntaskan tugasnya."},"ICON-1921":{"nm":"Cincin Penanda Mug Bersama","de":"Enam mug serupa di rak pantry kantor. Alih-alih bertanya milik siapa, kami menyematkan cincin warna-warni. Satu tanda kecil diam-diam mengikat enam orang dengan selera berbeda-beda pada satu meja yang sama."},"ICON-1922":{"nm":"Keranjang Berbagi Popcorn","de":"Selagi berpindah dari tangan ke tangan, uap gurihnya lebih dulu menyapa. Jika ada sesuatu yang anehnya tak pernah berkurang meski terus diambil segenggam demi segenggam, itu pasti hati sebuah malam yang dihabiskan bersama, duduk melingkar berbagi."},"ICON-1923":{"nm":"Wadah Penjepit Gula Batu","de":"Sebutir gula bersudut diketuk penjepit, jatuh ke cangkir teh. Menyaksikan sudut putihnya perlahan larut dan menghilang—etika manis yang tak tergesa, pertama kali dipelajari di meja teh Nenek."},"ICON-1924":{"nm":"Alas Antiselip Baki","de":"Meski baki agak miring, cangkir tetap di tempatnya. Seperti hal-hal yang diam-diam menahan dari bawah selalu begitu, alas ini sendirian menanggung momen nyaris tergelincir dan pada akhirnya tetap bungkam."},"ICON-1925":{"nm":"Gelas Penegak Sedotan","de":"Tegakkan sedotan lurus dan baik minuman maupun hati pun tak berantakan. Pada sore hari ketika meja jadi rapi berkat satu ketegakan kecil, gelas ini memeluk sebatang tiang mungil dan diam-diam menopang waktu yang malas berlalu."},"ICON-1926":{"nm":"Penampung Remah Kue","de":"Renyah, pada saat kue itu remuk, serpihan yang jatuh berkumpul di sini. Menampung bahkan jejak yang ditinggalkan gigitan paling lezat—penutup meja makan yang tenang, ramah bahkan pada remah terakhir."},"ICON-1927":{"nm":"Tali Jepit Gantung Foto","de":"Foto polaroid dijepit satu demi satu pada tali yang direntangkan seperti jemuran. Selagi senyum-senyum hari ini melambai dan mengering diterpa angin, satu bentang dinding berubah menjadi galeri kenangan yang kecil dan cerah."},"ICON-1928":{"nm":"Kumparan Benang Kenangan","de":"Kumparan tempat benang kusut diurai dan digulung rapi. Hal-hal yang tersambung dengan simpul di setiap tempat yang putus. Jika kenangan pun digulung ulang perlahan seputar demi seputar begini, jalan yang dikira memendek akan memanjang kembali."},"ICON-1929":{"nm":"Penutup Lubang Paku Dinding","de":"Penutup kecil dan bundar yang menyembunyikan bekas paku. Dengan lembut menutupi bahkan bekas luka kecil yang tersisa setelah sesuatu yang pernah tergantung diturunkan, dinding kembali ke wajah mulusnya seolah tak pernah terjadi apa-apa."},"ICON-1930":{"nm":"Bingkai Sisip Foto Bersama","de":"Foto bersama enam orang yang berdiri rapat bahu-membahu. Begitu diselipkan ke bingkai, tawa dan kehangatan hari itu ikut tersegel di dalamnya. Bingkai adalah tangan yang paling tenang menghentikan hari yang terus berlalu."},"ICON-1931":{"nm":"Papan Gabus Memo","de":"Papan cokelat yang penuh dengan bekas jarum pentul. Janji yang tak boleh dilupakan, catatan semangat dari seseorang, daftar tugas hari ini—semua tersemat berlapis-lapis. Dinding andalan di samping meja yang mengingat sebagai ganti kepala kita."},"ICON-1932":{"nm":"Simpul Gantung Karangan Bunga","de":"Sekalipun hanya karangan bunga yang tergantung di pintu, dibutuhkan keterampilan ujung jari. Simpulnya harus diikat kuat agar tak jatuh di musim berangin. Hati yang menyambut seseorang selalu mengeras kuat lebih dulu dari tempat yang tak terlihat."},"ICON-1933":{"nm":"Sarung Bandul Jam Dinding","de":"Sarung kain yang membungkus bandul yang berdetak untuk menahan debu. Bahkan pekerjaan mengukur waktu pun menerima perawatan seperti ini. Jaga ia dengan lembut agar tak lekas usang, dan jam dinding akan menemani kita sedikit lebih lama."},"ICON-1934":{"nm":"Papan Kumpulan Stiker","de":"Stiker-stiker yang dulu berserakan di tiap laci kini berkumpul dan berbaris di satu papan. Karakter favorit, bintang berkilau, selembar tulisan tangan. Ketika kegembiraan kecil dari mengoleksi tertata rapi, hati pun ikut menjadi lurus."},"ICON-1935":{"nm":"Tali Sambung Bendera Hias","de":"Tali yang menyambung bendera-bendera warna-warni menjadi satu untai. Entah ulang tahun atau penyambutan, begitu tali itu membentang di langit-langit, ruangan biasa berubah menjadi rumah pesta. Merayakan adalah pekerjaan menyambung kembali hati yang sempat terputus."},"ICON-1936":{"nm":"Alas Gabus Ketel Listrik","de":"Selembar gabus yang menopang dasar ketel yang panas. Agar meja tak sampai hangus, ia sendiri memeluk panas itu. Perhatian kecil yang diam-diam menyangga agar kehangatan seseorang tak meninggalkan bekas."},"ICON-1937":{"nm":"Nampan Remah Pemanggang Roti","de":"Remah yang jatuh dari roti yang dipanggang keemasan berguling turun ke nampan. Tinggal ditarik dan dikebaskan, selesai. Ia menerima pagi yang sibuk tanpa sepatah kata, lalu bersiap bersih kembali untuk santapan berikutnya."},"ICON-1938":{"nm":"Cincin Piring Putar Microwave","de":"Di atas cincin yang berputar, piring perlahan menggambar satu putaran penuh. Putaran yang diciptakan agar panas merata itu menghidupkan kembali nasi kemarin yang telah dingin menjadi santapan yang mengepul hangat sekali lagi."},"ICON-1939":{"nm":"Tutup Kompor Induksi Mini","de":"Sekeras apa pun minyak muncrat ke segala arah, kompor tetap bersih. Selembar tutup memisahkan panas yang ganas dari tangan. Hal-hal yang berdiri menghalangi tanpa terlihat itulah yang menjaga dapur tetap tempat yang tak akan menghanguskan."},"ICON-1940":{"nm":"Tutup Pelepas Uap Rice Cooker","de":"Bunyi desis uap yang keluar, cssh. Berkat tutup kecil yang perlahan melepaskan tekanan yang tertahan, nasi yang baru matang membuka tutupnya dengan wajah paling lembut. Tak ada tergesa dalam waktu mengukusnya."},"ICON-1941":{"nm":"Penyangga Berdiri Centong","de":"Tegakkan centong yang tadi mengaduk sup. Hati kecil yang tak ingin menumpahkan setitik pun noda di meja dapur. Kerapian dapur selalu bermula dari tempat-tempat sepele dan tak menonjol seperti ini."},"ICON-1942":{"nm":"Pegangan Silikon Gagang Panci","de":"Pasang silikon pada gagang panci yang panas membara dan tangan pun tak akan melepuh. Satu lapis yang menyusup di antara panas dan telapak tangan. Ia menjaga orang yang memasak makanan hangat dari tempat yang paling dekat."},"ICON-1943":{"nm":"Saringan Kerak Air Ketel Listrik","de":"Bahkan air yang direbus tiap hari meninggalkan bekas tipis. Saringan yang rapat diam-diam menyaring kerak itu, menuangkan hanya secangkir yang jernih. Tangan yang tekun menjaga tegukan pertama teh dari tempat yang tak terlihat."},"ICON-1944":{"nm":"Kaki Jepit Timer Masak","de":"Tiga menit lagi, kata timer, menggigit erat ujung meja dengan kaki jepitnya. Selagi mi matang, ia berdiri tegak bertumpu pada kaki mungilnya, berdetik menghitung bersama momen yang paling dinanti hari itu."},"ICON-1945":{"nm":"Cangkir Tiris Sendok Garpu","de":"Air menetes turun dari sendok garpu yang baru dibilas. Ketika cangkir tiris diam-diam mengumpulkan air itu, meja pun segera kering. Kerapian adalah ketekunan lembut yang memperhatikan bahkan setetes air."},"ICON-1946":{"nm":"Rak Sekat Piring Berdiri","de":"Tegakkan piring-piring, terbagi dalam sekat-sekat. Piring-piring yang dulu saling menggores saat ditumpuk kini masing-masing mendapat tempatnya sendiri. Menata pada akhirnya adalah memberi setiap orang sekatnya sendiri agar tak saling berbenturan."},"ICON-1947":{"nm":"Cincin Pasangan Sumpit","de":"Sumpit yang tertinggal kesepian tanpa pasangannya disematkan pada cincin dan dipertemukan kembali berdua. Karena satu batang saja akan segera kehilangan gunanya, cincin kecil ini menjaga keteraturan di dalam laci dengan mengikat mereka berjajar."},"ICON-1948":{"nm":"Rak Cabang Gantung Gelas","de":"Gantung gelas satu per satu pada penyangga yang bercabang seperti ranting. Selagi air mengering dari tiap gelas yang tertelungkup, satu sudut dapur berdiri diam bagaikan sebatang pohon kecil yang rapi."},"ICON-1949":{"nm":"Gagang Nampan Sekat Sendok Garpu","de":"Nampan tempat sendok, sumpit, dan garpu berbaring berjajar dalam sekat-sekat. Genggam gagangnya dan angkat semuanya sekaligus, menata meja pun jauh lebih ringan. Keindahan keteraturan hidup pula di dalam laci, tanpa pernah absen."},"ICON-1950":{"nm":"Papan Tiris Gelas Terbalik","de":"Telungkupkan gelas yang telah dicuci dan tetes air jatuh, menetes, menetes. Selagi perlahan mengering di dekat jendela yang disinari matahari, gelas kaca dengan tenang memulihkan kejernihan pertamanya untuk tegukan berikutnya."},"ICON-1951":{"nm":"Sikat Pembersih Sela Garpu","de":"Sela-selanya yang halus menyapu lembut sisa makanan dari antara gigi garpu. Berkat sentuhan yang merawat bahkan celah tersempit, santapan berikutnya selalu dimulai dengan suapan pertama yang bersih tanpa cela."},"ICON-1952":{"nm":"Felt Antiselip Tumpukan Mangkuk","de":"Tumpuk mangkuk dan porselen berdenting tajam saling berbenturan. Selembar felt yang terselip di antaranya meredam gesekan itu. Rahasia bertahan lama bersama terletak pada membiarkan satu sama lain sedikit lebih lembut."},"ICON-1953":{"nm":"Tali Gantung Sendok Teh","de":"Gantung sendok teh yang mungil pada tali dan pasang di dinding. Tak lagi terkubur di dalam laci, ia berkilau selalu dalam jangkauan tangan—alat kecil yang bangga menempati tempatnya sendiri. Dalam urusan rumah tangga pun, setiap benda punya posisinya."},"ICON-1954":{"nm":"Nampan Sekat Rak Kulkas","de":"Bagi rak kulkas menjadi beberapa bagian dan setiap bahan makanan mendapat rumah kecilnya sendiri. Hal-hal yang dulu tercampur dan terlupakan kini menemukan tempatnya, dan setiap kali pintu dibuka, terlihat jelas sekali pandang apa ada di mana."},"ICON-1955":{"nm":"Klip Penegak Kantong Beku","de":"Cengkeram kantong beku yang setengah terpakai dengan klip dan tegakkan berdiri. Agar tak tumbang dan tumpah, agar mudah ditemukan lain kali. Bahkan di dalam freezer yang dingin bersemayam kebijaksanaan cermat seorang penata rumah yang teliti."},"ICON-1956":{"nm":"Pengencang Tutup Botol","de":"Botol yang tak ditutup rapat akan segera kehilangan gasnya. Satu putaran pergelangan tangan yang mengencangkan tutup dengan erat itu mengunci aroma dan buih di dalamnya utuh hingga besok pagi. Ketelitian bersinar dari hal-hal kecil."},"ICON-1957":{"nm":"Alas Antiselip Rak Telur","de":"Alas yang menopang telur-telur bundar dalam sekat-sekat agar tak berguling dan pecah. Keinginan untuk memperlakukan yang paling rapuh dengan perhatian paling besar bersemayam kecil dan lembut di satu sudut pintu kulkas."},"ICON-1958":{"nm":"Perentang Kantong Pintu Kulkas","de":"Regangkan kantong pintu kulkas sedikit ke samping untuk membuat satu ruang lagi. Sebab ketika kebutuhan rumah tangga bertambah, ruangnya pun harus ikut bertambah. Dalam keterampilan melebarkan tempat sempit ini, terpantul hati seorang penata rumah yang cekatan."},"ICON-1959":{"nm":"Tutup Tekan Lauk Sisa","de":"Tutup yang ditekan lembut di atas lauk yang tersisa. Ia diam-diam menjaganya agar tak mengering atau menyerap bau lain. Tangan yang penuh perhatian merawat dengan saksama bahkan sisa dari satu kali makan."},"ICON-1960":{"nm":"Sirip Pengarah Udara Dingin","de":"Ke arah mana udara dingin akan mengalir, sirip kecil ini diam-diam menentukan arahnya. Belokkan sedikit jalur angin yang tak terlihat dengan ujung jari, dan hawa sejuk pun mencapai sudut terdalam sekalipun."},"ICON-1961":{"nm":"Bantalan Penyerap Lembap Laci Sayur","de":"Di sudut paling gelap laci sayur kulkas, aku diam-diam menyerap kelembapan. Keajaiban kecil daun yang layu kemarin kembali segar di pagi hari. Meski tak ada yang menyadarinya, kesegaran selalu menjadi tanggung jawabku."},"ICON-1962":{"nm":"Bibir Penahan Guling Kaleng Minuman","de":"Menempel diam di tepi meja, ia menahan kaki kaleng yang hendak berguling pergi. Minuman yang nyaris tumpah, meja yang nyaris perlu dilap. Rasa aman dalam mengurus rumah bermula dari bibir kecil yang tak terlihat seperti ini."},"ICON-1963":{"nm":"Dial Giliran Piket","de":"Hari ini siapa cuci piring, siapa memilah sampah daur ulang. Sekali putar panahnya, setiap perselisihan terurai dengan mulus. Di rumah tempat lima orang hidup berdesakan, bergiliran adalah bentuk kedamaian yang paling ramah."},"ICON-1964":{"nm":"Gelang Silikon Pembeda Gelas","de":"Lima gelas yang mirip satu sama lain, dan pagi yang membingungkan milik siapa yang mana. Selipkan sepotong gelang warna seukuran pergelangan tangan, dan janji kecil 'ini punyaku' pun menjadi jelas, menghiasi meja sarapan dengan keteraturan yang lembut."},"ICON-1965":{"nm":"Cincin Takaran Porsi Mangkuk","de":"Pada hari sibuk, garis takaran di dalam mangkuk menjadi teman yang bisa diandalkan. Satu bagian untuk nasi, satu bagian untuk lauk. Tak kurang, tak lebih, garis lembut ini diam-diam memberi tahu berapa banyak yang pantas dimakan hari ini."},"ICON-1966":{"nm":"Wadah Jepit Berbagi Camilan","de":"Sodorkan sekantong utuh dan bekas sentuhan tangan tertinggal, terasa canggung. Bagikan satu demi satu dengan penjepit dan barulah bagian semua orang jadi sama. Berbagi lebih cocok dengan tangan yang rapi daripada genggaman sekaligus."},"ICON-1967":{"nm":"Rak Nama Piket Ketel Air","de":"Merebus air selalu jatuh ke tangan yang sama. Sejak kami mulai menggantung papan nama secara bergiliran di rak samping ketel, secangkir teh hangat pun berubah menjadi kasih sayang yang diseduh bergantian."},"ICON-1968":{"nm":"Chip Peringatan Habiskan di Spatula","de":"Sepatah 'jangan disisakan' tergantung kecil di ujung spatula. Terdengar seperti omelan, tapi tak ada rasa jengkel di dalamnya—karena semangat meja makan zaman dulu yang menghargai setiap kali makan bersemayam di sini."},"ICON-1969":{"nm":"Gantungan Kantong Sendok Pribadi","de":"Sendok garpu tak lagi berguling-guling di dalam laci. Begitu masing-masing set masuk ke kantongnya sendiri dan tergantung di dinding, tempat lima anggota keluarga pun berbaris rapi berjajar. Kerapian kecil ini menopang kedamaian setiap hari."},"ICON-1970":{"nm":"Chip Gabus Penanda Kursi Meja Makan","de":"Letakkan kepingan gabus di meja dan jelas sudah siapa duduk di mana. Kursi yang selalu ditempati, wajah samping yang selalu dihadapi. Tempat yang tetap adalah bukti paling tenang dari kata 'hidup bersama.'"},"ICON-1971":{"nm":"Gantungan Gulung Apron Piket","de":"Apron yang selesai dipakai cuci piring tak dilempar sembarangan. Digulung rapi dan digantung di kaitan, ia siap kering dan segar untuk diraih esok pagi. Hati yang memikirkan orang berikutnya hidup di dalam simpul kecil ini."},"ICON-1972":{"nm":"Kantong Lipat Sandal Sekali Pakai","de":"Pada hari tamu datang, aku terbuka sepenuhnya beserta kantongnya. Sandal sekali pakai yang tersusun rapi di dalam menyambut kaki yang baru tiba dengan kehangatan empuk. Keramahan selalu bermula tenang dari pintu masuk."},"ICON-1973":{"nm":"Kantong Ekor Kertas Cotton Bud","de":"Ketika cotton bud habis terpakai dan hanya ekor kertasnya yang tersisa, aku dengan cermat mengumpulkan ujung-ujungnya. Memberi tempat bahkan bagi yang akan dibuang. Aku tahu rahasia meja yang rapi adalah kebaikan kecil seperti ini."},"ICON-1974":{"nm":"Ikatan Kumparan Perlengkapan Jahit","de":"Ikat benang-benang warna bersama agar kumparannya tak terurai dan kusut. Kancing yang lepas, kelim lengan yang mengendur—satu ikatan ini segera membuatnya utuh kembali. Jahitan tangan yang diam-diam menyelamatkan malam hari yang penting."},"ICON-1975":{"nm":"Sabun Kemasan Tunggal","de":"Sepotong sabun yang dibungkus rapi satuan diletakkan di setiap kamar tamu. Tubuh sebesar telapak tangan membasuh debu sehari dengan segenggam busa. Kebersihan selalu bermula dari tempat sekecil ini."},"ICON-1976":{"nm":"Kapsul Lipat Topi Mandi","de":"Lipat kerutannya dan ia masuk pas ke telapak tangan; buka dan ia membungkus rambut dengan pas. Agar rambut yang sudah tertata tak berantakan hanya karena satu kali mandi. Kerapian esok pagi dijaga oleh satu lapis ini."},"ICON-1977":{"nm":"Sarung Pelindung Sikat Gigi","de":"Bulu sikat lebih sensitif dari yang dikira. Satu sarung yang menutupi ujungnya membuat debu tas pun tak bisa menyentuhnya. Menjaga tempat yang tak terlihat—itulah tugas sesungguhnya dari kebersihan yang dipelajari di setiap perjalanan."},"ICON-1978":{"nm":"Penjepit Ambil Satu Kapas Wajah","de":"Kapas wajah keluar rapi hanya jika diambil selembar demi selembar. Tumpahkan sekaligus dan lebih banyak yang terbuang percuma. 'Satu demi satu, dengan telaten'—inilah aturan tenang di atas meja rias."},"ICON-1979":{"nm":"Sendok Sepatu Lipat Mini","de":"Dilipat, ia masuk ke saku; dibuka, ia pas di tumit. Aku bangga menuntaskan pekerjaan yang cukup besar dengan tubuh yang kecil. Bahkan di pagi yang kesiangan, akulah yang selalu memungkinkan sepatu dipakai tanpa merusak bentuknya."},"ICON-1980":{"nm":"Gulungan Benang Gigi Satuan","de":"Gulung serat benang gigi rapi-rapi dan potong secukupnya saat dibutuhkan. Gulungan yang tak lebih besar dari kuku ini tak pernah absen dari tugas menjaga senyum yang cerah. Bahkan senyuman punya persiapan yang tak terlihat."},"ICON-1981":{"nm":"Gagang Tutup Ketel Listrik","de":"Agar uap air mendidih tak melukai tangan, aku terpasang di atas tutupnya. Sejengkal jarak antara panas dan telapak tangan. Jarak kecil itu menghangatkan pagi seseorang yang sibuk dengan aman."},"ICON-1982":{"nm":"Alas Silikon Sandaran Setrika","de":"Saat menyetrika, momen paling berbahaya adalah ketika sejenak melepas tangan dari setrika. Tegakkan setrika di atas alas silikon dan baik meja maupun baju tak akan hangus. Merapikan kerutan hanya benar-benar selesai di atas alas ini."},"ICON-1983":{"nm":"Kait Gantungan Anti-Curi","de":"Agar pakaian yang tergantung tak melorot sembarangan, kaitnya mengatupkan mulutnya erat-erat. Penjaga kecil di samping satu pakaian kesayangan di dalam lemari. Menjaga adalah pekerjaan yang tenang seperti ini."},"ICON-1984":{"nm":"Saringan Kerak Ketel","de":"Tugasku adalah diam-diam menyaring kerak yang mengambang dalam air mendidih. Baru setelah menyaring bahkan endapan yang tak terlihat, secangkir teh menjadi jernih. Ketelitian selalu tumbuh dari tempat yang tak tampak mata."},"ICON-1985":{"nm":"Tali Antiselip Gantungan Baju","de":"Gantungan yang dililit tali antiselip tak akan menjatuhkan bahkan sutra yang ringan sekalipun. Siapa pun yang pernah melihat pakaian jatuh ke lantai dan kusut tahu betapa berharganya satu garis tipis ini."},"ICON-1986":{"nm":"Klip Rapi Kabel Setrika","de":"Kabel yang terurai bisa tersandung kaki dan membuat seseorang terhuyung. Satu sentuhan tangan yang mengikatnya rapi dengan klip. Mencegah kecelakaan selalu bermula dari kerapian kecil dan sepele seperti ini."},"ICON-1987":{"nm":"Alur Dudukan Ketel Listrik","de":"Aku mendudukkan ketel pas ke dalam alurku agar tak goyah. Berada di tempat yang semestinya berarti berada dalam ketenangan. Ada alasan mengapa air hangat dipanaskan di tempat yang sama setiap pagi."},"ICON-1988":{"nm":"Kaki Jepit Gantungan Celana","de":"Ketika kaki jepit mencengkeram ujung celana dengan mantap, tak satu pun kerutan terbentuk. Satu pakaian yang disetrika rapi diperlakukan istimewa sejak tergantung. Potongan yang rapi diselesaikan di dalam lemari."},"ICON-1989":{"nm":"Kait Gantung Pengering Rambut","de":"Letakkan pengering rambut sembarangan dan kabelnya cepat kusut. Gantung rapi di kaitnya dan wastafel pun jadi lapang, esok pagi jadi lebih ringan. Tempat yang tertata sedikit melonggarkan hari yang sibuk."},"ICON-1990":{"nm":"Tatakan Gelas Minibar","de":"Letakkan diam-diam di bawah gelas dan tetes air tak menyebar di atas meja. Perhatian dari selembar tatakan ini tak meninggalkan bekas lingkaran. Kerapian adalah kebaikan yang tak meninggalkan jejak."},"ICON-1991":{"nm":"Papan Gantung Jangan Ganggu","de":"Satu papan yang tergantung di kenop pintu berbisik lembut 'sedang beristirahat.' Menjaga satu tarikan napas tidur siang di penghujung hari yang panjang. Jeda pun perlu seseorang yang menjaganya dengan sepenuh hati."},"ICON-1992":{"nm":"Tutup Tombol Panggil Room Service","de":"Berkat tutup yang menyelubungi tombol, bahkan tersenggol ujung baju pun tak akan menekannya sembarangan. Agar panggilan hanya terdengar jelas saat benar-benar dibutuhkan. Satu penutup kecil membuat kamar yang sibuk terasa jauh lebih rapi."},"ICON-1993":{"nm":"Kaki Jepit Es Minibar","de":"Ambil es dengan tangan kosong dan terasa dingin serta terus licin. Tugas itu diambil alih dengan cekatan oleh kaki penjepit ini. Di balik awal segelas minuman dingin, tersembunyi sentuhan tangan yang tak terlihat."},"ICON-1994":{"nm":"Slot Kartu Kunci Kamar","de":"Selipkan kartu ke dalam slot dan lampu kamar pun menyala. Aku hanyalah celah kecil, tapi aku menjadi gerakan pertama yang membuka ruang untuk melepaskan lelahnya sehari. Lampu menyala kembali di tempat yang dituju untuk kembali."},"ICON-1995":{"nm":"Cincin Segel Leher Botol","de":"Jika cincin segel di leher botol masih utuh, artinya belum ada yang menyentuhnya. Sebuah janji kecil yang membuktikan segalanya masih sama seperti semula. Kepercayaan bermula dari segel yang tak terputus."},"ICON-1996":{"nm":"Penyangga Berdiri Brosur","de":"Tegakkan brosur agak miring dan pandangan yang lewat pun berhenti dengan sendirinya. Sikap sopan informasi yang menunggu untuk dibuka. Hanya dengan meletakkannya agar terlihat jelas, jalan seseorang menjadi jauh lebih mudah."},"ICON-1997":{"nm":"Chip Pipih Pembuka Botol Minibar","de":"Di satu sudut tubuhnya yang pipih tersembunyi diam-diam sebuah takik untuk membuka tutup botol. Kecil, tapi tugasnya diselesaikan dengan sempurna. Tegukan pertama yang segar dari sebotol minuman selalu terbuka lewat chip mungil ini."},"ICON-1998":{"nm":"Tutup Kenop Pengatur Cahaya","de":"Putar lembut kenop yang terselubung dan kecerahan ruangan perlahan berubah. Terang, lalu redup lembut. Memilih cahaya menjelang tidur adalah ritual yang menutup hari dengan penuh kasih."},"ICON-1999":{"nm":"Ganjal Penahan Roda Koper","de":"Selipkan sedikit di bawah roda dan koper tak akan berguling seenaknya. Bahkan di peron stasiun yang miring, bawaan tetap di tempatnya. Ketenangan hati di perjalanan yang berangkat mengeras kuat dari ganjal kecil ini."},"ICON-2000":{"nm":"Papan Lipat Kemas Bawaan","de":"Bentangkan lalu letakkan kemeja atau celana di atasnya, dan keduanya terlipat rapi bersudut. Agar isi tas tak berantakan, agar bisa melangkah tanpa kusut di kota yang dituju. Bawaan yang dikemas baik membantu perjalanan bahkan sebelum berangkat."},"ICON-2001":{"nm":"Kenop Kunci Brankas Kamar","de":"Memutar kenop membuat sebuah palang kecil meluncur ke dalam. Menitipkan barang berharga adalah janji untuk melapangkan hati sepenuhnya, hanya untuk semalam. Kunci ini hadir bukan sebagai kecemasan, melainkan sebagai nama lain dari rasa tenang."},"ICON-2002":{"nm":"Pembungkus Pegangan Koper","de":"Di setiap bekas sentuhan tangan tergores kisah keberangkatan seseorang. Genggam pembungkus ini, yang lusuh sebanyak jarak yang pernah ditempuhnya, dan diam-diam kau akan mengerti bahwa pergi, pada akhirnya, adalah kata yang menyimpan kepulangan."},"ICON-2003":{"nm":"Jepitan Gantung Pouch Perjalanan","de":"Gantungkan pouch di tepi wastafel, dan kamar yang sempit pun terasa selapang sejengkal. Bahwa keteraturan dalam tas dimulai dari satu jepitan kecil—tangan yang sudah lama merantau telah lebih dulu memahaminya."},"ICON-2004":{"nm":"Jepitan Multi-Colokan Charger","de":"Beberapa kabel dikumpulkan dan ditancapkan dalam satu stopkontak. Pada malam menunggu baterai penuh terisi, di sinilah ada tangan kecil yang dengan lembut menyatukan kabel-kabel yang berserakan."},"ICON-2005":{"nm":"Tali Gantung Label Nama Koper","de":"Di antara tas-tas hitam yang serupa, seutas tali inilah yang membuat milikmu dikenali. Menggantungkan nama adalah tanda kasih bahwa barang bawaan ini punya jalan pulang kepada seseorang."},"ICON-2006":{"nm":"Papan Gantung Kabel Charger Dinding Kamar","de":"Papan kecil di dinding sisi kepala ranjang menopang kabel charger dengan rapi. Pada malam pertama di kamar yang asing, ketika satu cahaya yang akrab menyala, tempat itu pun sejenak menjadi rumah."},"ICON-2007":{"nm":"Kaki Lipat Penyangga Koper","de":"Bentangkan kaki yang terlipat, dan tas pun terangkat sejengkal dari debu lantai. Koper yang diletakkan tanpa dibongkar diam-diam menyimpan perjalanan yang belum usai, menunggu pagi berikutnya."},"ICON-2008":{"nm":"Slot Kartu Kunci","de":"Kartu harus dimasukkan agar lampu kamar menyala. Cahaya yang hanya menyala selama kau menginap—hari seorang pelancong dihangatkan oleh terang secukupnya yang diizinkan oleh slot kecil ini."},"ICON-2009":{"nm":"Tali Gantung Kartu Kunci","de":"Kalungkan satu kartu di leher, dan kedua tangan pun menjadi ringan. Mengikat rasa takut kehilangan pada seutas tali adalah kecerdikan kecil yang telah lama diwariskan para pelancong berbawaan berat."},"ICON-2010":{"nm":"Tombol Bel Panggilan Resepsionis","de":"Tekan, dan sebuah bunyi jernih berdenting entah di mana di meja depan. Agar meminta bantuan tak pernah terasa memalukan, bel ini selalu diletakkan dengan lembut, hanya sejangkauan tangan."},"ICON-2011":{"nm":"Jepitan Nomor Antrean Check-In","de":"Kertas nomor antrean yang diambil di ujung barisan dijepit dan disematkan. Bahwa menunggu pun punya gilirannya sendiri—keteraturan tumbuh dari janji kecil untuk diam-diam menghargai waktu satu sama lain."},"ICON-2012":{"nm":"Rumbai Kunci Kamar","de":"Rumbai yang tergantung di ujung kunci bergoyang lembut setiap langkah. Hati yang menyelipkan setitik keanggunan ke dalam kegunaan hanya dimiliki oleh mereka yang tahu kesenangan di ujung jari."},"ICON-2013":{"nm":"Penutup Bel Pintu Resepsionis","de":"Pasang penutup di atas bel pintu, dan keheningan siang pun tak terusik. Perhatian kecil untuk menjaga tidur nyenyak seseorang—keheningan pun ternyata sesuatu yang dibuat dengan penuh kesungguhan oleh seseorang."},"ICON-2014":{"nm":"Kartu Gantung Nomor Kamar","de":"Secarik kertas yang tergantung di kenop pintu memuat nomor kamar dengan jelas. Beberapa angka menentukan tempatku kembali malam ini, dan di lorong yang asing, itu menjadi mercusuar kecil."},"ICON-2015":{"nm":"Strip Magnet Kartu Kunci","de":"Tempelkan pita hitam ke celah pintu, dan kunci pun terbuka perlahan. Zaman ketika sinyal tak kasat mata membuka pintu—sesuatu yang dulu terasa seperti sihir kini telah menetap sebagai keseharian di telapak tangan."},"ICON-2016":{"nm":"Bantalan Stempel Check-In","de":"Setiap kali stempel dijatuhkan, bantalan ini menerima tinta secara merata. Agar satu goresan pengesahan tercetak jelas, ada sebuah tangan yang diam-diam menopang dari tempat yang tak terlihat."},"ICON-2017":{"nm":"Batang Gantung Troli Koper","de":"Sebatang penggantung di troli koper menopang tas pakaian tanpa membuatnya kusut. Kepada benda-benda yang mengangkat beban berat hari kita sebagai gantinya, kadang terasa ingin mengucapkan terima kasih."},"ICON-2018":{"nm":"Label Gantung Pegangan Koper","de":"Gantungkan label kecil di pegangan koper. Selama kolom nama masih kosong, tersisa debar bahwa tujuan berikutnya tas ini belum ditentukan."},"ICON-2019":{"nm":"Ganjal Pengunci Roda Troli","de":"Selipkan ganjal di bawah roda agar troli tak menggelinding di jalan menurun. Menjaga sesuatu tetap diam adalah, kadang, wajah lain dari keselamatan yang paling dapat diandalkan."},"ICON-2020":{"nm":"Gesper Tali Bagasi","de":"Kencangkan tali erat-erat agar tas yang menggembung penuh barang perjalanan tak sampai jebol. Meski perjalanan berakhir, volume kenangan tak pernah menyusut, maka gesper ini menahan beban itu hingga akhir."},"ICON-2021":{"nm":"Penutup Kait Troli Koper","de":"Penutup yang membungkus kait troli tak meninggalkan satu pun bekas di pakaian. Hati yang memperhitungkan bahkan goresan yang tak terlihat—keramahan yang baik disempurnakan justru di tempat sekecil ini."},"ICON-2022":{"nm":"Kantong Label Nama Koper","de":"Kantong kecil di sisi tas mendekap sebuah label nama. Menuliskan milik siapa ini sama seperti mengukir sejak awal hak untuk bertemu kembali, sekalipun sempat hilang."},"ICON-2023":{"nm":"Jepitan Sarung Tangan Angkut Barang","de":"Saat mengangkut barang berat, jepitan ini menggigit erat sarung tangan agar tak melorot. Melindungi tangan dan menuntaskan pekerjaan dengan baik, pada akhirnya, berasal dari satu hati yang sama."},"ICON-2024":{"nm":"Penutup Jaring Bagasi","de":"Tutupi dengan jaring, dan barang-barang kecil tak lagi berserakan ke segala arah. Setiap mata jaring yang rapat menjaga agar benda-benda kecil tak terlewat di tengah kesibukan berpindah tempat."},"ICON-2025":{"nm":"Penjepit Memo Troli Koper","de":"Memo yang terselip di pegangan troli memuat nomor kamar. Kebiasaan menuliskan ke mana harus pergi—semakin sibuk tangan, semakin ia bersandar diam-diam pada satu baris tulisan."},"ICON-2026":{"nm":"Tudung Penutup Piring Nampan","de":"Angkat tudung peraknya, dan uap pun mengepul serentak. Hati yang menutupi makanan agar tak dingin adalah kesungguhan itu sendiri, keinginan untuk menyalurkan kehangatan apa adanya."},"ICON-2027":{"nm":"Papan Kenop 'Jangan Ganggu'","de":"Gantungkan papan ini di kenop pintu, dan bahkan langkah kaki di lorong menjadi berhati-hati. Sepatah kata 'jangan bangunkan aku'—istirahat pun baru terasa utuh ketika ada yang menjaganya."},"ICON-2028":{"nm":"Cincin Serbet Kertas Layanan Kamar","de":"Selipkan serbet kertas ke dalam cincin bundar untuk membentuk lipatan yang rapi. Tata krama semangkuk hidangan dimulai dari lingkaran kecil ini—kesungguhan tampak paling jelas pada hal-hal yang remeh."},"ICON-2029":{"nm":"Alas Anti-Selip Nampan","de":"Letakkan alas di atas nampan, dan piring pun tak lagi tergelincir. Menjaga sesuatu tetap di tempatnya bahkan di tengah guncangan—kestabilan yang tenang pun menyimpan rancangan penuh ketelitian dari seseorang."},"ICON-2030":{"nm":"Kartu Pesanan Sarapan Gantung Pintu","de":"Gantungkan kartu pesanan sarapan di kenop pintu, dan esok pagi pun telah dijanjikan sejak malam ini. Menuliskan santapan pertama malam ini adalah satu lagi wajah dari penantian yang penuh kasih."},"ICON-2031":{"nm":"Kaki Penyangga Nampan","de":"Bentangkan kaki nampannya, dan di atas ranjang pun ia menjadi meja makan yang layak. Sepiring sarapan yang diterima sambil berbaring—penyangga kecil ini mengubah kamar biasa menjadi pemandangan yang mewah."},"ICON-2032":{"nm":"Penutup Penghangat Teko","de":"Pasangkan penutup penghangat pada teko, dan kehangatan air pun bertahan lama. Seperti malam-malam lampau yang dihabiskan mengelilingi tungku, keinginan untuk menjaga kehangatan tak mengenal zaman."},"ICON-2033":{"nm":"Ekor Gantung Permintaan Bersih-Bersih","de":"Gantungkan ekor permintaan pembersihan di kenop pintu untuk meninggalkan isyarat tanpa kata. Permintaan yang tersampaikan tanpa membuka bibir—di balik kamar yang rapi tersimpan janji sebuah sentuhan tangan yang tak terlihat."},"ICON-2034":{"nm":"Dudukan Botol Bumbu Nampan","de":"Dudukan ini menggenggam erat botol-botol bumbu agar tak tumbang. Menjaga keseimbangan rasa bahkan di atas nampan yang berguncang, adalah tugas diam sebuah pengunci kecil ini."},"ICON-2035":{"nm":"Standar Penjepit Memo Reservasi","de":"Sematkan memo reservasi berdiri tegak, dan urutan giliran pun terbaca sepintas mata. Agar tangan yang sibuk pun tak keliru, ini adalah alat keteraturan kecil yang menegakkan selembar kertas dengan jelas."},"ICON-2036":{"nm":"Papan Peta Tusuk Pin Wisata","de":"Tancapkan pin di atas peta, menandai satu per satu tempat yang ingin dikunjungi. Setiap pin adalah debar tempat yang belum pernah didatangi—perjalanan sudah dimulai sejak saat peta itu dibentangkan."},"ICON-2037":{"nm":"Jepitan Bendera Panggil Taksi","de":"Saat memanggil taksi, jepitan ini menegakkan bendera kecil dengan lurus. Isyarat yang diteriakkan bendera menggantikan tangan yang terangkat—bahkan di jalan raya, sebuah panggilan harus jelas dahulu sebelum benar-benar tersampaikan."},"ICON-2038":{"nm":"Kenop Bel Concierge","de":"Tekan kenop ini, dan bunyi jernih pun sampai ke meja concierge. Isyarat keramahan yang berkata boleh bertanya apa saja—di kota yang asing, inilah satu panggilan paling menenangkan."},"ICON-2039":{"nm":"Papan Jepit Nomor Reservasi","de":"Jepitkan kertas nomor reservasi ke papan agar terlihat jelas. Agar tempat yang dijanjikan tak tertukar, ini adalah ketekunan kecil yang menjaga satu baris angka tetap rapi."},"ICON-2040":{"nm":"Rak Pajangan Pamflet Wisata","de":"Pajang pamflet wisata, dan tangan seorang pelancong pun berhenti dengan sendirinya. Di setiap lembar yang dibuka satu per satu, pemandangan dari jalan yang belum ditempuh terlipat diam-diam."},"ICON-2041":{"nm":"Penyangga Stempel Peta","de":"Untuk langkah pertama yang memasuki pintu masuk, ia menopang kotak stempel di atas peta agar tak goyah. Ketika tinta tak melebar, jalan pun tak membingungkan. Sebuah tempat yang diam-diam menahan beban agar petunjuk kecil ini berdiri tegak."},"ICON-2042":{"nm":"Label Simpan Payung","de":"Pada sore ketika tetes hujan menetes dari ujung atap, gantungkan satu nomor di setiap payung. Ketika seseorang yang kembali sehabis hujan datang mengambil miliknya, label ini memanggil kembali kenangan yang basah dengan jelas."},"ICON-2043":{"nm":"Gantungan Lonceng Panggilan Meja Informasi","de":"Berdenting sekali, dan seseorang datang berlari cerah dari seberang sana. Lonceng kecil yang tergantung di sudut meja adalah penerjemah paling lembut, menyampaikan bahkan kata yang tak sempat terucap."},"ICON-2044":{"nm":"Nozel Dispenser Sampo","de":"Buka telapak tangan dan tekan ringan, busa pun mekar dengan lembut. Satu semprotan itu, ketika aromanya menyebar memenuhi kamar mandi. Bunyi yang membangunkan pagi yang mengantuk dengan paling lembut dimulai justru dari sini."},"ICON-2045":{"nm":"Baki Peniris Air Tempat Sabun","de":"Baki yang diam-diam mengalirkan air yang menggenang di bawah sabun. Agar tak melunak, agar tak lembek. Perhatian kecil dan lembut untuk membuat sesuatu yang terus terkikis setiap hari bertahan sejengkal lebih lama di sisimu."},"ICON-2046":{"nm":"Sendok Garam Mandi","de":"Ambil sesendok bubuk, larutkan dalam air hangat, dan warna serta aroma pun perlahan menyebar. Sembari diaduk oleh pergelangan tangan, bak mandi pun berubah menjadi danau kecil, dan kelelahan sehari tenggelam diam-diam di dalamnya."},"ICON-2047":{"nm":"Kantong Jaring Busa","de":"Kurung sepotong sabun dalam jaring dan gosok, busa lembut pun memenuhi kedua telapak tangan. Alkemis diam-diam di satu sudut kamar mandi, mengubah yang kasar menjadi lembut."},"ICON-2048":{"nm":"Tutup Sterilisasi Sikat Gigi","de":"Keinginan agar apa pun yang menyentuh mulut selalu bersih. Satu tutup kecil yang lembut membungkus ujung bulu sikat merawat bahkan bagian yang tak terlihat. Kebersihan tercipta dari hal-hal remeh seperti ini yang bertumpuk."},"ICON-2049":{"nm":"Tutup Wadah Cotton Bud","de":"Wadah tempat batang-batang putih berbaring rapi, dan tutup yang membulat menudunginya. Buka dengan bunyi tok, tutup dengan bunyi klik. Titik akhir yang lembut bagi kerapian kamar mandi, disempurnakan oleh bunyi sekecil itu."},"ICON-2050":{"nm":"Botol Tetes Minyak Mandi","de":"Miringkan sedikit, dan minyak wangi pun menetes satu per satu. Kilau dan aroma lembut yang menyebar di bak mandi. Terlalu sederhana untuk disebut kemewahan, terlalu lembut untuk disebut biasa—satu tetes saja."},"ICON-2051":{"nm":"Sekat Nampan Amenitas","de":"Di atas nampan yang terbagi menjadi petak-petak, botol-botol kecil menemukan tempatnya masing-masing. Sesuatu yang terasa berantakan bila berserak dan rapi bila terkumpul. Satu sekat menjaga keteraturan pagi yang sibuk."},"ICON-2052":{"nm":"Penyangga Jam Pasir Sauna","de":"Ini janji lembut untuk menghangatkan punggung, setidaknya selama pasir masih mengalir turun. Ketika jam pasir yang bersandar miring di penyangganya menghitung waktu perlahan, di tengah uap yang pekat, seseorang beristirahat sejenak, tanpa menjadi siapa pun."},"ICON-2053":{"nm":"Handuk Telinga Domba Sauna","de":"Gulung ujung handuk dan tegakkan seperti sepasang telinga domba, dan wajah di cermin pun perlahan mengendur. Di antara uap panas, ini ritual kecil ruang sauna tempat siapa saja sejenak kembali menjadi kanak-kanak."},"ICON-2054":{"nm":"Gayung Air Sauna","de":"Ciduk air penuh dengan gayung, siramkan ke batu yang membara—cess—uap pun menyembur hingga ke langit-langit. Pada saat itu, seluruh tubuh terbenam dalam kabut hangat, dan kelelahan yang lama mengendap perlahan lepas dalam tetes-tetes keringat."},"ICON-2055":{"nm":"Batang Ukur Suhu Rendaman Kaki","de":"Celupkan batang ke dalam air, dan garis-garis penandanya pun berbisik lembut. Tak terlalu panas, tak juga dingin, pas suhunya. Sebelum mencelupkan ujung jari kaki, inilah jari yang pertama kali menanyakan kabar air."},"ICON-2056":{"nm":"Penjepit Batu Panas Sauna","de":"Batu yang baru saja dipanaskan tak bisa digenggam dengan tangan kosong. Ketika penjepit menggigitnya erat lalu mengangkatnya, panas pun berpindah ke jarak yang aman. Kehati-hatian pun sebuah keterampilan, begitu kata ruang sauna dengan tenang."},"ICON-2057":{"nm":"Alas Bantal Sauna","de":"Bentangkan selembar di lantai yang panas, dan tempat punggung bersentuhan pun menjadi jauh lebih lembut. Alas yang tanpa kata menerima sehari yang basah oleh keringat. Istirahat, pada akhirnya, datang dari jarak yang pas dengan lantai."},"ICON-2058":{"nm":"Kantong Garam Rendaman Kaki","de":"Genggam segenggam garam kasar, larutkan dalam air hangat, dan rasa lelah pun meleleh perlahan mulai dari ujung jari kaki. Ketika uap yang asin membalut betis, hari yang telah dijalani dengan berjalan seharian pun akhirnya berhenti."},"ICON-2059":{"nm":"Piring Batu Aroma Sauna","de":"Teteskan beberapa tetes minyak wangi di atas batu yang dipanaskan, dan aroma yang menghangat pun perlahan menyebar ke seluruh sauna. Pejamkan mata, dan apakah ini hutan atau ladang bunga? Perjalanan tersingkat, ditempuh lewat ujung hidung."},"ICON-2060":{"nm":"Sarung Penghangat Bantal Kompres","de":"Kain yang membungkus erat bantal kompres yang dihangatkan, menahan kehangatannya lebih lama. Persis seperti hati yang memeluknya erat agar tak mendingin, kehangatan yang terletak di perut menemani sepanjang malam."},"ICON-2061":{"nm":"Batang Diffuser Aroma","de":"Batang-batang ramping menyerap wangi dan mengalirkannya perlahan ke seluruh ruangan. Aroma tipis yang meresap dengan setiap tarikan napas. Cara sebuah ruang tempat tinggal perlahan menyerupai aroma orang yang menghuninya."},"ICON-2062":{"nm":"Kenop Pengatur Sudut Kursi Berjemur","de":"Putar kenop perlahan, dan sandaran punggung pun mereda dengan mulus. Sedikit ke arah matahari, sedikit ke arah teduh. Meraba sudut yang paling nyaman adalah perhitungan yang sepenuhnya milikmu sendiri."},"ICON-2063":{"nm":"Pita Anti-Selip Tepi Kolam","de":"Pita anti-selip yang melingkari tepi air. Agar kaki-kaki kecil yang berlari riang sehabis bermain cipratan bisa berhenti dengan selamat, ini garis akhir keselamatan yang tergelar diam-diam di tempat yang tak terlihat."},"ICON-2064":{"nm":"Gantungan Katup Angin Ban Renang","de":"Sebuah gantungan diikat dengan cermat pada katup kecil yang menahan udara. Agar katup yang tercabut dari ban renang tak hanyut terbawa air. Kearifan yang mencegah kehilangan sepele di siang bolong musim panas sejak awal."},"ICON-2065":{"nm":"Penutup Tangga Masuk Kolam","de":"Penutup yang membungkus lembut ujung tangga yang menurun ke dalam air. Agar telapak kaki telanjang tak tergores, ia menampung langkah pertama memasuki air dengan lembut. Sebab setiap awal harus selalu berhati-hati."},"ICON-2066":{"nm":"Gantungan Tali Bantal Kursi Berjemur","de":"Gantungan tempat tali diikat agar bantal tak melorot turun. Janji kecil untuk tetap di tempatnya bahkan saat angin bertiup. Satu simpul menahan kemalasan siang di tempat itu."},"ICON-2067":{"nm":"Papan Selot Minuman Kolam Villa","de":"Papan untuk menyelipkan gelas minuman rapi di tepi kolam. Satu tempat yang tak tergoyahkan bahkan oleh cipratan riang. Meletakkan kesejukan dalam jangkauan tangan memperpanjang siang musim panas."},"ICON-2068":{"nm":"Jepitan Gantung Baju Renang Basah","de":"Ambil baju renang yang basah menetes-netes dan serahkan diam-diam pada embusan angin. Selagi mengering di bawah matahari, jepitan ini berdiri diam menahannya. Penantian yang tenang dan penuh kasih, untuk permainan air berikutnya."},"ICON-2069":{"nm":"Pemberat Dasar Tiang Payung","de":"Pemberat yang berat diletakkan di dasar tiang agar payung tak oleng ditiup angin. Bahwa keteduhan bertahan lama di satu tempat, semua berkat bobot ini. Kekokohan sering bersembunyi di tempat yang paling rendah."},"ICON-2070":{"nm":"Chip Apung Penanda Suhu Kolam","de":"Chip kecil yang mengapung di air, diam-diam melaporkan suhunya. Memerah jika terlalu dingin, melunak jika pas. Peramal kecil yang lucu, membaca suasana hati air hanya dengan satu warna."},"ICON-2071":{"nm":"Rumbai Penarik Ritsleting Tenda","de":"Tarik sedikit rumbai kecil yang tergantung di ujung ritsleting, dan pintu tenda pun terbuka perlahan. Pegangan yang langsung tergenggam bahkan saat jari meraba dalam gelap. Ia dengan lembut memandu keluar-masuk pada malam yang pekat."},"ICON-2072":{"nm":"Pin Kupu-Kupu Pengunci Tali Tenda","de":"Pin yang menjepit tali dalam bentuk kupu-kupu dan menahannya erat. Kain yang berkibar ditiup angin pun akhirnya diam. Malam berkemah dijaga dengan tenang oleh simpul-simpul kecil dan cekatan seperti ini."},"ICON-2073":{"nm":"Katup Angin Matras Glamping","de":"Dekatkan mulut dan tiup, tiup, matras pun perlahan mengembang. Setelah penuh dan katup ditutup rapat, lantai pun menjadi empuk, dan tempat merebahkan tubuh di bawah cahaya bintang pun akhirnya sempurna."},"ICON-2074":{"nm":"Kait Gantung Langit-Langit Tenda","de":"Kait yang tergantung di langit-langit tenda untuk menggantung lentera atau saputangan. Kearifan berumah tangga yang hemat memanfaatkan bahkan ruang kecil di atas kepala. Ibarat menggantung sebutir bintang di langit-langit, menggantikan langit itu sendiri."},"ICON-2075":{"nm":"Ikat Pengunci Gulungan Sleeping Bag","de":"Pita yang dililitkan dan dikancingkan agar sleeping bag yang digulung tak terurai. Tempat tidur yang mengecil kembali saat pagi tiba. Bersiap untuk pergi adalah melipat rapi kehangatan malam sebelumnya."},"ICON-2076":{"nm":"Papan Alas Sepatu Pintu Tenda","de":"Papan yang diletakkan di pintu masuk tenda untuk menopang sepatu dengan rapi. Tanah tetap di luar, bagian dalam tetap bersih. Dengan satu ambang, ia dengan lembut memisahkan dalam dan luar—tata krama kecil berkemah."},"ICON-2077":{"nm":"Kait Gantung Lentera Glamping","de":"Kait bengkok untuk menggantung lentera. Gantungkan di sini, dan cahaya pun menyebar bundar ke dalam tenda kanvas. Tempat menggantung satu cahaya di tengah kegelapan itu menjadi ruang tamu kita malam ini."},"ICON-2078":{"nm":"Jepitan Gulung Jendela Ventilasi Tenda","de":"Jepitan yang menggulung dan menahan jendela ventilasi. Buka sedikit jalan bagi angin, dan udara di dalam tenda pun jauh lebih segar. Satu celah kecil diam-diam membuat ruang untuk bernapas sepanjang malam."},"ICON-2079":{"nm":"Matras Alas Lantai Tenda","de":"Matras yang digelar di lantai tenda untuk menahan tanah dan lembap. Satu lapis yang membentangkan tempat tidur yang kering bahkan di atas rerumputan. Agar tetap berada di alam namun tak basah olehnya, ia diam-diam membantu di sisimu."},"ICON-2080":{"nm":"Ring Pengunci Barbel","de":"Ring yang dikancingkan di kedua ujung barbel agar piring beban tak melorot. Pengunci kecil yang sepenuhnya mempercayai berat tubuh orang yang mengangkatnya. Ketika keselamatan menopang dengan kokoh, barulah batas kemampuan bisa diperbarui satu tingkat lagi."},"ICON-2081":{"nm":"Tutup Pegangan Kettlebell","de":"Pada set terakhir ketika besi menggerogoti telapak tangan, satu tutup kecil ini membuat rasa sakit itu lenyap. Bahwa bertahan menggenggam hingga akhir lebih sulit daripada mengangkat beban itu sendiri—tangan mengetahuinya lebih dulu di titik penutup itu."},"ICON-2082":{"nm":"Ganjal Sisip Piring Beban","de":"Jika piring beban bergoyang sedikit saja, postur tubuh pun runtuh bahkan sebelum diangkat. Ganjal tipis yang diselipkan ke celah menahan pusat keseimbangan tanpa suara. Kekokohan selalu dimulai dengan tenang di tempat yang tak terlihat."},"ICON-2083":{"nm":"Jepitan Pengunci Barbel","de":"Ujung jari yang mengancingkan pengunci tak boleh ragu-ragu. Satu bunyi klik kecil terkunci itu menopang seluruh gerakan berikutnya. Tubuh belajar lebih dulu bagaimana mempertaruhkan kepercayaan pada satu jepitan."},"ICON-2084":{"nm":"Chip Warna Berat Piring Beban","de":"Chip yang diberi warna berbeda untuk tiap berat—tangan mengenalinya lebih dulu bahkan tanpa membaca angka. Merah berarti berat, biru berarti ringan; mengingat berat lewat warna. Tubuh, ternyata, menakar kekuatan lewat mata."},"ICON-2085":{"nm":"Alas Dasar Kettlebell","de":"Berkat alas yang memperlebar permukaan yang menyentuh lantai, papan lantai tak tergores. Jejak sebuah latihan cukup tertinggal di keringat dan otot saja. Hati kecil yang enggan meninggalkan luka bahkan di bawah kaki terhampar di sini."},"ICON-2086":{"nm":"Tanda Titik Tengah Barbel","de":"Tanda yang terukir di tengah batang adalah titik acuan keseimbangan kiri-kanan. Tangan yang menggenggam tepat di tengah membelah dua guncangan. Begitu tahu di mana pusatnya, barulah bisa mengangkat dengan aman."},"ICON-2087":{"nm":"Rak Simpan Piring Beban","de":"Piring beban yang sudah dipakai kembali ke tempatnya. Pemandangan piring-piring yang tergantung rapi menurut berat di rak adalah perhatian diam-diam untuk orang berikutnya. Ruang yang tertata adalah alat pengaman paling dapat diandalkan, begitu keyakinan seseorang."},"ICON-2088":{"nm":"Bibir Penahan Gelinding Piring Beban","de":"Kecelakaan piring beban di lantai yang menggelinding menimpa punggung kaki selalu datang pada satu saat lengah. Bibir penahan ini diam-diam menghalau momen sekejap itu. Musibah besar tak datang dari tempat yang besar—ia menggelinding dari celah yang kecil."},"ICON-2089":{"nm":"Bantal Sandaran Bangku","de":"Jika bantal yang menopang punggung terlalu keras, napas pun menjadi dangkal lebih dulu. Batas antara cukup keras dan cukup lembut itu adalah titik keseimbangan yang hanya bisa diraba oleh ujung jari orang yang telah lama duduk."},"ICON-2090":{"nm":"Pin Pengatur Tinggi Rak","de":"Dengan satu pin penentu ketinggian, batang barbel pas di bahu siapa pun. Orang dengan tinggi badan berbeda berbagi alat yang sama dengan akrab—satu lubang penyetel kecil menciptakan kesetaraan yang lembut itu."},"ICON-2091":{"nm":"Penutup Katrol Mesin","de":"Di dalam penutup yang membungkus katrol, kabel berputar dan berputar tanpa suara. Komponen yang menyembunyikan gesekan di dalam dan hanya menyerahkan kelembutan pada tangan. Alat yang baik tak pernah menampakkan jerih payah yang telah ditunaikannya."},"ICON-2092":{"nm":"Kaki Anti-Selip Bangku","de":"Kaki anti-selip yang dipasang di keempat ujung kaki menahan bangku erat ke lantai. Hanya ketika tak bergoyang, kau bisa mencurahkan seluruh tenaga dengan lega. Kestabilan, pada akhirnya, dimulai dari gesekan kecil di ujung kaki."},"ICON-2093":{"nm":"Kait Penyangga Barbel Rak","de":"Kait tempat menggantung batang barbel harus selalu berada pada ketinggian yang terjangkau tangan. Tempat lengan yang lelah akhirnya meletakkan batang itu dengan tenang—posisi sejengkal itulah yang menutup latihan hari ini dengan aman."},"ICON-2094":{"nm":"Pegangan Pin Beban Mesin","de":"Pegangan untuk menancapkan pin memilih beban harus mulus agar tak melukai kuku. Bahkan dalam gerakan sekejap mengganti beban, terasa ada penyelesaian yang mempertimbangkan ujung jari manusia, tersembunyi diam-diam di sana."},"ICON-2095":{"nm":"Tuas Pengunci Sudut Bangku","de":"Jika tuas pengunci sudut sandaran longgar, postur tubuh pun diam-diam runtuh. Kepastian pada saat bunyi klik mengunci itu. Pengelola setiap pagi membuka pintu dengan lebih dulu memeriksa bunyi ini dengan tenang."},"ICON-2096":{"nm":"Penyangga Palang Aman Rak","de":"Pada saat terburuk ketika barbel lepas dari tangan, penyangga palang aman ini menerima beban itu sebagai gantinya. Karena ada penyangga tak terlihat yang selalu menunggu di bawah, seseorang barulah bisa mendorong dirinya hingga batas sesungguhnya."},"ICON-2097":{"nm":"Tutup Ujung Kabel Mesin","de":"Tutup kecil yang merapatkan ujung kabel adalah simpul terakhir melawan keterurai. Mengikat rapi agar untaian tak berserakan—martabat sebuah penyelesaian selalu bertahan di titik akhir yang tak terlihat itu."},"ICON-2098":{"nm":"Kantong Bubuk Kapur","de":"Segenggam bubuk putih yang dilumurkan ke tangan untuk menghapus licin. Tak terlihat seperti riasan di balik panggung, namun kestabilan setiap gerakan hari ini justru dimulai dari segenggam ini. Persiapan selalu dimulai dari ujung jari."},"ICON-2099":{"nm":"Jepitan Latihan Genggaman","de":"Jepitan kecil yang diam-diam mengulang menggenggam dan melepas membangun kekuatan genggaman. Kekuatan genggaman tumbuh lebih lambat daripada otot besar, jadi ini juga latihan untuk diam-diam melepaskan ketidaksabaran."},"ICON-2100":{"nm":"Pita Peregang Jari","de":"Pita yang diselipkan di antara jari-jari untuk perlahan direntangkan ke luar. Tangan yang hanya terbiasa menggunakan otot menggenggam pun mendapatkan kembali kekuatan untuk membentang. Sebanyak menggenggam erat, melepaskan dengan tenang pun butuh latihan, kata tangan."},"ICON-2101":{"nm":"Tutup Tabung Bedak Kapur","de":"Kalau tutup tabung bubuk sedikit saja longgar, seisi tas akan memutih semua. Satu tutup kecil yang menutup rapat mencegah kekacauan sepele itu sebelum terjadi. Berhasil tidaknya menjaga sesuatu selalu ditentukan oleh sumbatnya."},"ICON-2102":{"nm":"Pembalut Pelindung Lutut","de":"Pembalut yang melilit dan menopang lutut harus berhenti tepat pada tekanan yang pas. Terlalu kencang, darah tersumbat; terlalu longgar, sia-sia saja—maka tangan yang sudah berpengalaman diam-diam mengira-ngira batas tipis itu dari ingatan."},"ICON-2103":{"nm":"Tali Resistensi Elastis","de":"Tali elastis yang memanjang lalu kembali menyusut membangunkan otot yang tertidur tanpa sebongkah pun besi. Resistensi tidak harus berat. Bahkan di hadapan tarikan yang lembut sekalipun, tubuh selalu menjawab dengan jujur."},"ICON-2104":{"nm":"Kantong Pemberat Pergelangan Kaki","de":"Kantong pasir yang disematkan di pergelangan kaki menyeret setiap langkah dengan berat yang memuaskan. Tambahkan sedikit beban, dan berjalan biasa pun berubah menjadi latihan sungguhan. Itulah sedikit kebijaksanaan yang menyelipkan usaha ke dalam keseharian."},"ICON-2105":{"nm":"Batang Penggulung Pergelangan Tangan","de":"Penggulung yang perlahan digulung dengan pergelangan tangan untuk mengangkat beban yang tergantung di tali. Pergelangan tangan adalah sendi terkecil yang paling sering terlupakan, dan alat sederhana ini diam-diam membangkitkan kembali kekuatan yang terlupakan itu."},"ICON-2106":{"nm":"Bola Karet Penguat Genggaman","de":"Bola karet yang diremas dan dilepas terus melanjutkan latihan diam-diam bahkan di depan meja kerja. Kekuatan yang terkumpul di sela-sela waktu bertahan lebih lama daripada kekuatan yang dicurahkan sekaligus. Ketekunan selalu tumbuh dari hal-hal kecil semacam ini."},"ICON-2107":{"nm":"Gesper Sabuk Detak Jantung","de":"Kalau gesper sabuk yang melilit dada sedikit saja bergeser, angkanya pun melonjak. Bahkan usaha mendengarkan suara jantung sendiri dimulai dari ikatan yang kokoh. Semua pengukuran, pada akhirnya, bermula dari lekatan yang rapat tanpa celah."},"ICON-2108":{"nm":"Klip Penjepit Denyut Nadi","de":"Klip yang menggigit lembut ujung jari diam-diam menghitung denyut nadi. Pasangkan, tenangkan napas, dan irama jantung pun muncul jelas di layar mungil. Tubuh selalu melaporkan keadaannya yang sebenarnya tanpa berbohong."},"ICON-2109":{"nm":"Kotak Penyimpan Gelang Pemantau Detak Jantung","de":"Kotak yang menyimpan alat pemantau pergelangan tangan itu kecil, tapi mengenali keluarganya sendiri. Semakin mudah sebuah perangkat kecil itu hilang, semakin ia butuh rumah untuk kembali. Menyimpan sesuatu dengan baik juga salah satu bentuk kasih sayang."},"ICON-2110":{"nm":"Pin Bendera Penanda Kecepatan","de":"Pin bendera kecil yang menandai titik tujuan bagi pelari. Satu titik yang sudah ditetapkan sebelumnya—\"sampai sini saja\"—membawa kaki yang berat itu hingga garis akhir. Garis finis di dalam hati selalu ditancapkan dengan tangan sendiri."},"ICON-2111":{"nm":"Tutup Lampu Berkedip Detak Jantung","de":"Lampu kecil yang berkedip pelan mengikuti detak jantung. Menatap irama nyala dan padamnya itu, hati pun tersentuh lagi menyadari betapa teraturnya hidup ini ternyata."},"ICON-2112":{"nm":"Tali Manik Penghitung Putaran","de":"Manik yang didorong satu per satu untuk menghitung jumlah putaran. Tak perlu menghafal angka di kepala—jari-jari yang mengingatnya. Serahkan hitungan pada tangan, dan pikiran bisa sepenuhnya tinggal pada gerakan."},"ICON-2113":{"nm":"Bantalan Jepit Saturasi Oksigen","de":"Bantalan jepit yang disematkan di ujung jari diam-diam membaca kadar oksigen dalam darah. Ketika kedalaman napas yang tak terlihat itu muncul sebagai angka, kita menyadari lagi bahwa merawat tubuh, pada akhirnya, sekadar soal menatapnya dengan saksama."},"ICON-2114":{"nm":"Gelang Warna Zona Detak Jantung","de":"Gelang yang membagi intensitas olahraga berdasarkan warna memberi tahu sekilas seberapa keras kita sedang berusaha. Biru berarti santai, merah berarti batas. Warna pun menjadi bahasa yang lembut, sebuah janji diam-diam."},"ICON-2115":{"nm":"Kapsul Jeli Pengukur","de":"Kapsul jeli mungil yang mengukur kondisi tubuh menyimpan rapi informasi sehari penuh dalam satu butir. Apa pun yang tersimpan di balik cangkang beningnya, keinginan untuk mengenal diri sendiri sedikit lebih dalam ikut tersimpan di sana juga."},"ICON-2116":{"nm":"Gantungan Handuk Keringat","de":"Kebiasaan kecil untuk selalu menggantungkannya di gantungannya sendiri, bukan sembarang tempat, menjaga seluruh ruangan tetap rapi. Seperti gantungan ini yang menyediakan tempat kembali bagi handuk, kerapian selalu bersinar dari hal-hal sepele."},"ICON-2117":{"nm":"Tali Pengikat Tutup Botol Minum","de":"Tali pendek yang menempel di tutup botol minum mencegah kecelakaan tutup yang menggelinding pergi. Kebijaksanaan mengikat sesuatu yang mudah hilang ke tubuh kita—satu tali kecil diam-diam menyingkirkan kerepotan sehari penuh."},"ICON-2118":{"nm":"Bilah Kipas Lipat","de":"Bilah kipas yang membangkitkan angin saat dibentangkan lebar. Seperti kipas lawas yang mendinginkan keringat di hari yang panas, alat paling sederhana memberi kenyamanan paling sejuk. Satu hembusan angin selalu mekar dari ujung jari."},"ICON-2119":{"nm":"Kantong Handuk Pendingin","de":"Kantong kecil yang menyimpan handuk yang mendingin saat dibasahi. Selembar kain pendingin panas itu tertidur rapi di dalamnya, lalu turun lembut ke tengkuk yang lelah dan diam-diam membawa pergi panasnya siang."},"ICON-2120":{"nm":"Piring Penampung Tetesan","de":"Piring kecil yang disiapkan lebih dulu untuk menampung tempat jatuhnya tetesan air yang mengembun. Bukan menyalahkan yang menetes, melainkan menyediakan tempat untuk menampungnya lebih dulu. Kehangatan dapur selalu bertahan diam-diam seperti ini."},"ICON-2121":{"nm":"Bilah Pengarah Kipas Angin","de":"Saat embusan angin yang tadinya lurus ke depan berbelok sedikit mengikuti bilah kecil ini, udara ruang latihan yang gerah pun akhirnya bisa bernapas lega. Mengubah arah aliran selalu bermula dari sudut sekecil ini."},"ICON-2122":{"nm":"Bando Pelindung Dahi","de":"Kalau poni basah saat mencuci muka, seharian bisa jadi berantakan. Bando yang menyisir rambut lembut ke atas dahi ini memberi lima menit kering bagi orang di depan cermin. Baru terasa manfaatnya saat tak ada."},"ICON-2123":{"nm":"Penjepit Dudukan Gelas Minum","de":"Saat gelas oleng berbahaya di ujung meja, penjepit ini diam-diam menahan satu sisinya. Hari yang berlalu tanpa tumpah, seteguk air mengingatkan, adalah berkat seseorang yang menahan tepinya untuk kita."},"ICON-2124":{"nm":"Gagang Kait Jendela Ventilasi","de":"Jendela yang tertutup rapat terasa pengap, yang terbuka lebar terasa dingin. Gagang kait ini mengingat celah yang pas persis di antara keduanya. Ventilasi, pada akhirnya, adalah urusan hati—membiarkan sesuatu terbuka secukupnya."},"ICON-2125":{"nm":"Pelindung Sudut Balok Gabus","de":"Yang selalu melukai saat terbentur adalah sudut yang tajam. Karena itu sepotong gabus dipahat untuk menutup setiap ujungnya. Tempat yang dibalut lembut kini tak lagi menyakiti lutut siapa pun."},"ICON-2126":{"nm":"Tali Gagang Bantal Guling","de":"Memindahkan bantal panjang lebih merepotkan dari yang dikira. Pasang satu tali saja, dan ia langsung pas tergenggam satu tangan. Cara mengangkat sesuatu yang berat dengan ringan bergantung pada di mana gagangnya dipasang."},"ICON-2127":{"nm":"Pengunci Gesper Sabuk","de":"Ada hari-hari pinggang dikencangkan satu lubang lagi, ada pula hari-hari dilonggarkan satu lubang. Yang paling jujur mengenal kondisi hari itu adalah pengunci kecil ini. Sekeping logam yang diam-diam mencatat kejujuran tubuh."},"ICON-2128":{"nm":"Penyangga Balok Seperempat","de":"Balok yang dipotong menjadi empat bagian menopang lantai dengan kokoh. Tidak terlalu tinggi, tidak terlalu rendah—dengan keseimbangan yang pas persis segitu. Ia menunjukkan diam-diam bahwa menopang berarti merendahkan diri untuk mengangkat yang di atas."},"ICON-2129":{"nm":"Sarung Bantal Guling Telur","de":"Bantal bulat seperti telur ini dikenakan pakaian yang pas benar. Kalaupun basah keringat, tinggal dilepas dan dicuci. Semakin sering sesuatu bersentuhan dengan kulit setiap hari, semakin perlu ia punya satu lapis ganti—begitulah yang dipahami urusan rumah tangga."},"ICON-2130":{"nm":"Baji Penyeimbang Balok","de":"Kalau lantai miring sedikit saja, semua yang susah payah ditumpuk pun bergoyang. Selipkan satu baji tipis ke celah itu, dan dunia pun kembali mendatar. Meluruskan sesuatu tidak butuh hal yang besar-besar."},"ICON-2131":{"nm":"Manik Simpul Ujung Tali","de":"Diikat simpul yang kokoh agar ujung tali tidak terurai berantakan. Tali yang ujungnya dirapikan dengan baik bertahan lama. Satu simpul kecil mengajarkan bahwa mengakhiri lebih sulit daripada memulai."},"ICON-2132":{"nm":"Bantalan Lipat Pelindung Lutut","de":"Rasa ngilu yang menusuk setiap kali lutut menyentuh lantai keras. Selembar bantalan yang bisa dilipat dan dibuka ini menyelip lembut di antara lutut dan lantai. Ini adalah kelembutan yang menopang lutut seseorang menggantikan dirinya."},"ICON-2133":{"nm":"Alas Anti-Slip Balok","de":"Sekokoh apa pun balok, akan sia-sia kalau tergelincir. Alur-alur halus yang terukir di alasnya mencengkeram lantai dengan erat. Rahasia sesuatu yang tak goyah selalu tersembunyi di bagian bawah yang tak terlihat."},"ICON-2134":{"nm":"Klip Perata Batang","de":"Batang-batang diluruskan rapi lalu dijepit dengan klip. Orang yang terbiasa merapikan barisan tahu betul—kepuasan kecil dan aneh yang muncul ketika sesuatu yang berantakan disejajarkan."},"ICON-2135":{"nm":"Loop Tali Peregang Paha Belakang","de":"Ketika bagian belakang paha tertarik hingga jeritan lolos, loop ini meraih ujung kaki yang tak terjangkau tangan. Ke tempat yang tak bisa dicapai sendirian, seutas tali membentangkan jembatan bagi kaki."},"ICON-2136":{"nm":"Bantalan Perenggang Jari Kaki","de":"Jari-jari kaki yang terkurung sepatu seharian pun butuh istirahat. Di atas bantalan yang merenggangkan sela-selanya, kaki akhirnya bisa meregang lega. Malam yang melonggarkan diri dimulai dari tempat yang paling jauh."},"ICON-2137":{"nm":"Pengukur Sudut Postur","de":"Mata sendiri sama sekali tak bisa mengira-ngira sudah berapa derajat postur kita bergeser. Ketika alat pengukur ini diam-diam memberi tahu sudutnya, barulah tubuh berdiri tegak. Skala yang memperlihatkan kemiringan yang tak terlihat."},"ICON-2138":{"nm":"Baji Perata Panggul","de":"Sore yang lesu, panggul yang kaku miring ke satu sisi. Sanggah satu baji, dan perlahan pusat keseimbangan pun pulih kembali. Ini bukan meluruskan secara paksa, melainkan membantu menemukan kembali tempat yang tepat."},"ICON-2139":{"nm":"Gesper Gelang Pembuka Bahu","de":"Gelang yang perlahan meluruskan bahu yang membungkuk. Kencangkan gespernya, dan punggung yang bungkuk pun perlahan terbuka. Tarik napas dalam dengan bahu terbuka lebar, dan barulah muncul sikap membungkuk hormat di atas panggung."},"ICON-2140":{"nm":"Baji Penyangga Tulang Belakang","de":"Berbaring telentang, dan tulang belakang menggambar lengkungnya yang alami. Baji ini diam-diam menopang lengkungan itu tanpa melawannya. Cara beristirahat dengan baik dimulai dari menghargai lengkungan yang sudah dibawa tubuh sejak lahir."},"ICON-2141":{"nm":"Baji Peregang Punggung Kaki","de":"Peregangan punggung kaki selalu terasa kurang dalam. Sanggah baji yang pas, dan peregangan pun terasa segar hingga kedalaman yang sebelumnya tak terjangkau. Lereng kecil yang membantu kita menjangkau sedikit lebih jauh."},"ICON-2142":{"nm":"Sandaran Perata Pergelangan Tangan","de":"Ketika pergelangan tangan yang tertekuk di depan papan ketik mulai kesemutan, sandaran ini diam-diam menyelip di bawahnya. Yang paling dulu memperhatikan tangan yang bekerja lama justru barang-barang sederhana yang letaknya rendah seperti ini."},"ICON-2143":{"nm":"Pembalut Pelindung Pergelangan Tangan","de":"Sebelum mengangkat beban berat, pergelangan tangan dililit pembalut satu putaran. Rasa yakin yang tumbuh seiring lilitannya. Kebiasaan membungkus diri sebelum terluka adalah rahasia diam-diam mereka yang berlatih untuk jangka panjang."},"ICON-2144":{"nm":"Kantong Ponsel Lengan","de":"Ke mana menaruh ponsel saat berlari selalu jadi kekhawatiran tersendiri. Kantong yang diikat di lengan ini mengambil alih kekhawatiran itu. Berlari dengan lagu kesukaan terselip di lengan, jalan pun terasa jauh lebih pendek."},"ICON-2145":{"nm":"Tutup Pegas Alat Genggam","de":"Tutup yang menutupi ujung pegas alat genggam agar tidak menusuk telapak tangan. Selama meremas dan melepas berulang kali, penutup kecil ini menjaga kedamaian antara tangan dan besi. Perhatian di tempat yang tak terlihat."},"ICON-2146":{"nm":"Bidal Pelindung Jari Sarung Tangan","de":"Jari-jari nenek yang mahir menjahit selalu memakai bidal. Bidal yang dipasang di ujung sarung tangan ini melindungi ujung jari. Keinginan untuk menyayangi tangan yang sudah lama bekerja ternyata serupa, bahkan lintas generasi."},"ICON-2147":{"nm":"Bantalan Kapalan Genggaman","de":"Kapalan yang mengeras di telapak tangan adalah sidik jari yang ditinggalkan usaha. Bantalan yang dilapiskan di atasnya memungkinkan satu kali lagi. Membalut kembali tempat yang telah mengeras itu, seseorang pun kembali bergantung."},"ICON-2148":{"nm":"Selotip Anti-Slip Telapak Tangan","de":"Kalau telapak tangan terus tergelincir, apa yang susah payah digenggam pun lepas begitu saja. Lilitkan selotip yang kasar, dan tangan serta alat pun menyatu jadi satu. Kekuatan untuk tidak kehilangan genggaman ternyata datang dari gesekan."},"ICON-2149":{"nm":"Gelang Penyerap Keringat Lengan","de":"Sebelum keringat yang mengalir saat berolahraga sampai ke pergelangan tangan, gelang di lengan ini menyerapnya lebih dulu. Bahwa keringat bukanlah sesuatu yang memalukan, kain yang basah kuyup ini menjadi saksi tanpa kata."},"ICON-2150":{"nm":"Gantungan Pengering Sarung Tangan","de":"Kalau dilempar sembarangan, pagi berikutnya jadi merepotkan; tapi kalau digantung rapi, angin malam akan mengeringkannya sendiri hingga lembut. Aroma bersih sarung tangan yang kering sempurna membuka esok dengan segar."},"ICON-2151":{"nm":"Gagang Ritsleting Pakaian Olahraga","de":"Dengan tangan yang basah kuyup, ritsleting yang kecil mungil sama sekali tak bisa dipegang. Pasang satu gagang saja, dan sekali tarik langsung terbuka mulus. Sebuah loop sepele menyelamatkan satu menit penuh kepanikan."},"ICON-2152":{"nm":"Tempelan Ventilasi Penyerap Keringat","de":"Tempelan ventilasi dipasang di titik tubuh yang paling panas. Panas yang terperangkap perlahan lolos keluar lewat sela tempelan itu. Sebuah tindakan membuka satu lubang napas kecil tepat di tengah yang paling sesak."},"ICON-2153":{"nm":"Potongan Bantalan Insole Sepatu","de":"Bagian yang aus dari insole lama dipotong keluar, lalu diganti potongan baru. Sentuhan tangan yang tidak membuang semuanya, hanya mengganti bagian yang sakit. Perbaikan kecil di bawah kaki mengubah setiap langkah hari itu menjadi lebih ringan."},"ICON-2154":{"nm":"Tempelan Setrika Nomor Pakaian Olahraga","de":"Nomor punggung ditekan kuat dengan setrika ke pakaian. Selagi panasnya mendingin, angka pun tertanam kokoh di atas kain. Cap awal yang menyatukan orang-orang bernomor sama menjadi satu tim."},"ICON-2155":{"nm":"Pelindung Ujung Sepatu","de":"Pelindung yang dipasang di ujung sepatu diam-diam menangkis nasib sepatu yang ujungnya terus tersandung. Bagian yang paling dulu aus, dibuat paling kokoh. Semakin awet sebuah sepatu, semakin kuat pula bagian ujungnya."},"ICON-2156":{"nm":"Simpul Tali Serut Pakaian Olahraga","de":"Begitu tali serut pinggang ditarik dan diikat, pakaian yang longgar pun langsung pas melekat di tubuh. Simpul yang kokoh dan tak mudah lepas ini menjaga segalanya tetap rapi sepanjang gerakan paling intens."},"ICON-2157":{"nm":"Gelang Anti-Slip Kaus Kaki Pendek","de":"Kerepotan kaus kaki pendek yang terus melorot masuk ke dalam sepatu. Satu gelang saja menahan gelinciran itu. Sepasang kaus kaki kecil yang selama ini luput dari perhatian, akhirnya bisa bertahan di tempatnya."},"ICON-2158":{"nm":"Bantalan Keringat Ketiak Pakaian Olahraga","de":"Bantalan yang dipasang lebih dulu di tempat keringat paling deras keluar. Meski basah kuyup, tak setitik pun terlihat di permukaan pakaian. Hal-hal yang bekerja diam-diam tanpa terlihat itulah yang menjaga panggung tetap bersih."},"ICON-2159":{"nm":"Loop Penarik Tumit Sepatu","de":"Setelah sepatu dipakai, tarik saja loop tumitnya, kaki pun langsung masuk sempurna. Kepraktisan singkat yang membebaskan kita dari harus jongkok. Di pagi yang sibuk, satu loop seperti ini berjasa besar."},"ICON-2160":{"nm":"Kepala Ganti Alat Pijat","de":"Kepala alat diganti sesuai bagian yang ditepuk. Setiap otot yang tegang punya bentuk yang cocok tersendiri. Malam yang memilihkan intensitas kenyamanan yang pas untuk bahu yang telah bertahan seharian."},"ICON-2161":{"nm":"Dok Pengisi Daya Alat Pijat","de":"Bahkan tangan yang akan melemaskan tubuh seharian pun baru terbangun setelah selesai diisi daya. Selagi lampu merah berubah menjadi hijau, boleh saja beristirahat sejenak. Ketika kedipannya berhenti, giliran untuk mengusap bahu yang kaku pun diam-diam datang lagi."},"ICON-2162":{"nm":"Dial Intensitas Alat Pijat","de":"Pelan, sedikit lagi, sampai di situ saja. Sambil memutar dial, ujung jari diam-diam bertawar dengan tubuhnya sendiri. Janji hari ini—untuk mengeras hanya sebatas rasa sakitnya—tertulis jelas di antara guratan-guratan kecil itu."},"ICON-2163":{"nm":"Cincin Dudukan Bola Getar","de":"Bahkan bola yang lincah menggelinding pun butuh tempat berhenti sejenak. Dudukan bundar ini diam-diam mendekap hasrat yang ingin bergulir pergi, menjaganya tetap di tempat hingga giliran berikutnya tiba. Istirahat juga bagian dari olahraga."},"ICON-2164":{"nm":"Tutup Gagang Tongkat Pijat","de":"Dengan satu tutup kecil di ujungnya, rasa sakit di telapak tangan pun perlahan menghilang. Antara kekerasan dan kulit selalu perlu ada satu lapis lembut. Sejengkal kelembutan yang lebih dulu membulatkan tempat yang bersentuhan."},"ICON-2165":{"nm":"Kantong Roller Kacang","de":"Kantong kecil yang menyimpan roller berbentuk kacang. Ketika ia menggelinding keluar dari sudut tas, tekad kemarin untuk mulai merawat tubuh hari ini pun ikut terbawa keluar bersamanya. Kantong kecil yang mengingat sebuah janji."},"ICON-2166":{"nm":"Dudukan Roller Pijat Kaki","de":"Kalau tempat untuk mempercayakan kaki goyah, relaksasi pun ikut goyah. Dudukan yang menopang roller ini mencengkeram lantai dengan kokoh, menyediakan tempat bagi kedua kaki yang lelah untuk bersandar dengan tenang. Keandalan datang dari sesuatu yang tak goyah."},"ICON-2167":{"nm":"Penutup Inti Roller","de":"Penutup kecil yang menyumbat inti yang kosong. Bagian dalam yang tak terlihat harus terisi agar bagian luar tidak berantakan. Tempat yang tak akan pernah dilihat siapa pun selama ia berputar itulah yang diam-diam disangga komponen kecil ini."},"ICON-2168":{"nm":"Penutup Ujung Tongkat Pijat","de":"Tutup bundar yang menyelimuti ujung tongkat. Agar tidak aus, agar tidak tergores—menjaga ujungnya adalah, pada akhirnya, cara untuk terus menemani lama-lama. Sebuah niat untuk membalut tempat yang paling dulu terbentur dengan cara paling lembut."},"ICON-2169":{"nm":"Pemotong Gulungan Plester Perekat","de":"Tarik dengan satu tangan, dan plester pun terpotong rapi. Ada trik kecil juga dalam mengikat simpul dan menyelesaikannya, dan bilah ini mengenal betul rasa dari sebuah akhir yang rapi. Penutupan yang bersih membuat langkah berikutnya lebih ringan."},"ICON-2170":{"nm":"Tutup Perekat Ujung Plester","de":"Tutup yang diam-diam menekan ujungnya agar tidak terurai. Siapa pun bisa memulai, tapi bertahan lengket sampai akhir selalu sulit. Tangan kecil yang menahan sejengkal terakhir ini diam-diam bertanggung jawab atas penyelesaian hari itu."},"ICON-2171":{"nm":"Sleeve Kompresi Pergelangan Tangan","de":"Balutkan satu lapis pada pergelangan tangan yang kelelahan, dan rasa sakit pun datang sedetak lebih lambat. Seperti tangan yang diam-diam menggenggam kita, kompresi terkadang menjadi perlindungan paling lembut. Bukan mencekik, melainkan menopang."},"ICON-2172":{"nm":"Gesper Pelindung Pergelangan Kaki","de":"Bunyi klik singkat saat mengencangkan gesper membuat hati menjadi tenang. Bungkus pergelangan kaki dengan kokoh, dan keberanian pun perlahan tumbuh bahwa mungkin tak apa melangkah satu jarak lagi. Satu bunyi kecil menjadi awal yang kukuh."},"ICON-2173":{"nm":"Pengunci Tali Kompresi Lutut","de":"Semakin tali ditarik kencang, semakin kokoh pula lutut terasa. Tak boleh lepas, tapi juga tak boleh sakit—di antara keduanya ada satu titik yang pas persis. Pengunci ini tak pernah lupa mengingat titik itu, setiap kali."},"ICON-2174":{"nm":"Gunting Plester Jari","de":"Gunting kecil yang memotong dengan presisi plester yang melilit ruas jari. Ujungnya bundar agar tidak melukai kulit. Semakin sebuah alat ditujukan untuk merawat, semakin lembut pula bilahnya diasah—gunting ini diam-diam menunjukkannya."},"ICON-2175":{"nm":"Alat Penggulung Gelang Kompresi","de":"Alat yang menggulung rapi kembali gelang kompresi yang terurai. Tangan yang dengan telaten menggulung apa yang sudah dipakai tidak akan membuatnya kusut lagi di lain waktu. Di setiap lapis yang tergulung rapi, tersimpan kerapian hari itu."},"ICON-2176":{"nm":"Tali Pelindung Tulang Kering","de":"Tali yang mengikatkan bantalan pelindung bagian depan tulang kering. Pikiran yang lebih dulu memeriksa tempat yang mungkin terbentur itu sendiri sudah merupakan persiapan. Melangkah ke lapangan dengan kaki yang terikat kokoh, rasa takut di hati pun berkurang separuh."},"ICON-2177":{"nm":"Klip Pelindung Siku","de":"Klip kecil yang menggigit erat agar pelindung tidak melorot. Sesepele menjepit selembar kertas, namun kalau ini lepas, semuanya jadi longgar. Satu pengencang kecil memegang teguh rasa aman untuk sehari penuh."},"ICON-2178":{"nm":"Gagang Loop Peregangan","de":"Genggam loopnya dan regangkan tubuh panjang-panjang, terlihat ujung jari yang menjangkau sejengkal lebih jauh dari kemarin. Bukan hanya otot yang memanjang seiring tarikan. Hati yang kaku pun ikut sedikit demi sedikit terurai di sela-selanya."},"ICON-2179":{"nm":"Penyekat Perenggang Jari Kaki","de":"Renggangkan sela jari kaki yang terkurung sepatu seharian, dan angin pun masuk ke ruang yang sempit itu. Ada hal-hal di dunia ini yang baru terasa nyaman setelah sejenak terpisah. Ujung kaki pun butuh celah untuk bernapas."},"ICON-2180":{"nm":"Papan Baji Pelemas Betis","de":"Diselipkan seperti baji di bawah betis, kaki pun perlahan melemas. Satu sudut yang miring diam-diam mengalirkan pergi beban sehari penuh. Bersandar sedikit miring sambil berbaring—itulah, kadang, posisi paling nyaman."},"ICON-2181":{"nm":"Sandaran Pelemas Leher","de":"Sandarkan leher, dan pejamkan mata sejenak. Bahwa tak apa meletakkan sejenak kepala yang berat, sandaran kecil ini selalu membisikkan lembut ke bahu dari tempatnya yang sama. Bersandar pun butuh keberanian."},"ICON-2182":{"nm":"Tutup Ujung Tongkat Peregangan","de":"Satu tutup yang menyelimuti ujung tongkat yang menjulur panjang. Kalau ujungnya lembut, di mana pun ia menyentuh terasa aman. Ke arah siapa pun ia terjulur, membulatkan sudutnya lebih dulu—perhatian selalu dimulai diam-diam seperti ini."},"ICON-2183":{"nm":"Papan Bantalan Tonjolan Akupresur","de":"Baringkan tubuh di atas tonjolan yang bergelombang, dan hari pun mengalir keluar di setiap titik yang tertekan. Di batas antara nyeri dan lega itu, bahu yang kaku seharian perlahan menyerah dan melemas."},"ICON-2184":{"nm":"Jam Pasir Pernapasan Relaksasi","de":"Janji diam-diam untuk menarik napas panjang hingga butir pasir terakhir jatuh. Aliran pasir yang tipis itu diam-diam menghitung irama tarikan dan embusan napas. Hati yang sibuk pun ikut mereda sejenak di sela-selanya."},"ICON-2185":{"nm":"Dudukan Bola Akupresur Telapak Kaki","de":"Sanggah bola di tengah telapak kaki dan tekan perlahan. Kepada kaki yang menopang seluruh tubuh seharian penuh, dudukan kecil ini diam-diam menyerahkan tempatnya, berkata kini giliran mereka untuk ditopang. Bahkan yang biasa menopang pun ada saatnya beristirahat."},"ICON-2186":{"nm":"Tali Loop Pelemas Bahu","de":"Tali loop yang dikaitkan di bahu lalu ditarik. Rentangkan tali ke arah tempat yang kaku, dan ruas yang tegang pun terurai longgar satu demi satu. Ini menunjukkan bahwa bahkan untuk menjadi bebas pun kita butuh sesuatu yang menggenggam tangan kita."},"ICON-2187":{"nm":"Cakram Tali Lintasan","de":"Satu bulatan ruas dari tali lintasan yang membagi jalur air. Batas yang lembut, digariskan di atas air agar tidak berbenturan dengan perenang di sebelah. Sekat-sekat kecil yang menjaga jalur masing-masing membuat semua orang bisa maju berdampingan hingga akhir."},"ICON-2188":{"nm":"Kait Penegang Tali Lintasan","de":"Kait yang menarik tali lintasan hingga kencang lalu menggantungnya. Terlalu longgar, ia melengkung diterjang ombak; terlalu kencang, ia putus. Mencari tegangan yang pas mirip dengan meneguhkan hati—selalu meraba-raba di suatu tempat di antara keduanya."},"ICON-2189":{"nm":"Tutup Warna Lintasan","de":"Tutup kecil yang diwarnai berbeda untuk setiap lintasan. Tanda yang diwarnai agar jalurnya sendiri bisa dikenali sekilas bahkan dari kejauhan. Menjaga seseorang agar tak tersesat hanya dengan satu warna—pemandu, pada dasarnya, dimulai dari kebaikan sekecil ini."},"ICON-2190":{"nm":"Papan Gantungan Tali Lintasan","de":"Papan untuk menggantung rapi tali lintasan saat tidak digunakan. Di tangan yang merapikan tali dengan telaten demi start berikutnya, tersimpan diam-diam niat tenang untuk menutup hari ini dengan baik."},"ICON-2191":{"nm":"Gagang Penggulung Tali Lintasan","de":"Putar gagangnya berputar-putar untuk menggulung kembali tali yang terurai panjang. Mengumpulkan kembali apa yang sudah tercerai-berai selalu membutuhkan kesabaran. Satu putaran, lalu satu putaran lagi—sebuah penyelesaian dirampungkan perlahan seperti ini, tanpa tergesa."},"ICON-2192":{"nm":"Penjepit Simpul Ujung Tali Lintasan","de":"Penjepit yang menggigit kokoh agar simpul di ujung tali tidak lepas. Tak membiarkan seutas sisa pun terlepas begitu saja. Harus ada tangan yang mengawasi hingga akhir agar tali yang panjang tetap menjaga bentuknya yang rapi tanpa berantakan."},"ICON-2193":{"nm":"Manik Pelampung Tali Lintasan","de":"Manik pelampung tali lintasan yang mengambang di atas air. Agar tidak tenggelam, ia menyimpan sepenuh udara di dalam dirinya. Bahwa ada kelonggaran yang datang dari kekosongan yang diisi dengan susah payah, riak air selalu memperlihatkannya berulang kali."},"ICON-2194":{"nm":"Bendera Nomor Lintasan","de":"Bendera kecil yang menandai nomor lintasan. Sepotong kain yang berkibar tertiup angin memberi tahu dengan jelas, \"ini tempatmu.\" Penunjuk arah yang kecil namun tegas, yang membawa seseorang langsung ke jalurnya sendiri tanpa tersesat."},"ICON-2195":{"nm":"Kait Penyambung Tali Lintasan","de":"Kait yang menyambungkan satu tali lintasan ke tali berikutnya. Dengan satu kait yang menyambung kembali jalur yang terputus, jalur air pun akhirnya lengkap. Menyambungkan, pada akhirnya, adalah pekerjaan sekeping logam kecil yang diam-diam mengulurkan tangan di antara hal-hal yang terpisah."},"ICON-2196":{"nm":"Pijakan Balok Start","de":"Pijakan di atas garis start menerima sepenuhnya beban lompatan pertama. 0,1 detik menghentak sekuat tenaga—kekokohan yang diinjak ujung kaki itulah yang mendorong dimulainya sebuah pertandingan. Setiap lompatan tinggi selalu bermula dari tempat berpijak yang kukuh."},"ICON-2197":{"nm":"Batang Pegangan Start","de":"Batang yang digenggam erat tangan sesaat sebelum aba-aba start. Hati yang gemetar harus ditambatkan di suatu tempat agar start tidak goyah. Hanya dengan adanya sesuatu untuk dipegang, satu gerakan berikutnya menjadi jauh lebih jelas dan kukuh."},"ICON-2198":{"nm":"Tali Bendera Gaya Punggung","de":"Tali berbendera yang memberi tahu perenang yang menatap langit-langit bahwa dinding sudah dekat. Sebuah kebaikan yang memperingatkan lebih dulu tentang tempat yang tak terlihat. Dengan satu isyarat yang menjaga punggung dengan penuh perhatian, kayuhan terakhir pun menjadi aman."},"ICON-2199":{"nm":"Bantalan Dinding Putaran","de":"Bantalan lembut yang dilapiskan pada dinding tempat berganti arah. Agar tak sakit meski terbentur keras, ia membungkus empuk tempat berbalik itu. Di jalan kembali, perhatian diam-diam seseorang selalu terhampar lebih dulu."},"ICON-2200":{"nm":"Papan Sentuh Garis Finis","de":"Begitu ujung jari menyentuh, semuanya berakhir. Akhir dari jalur yang panjang dan menyesakkan napas itu, pada akhirnya, hanya satu ketukan ringan ini. Garis finis bukanlah sesuatu yang megah, melainkan ketepatan menyentuh titik yang tepat—begitu papan ini diam-diam menjawab."},"ICON-2201":{"nm":"Strip Peluncur Titik Start","de":"Siapa pun yang berdiri di ujung tanjakan pasti sekali menahan napas. Melewati ketakutan sesaat itu lalu meluncur turun, dan—byur—tawa pun pecah bersama percikan air. Sebuah awal selalu dimulai satu langkah kecil melampaui rasa takut."},"ICON-2202":{"nm":"Kerucut Penanda Jarak Belok","de":"Saat ragu di persimpangan, titik kecil ini yang lebih dulu menyapa. Belok di sini, katanya, jangan sampai tersesat. Seseorang melihat satu warna ini dan menemukan arahnya kembali, lalu melangkah lagi."},"ICON-2203":{"nm":"Baji Sudut Balok Start","de":"Setengah ketukan saat tubuh membungkuk paling rendah, tepat sebelum melompat. Sebuah pijakan kecil ada di sana, menopang sudut agar ujung kaki tak tergelincir. Setiap momen melambung tinggi lahir dari kemiringan ini."},"ICON-2204":{"nm":"Pelindung Sudut Tembok","de":"Agar tak sakit walau tertabrak saat bermain, sudut itu telah merelakan ketajamannya menjadi bulat. Keinginan agar kau tak terluka, terpahat dan terpahat, menempel di dinding. Perlindungan paling penuh kasih biasanya sesunyi ini."},"ICON-2205":{"nm":"Gantungan Pelampung Penyelamat","de":"Biasanya ia hanya tempat sesuatu tergantung. Namun begitu seseorang jatuh ke air, di sinilah tangan pertama kali terulur. Ada semacam keandalan di dunia ini yang lebih baik tak pernah dipakai."},"ICON-2206":{"nm":"Galah Kait Penyelamat","de":"Lengan panjang yang mempersempit jarak tak terjangkau dalam sekali gerak. Saat tangan tak cukup panjang, kait ini menjadi tangan pengganti. Penyelamatan, pada akhirnya, adalah tindakan mengulurkan ujung jari kepada seseorang yang jauh."},"ICON-2207":{"nm":"Kepala Pancuran Tepi Kolam","de":"\"Bilas dulu sebelum masuk.\" Seperti kalimat andalan penjaga kolam, aliran air tercurah di atas kepala. Dengan satu semburan dingin, debu sehari langsung luruh jatuh."},"ICON-2208":{"nm":"Ubin Anti-Selip","de":"Alur bertekstur halus agar telapak kaki telanjang tak tergelincir. Dari tempat yang tak terlihat, ia diam-diam menopang telapak kakimu. Keselamatan paling kokoh selalu tersembunyi di tempat yang tak mencolok."},"ICON-2209":{"nm":"Papan Tanda Kedalaman Air","de":"Sebelum melangkah masuk, angka lebih dulu memberitahu kedalamannya. Tempat yang bisa menakutkan jika dimasuki tanpa tahu menjadi tenang begitu dibaca sekali. Yang dilakukan papan ini adalah membantu sedikit persiapan."},"ICON-2210":{"nm":"Tali Pelampung Batas Aman","de":"Tali warna-warni mengapung di air, membagi wilayah kolam. Sampai sini masih aman, janji para pelampung sambil bergandengan tangan. Karena ada batas, barulah kau bisa berenang bebas dengan hati tenang."},"ICON-2211":{"nm":"Bak Rendam Kaki Antiseptik","de":"Bak kecil tempat kaki telanjang singgah sejenak sebelum masuk ke air. Sebuah ritual singkat menjadi bersih dari kaki hingga ke atas tersimpan di sana. Kebersihan selalu bermula dari kepedulian satu langkah seperti ini."},"ICON-2212":{"nm":"Kerucut Peringatan Lantai Basah","de":"Satu kerucut kuning diam-diam memperlambat langkah. \"Di sini basah, hati-hati.\" Sebuah perhatian yang disampaikan lewat warna, bukan kata-kata. Peringatan kecil ini diam-diam menjaga hari seseorang yang hampir terpeleset."},"ICON-2213":{"nm":"Lemari P3K Dinding","de":"Lemari putih di dinding jarang sekali terbuka. Namun tepat saat ia terbuka, ia menjadi kelegaan bagi seseorang. Keadaan darurat selalu menunggu diam-diam di tempat yang paling dekat."},"ICON-2214":{"nm":"Jaring Serok Permukaan Air","de":"Diam-diam ia mengangkat daun dan debu yang mengambang di permukaan. Kejernihan tak datang dengan sendirinya, jadi tangan seseorang harus menyerok sekali setiap hari. Di balik air yang tenang, ada jaring yang rajin bekerja."},"ICON-2215":{"nm":"Selang Robot Pembersih Dasar Kolam","de":"Bahkan di malam saat semua orang tertidur, ia merayap perlahan menjelajahi dasar kolam. Pekerja paling setia di jam-jam yang tak dilihat siapa pun. Kejernihan pagi itu adalah jejak yang digurat selang ini sepanjang malam."},"ICON-2216":{"nm":"Tabung Dosis Klorin","de":"Bahkan menjaga air tetap jernih punya takaran yang pas. Terlalu banyak jadi keras, terlalu sedikit jadi keruh—keseimbangan ada di antara keduanya. Tangan tak terlihat diam-diam menyetel ukuran itu setiap hari."},"ICON-2217":{"nm":"Botol Uji Kualitas Air","de":"Segenggam air dikumpulkan dalam botol kecil untuk menanyakan kabar hari ini. Di mata terlihat sama saja, tapi angka tak pernah berbohong. Ketenangan hati adalah sesuatu yang dipastikan sekali sehari seperti ini."},"ICON-2218":{"nm":"Garuk Serok Papan Apung","de":"Garuk panjang yang mengumpulkan papan dan sampah apung yang melayang di air. Tangan yang menyapu bersih yang berserakan entah mengapa mirip dengan hati. Kekacauan pun, sekali disapu, menjadi rapi."},"ICON-2219":{"nm":"Jaring Penutup Saluran Air","de":"Jaring rapat yang menjaga jalur keluarnya air. Diam-diam ia memilah mana yang boleh lewat dan mana yang harus ditahan. Bahkan melepaskan sesuatu butuh penyaring, kata jaring kecil ini tanpa suara."},"ICON-2220":{"nm":"Pelampung Termometer Air","de":"Pengintai kecil yang mengapung di air dan membaca suhunya. Dingin atau pas, kebaikan hati yang memberitahu lebih dulu sebelum tubuh menyentuhnya. Kelegaan pertama saat masuk ke air selalu dimulai dari pelampung ini."},"ICON-2221":{"nm":"Batang Gulung Penutup Kolam","de":"Gagang yang menggulung penutup lebar dan menyimpannya ke satu sisi. Alat yang tahu kapan harus dibentangkan dan kapan digulung terasa entah mengapa dapat diandalkan. Saat istirahat, ini seperti menyelimuti air dengan selimut juga."},"ICON-2222":{"nm":"Keranjang Skimmer","de":"Keranjang tempat sampah apung di permukaan akhirnya berkumpul. Karena ada wadah yang menampung kotoran di tempat tak terlihat, air di atasnya selalu bening. Di balik kebersihan, tertimbun kerja keras."},"ICON-2223":{"nm":"Gantungan Pengering Topi Renang","de":"Topi renang yang basah digantung terbalik. Sambil menetes setetes demi setetes, topi itu perlahan mengatur napas. Mengering, pada akhirnya, hanyalah nama lain dari menunggu."},"ICON-2224":{"nm":"Pengait Tali Bahu Baju Renang","de":"Pengait kecil yang menahan tali agar tak melorot dari bahu. Dari tempat yang tak terlihat, ia diam-diam menjaga penampilan tetap rapi. Kerapian selalu tersempurnakan di atas penopang sekecil ini."},"ICON-2225":{"nm":"Kantong Penyimpan Topi Renang","de":"Kantong tempat topi-topi renang basah menemukan tempatnya satu per satu. Tempat kecil yang merangkul benda-benda yang mudah berserakan dalam satu pelukan. Merapikan adalah kebiasaan penuh kasih agar tak kehilangan sesuatu."},"ICON-2226":{"nm":"Bantalan Dada Baju Renang","de":"Satu bantalan yang diam-diam bersemayam di bagian dalam pakaian. Meski tak terlihat dari luar, ia lembut menegakkan bahu pemakainya. Sebagian rasa percaya diri diisi diam-diam dari dalam, bukan dari luar."},"ICON-2227":{"nm":"Jepitan Label Nama Topi Renang","de":"Jepitan kecil yang menyematkan label nama di tepi topi renang. Di antara benda-benda yang tampak sama, ia berkata jelas, \"ini punyaku.\" Satu tanda saja, dan kebingungan langsung berakhir."},"ICON-2228":{"nm":"Cincin Tarik Ritsleting Baju Renang","de":"\"Tolong naikkan ritsleting punggungku?\" Bagian yang tak terjangkau sendirian itu, cincin kecil ini menariknya naik menggantikan tangan. Jangkauan penuh kasih yang membantu setelan terakhir."},"ICON-2229":{"nm":"Papan Anti-Gulung Topi Renang","de":"Topi renang yang sudah terbiasa menggulung diluruskan dan disangga tegak. Sebuah penopang yang diam-diam membantu benda yang melengkung menemukan kembali bentuknya. Harus ada tangan yang meluruskan, agar apa pun bisa rapi dan lurus kembali."},"ICON-2230":{"nm":"Pengencang Tali Pinggang Baju Renang","de":"Pengencang yang membungkus pinggang secukupnya agar tak melorot. Tidak terlalu ketat, tidak juga terlalu longgar—pas secukupnya. Kenyamanan selalu hidup di suatu tempat di antara keduanya."},"ICON-2231":{"nm":"Jepitan Pembalik Topi Renang","de":"Jepitan yang menangkap topi renang yang terbalik dan meluruskannya sekaligus. Kepiawaian membalik sesuatu yang terbalik kembali ke posisi benar terasa cukup melegakan. Kenikmatan kecil dari merapikan datang dari hal-hal sepele seperti ini."},"ICON-2232":{"nm":"Tali Pegangan Papan Renang","de":"Tali yang melilit tangan agar papan renang tak terlepas. Punya sesuatu untuk dipegang meski terdorong arus adalah kelegaan besar. Getaran hari pertama belajar menendang kaki masih tertinggal di tali ini."},"ICON-2233":{"nm":"Tali Pengencang Pull Buoy","de":"Tali yang mengencangkan pelampung yang terselip di antara kedua kaki. Hanya jika tak lepas, barulah kau bisa fokus sepenuhnya pada gerakan. Di atas sesuatu yang terpegang erat, latihan hari itu semakin dalam sejengkal demi sejengkal."},"ICON-2234":{"nm":"Gantungan Dinding Kaki Katak","de":"Saat kaki katak tergantung berjajar di dinding, mereka persis seperti sekawanan bebek beristirahat di tepi air. Kaki-kaki yang baru selesai berenang mengibaskan air dan menunggu hari esok. Bahkan jeda pun entah mengapa terasa bulat dan menggemaskan."},"ICON-2235":{"nm":"Pelindung Sudut Papan Renang","de":"Satu tutup kecil yang dipasang di sudut papan renang. Agar tak sakit saat terbentur, tak rusak saat aus, ia membungkus ujungnya. Rahasia menyimpan sesuatu lama di sisi kita terletak pada merawatnya dari sudut-sudutnya dulu."},"ICON-2236":{"nm":"Jaring Penyimpan Kaki Katak","de":"Kaki katak yang menyerupai kaki berselaput berjemur di dalam jaring. Seperti bebek yang baru keluar dari air mengeringkan bulunya, mereka mengering perlahan di dalam jaring. Tidur siang yang santai untuk renang berikutnya."},"ICON-2237":{"nm":"Label Penanda Pull Buoy","de":"Kau menempelkan label nama pada setiap pelampung untuk menandai pemiliknya dengan jelas. Semakin banyak dibagikan bersama, semakin tenang hati ketika \"milik siapa\" itu jelas. Satu label kecil menegakkan keteraturan."},"ICON-2238":{"nm":"Sandaran Peniris Papan Renang","de":"Tempat yang disandarkan miring agar air yang tergenang di papan renang menetes turun. Kau harus mengosongkan apa yang telah kau serap agar menjadi ringan, kata sandaran itu diam-diam. Langkah pertama mengering adalah menyandarkan diri dengan baik."},"ICON-2239":{"nm":"Pengencang Tali Kaki Katak","de":"Komponen kecil yang mengencangkan tali kaki katak agar pas di kaki. Terlalu longgar lepas, terlalu ketat sakit—satu kelonggaran halus di antaranya. Untuk melaju ringan seperti bebek berselaput, dibutuhkan satu ketepatan ini."},"ICON-2240":{"nm":"Chip Ritme Tendangan","de":"Chip kecil yang memberi tahu ketukan setiap kali kau menendang. Satu, dua, tiga—begitu ritme meresap ke tubuh, air pun tanpa disadari berubah menjadi lagu. Chip ini lembut mengajarkan bahwa berenang pun punya ketukannya sendiri."},"ICON-2241":{"nm":"Kantong Baju Renang Basah","de":"Di dalam tas yang meninggalkan kolam renang, yang pertama mengklaim tempat selalu aku. Biarkan barang-barang lain melirik sinis, mau bagaimana lagi, yang basah harus dipisah agar semua tetap kering. Ruang karantina kelembapan, itulah jabatan penuh kasih yang kupegang."},"ICON-2242":{"nm":"Papan Pemeras Air","de":"Air punya sifat licin, diam-diam kabur begitu ditekan. Sekali tekan, dua kali tekan—baru ia menyerah begitu diletakkan di atas papan dan diberi bobot. Bagi orang yang tak pernah punya kesempatan memakai kekuatan pergelangan tangannya, jarang ada panggung sebaik ini."},"ICON-2243":{"nm":"Papan Sekat Tas Renang","de":"Jika dimasukkan semua dalam satu wadah, yang basah dan yang kering saling mengotori. Tugasnya menyelinap diam-diam di antara keduanya dan menggariskan batas. Jika satu sekat saja bisa membawa kedamaian, mungkin rekonsiliasi adalah hal yang mengejutkan sederhananya."},"ICON-2244":{"nm":"Kantong Sepatu Anti Air","de":"Ia menelan bulat-bulat sepatu berlumur pasir tanpa berubah raut sedikit pun. Apa pun yang terjadi di dalam, bagian luar tetap kering—itulah kesopanan yang dijaga sifat tahan airnya. Kantong yang pandai menjaga rahasia disambut di mana saja."},"ICON-2245":{"nm":"Tutup Pembuangan Tas Renang","de":"Putar tutupnya dan hari yang tergenang di dasar tas mengalir keluar. Beres-beres setelah bermain seru selalu bergantung pada satu lubang kecil ini. Bahkan tahu cara melepaskan sesuatu pun butuh rancangan."},"ICON-2246":{"nm":"Keset Penyerap Air","de":"Ia terbaring diam di depan pintu, menampung air dari setiap kaki yang masuk. Meski tak ada yang menyadarinya, lantai kayu tahu—hari ini pun tak ada yang terpeleset. Di tempat yang diam, tersimpan pahala yang diam pula."},"ICON-2247":{"nm":"Piring Alas Topi Renang Basah","de":"Saat topi renang yang dilempar kehilangan tempat tujuannya, akulah yang menampungnya. Meski disebut piring padahal menampung tetesan air, bukan makanan, kalau ini adalah tugas menyediakan tempat bagi seseorang, sebuah alas pun bisa bangga."},"ICON-2248":{"nm":"Jepitan Pengering Handuk","de":"Tugasku menggigit erat selembar handuk di atas tali jemuran. Betapa pun angin menggoda, kekeraskepalaanku untuk tak melepaskan adalah kebanggaanku. Sampai kering hangat oleh matahari, tangan yang sudah menggenggam tak akan pernah melepas duluan."},"ICON-2249":{"nm":"Gantungan Pouch Anti Air","de":"Begitu tergantung di pengait, pouch yang tadinya terkatung-katung akhirnya punya alamat. Meski hanya bergantung, meminjam satu petak dinding, adakah yang seyakin tempat yang bebas dari rasa takut hilang?"},"ICON-2250":{"nm":"Gelang Masuk Perosotan","de":"Debaran yang diam-diam menunggu giliran, seluruhnya terikat dalam satu gelang kecil ini. Baru setelah terpasang di pergelangan tangan, antrean perosotan mulai bergerak, jadi mungkin masuk adalah tindakan mengikatkan janji ke pergelangan tangan."},"ICON-2251":{"nm":"Potongan Matras Perosotan Air","de":"Orang-orang berlari riang di atasnya tanpa sadar ada yang retak di bawah kaki. Terpasang agar tak ada yang terpeleset, keberadaannya baru terungkap begitu satu potongan itu hilang. Cukup banyak hal di dunia ini yang hanya diingat lewat ruang kosong yang ditinggalkannya."},"ICON-2252":{"nm":"Gelang Anti Air Kunci Loker","de":"Menjaga kunci loker dari air adalah pekerjaan seumur hidupku. Melilit di pergelangan tangan, ikut byar-byur bersama, namun satu kunci itu tetap kujaga tetap kering. Kehilangan aku berarti kau bahkan tak bisa menemukan pakaianmu, jadi begini saja aku petugas dengan tanggung jawab berat."},"ICON-2253":{"nm":"Panel Lampu Sinyal Start Perosotan","de":"Pada momen singkat saat merah berganti hijau, semua jantung di atas perosotan berdebar bersamaan. Wewenang untuk mengizinkan keberangkatan—siapa sangka panel sinyal sekecil ini bisa menyimpan debar sebesar itu."},"ICON-2254":{"nm":"Gesper Rompi Pelampung Kolam Arus","de":"Gesper yang mengunci erat tubuh yang mengapung menyusuri kolam arus. Klik, baru setelah suara itu terdengar, hati bisa tenang menyerahkan tubuh pada arus. Kelegaan kadang bermula dari kunci sekecil ini."},"ICON-2255":{"nm":"Bendera Panduan Kolam Ombak","de":"Ia memberi tahu orang-orang lebih dulu kapan ombak akan datang. Bendera naik berarti sorak-sorai, bendera turun berarti sesaat menarik napas. Anehnya, yang menjaga irama di tepi kolam yang bergejolak hanyalah sepotong kain."},"ICON-2256":{"nm":"Kalung Nomor Antrean Perosotan","de":"Kenakan di leher nomor antrean keberapa kau berdiri, dan tak ada lagi kebingungan. Satu label nomor menentukan giliran—keteraturan, rupanya, sering bermula dari kalung sekecil ini."},"ICON-2257":{"nm":"Token Isi Ulang Gelang Air","de":"Tempelkan ringan ke gelang tangan dan isi ulang pun selesai. Di zaman menjelajah air tanpa uang tunai atau kartu, token kecil ini memainkan peran sebagai dompet seutuhnya. Sepergelangan tangan menjadi ringan, sehati itu pula menjadi lega."},"ICON-2258":{"nm":"Tutup Pegangan Meriam Air","de":"Pegangan meriam air paling nikmat digenggam erat. Lepas satu tutup dan lupakan soal membidik, ia hanya berputar-putar di tangan—menang kalahnya perang air di tengah musim panas bergantung pada satu penutup kecil ini."},"ICON-2259":{"nm":"Cetakan Menara Istana Pasir","de":"Padatkan pasir basah, tekan erat, balikkan, dan menara kecil pun menjulang. Tak ada yang lebih memahami hati yang terus membangun meski tahu akan runtuh selain aku. Bagi arsitek pasir, cetakan adalah cetak birunya."},"ICON-2260":{"nm":"Gigi Garuk Pasir","de":"Seret seperti menyisir pasir, dan alur-alur rapi pun tertinggal. Meski tahu ombak akan segera menghapus polanya, gigi garuk itu tetap rajin menggurat garisnya. Ada pesonanya tersendiri dalam mengerjakan dengan sepenuh hati sesuatu yang ditakdirkan lenyap."},"ICON-2261":{"nm":"Pemberat Penopang Tiang Payung","de":"Ia berdiri diam di kaki tiang agar payung tak terbang tertiup angin. Menjaga keteduhan bukan tugas kain yang mencolok, melainkan tugas pemberat yang tertanam kokoh. Bobot yang tak terlihat adalah yang paling bisa diandalkan."},"ICON-2262":{"nm":"Gagang Ayakan Pasir","de":"Guncang untuk menyaring pasir, dan hanya cangkang kerang serta harta kecil yang tersisa di tangan. Pegang gagangnya dan goyangkan—separuh perburuan harta karun di pantai diputuskan oleh satu ayakan ini."},"ICON-2263":{"nm":"Cetakan Pasir Bentuk Kerang","de":"Isi dengan pasir basah, ketuk-ketuk, dan kerang seukuran telapak tangan pun mekar berderet di pantai. Kerang sungguhan mungkin tak bisa dimakan, tapi bentuk ini bisa dibuat siapa saja. Sihir sederhana musim panas."},"ICON-2264":{"nm":"Pin Pengatur Sudut Payung","de":"Setiap kali matahari bergeser, payung pun harus memutar kepalanya mengikuti. Cabut satu pin lalu pasang lagi, dan keteduhan diam-diam berpindah tempat. Inti keahlian menghindari cahaya terletak pada sudut kecil ini."},"ICON-2265":{"nm":"Tutup Ujung Mata Sekop Pasir","de":"Pasang di ujung mata sekop yang tajam, dan isi tas pun aman. Keberanian menggali pasir disimpan sejenak, dan dengan satu tutup ia berubah jadi mainan yang lembut. Tahu cara menyembunyikan ketajaman juga sebuah kebaikan."},"ICON-2266":{"nm":"Jepitan Sudut Matras Pantai","de":"Ketika angin mencoba mengangkat sudut matras, akulah yang menggigitnya erat. Menjaga satu petak di atas pasir pada akhirnya bergantung pada kekeraskepalaan keempat sudutnya. Sore hari tanpa berkibar adalah jasa jepitan-jepitan kecil."},"ICON-2267":{"nm":"Pengait Jemuran Bayangan Payung","de":"Gantungkan santai di tiang payung, dan pakaian basah pun mengering di keteduhan. Menghindari terik, menerima angin, sebuah tali jemuran darurat yang dibuat oleh satu pengait. Bahkan di pantai pun, kearifan rumah tangga bersemayam."},"ICON-2268":{"nm":"Kantong Kalung Ponsel Anti Air","de":"Rangkul ponsel dan gantungkan di leher, keberanian memotret pun muncul bahkan di dalam air. Menjaga tetap kering keinginan untuk mengabadikan satu jepretan lagi. Sebagai pengawal kenangan, ia cukup tangguh."},"ICON-2269":{"nm":"Pouch Anti Air Pakaian Basah","de":"Ia menerima bulat-bulat pakaian basah yang baru diganti tanpa keluhan. Tak membiarkan setetes air pun menyentuh barang lain adalah harga dirinya, jadi ia menutup mulutnya rapat-rapat dan menjaga satu sudut tas. Penutup yang bersih dimulai dariku."},"ICON-2270":{"nm":"Tali Punggung Kaki Sandal Air","de":"Ia lembut membungkus punggung kaki agar sandal telanjang tak terlepas. Berlari-lari kecil di atas pasir sekalipun, satu tali saja sudah melegakan hati. Teman setia langkah kaki, tak mencolok namun selalu di sisi."},"ICON-2271":{"nm":"Case Kalung Kartu Anti Air","de":"Merangkul tiket masuk dan kartu, ia tergantung di leher dan ikut bermain air. Bermainlah sepuasnya tanpa takut kehilangan apa pun, sebab ia menjadikan tubuhnya sendiri sebagai perisai kartu. Sikap seorang pengawal yang bisa diandalkan."},"ICON-2272":{"nm":"Kantong Kain Anti-Kabut Kacamata Renang","de":"Lap sekali bagian dalam kacamata renang yang berkabut dengan kain ini, dan dunia bawah air pun kembali jernih. Satu kantong kain kecil menjadi kunci yang membuka pandangan yang kabur menjadi terang."},"ICON-2273":{"nm":"Sikat Pembersih Pasir Basah","de":"Ia lembut menyapu bersih pasir bahkan di sela-sela jari kaki. Tangan terakhir yang merapikan jejak menjelajah laut dengan riang, tepat di depan pintu rumah. Sekali sapuan sikat, dan pasir sehari pun akhirnya berpamitan."},"ICON-2274":{"nm":"Kantong Ritsleting Koin Anti Air","de":"Ia mengunci beberapa keping koin rapat-rapat di balik ritsleting. Basah atau tidak, bunyi gemerincingnya tetap sama, jadi uang darurat untuk jajan di kios pun terjaga sampai akhir. Kantong kecil tapi cermat menjaga isi."},"ICON-2275":{"nm":"Tali Gulung Handuk","de":"Gulung handuk, ikat dengan satu tali, dan ia langsung tersampir di tali tas. Kedua tangan bebas, handuk di bahu. Rahasia bermain air dengan bawaan ringan tersembunyi di gulungan kecil ini."},"ICON-2276":{"nm":"Tutup Gantungan Kunci Gelang Anti Air","de":"Tombol penutup pada gelang yang menjaga kunci dari air. Hanya setelah tutup berbunyi klik tertutup, barulah kau lompat ke kolam dengan tenang. Titik kecil namun tanpa celah yang bertanggung jawab atas penutupan kunci."},"ICON-2277":{"nm":"Sumbat Mulut Snorkel","de":"Gigit dan jalan napas pun terbuka, pemandangan bawah laut mendekat tepat di depan mata. Sumbat kecil yang membuatmu tetap bisa bernapas bahkan di bawah air. Siapa sangka meminjamkan napas bisa sedebar ini."},"ICON-2278":{"nm":"Bantalan Anti-Kabut Masker Selam","de":"Ketika bagian dalam masker mengabut, tur bawah air pun ikut buyar. Satu lembar bantalan menahan kabut itu, jadi pandangan yang jernih adalah jasa satu lapisan tak terlihat ini."},"ICON-2279":{"nm":"Klip Pengencang Ujung Kaki Katak","de":"Ia mengencangkan ujung kaki katak agar pas di kaki, sehingga menendang air tanpa kendur sedikit pun. Agar tenaga dalam satu tendangan tak bocor sia-sia, klip ini diam-diam mengikat simpul rapi di ujung kaki."},"ICON-2280":{"nm":"Pelindung Tali Masker Selam","de":"Ia lembut membungkus tali masker agar tak menarik rambut. Satu lapis perhatian yang menghapus momen perih setiap kali dilepas. Yang dijaga oleh pelindung kecil ini, ternyata, adalah kelembutan hati."},"ICON-2281":{"nm":"Tutup Katup Pembuang Air Snorkel","de":"Bahkan dalam tindakan menahan napas, ada celah yang diam-diam bocor. Satu katup kecil lembut mengalihkan aliran air itu kembali keluar, dan menjaga ruang untuk menghirup napas sampai akhir. Laut mengingat kesungguhan sekecil ini dengan penuh terima kasih."},"ICON-2282":{"nm":"Pengait Penyimpan Kaki Katak","de":"Saat kaki katak tergantung rapi di satu pengait yang tertanam di dinding, ketenangan pun turun bahkan di ruang peralatan yang tadinya berantakan. Menaruh sesuatu pada tempatnya adalah janji paling diam menuju penyelaman berikutnya."},"ICON-2283":{"nm":"Bantalan Kantong Hidung Masker Selam","de":"Sepotong bantalan yang lembut menekan hidung. Berkat kelembutan kecil ini yang menghalangi air masuk, wajah tetap mempertahankan ekspresinya bahkan di laut yang dingin."},"ICON-2284":{"nm":"Pelindung Ujung Atas Snorkel","de":"Pelindung yang membungkus bulat ujung snorkel diam-diam mendorong balik air saat ombak melintas. Semakin tak terlihat kerja sebuah bagian, semakin dalam ia menopang keselamatan satu tarikan napas."},"ICON-2285":{"nm":"Strip Anti-Selip Sol Kaki Katak","de":"Strip tipis yang menempel di sol kaki katak. Satu garis gesekan yang dipegang erat ujung kaki agar tak tergelincir di dek basah. Keselamatan selalu bermula diam-diam dari tekstur sekecil ini."},"ICON-2286":{"nm":"Tutup Katup Tabung Oksigen","de":"Tutup yang menutupi katup tabung yang penuh berisi udara. Agar debu tak menempel, agar jalur napas tak kotor. Menutup adalah cara merawat lebih dulu, hingga ke napas pertama orang berikutnya."},"ICON-2287":{"nm":"Tutup Mouthpiece Regulator","de":"Bagian yang menyentuh bibir harus selalu paling bersih. Satu lembar tutup ini yang dipasang pada mouthpiece, tanpa suara menjaga gerbang napas dari angin asin dan pasir."},"ICON-2288":{"nm":"Pengait Tarik Ritsleting Wetsuit","de":"Pengait tarik pendek yang dipasang pada ritsleting wetsuit. Perhatian yang disematkan agar tangan yang membeku oleh air dingin pun bisa menariknya sekali tarik. Bahkan mengancingkan pakaian menyimpan pikiran seseorang."},"ICON-2289":{"nm":"Tutup Pelindung Pengukur Udara","de":"Tutup pelindung yang membungkus kaca alat pengukur sisa udara. Sebab angka-angka itu tak boleh sampai buram. Semakin sebuah skala membaca kehidupan itu sendiri, semakin cermat ia dilap bersih dan ditutup."},"ICON-2290":{"nm":"Gesper Sabuk Pemberat","de":"Orang-orang melilitkan beban di pinggang untuk turun ke kedalaman. Pada sekejap saat satu gesper terbuka dan terkunci, pilihan antara naik dan tenggelam berkumpul diam-diam di ujung jari."},"ICON-2291":{"nm":"Tali Pergelangan Lentera Selam","de":"Di air yang gelap gulita, satu tali yang diikat di pergelangan tangan menahan erat lentera. Lepaskan tangan pun cahaya tetap mengikuti. Tak kehilangan satu cahaya kecil di tengah kegelapan, karena itulah terasa begitu menenangkan."},"ICON-2292":{"nm":"Klip Perapi Selang Napas","de":"Klip kecil yang mengumpulkan selang yang berserakan menjadi satu. Cegah kusut lebih dulu, dan tangan pun tak akan bingung bahkan di saat mendesak. Merapikan adalah kebaikan diam-diam untuk diri di masa depan."},"ICON-2293":{"nm":"Penguat Ujung Jari Sarung Tangan Selam","de":"Kain penguat yang dilapiskan di setiap ujung jari. Bagian yang menarik tali dan mencengkeram batu pasti paling cepat aus, jadi satu lapis tambahan dipasang untuk merangkul keausan itu lebih dulu."},"ICON-2294":{"nm":"Cincin Penopang Tabung Oksigen","de":"Satu cincin penopang yang menegakkan tabung berat. Ia merangkul bobot yang bisa saja terguling, memberikan keseimbangan dengan pelukan bulatnya. Menopang adalah hati yang meminjamkan sisinya agar sesuatu tak jatuh."},"ICON-2295":{"nm":"Tutup Sirip Papan Selancar","de":"Tutup yang membungkus ujung tajam sirip di bawah papan. Agar tak terluka saat berjalan di pasir, ujung tajam yang membelah ombak itu diistirahatkan sejenak. Selama beristirahat, siapa pun boleh menjadi tumpul."},"ICON-2296":{"nm":"Tutup Pelindung Ujung Bilah Dayung","de":"Tutup pelindung yang menjaga ujung bilah dayung. Ia menghalangi goresan akibat batu agar tak mengacaukan aliran air. Jaga baik ujungnya, dan satu kayuhan membawa lebih jauh."},"ICON-2297":{"nm":"Pegangan Dayung Kayak","de":"Pegangan yang dililitkan di tempat telapak tangan bertemu dayung. Ia lembut menopang bagian yang dulu melepuh, agar tangan tak sampai membenci dayung bahkan saat mendayung melawan arus sungai."},"ICON-2298":{"nm":"Kaleng Penyimpan Wax Selancar","de":"Kaleng kecil yang menyimpan sepotong wax. Sihir yang merekatkan kaki ke papan selalu diambil dari kotak seukuran telapak tangan ini. Persiapan hari ini dimulai dari satu kaleng rapi ini."},"ICON-2299":{"nm":"Cincin Pengencang Pergelangan Kaki Leash","de":"Cincin yang mengencangkan tali leash penghubung pergelangan kaki dan papan. Satu simpul yang bersumpah tak akan melepaskanmu bahkan saat terseret ombak besar. Sambungan adalah janji untuk menahan agar tak hanyut terlalu jauh."},"ICON-2300":{"nm":"Sumbat Udara Papan Dayung","de":"Papan yang mengeras saat terisi angin, dan sumbat yang mengunci napas itu. Buka dan ia terlipat rata, tutup dan ia berdiri di atas air. Satu sumbat kecil menyimpan sehari yang mengembang dan mengempis."},"ICON-2301":{"nm":"Tali Bantalan Kursi Kayak","de":"Tali yang mengikat bantalan pada kursi. Demi punggung dan pinggang yang lama duduk mendayung, ia menahan empuknya bantal agar tak melorot dari tempatnya. Bahkan kenyamanan pun butuh simpul yang kukuh."},"ICON-2302":{"nm":"Bemper Ujung Papan Selancar","de":"Bemper yang membungkus haluan papan. Ia adalah lapisan tambahan di ujung yang paling sering bertumbukan, agar bagian itulah yang lebih dulu menumpul. Menaruh kelembutan di posisi terdepan adalah janji untuk memakainya lama-lama."},"ICON-2303":{"nm":"Gesper Penutup Tas Anti Air","de":"Gesper yang dilipat dan dikancingkan dua, tiga kali agar tak setetes air pun masuk. Menjaga sesuatu yang berharga tetap kering selalu butuh satu sentuhan tangan lagi. Satu kancingan yang kukuh itulah yang menjadi rasa tenang."},"ICON-2304":{"nm":"Potongan Jaring Gawang Futsal","de":"Sepotong jaring yang dulu bergetar di gawang. Ia mengingat, seutas demi seutas, sorak-sorai saat bola mengisinya. Di setiap simpul tersimpan satu gol, dan di setiap bagian yang aus, pertandingan hari itu masih hidup."},"ICON-2305":{"nm":"Nosel Pompa Bola Sepak","de":"Nosel pompa yang meniupkan napas ke bola yang kempis. Kulit yang tadinya lesu menggelinding kini memantul riang kembali. Mengisi angin adalah cara membangkitkan permainan yang sempat terhenti."},"ICON-2306":{"nm":"Alas Bendera Sudut","de":"Alas yang menegakkan bendera di sudut lapangan. Ia hanya penanda kecil sebuah batas, namun berkat satu titik itu tanah berdebu akhirnya mengambil bentuk sebuah lapangan pertandingan."},"ICON-2307":{"nm":"Tali Pelindung Tulang Kering","de":"Tali yang mengikat pelindung tulang kering pada betis. Ia mengukuhkan tempat yang sering berbenturan, agar setiap langkah tak gentar bahkan di tengah benturan badan yang kasar."},"ICON-2308":{"nm":"Pin Pengganti Pul Sepatu","de":"Pin untuk menukar pul yang sudah aus dengan yang baru. Gigi-gigi kecil di ujung sepatu yang mencengkeram rumput. Agar tak tergelincir, kadang yang perlu dibangun ulang justru pijakan paling dasar."},"ICON-2309":{"nm":"Tutup Katup Bola Sepak","de":"Tutup katup kecil yang menyumbat lubang napas bola. Ia menjaga pintu masuk agar udara yang sudah diisi tak bocor keluar. Menjaga kekencangan itu mirip dengan tidak kehilangan ketegangan hingga pertandingan berikutnya."},"ICON-2310":{"nm":"Kerucut Penanda Garis","de":"Kerucut yang menggambar garis di tanah untuk membagi jalan. Sampai sini wilayah kita, dari situ wilayah lawan. Satu kerucut kecil mengubah tanah kosong yang semrawut menjadi arena bermain yang berperaturan."},"ICON-2311":{"nm":"Sikat Debu Sepatu Futsal","de":"Sikat yang menyapu debu tanah yang terselip di sela sepatu futsal. Ketika pertandingan usai, sepatu pun menyimpan debu satu hari penuh. Tangan yang menyikatnya adalah sapaan diam-diam untuk kaki yang telah berlari dengan baik."},"ICON-2312":{"nm":"Gantungan Sarung Tangan Kiper","de":"Gantungan tempat sarung tangan kiper dikeringkan. Di sinilah tangan yang basah keringat, sebanyak tendangan yang berhasil digagalkan, beristirahat sejenak. Demi pertandingan berikutnya, yang basah mengering dan hati yang tegang perlahan mengendur."},"ICON-2313":{"nm":"Kaitan Jaring Ring Basket","de":"Kaitan-kaitan kecil yang menggantungkan jaring pada ring. Berkat merekalah bola menimbulkan bunyi gemerisik lembut saat melewatinya. Suara skor yang begitu segar itu sesungguhnya bermula dari kaitan-kaitan kecil ini."},"ICON-2314":{"nm":"Alat Pengurang Angin Bola Basket","de":"Alat yang mengeluarkan sedikit angin dari bola yang terlalu keras. Jika terlalu kencang, pantulannya jadi liar. Mengurangi secukupnya, itulah kuncinya. Bola dengan sentuhan yang pas selalu lahir dari keseimbangan semacam itu."},"ICON-2315":{"nm":"Bantalan Sensor Papan Pantul","de":"Bantalan sensor yang tertempel di balik papan pantul. Ia membaca dengan jelas, dalam angka, saat-saat bola menyentuhnya. Bahkan momen yang luput dari mata pun diingat oleh indra kecil ini, sehingga keputusan wasit menjadi jauh lebih adil."},"ICON-2316":{"nm":"Kerucut Rintangan Dribel","de":"Kerucut-kerucut rintangan yang berbaris di jalur latihan dribel. Di sela-sela menghindar ke sana kemari itulah kelincahan kaki tumbuh. Menghalangi jalan juga merupakan kebaikan hati yang mengajarkan cara meloloskan diri dengan lebih baik."},"ICON-2317":{"nm":"Sikat Katup Bola Basket","de":"Sikat kecil yang membersihkan lubang katup bola. Jika debu menyumbatnya, jarum tak bisa masuk, maka pintu yang tak terlihat itulah yang dibersihkan lebih dulu. Sebelum mengisi, selalu ada aturan untuk mengosongkan dan membersihkan lebih dulu."},"ICON-2318":{"nm":"Gulungan Plester Jari","de":"Selembar plester untuk dililitkan pada jari. Ia mengukuhkan ruas yang terkilir, memberikan keberanian untuk memegang bola lagi. Membalut luka adalah pernyataan kecil bahwa aku tak akan berhenti."},"ICON-2319":{"nm":"Jepitan Nomor Punggung","de":"Jepitan yang mengaitkan nomor punggung pada seragam. Sebuah angka, menggantikan namamu, kini melintasi lapangan. Dalam satu jepitan kukuh agar tak terlepas itu, tertulis dengan jelas siapa yang bertanding hari ini."},"ICON-2320":{"nm":"Cincin Target Latihan Menembak","de":"Cincin target yang dipasang di dalam ring untuk mempersempit sasaran. Ia mengecilkan ruang masuk, melatihmu untuk menahan kegagalan. Melempar terus-menerus ke pintu sempit itu, tanpa sadar, membuat ujung jari belajar ketepatan."},"ICON-2321":{"nm":"Pengelap Sol Sepatu Basket","de":"Sebelum melangkah ke lapangan, kau berjongkok dan mengelap sol sepatu lebih dulu. Karena tak ingin meninggalkan setitik pun tergelincir di lantai kayu. Ketika langkah pertama dipijakkan dengan ujung kaki yang bersih, dirimu hari ini sedikit lebih kukuh dari kemarin."},"ICON-2322":{"nm":"Pengait Tegangan Net Voli","de":"Kekencangan tak terlihat oleh mata. Namun pada saat pengait menarik tali hingga berhenti di ujungnya, net membelah lapangan menjadi dua dengan ketegangan setinggi sejengkal. Keseimbangan yang dipegang tangan tak kasatmata inilah yang membangunkan pertandingan."},"ICON-2323":{"nm":"Klip Pengunci Antena","de":"Antena yang terus bergoyang tertiup angin kini berdiri tegak hanya dengan satu klip. Sesuatu yang kecil menahan goyangan yang besar. Tangan yang diam-diam mengencangkan satu kabel di balik panggung pun bergerak dengan hati yang sama besarnya."},"ICON-2324":{"nm":"Gantungan Rompi Libero","de":"Rompi berwarna berbeda milik spesialis bertahan tergantung di dinding, menunggu pertandingan berikutnya. Meski tak mencolok, itulah nama yang menopang seluruh lapangan: libero. Di tempat yang paling rendah itulah bersemayam mata yang memandang paling jauh."},"ICON-2325":{"nm":"Kantong Pelindung Lutut","de":"Semakin sering berguling di lantai, semakin sering pula lutut terbentur. Kantong kecil yang rapi menyimpan pelindung ini tahu benar: hanya mereka yang lebih dulu belajar cara jatuh dengan baik yang pada akhirnya mampu melompat paling jauh."},"ICON-2326":{"nm":"Alat Ukur Tekanan Bola Voli","de":"Sekadar mengetuk dengan ujung jari tak akan menjawabnya. Jarum pengukur bergetar halus dan menunjuk satu garis skala. Mengukur napas sebuah bola adalah kancing pertama sebuah pertandingan. Dari tekanan yang jujur, lahirlah lintasan yang jujur pula."},"ICON-2327":{"nm":"Selotip Garis Bola Bakar","de":"Sebuah lingkaran yang digambar dengan selotip di tanah berdebu lapangan. Bagian dalam dan luarnya membelah semesta kejar-kejaran selama setengah hari. Tangan yang menggoreskan garis itu tahu, aturan adalah awal mula sebuah permainan."},"ICON-2328":{"nm":"Dudukan Peluit Wasit","de":"Ketika bunyi peluit yang tajam berhenti, ia kembali diletakkan diam-diam di tempatnya di atas dudukan ini. Inilah tempat yang paling dekat mendengar embusan napas wasit. Keadilan selalu bermula dari hal kecil: menjaga tempatnya sendiri."},"ICON-2329":{"nm":"Target Dinding Latihan Toss","de":"Di subuh tanpa seorang pun yang menerima bola, ribuan kali ujung jari melambungkannya ke arah target yang menempel di dinding. Dinding adalah rekan yang paling murah hati. Bola yang memantul kembali membangunkan diriku yang letih."},"ICON-2330":{"nm":"Tongkat Pengukur Tinggi Net","de":"Sekalipun net rendah hanya seukuran satu jari, pertandingan akan meleset. Pada saat tongkat pengukur ini diangkat, keadilan bukan lagi sekadar angka, melainkan kebiasaan yang dijalani setiap hari. Ketepatan yang tak terlihat inilah yang menjaga lapangan."},"ICON-2331":{"nm":"Pin Sudut Balok Start","de":"Dalam posisi merunduk, sudut tempat ujung kaki menyentuh, satu derajat itu saja yang menentukan start. Dengan satu pin, balok dikunci sambil menenangkan napas. Sikap saat memulai diam-diam mengikutimu hingga garis akhir."},"ICON-2332":{"nm":"Bendera Nomor Lintasan","de":"Bendera kecil yang tertancap di setiap lintasan mengibarkan nomornya tertiup angin. Semua berlari ke arah yang sama, namun masing-masing punya jalannya sendiri. Trek merangkul kesejajaran dan perbedaan sekaligus."},"ICON-2333":{"nm":"Penutup Ujung Tongkat Estafet","de":"Demi saat ia akan menyentuh tangan pelari terakhir, penutup ujung ini membulatkan setiap sudutnya. Dalam lari estafet, yang paling berharga bukanlah kecepatan, melainkan tangan yang menyerahkannya kepada orang berikutnya."},"ICON-2334":{"nm":"Gantungan Pita Ukur Rekor","de":"Pita ukur yang mencatat rekor digantung di dinding agar tak kusut. Di sinilah jarak kemarin dan jarak hari ini tergantung berdampingan. Pertumbuhan selalu datang lebih dulu dalam wujud selisih angka yang kecil."},"ICON-2335":{"nm":"Kerucut Penanda Tikungan","de":"Kerucut kecil yang diletakkan di sisi dalam tikungan menunjukkan maksud sang jalur. Jangan terlalu menukik ke dalam, jangan pula melebar ke luar. Mereka yang pandai menikung, pada akhirnya, memimpin paling depan."},"ICON-2336":{"nm":"Klip Pita Garis Finis","de":"Pita yang akan pertama kali menyentuh dada seseorang itu ditahan klip dengan kencang, menunggu. Seutas tali yang ada demi terputus. Ia menahan tiupan angin sepanjang hari, demi satu detik milik seseorang."},"ICON-2337":{"nm":"Penutup Pistol Start","de":"Sampai bunyi tanda \"dor\" itu meletus, moncong pistol tertidur di balik penutupnya. Sebuah wadah suara yang menyimpan momen keberangkatan. Semakin dalam keheningannya, semakin jauh pula gema tembakan pertama menyebar."},"ICON-2338":{"nm":"Pin Penyetel Tinggi Gawang","de":"Setiap kali ketinggian yang harus dilompati dinaikkan satu tingkat, posisi pin pun ikut berubah. Rasa takut pun tumbuh sebesar itu juga. Namun kaki tetap berlari maju, mengukur-ukur tempat yang sedikit lebih tinggi setiap kalinya."},"ICON-2339":{"nm":"Roda Penghitung Putaran","de":"Ketika bingung berapa putaran yang tersisa, roda ini diputar satu tingkat. Bunyi kecil angka yang berkurang menyalurkan kembali tenaga ke kaki. Tangan yang menghitung jarak tersisa itulah yang menjaga tempo."},"ICON-2340":{"nm":"Penyangga Simpan Galah","de":"Galah yang panjang dan lentur butuh tempat tersendiri untuk bersandar. Karena ia adalah alat yang harus melengkung untuk bisa melesat, ia ditegakkan dengan lebih hati-hati. Kelenturan yang tersimpan baik menyimpan lompatan yang paling tinggi."},"ICON-2341":{"nm":"Garu Perata Bak Pasir","de":"Jejak kaki yang ditinggalkan atlet sebelumnya diratakan perlahan dengan garu. Bak pasir kembali rata seperti pertama kali, setiap kali. Di sana, diam-diam, ada tangan yang menghapus jejak demi lompatan seseorang."},"ICON-2342":{"nm":"Pita Penanda Jarak Awalan","de":"Kurang satu langkah pun tak boleh, lebih satu langkah pun tak boleh. Pita penanda jarak di tanah dengan jujur menunjukkan tempat untuk menghentak kaki. Awalan yang baik bukan lahir dari ambisi yang membabi buta, melainkan dari perhitungan yang tenang."},"ICON-2343":{"nm":"Pegangan Cakram","de":"Jika jari tergelincir, lemparan sudah terlepas bahkan sebelum benar-benar dilempar. Tekstur kasar pegangan yang membungkus cakram itulah yang mengendalikan putarannya. Ketepatan waktu melepas selalu bermula dari kepekaan saat menggenggam."},"ICON-2344":{"nm":"Cincin Alas Peluru Tolak","de":"Cincin alas ini diam-diam mendekap bola besi yang berat agar tak menggelinding. Sebuah sarang kecil yang menjaga keheningan tepat sebelum lemparan. Semakin meledak tenaga yang akan dilepaskan, semakin kukuh pula tempat ia bersandar."},"ICON-2345":{"nm":"Tutup Pelindung Ujung Lembing","de":"Tutup yang disematkan pada ujung lembing yang tajam menyelimutinya dengan keheningan yang lembut. Ketika alat yang akan terbang jauh itu berbaring diam, bahaya dikendalikan oleh kepedulian. Keselamatan pun hidup bahkan di dalam penyimpanan."},"ICON-2346":{"nm":"Pengait Penyangga Mistar Lompat Tinggi","de":"Agar mistar tidak jatuh meski tersentuh sedikit, pengait ini menopangnya dengan keseimbangan yang begitu pas. Inilah tempat yang bertanggung jawab atas batas getar antara berhasil dan gagal melewatinya. Keadilan bersemayam dalam detail sekecil ini."},"ICON-2347":{"nm":"Pengunci Sudut Matras Pendaratan","de":"Jika sudut matras pendaratan terangkat, seseorang bisa terluka. Pengunci ini menekan keempat sudutnya dengan kukuh. Agar tubuh yang melompat paling tinggi mendarat dengan paling aman, ia menopangnya tanpa terlihat."},"ICON-2348":{"nm":"Selotip Batas Lingkaran Lempar","de":"Batas tempat melempar digambar dengan satu garis selotip. Terinjak atau tidaknya garis itu menentukan hidup matinya sebuah rekor. Sebuah janji berupa satu garis tipis, tempat kebebasan dan aturan bertemu."},"ICON-2349":{"nm":"Kaki Karet Balok Keseimbangan","de":"Agar balok keseimbangan yang sempit tak bergoyang, kaki karet ini mencengkeram lantai erat-erat. Keseimbangan tanpa gemetar yang akan terbentang di atasnya sesungguhnya diciptakan oleh kekukuhan tak terlihat di bawahnya."},"ICON-2350":{"nm":"Pembalut Pegangan Palang Tunggal","de":"Agar telapak tangan tak tergelincir, pembalut ini dililitkan pada pegangan palang tunggal. Rahasia putaran yang berputar-putar bukan terletak pada kemegahan, melainkan pada genggaman tangan yang erat. Keringat yang menetes ke matras tahu itu."},"ICON-2351":{"nm":"Pengunci Tinggi Tali Gelang","de":"Sekalipun ketinggian kedua tali hanya berselisih selebar telapak tangan, gerakan akan runtuh. Pengunci ini diam-diam menjaga keseimbangan tersebut. Hanya di atas ketinggian yang tepat itulah penerbangan yang bebas benar-benar dimulai."},"ICON-2352":{"nm":"Penutup Pegangan Kuda-Kuda Pelana","de":"Penutup yang membungkus pegangan mencegah lepuh di telapak tangan. Di balik gerakan yang berputar-putar itu, ada tangan yang terluka dan sembuh berkali-kali tanpa henti. Perlindungan adalah janji lembut menuju latihan berikutnya."},"ICON-2353":{"nm":"Pin Pengatur Jarak Palang Bertingkat","de":"Jarak antara kedua palang disetel dengan tepat menggunakan pin ini. Ruang kosong tempat tubuh akan berpindah itulah yang menjadi panggung. Ujung jari lebih dulu tahu bahwa di atas jarak yang tepat, lahirlah lompatan yang paling berani."},"ICON-2354":{"nm":"Tutup Pegas Papan Loncat Kuda Lompat","de":"Pada saat menghentak papan, pegas mendorong tubuh ke langit. Tutup ini membungkus tenaga pantulan itu dengan rapi. Awalan yang paling singkat menciptakan melayang di udara yang paling panjang."},"ICON-2355":{"nm":"Kantong Bubuk Magnesium","de":"Bubuk putih yang menempel di tangan adalah jimat kecil yang menghapus rasa licin. Ritual singkat memasukkan lalu mengeluarkan tangan dari kantong ini meredakan rasa takut. Ketegangan pun, pada akhirnya, dikendalikan dari ujung jari."},"ICON-2356":{"nm":"Pembalut Pergelangan Tangan Senam","de":"Sembari melilitkan pembalut pada pergelangan tangan, tali hati pun ikut dikencangkan. Menahan lebih dulu sendi yang akan bergoyang. Satu pergelangan tangan yang terikat dengan baik diam-diam mengizinkan putaran yang lebih berani."},"ICON-2357":{"nm":"Tali Pengaman Trapeze","de":"Tepat sebelum melemparkan tubuh ke udara, tali pengaman ini menjelma tangan tak kasatmata. Hanya ketika kekhawatiran akan jatuh lenyap, seseorang bisa terbang paling jauh. Kepercayaan itulah yang menyempurnakan penerbangan."},"ICON-2358":{"nm":"Tutup Kaleng Bola Tenis","de":"Di balik tutup yang menyumbat mulut kaleng, bola-bola baru tertidur sambil menyimpan tekanannya. Bunyi \"pop\" kecil saat kaleng dibuka membangunkan debaran menjelang pertandingan. Segel adalah janji yang menjaga kesegarannya."},"ICON-2359":{"nm":"Penjepit Tegangan Senar Raket","de":"Penjepit ini menggigit kekencangan senar dengan kukuh dan tak melepaskannya hingga akhir. Sebab tegangan satu senar itulah yang menentukan pantulan bola. Sentuhan tak kasatmata itu bermula dari penjepit kecil ini."},"ICON-2360":{"nm":"Sapu Garis Lapangan Tenis","de":"Ketika pertandingan usai, garis putih lapangan disapu perlahan mengikuti alurnya. Setelah debu tersingkir, garis itu kembali tegas. Membersihkan jalan demi pertandingan berikutnya, ketelitian terakhir inilah yang menghidupkan lapangan."},"ICON-2361":{"nm":"Selotip Pelindung Kepala Raket","de":"Lilitkan satu putaran pada bingkai raket, dan benturan sekasar apa pun akan diterima dengan lembut. Aku tahu, sisi terluarlah yang paling dulu aus. Karena menanggung keausan itu adalah tugasku, hari ini pun aku berdiri di posisi paling luar."},"ICON-2362":{"nm":"Cip Suhu Udara Ruangan","de":"Angin dingin subuh yang menerobos saat pintu terbuka, dibaca oleh cip sebesar telapak tangan ini lebih dulu daripada manusia. Menyadarinya bahkan sebelum ujung hidung terasa dingin—itulah sapaan paling sunyi yang membuka hari di gedung olahraga yang kosong."},"ICON-2363":{"nm":"Pijakan Garis Dasar","de":"Bagi atlet yang ragu meletakkan ujung kaki, satu garis di tanah sudah cukup. Garis yang tak boleh dilewati itu justru menjadi garis start bagi lompatan paling jauh, begitulah pijakan ini berbisik tanpa kata."},"ICON-2364":{"nm":"Gantungan Keranjang Bola Tenis","de":"Menampung puluhan bola sekaligus tanpa menjatuhkan satu pun. Mengumpulkan yang berserakan di lapangan dan menyerahkannya untuk latihan berikutnya—tangan yang sibuk diam-diam di pojokan itu, hari ini pun tergantung di sini."},"ICON-2365":{"nm":"Tutup Ujung Pegangan Raket","de":"Begitu dipasang di ujung pegangan, barulah raket benar-benar merapat ke telapak tangan. Satu tutup kecil ini memisahkan antara tergelincir dan rasa tenang. Hanya dengan menutup ujungnya dengan rapi, ayunan pertama menjadi kukuh."},"ICON-2366":{"nm":"Jepitan Handuk Pinggir Lapangan","de":"Meski angin bertiup kencang, ia bertahan dengan mulut terkatup rapat di pinggir lapangan agar handuk yang sudah diperas dengan susah payah tak terbang. Bahkan dalam menjaga sesaat waktu menarik napas ini, tersentuh ujung jari seseorang yang teliti."},"ICON-2367":{"nm":"Penjepit Perata Bulu Kok","de":"Satu bulu saja yang kusut, penerbangan pun terguncang. Meluruskan sayap yang meringkuk dengan hati-hati, kok kembali bersiap untuk terbang lurus. Perjalanan jauh selalu bermula dari rapian sekecil ini."},"ICON-2368":{"nm":"Tutup Tabung Kok","de":"Agar kok-kok yang tersusun berbaris tak melunak, ujung tabung disumbat dengan kukuh. Sudah lama diperhatikan, setitik kelembapan saja membuat bulu kok layu. Menyimpan dengan baik pun, sesungguhnya, sudah menjadi bagian dari pertandingan."},"ICON-2369":{"nm":"Alas Gulir Bola Pingpong","de":"Bola kecil yang menggelinding perlahan menarik napas sejenak di atasku. Menopangnya diam-diam agar tak jatuh menggelinding pergi—inilah kepedulian berbentuk paling bulat yang dihaturkan di samping meja pingpong."},"ICON-2370":{"nm":"Roller Karet Raket Tenis Meja","de":"Menggulirkan roller dengan tenang di atas permukaan karet mengangkat debu lama dan menghidupkan kembali daya lengketnya. Putaran harus hidup agar bola membelok. Kondisi raket hari ini terjaga oleh satu sentuhan perawatan penuh kasih ini."},"ICON-2371":{"nm":"Tongkat Pengukur Tinggi Net","de":"Sekalipun net hanya lebih tinggi sejengkal, corak pertandingan berubah. Orang-orang yang pada akhirnya tak mau percaya perkiraan mata membawaku mendekat. Keadilan, rupanya, baru datang dari tinggi yang diukur teliti dengan alat ukur seperti ini."},"ICON-2372":{"nm":"Cip Pengukur Kecepatan Kok","de":"Kecepatan kok yang membelah udara, kuhitung diam-diam. Ketika kecepatan yang tadinya tak terlihat mengendap menjadi angka yang jelas, kata-kata berikutnya dari pelatih menjadi jauh lebih tegas. Ini adalah pekerjaan mengubah firasat menjadi fakta."},"ICON-2373":{"nm":"Kapsul Simpan Bola Pingpong","de":"Membaringkan satu bola bulat dengan lembut ke dalam kapsul membuat goresan dan debu menjauh. Berharap ia baik-baik saja hingga pertandingan berikutnya, inilah hati yang merelakan satu ruang kecil secara utuh untuknya."},"ICON-2374":{"nm":"Gantungan Senar Raket Bulu Tangkis","de":"Menggantungkan senar-senar yang kendur secara rapi membuat tangan berikutnya tak kebingungan. Merapikan, pada akhirnya, seperti catatan penuh kasih yang ditulis lebih dulu untuk diriku esok hari. Hari ini meringankan hari esok."},"ICON-2375":{"nm":"Selotip Pelindung Tepi Raket Tenis Meja","de":"Tepi tempat karet mudah terangkat, kudekap diam-diam dengan satu garis lilitan. Sebab jika ujungnya terbuka, bahkan gerak bola pun akan kacau. Menjaga tepi ini, pada akhirnya, sama dengan menjaga satu poin."},"ICON-2376":{"nm":"Kantong Penghangat Bola Squash","de":"Bola yang dingin nyaris tak memantul. Sebelum pertandingan, kantong ini menghangatkannya dan mendekapnya sehangat telapak tangan. Kehangatan kecil yang tersalur ke tangan itulah yang menentukan napas dan ritme satu ronde lebih dulu."},"ICON-2377":{"nm":"Penjepit Jaring Lacrosse","de":"Ketika satu simpul jaring hendak mengendur diam-diam, aku menggigit dan menahan simpul itu tanpa sepatah kata pun. Jaring harus kukuh agar bola bisa bertahan. Di sini, di tempat yang tak terlihat, ada tangan yang menahan seluruh pertandingan."},"ICON-2378":{"nm":"Selotip Pelindung Ujung Raket Squash","de":"Semakin keras diayunkan ke arah dinding, semakin dulu pula ujung raket menangis. Bungkus diam-diam ujung yang menangis itu, dan ia akan bermain bersamamu satu musim lagi. Orang yang tahu cara menyayangi ujungnya, pada akhirnya, memegang raket itu paling lama."},"ICON-2379":{"nm":"Sarung Bilah Tongkat Hoki","de":"Menyematkan sarung ke atas bilah yang tajam barulah membuat isi tas dan ujung jari sama-sama lega. Menidurkan diam-diam sesuatu yang berbahaya—inilah tata krama lama yang pertama kali disiapkan saat mengemas tongkat."},"ICON-2380":{"nm":"Kain Pengkilap Bola Kriket","de":"Menggosok bola merah dengan kain membuat satu sisinya menyimpan cahaya seperti cermin. Pelempar tahu, lewat kepekaan ujung jarinya, bahwa bola membelok hanya jika kilaunya hidup. Bahkan dalam menggosok dengan penuh perhatian, tersimpan strategi yang diam-diam."},"ICON-2381":{"nm":"Tutup Tabung Bola Lacrosse","de":"Agar bola-bola keras tak menggelinding pergi sesuka hati, mulut tabung disumbat dengan rapi. Mengumpulkan hal-hal yang mudah berserakan ke satu tempat—dasar dari pengelolaan yang baik selalu sesederhana ini."},"ICON-2382":{"nm":"Keping Target Dinding Squash","de":"Satu target kecil yang tertanam di dinding mengumpulkan mata atlet yang gelisah menjadi satu titik. Satu titik yang menentukan ke mana harus membidik—dinding yang begitu luas pun menyempit menjadi sasaran yang jelas di hadapan keping ini."},"ICON-2383":{"nm":"Sarung Pegangan Tongkat Hoki","de":"Memindahkan pegangan yang sudah akrab di tangan ke tongkat baru yang asing membuat alat itu seketika menjadi milikku. Sarung kecil yang mengalihkan keakraban apa adanya—inilah jalan pintas menuju penyesuaian diri."},"ICON-2384":{"nm":"Gantungan Jaring Gawang Lapangan","de":"Baru setelah jaring tergantung di gawang, sebuah gol benar-benar terasa seperti gol. Yang selalu menahan hingga akhir saat singkat bola mengisi penuh itu adalah jaring. Di tempat yang menampung wujud sorak-sorai yang meledak, di situlah aku berada."},"ICON-2385":{"nm":"Sarung Bilah Sepatu Es","de":"Dengan bilah yang masih terbuka, tak satu langkah pun bisa dirasa aman di luar arena es. Jika sudah meninggalkan es, kenakanlah aku, kumohon. Menidurkan ketajaman diam-diam pun merupakan tata krama yang lama dijaga oleh para pemain seluncur es."},"ICON-2386":{"nm":"Gantungan Tali Sepatu Es","de":"Tali panjang sepatu bot yang dilepas digantung rapi, seutas demi seutas. Tali yang dilepas agar tak kusut membuka lembaran es berikutnya dengan mulus. Penutup hari ini, apa adanya, menjadi persiapan untuk esok."},"ICON-2387":{"nm":"Kain Lap Bilah Sepatu Es","de":"Pada bilah yang baru saja meninggalkan es, titik-titik air kecil mengembun. Mengusap kelembapan itu dengan lembut membuat karat berlalu tanpa singgah. Mengumpulkan diam-diam jejak yang ditinggalkan hawa dingin, itulah hariku."},"ICON-2388":{"nm":"Bantalan Pergelangan Kaki Sepatu Es","de":"Sekali pergelangan kaki bergoyang, seluruh luncuran akan runtuh. Bantalan ini mendekap erat dan menahan pijakan. Keseimbangan yang anggun di atas es itu selalu bermula lebih dulu dari tempat yang tak terlihat."},"ICON-2389":{"nm":"Kantong Pelindung Bilah Sepatu Es","de":"Ada kantong kecil di sudut tas untuk menyimpan pelindung bilah dengan rapi. Kebiasaan mengemas semua yang perlu tanpa melewatkan satu pun menjaga peralatan tetap hidup lama. Tas yang rapi adalah adegan pertama dari luncuran yang baik."},"ICON-2390":{"nm":"Penjepit Sol Dalam Sepatu Es","de":"Agar sol dalam di sepatu bot tak diam-diam bergeser, ia menahannya erat di bawah kaki. Jika tempat pijakan meleset, lompatan pun ikut meleset. Tangan yang menahan tempat paling rendah, pada akhirnya, membantu lompatan yang paling tinggi."},"ICON-2391":{"nm":"Gesper Sarung Bilah Sepatu Es","de":"Agar sarung tak diam-diam melorot, gesper ini mengunci dan mengencangkannya dengan kukuh. Aku tahu, perlindungan yang longgar pada akhirnya bukanlah perlindungan sama sekali. Satu gesper yang terkunci baik menjaga bilah itu hingga akhir."},"ICON-2392":{"nm":"Tutup Pengunci Tali Sepatu Es","de":"Menarik tali sekuat tenaga lalu menguncinya dengan tutup ini membuatnya tak akan pernah lagi terurai. Mengencangkan tanpa celah dari ujung kaki—inilah simpul yang paling kukuh diikatkan sebelum langkah pertama dipijakkan di atas es."},"ICON-2393":{"nm":"Kain Pengering Bilah Sepatu Es","de":"Dari bilah yang baru selesai meluncur sekali, kelembapan yang mengembun dikumpulkan diam-diam. Kutahu, bilah yang dibiarkan basah akan menangis. Hanya bilah yang kering dan lembut mampu menggoreskan lengkungan berikutnya dengan jelas di atas es."},"ICON-2394":{"nm":"Tutup Pegangan Tongkat Ski","de":"Membungkus ujung pegangan tongkat dengan lembut membuat telapak tangan yang menggenggam jauh lebih nyaman. Tenaga yang membelah padang salju, pada akhirnya, lahir dari tempat yang digenggam erat itu. Satu tutup kecil menopang seluncuran panjang hingga akhir."},"ICON-2395":{"nm":"Pin Pengikat Snowboard","de":"Pada saat pin kecil yang menyambungkan papan dan kaki terlepas, gunung di hadapan mata pun berhenti. Sebuah bagian yang harus diperiksa pertama kali meski sulit terlihat—sambungan yang kukuh inilah yang menjadi kebebasan di atas padang salju."},"ICON-2396":{"nm":"Penjepit Pelindung Ujung Ski","de":"Agar sisi yang tajam tak menggores bagian dalam tas, penjepit ini menggigit dan menahan ujungnya diam-diam. Menenangkan ketajaman hingga tertidur—inilah penutup penuh kasih yang dihaturkan setelah menuruni gunung sekali jalan."},"ICON-2397":{"nm":"Pelindung Ujung Depan Snowboard","de":"Membungkus ujung depan papan secara penuh membuat benturan langsung dari depan sekalipun terurai dengan lembut. Menjaga diam-diam tempat yang paling dulu berbenturan—keberanian menghadapi turunan yang curam bermula tepat di sini."},"ICON-2398":{"nm":"Penutup Gesper Sepatu Ski","de":"Agar gesper tak rusak akibat berbenturan dengan salju yang dingin, ia ditutup diam-diam. Satu kunci lagi yang menjaga alat pengunci—satu penutup kecil ini diam-diam memperpanjang usia musim sepatu bot."},"ICON-2399":{"nm":"Tali Pengikat Snowboard","de":"Agar papan tak lari jauh meski terlepas dari tangan, aku menyambungkan pergelangan kaki dan papan dalam satu tali. Agar sekalipun terlepas, ia tak benar-benar hilang—inilah tali pengaman yang tenang, tergantung di ujung tali panjang."},"ICON-2400":{"nm":"Ujung Pengerok Alas Ski","de":"Lilin lama yang mengeras dan menempel di alas ski didorong bersih dengan satu geseran mulus. Yang lama harus disingkirkan tuntas agar luncuran baru bisa hidup. Alas yang dirawat dengan penuh perhatian membuka padang salju berikutnya jauh lebih cepat."},"ICON-2401":{"nm":"Bumper Ujung Papan Snowboard","de":"Sebelum papan membelah salju, ujung hidungnya lebih dulu menyentuh dunia. Setiap benturan selalu diterima lebih dulu oleh karet kecil ini. Posisi paling depan yang terus terkikis tanpa pernah menonjolkan diri—luncuran seseorang selalu meluncur di atas pengabdian tumpul ini."},"ICON-2402":{"nm":"Cincin Keranjang Tongkat Ski","de":"Tepat saat tongkat hampir tenggelam dalam salju tebal, lingkaran bundar ini meraba tanah sebagai gantinya. Lingkaran yang diam-diam menopang satu langkah yang nyaris tergelincir. Tak terlihat, ia tetap setia di sisi seperti tangan yang menjaga agar tak terpeleset."},"ICON-2403":{"nm":"Tutup Sikat Wax Tepi Papan","de":"Setelah perawatan selesai, ia menutup dengan lembut sebelum bubuknya mengering. Menyegel kelembutan hari ini agar tak satu pun serat berantakan. Agar saat dibuka lagi nanti, ketelitian kemarin masih menunggu persis seperti semula."},"ICON-2404":{"nm":"Gantungan Penutup Telinga","de":"Ingatkah kau? Penutup telinga yang sempat terlupakan di samping tas begitu musim semi tiba. Namun di malam ketika kabar salju pertama terdengar, ia yang pertama dipanggil. Ada tempat khusus untuk menggantung musim, dan kaitan kecil ini tak pernah lupa akan janji itu."},"ICON-2405":{"nm":"Wadah Batu Asah","de":"Untuk mengasah pisau, batu harus dibasahi lebih dulu—urutan yang meresap seperti sentuhan tangan nenek. Bahkan alat penakluk ketumpulan pun butuh tempat beristirahat, maka rumah kecil ini mendekap batu asah dan menanti perawatan berikutnya."},"ICON-2406":{"nm":"Kantong Balok Wax","de":"Bahan yang menciptakan luncuran gemilang justru tidur terbungkus rapat di dalamnya. Kepadatan yang mendekap gumpalan keras. Luncuran selalu terurai dari bobot yang tenang ini dan menyebar ke atas hamparan salju."},"ICON-2407":{"nm":"Kaitan Kantong Penghangat Tangan","de":"Di jalan-jalan musim dingin, tempat pertama yang diraba jari-jari di dalam saku. Ia memberi rumah tetap bagi kehangatan kecil yang mencairkan tangan beku. Semakin dingin hari, semakin lembut kaitan kecil ini menjadi."},"ICON-2408":{"nm":"Dudukan Batu Asah Ujung Bilah","de":"Jika goyah, bilah akan miring, maka ia lebih dulu mengunci tubuhnya sendiri erat-erat. Dudukan yang tak pernah bergeming, demi bertanggung jawab atas ketepatan orang lain. Ujung pisau lurus milik seseorang berdiri di atas ketenangan diam ini."},"ICON-2409":{"nm":"Jepitan Penghangat Leher","de":"Di jalan berangkat sekolah yang berangin dingin, saat penghangat leher hampir melorot—klik, terkait ke kerah. Bahkan kehangatan pun harus menjaga posisinya agar benar-benar menghangatkan. Satu bunyi kecil menahan kehangatan pagi tetap di tempatnya."},"ICON-2410":{"nm":"Penutup Setrika Wax","de":"Selagi permukaan yang bekerja panas itu mendingin, sehelai kain diam-diam melindunginya dari debu. Satu alat menjaga alat lain yang telah menyiapkan luncuran. Kepedulian terus berlanjut dengan tenang seperti ini."},"ICON-2411":{"nm":"Tutup Pena Minyak Bilah","de":"Sekali dibuka lalu mengering, garis berikutnya tak bisa digoreskan lagi. Maka menutup sama artinya dengan membuka yang berikutnya—tutup kecil ini menyegel kelembapan di ujung pena, menjanjikan satu goresan esok hari sejak sekarang."},"ICON-2412":{"nm":"Pangkal Pom-Pom Semangat","de":"Ratusan helai jumbai berawal dari satu titik ini, berhamburan serentak mengikuti ketukan. Kemegahan setiap goyangan selalu bermula dari tempat yang terikat erat. Di bawah panggung, ikatan pertama yang menggelombangkan penonton."},"ICON-2413":{"nm":"Tali Genggam Lightstick","de":"Setelah dua jam bersorak, tepat saat lightstick hampir terlepas, tali ini membawanya kembali ke tangan. Keinginan untuk tak kehilangan meski terjatuh. Kekhawatiran lembut itulah yang membentuk kaitan di pergelangan tangan."},"ICON-2414":{"nm":"Penjepit Lipat Bantal Penonton","de":"Berdiri lalu duduk berpuluh kali sambil bersorak. Di sela itu, penjepit kecil ini melipat bantal dengan rapi dan menjaga tempat duduk tetap terjaga. Bahkan di tengah penonton yang riuh, ada sentuhan yang menjaga tempat seseorang."},"ICON-2415":{"nm":"Kaitan Bandana Semangat","de":"Di hari ketika motif yang sama terbentang memenuhi seluruh tribun, sehelai kain mengikat puluhan ribu hati dalam satu warna. Titik pertama tempat gelombang itu bermula adalah kaitan kecil ini—tempat sorakan yang tadinya sendiri berubah menjadi kita."},"ICON-2416":{"nm":"Belahan Papan Tepuk Semangat","de":"Ditepuk sendirian, bunyinya kecil; berkumpul di tribun, ia menjadi gelombang. Satu belah yang paling jujur memahami kebenaran bahwa suara hanya berdenting saat bertemu yang lain. Saat tepukanmu bertemu tepukanku, sorakan pun membesar."},"ICON-2417":{"nm":"Tutup Sudut Papan Semangat","de":"Ia membungkus sudut tajam menjadi bundar, agar orang di sebelah tak terluka. Bahkan dalam hati yang berkobar mengibarkan papan, ada kepedulian yang terselip untuk sesama. Sorakan menjadi lebih hangat justru di titik yang membulat ini."},"ICON-2418":{"nm":"Wadah Tongkat Pita Semangat","de":"Bahkan saat kibaran berhenti, tongkat tetap berdiri tegak menanti sorakan berikutnya. Tempat berdiam sejenak agar bisa bergoyang lagi. Di antara satu sorakan dan sorakan lain, ada keheningan singkat tempat pita mengatur napas."},"ICON-2419":{"nm":"Kipas Pengeras Suara Semangat","de":"Agar teriakan satu orang mencapai ujung panggung, bentuk kipas ini mempersempit jalur suara. Mulut yang selalu memikirkan cara menyampaikan, lebih dari sekadar besar kecilnya hati. Bentuk yang lahir dari kerinduan untuk menjangkau lebih jauh."},"ICON-2420":{"nm":"Wadah Peniti Belakang Lencana","de":"Sebelum disematkan di dada dan sesudah dilepas, istirahat lencana bermula dan berakhir di sini. Rumah kecil yang menidurkan peniti tajam di baliknya dengan aman. Bahkan satu titik yang berkilau butuh tempat untuk berbaring sejenak."},"ICON-2421":{"nm":"Lempeng Angka Papan Skor","de":"Ia menyimpan ketelitian dari masa ketika setiap gol diganti dengan tangan. Sebelum era digital, hasil pertandingan diukir satu petak demi satu petak oleh ujung jari manusia. Lempeng tempat bahkan satu angka menyimpan debar hati seseorang."},"ICON-2422":{"nm":"Bidak Magnet Papan Taktik","de":"Mengikuti ujung jari pelatih, pertahanan dan serangan bertukar tempat. Setiap gambaran di kepala sebelum pertandingan lebih dulu tergambar dalam pergeseran titik-titik kecil ini. Hasil pertandingan dimainkan sekali lebih dulu di atas papan."},"ICON-2423":{"nm":"Tudung Silau Papan Skor","de":"Agar angka yang menyilaukan tak mengaburkan pandangan pemain, tudung ini memotong cahaya. Bahkan cahaya terang pun kadang perlu ditutupi secukupnya untuk menjalankan perannya. Di tempat paling terang, bayangan yang bekerja paling diam."},"ICON-2424":{"nm":"Cincin Pembalik Skor","de":"Setiap kali satu lembar berbalik, angka berubah dan sorakan ikut naik. Jejak era analog ketika catatan diperbarui lewat rasa di tangan. Masa ketika, seiring bunyi skor berbalik, jantung pun ikut berbalik."},"ICON-2425":{"nm":"Wadah Spidol Garis Taktik","de":"Setiap alur yang tergambar di papan tulis ruang ganti berasal dari pena ini. Wadah kecil nan kokoh yang mendekap sketsa dasar pertandingan. Di tengah keheningan sebelum laga penentuan, tempat yang menyimpan kata paling banyak."},"ICON-2426":{"nm":"Pengklik Penghitung Skor","de":"Setiap ditekan, satu petak naik dengan bunyi klik yang jernih. Serahkan angka pada jari, dan hati bisa sepenuhnya menghadap ke pertandingan. Ritme kecil yang meringankan beban menghitung."},"ICON-2427":{"nm":"Penutup Kabel Papan Skor","de":"Di balik cahaya yang gemerlap, selalu ada kabel-kabel kusut yang belum tertata. Pekerjaan menutup kekacauan itu dengan rapi. Hanya ketika tempat yang tak terlihat tertata rapi, tempat yang terlihat pun akhirnya bersinar."},"ICON-2428":{"nm":"Sikat Penghapus Papan Taktik","de":"Ketika satu babak usai, permukaan dikosongkan bersih untuk gambar berikutnya. Strategi baru hanya bisa dimulai di atas ruang yang kosong. Sikat penghapus ini sebenarnya adalah goresan pertama dari taktik berikutnya."},"ICON-2429":{"nm":"Jepitan Bendera Skor","de":"Ia menggigit erat bendera yang hampir terbang tertiup angin dan tak melepaskannya. Agar kain yang berkibar tetap di tempatnya. Bahkan pekerjaan mengumumkan catatan ke dunia butuh lebih dulu satu tangan yang memegang kukuh."},"ICON-2430":{"nm":"Jepitan Tali Peluit Wasit","de":"Dengan satu tiupan peluit, pertandingan berhenti lalu mengalir kembali. Simpul kecil yang mengikat kukuh otoritas itu ke leher. Sampai peluit berbunyi, mengikat keheningan dengan rapi pun menjadi tugas jepitan ini."},"ICON-2431":{"nm":"Gulungan Meteran","de":"Ia menarik kembali panjang yang telah diukur ke dalam dirinya sendiri. Mengukur, pada akhirnya, adalah pengulangan membentang lalu menggulung. Pegangan yang membantu perjalanan bolak-balik sederhana itu tanpa keluhan, berputar setiap kali di balik ketepatan."},"ICON-2432":{"nm":"Wadah Lipat Bendera Wasit","de":"Bendera yang tegas memisahkan dalam dan luar, begitu pertandingan usai, dilipat rapi dan beristirahat. Bahkan sinyal yang jelas itu pun mengatur napas sejenak untuk yang berikutnya. Di balik ketegasan pun ada istirahat yang tenang."},"ICON-2433":{"nm":"Kaitan Gantung Stopwatch","de":"Ia menggantung waktu yang mengalir di satu tempat, bukan di pergelangan tangan. Diam sebelum pengukuran, lalu berlari secepatnya begitu dipanggil—stasiun bagi waktu. Rumah kecil bagi detik, menahan napas menanti aba-aba mulai."},"ICON-2434":{"nm":"Roda Penanda Garis Lapangan","de":"Di setiap tempat yang dilalui, jalur putih tergores jelas. Batas-batas aturan terukir di atas tanah seperti ini, satu putaran demi satu putaran dengan rapi. Sebelum pertandingan dimulai, roda yang pertama meninggalkan jejak di lapangan."},"ICON-2435":{"nm":"Kantong Kartu Wasit","de":"Pada saat keputusan, selembar kartu yang ditarik dari dada tertidur di sini. Ruang tunggu keputusan yang tetap diam sampai akhir hingga ditunjukkan. Kantong yang selalu siap dan menunggu, berharap tak pernah perlu dikeluarkan."},"ICON-2436":{"nm":"Dudukan Anak Timbangan","de":"Pekerjaan menimbang hanya jujur di atas alas yang tak bergoyang. Dudukan yang menopang beban sambil menyerahkan tubuhnya sendiri rata. Langkah pertama pengukuran yang akurat selalu bermula dari tempat yang tenang."},"ICON-2437":{"nm":"Pengklik Aba-Aba Mulai","de":"Dengan satu bunyi, semua kaki serentak menghentak tanah. Awal itu amat singkat, tapi tangan yang menciptakan kesingkatan itu paling tenang dari siapa pun. Tangan yang melepaskan getaran garis start hanya dengan satu klik."},"ICON-2438":{"nm":"Alas Berdiri Kerucut Lapangan","de":"Namanya mungkin asing, tapi tugasnya jelas—menopang berat pusat lapangan bagai panggung. Di pusat tempat semua orang bersinar, selalu ada satu kaki tak terlihat yang bertahan diam-diam."},"ICON-2439":{"nm":"Gesper Sabuk Pernapasan Diafragma","de":"Suara yang baik datang bukan dari tenggorokan melainkan dari napas dalam, dan pinggang mengetahuinya lebih dulu. Gesper yang membiarkan telapak tangan merasakan perut mengembang dan mengempis. Titik awal sebuah lagu selalu berada di bawah satu tarikan napas ini."},"ICON-2440":{"nm":"Papan Bulu Latihan Napas","de":"Saat bulu bergoyang lembut tertiup napas, itu tanda pernapasan yang teratur. Diam-diam memberi bentuk pada napas yang tak terlihat, ia mengajarkan dasar sebuah lagu. Latihan mempelajari napas sebelum nada pertama, lewat mata."},"ICON-2441":{"nm":"Jam Pasir Tarikan Napas","de":"Di dalam kaca, pasir mengalir turun seperti napas. Tarik napas, berhenti sejenak, lalu embuskan perlahan—butiran pasir menghitung ritme itu untukmu. Perhatikan pasir yang jatuh tanpa suara sejenak, dan entah bagaimana napas yang berantakan kembali teratur."},"ICON-2442":{"nm":"Alas Latihan Lilin","de":"Nyalakan sumbu, dan suaramu ikut bergetar mengikuti kobaran api yang berayun. Seseorang mengukir tempat ini dengan teliti, untuk menopang getaran kecil itu sejenak. Setebal lelehan lilin yang mengeras dan menumpuk, di sinilah tertampung malam-malam bernyanyi seorang diri."},"ICON-2443":{"nm":"Tali Bantal Penekan Perut","de":"Alih-alih meletakkan tangan di perut, satu tali dengan tenang menekan tempat itu. Ia menegang saat napas membuncah dan mengendur perlahan begitu semua terkuras habis. Sahabat kecil yang diam, membantu di sisi agar tubuh mengingat ritme lebih dulu."},"ICON-2444":{"nm":"Tutup Balon Penahan Napas","de":"Jangan tiup balon itu habis sekaligus. Panjang, perlahan, dorong sampai ujungnya. Sambil menggigit tutupnya dan mengeluarkan angin, udara mencapai bagian terdalam paru-paru. Sebuah lagu, pada akhirnya, terbang sejauh panjang napas yang kau tahan."},"ICON-2445":{"nm":"Genggaman Penenang Napas","de":"Semakin hati bergoyah, semakin tangan ingin menggenggam sesuatu erat-erat. Genggam pegangan ini, dan bahu perlahan turun, tarikan napas memanjang sejengkal lagi. Belajar cara menggenggam adalah belajar cara menenangkan diri, telapak tangan mengetahuinya lebih dulu."},"ICON-2446":{"nm":"Kaitan Pita Getar Perut","de":"Kaitkan pita pada kaitan ini, dan getaran lembut menyebar ke tengah perut. Kekuatan terkumpul diam-diam tepat di tempat yang bergetar saat tertawa terbahak. Pusat yang kokoh selalu tumbuh perlahan seperti ini, di tempat yang tak terlihat siapa pun."},"ICON-2447":{"nm":"Dial Penghitung Tarikan Napas","de":"Satu, dua, tiga—setiap kali dial berputar satu petak, kedalaman napas yang ditarik terukir. Tambah satu petak, lagu pun bertahan satu bait lebih lama. Di dial kecil ini, kapasitas paru-paru yang dilatih hari ini tercatat diam-diam."},"ICON-2448":{"nm":"Papan Sendok Latihan Lidah","de":"Tempat yang harus disentuh ujung lidah tertera jelas di atas papan. Cara menggulung, menyentak, dan berhenti sejenak. Di balik pelafalan yang mengalir mulus tersembunyi begitu banyak fajar tempat lidah menghafal jalannya seperti ini."},"ICON-2449":{"nm":"Jepitan Cermin Bentuk Mulut","de":"Jepitan ini dengan lembut menahan bentuk mulut yang terpantul di cermin. 'A' membulat, 'I' melebar ke samping. Pelajaran tenang hanya berdua dengan cermin, merapikan bentuk suara sambil menghadapi wajah sendiri lurus-lurus."},"ICON-2450":{"nm":"Anjing Laut Gabus Pelafalan","de":"Seekor anjing laut kecil yang diukir dari gabus duduk di sudut meja, mendengarkan pelafalan. Di malam ketika bunyi 'r' terus tergelincir dan semangat merosot, mata bulat si anjing laut diam-diam berkata: Tak apa, coba sekali lagi saja."},"ICON-2451":{"nm":"Pin Penanda Napas Lirik","de":"Di mana harus bernapas dalam lirik—pin ini yang memberi tahu lebih dulu. Tancapkan di akhir baris, dan tempat itu menjadi jeda lembut sebuah lagu. Untuk bernyanyi sepuas hati, bahkan sebuah kalimat butuh satu spasi untuk menarik napas."},"ICON-2452":{"nm":"Sandaran Dagu Latihan Diksi","de":"Cukup dengan menopang dagu sedikit saja, pelafalan yang hampir berantakan menemukan tempatnya. Ucapan yang jelas bukan hanya kerja mulut, melainkan karya bersama dagu, tenggorokan, dan napas. Satu sandaran kecil ini diam-diam membantu keseimbangan yang rumit itu."},"ICON-2453":{"nm":"Penyangga Cetakan Mulut Vokal","de":"A, E, I, O, U—cetakan yang menegakkan persis jalur yang dilalui kelima vokal keluar dari mulut. Letakkan diam-diam di samping cermin dan bentuk kerangka suara setiap hari. Kerangka lagu apa pun, pada akhirnya, bermula dari kelima vokal ini."},"ICON-2454":{"nm":"Kartu Pemelintir Lidah","de":"Satu kartu yang begitu memelintir hingga saat dibaca, lidah tersandung dan tawa akhirnya meledak. Salah pun sungguh tak apa—salah itu sendiri adalah latihannya. Setiap kali berhasil melewati kalimat jahil ini, satu pelafalan kembali terjaga jernih."},"ICON-2455":{"nm":"Sumbat Pelemas Bibir","de":"Pemanasan yang menggetarkan bibir untuk membangunkan mulut yang kaku. Gigit sumbatnya dan embuskan angin panjang, dan bibir yang tertidur pun melemas lentur. Pemanasan terkecil dan paling lembut untuk membuka bait pertama dengan lembut."},"ICON-2456":{"nm":"Karet Gelang Penanda Bagian Lirik","de":"Lilitkan karet gelang untuk menandai bagian yang terus tersendat. Setiap kali melihat tempat itu di pergelangan tangan, gunung yang harus didaki hari ini terlintas di pikiran. Semakin sulit birama itu, semakin sering dilihat, semakin lama disimpan di hati."},"ICON-2457":{"nm":"Kaitan Syal Penghangat Leher","de":"Agar tenggorokan tak serak di udara dini hari pergantian musim, syal digantung kukuh di kaitan ini. Hanya dari leher yang terbungkus hangat, suara jernih akhirnya terurai. Menjaga suara selalu dimulai dari merawat leher lebih dulu."},"ICON-2458":{"nm":"Ujung Roller Getar Pita Suara","de":"Saat ujung roller perlahan bergulir di sisi leher, pita suara yang tertidur semalaman diam-diam terbangun. Getaran ringan melonggarkan ketegangan yang kaku, dan nada pertama yang ragu pun menjadi jauh lebih lembut. Sentuhan yang menghangatkan tubuh sebelum bernyanyi."},"ICON-2459":{"nm":"Tatakan Cangkir Pemanasan Senandung","de":"Bibir tertutup, bersenandung pelan, genggam cangkir hangat yang mengepul dengan kedua tangan dan tenggorokan pun ikut menghangat. Senandung rendah menyebar membulat di atas tatakan. Sebuah lagu bermula seperti ini, dari satu teguk kehangatan yang hangat-hangat kuku."},"ICON-2460":{"nm":"Kapsul Penyimpan Permen Tenggorokan","de":"Untuk hari-hari ketika tenggorokan terasa kering dan gatal, permen dikumpulkan diam-diam di dalam kapsul. Gulirkan satu di mulut tepat sebelum naik panggung, dan mentol yang menyegarkan melapangkan tenggorokan yang tersumbat. Sedikit penghiburan darurat, tersimpan dalam wadah kecil milik sendiri."},"ICON-2461":{"nm":"Kantong Kompres Uap Tenggorokan","de":"Lilitkan kantong yang meresap uap hangat halus ke leher, dan tempat yang kaku karena latihan panjang meleleh lembut. Dengan kehangatan handuk yang baru dipanaskan, ia diam-diam menawarkan satu ketukan istirahat pada pita suara yang lelah dan lesu."},"ICON-2462":{"nm":"Jam Pasir Istirahat Pita Suara","de":"Janji tenang untuk tidak bicara hari ini dihitung diam-diam oleh butiran pasir yang halus. Menutup mulut sejenak dan menyayangi suara. Waktu tenang itu, yang juga merupakan perawatan terbaik, mengalir perlahan di sini."},"ICON-2463":{"nm":"Sumbat Pemanasan Getar Bibir","de":"Getaran bibir yang naik turun mengikuti nada sambil bergetar ringan. Gigit sumbatnya sedikit, dan getaran yang liar itu menjadi jauh lebih rata. Alat kecil sebesar telapak tangan yang dengan lembut mengencangkan kancing pertama vokal."},"ICON-2464":{"nm":"Tutup Semprot Pelembap Tenggorokan","de":"Agar tenggorokan tak mengering di panggung yang kering, tekan tutupnya dan semprotkan kabut halus. Tarik napas dalam sekali dari udara yang lembap itu, dan suara yang kering kembali memancarkan kilau jernihnya."},"ICON-2465":{"nm":"Bola Getar Pelemas Vokal","de":"Genggam diam-diam bola yang bergetar halus di telapak tangan, dan getaran itu naik lembut melalui lengan hingga ke leher. Sahabat pemanasan yang bulat dan lembut, mengguncang perlahan membangunkan organ vokal yang kaku karena ketegangan."},"ICON-2466":{"nm":"Penanda Titik Formasi","de":"Satu penanda kecil tertancap di lantai panggung. Di sini tempatmu, di sana tempatku. Saat banyak orang berkumpul menggambar satu lukisan bersama, ia diam-diam menahan agar tak seorang pun tercerai—janji tak terlihat bahwa tak ada yang tersesat."},"ICON-2467":{"nm":"Cip Anak Panah Alur Gerak","de":"Cip berbentuk mata panah menunjuk jelas arah langkah berikutnya. Ke mana harus berputar, di mana harus berhenti—lantai memberi tahu lebih dulu agar tak tersesat. Alur gerak adalah peta yang dihafal ujung kaki lewat pijakan tak terhitung banyaknya."},"ICON-2468":{"nm":"Pin Titik Pusat Formasi","de":"Satu titik tunggal yang diam-diam menjadi acuan ketika banyak orang berkumpul. Mengelilingi pin ini, lingkaran tergambar membulat, dan formasi terbentang lebar. Bahkan gerakan yang tercerai-berai menemukan keteraturannya sendiri hanya dengan satu titik pusat."},"ICON-2469":{"nm":"Baji Titik Persilangan","de":"Di tempat dua jalur bertemu di satu titik, sebuah baji ditancapkan kukuh. Agar tak saling bertabrakan, agar tak melenceng dan bersimpangan. Bahkan di sekejap napas yang berpapasan itu, tak seorang pun kehilangan arah."},"ICON-2470":{"nm":"Bendera Arah Keluar Panggung","de":"Ketika gema nada terakhir memudar, kau menyelinap keluar dengan tenang ke arah yang ditunjuk bendera. Keluar tak boleh lebih berantakan daripada masuk. Bahkan penutupan panggung punya arah yang telah dijanjikan sejak awal."},"ICON-2471":{"nm":"Jepitan Meteran Pengukur Jarak","de":"Cengkeram ujung meteran erat dengan jepitan, dan sejengkal demi sejengkal menjadi tepat tanpa gagal. Bahkan jarak antar orang disejajarkan rapi seolah diukur penggaris. Pemandangan yang indah selalu lahir dari ujung jari yang teliti seperti ini."},"ICON-2472":{"nm":"Kaitan Tali Acuan Baris","de":"Kaitkan tali pada kaitan dan tarik tegang dalam satu garis, dan garis tipis itu menjadi acuan bagi semua orang untuk berdiri sejajar. Barisan yang terlihat begitu rapi berkat satu garis lurus tak terlihat ini."},"ICON-2473":{"nm":"Kepingan Garis Putus-Putus Jalur Gerak","de":"Kepingan-kepingan yang diam-diam menggambar jalur berupa garis putus-putus di lantai. Berjalan mengikuti jejak samar ini, kau tak akan tersesat bahkan dalam gelap. Selagi titik demi titik tersambung rapi, langkah-langkah yang tercerai menyatu menjadi satu alur."},"ICON-2474":{"nm":"Paku Payung Posisi Lantai","de":"Paku payung yang ditekan ke lantai agar tak lupa posisi. Bahkan dalam gelap gulita, ujung kaki meraba tonjolan kecil itu dan menemukannya tanpa gagal. Hanya saat berhenti tepat di satu titik itu, sorotan lampu akhirnya tumpah dari atas kepala."},"ICON-2475":{"nm":"Pita Fokus Isolasi Leher","de":"Jika dagu ikut bergoyang, suara pun ikut bergetar dan berantakan. Untuk menguasai cara menggerakkan leher saja sementara kepala tetap diam, pita ini dililitkan. Di balik gerakan yang tampak begitu bebas, ada latihan isolasi yang tenang seperti ini."},"ICON-2476":{"nm":"Jepitan Bantal Penahan Bahu","de":"Agar bahu tak terangkat sesukanya, bantal ini ditahan diam oleh jepitan. Agar tubuh membedakan dengan jelas mana yang harus bergoyang dan mana yang harus diam. Garis yang terkendali selalu lahir dari pengekangan kecil seperti ini."},"ICON-2477":{"nm":"Gesper Sabuk Pengenal Tulang Rusuk","de":"Sabuk ini diam-diam membaca gerakan halus tulang rusuk yang mengembang dan menutup kembali. Kencangkan gespernya, dan gerakan napas tersampaikan jelas hingga ke ujung jari. Vokal yang dalam dan kokoh berasal dari gerakan tulang tak terlihat ini."},"ICON-2478":{"nm":"Bandul Ayun Pinggul","de":"Bandul berayun perlahan ke kiri dan kanan, diam-diam memberi tahu ritme yang digambar pinggul. Bagaimana pusat tubuh memindahkan beban, beban kecil sebesar telapak tangan mengajarkannya tanpa kata-kata. Bahwa bahkan ayunan punya alurnya sendiri."},"ICON-2479":{"nm":"Kaitan Putar Pergelangan Tangan","de":"Kaitkan kaitan ini di pergelangan tangan dan putar perlahan ke dalam, lalu ke luar, dan sendi yang kaku semalaman melemas lembut. Untuk gerakan yang hidup hingga ke ujung jari, pergelangan tangan harus lentur lebih dulu. Putaran kecil ini membuka ekspresi yang lebih besar."},"ICON-2480":{"nm":"Tali Cincin Resistansi Pergelangan Kaki","de":"Selipkan cincin di pergelangan kaki dan tarik talinya, dan setiap langkah yang diayunkan mendapat perlawanan lembut di ujung kaki. Sebanyak pijakan berat yang dilakukan, sebanyak itu pula kekuatan diam-diam terkumpul di kaki. Lompatan seringan bulu selalu berdiri di atas latihan seberat ini."},"ICON-2481":{"nm":"Kantong Pasir Fokus Otot Inti","de":"Hanya setelah melilitkannya di perut, kau akhirnya tahu di mana letak pusat tubuhmu yang sebenarnya. Selagi beban menarik bahu, pusat yang goyah perlahan menemukan tempatnya, dan di tempat yang telah dilepaskan, tersisa satu postur yang berdiri tegak."},"ICON-2482":{"nm":"Tutup Batang Penyelaras Tulang Belakang","de":"Ketika tutup kecil ini menyentuh punggung yang seharian hidup membungkuk, rasanya seperti ada seseorang yang diam-diam meluruskan bahumu. Kau bisa tetap hidup meski membungkuk, tapi berdiri tegak adalah keahlian lembut yang harus dipelajari kembali perlahan-lahan."},"ICON-2483":{"nm":"Bola Pijat Akupresur Pelemas Otot","de":"Tekan kuat tempat yang mengeras, dan mula-mula terasa nyeri lalu segera terasa lega. Seperti kehangatan punggung tangan nenek yang mengusap punggungmu saat kecil, melonggarkan berarti bersedia menahan sedikit rasa sakit lebih lama sambil tetap berada di sisimu."},"ICON-2484":{"nm":"Sekrup Pengatur Sudut Cermin","de":"Dimiringkan sejengkal telapak tangan saja, cermin memantulkan wajah yang sama sekali berbeda. Dengan satu putaran sekrup dunia miring lalu tegak kembali, tampaknya bahkan menghadapi diri sendiri butuh bidikan yang tenang."},"ICON-2485":{"nm":"Bantalan Pengusap Embun Cermin","de":"Di depan cermin yang mengabur oleh uap panas, seseorang sejenak kehilangan wajahnya sendiri. Sekali usapan, wajah itu kembali. Berkat sentuhan yang menyingkirkan kabut ini, aku bertemu diriku sendiri lagi setiap pagi."},"ICON-2486":{"nm":"Karet Kaki Tripod Kamera","de":"Di ujung kaki tripod, satu titik karet sebesar kuku menentukan nasib gambar. Cengkeraman kuat yang menggigit lantai meredakan guncangan, sehingga gambar yang tanpa getaran selalu bermula diam-diam dari gesekan tak terlihat."},"ICON-2487":{"nm":"Film Kisi Acuan Sudut","de":"Garis-garis kisi tipis di atas film seperti roda bantu untuk mata. Semakin komposisi terbiasa di tangan, semakin garis itu diam-diam menghilang, menyisakan hanya insting. Jejak pembelajaran menjadi tak terlihat justru saat semakin matang."},"ICON-2488":{"nm":"Pedal Kaki Mulai Rekam","de":"Bagi orang yang kedua tangannya penuh barang bawaan, jari terakhirnya selalu ujung kaki. Tekan ringan, dan rekaman pun dimulai—di balik layar, urusan rumah tangga terselesaikan dengan cekatan, sampai ke ujung kaki sekalipun."},"ICON-2489":{"nm":"Jepitan Arah Pencahayaan","de":"Ke mana cahaya akan jatuh bergantung pada ujung jari klip sebesar kuku ini. Pekerjaan menggeser bayangan sejengkal dan menghidupkan kontur, atas perbedaan sekecil itu seseorang bisa lama sekali termenung ragu."},"ICON-2490":{"nm":"Tirai Pembanding Rekaman","de":"Letakkan kemarin dan hari ini berdampingan, dan barulah perubahan itu mulai bicara. Tepat saat tirai meluncur turun, jarak waktu yang telah dilalui di antara keduanya terungkap jujur di layar."},"ICON-2491":{"nm":"Tali Pergelangan Remote","de":"Lilitkan satu tali di pergelangan tangan, dan hati yang cemas takut menjatuhkannya pun melonggar. Alat pengaman kecil justru membuat tangan lebih bebas, sebuah paradoks lembut di mana terikat justru menenangkan hati."},"ICON-2492":{"nm":"Tutup Lensa","de":"Selagi kamera beristirahat, lensa pun diam-diam memejamkan matanya. Di dunia tempat sebutir debu meninggalkan bekas luka di layar, menutupnya dengan lembut adalah keinginan untuk menjaganya lama-lama."},"ICON-2493":{"nm":"Pita Pengangkat Sudut Bibir","de":"Angkat sedikit sudut bibir, dan ekspresi yang kaku perlahan melonggar. Senyum, pada akhirnya, juga otot—mula-mula meminjam kekuatan alat, lalu di suatu pagi kau tersenyum cerah dengan kekuatanmu sendiri."},"ICON-2494":{"nm":"Roll Pijat Otot Pipi","de":"Gulirkan perlahan bagian dalam pipi hingga melonggar, dan ucapan mengalir jauh lebih mulus. Persiapan tenang yang membangunkan wajah dengan lembut sebelum bernyanyi. Ekspresi pun, setelah dihangatkan, menjadi lebih hangat."},"ICON-2495":{"nm":"Pengukur Sudut Senyum","de":"Kamera tahu bahwa bahkan senyum punya sudut yang tepat. Mengukur ke sana kemari dengan alat ini, kau akhirnya sadar—senyum yang paling indah mekar dari ketulusan yang sama sekali tak bisa diukur."},"ICON-2496":{"nm":"Jepitan Gerakan Alis","de":"Gerakkan alis walau hanya 1 milimeter, dan seluruh alur hati pun berubah. Jepitan yang diam-diam menahan bagian terkecil dari sebuah ekspresi—akting adalah kerja ujung jari yang mengendalikan kehalusan sekecil ini."},"ICON-2497":{"nm":"Stiker Pengangkat Tulang Pipi","de":"Angkat sedikit tulang pipi dan tempelkan, maka muncul satu tempat di wajah tempat cahaya berdiam. Dimensi yang tercipta dari selembar stiker sebesar kuku—rias panggung menyimpan rahasia tak terlihat seperti ini."},"ICON-2498":{"nm":"Penutup Mata Latihan Kedip","de":"Tutup satu mata, dan hati terkumpul sepenuhnya pada mata yang tersisa. Latihan mengedip, pada akhirnya, adalah belajar cara menyembunyikan separuh dengan anggun. Ada juga ekspresi yang justru menjadi lebih jelas karena sebagian ditutupi."},"ICON-2499":{"nm":"Jepitan Cetakan Bentuk Mulut","de":"Ga, gya, geo... sesuaikan bentuk mulut dengan cetakan, dan pelafalan yang samar pun menjadi jelas. Bahwa setiap vokal adalah postur wajah, kau ukir perlahan ke dalam tubuh di depan cermin."},"ICON-2500":{"nm":"Kantong Pemanasan Ekspresi","de":"Tepat sebelum naik panggung, kantong hangat yang lembut menghangatkan wajah. Sama seperti tangan yang kedinginan membuat permainan menjadi kaku, ekspresi pun demikian. Bahkan senyum butuh pemanasan lebih dulu, kebenaran kecil dari balik panggung."},"ICON-2501":{"nm":"Bandana Pelicin Kerutan Dahi","de":"Lilitkan bandana ini di dahi, dan kerutan yang terukir dalam pun perlahan mengendur. Benda yang mengistirahatkan, sejenak, kerutan yang terpahat oleh kekhawatiran. Di balik dahi yang telah licin, seseorang tampak sedikit lebih muda."},"ICON-2502":{"nm":"Bidal Pembalik Naskah","de":"Bidal kecil yang dikenakan di ujung jari untuk membalik halaman. Irama membalik naskah tebal lembar demi lembar, tanpa disadari, menjadi ketukan sebuah kisah. Bahkan dalam membaca pun tersimpan kebiasaan tangan yang penuh sayang."},"ICON-2503":{"nm":"Bendera Pewarna Perasaan","de":"Kegembiraan berwarna kuning, kesedihan berwarna biru. Warnai hati lalu kibarkan benderanya, dan perasaan yang tak terlihat pun mengambil bentuk, berkibar tertiup angin. Perasaan pun ternyata bisa digambar dengan tangan seperti ini."},"ICON-2504":{"nm":"Jepitan Penekan Dialog","de":"'Berikan tekanan pada kata ini,' bisik jepitan itu perlahan. Dialog yang sama bisa berubah total maknanya hanya dengan satu tekanan, maka ia menjadi penanda kecil yang menjaga titik berat sebuah ucapan."},"ICON-2505":{"nm":"Balok Koma Baca","de":"Balok yang diletakkan untuk berkata, 'istirahatlah satu ketukan di sini.' Koma dalam dialog bukanlah jeda, melainkan napas yang ditarik untuk kata-kata berikutnya. Orang yang pandai beristirahat, pada akhirnya, pandai pula berbicara."},"ICON-2506":{"nm":"Pita Klip Penanda Napas","de":"Pita itu naik turun mengikuti klip, menggambarkan panjang napas di depan mata. Mengamati dan mengikuti irama tarikan dan embusan napas—awal sebuah lagu selalu dimulai dari menguasai napas."},"ICON-2507":{"nm":"Kantong Dadu Perasaan","de":"Sebuah dadu menggelinding keluar dari kantong dan menentukan perasaan hari ini. Jika keluar gembira, coba tampil gembira; jika marah, coba tampil marah. Latihan akting pun menjadi permainan mempercayakan hati pada kebetulan."},"ICON-2508":{"nm":"Dudukan Miring Naskah","de":"Letakkan naskah di atas dudukan yang miring, dan kau tak perlu menundukkan kepala. Kemiringan kecil yang menjaga garis pandang mata ini, diam-diam merawat leher yang kaku karena latihan panjang."},"ICON-2509":{"nm":"Sekat Bisikan","de":"Sebuah tanda untuk mulai berbisik dari sini. Rendahkan suaramu di balik sekat, dan penonton justru menahan napas serta condong untuk mendengar. Paradoks lembut panggung: semakin pelan kau bicara, semakin jauh ia tersampaikan."},"ICON-2510":{"nm":"Kotak Token Tukar Peran","de":"Balik sedikit tokennya, dan peran yang dimainkan pun berubah. Hari ini tokoh utama, esok teman yang setia mendampingi. Di pulau tempat mereka tumbuh bersama, semua orang mendapat giliran berdiri di tengah panggung."},"ICON-2511":{"nm":"Stiker Titik Fokus Pandangan","de":"Diamkan mata pada satu titik kecil di samping kamera. Begitu pandangan yang goyah berhenti di satu tempat, tatapan di layar pun hidup dengan jelas. Tatapan yang teguh, pada akhirnya, berawal dari diam yang tenang."},"ICON-2512":{"nm":"Penggaris Segitiga Pengukur Sudut","de":"Ketika satu sudut layar entah kenapa terlihat miring, tempelkan penggaris segitiga dan jawabannya pun muncul. Pekerjaan meluruskan yang bengkok. Sebelum memercayai mata, cobalah percaya pada penggaris sejenak."},"ICON-2513":{"nm":"Dudukan Lensa Sejajar Mata","de":"Sejajarkan lensa dengan tinggi mata seseorang, dan layar pun berbohong lebih sedikit. Bukan dari atas, bukan pula dari bawah—hanya ketika berhadapan dengan mata yang setara, ekspresi asli yang tak dibuat-buat pun terekam."},"ICON-2514":{"nm":"Sirip Panah Pengarah Pandangan","de":"Pandangan mengalir perlahan ke arah yang ditunjuk sirip itu. Panah kecil yang lembut menuntun mata penonton. Gambar yang baik dengan ramah menunjukkan ke mana seharusnya kita melihat."},"ICON-2515":{"nm":"Cip Lantai Jalur Syuting","de":"Injak satu titik dari jalur yang sudah dihafal luar kepala, dan posisi berikutnya langsung tergenggam. Langkah kaki yang menjelajahi panggung adalah jalan tak kasatmata yang tercipta dari sambungan penanda-penanda kecil yang tertancap di lantai."},"ICON-2516":{"nm":"Pita Meteran Jarak Kamera","de":"Ukur jarak antara objek dan kamera dengan pita ini. Di dunia tempat sejengkal tangan memisahkan jauh dan dekat, meteran ini menjadi penjaga sunyi yang mengawal batas antara buram dan tajam."},"ICON-2517":{"nm":"Panduan Kemiringan Kepala","de":"Seberapa jauh kepala harus dimiringkan agar terlihat paling lembut? Ikuti panduannya, dan perlahan kau akan menyadari—sudut kemiringan itu, pada akhirnya, sangat mirip dengan seberapa jauh hati kita terbuka."},"ICON-2518":{"nm":"Jepitan Cermin Tangan Kontak Mata","de":"Letakkan cermin tangan di samping kamera dengan jepitan ini, maka kau menatap matamu sendiri sembari beradu pandang denganmu. Alat kecil yang lembut menjembatani pandangan antara aku di cermin dan kamu di layar."},"ICON-2519":{"nm":"Lampu Penanda Syuting","de":"Ketika lampu menyala, itu tandanya syuting sedang berlangsung. Satu lampu kecil mengumpulkan ketegangan lokasi yang riuh menjadi satu. Sejak lampu itu menyala, napas semua orang tertata rapi dalam satu ketukan."},"ICON-2520":{"nm":"Tombol Lonceng Reaksi","de":"Tekan tombolnya, dan bunyi lonceng jernih berdenting nyaring. Seperti tepuk tangan yang meledak setelah adegan bagus, sepatah kata hangat 'kerja bagus' dari seseorang tersimpan di dalam lonceng kecil ini."},"ICON-2521":{"nm":"Tabung Undian Refleks Cepat","de":"Goyangkan, dan batang-batang kayu berderak, membangunkan suasana lebih dulu. Siapa yang membuka panggung ditentukan oleh satu kibasan pergelangan tangan—yang terpilih tersenyum kikuk, yang tersisa mengelus dada lega. Bahkan berbagi keberuntungan pun punya aturannya yang ramah."},"ICON-2522":{"nm":"Lonceng Kocok Efek Suara","de":"Goyangkan pergelangan tangan sedikit saja, dan—kring—sebuah sahutan pun menyela. Lonceng kecil ini mengisi jeda sebelum kesunyian sempat terasa canggung. Menghitung ketukan tawa, yang ini selalu selangkah lebih cepat."},"ICON-2523":{"nm":"Tutup Kotak Kejutan","de":"Sebelum terbuka, tak seorang pun bisa menebak isinya. Itulah satu-satunya tugas yang diemban tutup ini. Agar jeritan dan tawa meledak bersamaan pada saat ia terguncang terbuka, ia menggantungkan debar itu pada sebuah engsel."},"ICON-2524":{"nm":"Kipas Lipat Reaksi","de":"Bunyi 'crak' saat terbuka pun menjadi jawaban itu sendiri. Rangka kipas mengipaskan kekaguman yang tak sempat terucap lewat kata. Di antara gerakan melipat dan membuka, keceriaan berbalas-balasan, dan sehelai perasaan pun ikut bergoyang bersama angin."},"ICON-2525":{"nm":"Roda Roulette Hukuman","de":"Tak seorang pun tahu lebih dulu petak mana yang akan menjadi tempat berhentinya jarum. Semakin lambat roda berputar, semakin cepat justru detak jantung berpacu—klik, dan di titik berhentinya tertulis nasib konyol hari ini. Beberapa detik saat gemetar pun terasa menyenangkan."},"ICON-2526":{"nm":"Papan Balon Kata Seru","de":"Angkat tinggi-tinggi di atas kepala, dan 'wow' pun muncul menjadi huruf yang melayang. Selembar kertas mendahului hati, meneriakkan apa yang tak sempat dikejar oleh mulut. Sebab bahkan reaksi pun butuh sedikit arahan panggung."},"ICON-2527":{"nm":"Bendera Tangan Jeda Beku","de":"Begitu bendera terangkat, semua orang membeku di tempat masing-masing. Sinyal yang mengunci bahkan suara napas ke dalam gambar diam. Ketika diturunkan kembali, tawa yang tertahan pun tumpah ruah sekaligus."},"ICON-2528":{"nm":"Wadah Jepitan Jawaban Konyol","de":"Semakin konyol jawabannya, semakin erat pula ia dijepit dan digantung. Ketika jawaban-jawaban salah yang terjemur di tali bergoyang tertiup angin, panggung ini justru mencintai kesalahan itu lebih dari jawaban yang benar. Ini pemandangan sehari saat salah pun tak apa-apa."},"ICON-2529":{"nm":"Baji Sandaran Pembenar Postur","de":"Begitu punggung bersandar, tulang belakang yang bungkuk perlahan meraba jalannya sendiri kembali. Satu baji kecil yang menopang tanpa sepatah kata. Postur yang baik, bisiknya pelan dari belakang, baru terasa nyaman ketika ada yang menopangnya."},"ICON-2530":{"nm":"Balok Penopang Perata Panggul","de":"Kekokohan kecil yang diganjal di bawah kaki saat titik berat tubuh mulai goyah. Keseimbangan tubuh, pada akhirnya, naik perlahan dari lantai. Ia pemeran pendukung tanpa nama yang menopang postur dari tempat yang tak terlihat."},"ICON-2531":{"nm":"Bola Keseimbangan Pengencang Perut","de":"Selipkan di perut lalu kencangkan perlahan, dan pusat yang tadinya berserakan pun berkumpul menjadi satu titik. Semakin dalam napas diatur, semakin kokoh bola ini terasa, dan tubuh merebut kembali, napas demi napas, poros yang sempat terlupakan."},"ICON-2532":{"nm":"Penggaris Cek Lengkung Tulang Belakang","de":"Tempelkan penggaris di sepanjang punggung, dan lengkungan yang tak terlihat pun muncul di atas skala ukur. Berdiri tegak bukan berarti menghapus lengkungan, melainkan membaca bahkan kelokan kecil itu dengan penuh kasih."},"ICON-2533":{"nm":"Loop Elastis Peregang Bahu","de":"Kaitkan di bahu lalu tarik perlahan, dan dada yang mengerut pun terbuka lebar. Elastisitasnya selalu berbisik, kembalilah ke tempatmu, dan punggung yang membungkuk seharian pun perlahan-lahan lurus mengikuti panggilan lembut itu."},"ICON-2534":{"nm":"Kantong Pasir Perangsang Inti Tubuh","de":"Lilitkan di pinggang, dan butiran pasir yang berat membangunkan inti tubuh yang tertidur. Bahkan gerakan ringan pun seketika menjadi sungguh-sungguh di hadapan beban ini. Bahwa semakin bertahan semakin kokoh, setiap butir pasir diam-diam mengajarkannya."},"ICON-2535":{"nm":"Label Bantal Penopang Tulang Ekor","de":"Bantal yang lembut menopang di bawah tulang ekor, dengan sehelai label kecil tergantung di ujungnya. Alat seperti secarik pesan penuh sayang, tertulis dan ditempelkan untuk hari yang lelah karena terlalu lama duduk: 'Bersandarlah di sini sebentar.'"},"ICON-2536":{"nm":"Tripod Sudut Penopang Pinggang","de":"Bertumpu pada tiga kaki, ia diam-diam menjaga sudut tempat pinggang bersandar. Penopang yang menyusup diam-diam ke dalam postur yang hampir runtuh. Untuk menahan yang goyah, ternyata tiga titik saja sudah cukup."},"ICON-2537":{"nm":"Jepitan Postur Penarik Dagu","de":"Tarik dagu sedikit lalu sangga, dan garis leher yang berantakan pun kembali ke tempatnya. Omelan dari jepitan sebesar jari ini entah kenapa terasa hangat. Cara menegakkan kepala, diajarkan oleh alat kecil ini."},"ICON-2538":{"nm":"Tangga Pita Langkah Kaki","de":"Pita yang terbentang di lantai menggambarkan, satu demi satu, petak tempat kaki melangkah. Injak jujur petak demi petak, dan tanpa disadari, langkah itu terukir dalam tubuh. Jalan menjadi semakin jelas semakin sering diinjak."},"ICON-2539":{"nm":"Cip Kerucut Pengubah Arah","de":"Berdirikan, dan ia menjadi penanda kecil yang berkata 'beloklah di sini.' Ia menghadiahkan tikungan bagi kaki yang selama ini hanya berlari lurus. Bahkan jalan berputar pun menyimpan iramanya sendiri."},"ICON-2540":{"nm":"Papan Goyang Berdiri Satu Kaki","de":"Begitu kaki naik ke atasnya dengan satu kaki, papan itu perlahan miring. Beberapa detik berjuang keras melawan goyangan itulah pelajaran paling jujur tentang keseimbangan. Ujung jari kaki yang menahan diri agar tak jatuh menceritakan semuanya."},"ICON-2541":{"nm":"Lampu Kedip Kecepatan Reaksi","de":"Saat sinyal menyala, tangan dan mata berlomba menjadi yang tercepat. Cahaya yang berkedip tak memberi ruang untuk ragu. Tangan yang cekatan selalu bergerak setengah ketukan lebih cepat dari pikiran."},"ICON-2542":{"nm":"Marka Langkah Zigzag","de":"Titik-titik kecil yang menempel miring di lantai menuntun kaki menari zigzag. Yang lebih sulit dari garis lurus selalu adalah persilangan. Menyusuri titik-titik itu sambil tersesat, langkah kaki kecil pun matang dengan cekatan."},"ICON-2543":{"nm":"Palang Datar Tali Keseimbangan","de":"Letakkan kaki di atas palang tipis ini, dan dunia menyempit bagai seutas tali. Seperti pemain akrobat yang berjalan di udara, seluruh fokus tubuh dibebankan pada bentangan selebar sejengkal. Keseimbangan justru semakin jelas ketika ruangnya menyempit."},"ICON-2544":{"nm":"Gelang Bola Pantul Kelincahan","de":"Kenakan di pergelangan tangan, dan bola kecil memantul kembali dengan sekali sentakan. Dalam sekejap melempar dan menangkap, kecepatan reaksi terukir di ujung jari. Kecepatan, pada akhirnya, adalah soal tidak melewatkan apa yang kembali."},"ICON-2545":{"nm":"Ring Hula Kaki Lincah","de":"Kaitkan di kaki lalu putar, dan ring hula terus menggoda betis untuk bergerak. Begitu berhenti, ia jatuh, maka kaki tak henti bergoyang. Sambil bergerak seperti bermain, gerak kaki pun matang dengan lincah dan cepat."},"ICON-2546":{"nm":"Gasing Kayu Pusat Ujung Kaki","de":"Gasing yang berputar di telapak tangan berhenti seketika begitu kehilangan pusatnya. Seperti hari-hari kanak-kanak memutar gasing di halaman, keseimbangan adalah sesuatu yang hanya bisa berdiri tegak selama ia terus berputar tanpa henti."},"ICON-2547":{"nm":"Tali Pengencang Pelindung Pergelangan Kaki","de":"Bungkus dan kencangkan pergelangan kaki, dan pijakan yang goyah pun jauh lebih mantap. Semakin rawan cedera suatu bagian, semakin lembut pula harus dijaga. Seutas tali menjadi rasa aman bagi satu langkah."},"ICON-2548":{"nm":"Pita Lilit Penghangat Lutut","de":"Lilitkan pada lutut yang dingin, dan kehangatan pun meresap di antara persendian. Sendi yang kaku baru melunak setelah dihangatkan. Sebelum bergerak, ini adalah salam pagi paling hangat yang kau berikan pada tubuhmu sendiri."},"ICON-2549":{"nm":"Bola Akupresur Pelemas Otot","de":"Tekan perlahan bagian yang tegang, dan butiran-butirannya dengan lembut mengurai simpul itu. Kelegaan aneh bahwa semakin sakit semakin lega. Bahkan pegal yang tak terjangkau tangan pun, dielus oleh bola kecil ini sebagai gantinya."},"ICON-2550":{"nm":"Roda Urutan Pemanasan","de":"Bangunkan tubuh mulai dari petak tempat roda berhenti. Leher, bahu, pergelangan kaki—serahkan urutannya pada keberuntungan dan biarkan hati ringan. Ketika permainan menyusup ke dalam pemanasan, tubuh yang kaku pun tersenyum lembut lebih dulu."},"ICON-2551":{"nm":"Kompres Hangat Penghangat Sendi","de":"Letakkan kompres hangat yang mengepul di atas persendian, dan kelegaan bagai lantai rumah yang hangat di musim dingin pun menyebar. Ini waktunya sendi yang kaku melunak dalam kantuk yang nyaman. Baru setelah dihangatkan, tubuh perlahan bersiap untuk bergerak."},"ICON-2552":{"nm":"Loop Gagang Tarik Peregangan","de":"Genggam loop-nya lalu tarik, dan otot yang kaku pun memanjang. Sebuah percakapan yang tegang berlangsung antara tangan yang bertahan dan tubuh yang terbuka. Semakin jauh ia meregang, semakin ringan pula gerakan esok hari akan terasa."},"ICON-2553":{"nm":"Papan Tonjolan Perangsang Telapak Kaki","de":"Berdiri tanpa alas kaki di atas tonjolan-tonjolan ini, dan telapak kaki yang tertidur pun terbangun kaget. Seperti sensasi menggigit saat berjalan tanpa alas di jalan berkerikil, rasa menapak tanah pun mengalir naik dari ujung jari kaki."},"ICON-2554":{"nm":"Pin Magnet Catatan Cedera","de":"Tulis 'jangan memaksakan diri' lalu tempelkan pada lempeng logam. Kenangan sakit mudah terlupakan, maka digantungkan di depan mata dengan magnet. Merawat tubuh sendiri pun, pada akhirnya, berawal dari sebaris catatan."},"ICON-2555":{"nm":"Roller Bertonjol Pelepas Fasia","de":"Gulirkan perlahan batang bertonjol ini, dan fasia yang melekat pun terlepas selangkah demi selangkah. Sentuhan yang lembut mendorong pergi simpul-simpul itu. Hari yang menggumpal pun, jika diluruskan ruas demi ruas seperti ini, menjadi jauh lebih ringan."},"ICON-2556":{"nm":"Pita Lantai Jalur Langkah","de":"Bentangkan lurus di lantai, dan tercipta satu garis untuk diikuti langkah kaki. Bahkan langkah yang berantakan, begitu diletakkan di atas garis ini, tanpa disadari menjadi lurus. Gambarkan jalannya, dan kaki tak lagi tersesat."},"ICON-2557":{"nm":"Palang Perata Bahu","de":"Letakkan melintang di bahu, dan keseimbangan yang miring ke satu sisi pun perlahan terungkap. Rata selalu berarti merendahkan satu sisi dan meninggikan sisi yang lain. Satu palang saja diam-diam menunjuk kebiasaan yang bengkok."},"ICON-2558":{"nm":"Pemberat Keseimbangan Ubun-Ubun","de":"Agar beban di ubun-ubun tak terjatuh, seluruh tubuh harus tegak lurus bagai satu garis. Seperti sosok masa lalu yang berjalan dengan tempayan air di kepala, pusat keseimbangan diatur dari titik tertinggi turun ke bawah."},"ICON-2559":{"nm":"Dudukan Sudut Dagu","de":"Sangga dagu dengan lembut, dan kepala yang terus menunduk pun kembali pada sudutnya yang tepat. Sejenak beristirahat, bersandar pada satu penopang. Garis yang lurus baru sempurna ketika ada yang menopangnya dari bawah."},"ICON-2560":{"nm":"Patok Jarak Langkah","de":"Patok yang tertancap di lantai mengukur lebih dulu jarak tempat kaki harus mendarat. Satu langkah, tak terlalu lebar tak pula terlalu sempit, jarak yang jujur itu. Keseimbangan berjalan berawal dengan tenang dari penanda kecil ini."},"ICON-2561":{"nm":"Baji Pengarah Ujung Kaki","de":"Langkah pertama yang ragu, ujung kaki lebih dulu bimbang ke mana harus melangkah. Ketika baji kecil ini menentukan arah, hati pun perlahan condong ke sana juga. Menentukan jalan yang akan ditempuh bukanlah tekad besar, melainkan sejengkal yang ditunjuk oleh ujung kaki."},"ICON-2562":{"nm":"Sabuk Penegak Punggung","de":"Suara yang dulu selalu berkata 'tegakkan punggungmu, tegakkan' seolah hidup kembali di dalam sabuk ini. Tegakkan perlahan hari yang membungkuk, dan beban yang bertumpu di atas bahu pun anehnya terasa sedikit lebih ringan. Satu postur yang baik bahkan menegakkan hati."},"ICON-2563":{"nm":"Pijakan Pembagi Berat Badan","de":"Tujuh di kaki kiri, tiga di kaki kanan. Ke mana beban lebih banyak ditumpukan menentukan keseimbangan. Pijakan ini diam-diam bertanya—ke arah mana kau condong berdiri sekarang? Berdiri tegak lurus pun, ternyata, adalah penyesuaian yang tak pernah berhenti."},"ICON-2564":{"nm":"Tiang Sasaran Sejajar Mata","de":"Mata terus-menerus jatuh ke ujung kaki. Pada saat itu, sebatang tiang yang berdiri jauh di sana perlahan mengangkat pandangan. Berlatih melihat jauh adalah berlatih pergi jauh, maka begitu kepala terangkat, tempat yang tadinya terasa tak terjangkau pun mendekat."},"ICON-2565":{"nm":"Jepitan Kartu Sudut Membungkuk","de":"Lima belas derajat, tiga puluh derajat, empat puluh lima derajat. Hati membungkuk sedalam pinggang melipat. Sudut yang tertulis di kartu bukan sekadar angka, melainkan skala kecil yang mengukur ketulusan bagi orang lain."},"ICON-2566":{"nm":"Loop Tata Krama Tangan Terlipat","de":"Rapatkan kedua tangan, dan hati yang bergejolak pun tenang mengendap di satu tempat. Loop kecil ini dengan lembut menangkap ujung-ujung jari yang gelisah tak tahu harus berbuat apa, lalu diam-diam menetapkan sikap pertama sebuah salam."},"ICON-2567":{"nm":"Magnet Panah Jalur","de":"Yang pertama dicari oleh kaki yang tersesat, sambil menoleh ke sekeliling, adalah sebuah panah. Satu arah yang menempel dengan magnet memutus keraguan dan lembut menarik langkah menuju tempat yang harus dituju. Hati yang tersesat pun akhirnya menemukan satu arah."},"ICON-2568":{"nm":"Pin Penanda Arah Keluar","de":"Jalan keluar selalu lebih sulit daripada jalan masuk. Bahkan dalam gelap tanpa cahaya, pin yang bersinar jelas ini diam-diam menunjukkan jalur terakhir. Bahwa pergi dengan baik pun bagian dari panggung, baru disadari di penghujungnya."},"ICON-2569":{"nm":"Pita Kartu Urutan Salam Hormat","de":"Pernah ada masa ketika giliran siapa membungkuk lebih dulu dan siapa kemudian sangatlah jelas. Rendahkan tubuh sesuai urutan yang tertulis di pita ini, dan bahkan kesopanan pun mendapat tekstur, tata krama pun mengalir. Ini adalah menjaga giliran hati."},"ICON-2570":{"nm":"Cip Magnet Penyelaras Langkah","de":"Jika satu orang melenceng, seluruh barisan pun bergoyang. Seperti cip yang berbunyi klik menempel saat ujung kaki sejajar, berdiri bersama berarti dengan lembut mengalah pada langkah orang di samping. Suara langkah yang jatuh pada ketukan yang sama adalah yang paling meyakinkan."},"ICON-2571":{"nm":"Tapal Kuda Posisi Salam Panggung","de":"Bahkan satu salam panggung punya tempat berdiri. Letakkan kaki di atas jejak yang terbentang bulat seperti tapal kuda, dan salam pembuka yang tadinya berantakan karena gemetar pun akhirnya menemukan bentuknya. Mengetahui tempat, getaran pun sedikit mereda."},"ICON-2572":{"nm":"Kartu Isyarat Ucapan Terima Kasih","de":"Rasa terima kasih yang tak sanggup diungkapkan sepenuhnya dengan kata mengalir keluar lewat ujung jari. Menggambar hati, meletakkan tangan di dada—setiap isyarat yang tertulis di kartu menjadi terjemahan hati yang dituangkan dalam gerak. Ketulusan yang ingin tersampaikan selalu punya bentuk."},"ICON-2573":{"nm":"Patok Kartu Jarak Antrean","de":"Bahkan mengantre pun punya kesopanan yang penuh perhatian. Seperti patok yang menjaga jarak tepat sejengkal dari orang di depan, menunggu berawal dari perhatian kecil untuk tidak saling mendesak. Berdiri sedikit berjarak pun adalah bentuk peduli."},"ICON-2574":{"nm":"Ring Pembalik Kartu Cue","de":"Ketika kalimat berikutnya terus melayang di ujung bibir, jari diam-diam membalik satu lembar. Kertas-kertas kecil yang terurai di ring ini dengan lembut menahan degup jantung, dan tenang membuka kolom untuk apa yang harus dikatakan selanjutnya. Segemetar apa pun, alurnya tak terputus."},"ICON-2575":{"nm":"Jam Pasir Urutan Acara","de":"Amati butiran pasir yang mengalir turun perlahan, dan urutan berikutnya pun tertata tenang dalam pikiran. Sampai butir terakhir jatuh, jam pasir kecil ini mengajarkan cara membaca waktu dengan mata, tanpa terburu-buru."},"ICON-2576":{"nm":"Tongkat Latihan Pegang Mikrofon","de":"Sebelum terbiasa di tangan, sebatang tongkat kosong terasa berat bagai seribu kati. Sudut genggaman, jarak ke mulut, tenaga di pergelangan tangan—latihan menggenggam dan melepas berulang tanpa henti suatu hari tiba-tiba mekar menjadi satu gerakan yang alami."},"ICON-2577":{"nm":"Tongkat Latihan Pelafalan Jelas","de":"Ga, na, da, ra. Gigit tongkatnya dan gulirkan pelafalan sampai ujung lidah terasa jelas. Sepatah kata yang terlontar rapi dan jernih adalah seperti bunga yang mekar diam-diam di atas ratusan waktu yang cadel dan bergumam."},"ICON-2578":{"nm":"Bendera Tangan Isyarat Cue","de":"Mulai, berhenti, istirahat satu ketukan. Sebuah bendera tanpa sepatah kata pun memimpin napas panggung. Dari tempat yang tak terlihat penonton, tangan yang bergoyang pelan itu menahan setiap ketukan tanpa celah."},"ICON-2579":{"nm":"Lonceng Pergantian Segmen","de":"Kring, berdenting jernih, dan adegan pun berganti. Seperti bunyi lonceng yang menyebar di pasar senja, satu dentingan kecil ini membawa hati yang ragu-ragu melayang ringan ke segmen berikutnya. Peralihan selalu berawal dari suara."},"ICON-2580":{"nm":"Bandul Napas Bicara","de":"Tarik napas—satu, dua—lalu embuskan perlahan. Selaraskan napas mengikuti bandul yang bergoyang ke kiri dan kanan, dan kata-kata yang tadinya tumpah terburu-buru pun kembali menemukan ketukannya. Kecepatan bicara, ternyata, adalah kecepatan napas."},"ICON-2581":{"nm":"Papan Lipat Naskah Acara","de":"Dalam satu kali lipat-dan-buka, seluruh urutan hari itu tersimpan utuh. Begitu papan yang sudah lusuh disentuh tangan dibentangkan, pikiran yang tadinya kalut soal apa yang harus dibahas lebih dulu pun tenang berbaris rapi. Satu bentangan saja menata seluruh hari."},"ICON-2582":{"nm":"Jam Pasir Irama Napas","de":"Tarik napas tiga hitungan, tahan empat, embuskan enam. Selama pasir mengalir, napasku pun mengalir mengikutinya dengan tenang. Menghitung napas satu demi satu adalah cara tertua dan paling penuh sayang untuk merawat diri yang sibuk secara perlahan."},"ICON-2583":{"nm":"Rumbai Bantal Meditasi","de":"Rumbai yang tergantung di ujung bantal bergoyang lembut tanpa angin sekalipun. Duduk bersila, dan kesunyian orang tua zaman dahulu yang menenangkan hati sambil duduk di beranda kayu pun datang perlahan ke sisimu, singgah sejenak, lalu pergi."},"ICON-2584":{"nm":"Genta Angin Tangan Penenang Napas","de":"Ketika seutas angin berlalu, suara jernih pun menggema pelan. Tergantung seperti genta angin di ujung atap, ia menjatuhkan setetes kesejukan yang menyegarkan di atas hati yang bergolak kacau. Bahkan suara pun punya kekuatan untuk mendinginkan."},"ICON-2585":{"nm":"Piring Penampung Asap Dupa","de":"Asap sisa dupa yang terbakar perlahan turun mengendap di atas piring. Seperti aroma yang mengepul di depan meja perayaan pada pagi hari raya, seuntai asap dengan lembut menenangkan udara yang riuh dan memenuhi ruangan dengan keheningan."},"ICON-2586":{"nm":"Pemberat Ayun Tarik-Embus Napas","de":"Napasku tertumpang pada satu pemberat yang perlahan naik lalu turun kembali. Melayang saat menarik napas, mengendap saat mengembuskannya—pada hari tubuh lupa cara bernapas, jam kecil ini mengajarkannya kembali dari awal."},"ICON-2587":{"nm":"Pemukul Lonceng Meditasi","de":"Pukul lonceng sekali dengan tenang, dan gaungnya menyebar panjang. Seperti bunyi genta angin yang menggema di kuil gunung, hanya dengan mendengarkan dalam diam sampai dentingan itu lenyap sepenuhnya ke udara, satu sudut hati pun terbilas jernih."},"ICON-2588":{"nm":"Bulu Penunjuk Jalur Napas","de":"Diamkan bulu itu di depan hidung, dan jalur napas yang tak terlihat pun akhirnya tampak. Bergoyang lembut berarti bernapas dengan baik; diam berarti terlalu lama menahannya. Yang paling ringan kadang menjadi penunjuk jalan yang paling jujur."},"ICON-2589":{"nm":"Kerikil Penenang Hati","de":"Kerikil yang digenggam di telapak tangan terasa dingin dan licin. Seperti batu yang lama menggelinding di tepi sungai hingga menyerahkan semua sudutnya, terus-menerus memainkannya di ujung jari, dan bagian tajam dari hati yang bergolak pun perlahan terkikis membulat."},"ICON-2590":{"nm":"Jepitan Suhu Napas Hidung","de":"Suhu di ujung hidung diam-diam memberitahu kedalaman napas. Jepitan ini diam-diam membaca udara yang masuk dingin dan keluar hangat, memperlihatkan dengan jelas di depan mata napas yang biasanya bahkan tak kita rasakan. Napas pun ternyata punya ekspresi."},"ICON-2591":{"nm":"Papan Stiker Cuaca Perasaan","de":"Apakah hatiku hari ini cerah, atau mendung? Begitu memilih stiker kecil lalu menempelkannya di papan, perasaan yang sulit diungkapkan dengan kata pun menjadi semacam cuaca dan mengambil bentuk yang jelas. Hati pun butuh ramalan cuaca."},"ICON-2592":{"nm":"Stempel Tangan Warna Perasaan","de":"Kegembiraan berwarna kuning, kesedihan berwarna biru. Pilih warna dan tekan kuat-kuat di atas kertas, dan corak hati pun tertinggal sebagai bekas. Bahkan perasaan yang sulit diberi nama, warna itu lebih dulu mendekat dan diam-diam mengenalinya."},"ICON-2593":{"nm":"Cip Kelopak Hati Hari Ini","de":"Letakkan lembut seluruh hati hari ini di atas selembar kelopak bunga. Seperti bunga azalea yang berhamburan di hari musim semi, satu cip yang ringan dan lembut ini pelan-pelan bertanya kabar, di penghujung hari yang meredup, apakah kau baik-baik saja."},"ICON-2594":{"nm":"Magnet Balon Kata Semangat","de":"Kata-kata yang ingin diucapkan terus melayang di ujung bibir. Begitu menempelkan magnet balon kata, sepatah kata semangat yang tak sanggup disuarakan lantang pun diam-diam menyentuh hari seseorang yang lelah. Begitulah hati tersampaikan."},"ICON-2595":{"nm":"Segel Amplop Hati Terdalam","de":"Kata yang tak sempat dikeluarkan dibungkus rapi dalam amplop lalu disegel. Seperti orang zaman dahulu yang mengoleskan lem dengan ujung jari untuk menutup surat, selembar segel menjaga hati terdalam tetap aman. Sambil diam-diam menanti hari untuk dikeluarkan dan dibuka kembali."},"ICON-2596":{"nm":"Kuncup Bunga Suhu Perasaan","de":"Kuncup yang terkatup, begitu bersentuhan dengan kehangatan, terbuka lapis demi lapis dengan hati-hati. Mekar seiring naiknya suhu hati—seberapa hangat aku hari ini, bunga ini tahu lebih dulu daripada kata-kata. Musim semi pun datang ke dalam hati."},"ICON-2597":{"nm":"Tali Cermin Tangan Pujian Diri","de":"Angkat cermin dan pandang lembut mata sendiri yang terpantul di sana. Yang ditunjukkan wajah kecil yang tergantung di tali ini bukanlah wajahmu, melainkan dirimu di masa lalu, yang layak mendapat sepatah kata karena telah bertahan dengan baik. Penghiburan ternyata tak pernah jauh."},"ICON-2598":{"nm":"Set Stempel Wajah Perasaan","de":"Senyum ceria, air mata yang berlinang, bibir yang cemberut kesal. Tekan-tekan stempel ekspresi itu untuk menulis buku harian hati. Pada hari yang terlalu berat untuk dituliskan dengan kata, sebuah wajah kecil berbicara mewakili perasaan hari itu."},"ICON-2599":{"nm":"Loop Perapi Benang Kusut Perasaan","de":"Sekusut apa pun gulungan benang, urai perlahan seutas demi seutas, dan pada akhirnya kembali menjadi satu helai. Gantungkan satu per satu perasaan yang membingungkan dan sesak itu di loop ini, dan hati yang tadinya sama sekali tak dimengerti pun menemukan seutas benang tipis untuk diikuti."},"ICON-2600":{"nm":"Tali Kantong Wangi Tidur","de":"Dari kantong wangi yang tergantung di sisi bantal, aroma tumbuhan yang samar perlahan menyebar. Seperti aroma nenek yang dulu menyimpan wewangian jauh di dalam lemari, sambil menyentuh talinya, ketegangan yang menegang seharian pun perlahan tertidur."},"ICON-2601":{"nm":"Papan Pembalik Urutan Tidur","de":"Malam ketika kau berguling-guling dan baru terlelap saat fajar. Balikkan posisi berbaring dengan lembut, dan gelisahnya kemarin diam-diam berpindah menjadi kesegaran pagi ini. Beristirahat pun perlu latihan, papan kecil ini membisikkannya tanpa sepatah kata."},"ICON-2602":{"nm":"Gantungan Cahaya Bulan di Samping Bantal","de":"Gantungkan seberkas cahaya yang menyusup lewat celah tirai di samping bantal. Sungai lembut mengalir di atas wajah yang tertidur, dan malam-malam seorang trainee yang dulu takut gelap pun akhirnya melunak. Itulah penghiburan kecil pertama yang pernah ia kenal."},"ICON-2603":{"nm":"Chip Kuncup Bunga Kondisi","de":"Kondisi hari ini tertutup rapat seperti kuncup bunga. Sentuh chip-nya dan ia perlahan mekar—entah tidurmu nyenyak atau tidak, tubuhlah yang pertama tahu. Bahkan keraguan sebelum mekar sepenuhnya itu pun diam-diam memikat."},"ICON-2604":{"nm":"Tudung Sumbu Lampu Tidur","de":"\"Jangan matikan lampunya.\" Untuk si bungsu yang takut gelap, seseorang diam-diam memasang tudung di atas sumbu. Tidak terlalu terang, tidak terlalu gelap, sebuah janji kecil dan lembut untuk menemani hanya sampai tertidur."},"ICON-2605":{"nm":"Peniti Bunga Matahari Bangun Pagi","de":"Sematkan di samping ranjang, dan ia menoleh perlahan seperti bunga matahari ke arah sinar mentari pertama. Bahkan di hari kau enggan bangun, ada alasan mengapa cahaya memanggil, dan ia menuntun pagi ke satu arah."},"ICON-2606":{"nm":"Sikat Bantal Herba Tidur","de":"Oleskan lavender dan chamomile di ujung sikat lalu sapukan sekali ke bantal. Selagi aromanya meresap ke sarung bantal, ketegangan sehari perlahan lepas dari bahu. Tidur yang nyenyak dimulai dari wangi kecil ini."},"ICON-2607":{"nm":"Jepitan Sudut Selimut Tidur","de":"Menjelang subuh, ujung kaki terus saja lolos keluar dari selimut. Jepit sudutnya erat-erat dengan penjepit ini, dan kehangatan tak akan kabur semalaman. Ini pengikat kecil yang dipasang, menggantikan ucapan 'selamat tidur.'"},"ICON-2608":{"nm":"Keranjang Kerikil Kondisi","de":"Satu hal baik sehari, satu kerikil seukuran telapak tangan. Semakin berat batu yang terkumpul di keranjang, semakin diam-diam mantap pula hati. Mengumpulkan momen sederhana ke dalam genggaman—begitulah kebahagiaan sejak dulu dihitung."},"ICON-2609":{"nm":"Guci Pengumpul Bintang Tekad","de":"Setiap malam, bentuk tekad hari ini menjadi bintang lalu jatuhkan pelan ke dalam guci. Ketika penuh, guci itu menjelma langit malam kecil. Mulut guci yang dulu kosong itu tahu, janji hanya bersinar bila dikumpulkan."},"ICON-2610":{"nm":"Gantungan Permen Hadiah Kecil","de":"Satu permen yang kau berikan untuk dirimu sendiri di penghujung hari yang melelahkan. Saat kau ambil satu dari gantungannya dan menyelipkannya ke mulut, semua terasa baik-baik saja meski tak ada yang menyadari. Hadiah kecil adalah semangat paling jujur."},"ICON-2611":{"nm":"Cetakan Stempel Hari Ini Berhasil","de":"Celupkan tinta lalu tekan mantap ke buku catatan. \"Hari ini berhasil.\" Hari yang dijalani dengan baik dan hari yang sekadar bertahan sama-sama mengisi satu kotak. Setiap hari tak perlu sempurna, cukup jangan berhenti menekan stempelnya."},"ICON-2612":{"nm":"Alas Penyangga Bendera Semangat","de":"Tancapkan kuat-kuat ke tanah, dan semakin kencang angin bertiup, semakin gagah bendera berkibar. Bahkan yang bergoyang pun butuh tangan penopang. Begitulah hati yang menyemangati seseorang, bertahan diam-diam dari bawah."},"ICON-2613":{"nm":"Pot Tanam Benih Tujuan","de":"Tujuan bukan dihafalkan dengan kata, melainkan ditanam di tanah. Selagi kau menanam sebutir benih, menyiraminya, dan menunggu, ketergesaan perlahan berubah menjadi akar. Yang tumbuh di dalam pot bukan cuma tunas."},"ICON-2614":{"nm":"Papan Tempel Stiker Pujian","de":"Satu stiker untuk setiap hal yang dilakukan dengan baik. Semakin berwarna-warni papan itu terisi, semakin hari-hari yang lewat begitu saja hidup kembali dalam warna. Sejak kecil kita sudah tahu, pujian makin jelas terlihat semakin sering ditempelkan."},"ICON-2615":{"nm":"Simpul Pengikat Pita Tekad","de":"Tangan yang menjalin pita melalui simpul lalu mengikatnya erat. Kencang agar tak terlepas, namun tidak terlalu kencang. Tekad itu persis seperti simpul ini—terlalu erat akan putus, terlalu longgar akan diam-diam terlepas."},"ICON-2616":{"nm":"Chip Cangkang Kerang Pencapaian Kecil","de":"Tuliskan satu pencapaian kecil di cangkang kerang yang dipungut dari pantai. Seperti pecahan yang terkikis dan dihaluskan ombak hingga sampai sejauh ini, harimu pun telah lama berguling dan kini berkilau mengilap. Segala yang bertahan melewati waktu akan bersinar."},"ICON-2617":{"nm":"Kaitan Gantung Medali Hadiah","de":"Medali yang diraih dengan susah payah digantung bukan di laci, melainkan setinggi mata. Beban di kaitan itu menegakkan bahu setiap pagi. Hadiah bukan untuk disembunyikan, melainkan digantung di sana agar dipandangi."},"ICON-2618":{"nm":"Cangkir Penampung Tetesan Payung Musim Hujan","de":"Hujan musim penghujan menetes turun dari ujung payung. Letakkan sebuah cangkir di bawahnya, dan teras rumah tetap kering. Kau tak bisa menghentikan yang tercurah, tapi kau bisa menentukan di mana ia jatuh."},"ICON-2619":{"nm":"Kantong Kompres Dingin Peredam Panas","de":"Di balik panggung tengah musim panas, sebuah kantong dingin ditempelkan ringan ke tengkuk. Panas yang membara mereda satu ketukan. \"Tarik napas dulu.\" Tangan yang memperhatikanku bahkan sebelum panasnya sendiri, terasa begitu menenangkan."},"ICON-2620":{"nm":"Klip Pengunci Baling-Baling Kipas","de":"Baling-baling yang berputar kencang pun diam terhenti hanya dengan satu klip. Semakin kencang angin, semakin perlu sesuatu yang memegangnya erat-erat. Hal-hal yang berputar cepat pada akhirnya menjadi aman karena ada yang menahannya."},"ICON-2621":{"nm":"Tongkat Pengering Sepatu Basah","de":"Sepatu yang basah kehujanan membuat hati pun ikut lembap semalaman. Selipkan tongkat ini ke dalamnya, dan pagi hari sepatu itu cukup kering untuk dipakai lagi. Yang basah bukan untuk dibuang, melainkan dikeringkan dengan telaten."},"ICON-2622":{"nm":"Alas Pengikis Lumpur Sepatu Bot","de":"Sepatu bot yang penuh lumpur dari pematang sawah. Baru setelah digosokkan berkali-kali di alas ini barulah kau boleh naik ke lantai. Meninggalkan lumpur luar di depan pintu sebelum masuk, itulah tata krama lama yang menjaga rumah tetap bersih."},"ICON-2623":{"nm":"Kepingan Ubin Dingin Alas Kaki Musim Panas","de":"Kaki telanjang yang lebih dulu tahu. Tempelkan telapak kaki ke kepingan ubin yang digelar di lantai musim panas, dan panas siang hari diam-diam sirna dalam segenggam sejuk. Satu dinginan kecil saja bisa membuat musim yang panjang tertahankan."},"ICON-2624":{"nm":"Pita Penahan Air Hujan di Ambang Pintu","de":"Hanya dengan melilitkan satu pita di ambang pintu, air hujan tak lagi bisa melimpah masuk. Sebuah garis tipis yang memisahkan dalam dan luar. Tempat yang perlu dijaga lebih cocok dengan batas yang rapi ketimbang tembok yang megah."},"ICON-2625":{"nm":"Piring Alas Obat Nyamuk Bakar","de":"Pada malam musim panas, letakkan obat nyamuk bakar di atas alasnya, dan asap yang pedih namun akrab pun mengepul. Seperti obat nyamuk yang melingkar makin kecil dan padam, malam pun perlahan kian dalam. Itulah aroma masa-masa berbaring di dipan sambil menghitung bintang."},"ICON-2626":{"nm":"Gelang Pengait Manset Sejuk Anti-Panas","de":"Tutupi lengan yang tersengat matahari dengan manset lengan. Kaitkan erat ke lengan baju dengan gelangnya, dan pekerjaan siang hari pun jadi tertahankan. Kesejukan adalah kebaikan kecil yang meneduhkan sejengkal tempat yang tersentuh."},"ICON-2627":{"nm":"Sapu Tangan Penyapu Daun Gugur","de":"Sapukan daun-daun gugur yang memenuhi halaman dengan sapu tangan ini hingga terkumpul. Satu musim penuh berdesir di bawah kaki. Merapikan sesuatu juga berarti mengantar kepergian, dengan penuh perhatian, apa yang harus dilepaskan."},"ICON-2628":{"nm":"Tongkat Penopang Jendela Ventilasi","de":"Selipkan sebatang tongkat ke ruangan yang pengap dan biarkan jendela terbuka sedikit. Angin musim gugur menyusup masuk membawa pergi udara yang basi. Ventilasi adalah lubang napas kecil yang diam-diam menukar apa yang mengendap di dalam dengan udara luar."},"ICON-2629":{"nm":"Sumbat Kantong Biji Ek","de":"Seperti tupai, penuhi kantong dengan biji ek lalu sumbat mulutnya rapat-rapat. Erat, agar tak ada yang menggelinding keluar. Keinginan menjaga apa yang telah dikumpulkan adalah naluri lama makhluk-makhluk kecil yang melewati musim dingin."},"ICON-2630":{"nm":"Pemukul Debu Selimut Musim Gugur","de":"Jemur selimut yang dipakai sepanjang musim panas di halaman lalu pukul-pukul dengan pemukul ini. Aroma matahari menyebar di antara debu yang beterbangan. Bahwa musim lama harus dikebaskan dulu sebelum musim baru bisa diselimutkan, pergelangan tanganlah yang lebih dulu mengingatnya."},"ICON-2631":{"nm":"Tali Penahan Angin Celah Jendela","de":"Tahan angin dingin yang menyusup lewat celah jendela dengan seutas tali yang rapi. Satu garis tipis menjaga kehangatan ruangan hingga tetes terakhir. Dingin yang besar selalu bermula dari celah yang kecil, begitu yang diketahui persiapan musim dingin."},"ICON-2632":{"nm":"Tudung Saringan Daun Gugur","de":"Saringan yang menutup talang air hujan. Ia menyaring daun-daun dengan bersih dan hanya meloloskan air. Untuk mengalir tanpa tersumbat, kau harus menentukan apa yang diloloskan dan apa yang ditahan, begitu kata cucuran atap musim gugur."},"ICON-2633":{"nm":"Jepitan Ikat Rumput Kering","de":"Ikat erat seikat rumput yang sudah kering kerontang dengan penjepit ini. Sebuah tangan yang menyatukan hal-hal yang hendak bercerai-berai. Bahkan di tempat kehijauan musim panas telah sepenuhnya luntur, jika dikumpulkan, kegunaannya tetap utuh."},"ICON-2634":{"nm":"Ayunan Suhu Angin Musim Gugur","de":"Ketika angin bertiup, ayunan ini bergoyang lembut. Dari lebar goyangannya, kau menakar seberapa dalam musim gugur hari ini. Suhu bukanlah angka, ia lebih dulu menyentuh tangan sebagai sesuatu yang bergoyang pelan."},"ICON-2635":{"nm":"Wadah Penghangat Tangan Saku Mantel","de":"\"Tanganmu pasti dingin.\" Wadah penghangat tangan yang terselip di saku mantel diam-diam menghangatkan jari yang kaku kedinginan. Hati yang lebih dulu memikirkan dinginnya orang lain selalu diam-diam bersembunyi di dalam saku."},"ICON-2636":{"nm":"Bibir Penampung Embun Jendela","de":"Bibir ini diam-diam menampung air mata yang diteteskan jendela musim dingin semalaman. Sebuah aliran air kecil yang tercipta dari perbedaan suhu antara dalam dan luar. Semakin besar perbedaannya, semakin banyak yang mengalir—jendela subuh menunjukkannya setiap hari."},"ICON-2637":{"nm":"Jaring Pengaman Pelindung Api Perapian","de":"Pasang jaring pengaman di depan perapian yang menyala berkobar. Kehangatan di dekat, bahaya persis sejengkal jauhnya. Menjaga api tetap dekat tanpa membuat siapa pun terluka, itulah jarak paling mendasar dari merawat seseorang."},"ICON-2638":{"nm":"Jepitan Penahan Selimut Musim Dingin","de":"Ketika selimut tebal musim dingin terus melorot, penjepit ini menekannya diam-diam agar tetap pada tempatnya. Kehangatan yang berat harus dipegang erat agar sepadan nilainya. Kenyamanan malam musim dingin dijaga setelaten ini."},"ICON-2639":{"nm":"Spatula Pengikis Embun Beku","de":"Kikis habis embun beku yang memutih di kaca mobil subuh dengan spatula ini. Pandangan yang buram terbuka baris demi baris. Bahkan yang membeku pun akhirnya bisa dikikis, begitu yang diajarkan ujung jari pagi musim dingin."},"ICON-2640":{"nm":"Selongsong Penghangat Tutup Botol Air Panas","de":"Selubungi botol berisi air panas dengan selongsong penghangat ini. Agar tak mendingin semalaman, ia membungkus kehangatan dengan satu lapis lagi. Cara menahan kehangatan agar bertahan lama adalah, pada akhirnya, memeluknya dengan telaten memakai sesuatu."},"ICON-2641":{"nm":"Tongkat Penekan Kertas Penahan Angin Pintu","de":"Angin tajam yang menerobos celah pintu terhenti sejenak saat berjumpa denganmu. Sebatang tongkat yang menekan tepi kertas jendela erat-erat. Kehangatan ruangan akhirnya menjaga keluarganya sendiri—musim dingin dihangatkan oleh keteguhan kecil semacam ini."},"ICON-2642":{"nm":"Piring Alas Penghangat Kaki","de":"Piring bundar yang digelar di bawah penghangat kaki. Ia menampung semua panasnya sendirian tanpa meninggalkan sedikit pun bekas hangus di lantai. Ketika ujung kaki seseorang dihangatkan hingga terkantuk, bagianku dari hari ini pun diam-diam berakhir."},"ICON-2643":{"nm":"Gantungan Kain Penyerap Embun","de":"Agar kain yang mengelap embun di jendela subuh tak kehilangan tempatnya, sebuah gantungan tergantung di dinding dan menunggu. Lebih dari sekadar meresap basah, menunggu kering kembali untuk pagi esok adalah hati sejati dari penyerapan."},"ICON-2644":{"nm":"Gantungan Pengering Sarung Tangan Musim Dingin","de":"Sarung tangan yang usai bertempur perang bola salju merentangkan jarinya lebar-lebar di samping radiator. Pemandangan mereka tergantung di gantungan sambil mengepulkan uap tipis. Di penghujung sore dengan hidung memerah, itulah cucian paling damai di musim dingin."},"ICON-2645":{"nm":"Isi Ulang Bulu Kemoceng","de":"Ketika bulunya aus, gantikan dengan bulu baru. Saat ujung pengusir debu itu kembali berbulu halus. Bahwa alat kebersihan pun punya musim pergantiannya sendiri, isi ulang kecil ini diam-diam memberitahumu di telapak tangan."},"ICON-2646":{"nm":"Gagang Pemeras Kain Pel","de":"Gagang yang terpasang untuk menghemat tenaga pergelangan tanganmu. Sekali putar, kain pel dengan sendirinya memuntahkan air. Selamat tinggal masa-masa berjuang di depan papan cuci. Dalam urusan rumah tangga, segenggam kepandaian menjelma kebaikan hati."},"ICON-2647":{"nm":"Kepala Ganti Sikat Lantai","de":"Ketika sikat lantai sudah aus, ganti saja kepalanya. Gagangnya tetap sama, beratnya yang sudah akrab di tangan pun tetap sama. Pada benda yang dipakai lama, bersemayam kebaikan kecil dan kukuh yang enggan membuang semuanya sekaligus."},"ICON-2648":{"nm":"Inti Isi Ulang Roller Debu","de":"Setelah merobek lembar terakhir alat penggulung, entah kenapa terasa kosong. Saat itulah kau memasang inti baru. Itulah janji isi ulang yang gigih dan penuh kasih, untuk bertanggung jawab hingga sehelai bulu halus di sweater sekalipun."},"ICON-2649":{"nm":"Pengikis Debu Sudut","de":"Bahkan di sudut yang tak terjangkau sapu, debu diam-diam membangun rumahnya sendiri. Mengorek bersih sudut itu dengan ujung yang ramping. Hati yang memperhatikan hingga ke tempat yang tak terlihat itulah kebanggaan sejati mengurus rumah."},"ICON-2650":{"nm":"Sisir Pembersih Sapu","de":"Sapu yang biasa menyapu pun butuh sentuhan istirahat sesekali. Sisirkan rambut yang kusut di antara bulunya dengan sisir ini, dan sapu yang baru saja menyelesaikan tugasnya siap sedia untuk sapuan berikutnya."},"ICON-2651":{"nm":"Bantalan Lilin Serat Lantai","de":"Lapisi serat lantai dengan selapis lilin, dan kayu perlahan mengingat kembali kilau yang lama terlupakan. Telapak kaki nyaris tergelincir, nyaris tidak—sebuah sore ketika seluruh rumah tersenyum, mengilap dan puas."},"ICON-2652":{"nm":"Penyapu Debu Celah Pintu","de":"Aku mengincar debu yang bersarang di celah pintu. Apa pun yang menyelinap dan menumpuk setiap kali pintu terbuka-tutup, kusapu bersih dengan tubuhku yang tipis. Semakin sempit dan dalam celahnya, semakin pasti giliranku tiba."},"ICON-2653":{"nm":"Tudung Jaring Debu Keset","de":"Agar debu yang ditelan keset pintu tak bocor kembali ke luar, sebuah tudung jaring berdiri sebagai penjaga gerbang terakhir. Debu yang dibawa sepatu berlumpur dari dunia luar, hanya diizinkan masuk sejauh ini dan tak lebih."},"ICON-2654":{"nm":"Sikat Kerak Air Keran","de":"Sikat kecil berputar mengelilingi dan mengelupas kerak air yang diam-diam menetap di leher keran. Semakin sering sebuah tempat tersentuh tangan setiap hari, semakin ia harus berkilau. Itulah tata krama kamar mandi yang dijaga oleh sikat kecil ini."},"ICON-2655":{"nm":"Tudung Jaring Rambut Saluran Pembuangan","de":"Aku diam-diam menangkap rambut yang hanyut menuju saluran pembuangan. Mencegah bencana kecil berupa sumbatan hanya dengan satu tudung. Hari sang pahlawan kecil yang bulat dan kukuh ini mengalir tenang, selalu di bawah kaki."},"ICON-2656":{"nm":"Pengikis Nat Ubin","de":"Nat yang menghitam di antara ubin putih, kikis pelan-pelan waktu yang mengendap itu hingga tuntas. Ketika celah-celah sempit itu bersih, seluruh kamar mandi menghela napas ringan, seperti baru lagi."},"ICON-2657":{"nm":"Jarum Pembersih Kepala Shower","de":"Colok lubang kepala shower yang tersumbat dengan ujung jarum ini, dan air yang tadinya hanya menetes-netes kini menyembur segar kembali. Suara air pagi yang penuh kemenangan, ketika satu sumbatan kecil akhirnya terurai."},"ICON-2658":{"nm":"Cangkir Penyimpan Sikat Toilet","de":"Sikat toilet pun baru benar-benar higienis setelah beristirahat di tempat yang kering. Tersimpan rapi di cangkir kecil yang menampung tetesan airnya, ia menunggu giliran berikutnya. Martabat sebuah alat terlihat bukan dari pemakaiannya, melainkan dari cara ia disimpan."},"ICON-2659":{"nm":"Spons Pembersih Jamur","de":"Jamur yang menghitam di sudut ubin, tamu yang keras kepala itu, disilakan pergi dengan sopan oleh spons ini. Sekali diusap bersih, kamar mandi kembali cerah ke warna putih aslinya."},"ICON-2660":{"nm":"Alat Penghapus Embun Cermin","de":"Di depan cermin yang berkabut selesai mandi, alat penghapus ini menggores satu garis dan wajahmu yang jelas kembali muncul. Saat itulah kau kembali berhadapan dengan ekspresi hari ini yang sempat bersembunyi di balik kabut."},"ICON-2661":{"nm":"Gantungan Sandal Kamar Mandi","de":"Gantung sandal basah terbalik, dan air menetes turun sementara bagian dalamnya mengering dengan nyaman. Agar kaki orang berikutnya tak kedinginan. Perhatian gantungan kecil ini selalu selangkah lebih dulu menyambut."},"ICON-2662":{"nm":"Wadah Sikat Kuku","de":"Bahkan sikat kecil yang menyikat kotoran di bawah kuku punya rumahnya sendiri. Terselip rapi di dalam wadah, ia mengering tanpa lembap tersisa, menunggu wastafel berikutnya. Kebersihan selalu diam-diam dimulai dari kerapian menyimpan."},"ICON-2663":{"nm":"Tutup Cangkir Sterilisasi Sikat Gigi","de":"Sikat gigi yang bertemu mulutmu dua kali sehari pun butuh tempat berlindung kecil. Saat tutup cangkir sterilisasi ditutup rapat, satu ruang kebersihan diam-diam terjaga dari lembap yang mengambang di kamar mandi."},"ICON-2664":{"nm":"Kapsul Bawa Cotton Bud","de":"Agar cotton bud di dalam tas travel tak patah atau berserakan, sebuah kapsul memeluknya erat dengan hangat. Semakin kecil sesuatu, semakin harus disiapkan lebih dulu, agar tak kelabakan di jalan yang asing."},"ICON-2665":{"nm":"Papan Mini Pengecek Embusan Napas","de":"Embuskan napas ke telapak tangan lalu tempelkan ringan ke papan mini, dan embusan itu menyentuhnya hingga mengembun putih susu. Bukti paling menggemaskan bahwa aku hidup di hari yang dingin, papan kecil ini mencatatnya tanpa sepatah kata."},"ICON-2666":{"nm":"Rumah Penyimpan Korek Kuping","de":"Ketika korek kuping ikut bepergian di dalam tas, ujungnya mudah tumpul. Karena itu dibuatlah sebuah rumah kecil. Di dalamnya, tempat ujungnya tak akan terluka meski dibawa-bawa, alat yang halus itu tertidur nyenyak."},"ICON-2667":{"nm":"Klip Lipat Sapu Tangan","de":"Klip ini menggigit lembut sapu tangan yang keempat sudutnya dilipat rapi, mencegahnya berantakan di dalam tas. Selembar kain yang terlipat rapi memberi keanggunan yang tenang kapan pun dikeluarkan."},"ICON-2668":{"nm":"Wadah Plester Luka","de":"Pada hari lututmu tergores, buka wadahnya dan berbagai plester berbaris menantimu. Kelembutan yang tahu cara heboh bahkan untuk luka kecil sekalipun. Kotak P3K harus selalu berada dekat dalam jangkauan tangan."},"ICON-2669":{"nm":"Penghapus Sidik Jari Telapak Tangan","de":"Usap sidik jari yang menempel di kaca, dan jejak tangan yang ragu-ragu itu lenyap. Sebuah sihir kecil seukuran telapak tangan, tempat dunia di balik jendela yang buram di setiap sentuhan menjadi bening kembali."},"ICON-2670":{"nm":"Sekat Pemilah Daur Ulang","de":"Kertas di sisi ini, kaleng di sisi itu. Satu sekat memisahkan nasib yang nyaris tercampur aduk. Daur ulang pada akhirnya adalah hati yang memilah dengan telaten, dan garis pertama itu ditarik tegas oleh sekat yang rapi ini."},"ICON-2671":{"nm":"Sekop Pengelupas Stiker","de":"Bahkan stiker yang melekat lengket pun diam-diam menyerah di hadapanku. Selipkan pelan mata sekop yang pipih ke sudutnya, dan ia terlepas bersih tanpa bekas sedikit pun—perpisahan yang penuh kemenangan."},"ICON-2672":{"nm":"Gerigi Pemotong Masking Tape","de":"Tak perlu repot mencari gunting hanya untuk memakai masking tape. Tempelkan ke gerigi lalu tarik, dan ia putus rapi mengikuti seratnya. Sahabat kecil yang gesit ini paling disayangi oleh jari-jari pencinta dekorasi."},"ICON-2673":{"nm":"Braket Sudut Perekat Pojok","de":"Braket kecil yang menahan erat sudut yang terangkat dari dalam. Dari tempat yang tak terlihat, ia diam-diam menjaga sudutnya tetap presisi. Di balik hal-hal yang tampak rapi di permukaan, biasanya ada penopang tersembunyi seperti ini."},"ICON-2674":{"nm":"Tabung Pelindung Lembar Seal","de":"Agar lembar seal yang berharga tak kusut atau lembap, ia tidur berdampingan dengan lapisan film pelindung di dalam tabung. Di samping kegembiraan mengoleksi, selalu mengikuti ketelatenan untuk menjaganya dengan lembut."},"ICON-2675":{"nm":"Sikat Pembersih Stempel Tinta","de":"Sikat ini menyapu pelan mengikuti sela-sela stempel yang basah tinta, mengelupas warna lama. Sentuhan kecil yang rajin, membersihkan lebih dulu agar cap berikutnya tercetak jernih."},"ICON-2676":{"nm":"Sayap Penjepit Lembar Isi Bening","de":"Agar lembar isi binder tak melorot dan terlepas, sayap ini mencengkeram erat kedua sisinya. Berkat setiap lembar yang tetap pada tempatnya, jari yang membalik halaman tak pernah kacau."},"ICON-2677":{"nm":"Sekop Penyimpan Kepingan Dekorasi","de":"Cedok sekaligus kepingan dekorasi kecil yang berserakan dengan sekop mungil ini. Ketika repotnya memungut satu per satu dengan jari lenyap, waktu untuk membuat sesuatu dengan penuh perhatian pun jadi lebih menyenangkan."},"ICON-2678":{"nm":"Pengikat Rumbai Pembatas Buku","de":"Agar rumbai di ujung pembatas buku tak longgar, pengikat ini mengencangkannya rapi. Bahkan penunjuk jalan kembali ke halaman yang belum selesai dibaca pun terasa lebih menenangkan bila penampilannya sendiri rapi."},"ICON-2679":{"nm":"Klip Tutup Ujung Pena Dekorasi","de":"Klip yang menjepit erat tutupnya agar ujung pena dekorasi tak mengering. Ia mencegah kekecewaan pena yang lupa ditutup mengeras, sehingga warnanya selalu mengalir lembap seperti pertama kali."},"ICON-2680":{"nm":"Mata Sisip Ganti Obeng","de":"Biarkan gagang obeng tetap sama, cukup ganti mata di ujungnya. Kembang atau minus, semua beres. Kepintaran menangani banyak pekerjaan dengan satu alat, tersimpan rapat dalam ujung mata kecil ini."},"ICON-2681":{"nm":"Gulungan Sudut Amplas","de":"Gulung permukaan kasarnya melingkar untuk digenggam, dan telapak tanganmu pun menjelma alat. Setiap kali digosokkan mengikuti serat, sudut yang kasar berangsur membulat, dan kehalusan terakhir selalu dikenali oleh ujung jari manusia."},"ICON-2682":{"nm":"Corong Pemilah Sekrup","de":"Sekrup yang berserakan melewati leher yang sempit lalu berguling berkumpul di satu tempat. Suara benda-benda kecil yang tadinya berguling-guling di atas meja menemukan tempatnya, terasa seolah hati yang berantakan pun ikut tertata rapi."},"ICON-2683":{"nm":"Kait Ujung Meteran","de":"Kait di ujung meteran adalah tangan kedua bagi orang yang bekerja sendirian. Kaitkan ke sudut, dan pitanya tak akan goyah, sepanjang ukuran yang diambil pun tangan dan hati menjadi kian jujur."},"ICON-2684":{"nm":"Sarung Gagang Kunci Pas","de":"Satu lapis yang dibalutkan pada gagang besi yang dingin. Saat kau menggenggamnya, kehangatan yang lembut menyentuh tangan, bukan rasa dingin. Sebuah alat bertahan lebih lama di sisimu ketika ia lebih dulu memikirkan orang yang memegangnya."},"ICON-2685":{"nm":"Kerucut Pelindung Ujung Penusuk","de":"Sebuah kerucut kecil dipasang di setiap ujung yang tajam. Kelegaan meraba-raba laci tanpa takut tertusuk—semakin tajam sesuatu, semakin telaten ia dibungkus, dan tak seorang pun terluka."},"ICON-2686":{"nm":"Mata Pisau Pengupas Kabel","de":"Kupas tipis hanya lapisan pembungkusnya, biarkan kawat di dalamnya tak tersentuh. Saat satu lapis terurai lembut dan seutas kawat tembaga berkilau muncul, hari yang baik tahu persis di mana harus berhenti."},"ICON-2687":{"nm":"Pengelap Jendela Gelembung Waterpas","de":"Hanya ketika satu gelembung berhenti tepat di tengah, barulah benar-benar datar. Mengelap jendela kecilnya hingga bening menyerupai persiapan yang tenang, menenangkan napas dulu sebelum menggores sebuah garis."},"ICON-2688":{"nm":"Sarung Pelindung Jari Pemaku","de":"Sarung kecil yang membungkus rapat jari yang memegang paku. Palu boleh meleset, tak apa, pukullah tanpa rasa takut, katanya—sudah siap sedia menerima pukulan menggantikan jarimu."},"ICON-2689":{"nm":"Alas Anti Selip Mangkuk Makan","de":"Selapis karet yang menopang mangkuk agar tak terpeleset di lantai. Tanpa mangkuk yang kabur saat makan dengan riang, ketenangan satu waktu makan dimulai dari tempat yang tak goyah."},"ICON-2690":{"nm":"Gantungan Sendok Pakan","de":"Gantung sendok penakar pakan di dinding untuk dikeringkan ringan. Sebuah tatanan kecil yang menyambut tanganmu dari tempat yang sama setiap kali makan—memiliki mulut yang harus diurus adalah hal yang selembut ini."},"ICON-2691":{"nm":"Piring Tampung Luapan Mangkuk Air","de":"Ia diam-diam menampung seteguk air yang meluap dari tepi mangkuk minum. Berkat piring lebar yang menampungnya lebih dulu agar lantai tak basah, tanah di bawah kaki selalu kering dan nyaman."},"ICON-2692":{"nm":"Penjepit Pembagi Camilan","de":"Penjepit yang mengambil tepat satu camilan lalu menyodorkannya. Bahkan di hadapan mulut kecil yang menunggu dengan hidung menyodok maju, ada ujung jari yang lembut dalam berbagi, yang tak pernah kacau."},"ICON-2693":{"nm":"Klip Gulung Mulut Kantong Pakan","de":"Klip kecil yang menggulung dan menjepit mulut kantong pakan yang sudah dibuka. Dengan satu kali klik menutup, kelembapan terbendung, dan segenggam kerenyahan pagi esok terjaga sempurna."},"ICON-2694":{"nm":"Sumbat Corong Botol Minum","de":"Sebuah sumbat yang pas terpasang di corong botol minum. Tes, tetesan air yang bocor pun berhenti dan sekelilingnya mengering. Yang tersumbat rapat tidak akan bocor, dan tetap tergenang jernih dalam waktu lama."},"ICON-2695":{"nm":"Cangkir Takar Garis Ukur Pakan","de":"Takar tepat satu cangkir mengikuti garis ukurnya. Tidak berlebih, tidak berkurang—dalam tangan yang menakar makanan hari ini dengan adil, hari sang anggota keluarga kecil terisi pas secukupnya."},"ICON-2696":{"nm":"Tepi Alas Anti Tumpah Pakan","de":"Tepian yang mencegah pakan yang tumpah melewati batas alas. Satu tepi yang sedikit ditinggikan ini mengumpulkan rapat remah-remah yang nyaris berserakan."},"ICON-2697":{"nm":"Cincin Pemisah Mangkuk Susun","de":"Cincin kecil yang melepas lembut dua mangkuk yang bertumpuk. Tangan yang tadinya berjuang karena keduanya lengket erat menjadi ringan. Melepaskan dengan baik, ternyata, juga sebuah bentuk perhatian yang lembut."},"ICON-2698":{"nm":"Corong Penggulung Bola Halaman","de":"Corong yang mengumpulkan ke satu tempat bola-bola yang menggelinding ke seluruh halaman. Setelah sore penuh berlarian riang, tangan yang mengumpulkan apa yang berserakan di sana-sini terbayang dengan sendirinya."},"ICON-2699":{"nm":"Topi Pucuk Pagar","de":"Pasang topi bundar di setiap pucuk pagar. Agar ujungnya tak retak diterpa angin dan hujan, hati yang memperhatikan dan menutupi bahkan hal sekecil ini meresap ke seluruh halaman."},"ICON-2700":{"nm":"Kait Lipat Terowongan Bermain","de":"Kait untuk melipat rapi terowongan bermain yang sudah puas dimainkan lalu menggantungnya. Simpan baik-baik hari yang berlumur tanah lalu gantungkan, dan permainan yang tertata rapi selalu menjanjikan hari esok."},"ICON-2701":{"nm":"Bantalan Pegangan Tali Tarik","de":"Bantalan yang membungkus pegangan tali tarik dengan lembut. Sekeras apa pun ditarik, telapak tangan tidak akan lecet. Semakin lama digenggam, semakin nyaman rasanya di tangan—semua berkat kepedulian kecil seseorang."},"ICON-2702":{"nm":"Pengait Kain Peneduh Halaman","de":"Pengait yang menahan erat kain peneduh yang terbentang di halaman. Bahkan kesejukan siang hari perlu ditahan agar tetap bertahan. Di bawah naungan yang dijaga pengait ini, sore yang malas beristirahat panjang."},"ICON-2703":{"nm":"Sarung Mata Sekop Penggali Tanah","de":"Sarung yang perlahan diselipkan ke mata sekop penggali tanah. Biarkan ia beristirahat setelah sehari penuh bekerja, dan ia tetap tajam—siap menyambut tanah musim semi berikutnya sekali lagi."},"ICON-2704":{"nm":"Papan Miring Gelinding Bola","de":"Sebuah papan miring tempat bola menggelinding turun dengan riang. Menyusuri lereng yang sedikit condong, bola berlari dengan gembira. Satu kemiringan kecil menciptakan kesenangan sepanjang hari."},"ICON-2705":{"nm":"Cincin Gerendel Pintu Pagar","de":"Cincin gerendel yang mengunci pintu pagar. Bunyi klik kecil saat terkunci membuat hati menjadi tenang. Satu pintu yang tertutup rapat menjaga halaman kecil sebagai dunianya sendiri yang utuh."},"ICON-2706":{"nm":"Tali Lonceng Mainan","de":"Goyangkan lembut tali berlonceng ini dan suara jernih pun menyebar. Kring, kring—satu ruangan yang tadinya sunyi pun terbangun, dan pada satu dentingan kecil, seluruh hati memasang telinga."},"ICON-2707":{"nm":"Nampan Tetes Pot Bunga","de":"Piring yang diam-diam menampung air yang meresap turun dari bawah pot bunga. Ia menahan luapan air agar ambang jendela tetap kering. Bahkan ketulusan, saat meluap, butuh tempat untuk ditampung."},"ICON-2708":{"nm":"Sekop Tanam Bibit","de":"Sekop kecil untuk memindahkan bibit lembut ke tanah dan menyelipkannya perlahan. Di ujung jari yang menempatkan setiap tunas dengan hati-hati, musim semi yang hijau pun mengangkat kepalanya bahkan di kebun sekecil telapak tangan."},"ICON-2709":{"nm":"Pin Penanda Bedengan Kebun","de":"Pin penanda yang dituliskan dan ditancapkan di setiap bedengan untuk mencatat apa yang ditanam. Di atas tanah yang belum juga bertunas, satu label kecil diam-diam mengingat apa yang akan tumbuh."},"ICON-2710":{"nm":"Saringan Corong Penyiram Tanaman","de":"Saringan halus yang dipasang di corong penyiram tanaman. Air yang tadinya tumpah dalam satu aliran kini terpecah menjadi banyak percikan seperti gerimis lembut. Hanya aliran air yang lembut yang tidak melukai daun yang rapuh."},"ICON-2711":{"nm":"Jepitan Penopang Batang","de":"Jepitan yang dengan lembut mengikat batang yang goyah ke tiang penopangnya. Hanya sedikit sokongan yang dipinjamkan sampai yang masih rapuh itu bisa berdiri tegak—untuk tumbuh, dibutuhkan penopang seperti ini."},"ICON-2712":{"nm":"Klip Penyegel Kantong Benih","de":"Klip yang menjepit erat kantong benih yang tersisa. Sekali dipasang, tak satu butir pun akan bocor keluar. Sebuah janji kecil untuk musim semi berikutnya tersimpan dalam satu jepitan ini."},"ICON-2713":{"nm":"Sendok Takar Tanah dan Pupuk","de":"Sendok kecil untuk mengambil takaran tanah dan pupuk yang pas. Tidak berlebih, tidak kurang—satu sendok yang terukur. Hanya dengan takaran yang tepat, tanah bisa menjalankan tugasnya dengan sempurna."},"ICON-2714":{"nm":"Kaitan Gantungan Pot Bunga","de":"Kaitan gantungan yang menggantungkan pot bunga ringan di udara. Diangkat ke atas, hijaunya dedaunan menjadi sejengkal lebih dekat dengan matahari dan angin. Sebuah taman kecil mengambang di dekat jendela."},"ICON-2715":{"nm":"Jaring Pelindung Tunas","de":"Jaring penutup yang melindungi tunas yang baru muncul dengan lembut. Sampai daun yang masih lembut itu mampu bertahan dari dingin pertama dan terik matahari, yang paling rapuhlah yang pertama menerima perhatian."},"ICON-2716":{"nm":"Gantungan Sisir Perawatan Bulu","de":"Tempat untuk mengetuk-ngetuk rambut rontok dari sisir dan menggantungkannya rapi. Sisir yang telah dibersihkan dan kosong menunggu sentuhan berikutnya. Kerapian selalu dimulai dari kebiasaan kecil merawat peralatan sendiri."},"ICON-2717":{"nm":"Cincin Anti-Selip Baskom Cuci Kaki","de":"Cincin yang menopang baskom cuci kaki agar tidak tergelincir. Dengan baskom yang stabil di bawah kaki kecil yang bercipratan, baik tangan yang mencuci maupun hati yang dicuci tidak akan goyah."},"ICON-2718":{"nm":"Kait Dinding Tali Jalan-Jalan","de":"Satu kait untuk menggantungkan tali jalan-jalan di depan pintu. Dari tempatnya di sisi pintu, kesiapan untuk berangkat selalu menunggu. Saat tali diturunkan, satu langkah kecil yang berdebar ikut serta."},"ICON-2719":{"nm":"Tutup Pelindung Gunting Kuku","de":"Tutup pelindung yang menjaga bagian lunak yang rentan saat memotong kuku. Hanya dengan batas aman yang ditandai sejauh ini saja, tangan yang memegang gunting bisa tetap tenang dan tidak gemetar."},"ICON-2720":{"nm":"Pita Suhu Air Mandi","de":"Pita yang mengapung di air mandi untuk memberi tahu suhunya. Kebiasaan lama mencelupkan punggung tangan untuk mengira-ngira kehangatan yang pas kini mengapung di sana, diterjemahkan dengan jelas menjadi satu garis warna."},"ICON-2721":{"nm":"Rol Perekat Bulu Rontok","de":"Satu helai rambut putih di baju hitam, tepat sebelum naik panggung terlihat paling mencolok. Mengikuti suara gulungannya, remah-remah sehari pindah rapi ke kertas lengket. Kerapian selesai seperti ini, selembar demi selembar, sebanyak yang dikelupas."},"ICON-2722":{"nm":"Penjepit Kantong Kotoran Jalan-Jalan","de":"Di ujung jalan-jalan, ada momen lembut membungkukkan badan. Genggam kantong di ujung penjepit dan tangan tetap bersih, hati tetap ringan. Berjalan bersama menyimpan sopan santun kecil untuk membersihkan setelahnya—penjepit ini yang paling dulu mengetahuinya."},"ICON-2723":{"nm":"Tepi Keset Pintu","de":"Tepi keset di depan pintu adalah sapaan selamat datang pertama yang disentuh kaki. Sekali ujung kaki yang basah berhenti di sini, lantai di dalam tetap kering. Tempat paling rendah dari semuanya, mengelap dan menyambut setiap orang yang masuk tanpa sepatah kata."},"ICON-2724":{"nm":"Tali Simpul Lonceng Perawatan","de":"Bahkan memasang satu lonceng pun ada urutannya. Lilitkan tali dua kali lalu selipkan sekali, maka suara jernih akan mengikuti setiap langkah. Perawatan diri, pada akhirnya, adalah hati yang tak pernah melewatkan sentuhan akhir sekecil ini."},"ICON-2725":{"nm":"Kantong Tetes Payung Lipat","de":"Di lobi setelah hujan reda, tetesan air menitik di lantai dari ujung payung yang terlipat. Satu kantong diam-diam menampungnya, dan kaki siapa pun tidak tergelincir. Kebaikan biasanya menjaga jarak sedekat ini, tanpa suara."},"ICON-2726":{"nm":"Jepitan Tali Tas","de":"Tas yang digantung di kursi terus-menerus melorot turun perlahan. Jepit sekali dengan jepitan tali, dan kedua tangan pun bebas dari kekhawatiran ia akan jatuh. Kelegaan bepergian dimulai saat kau bisa melupakan bawaanmu sejenak."},"ICON-2727":{"nm":"Kantong Kain Penghangat Tangan","de":"Di gang berangin dingin, kantong kain di saku diam-diam mengalirkan kehangatan ke telapak tangan. Satu lapisan lembut yang membungkus sesuatu yang panas dan menghangatkannya pas secukupnya. Kehangatan musim dingin selalu tersampaikan melalui selembar kain."},"ICON-2728":{"nm":"Penyangga Cermin Lipat","de":"Buka lipatannya dan cermin kecil pun miring mencari sudutnya sendiri. Agar kau bisa bertatapan dengan wajahmu tanpa memegangnya, penyangga ini berdiri menggantikanmu. Bahkan dalam jeda singkat merapikan penampilan, ada satu pemeran pendukung yang bisa diandalkan di sisimu."},"ICON-2729":{"nm":"Tutup Tisu Basah Bepergian","de":"Lembar pertama tisu basah selalu perlahan mengering. Tutup kancingnya rapat dan bahkan lembar terakhir pun tetap lembap. Menjaga agar bisa dipakai sampai habis—rahasia rumah tangga yang bertahan lama tersembunyi dalam hal sekecil ini."},"ICON-2730":{"nm":"Sekat Koin Dompet","de":"Saat koin bertebaran di antara uang kertas, antrean kasir selalu jadi sibuk. Satu sekat mengumpulkan benda-benda bundar itu ke satu sisi, dan ujung jari tak lagi meraba-raba. Merapikan adalah pekerjaan memberi nama pada setiap tempat."},"ICON-2731":{"nm":"Kotak Lipat Masker Bepergian","de":"Dilipat masuk, masker tidak akan kusut meski di dalam tas. Sebuah kotak yang menyimpan bersih selembar masker yang sempat dilepas. Satu kebiasaan lembut menyimpannya rapi untuk dipakai lagi tersimpan di sini."},"ICON-2732":{"nm":"Penutup Gigi Sisir Bepergian","de":"Gigi sisir di dalam tas sering kali menyangkut barang lain. Pasang penutup giginya dan sisir pun aman, begitu pula barang-barang yang dikemas bersamanya. Bahwa satu lapis perlindungan kecil menjaga kedua belah pihak, hanya diketahui oleh mereka yang pernah merawat barangnya."},"ICON-2733":{"nm":"Klip Pembagi Sekat Laci","de":"Setiap kali laci dibuka, barang-barang yang bercampur aduk tumpah seperti sebuah keluhan. Bagi menjadi beberapa bagian dengan satu klip, dan benda-benda kecil itu akhirnya menemukan zona masing-masing. Laci yang rapi diam-diam mengubah suasana hati setiap pagi."},"ICON-2734":{"nm":"Penyangga Pajangan Koin","de":"Berdirikan satu koin tua dan ia sendiri menjadi pameran kecil. Penyangga menopangnya miring untuk memperlihatkan corak sisi depannya dengan jelas. Mengangkat waktu yang usang ke sejajar mata—di sinilah kegembiraan mengoleksi semakin mendalam."},"ICON-2735":{"nm":"Gulungan Kabel Earphone","de":"Ada pagi-pagi yang separuh terbuang untuk mengurai kabel earphone yang kusut. Gulung rapi pada gulungannya, dan lain kali dikeluarkan, kabelnya akan mulus. Sedikit kerapian menjadi hadiah kecil yang diam-diam kau berikan pada dirimu di hari esok."},"ICON-2736":{"nm":"Kait Dinding Kabel Charger","de":"Kabel pengisi daya yang tergeletak di lantai terus-menerus terinjak. Tempelkan satu kait di dinding untuk menggantungnya, dan meja kerja pun terasa jauh lebih luas. Mengendalikan kekacauan bukan hal besar—hanya sebuah tempat sekecil satu paku."},"ICON-2737":{"nm":"Tempat Berdiri Remote Kontrol","de":"Remote yang selalu menghilang ke celah sofa akhirnya punya rumah untuk pulang. Berdirikan di tempatnya, dan tak ada lagi acara mencari-cari, tak ada lagi acara terduduki. Memiliki tempat sendiri menjadi istirahat kecil bahkan bagi sebuah benda."},"ICON-2738":{"nm":"Jepitan Gantungan Gagang Kacamata","de":"Kacamata yang dilepas selalu diam-diam tergelincir ke suatu tempat. Kaitkan gagangnya ringan pada jepitan, dan lensa tak pernah menyentuh lantai. Keinginan untuk menjaganya tetap bebas goresan hingga esok tersimpan dalam gantungan kecil ini."},"ICON-2739":{"nm":"Klip Pemisah Gantungan Kunci","de":"Semakin berat segenggam kunci, semakin kabur mana yang membuka pintu yang mana. Ikat dengan klip pemisah, dan hanya dengan ujung jari saja pasangannya bisa dikenali. Penuntun tanpa suara yang diam-diam memberi keteraturan pada pintu-pintu yang dibuka tutup setiap hari."},"ICON-2740":{"nm":"Klip Penyangga Memo","de":"Memo yang dituliskan sering kali terjungkal di atas meja. Saat klip menahan kertas tegak berdiri, tulisannya pun menatap lurus ke matamu. Cara membiarkan satu baris yang tak boleh terlupa tetap tinggal di tempat yang selalu terlihat."},"ICON-2741":{"nm":"Penyangga Ujung Pena","de":"Berapa kali punggung membungkuk untuk memungut pena yang jatuh menggelinding? Tancapkan ujungnya berdiri di penyangga, dan jarak ke baris berikutnya menyusut sejengkal. Sebuah ruang tunggu kecil yang selalu terjaga di sisi orang yang menulis."},"ICON-2742":{"nm":"Alas Pembalik Jam Pasir","de":"Setelah jam pasir habis mengalir, seseorang harus membaliknya agar hidup kembali. Alasnya menangkap momen butir terakhir itu dan membalikkannya tegak dengan mulus. Sentuhan yang mengembalikan waktu ke awal bersemayam di sini, di atas sepotong kayu kecil."},"ICON-2743":{"nm":"Kentang Panggang Mentega","de":"Mentega meleleh perlahan di atas kentang yang dipanggang dengan kulitnya. Saat serat kuningnya meresap bersama uap, daging dalamnya yang lembut diam-diam menyerap gurihnya. Persis saat itulah, umbi beraroma tanah menjadi paling hangat."},"ICON-2744":{"nm":"Jagung Bakar Mentega","de":"Butiran-butiran kuning yang berjejer berbunyi tok-tok di atas panggangan. Sepotong mentega meluncur di atasnya dan aroma manis pun menyeruak. Manisnya ladang musim panas berpindah utuh ke dalam satu gigitan."},"ICON-2745":{"nm":"Wafel","de":"Di setiap kotak kisi-kisinya, sirup diam-diam menunggu untuk menggenang. Luarnya renyah, dalamnya empuk—satu gigitan dan uap hangat pun menyelinap keluar. Kotak-kotak persegi itu seperti wadah yang membagikan sedikit kebahagiaan."},"ICON-2746":{"nm":"Panekuk","de":"Aku ingat aroma adonan yang mengembang keemasan di atas wajan. Di atas kue bundar yang bertumpuk berlapis-lapis, mentega meluncur perlahan meleleh. Sepiring lembut yang hanya diizinkan diam-diam pada pagi yang santai."},"ICON-2747":{"nm":"Cokelat","de":"Kulum satu potong dan ia perlahan lumer terkena suhu tubuh. Manis yang menyebar di ujung pahitnya diam-diam melepaskan ketegangan hati. Di hari yang melelahkan, sepotong cokelat kecil yang diambil dari saku sebagai penghiburan."},"ICON-2748":{"nm":"Kue Stroberi","de":"Stroberi merah bertengger di atas krim kocok putih, mengabarkan musim semi lebih dulu. Saat garpu membelah irisan lembutnya, aroma asam segar pun mekar perlahan. Di hari ada sesuatu yang dirayakan, bintang lembut yang diletakkan di tengah meja."},"ICON-2749":{"nm":"Kue Keju","de":"Satu potong yang berat runtuh pekat di atas lidah. Rasa asin di akhirnya menggandeng tangan rasa manis dan terus memanggil satu gigitan lagi. Hidangan penutup yang diam-diam dinikmati oleh mereka yang menyukai kekentalan yang pekat."},"ICON-2750":{"nm":"Kue Kering Pisang","de":"Aroma pisang yang dihaluskan matang keemasan di dalam oven. Gigit satu potong dan manis yang lembut menyebar memenuhi mulut. Momen hangat saat satu buah yang matang sempurna terlahir kembali sebagai kue kering."},"ICON-2751":{"nm":"Kue Kering Keping Cokelat","de":"Butiran cokelat di dalam adonan meleleh pekat saat dipanggang. Belah selagi hangat, dan cokelat gelap menempel di ujung jari. Bersama segelas susu, sepotong yang membuat sore hari menjadi jauh lebih hangat."},"ICON-2752":{"nm":"Kue Kering Kakao Nib","de":"Serpihan kakao yang dihancurkan halus renyah di antara adonan. Rasa pahit yang dalam dan tak manis menenangkan lidah orang dewasa dengan tenang. Kue kering yang sedikit serius, menyimpan aroma aslinya sebelum diolah."},"ICON-2753":{"nm":"Roti Panggang Keju","de":"Keju terulur panjang seperti benang di atas roti yang dipanggang keemasan. Kerenyahan di luar dan kegurihan di dalam menyatu dalam satu gigitan. Santapan paling sederhana dan hangat yang mengenyangkan pagi yang terlambat."},"ICON-2754":{"nm":"Roti Lapis","de":"Di antara dua lembar roti, ketulusan sehari penuh tersusun rapi berlapis-lapis. Gigit, dan rasa-rasa yang bertumpuk pun menyapa sekaligus. Sebuah meja makan kecil di atas telapak tangan, siap dibawa ke mana saja."},"ICON-2755":{"nm":"Roti Panggang Prancis","de":"Roti yang direndam basah dalam kocokan telur matang keemasan di atas wajan. Tepinya, yang mengembang bersama aroma mentega, paling dulu renyah. Beri satu garis sirup, dan roti biasa pun menjadi kemewahan hari libur."},"ICON-2756":{"nm":"Ramyeon Jamur","de":"Aroma dalam jamur bangkit bersama uap di atas kaldu yang mendidih. Angkat sepotong tudungnya yang kenyal dan manis beraroma tanah menyebar di mulut. Semangkuk yang sedikit istimewa, mengenyangkan lewat aroma sebelum mi."},"ICON-2757":{"nm":"Ramyeon Goreng","de":"Pada mi yang diaduk tanpa kuah, bumbu pedas melilit dengan kilau mengilap. Angkat dengan sumpit dan aroma gurih terbakar menyebar di antara uapnya. Saat merindukan santapan cepat nan pekat, sahabat paling bisa diandalkan."},"ICON-2758":{"nm":"Ramyeon Keju","de":"Letakkan selembar keju di atas mi panas dan ia perlahan runtuh meleleh. Kuah pedas bertemu kegurihan lembut dan tepinya pun membulat. Semangkuk yang pas untuk malam ketika kau ingin melunakkan sengatannya sedikit."},"ICON-2759":{"nm":"Ramyeon Kari","de":"Aroma kari yang pekat melilit mi, mengepulkan uap kuning ke atas. Seruput satu suapan dan pedas yang hangat menghangatkan dari dalam. Mi variasi yang menyenangkan, menambahkan aroma sedikit asing pada kuah yang akrab."},"ICON-2760":{"nm":"Ramyeon Seafood","de":"Di atas kuah yang penuh aroma laut, udang dan kerang mengapung montok ke permukaan. Rasa gurih yang segar sekaligus dalam meresap di sela-sela mi. Sihir kecil yang membawa aroma pantai ke dalam satu mangkuk tanpa perlu pergi jauh."},"ICON-2761":{"nm":"Gimbap Lobak Acar","de":"Dengan lobak acar kuning di tengah dan butiran nasi mengelilinginya bundar, selembar rumput laut mengikat semuanya menjadi satu gulungan yang hangat. Di fajar hari piknik, santapan paling jujur yang lahir di atas talenan."},"ICON-2762":{"nm":"Gimbap Tuna","de":"Saat sesendok tuna berbalut mayones meresap di antara nasi, satu santapan pun cukup hangat bahkan di bawah cahaya minimarket larut malam. Penghibur yang paling sering diraih tangan yang sibuk."},"ICON-2763":{"nm":"Salad Buah","de":"Warna-warna musiman bertemu untuk pertama kalinya dalam satu mangkuk. Bagaimana merah, hijau, dan kuning bisa akur tanpa berselisih, hanya diperlihatkan buah setelah diiris dan disatukan."},"ICON-2764":{"nm":"Salad Ayam","de":"Dada ayam yang dipanggang tawar diletakkan rapi di atas sayuran hijau. Di meja makan seseorang yang bersiap untuk panggung esok hari, selalu ada sepiring yang serapi ini."},"ICON-2765":{"nm":"Asinan Tomat Timun","de":"Tomat yang matang sempurna dan timun yang renyah dicampur asam segar. Di siang hari yang riuh suara jangkrik, satu suapan sumpit membuat musim panas mendingin satu ketukan di dalamnya."},"ICON-2766":{"nm":"Salad Selada","de":"Bilas daun yang baru dipetik dari kebun dengan air dingin dan ujung jari terbangun sejuk. Momen ketika sayuran yang paling biasa mengambil tempat paling hijau dan segar di meja makan."},"ICON-2767":{"nm":"Salad Jagung","de":"Setiap kali butiran manisnya meletup, ladang pertengahan musim panas yang penuh sinar mentari terbentang di depan mata. Jagung kuning tak pernah lupa sinar mentarinya sendiri, bahkan di dalam mangkuk salad."},"ICON-2768":{"nm":"Coleslaw","de":"Saat kubis yang diiris tipis menyerap saus asam manis, kerenyahannya melunak jauh lebih lembut. Kebajikan lauk pendamping: diletakkan di samping hidangan utama apa pun, ia tak pernah bersaing sorotan dan tetap menjalankan perannya."},"ICON-2769":{"nm":"Salad Udang Jeruk Nipis","de":"Peras sedikit jeruk nipis dan manis udang pun terbangun lebih tajam. Satu tetes asam menghembuskan kehidupan ke seluruh piring—sentuhan akhir yang kecil namun menentukan."},"ICON-2770":{"nm":"Steik Hamburg","de":"Adonan daging yang dibentuk tebal matang keemasan di atas pelat besi yang panas. Sari daging yang meresap keluar begitu ujung pisau menyentuhnya—santapan yang paling lama dicintai di antara masakan rumahan dan masakan Barat."},"ICON-2771":{"nm":"Pizza","de":"Satu gigitan di mana keju terulur panjang, berpindah dari tangan ke tangan di antara banyak orang yang berkumpul. Hanya ketika satu loyang bundar dipotong-potong dan dibagi bersama, sebuah perkumpulan benar-benar menjadi perkumpulan."},"ICON-2772":{"nm":"Pasta Krim Jamur","de":"Aroma tanah yang dalam dari jamur dan kelembutan krim merangkul setiap helai mi. Di malam dengan suara hujan yang tenang, aroma pekatnya perlahan menyebar hingga ke dasar piring."},"ICON-2773":{"nm":"Pasta Udang","de":"Udang montok ditumis sebentar dalam minyak zaitun lalu dicampur bersama mi. Ketika asinnya laut bertemu tawarnya mi, sore yang biasa-biasa saja pun menjadi sedikit istimewa."},"ICON-2774":{"nm":"Pasta Minyak","de":"Bawang putih, minyak, dan mi—hanya tiga hal itu saja. Ada rasa yang justru semakin jernih ketika semakin banyak yang dihilangkan, dan aglio e olio membuktikannya diam-diam, tanpa satu pun yang berlebihan."},"ICON-2775":{"nm":"Pasta Kerang","de":"Kaldu yang dilepaskan kerang saat membuka cangkangnya meresap dalam ke setiap helai mi. Aroma seteguk anggur putih bertahan lama di atas piring, seperti hari musim semi yang tak mau memudar."},"ICON-2776":{"nm":"Pasta Krim","de":"Ketika krim yang pekat merangkul mi dengan lembut, satu sudut hati pun menghangat sejak gigitan pertama. Penghiburan yang ditawarkan kelembutan, yang semakin dalam justru di hari yang berangin."},"ICON-2777":{"nm":"Pasta Tomat","de":"Saus tomat yang dimasak lama menyebar merah di atas mi. Ketika manis dan asam perlahan menyusut dan akhirnya menemukan keseimbangan, sepiring yang paling dasar adalah yang paling bisa diandalkan."},"ICON-2778":{"nm":"Omurice","de":"Telur yang lembut menutupi nasi hangat seperti selimut, terselip dengan lembut. Tuliskan bahkan hanya satu nama dengan saus tomat, dan meja makan hari itu pun menjadi surat kecil yang diberikan seseorang."},"ICON-2779":{"nm":"Salmon Panggang","de":"Panggang perlahan di depan api hingga kulitnya renyah matang. Sehelai uap yang mengepul saat daging merah mudanya terbelah mengikuti seratnya—kesabaran selalu dibalas dengan jujur oleh salmon."},"ICON-2780":{"nm":"Bruschetta","de":"Tumpuk tomat cincang dan basil melimpah di atas roti panggang yang renyah. Ringannya mengambil dengan jari dan menggigit sepotong itu, membuka salam pertama sebuah perkumpulan dengan hangat."},"ICON-2781":{"nm":"Smoothie Mangga","de":"Haluskan mangga yang matang sempurna dan campur sejuk dengan es. Ketika titik-titik embun mengembun di gelas kuningnya, sore pertengahan musim panas yang malas naik penuh hingga ujung sedotan."},"ICON-2782":{"nm":"Limun","de":"Masukkan lemon peras segar, gula, dan air dingin, lalu kocok dalam gelas. Saat asamnya yang kuning meluncur sejuk menuruni tenggorokan, panas yang mengamuk pun menyerah sejenak."},"ICON-2783":{"nm":"Susu Stroberi","de":"Larutkan stroberi yang dihaluskan ke dalam susu, dan awan merah muda perlahan mengendap di dalam gelas. Debaran ujung jari membuka pintu kulkas semasa kecil tersimpan utuh dalam satu gelas."},"ICON-2784":{"nm":"Susu Pisang","de":"Minuman yang sudah menjadi kenangan satu masa hanya lewat bentuk bundar toples kecilnya. Kenangan kuning menancapkan sedotan di bangku pemandian umum kembali hidup dengan hangat di setiap tegukan."},"ICON-2785":{"nm":"Susu Blueberry","de":"Masukkan dan hancurkan butiran ungu itu, dan susu putih pun berubah menjadi biru langit yang lembut. Segenggam buah kecil itu mengubah satu gelas penuh menjadi warna yang sama sekali baru."},"ICON-2786":{"nm":"Jus Buah","de":"Peras beberapa buah menjadi satu, dan rasanya berubah menjadi sesuatu yang tak bisa disebut dengan satu nama saja. Sebuah paduan suara kecil dari rasa-rasa manis, bercampur dan mengembang semakin kaya."},"ICON-2787":{"nm":"Cokelat Panas","de":"Di dekat jendela yang bersalju, genggam mug hangat diam-diam dengan kedua tangan. Secangkir cokelat yang uapnya mengepul perlahan menghangatkan dari ujung jari hingga ke hati."},"ICON-2788":{"nm":"Kopi","de":"Yang menyalakan lampu ruang latihan dini hari selalu secangkir ini. Saat aroma pahitnya diam-diam mendorong kantuk pergi, panggung hari yang lain pun dimulai, begitu saja, dalam diam."},"ICON-2789":{"nm":"Sushi Salmon","de":"Genggam nasi di tangan, mengira-ngira garis tipis antara kepadatan dan kelembutan. Saat sepotong salmon yang diiris tipis berbaring lembut di atasnya, satu gigitan pun menjadi penyempurnaan sebuah ketulusan kecil."},"ICON-2790":{"nm":"Bubur Labu Manis","de":"Rebus labu kuning hingga lunak lalu haluskan lembut. Setiap kali satu sendok disuap, sinar mentari musim gugur meleleh hangat di mulut. Bubur yang paling dulu terlintas saat sedang sakit."},"ICON-2791":{"nm":"Kari Ikan","de":"Daging ikan yang direbus sebentar dalam rempah hancur lembut di dalam kari. Tambahkan tekstur laut ke semangkuk yang akrab, dan sore yang biasa pun berangkat berjalan lebih jauh sejengkal."},"ICON-2792":{"nm":"Udang Goreng Tepung","de":"Momen singkat memegang ekornya, melumurinya dengan adonan, dan menjatuhkannya ke minyak mendidih adalah penentu segalanya. Udang berbalut baju keemasan bersinar paling terang jika dimakan sebelum kerenyahannya sempat dingin."},"ICON-2793":{"nm":"Cumi Goreng Tepung","de":"Cincin bundar mengembang montok di dalam minyak panas. Satu gigitan yang kerenyahannya membungkus kekenyalan itu paling cocok di bawah lampu kuning kios makanan kaki lima."},"ICON-2794":{"nm":"Ayam Panggang","de":"Oleskan bumbu dan panggang perlahan di depan api, dan kulitnya pun berkilau mengilap. Hidangan yang rasanya ditentukan oleh satu penyesuaian api—paling sederhana, dan karenanya paling jujur."},"ICON-2795":{"nm":"Tumis Kimchi Babi","de":"Tumis kimchi yang matang sempurna bersama daging babi, dan rasa asamnya pun matang menjadi manis. Hidangan yang dengan sendirinya memanggil semangkuk nasi putih—pasangan paling bisa diandalkan di meja makan Korea."},"ICON-2796":{"nm":"Tumis Daging Babi","de":"Tumis cepat dengan api besar hingga bagian luarnya matang renyah. Ketika aroma gurih minyak memenuhi dapur, menu makan malam hari ini sudah ditentukan tanpa perlu ditanya lagi."},"ICON-2797":{"nm":"Tumis Daging Sapi Jamur","de":"Tumis jamur yang harum bersama daging sapi, dan rasa keduanya pun semakin dalam. Tanah dan ladang bergandengan tangan dengan tenang di satu piring—santapan musim gugur yang rapi."},"ICON-2798":{"nm":"Dak-galbi Keju","de":"Lelehkan keju berlimpah di atas dak-galbi pedas dan tarik memanjang. Berkumpul mengelilingi pelat besi panas di tengah, dan bahkan rasa pedas yang menggigit pun terurai menjadi tawa."},"ICON-2799":{"nm":"Sup Kimchi","de":"Semakin lama kimchi difermentasi, semakin dalam dan pekat kaldu yang dihasilkannya. Duduk berhadapan di depan panci tanah liat yang mendidih, dan kata \"keluarga\" pun menghangat kembali."},"ICON-2800":{"nm":"Sup Doenjang","de":"Larutkan doenjang yang gurih, masukkan tahu dan zukini, lalu masak perlahan dan stabil. Suara mendidih hingga tetes terakhir di panci tanah liat itu adalah tanda paling pasti bahwa kau telah pulang ke rumah."},"ICON-2801":{"nm":"Sup Lobak Daging Sapi","de":"Setengah hari menunggu dengan tenang di depan api kecil, sampai lobak menjadi bening. Ketika seujung sendok kuah bening menyentuh bibir, teringat kembali meja makan masa itu yang tak pernah mewah. Yang sederhana justru bertahan paling lama dalam ingatan."},"ICON-2802":{"nm":"Sup Kerang","de":"Saat kerang membuka cangkangnya, musim semi pun kian mendalam di dalam panci. Ketika seuntai aroma laut naik bersama uap, terbayang dapur pagi buta di sebuah desa pesisir. Di setiap celah cangkang yang terbuka, tergenang sepotong laut yang asin."},"ICON-2803":{"nm":"Ubi Madu","de":"Dalam perjalanan pulang sekolah, segumpal kuning digenggam dalam gelas kertas seperti penghangat tangan. Gigit kulit luarnya yang keemasan, dan uap panas langsung mengepul dari dalamnya. Kulit manis berkaramel dan isi yang hangat—rasa musim dingin yang paling lembut."},"ICON-2804":{"nm":"Tumis Terong","de":"Sekejap ketika warna ungu bertemu minyak dan perlahan melunak. Sayur yang sering dicela karena lembek itu ternyata paling pandai menyerap bumbu. Sekali gigit, sentuhan tangan yang meresap lembut itulah yang pertama kali sampai ke lidah."},"ICON-2805":{"nm":"Kentang Kecap","de":"Sore hari ketika aroma manis memenuhi seisi dapur selagi kecap asin menyusut kental. Sentuhan tangan yang mengisi satu petak kotak bekal dengan sebutir kentang cokelat mengilap. Ketulusan yang tak tertulis dalam resep mana pun meresap ke dalam setiap butir kecil ini."},"ICON-2806":{"nm":"Acar Daun Perilla","de":"Pekerjaan mengasinkan seluruh aroma musim panas untuk dibawa hingga ke meja makan musim dingin. Lepas selembar daun dan letakkan di atas nasi, maka musim yang telah berlalu mekar kembali di dalam mulut. Di antara lapisan daun yang bertumpuk-tumpuk, sinar matahari tahun itu tertidur lelap."},"ICON-2807":{"nm":"Kimchi Sawi Segar","de":"Tangan yang tak sabar menunggu musim kimjang langsung meremas-remas lembut hari itu juga. Kesegaran yang hanya bisa dinikmati pada saat bumbu baru mulai meresap ke daun yang renyah. Kehijauan sebelum fermentasi adalah kemewahan hari ini saja."},"ICON-2808":{"nm":"Tumis Jamur","de":"Sesuatu yang muncul diam-diam di bawah naungan hutan setelah hujan reda. Selagi digoreng dengan minyak wijen perilla, aroma tanahnya berubah menjadi gurih. Semakin diam sesuatu tumbuh dalam gelap, semakin dalam dan pekat wanginya."},"ICON-2809":{"nm":"Bayam Bumbu","de":"Sayuran hijau yang menyusut jadi segenggam saja ketika direbus sebentar, diremas lembut dengan ujung jari. Volume yang rendah hati itulah kebajikan sayuran musim semi. Satu piring hijau membuat sejengkal lagi cahaya musim semi masuk ke meja makan."},"ICON-2810":{"nm":"Rumput Laut Bumbu","de":"Untaian licin yang baru saja diangkat dari laut berpadu dengan saus cuka pedas yang segar. Sensasi asin yang meletup-letup setiap kali dikunyah. Sepiring yang memindahkan tekstur ombak yang bergulung langsung ke dalam mangkuk."},"ICON-2811":{"nm":"Tumis Zukini","de":"Ada sayuran yang rasa manisnya justru makin bertambah seiring bertambah tua. Iris tipis dan tumis dengan udang asin, dan zukini yang biasa-biasa saja pun diam-diam mengeluarkan rasa manisnya sendiri. Warna kuning yang meleleh lembut di mulut hingga suapan terakhir."},"ICON-2812":{"nm":"Nasi Goreng Kimchi","de":"Ketika kimchi tua kian mendalam rasanya, ia bertemu nasi dingin dalam satu wajan. Semangkuk yang justru paling mengenyangkan ketika sisa bertemu sisa. Penyelamatan paling hangat di bawah cahaya lampu kos larut malam."},"ICON-2813":{"nm":"Kari Ayam","de":"Ketika kuah kuning menutupi nasi putih, meja makan pun cerah seketika. Di masa ketika rempah masih terasa asing, inilah rasa dunia luar pertama yang menjadi akrab. Suatu siang Minggu ketika daging ayam terurai lembut dan empuk."},"ICON-2814":{"nm":"Nasi Goreng","de":"Sisa-sisa yang tertinggal di sudut kulkas berbaur akrab dalam satu wajan. Kemurahan hati yang menerima apa saja dengan lapang. Mengumpulkan yang tercecer menjadi satu—itulah awal dari mengurus rumah tangga."},"ICON-2815":{"nm":"Nasi Bulgogi","de":"Daging yang direndam bumbu manis meluncur perlahan di atas nasi yang mengepul. Ketika bintang meja tamu turun menjadi semangkuk hidangan hari biasa, keistimewaan itu justru terasa lebih hangat lagi."},"ICON-2816":{"nm":"Bibimbap","de":"Di atas nasi yang pulen, lima warna namul duduk melingkar rapi. Di ujung jari yang menata warna-warni itu mengalir cita rasa estetika lama yang penuh ketelitian. Rasa keharmonisan yang baru sempurna setelah semuanya diaduk menjadi satu."},"ICON-2817":{"nm":"Nasi Goreng Udang","de":"Udang gemuk tampak menonjol merah muda di antara butiran nasi. Menumis segenggam laut ke dalamnya membuat makanan biasa pun berlagak seperti pesta. Rasa manis yang menyebar saat renyah tergigit terasa menyenangkan."},"ICON-2818":{"nm":"Nasi Babi Pedas","de":"Daging babi yang bumbu pedasnya meresap dalam bertemu nasi yang mengepul. Mangkuk yang paling dulu terlihat dasarnya saat jam makan siang. Kelegaan sepiring makanan yang menepuk-nepuk lembut hari yang sibuk."},"ICON-2819":{"nm":"Nasi Tuna Mayo","de":"Satu kaleng tuna, seuntai mayones, dan semangkuk nasi hangat. Bahannya sederhana, tapi rasa hiburannya melimpah. Rasa malam itu, yang diam-diam diaduk di meja kelas seusai jam belajar malam."},"ICON-2820":{"nm":"Nasi Kari","de":"Warna emas yang kental memenuhi seluruh piring. Ketulusan mengaduk lama-lama sampai kentang dan wortel benar-benar empuk. Teringat kehangatan sore itu ketika seisi keluarga sama-sama menengok ke dalam panci yang sama."},"ICON-2821":{"nm":"Bibimbap Rumput Laut","de":"Untaian beraroma laut bertemu gochujang dan diaduk perlahan berputar-putar. Ketika tekstur licin dan segar itu membalut butiran nasi, laut yang ditahan napas oleh seorang haenyeo untuk diangkat pun terbentang dalam satu mangkuk."},"ICON-2822":{"nm":"Ikan Makarel Bakar","de":"Punggung keperakan itu matang keemasan di atas pemanggang. Sentuhan tangan yang memisahkan duri dan meletakkan dagingnya di atas nasi. Dalam sepotong ikan bersirip biru itu meresap cinta yang diam-diam memberi makan dan membesarkan."},"ICON-2823":{"nm":"Jeon Kentang","de":"Sesuatu yang diparut dan digoreng di dapur pegunungan Gangwon setiap hari hujan turun. Pinggiran yang kenyal dan ujung yang renyah hidup berdampingan dalam satu lembar. Adonan yang paling cocok dengan suara hujan yang mengetuk jendela."},"ICON-2824":{"nm":"Jeon Kimchi","de":"Begitu kimchi asam menyentuh wajan berminyak, seisi rumah pun dipenuhi suara mendesis. Bundaran keemasan yang dengan sendirinya memanggil semangkuk makgeolli. Menu andalan yang berpasangan dengan suara hujan di bawah atap rumah."},"ICON-2825":{"nm":"Jeon Daun Bawang","de":"Bentangkan daun bawang muda rapi, tuangkan adonan, dan goreng perlahan. Selembar yang berayun-ayun antara renyah dan lembut. Persis seperti pemandangan hangat itu, uap yang mengepul-ngepul dari lapak pasar di hari pekan."},"ICON-2826":{"nm":"Jeon Zukini","de":"Balut irisan tipis zukini dengan adonan, lalu goreng hingga keemasan. Lingkaran hijau muda yang rapi menjaga sudutnya di meja sesaji leluhur. Kerapian penuh ketulusan itu baru terwujud dengan banyak sentuhan tangan."},"ICON-2827":{"nm":"Tumis Cumi Pedas","de":"Lengan-lengan cumi berbalut bumbu merah berkilau mengilap dengan minyaknya. Meski dahi berkeringat karena pedasnya, sumpit tak juga berhenti bergerak. Sepiring itu tempat keringat dan kesenangan saling berbaur."},"ICON-2828":{"nm":"Tteokbokki","de":"Kue beras dan odeng tenggelam dalam kuah gochujang merah yang kental. Seluruh siang di kedai jajanan, saat uang receh dikumpulkan dan dimakan berdua, tersimpan utuh di dalamnya. Rasa kenangan yang membuat air liur menetes hanya dengan menyebut namanya."},"ICON-2829":{"nm":"Sup Odeng","de":"Gerobak pinggir jalan tempat odeng bergoyang dalam kuah, uapnya mengaburkan kaca hingga memutih pucat. Genggam satu tusuk, tuang kuahnya ke gelas kertas, lalu seruput perlahan—malam musim dingin yang menggigil pun jadi jauh lebih hangat."},"ICON-2830":{"nm":"Tahu Kimchi","de":"Di samping tahu yang lembut, kimchi tumis pedas duduk berdampingan. Dingin dan panas, lembut dan tajam, berbaur dalam satu piring. Pasangan yang telah lama menemani malam-malam orang dewasa."},"ICON-2831":{"nm":"Tumis Sosis Sayur","de":"Sosis merah dan sayuran berdesis berbaur dalam warna saus tomat. Petak yang paling dulu kosong ketika tutup kotak bekal hari olahraga dibuka. Warna hari itu tetap cerah, sekalipun waktu terus berlalu."},"ICON-2832":{"nm":"Latte Ubi Manis","de":"Ubi manis yang dihaluskan lembut larut perlahan dalam susu hangat. Manisnya cita rasa lokal yang tertulis dalam huruf Hangeul di papan menu. Di hari ujung jari terasa dingin, genggam dengan kedua tangan, dan kehangatannya menyebar perlahan ke seluruh cangkir."},"ICON-2833":{"nm":"Mayones","de":"Saus yang belum tiba di dapur Pulau Berkilau. Sebentar lagi ia akan digambarkan sebagai ikon berwarna krem. (sedang disiapkan)"}};